INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'Simya Ustalığı', 'Alchemical Mastery', 'Savaş alanını kontrol etmek için iksir hazırlama, elementleri dönüştürme ve patlayıcı cihazlar tasarlama sanatında ustalaşın.', 'Master the art of brewing potions, transmuting elements, and concocting explosive devices to control the battlefield.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('30efb19f-9bdb-4e07-8a2d-0bf8c78acd5c', 'Aura Savaşçısı', 'Aura Fighter', 'Sınıflarını tespit etmek için rakip auralarını okuyan, dövüş stilini buna göre uyarlayan ve hassas ki vuruşları serbest bırakan algısı yüksek bir savaşçı.', 'A perceptive warrior who reads opponent auras to detect their class, adapts their combat style to counter it, and unleashes precise ki strikes.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('0f19284d-34cf-4a90-b78c-558c600bb543', 'Canavar Terbiyecisi', 'Beast Tamer', 'Canavarları çağırarak, hayvan yoldaşlarını güçlendirerek ve ilkel içgüdülerle hayatta kalarak vahşi doğaya hükmet.', 'Master the wilds by summoning beasts, buffing animal companions, and surviving through primal instincts.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('24b2f2a9-b6cd-47cb-9d8e-49c7e0da5c69', 'Vahşinin Yolu', 'Path of the Berserker', 'Vahşinin Yolu saf öfkeyi, ilkel içgüdüleri ve boyun eğmez kan susuzluğunu kullanır. Yıkıcı güç için sağlıktan feragat ederek, savaş alanında durdurulamaz yıkım güçlerine dönüşürler.', 'The Path of the Berserker harnesses raw fury, primal instincts, and unyielding bloodlust. By trading health for devastating power, they become unstoppable forces of destruction on the battlefield.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('5fb3736e-08b0-417b-aa15-f791f4d8e136', 'Demirci', 'Blacksmith', 'Ocak ustaları olan demirciler silah üretir, zırhları geliştirir ve düşmanlarını kavurucu metallerle eritir.', 'Masters of the forge, blacksmiths craft weapons, upgrade armor, and melt their foes with searing metal.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('f4de9c34-33e5-43ff-807d-80ddba9561f6', 'Kan Sanatları', 'Blood Arts', 'Kendi canlılığınızı feda ederek yıkıcı saldırılar açığa çıkaran veya hayatta kalmak için düşmanlarınızdan yaşam sömüren yasaklı kan büyücülüğü gücünü kontrol edin.', 'Harness the forbidden power of hemomancy, sacrificing your own vitality to unleash devastating attacks, or siphoning life from your foes to sustain yourself.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('00ef86dd-8278-42b0-98d8-322772dd8bff', 'Komutanın Otoritesi', 'Commander''s Authority', 'Taktiksel deha, ilham verici liderlik ve kırılmaz dizilişlerle savaş sanatında ustalaşın.', 'Master the art of war through tactical brilliance, inspiring leadership, and unbreakable formations.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('e6a28b81-c07b-4777-bc36-7e559f229425', 'Aşçılık Sanatları', 'Culinary Arts', 'İyileştirici yemekler, kaynayan çorbalar ve jilet gibi keskin satırlar kullanarak düşmanları dilimlemek ve müttefikleri beslemek için savaş aşçılığı sanatında ustalaşın.', 'Master the art of combat cooking, using healing meals, boiling soups, and razor-sharp cleavers to slice through enemies and nourish allies.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('fe0b6a87-eab0-4366-9df8-d072ab4ad6ac', 'Coreplate', 'Coreplate', 'Defansif auralar, enerji bariyerleri ve fiziksel güçlendirme ustalığı; büyücüyü müttefikleri için aşılmaz bir kaleye dönüştürür.', 'Mastery of defensive auras, energy barriers, and physical reinforcement, turning the caster into an impenetrable fortress for their allies.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('8bb37e61-f410-41af-a0dc-5bc5acc53e01', 'Merak ve Deney', 'Curiosity & Experimentation', 'Evrenin sırlarını ortaya çıkarmak için amansız keşif, öngörülemeyen büyülü deneyler ve derin analiz yolu.', 'A path of relentless exploration, unpredictable magical experiments, and deep analysis to uncover the secrets of the universe.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('57281a71-b651-4b8c-bdf6-e03b42842a62', 'Karanlık Büyücü', 'Dark Mage', 'Gölgelerin, ölümcül lanetlerin ve yasaklı nekrotik bilginin efendileri. Düşmanlarını ezmek için karanlığı kullanırlar.', 'Masters of shadows, deadly curses, and forbidden necrotic knowledge. They manipulate the dark to crush their foes.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('fa5e3592-4f94-4225-b874-5b543f329214', 'Karanlık Suikastçı', 'Darkcabe', 'Gölge büyüsü ustaları, karanlığın içinden geçerek hedeflerini ölümcül bir hassasiyetle infaz ederler.', 'Masters of shadow magic, blinking through darkness to execute their targets with lethal precision.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'Druid Sanatları', 'Druidic Arts', 'Canavarları yönetmek, bitki örtüsünü yönlendirmek ve güçlü hayvan formlarına dönüşmek için doğanın kadim gücünü kontrol edin.', 'Harness the ancient power of nature to command beasts, manipulate flora, and shapeshift into formidable animal forms.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('f63c334c-e944-47aa-a38c-c6a37ab1b974', 'Sarhoş Usta', 'Drunken Master', 'Düşmanları şaşırtmak ve yok etmek için öngörülemez hareketleri, sendeleyen vuruşları ve sarhoş edici içkilerin gücünü kucaklar. Sarhoşken gelen saldırıları yönlendirme sanatında ustalaşır.', 'Embraces unpredictable movements, staggering strikes, and the power of intoxicating brews to confuse and decimate foes. Masters the art of redirecting incoming attacks while intoxicated.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'Yankı Kılıcı', 'Echoblade', 'Ses ve titreşim ustaları. Yankı Kılıçları; sonik dalgaları, gecikmeli yankıları ve moleküler titreşimleri ölümcül suikastlerine işlerler.', 'Masters of sound and vibration. Echoblades weave sonic waves, delayed echoes, and molecular vibrations into their deadly assassinations.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('1396c72f-f712-4586-b3c1-0c6951b05d8f', 'Element Kılıçustası', 'Elemental Swordmaster', 'Alev, ayaz ve fırtınanın ilkel güçlerini dizginle, onları kılıcınla yönlendirerek düşmanlarını yıkıcı element vuruşlarıyla yok et.', 'Harness the primal forces of flame, frost, and storm, channeling them through your blade to decimate your foes with devastating elemental strikes.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'Element Okçuluğu', 'Elemental Marksmanship', 'Okları saf element gücüyle doldurma ustalığı; düşmanları yok etmek için Ateş, Buz, Yıldırım, Toprak ve İlkel büyü arasında anında geçiş yapar.', 'Mastery of infusing arrows with raw elemental power, swapping between Fire, Ice, Lightning, Earth, and Primal magic on the fly to decimate enemies.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('af89d25d-f951-4fc8-8951-d53ac92c89e6', 'Element Ustalığı', 'Elemental Mastery', 'Savaş alanını kontrol etmek, yıkıcı alan hasarları vermek ve elementalleri çağırmak için dört ana elementte ustalaşır.', 'Masters the four prime elements to summon elementals, control the battlefield, and unleash devastating area-of-effect destruction.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'Cellat', 'Executioner', 'Ölümcül darbe sanatında ustalaş. Yıkıcı bitirici vuruşlar yap, ağır bıçakları eşsiz bir ustalıkla savur ve düşmanın savaşma iradesini kır.', 'Master the art of the killing blow. Deliver devastating finishers, swing heavy blades with unmatched mastery, and break the enemy''s will to fight.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('320777c7-178e-49ca-9e6a-82fbfa9e064a', 'Gelişmiş İnfaz', 'Advanced Execution', 'Gelişmiş infazcılar, hızlı ve mutlak ölüm getirme konusunda uzmanlaşmıştır. İnfaz eşikleri %50''ye kadar ulaşarak yaralı düşmanları tamamen yok eder.', 'Advanced executioners specialize in bringing swift and absolute death. Their execute threshold natively reaches up to 50%, completely obliterating wounded foes.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('4ef832e0-825d-426b-a9a6-25712e3a095a', 'Büyük Oyuncu', 'High Roller', 'Şans, kader ve yüksek bahislerin değişken yolu. Bu ağacın ustaları olasılıkları manipüle eder, mistik kartlar çeker ve oranları kendi lehlerine çevirmek için kader değiştiren zarlar atarlar.', 'A volatile path of chance, fate, and high stakes. Masters of this tree manipulate probabilities, draw mystical cards, and roll fate-altering dice to swing the odds in their favor.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('c3b46298-8994-4bbf-986a-4de60cd04d90', 'Dehanın Zihni', 'Mind of the Genius', 'Savaş alanını bir satranç tahtasına çeviren eşsiz bir zeka. Taktiksel emirler, dahiyane aletler ve düşman hareketlerini öngörme yetenekleri içerir.', 'Unparalleled intellect that turns the battlefield into a chessboard. Features tactical commands, ingenious gadgets, and the ability to foresee enemy movements.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('6109ccf1-2d81-4d0d-8047-0c027397aa04', 'İnanç Muhafızı', 'Guardian of Faith', 'Kutsal büyü bariyerleri, takım sığınağı ve haklı intikam konusunda uzmanlaşmış ilahi bir koruyucu.', 'A divine protector specializing in holy magic barriers, team sanctuary, and righteous retribution.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'Silahşor Sanatları', 'Gunslinger Arts', 'Savaş alanına gerçek bir eşkıya gibi hükmetmek için çifte tabancalar, seri ateş, hileli atışlar ve eşsiz çeviklik üzerinde ustalık.', 'Mastery over dual pistols, rapid fire, trick shots, and unmatched agility to dominate the battlefield like a true desperado.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'Cehennem Bağlayıcısı', 'Hellbinder', 'Şeytani çağırma, cehennem ateşi manipülasyonu ve tehlikeli kan anlaşmalarının ustaları. Kendi yaşam güçlerini feda ederek yıkıcı cehennem gücünü serbest bırakırlar.', 'Masters of demonic summoning, hellfire manipulation, and dangerous blood pacts. They sacrifice their own vitality to unleash devastating infernal power.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'Sahtekar Yolu', 'Path of the Imposter', 'Taklit, kılık değiştirme ve hile sanatlarında ustalaşın. Herkes olun, her gücü çalın ve düşmanlarınızı sırtından bıçaklayın.', 'Master the arts of mimicry, disguise, and deception. Become anyone, steal any power, and backstab your enemies.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'Endeks Nişancısı', 'Index Marksman', 'Kusursuz cinayet sanatında ustalaş. Hedeflerini işaretle, onları her türlü arazide amansızca takip et ve her atışın ölümcül olmasını sağlamak için zayıf noktalarını matematiksel olarak analiz et.', 'Master the art of the perfect kill. Mark your targets, track them relentlessly across any terrain, and mathematically analyze their weak points to ensure every shot is fatal.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'Demir Yumruk', 'Iron Fist', 'Kırılmaz bir beden ve zırhı aşan ezen vuruşlar kullanarak düşmanları toza çeviren silahsız dövüş ustası.', 'A master of unarmed combat, utilizing an unbreakable body and crushing strikes to bypass armor and pulverize enemies.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('24b18355-7389-4396-ad86-68f268ceab48', 'Son Samuray''ın Yolu', 'The Way of the Last Samurai', 'Samuray''ın kadim sanatlarında ustalaş. Çift bıçakla kör edici bir hızda saldır, kırılmaz bir onurla dimdik dur veya gerçekliği parçalayan efsanevi, eşsiz vuruşlar yap.', 'Master the ancient arts of the Samurai. Wield twin blades with blinding speed, stand firm with unbreakable honor, or deliver singular, legendary strikes that shatter reality.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('457006e7-a9ee-41c4-baf7-e892a7008bb3', 'Geç Kalan Takipçi', 'Late Chaser', 'Sabır, takip ve ölümcül isabetlilik ustaları. Gecikmeli tuzaklar kurarlar, işaretlediklerini amansızca avlarlar ve zayıflamış avları bitirmede uzmandırlar.', 'Masters of patience, tracking, and lethal precision. They set delayed traps, relentlessly hunt their marks, and excel at finishing off weakened prey.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('49803aae-f03d-4737-83dd-d77a696bcfd2', 'Yaşam Muhafızı', 'Life Guardian', 'Yaşam fedakarlığı, devasa zindelik haleleri ve mutlak koruma üzerine uzmanlaşmış ağır zırhlı bir şifacı. Müttefiklerinin asla düşmemesi için kendi yaşam güçlerini bir kalkan ve silah olarak kullanırlar.', 'A heavy armor healer that specializes in life sacrifice, massive vitality auras, and absolute protection. They wield their own life force as a shield and weapon to ensure their allies never fall.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('639e3303-56a5-4eee-a513-c8c5e9426d24', 'Mana Dokuma', 'Mana Weaving', 'Anti-büyücü uzmanı. Rakip büyülerin %50''sini emer ve büyü akışını manipüle eder.', 'Anti-mage caster. Absorbs 50% of opponent spells and manipulates the flow of magic.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'Tüccarın Defteri', 'Merchant''s Ledger', 'Ticaret, ezici servet ve acımasız anlaşmaların sanatı. Gerçek bir Tüccar her şeyin ve herkesin bir fiyatı olduğunu bilir.', 'The art of trade, overwhelming wealth, and ruthless deals. A true Merchant knows that everything, and everyone, has a price.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('10799c87-b680-4d06-861c-9ec600b7ac1a', 'Zihin Avcısı', 'Mindhunter', 'Hedeflerini takip etmek, zihinlerini okumak ve doğrudan sinir sistemlerini vurmak için psişik güçler kullanan ölümcül bir suikastçı.', 'A deadly assassin who uses psychic powers to track targets, read their minds, and strike their very nervous systems.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('845bea40-0852-439d-8add-2f1c78cb3ef0', 'Yükselen Keşiş Yolu', 'Path of the Ascendant Monk', 'Yıkıcı dövüş sanatları ve güçlü ki enerjisini açığa çıkarmak için zihin, beden ve ruh dengesinde ustalaşın.', 'Master the balance of mind, body, and spirit to unleash devastating martial arts and potent ki energy.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'Karanlık Sanatlar', 'The Dark Arts', 'Ölümün güçlerinde ustalaşarak iskelet orduları diriltin, kemikleri manipüle edin ve iğrenç vebalar yayın.', 'Master the forces of death, raising armies of skeletons, manipulating bone, and spreading vile plagues.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('82fd6006-b419-4842-a601-cfd4a7eb95fb', 'Kabus Avcısı', 'Nightmare Stalker', 'Korku ve uykunun efendisi olan bu suikastçı, zihnin gölgelerinden saldırır. Gölge canavarları çağırır, düşmanları dehşetle felç eder ve kabuslara hapsolmuş olanları infaz eder.', 'Master of fear and sleep, this assassin strikes from the shadows of the mind. They summon shadow beasts, paralyze foes with terror, and execute those trapped in nightmares.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('badddee7-0723-4049-bf7a-1b4fab340f40', 'Ninja Yolu', 'Path of the Ninja', 'Hedeflere gölgelerden suikast düzenlemek için gizlilik, ölümcül shurikenler ve elementel ninjutsu sanatlarında ustalaşın.', 'Master the arts of stealth, deadly shurikens, and elemental ninjutsu to assassinate targets from the shadows.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'Tek Atışın Yolu', 'Way of the One Shot', 'Hazırlanması zaman alan ama mutlak yok ediş garantileyen tek ve yıkıcı saldırıların ustalığı.', 'Mastery of single, devastating attacks that take time to prepare but guarantee absolute annihilation.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('eb28a661-21fd-4a50-9992-eb7328fad584', 'Kâhin Sanatları', 'Oracle Arts', 'Zaman, kader ve gizli bilgi üzerinde ustalık, büyücünün herhangi bir rakibi alt etmesini ve zekasıyla aşmasını sağlar.', 'Mastery over time, destiny, and hidden knowledge, allowing the mage to outwit and outmaneuver any opponent.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('2df3a504-d8d8-4164-8368-2b5d9d828c14', 'Kahin Çağırıcı', 'Oracle Summoner', 'Saldırıları önceden görmek ve gerçekliği bükmek için ruhani varlıkları, gelecekten gelen ruhları ve semavi muhafızları çağırın.', 'Summon ethereal beings, spirits from the future, and celestial guardians to foresee attacks and bend reality.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'Hayalet Peçe Sanatları', 'Phantom Veil Arts', 'Hedeflere neyin çarptığını asla bilmeden suikast düzenlemek için yanılsama, boğucu duman ve psişik kafa karışıklığı sanatlarında ustalaşın.', 'Master the arts of illusions, choking smoke, and psychic confusion to assassinate targets without them ever knowing what hit them.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('8838933d-3f1b-4886-8179-5fa2b9f3d050', 'İlahi Takdir', 'Divine Providence', 'Güçlü şifalar, mutlak arınma ve kırılmaz ilahi kalkanlar konusunda uzmanlaşmış kutsal büyü ustası.', 'A master of holy magic, specializing in powerful heals, absolute purification, and unbreakable divine shields.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('90345517-fe58-4e70-96a1-f9612d716a2d', 'Psiyonik Ustalık', 'Psionic Mastery', 'Psikobüyücü zihnin sınırsız gücünü dizginleyerek, telepati, telekinezi ve aşılmaz psişik kalkanları kullanarak hem maddeyi hem de düşünceyi manipüle eder.', 'The Psychomage harnesses the boundless power of the mind, wielding telepathy, telekinesis, and impenetrable psychic shields to manipulate both matter and thought.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'Rün Okçusu Büyü Ağacı', 'Rune Archer Spell Tree', 'Efsunlu oklar, rün tuzakları kurma ve elementsel sihirli atışlar yapma üzerinde ustalık.', 'Mastery over enchanted arrows, setting rune traps, and unleashing elemental magic shots.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'Rün Ustası', 'Rune Master', 'Kadim metinlerin, savunma sembollerinin ve derin efsunların ustası; büyüyü ekipmanların ve savaş alanının dokusuna işler.', 'Master of ancient scripts, defensive wards, and profound enchantments, weaving magic into the very fabric of gear and the battlefield.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'Samurayın Yolu', 'Path of the Samurai', 'Samurayın Yolu; eşsiz katana ustalığına, onurlu bushido felsefesine ve yıldırım hızında iaijutsu tekniklerine odaklanır. Samuray mutlak bir hassasiyetle saldırır, çoğu zaman seçilen hedeflere peş peşe 2X (iki kat) yıkıcı vuruşlar yapar.', 'The Path of the Samurai focuses on unparalleled katana mastery, honorable bushido, and lightning-fast iaijutsu. The Samurai strikes with absolute precision, often hitting their chosen targets 2X with devastating consecutive strikes.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('1e5c47c8-85dc-4484-946d-bcae2f244810', 'Totemik Soy', 'Totemic Ancestry', 'Totemik büyü, atasal ruhların gücü ve yenilmiş canavarlardan özellikleri kalıcı olarak toplayıp kullanma yeteneğinin ustalığı.', 'Mastery of totemic magic, the power of ancestral spirits, and the ability to permanently harvest and utilize traits from defeated monsters.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('43245dbf-79d6-40d3-842e-a83237981c5d', 'Keskin Nişancı Sanatları', 'Sniper Arts', 'Aşırı menzil, hassas tekli atışlar, kamuflaj ve ölümcül yuva kurulumlarında ustalık.', 'Mastery of extreme range, precise single shots, camouflage, and deadly nest setups.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('5da817a6-abb7-45c1-9c73-4389b28a78c3', 'Ruh Çağırıcı', 'Soul Summoner', 'Ruhani düzlemin ustaları; ruhları manipüle eder, spektral lejyonları çağırır ve savaş alanını kontrol etmek için ruh zincirleri örerler.', 'Masters of the ethereal plane, manipulating souls, calling forth spectral legions, and weaving spirit chains to control the battlefield.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('065cd5a7-34a9-494d-a73b-1e29477689dd', 'Casus Cephaneliği', 'Spy Arsenal', 'Casus büyü ağacı, sızma, istihbarat toplama, gelişmiş teçhizat kullanımı ve gölgelerden saldırmaya odaklanır.', 'The Spy spell tree focuses on infiltration, gathering intel, utilizing advanced gadgets, and striking from the shadows.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('6131e7f8-eb6a-4082-b950-6d2035a1132a', 'Taşyürek', 'Stoneheart', 'Toprak büyüsü, eşsiz taşlaştırma savunması ve sarsılmaz savaş kararlılığı ustaları.', 'Masters of earth magic, unmatched petrification defense, and unbreakable combat resolve.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('c07d7bb7-58ea-4482-b353-a32427fda6c2', 'Fırtına Atıcısı Cephaneliği', 'Stormshot Arsenal', 'Savaş alanına aşırı hareketlilikle hükmetmek için yıldırım okları, gök gürültülü patlamalar ve rüzgar manipülasyonunda ustalık.', 'Mastery of lightning arrows, thunderous blasts, and wind manipulation to dominate the battlefield with extreme mobility.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('4919f48b-b5cd-4551-909c-27f05702c9d4', 'Altı Uçan Kılıç', 'Six Flying Swords', 'Telekinezi, taktik dizilimler ve psişik kenar yoluyla altı uçan kılıcı kontrol etme sanatında ustalaş.', 'Master the art of controlling six flying swords through telekinesis, tactical formations, and psychic edge.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'Aegis Yemini', 'Vow of the Aegis', 'Müttefiklere bağlanarak onların büyüsel yüklerini emer ve koruyucu ruhlar çağırarak nihai kalkan haline gelir.', 'Binds to allies, absorbing their magical burdens and manifesting protective guardian spirits to become the ultimate shield.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('22ae70c4-aef6-46fc-a142-86ef09dcef23', 'Üçlü Surlar', 'Triple Ramparts', 'Geçilmez bir savunma ve çok yönlü bir hücum sunan üç kalkanlı dövüş sanatının ustaları.', 'Masters of the three-shield combat style, offering impenetrable defense and versatile offense.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'İkiz Surlar', 'Twin Ramparts', 'Çifte kalkan ustalığı, aşılmaz savunmalar ve yıkıcı karşı saldırılar.', 'Mastery of dual shields, impenetrable defenses, and devastating counterattacks.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('518513b1-77f3-4b81-8332-2ed17be001b6', 'Öncü Birliğin Kalkanı', 'Aegis of the Vanguard', 'Müttefikleriniz için kırılmaz bir kalkan olarak durun, onların acısını emin ve her türlü fırtınayı atlatmak için savunmanızı güçlendirin.', 'Stand as the unbreakable shield for your allies, absorbing their pain and fortifying your defenses to weather any storm.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'Zehirkan Sanatları', 'Venomblood Arts', 'Ölümcül zehirler, toksik ortamlar ve sakat bırakıcı hastalıklar üzerinde ustalık.', 'Mastery over lethal poisons, toxic environments, and crippling afflictions.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('d5034784-1d26-4fdb-9603-ff3722d20713', 'Duvar Muhafızı', 'Wall Guard', 'Kullanıcıyı sarsılmaz bir kaleye dönüştüren efsanevi bir tank alt sınıfı. Aşırı savunma, devasa hasarları yok sayma ve savaş alanına demir atma konularında uzmanlaşmıştır.', 'A legendary tank subclass that transforms the user into an immovable fortress. Specializes in extreme defense, ignoring massive hits, and anchoring to the battlefield.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'Büyücünün Hamisi', 'Warlock''s Patronus', 'Başka dünyadan Haminin yıkıcı gücünü kanalize et. Kadim Güç, Antlaşma Büyüsü ve Karanlık Antlaşmalar üzerine uzmanlaşarak 3 tur boyunca mutlak hakimiyet kuracağın ani hasar pencereleri yarat.', 'Channel the devastating power of your otherworldly Patron. Specialize in Eldritch Power, Pact Magic, and Dark Pacts, creating burst damage windows where you reign supreme for 3 turns.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('f84d698e-3be4-474b-9413-2b42de08d563', 'Silah Azizi Yolu', 'Path of the Weapon Saint', 'Silah Azizi Yolu, savaşçının ruhunu doğrudan cephaneliğine bağlar. Silahları sadece birer araç olarak değil, kendi ruhlarının bir uzantısı olarak kullanırlar; fiziksel vuruşlarda, telekinetik yönlendirmede ve ruh parçalayan tekniklerde ustalaşırlar.', 'The Path of the Weapon Saint binds the soul of the warrior directly to their arsenal. They wield weapons not as mere tools, but as extensions of their own spirit, mastering physical strikes, telekinetic manipulation, and soul-rending techniques.');
INSERT INTO spell_trees (id, name_tr, name_en, description_tr, description_en) VALUES ('36f3ab60-f57a-443c-ae43-feab252aab30', 'Güreşçinin Kudreti', 'Wrestler''s Might', 'Yıkıcı kavramalar, yeri sarsan fırlatmalar ve ölümcül pes ettirmeler aracılığıyla yakın dövüş sanatında ustalaş.', 'Master the art of close-quarters combat through devastating grapples, earth-shattering throws, and lethal submissions.');
INSERT INTO spell_tree_assignments (id, spell_tree_id, class_key, subclass_key, min_level) VALUES ('491d71dd-7089-4c9f-a475-d55113183b02', 'ffea83e8-5a1b-4f55-85fe-8f9a23384f43', 'crafting', 'alchemist', 1);
