INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2635ce5d-1361-4953-8f06-c1e2aa5e3946', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_soul_bind', 'Ruh Bağı', 'Soul Bind', 'İki hedefin ruhunu birbirine bağlayarak, birine verilen hasarın diğerini de etkilemesini sağlar.', 'Binds the souls of two targets, causing damage dealt to one to affect the other.', 'Curse', 74, 780, 4, '{"dm_curse_of_aging"}', '{"x": 1735, "y": 2068}', '{"targets": "2 enemies", "shared_damage": "100%", "duration": "1 min"}', '🔗');
