INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb016339-1efc-4869-a1dc-bd9a5c951a4f', '57281a71-b651-4b8c-bdf6-e03b42842a62', 'dm_abyssal_chains', 'Hiçlik Zincirleri', 'Abyssal Chains', 'Hiçlikten fırlayan karanlık zincirler, birden fazla düşmanı ezici bir merkeze çeker.', 'Dark chains shoot from the abyss, pulling multiple enemies into a crushing center.', 'Cross-Branch', 65, 650, 4, '{"dm_shadow_fiend", "dm_soul_shatter"}', '{"x": -1039, "y": -600}', '{"damage": "8d8 necrotic", "radius": "20m", "effect": "pulls to center"}', '⚓');
