INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f50ed97c-e66a-4c62-bff0-c08f05d1b637', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_walk', 'Gölge Yürüyüşü', 'Shadow Walk', '5s boyunca gölge düzlemine geçerek tamamen hedef alınamaz hale gelin ve özgürce hareket edin.', 'Step into the shadow plane for 5s, becoming completely untargetable and able to move freely.', 'Shadowstep', 50, 450, 3, '{"dc_evasive_shadows"}', '{"x": 1688, "y": -974}', '{"duration": "5s", "status": "Untargetable"}', '🚶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0d82ed0-3c71-43f8-a384-fb69de45d71b', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_dark_momentum', 'Karanlık İvme', 'Dark Momentum', 'Pasif. En az 5m hareket etmek, bir sonraki saldırınızın hasarını %20 artırır.', 'Passive. Moving at least 5m increases the damage of your next attack by 20%.', 'Shadowstep', 55, 500, 3, '{"dc_shadow_swap"}', '{"x": 1905, "y": -1099}', '{"damage_bonus": "+20%", "trigger": "Move 5m"}', '🛹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('889e903c-002d-4e06-870d-dedfdfe21733', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_dance', 'Gölge Dansı', 'Shadow Dance', '5 saniye içinde art arda 3 kısa ışınlanma (her biri en fazla 10m) gerçekleştirin.', 'Chain up to 3 short teleports (max 10m each) within 5 seconds.', 'Shadowstep', 65, 700, 4, '{"dc_umbral_leap"}', '{"x": 2121, "y": -1224}', '{"charges": 3, "range": "10m", "duration": "5s"}', '💃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd9d17c1-8057-47e8-9de7-3b68c3a23dbc', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_living_shadow', 'Yaşayan Gölge', 'Living Shadow', 'Gölgeniz 10s boyunca sizden ayrılır, saldırılarınızı taklit eder ve hasarınızın %30''unu verir.', 'Your shadow detaches for 10s, mimicking your attacks and dealing 30% of your damage.', 'Shadowstep', 70, 750, 4, '{"dc_shadow_walk"}', '{"x": 2338, "y": -1349}', '{"duration": "10s", "damage_mimic": "30%"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ab3da57-6026-425d-96fa-81d1f01e2c43', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_void_step', 'Hiçlik Adımı', 'Void Step', 'Büyülü bariyerleri ve korumaları aşan, güçlü bir 30m ışınlanma.', 'A powerful 30m teleport that bypasses magical barriers and wards.', 'Shadowstep', 75, 800, 4, '{"dc_shadow_dance"}', '{"x": 2554, "y": -1474}', '{"range": "30m", "special": "Bypasses barriers"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8bb51432-09a1-4e19-826d-4cdf30201c05', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_omnipresence', 'Her Yerde Olma', 'Omnipresence', '50m içindeki herhangi bir gölgenin konumuna anında ışınlanın.', 'Teleport instantly to the location of any cast shadow within 50m.', 'Shadowstep', 78, 850, 4, '{"dc_dark_momentum"}', '{"x": 2771, "y": -1599}', '{"range": "50m"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d40645c-ac14-4cc5-8147-3ba9153b85f6', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_realm_of_shadows', 'Gölgeler Diyarı', 'Realm of Shadows', 'Ulti. 8s boyunca hedef alınamaz olun. Bu süre zarfında ışınlanma bekleme süreleriniz sıfıra iner ve sonsuz 15m sıçramalar yapmanıza olanak tanır.', 'Ultimate. Become untargetable for 8s. During this time, your teleport cooldowns are zero, allowing infinite 15m leaps.', 'Shadowstep', 90, 1200, 5, '{"dc_void_step", "dc_omnipresence"}', '{"x": 2987, "y": -1724}', '{"duration": "8s", "teleport_range": "15m", "cooldown_reduction": "100%"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee913f8e-4304-453f-aba9-166758d3f233', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_gloom_veil', 'Karanlık Örtüsü', 'Gloom Veil', '10s süren 5m yarıçapında büyülü bir karanlık küresi yaratın.', 'Create a 5m radius sphere of magical darkness lasting 10s.', 'Gloom', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"radius": "5m", "duration": "10s"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('62f0e9d9-eb2e-4211-9dd5-dac81bff10a5', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_blinding_shade', 'Kör Eden Gölge', 'Blinding Shade', 'Bir hedefin gözlerine gölgelerle vurarak onları 3s boyunca kör edin.', 'Strike a target''s eyes with shadows, blinding them for 3s.', 'Gloom', 5, 75, 1, '{}', '{"x": 289, "y": 344}', '{"duration": "3s", "status": "Blind"}', '🕶️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b5630198-1e40-46de-bb61-4326bed2c22d', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_snare', 'Gölge Kapanı', 'Shadow Snare', 'Bir gölgeye hedefin bacaklarına dolanmasını emrederek onları 4s boyunca yerine sabitleyin.', 'Command a shadow to wrap around a target''s legs, rooting them in place for 4s.', 'Gloom', 10, 100, 1, '{}', '{"x": 449, "y": 536}', '{"duration": "4s", "status": "Root"}', '🪢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('120f15a0-d9c3-4855-bf12-ae6bfb677f07', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_creeping_dark', 'Sürünen Karanlık', 'Creeping Dark', 'Pasif. Karanlık Örtüsü her saniye 2m genişler ve içindeki düşmanları %30 yavaşlatır.', 'Passive. Your Gloom Veil expands by 2m per second and slows enemies inside by 30%.', 'Gloom', 25, 200, 2, '{"dc_gloom_veil"}', '{"x": 610, "y": 727}', '{"expansion_rate": "2m/s", "slow": "30%"}', '🦑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8a01e8c2-6cdd-499b-927d-deb0cf3de07f', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_night_terror', 'Gece Terörü', 'Night Terror', 'Pasif. Büyülü karanlığınızın içindeki düşmanların her saniye %20 ihtimalle 2s boyunca korkutulma şansı vardır.', 'Passive. Enemies inside your magical darkness have a 20% chance each second to be feared for 2s.', 'Gloom', 30, 225, 2, '{"dc_blinding_shade"}', '{"x": 771, "y": 919}', '{"fear_chance": "20%/s", "fear_duration": "2s"}', '😱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35d67c0f-c174-4b88-ba79-2f579ca3d49b', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_smokescreen', 'Sis Perdesi', 'Smokescreen', '8m yarıçaplı bir alan yaratan gölge bombası atın. İçerdeki düşmanlar 5s boyunca kör olur.', 'Throw a shadow bomb that creates an 8m radius zone. Enemies inside are blinded for 5s.', 'Gloom', 35, 250, 2, '{"dc_shadow_snare"}', '{"x": 932, "y": 1110}', '{"radius": "8m", "duration": "5s", "status": "Blind"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0856366-5712-4ce0-9f2f-61c790fd1e5a', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_suffocating_shadows', 'Boğucu Gölgeler', 'Suffocating Shadows', 'Pasif. Karanlığınızın içinde duran düşmanlar saniyede 3d6 gölge hasarı alır.', 'Passive. Enemies standing in your darkness take 3d6 shadow damage per second.', 'Gloom', 45, 400, 3, '{"dc_creeping_dark"}', '{"x": 1092, "y": 1302}', '{"damage": "3d6/s", "type": "Shadow"}', '😵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fcb6b171-93df-4802-9028-7a5658dc6763', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_gloom_ward', 'Karanlık Kalkanı', 'Gloom Ward', 'Herhangi bir büyülü karanlığın içinde dururken 50 HP hasar emme kalkanı kazanın.', 'Gain a 50 HP damage absorption shield while standing inside any magical darkness.', 'Gloom', 50, 450, 3, '{"dc_night_terror"}', '{"x": 1253, "y": 1493}', '{"shield": "50 HP"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29d424cc-2adc-4fb1-9c36-7db14d8b9cb2', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_tendrils', 'Gölge Dokunaçları', 'Shadow Tendrils', '10m''lik bir alanda yerden gölgeler fışkırtarak düşmanları yere sabitleyin ve onları merkeze doğru 3m çekin.', 'Erupt shadows from the ground in a 10m area, rooting enemies and pulling them 3m towards the center.', 'Gloom', 55, 500, 3, '{"dc_smokescreen"}', '{"x": 1414, "y": 1685}', '{"radius": "10m", "pull_distance": "3m", "status": "Root"}', '🐙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('03ddf197-5da8-47a7-97ad-2218f325683b', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_pitch_black', 'Zifiri Karanlık', 'Pitch Black', 'Seviye 3 veya daha düşük tüm ışık büyülerini dağıtan 15m''lik mutlak bir karanlık alanı yaratın.', 'Create a 15m area of absolute darkness that dispels all light magic of Tier 3 or lower.', 'Gloom', 65, 700, 4, '{"dc_suffocating_shadows"}', '{"x": 1574, "y": 1876}', '{"radius": "15m", "special": "Dispels Light"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60510f74-ee9f-49df-a014-c464b476432b', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_mind_eclipse', 'Zihin Tutulması', 'Mind Eclipse', '10m''lik bir konideki tüm düşmanları 6s boyunca susturan ve kör eden bir karanlık dalgası serbest bırakın.', 'Unleash a wave of darkness that silences and blinds all enemies in a 10m cone for 6s.', 'Gloom', 70, 750, 4, '{"dc_gloom_ward"}', '{"x": 1735, "y": 2068}', '{"range": "10m cone", "duration": "6s", "status": "Blind & Silence"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('36c0cc0c-ab7b-4ed8-81a4-ddf892d3abf8', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_gloom_fiend', 'Karanlık İblisi', 'Gloom Fiend', 'Kör edilmiş hedeflere öncelik vererek düşmanlara saldıran korkunç bir gölge varlığını 15s boyunca çağırın.', 'Summon a terrifying shadow entity for 15s that attacks enemies, prioritizing blinded targets.', 'Gloom', 75, 800, 4, '{"dc_shadow_tendrils"}', '{"x": 1896, "y": 2259}', '{"duration": "15s", "summon": "Gloom Fiend"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0569ede0-9866-42c9-aab1-734799b7a0a4', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_devouring_dark', 'Yutan Karanlık', 'Devouring Dark', 'Pasif. Karanlık alanlarınız düşmanların yaşam gücünü tüketerek, içeride kaldıkları her saniye için maksimum canlarını %2 azaltır.', 'Passive. Your darkness areas drain the life force of enemies, reducing their max HP by 2% per second they remain inside.', 'Gloom', 78, 850, 4, '{"dc_pitch_black"}', '{"x": 2056, "y": 2451}', '{"max_hp_drain": "2%/s"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('892ccf35-b983-4a7b-a2a6-32dd16090514', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_eclipse_of_despair', 'Umutsuzluk Tutulması', 'Eclipse of Despair', 'Ulti. 15s boyunca 30m yarıçapında devasa bir karanlık çağırın. İçerdeki tüm düşmanlar kör olur, susturulur, %80 yavaşlar ve saniyede 8d8 gölge hasarı alır.', 'Ultimate. Summon a massive 30m radius darkness for 15s. All enemies inside are blinded, silenced, slowed by 80%, and suffer 8d8 shadow damage per second.', 'Gloom', 90, 1200, 5, '{"dc_devouring_dark", "dc_mind_eclipse"}', '{"x": 2217, "y": 2642}', '{"radius": "30m", "duration": "15s", "slow": "80%", "damage": "8d8/s"}', '🌘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98c982b7-066b-4c08-9f1b-df997212a816', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_strike', 'Gölge Vuruşu', 'Shadow Strike', 'Gölgeyle aşılanmış hızlı bir yakın dövüş saldırısı, silah hasarı artı 2d6 gölge hasarı verir.', 'A swift melee attack infused with shadow, dealing weapon damage plus 2d6 shadow damage.', 'Execution', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "Weapon + 2d6"}', '🤺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2445afe4-84f1-42d5-a48f-9e17331e9bcd', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_backstab', 'Arkadan Bıçaklama', 'Backstab', 'Pasif. Bir düşmana arkadan vurmak, verilen toplam hasarı %50 artırır.', 'Passive. Striking an enemy from behind increases the total damage dealt by 50%.', 'Execution', 5, 75, 1, '{}', '{"x": -289, "y": 344}', '{"damage_bonus": "50%"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2313ee75-fb9a-4ad0-89ad-e7c964f619d3', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_blood_in_the_dark', 'Karanlıktaki Kan', 'Blood in the Dark', 'Pasif. Yakın dövüş kritik vuruşlarınız, 3s boyunca saniyede 1d6 hasar veren bir kanama etkisi uygular.', 'Passive. Your melee critical hits apply a bleeding effect dealing 1d6 damage per second for 3s.', 'Execution', 10, 100, 1, '{}', '{"x": -449, "y": 536}', '{"bleed_damage": "1d6/s", "duration": "3s"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0428e94d-51ea-4047-9404-85202c33b9a9', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_throat_slitter', 'Boğaz Kesen', 'Throat Slitter', 'Pasif. Kör, sersemlemiş veya sizden habersiz düşmanlara karşı +%30 kritik vuruş şansı kazanın.', 'Passive. Gain +30% critical hit chance against enemies who are blinded, stunned, or unaware of you.', 'Execution', 25, 200, 2, '{"dc_shadow_strike"}', '{"x": -610, "y": 727}', '{"crit_chance": "+30%"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b816d517-cd4a-47f1-b993-149a068c305c', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_phantom_blades', 'Hayalet Bıçaklar', 'Phantom Blades', 'Her biri 2d8 delici gölge hasarı veren, 15m uzağa kadar 3 gölge dövme hançer fırlatın.', 'Throw 3 shadow-forged daggers up to 15m away, each dealing 2d8 piercing shadow damage.', 'Execution', 30, 225, 2, '{"dc_backstab"}', '{"x": -771, "y": 919}', '{"projectiles": 3, "damage": "2d8 per hit", "range": "15m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3e029ae7-dd02-4e09-9b5b-d1b330ef849d', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_coup_de_grace', 'Son Darbe', 'Coup de Grace', 'Pasif. Saldırılarınız, maksimum canı %30''un altında olan hedeflere %40 daha fazla hasar verir.', 'Passive. Your attacks deal 40% more damage to targets with less than 30% of their maximum HP.', 'Execution', 35, 250, 2, '{"dc_blood_in_the_dark"}', '{"x": -932, "y": 1110}', '{"damage_multiplier": "+40%", "condition": "<30% HP"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1cf91d3-2569-49fd-a43b-4045acfee3b0', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_pierce', 'Gölge Delici', 'Shadow Pierce', 'Pasif. Gölge aşılanmış saldırılarınız, hedefin fiziksel zırhının %50''sini yok sayar.', 'Passive. Your shadow-infused attacks ignore 50% of the target''s physical armor.', 'Execution', 45, 400, 3, '{"dc_throat_slitter"}', '{"x": -1092, "y": 1302}', '{"armor_penetration": "50%"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5978f192-54f2-4529-8e72-c532fff01253', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_lethal_precision', 'Ölümcül İsabet', 'Lethal Precision', 'Pasif. Kritik hasar çarpanınız ek olarak 0.5x artar.', 'Passive. Your critical damage multiplier is increased by an additional 0.5x.', 'Execution', 50, 450, 3, '{"dc_phantom_blades"}', '{"x": -1253, "y": 1493}', '{"crit_damage": "+0.5x"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('038d04d2-26b1-43ca-b03e-07ab555d4086', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_assassins_mark', 'Suikastçının İşareti', 'Assassin''s Mark', 'Bir hedefi 10s boyunca işaretleyin. Tüm saldırılarınızdan %15 daha fazla hasar alırlar.', 'Mark a target for 10s. They take 15% increased damage from all your attacks.', 'Execution', 55, 500, 3, '{"dc_coup_de_grace"}', '{"x": -1414, "y": 1685}', '{"damage_taken": "+15%", "duration": "10s"}', '✖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a5160400-1bd4-4bd3-a32c-7c512babff24', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_gloom_blade', 'Karanlık Kılıcı', 'Gloom Blade', 'Silahınızı 10s boyunca saf gölgeye dönüştürün. Yakın dövüş menzilini 3m''ye çıkarır ve tüm hasarı saf gölge hasarına çevirir.', 'Transform your weapon into pure shadow for 10s. Increases melee range to 3m and converts all damage to pure shadow damage.', 'Execution', 65, 700, 4, '{"dc_shadow_pierce"}', '{"x": -1574, "y": 1876}', '{"duration": "10s", "melee_range": "3m", "damage_type": "Shadow"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fec1c46c-3372-4905-9f8f-f2d83d760131', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_heartseeker', 'Kalp Arayan', 'Heartseeker', '5s içindeki bir sonraki saldırınız garantili bir kritik vuruştur ve hedefi 2s sersemletir.', 'Your next attack within 5s is a guaranteed critical hit and stuns the target for 2s.', 'Execution', 70, 750, 4, '{"dc_lethal_precision"}', '{"x": -1735, "y": 2068}', '{"crit_chance": "100%", "stun_duration": "2s"}', '💘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b39629d9-7fc6-492a-8019-e64eaeac3edd', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_dark_harvest', 'Karanlık Hasat', 'Dark Harvest', 'Pasif. Bir düşmana ölümcül darbe indirmek, maksimum HP''nizin %15''ini geri yükler.', 'Passive. Landing a killing blow on an enemy restores 15% of your maximum HP.', 'Execution', 75, 800, 4, '{"dc_assassins_mark"}', '{"x": -1896, "y": 2259}', '{"heal": "15% Max HP"}', '🌾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('69c0b313-cc04-4ae5-8d76-c238274f781e', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_silent_death', 'Sessiz Ölüm', 'Silent Death', 'Pasif. Kritik vuruşların patron olmayan düşmanları anında öldürme ihtimali %10''dur.', 'Passive. Critical hits have a 10% chance to instantly kill non-boss enemies.', 'Execution', 78, 850, 4, '{"dc_gloom_blade"}', '{"x": -2056, "y": 2451}', '{"instant_kill_chance": "10%"}', '🤫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('745b29f0-ecc8-438a-a6a4-7e6c0bcca627', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_guillotine', 'Gölge Giyotini', 'Shadow Guillotine', 'Ulti. 10d20 gölge hasarı veren yıkıcı tek bir vuruş yapın. Hedefin canı %20''nin altına düşerse, anında infaz edilir.', 'Ultimate. Deliver a devastating single strike dealing 10d20 shadow damage. If the target drops below 20% max HP, they are instantly executed.', 'Execution', 90, 1200, 5, '{"dc_heartseeker", "dc_silent_death"}', '{"x": -2217, "y": 2642}', '{"damage": "10d20", "execute_threshold": "20% Max HP"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f6ac32ae-c730-4f2a-a055-858bf8735bdc', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_gloom_step', 'Karanlık Adımı', 'Gloom Step', '40m içindeki herhangi bir aktif karanlık alanınıza anında ışınlanın. Bekleme süresi sadece 2s''dir.', 'Teleport instantly into any of your active darkness areas within 40m. Cooldown is only 2s.', 'Cross-Branch', 38, 300, 2, '{"dc_phantom_step", "dc_gloom_veil"}', '{"x": -173, "y": -100}', '{"range": "40m", "cooldown": "2s"}', '🚪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8ec9a754-718b-4995-bd54-8c3cedeac08b', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_executioners_shade', 'İnfazcının Gölgesi', 'Executioner''s Shade', 'Pasif. Bir düşmanı öldürdükten sonra, 5s içindeki bir sonraki ışınlanma büyünüz mana/dayanıklılık harcamaz ve anında gerçekleşir.', 'Passive. Upon killing an enemy, your next teleportation spell within 5s costs no mana/stamina and is instantaneous.', 'Cross-Branch', 58, 500, 3, '{"dc_backstab", "dc_phantom_step"}', '{"x": -389, "y": -225}', '{"duration": "5s", "resource_cost": "0"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7db4ac31-7acc-4582-98c4-2e5257aeacd5', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_blind_side', 'Kör Nokta', 'Blind Side', 'Pasif. Kritik vuruşlarınız kör edilmiş düşmanlara karşı iki kat hasar verir.', 'Passive. Your critical strikes deal double damage against blinded enemies.', 'Cross-Branch', 58, 500, 3, '{"dc_blinding_shade", "dc_throat_slitter"}', '{"x": -606, "y": -350}', '{"damage_multiplier": "2x"}', '🙈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0bde64c1-735b-4ea5-b5bd-afbd30ce7688', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_shadow_trap', 'Gölge Tuzağı', 'Shadow Trap', 'Her ışınlandığınızda geride 4m''lik bir tuzak bırakın. Karanlıkta tetiklenirse, 3d10 hasar vererek patlar ve 2s kör eder.', 'Whenever you teleport, leave behind a 4m trap. If triggered in darkness, it explodes for 3d10 damage and blinds for 2s.', 'Cross-Branch', 72, 900, 4, '{"dc_umbral_leap", "dc_smokescreen"}', '{"x": -822, "y": -475}', '{"radius": "4m", "damage": "3d10", "blind_duration": "2s"}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e7f1ffc1-bcd6-4de3-a656-7de2c7779811', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_umbral_assassin', 'Karanlık Suikastçı', 'Umbral Assassin', 'Pasif. Büyülü karanlığın içindeyken, +%20 hareket hızı ve +%25 saldırı hızı kazanın.', 'Passive. While inside magical darkness, gain +20% movement speed and +25% attack speed.', 'Cross-Branch', 75, 900, 4, '{"dc_pitch_black", "dc_shadow_pierce"}', '{"x": -1039, "y": -600}', '{"movement_speed": "+20%", "attack_speed": "+25%"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('92fd4df6-e4a1-4720-9264-3ba68f68bc5d', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_death_from_nowhere', 'Hiçlikten Gelen Ölüm', 'Death From Nowhere', 'Pasif. Işınlandıktan sonraki 1s içinde yapılan saldırılar +%100 hasar verir.', 'Passive. Attacks made within 1s after teleporting deal +100% damage.', 'Cross-Branch', 79, 900, 4, '{"dc_shadow_dance", "dc_assassins_mark"}', '{"x": -1255, "y": -725}', '{"damage_bonus": "+100%", "duration": "1s"}', '🪦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9527e1c7-943b-4166-90ec-55db449a5d9f', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_nightfall_carnage', 'Alacakaranlık Katliamı', 'Nightfall Carnage', '30m içindeki 5''e kadar kör edilmiş düşmana anında ışınlanıp saldırın, her birine 8d10 hasar verin.', 'Instantly teleport to and strike up to 5 blinded enemies within 30m, dealing 8d10 damage to each.', 'Cross-Branch', 85, 1400, 5, '{"dc_void_step", "dc_pitch_black", "dc_heartseeker"}', '{"x": -1472, "y": -850}', '{"targets": 5, "range": "30m", "damage": "8d10"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4754ffdb-8a44-4e6c-8269-f285c68188ac', 'fa5e3592-4f94-4225-b874-5b543f329214', 'dc_absolute_void_assassination', 'Mutlak Hiçlik İnfazı', 'Absolute Void Assassination', 'Büyük Ulti. 50m''lik bir alanı mutlak karanlığa gömer ve zamanı 3s boyunca durdurur. Hedefler arasında dağıtılan, her biri 5d10 hasar veren ardışık 15 garantili kritik vuruş serbest bırakırsınız.', 'Grand Ultimate. Plunges a 50m area into absolute darkness and stops time for 3s. You unleash 15 consecutive guaranteed critical strikes, each dealing 5d10 damage, distributed among targets.', 'Cross-Branch', 100, 1500, 5, '{"dc_realm_of_shadows", "dc_eclipse_of_despair", "dc_shadow_guillotine"}', '{"x": -1688, "y": -975}', '{"radius": "50m", "duration": "3s", "strikes": 15, "damage": "5d10 per strike"}', '🖤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aead6aed-f6dc-401a-ba5d-50f2166b9013', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_summon_wolf', 'Kurt Çağır', 'Summon Wolf', 'Sizinle birlikte savaşması için sadık bir kurt yoldaşı çağırır. 20m komuta menzili içerisinde her saldırıda 1d8 fiziksel hasar verir.', 'Summons a loyal wolf companion to fight alongside you. Deals 1d8 physical damage per attack within a 20m command range.', 'Animal', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8 physical", "range": "20m", "duration": "Until dead"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('385d0214-cf07-4594-9add-7d12c3431b24', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_eagle_eye', 'Kartal Gözü', 'Eagle Eye', 'Bir yırtıcı kuşun görüş yeteneğini bağışlar. Algı zarlarına +5 bonus ekler ve 1 saat boyunca net görüşü 100m''ye kadar uzatır.', 'Grants the vision of a bird of prey. Adds +5 to Perception checks and extends clear vision up to 100m for 1 hour.', 'Animal', 5, 75, 1, '{"dr_summon_wolf"}', '{"x": 389, "y": -224}', '{"bonus": "+5 Perception", "range": "100m", "duration": "1 hour"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('047195ff-dd84-417e-9e24-bc6207e7c4ca', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_beast_speech', 'Canavar Dili', 'Beast Speech', '1 saat boyunca hayvanlarla iletişim kurmanızı ve onları anlamanızı sağlayarak barışçıl müzakerelere veya bilgi toplamaya olanak tanır.', 'Allows you to comprehend and communicate with beasts for 1 hour, enabling peaceful negotiations or gathering information.', 'Animal', 10, 100, 1, '{"dr_eagle_eye"}', '{"x": 606, "y": -349}', '{"range": "Self", "duration": "1 hour"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a0a9880-5711-41c0-8fa1-1a6332aee025', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_swarm_of_bees', 'Arı Sürüsü', 'Swarm of Bees', '10m yarıçaplı bir alanda vızıldayan bir arı sürüsü çağırarak içerideki düşmanlara 2d6 delici hasar verir.', 'Summons a buzzing swarm of bees in a 10m radius, dealing 2d6 piercing damage to enemies within.', 'Animal', 15, 125, 1, '{"dr_beast_speech"}', '{"x": 822, "y": -474}', '{"damage": "2d6 piercing", "radius": "10m", "range": "15m"}', '🐝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d75f6103-0cb4-46b5-b876-6de204e29778', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_bear_strength', 'Ayı Gücü', 'Bear Strength', 'Bir müttefiki ayının ham gücüyle doldurarak 10 dakika boyunca Güç değerine +4 bonus ve Atletizm zarlarında avantaj sağlar.', 'Infuses an ally with the raw power of a bear, granting a +4 bonus to Strength and advantage on Athletics checks for 10 minutes.', 'Animal', 22, 200, 2, '{"dr_swarm_of_bees"}', '{"x": 1039, "y": -599}', '{"buff": "+4 Strength", "duration": "10 minutes", "range": "Touch"}', '🐻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7232926-d224-488f-aeff-0cb5abb08997', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_summon_panther', 'Panter Çağır', 'Summon Panther', 'Görünmez olabilen ve sürpriz saldırılar yaparak 2x 1d10 kesici hasar veren sinsi bir panter çağırır.', 'Calls forth a stealthy panther that can turn invisible and execute surprise attacks dealing 2x 1d10 slashing damage.', 'Animal', 28, 250, 2, '{"dr_bear_strength"}', '{"x": 1255, "y": -724}', '{"damage": "2x 1d10 slashing", "stealth": "+8", "duration": "Until dead"}', '🐆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('96aa5436-9d24-4399-968f-34b5d5306723', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_animal_bond', 'Hayvan Bağı', 'Animal Bond', '30m uzaklığa kadar çağrılmış bir canavarla mistik bir bağ kurarak alınan hasarın yarısını ve duyusal girdileri paylaşır.', 'Forges a mystic link with a summoned beast up to 30m away, sharing half of the damage taken and sharing sensory inputs.', 'Animal', 35, 300, 2, '{"dr_summon_panther"}', '{"x": 1472, "y": -849}', '{"range": "30m", "damage_share": "50%", "duration": "1 hour"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ac2b0ca2-c85f-464f-b0fe-03eb2811d93d', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_summon_dire_wolf', 'Ulu Kurt Çağır', 'Summon Dire Wolf', 'Savaş alanına devasa bir ulu kurt çağırır. Isırığı 3d8 delici hasar verir ve hedefin yere düşmemek için Güç kurtarış zarı atmasını gerektirir.', 'Summons a massive dire wolf to the battlefield. Its bite deals 3d8 piercing damage and forces a Strength save to avoid being knocked prone.', 'Animal', 42, 400, 3, '{"dr_animal_bond"}', '{"x": 1688, "y": -974}', '{"damage": "3d8 piercing", "condition": "Prone on failed save", "range": "20m"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ad26326-d4ce-42e6-b177-cb702dc145ac', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_pack_tactics', 'Sürü Taktikleri', 'Pack Tactics', '15m menzil içindeki müttefikler, hedefin 2m yakınında en az bir müttefikleri varsa o hedefe karşı yakın dövüş saldırılarında avantaj kazanır.', 'Allies within 15m gain advantage on melee attack rolls against a creature if at least one of their allies is within 2m of the target.', 'Animal', 48, 450, 3, '{"dr_summon_dire_wolf"}', '{"x": 1905, "y": -1099}', '{"radius": "15m", "buff": "Advantage on melee attacks", "duration": "10 minutes"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c5b4822-b945-4949-8312-c77bbbe0c1fd', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_call_of_the_wild', 'Yabani Çağrı', 'Call of the Wild', 'Yankılanan bir uluma salıvererek düşmanlarınızı 5 dakika boyunca durmaksızın avlayacak 1d4 ruhani kurt çağırır.', 'Releases a resonant howl, summoning 1d4 spectral wolves that relentlessly hunt your enemies for 5 minutes.', 'Animal', 55, 500, 3, '{"dr_pack_tactics"}', '{"x": 2121, "y": -1224}', '{"summons": "1d4 wolves", "duration": "5 minutes", "range": "30m"}', '🌕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4fd321c7-a97b-4b56-a2be-9693cc0867a0', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_summon_grizzly', 'Bozayı Çağır', 'Summon Grizzly', '250 HP''ye sahip korkutucu bir bozayı çağırır. Vahşi pençe saldırıları 4d10 kesici hasar verir.', 'Calls a terrifying grizzly bear with 250 HP. Its ferocious maul attacks deal 4d10 slashing damage.', 'Animal', 65, 700, 4, '{"dr_call_of_the_wild"}', '{"x": 2338, "y": -1349}', '{"damage": "4d10 slashing", "hp": "250", "duration": "Until dead"}', '🐻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('89dc73db-c642-4bc6-bf81-f9e689270be3', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_beast_frenzy', 'Canavar Çılgınlığı', 'Beast Frenzy', 'Tüm çağrılmış canavarlarınızı kana susamış bir çılgınlığa sokarak onlara +2 Zırh Sınıfı, iki kat hareket hızı ve tur başına ekstra bir saldırı sağlar.', 'Sends all your summoned beasts into a bloodthirsty frenzy, granting them +2 AC, double movement speed, and an extra attack per turn.', 'Animal', 75, 850, 4, '{"dr_summon_grizzly"}', '{"x": 2554, "y": -1474}', '{"buff": "+2 AC, 2x speed, +1 attack", "duration": "1 minute", "radius": "30m"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d5b53146-4325-4c67-944b-60ab8da3916a', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_stampede', 'İzdiham', 'Stampede', '30m uzunluğunda bir hatta hücum eden hayalet bir gergedan sürüsü çağırarak 8d10 ezici hasar verir ve hedefleri yere serer.', 'Summons a phantom herd of spectral rhinos that charge in a 30m long line, dealing 8d10 bludgeoning damage and knocking targets prone.', 'Animal', 85, 1100, 5, '{"dr_beast_frenzy"}', '{"x": 2771, "y": -1599}', '{"damage": "8d10 bludgeoning", "area": "30m line", "condition": "Prone"}', '🦏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce70b6f1-b819-45f2-97b7-4379ec692aea', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_apex_predator_ult', 'Zirve Avcısı', 'Apex Predator', '500 HP''ye sahip efsanevi bir mitolojik canavar çağırır. Saldırıları düşmanlara korku salar ve tur başına 6d12 hasar verir.', 'Summons a legendary beast of myth with 500 HP. Its attacks strike fear into enemies and deal 6d12 damage per turn.', 'Animal', 95, 1400, 5, '{"dr_stampede"}', '{"x": 2987, "y": -1724}', '{"hp": "500", "damage": "6d12 mixed", "duration": "Until dead"}', '🦖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b167c3ce-6239-4783-b7a7-6c556bf67e76', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_entangling_vines', 'Dolanmayan Sarmaşıklar', 'Entangling Vines', '20m uzağa kadar 5m yarıçaplı bir alanda yerden sarmaşıklar fışkırtarak hedefleri kısıtlar ve tur başına 1d6 hasar verir.', 'Causes vines to erupt from the ground in a 5m radius up to 20m away, restraining targets and dealing 1d6 damage per turn.', 'Nature', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d6/turn", "radius": "5m", "range": "20m", "condition": "Restrained"}', '🌿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ac42bdf-5eec-4b32-8e2e-a8ed4d9e2914', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_poison_spores', 'Zehirli Sporlar', 'Poison Spores', '4m yarıçapında zehirli spor bulutu salar. Düşmanlar 2d8 zehir hasarı alır ve 1 dakika boyunca zehirlenir.', 'Releases a cloud of toxic spores in a 4m radius. Enemies suffer 2d8 poison damage and are poisoned for 1 minute.', 'Nature', 8, 75, 1, '{"dr_entangling_vines"}', '{"x": 289, "y": 344}', '{"damage": "2d8 poison", "radius": "4m", "duration": "1 minute"}', '🍄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('446a0bf7-78a2-467a-8799-0c21cf3597e9', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_healing_bloom', 'İyileştiren Çiçek', 'Healing Bloom', 'Büyülü bir çiçeğin açmasını sağlayarak 6m yarıçapındaki müttefikleri 1d8 + Bilgelik değiştiricisi kadar HP iyileştiren yenileyici bir büyü yayar.', 'Causes a magical flower to bloom, radiating restorative magic that heals allies within a 6m radius for 1d8 + Wisdom modifier HP.', 'Nature', 12, 100, 1, '{"dr_poison_spores"}', '{"x": 449, "y": 536}', '{"healing": "1d8 + Wisdom", "radius": "6m", "range": "15m"}', '🌸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a2aa208c-183d-43ef-98b8-b846f3462cfc', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_razor_leaf', 'Jilet Yaprak', 'Razor Leaf', 'Büyüyle sertleştirilmiş yaprak yağmuru fırlatarak hedefleri keser ve 25m uzağa kadar 3d6 kesici hasar verir.', 'Hurls a barrage of magically hardened leaves that slice through targets, dealing 3d6 slashing damage up to 25m away.', 'Nature', 18, 125, 1, '{"dr_healing_bloom"}', '{"x": 610, "y": 727}', '{"damage": "3d6 slashing", "range": "25m"}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('981f8ee3-2fc2-4892-a636-c805b5d18a08', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_bark_shield', 'Ağaç Kabuğu Kalkanı', 'Bark Shield', 'Hedefin derisini kalın büyülü bir ağaç kabuğu ile kaplayarak 1 saat boyunca Zırh Sınıfına +3 bonus sağlar.', 'Encrusts the target''s skin in thick magical bark, granting a +3 bonus to Armor Class for 1 hour.', 'Nature', 25, 200, 2, '{"dr_razor_leaf"}', '{"x": 771, "y": 919}', '{"buff": "+3 AC", "duration": "1 hour", "range": "Touch"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64644f25-df1f-43b0-8d34-d4fc0d0bc059', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_strangling_roots', 'Boğan Kökler', 'Strangling Roots', 'Topraktan fırlayan kökler 10m içindeki tek bir hedefi ezerek 3d8 ezici hasar verir ve onları yere sabitler.', 'Roots burst from the earth to crush a single target within 10m, dealing 3d8 bludgeoning damage and rooting them in place.', 'Nature', 30, 250, 2, '{"dr_bark_shield"}', '{"x": 932, "y": 1110}', '{"damage": "3d8 bludgeoning", "range": "10m", "condition": "Rooted"}', '🌳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('51ae740b-2ce6-4905-851c-8e9835f32e93', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_nature_bounty', 'Doğanın Lütfu', 'Nature''s Bounty', '10 kişi için yeterli taze yiyecek ve saf su yaratır. Bu büyülü ziyafeti yemek, savaş dışında 2d8 HP iyileştirir.', 'Conjures fresh food and pure water sufficient for 10 people. Eating this magical feast heals 2d8 HP outside of combat.', 'Nature', 38, 300, 2, '{"dr_strangling_roots"}', '{"x": 1092, "y": 1302}', '{"healing": "2d8", "capacity": "10 people", "duration": "Instant"}', '🍎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('32c1d10d-5df9-4e11-80a1-acc492ba6c1e', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_thorn_burst', 'Diken Patlaması', 'Thorn Burst', '10m yarıçaplı bir alanda acımasız dikenlerin şiddetli bir patlamasına neden olarak içerideki tüm düşmanlara 4d8 delici hasar verir.', 'Causes a violent explosion of vicious thorns in a 10m radius, inflicting 4d8 piercing damage to all enemies caught within.', 'Nature', 45, 400, 3, '{"dr_nature_bounty"}', '{"x": 1253, "y": 1493}', '{"damage": "4d8 piercing", "radius": "10m", "range": "20m"}', '🌵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d2a04a5-da02-44b3-ae8a-758dd185a317', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_toxic_miasma', 'Zehirli Miasma', 'Toxic Miasma', '15m yarıçaplı bir alanda nefes alan düşmanlara 1 dakika boyunca tur başına 5d6 zehir hasarı veren kalın, ölümcül bir sis yaratır.', 'Creates a thick, deadly fog in a 15m radius that deals 5d6 poison damage per turn to breathing enemies for 1 minute.', 'Nature', 50, 450, 3, '{"dr_thorn_burst"}', '{"x": 1414, "y": 1685}', '{"damage": "5d6 poison/turn", "radius": "15m", "duration": "1 minute"}', '☣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('79bf3393-7cd4-444b-8d44-0d7301d7af36', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_living_wall', 'Yaşayan Duvar', 'Living Wall', '15m uzunluğunda, 3m kalınlığında aşılmaz, yoğun dikenli sarmaşıklardan oluşan bir duvar filizlendirir. Her 3m''lik bölüm 100 HP''ye sahiptir.', 'Sprouts a 15m long, 3m thick impenetrable wall of dense thorny vines. Each 3m section has 100 HP.', 'Nature', 58, 500, 3, '{"dr_toxic_miasma"}', '{"x": 1574, "y": 1876}', '{"hp": "100 per 3m section", "dimensions": "15m x 3m", "range": "30m"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c9615d5b-ae00-4767-83fa-a8eaad1d5eb8', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_earthquake', 'Deprem', 'Earthquake', '30m yarıçaplı bir alanda yeri çatlatır. 8d6 ezici hasar verir, alanı zorlu araziye dönüştürür ve hedefleri yere serer.', 'Fractures the ground in a 30m radius. Deals 8d6 bludgeoning damage, turns the area into difficult terrain, and knocks targets prone.', 'Nature', 68, 700, 4, '{"dr_living_wall"}', '{"x": 1735, "y": 2068}', '{"damage": "8d6 bludgeoning", "radius": "30m", "condition": "Prone"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ba33007f-f5e9-4eb4-96a0-e70cc74cd2f4', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_wrath_of_the_forest', 'Ormanın Öfkesi', 'Wrath of the Forest', '3 devasa ağacı öfkeli koruyucular olarak canlandırır. Her ağaç 150 HP''ye sahiptir ve yakındaki düşmanlara 4d10 ezici hasarla saldırır.', 'Animates 3 massive trees into furious protectors. Each tree has 150 HP and attacks nearby foes for 4d10 bludgeoning damage.', 'Nature', 78, 850, 4, '{"dr_earthquake"}', '{"x": 1896, "y": 2259}', '{"summons": "3 trees", "hp": "150 each", "damage": "4d10 bludgeoning"}', '🌲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93386ba5-9b25-4b34-9f92-a337b8290c8c', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_tree_of_life', 'Hayat Ağacı', 'Tree of Life', 'Yenileyici bir ışıkla atan görkemli, büyülü bir ağaç ortaya çıkararak 20m yarıçapındaki tüm müttefikleri 1 dakika boyunca tur başına 5d10 HP iyileştirir.', 'Manifests a glorious magical tree that pulses with restorative light, healing all allies in a 20m radius for 5d10 HP per turn for 1 minute.', 'Nature', 88, 1100, 5, '{"dr_wrath_of_the_forest"}', '{"x": 2056, "y": 2451}', '{"healing": "5d10/turn", "radius": "20m", "duration": "1 minute"}', '🌳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('358a1ca9-7a8a-431d-9d72-243d670d8780', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_nature_domain_ult', 'Doğanın Hükmü', 'Nature''s Domain', '50m''lik bir alanı büyülü, ilkel bir ormana dönüştürür. İçerideki düşmanlar tur başına 10d10 hasar alırken müttefikler tur başına 50 HP yeniler.', 'Transforms a 50m area into an enchanted primordial forest. Enemies within take 10d10 damage per turn while allies regenerate 50 HP per turn.', 'Nature', 95, 1400, 5, '{"dr_tree_of_life"}', '{"x": 2217, "y": 2642}', '{"damage": "10d10/turn", "healing": "50/turn", "radius": "50m", "duration": "1 minute"}', '🏞️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aa4d06c2-4a7f-44d6-9d91-afda1743e498', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_shape_cat', 'Form: Kedi', 'Shape: Cat', 'Çevik bir kediye dönüşür. Gizlilik zarlarına +10 bonus, kusursuz denge ve 15m hareket hızı sağlar.', 'Shapeshift into an agile feline. Grants a +10 bonus to Stealth checks, perfect balance, and a 15m movement speed.', 'Form', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"buff": "+10 Stealth", "speed": "15m", "duration": "Until dismissed"}', '🐈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f0abe88-90d7-49db-8e3a-e05c1e117438', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_wild_senses', 'Vahşi Duyular', 'Wild Senses', 'Duyularınızı hayvani bir dereceye kadar geliştirir. 10 dakika boyunca Algı zarlarında avantaj ve 20m kör görüş kazandırır.', 'Enhances your senses to an animalistic degree. Gain advantage on Perception checks and 20m blindsight for 10 minutes.', 'Form', 9, 75, 1, '{"dr_shape_cat"}', '{"x": -289, "y": 344}', '{"buff": "Advantage Perception", "blindsight": "20m", "duration": "10 minutes"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('357a4ff6-a7e8-48f8-85e7-1c47e07271af', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_swift_paws', 'Çevik Patiler', 'Swift Paws', 'Uzuvlarınızı bir çitanın hızıyla doldurarak 1 saat boyunca hareket hızınıza 10m ekler.', 'Infuses your limbs with the speed of a cheetah, granting an additional 10m to your movement speed for 1 hour.', 'Form', 14, 100, 1, '{"dr_wild_senses"}', '{"x": -449, "y": 536}', '{"buff": "+10m speed", "duration": "1 hour", "range": "Self"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ee32e72-b006-43db-a25a-39ee4d93a8d1', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_shape_wolf', 'Form: Kurt', 'Shape: Wolf', 'Hızlı bir kurda dönüşür. Hareket hızınız 20m olur ve ısırığınız 1d8 delici hasar verir.', 'Shapeshift into a swift wolf. Your movement speed becomes 20m, and your bite deals 1d8 piercing damage.', 'Form', 20, 125, 1, '{"dr_swift_paws"}', '{"x": -610, "y": 727}', '{"damage": "1d8 piercing", "speed": "20m", "duration": "Until dismissed"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bc6ec6da-308f-4343-aa8c-9fb9a6a584d0', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_feral_claws', 'Vahşi Pençeler', 'Feral Claws', 'Elleriniz 10 dakika boyunca ölümcül pençelere dönüşür. Silahsız saldırılarınız 2d6 kesici hasar verir ve büyülü sayılır.', 'Your hands transform into deadly claws for 10 minutes. Your unarmed strikes deal 2d6 slashing damage and count as magical.', 'Form', 26, 200, 2, '{"dr_shape_wolf"}', '{"x": -771, "y": 919}', '{"damage": "2d6 slashing", "duration": "10 minutes", "type": "Magical unarmed"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ad35a425-1414-4873-bab4-a42b471271a1', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_shape_bear', 'Form: Ayı', 'Shape: Bear', 'Devasa bir ayıya dönüşür. 50 Geçici HP ve 2d8 hasar veren yıkıcı bir pençe saldırısı kazanırsınız.', 'Shapeshift into a massive bear. You gain 50 Temporary HP and a devastating claw attack that deals 2d8 damage.', 'Form', 32, 250, 2, '{"dr_feral_claws"}', '{"x": -932, "y": 1110}', '{"hp_temp": "50", "damage": "2d8 slashing", "duration": "Until dismissed"}', '🐻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0bea4899-23f4-4d4a-afa1-2d6ec595bb71', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_thick_hide', 'Kalın Deri', 'Thick Hide', 'Cildiniz eski deri gibi sertleşir. 1 saat boyunca büyülü olmayan ezici, delici ve kesici hasarlara karşı direnç kazanırsınız.', 'Your skin hardens like old leather. You gain resistance to non-magical bludgeoning, piercing, and slashing damage for 1 hour.', 'Form', 40, 300, 2, '{"dr_shape_bear"}', '{"x": -1092, "y": 1302}', '{"resistance": "Non-magical physical", "duration": "1 hour", "range": "Self"}', '🦏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aabc68ec-b7c2-4320-b48a-d50f3fc1a952', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_shape_eagle', 'Form: Kartal', 'Shape: Eagle', 'Dev bir kartala dönüşür. 30m uçuş hızı kazanırsınız ve jilet gibi keskin pençeleriniz 2d6 hasar verir.', 'Shapeshift into a giant eagle. You gain a flying speed of 30m and your razor-sharp talons deal 2d6 damage.', 'Form', 46, 400, 3, '{"dr_thick_hide"}', '{"x": -1253, "y": 1493}', '{"speed_fly": "30m", "damage": "2d6 slashing", "duration": "Until dismissed"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71ae5931-55a8-4c5b-881a-92d574d6830d', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_savage_bite', 'Vahşi Isırık', 'Savage Bite', '4d10 delici hasar veren ve verilen hasarın yarısı kadar sizi iyileştiren vahşi, et parçalayan bir ısırık gerçekleştirir.', 'Deliver a brutal, flesh-rending bite that deals 4d10 piercing damage and heals you for half the damage dealt.', 'Form', 52, 450, 3, '{"dr_shape_eagle"}', '{"x": -1414, "y": 1685}', '{"damage": "4d10 piercing", "healing": "50% of damage", "range": "Melee"}', '🦷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('875ee9c0-cf02-427a-8de0-3b871224305e', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_predator_instinct', 'Avcı İçgüdüsü', 'Predator Instinct', 'İçinizdeki zirve avcısını uyandırır. 1 dakika boyunca yaralı hedeflere karşı yapılan tüm saldırı zarlarında avantaj sağlarsınız.', 'Awaken your inner apex predator. For 1 minute, you have advantage on all attack rolls made against wounded targets.', 'Form', 60, 500, 3, '{"dr_savage_bite"}', '{"x": -1574, "y": 1876}', '{"buff": "Advantage vs wounded", "duration": "1 minute", "range": "Self"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('79c54e2a-2638-4aa3-83d4-006229c5e516', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_shape_tiger', 'Form: Kaplan', 'Shape: Tiger', 'Vahşi bir kaplana dönüşür. 80 Geçici HP ve hedefleri yere seren, 4d10 hasar veren bir atılma saldırısı kazanırsınız.', 'Shapeshift into a ferocious tiger. You gain 80 Temporary HP and a pounce attack dealing 4d10 damage that knocks targets prone.', 'Form', 66, 700, 4, '{"dr_predator_instinct"}', '{"x": -1735, "y": 2068}', '{"hp_temp": "80", "damage": "4d10 slashing", "condition": "Prone"}', '🐅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3b794c10-45e4-443d-81a7-17816c6a18f7', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_primal_roar', 'İlkel Kükreme', 'Primal Roar', '30m koni şeklinde korkunç bir kükreme salıverir. İçerideki düşmanlar korkar, müttefikleriniz ise güçlenerek 20 Geçici HP kazanır.', 'Unleash a terrifying roar in a 30m cone. Enemies within are frightened, while your allies are bolstered, gaining 20 Temporary HP.', 'Form', 76, 850, 4, '{"dr_shape_tiger"}', '{"x": -1896, "y": 2259}', '{"area": "30m cone", "condition": "Frightened", "hp_temp": "20 to allies"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('efcc6694-4a11-416d-a7cc-417452cc0226', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_shape_dragon', 'Form: Ejderha', 'Shape: Dragon', 'Efsanevi yeşil bir ejderhaya dönüşür. 40m uçuş hızı, 200 Geçici HP ve 10d8 hasar veren yıkıcı bir nefes silahı kazanırsınız.', 'Shapeshift into a legendary green dragon. Gain a 40m flying speed, 200 Temporary HP, and a devastating 10d8 breath weapon.', 'Form', 86, 1100, 5, '{"dr_primal_roar"}', '{"x": -2056, "y": 2451}', '{"speed_fly": "40m", "hp_temp": "200", "damage": "10d8 poison/nature"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f315f13-203a-4a88-a240-9913d4d13cfa', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_chimera_form_ult', 'Kimera Formu', 'Chimera Form', 'Üç başlı korkunç bir kimera formuna bürünür. 300 Geçici HP kazanırsınız ve tur başına her biri 6d12 hasar veren üç saldırı yaparsınız.', 'Take on the horrifying form of a three-headed chimera. Gain 300 Temporary HP and make three attacks per turn, each dealing 6d12 damage.', 'Form', 95, 1400, 5, '{"dr_shape_dragon"}', '{"x": -2217, "y": 2642}', '{"hp_temp": "300", "damage": "3x 6d12", "duration": "Until dismissed or HP depleted"}', '🐲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('801d47fb-5428-4607-969b-cc93df75e616', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_spirit_bear', 'Ruh Ayı', 'Spirit Bear', 'Yakın dövüş saldırılarınızı taklit eden parlayan ruhani bir ayı çağırarak 1 dakika boyunca yakın dövüş hasarınızı etkili bir şekilde ikiye katlar.', 'Summons a glowing spectral bear that mimics your melee attacks, effectively doubling your melee damage output for 1 minute.', 'Cross-Branch', 50, 450, 3, '{"dr_shape_bear", "dr_summon_panther"}', '{"x": -173, "y": -100}', '{"buff": "Double melee damage", "duration": "1 minute", "summons": "1 Spirit Bear"}', '🐻‍❄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9d7241e-30ae-4e72-96dc-e56ab5beffe4', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_thorned_beast', 'Dikenli Canavar', 'Thorned Beast', 'Çağrılmış hayvanlarınızı keskin dikenli bir aurayla doldurur. Onlara yakın dövüş saldırısıyla vuran herhangi bir düşman 2d6 delici hasar alır.', 'Infuses your summoned animals with an aura of sharp briars. Any enemy hitting them with a melee attack takes 2d6 piercing damage.', 'Cross-Branch', 55, 450, 3, '{"dr_summon_dire_wolf", "dr_bark_shield"}', '{"x": -389, "y": -225}', '{"damage": "2d6 piercing retaliation", "duration": "1 hour", "target": "Summoned beasts"}', '🦔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a75366e-1a1d-47a5-95b1-64fe7594d56a', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_forest_strider', 'Orman Gezgini', 'Forest Strider', 'Doğayla kusursuz bir şekilde bütünleşir. Büyülü bitkilerin arasından ceza almadan geçebilir ve doğal orman arazisindeyken görünmez olursunuz.', 'Merge seamlessly with nature. You can move through magical plants without penalty and become invisible while within natural forest terrain.', 'Cross-Branch', 60, 500, 3, '{"dr_living_wall", "dr_thick_hide"}', '{"x": -606, "y": -350}', '{"buff": "Invisibility in forests, ignore difficult plant terrain", "duration": "1 hour"}', '🧝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('866494f2-a5ab-4f54-802d-0cb612806a50', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_furious_swarm', 'Öfkeli Sürü', 'Furious Swarm', '20m yarıçaplı bir alanda, düşmanları kör eden ve tur başına 6d8 delici hasar veren, toprağı kazan devasa ve öfkeli bir böcek sürüsü çağırır.', 'Summons a massive swarm of furious, earth-burrowing insects in a 20m radius that blinds enemies and deals 6d8 piercing damage per turn.', 'Cross-Branch', 70, 750, 4, '{"dr_beast_frenzy", "dr_earthquake"}', '{"x": -822, "y": -475}', '{"damage": "6d8 piercing/turn", "radius": "20m", "condition": "Blinded"}', '🦗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b520a5ff-2414-4e66-8937-deeeda9ce841', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_treant_form', 'Ağaç Adam Formu', 'Treant Form', 'Devasa bir Ağaç Adama dönüşür. 250 Geçici HP kazanırsınız ve devasa vurma saldırılarınız 6d10 hasar verir (yapılara iki kat hasar).', 'Shapeshift into a colossal Treant. You gain 250 Temporary HP and your massive slam attacks deal 6d10 damage with double damage to structures.', 'Cross-Branch', 72, 750, 4, '{"dr_wrath_of_the_forest", "dr_primal_roar"}', '{"x": -1039, "y": -600}', '{"hp_temp": "250", "damage": "6d10 bludgeoning (x2 to structures)", "duration": "Until dismissed"}', '🌲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3dd82934-76be-4801-bce8-2a671f46af90', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_pack_leader_form', 'Sürü Lideri Formu', 'Pack Leader Form', 'Bir canavar formundayken baskın bir enerji yayar, yanınızda koşulsuz olarak savaşmaları için pasif olarak iki ruh kurdu çağırırsınız.', 'While shapeshifted in a beast form, you exude dominant energy, passively summoning two spirit wolves to fight alongside you unconditionally.', 'Cross-Branch', 75, 800, 4, '{"dr_summon_grizzly", "dr_shape_tiger"}', '{"x": -1255, "y": -725}', '{"summons": "2 Spirit Wolves", "condition": "Requires beast form"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9be8411f-0904-42b6-a012-d2977abb1aa0', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_avatar_of_the_wild', 'Yabanın Avatarı', 'Avatar of the Wild', 'Tamamen kalın sarmaşıklardan ve köklerden oluşan devasa bir canavara dönüşür. 400 Geçici HP kazanır, vuruş başına 12d12 hasar verir ve 30m içindeki tüm düşmanları yere sabitlersiniz.', 'Transform into a towering beast made entirely of thick vines and roots. Gain 400 Temporary HP, deal 12d12 damage per strike, and root all enemies within 30m.', 'Cross-Branch', 85, 1200, 5, '{"dr_stampede", "dr_tree_of_life", "dr_shape_dragon"}', '{"x": -1472, "y": -850}', '{"hp_temp": "400", "damage": "12d12 mixed", "radius": "30m", "condition": "Rooted"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de5b727f-e889-4396-910a-25bc514e5935', '53ffd6d3-ee70-4198-b206-42f8d9d372ea', 'dr_world_tree_incarnate', 'Dünya Ağacı Vücut Bulmuş', 'World Tree Incarnate', '1 dakika boyunca Dünya Ağacı''nın dünyevi damarı olursunuz. 100m içindeki müttefikler ölüme karşı bağışıklık kazanır ve tur başına 100 HP yeniler. Alandaki düşmanlar 20d10 parlak ve doğa hasarı alır.', 'You become the earthly vessel of the World Tree for 1 minute. Allies within 100m are immune to death and regenerate 100 HP per turn. Enemies in the area take 20d10 radiant and nature damage.', 'Cross-Branch', 100, 1500, 5, '{"dr_apex_predator_ult", "dr_nature_domain_ult", "dr_chimera_form_ult"}', '{"x": -1688, "y": -975}', '{"healing": "100 HP/turn", "damage": "20d10 radiant/nature", "radius": "100m", "immunity": "Death for allies"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('406c8a4f-5b81-4217-bb4c-8d3e970b816e', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_staggering_step', 'Sendeleyen Adım', 'Staggering Step', 'Gelen bir saldırıdan sihirli bir şekilde kaçınan ani ve sakar bir adım atar. Saldırıyı 2m içindeki yakın bir düşmana yönlendirmek için %20 şans kazandırır.', 'Take a sudden, clumsy step that magically evades an incoming attack. Grants a 20% chance to redirect the attack to a nearby enemy within 2m.', 'Drunken Style', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"evasion": true, "redirect_chance": "20%", "range": "2m"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c610e853-2cc7-4f22-a01f-324ad99debde', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_liquid_courage', 'Sıvı Cesaret', 'Liquid Courage', 'Mataranızdan bir yudum alarak 1d8+DAY geçici HP kazanın ve 3 tur boyunca ''Sarhoş'' durumuna girin.', 'Take a swig from your flask, gaining 1d8+CON temporary HP and entering the ''Drunk'' state for 3 turns.', 'Drunken Style', 4, 75, 1, '{}', '{"x": 389, "y": -224}', '{"temp_hp": "1d8+CON", "duration": "3 turns", "status": "Drunk"}', '🍶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('37be5fe9-09cb-4641-8268-a99d388a457a', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_slurred_taunt', 'Sarhoş Narası', 'Slurred Taunt', '10m içindeki düşmanlara geveleyerek hakaret edin. 2 tur boyunca, sizden başka hedeflere yaptıkları saldırılarda dezavantajlı olurlar.', 'Insult enemies within 10m with slurred words. For 2 turns, they have disadvantage on attacks against targets other than you.', 'Drunken Style', 8, 100, 1, '{}', '{"x": 606, "y": -349}', '{"range": "10m", "duration": "2 turns", "debuff": "Disadvantage on others"}', '🤬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8f521aef-cf5c-4c41-99a2-2952294f93b9', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_swaying_reed', 'Sallanan Sazlık', 'Swaying Reed', 'Kaçınma odaklı bir duruş benimseyin. Sarhoşken, yönlendirme şansınız 3 tur boyunca %30''a çıkar.', 'Adopt an evasive stance. While Drunk, your redirect chance increases to 30% for 3 turns.', 'Drunken Style', 22, 200, 2, '{"dkm_staggering_step"}', '{"x": 822, "y": -474}', '{"duration": "3 turns", "redirect_chance_bonus": "+10%", "stance": true}', '🌾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d737858-ecf6-415a-b9ce-c52faec6b9fe', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_sudden_counter', 'Ani Kontra', 'Sudden Counter', 'Bir düşman sizi ıskaladığında, tepki olarak anında 2d8 ezme hasarı veren beklenmedik bir darbeyle karşılık verin.', 'When an enemy misses you, immediately strike back as a reaction with an unpredictable blow dealing 2d8 bludgeoning damage.', 'Drunken Style', 26, 225, 2, '{"dkm_staggering_step"}', '{"x": 1039, "y": -599}', '{"damage": "2d8 Bludgeoning", "trigger": "On Miss", "type": "Reaction"}', '👊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8dcb0b2c-b1d1-414a-8499-3ad77c9dc049', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_drunkards_resolve', 'Ayyaşın İradesi', 'Drunkard''s Resolve', 'Sarhoş zihninizi okumak zordur. Sarhoşken psişik hasara karşı direnç ve tılsımlanma ile korku etkilerine karşı bağışıklık kazanın.', 'Your inebriated mind is hard to read. Gain resistance to psychic damage and immunity to charm and fear effects while Drunk.', 'Drunken Style', 32, 250, 2, '{"dkm_liquid_courage"}', '{"x": 1255, "y": -724}', '{"immunity": "Charm, Fear", "resistance": "Psychic", "duration": "Passive while Drunk"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09632fd1-30e9-4418-bc30-910df148ed2a', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_falling_leaf_strike', 'Düşen Yaprak Vuruşu', 'Falling Leaf Strike', 'Muazzam bir güç taşıyan ve görünüşte zayıf olan bu vuruş, 3d10 hasar verir ve GÜÇ kurtarmasında başarısız olursa hedefi yere serer.', 'A seemingly weak strike that carries immense force, dealing 3d10 damage and knocking the target prone if they fail a STR save.', 'Drunken Style', 42, 400, 3, '{"dkm_sudden_counter"}', '{"x": 1472, "y": -849}', '{"damage": "3d10 Bludgeoning", "save": "STR", "condition": "Prone"}', '🍂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ce80f08-5ef0-4acc-86ff-0ec5726dfec6', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_dizzying_parry', 'Baş Döndüren Savuşturma', 'Dizzying Parry', 'Yakın dövüş saldırısını savuşturun ve saldırganı döndürerek 1 tur boyunca ''Baş Dönmesi'' durumu uygulayın.', 'Parry a melee attack and spin the attacker around, inflicting the ''Dizzy'' status for 1 turn.', 'Drunken Style', 48, 425, 3, '{"dkm_swaying_reed"}', '{"x": 1688, "y": -974}', '{"parry": true, "status": "Dizzy", "duration": "1 turn", "range": "Melee"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8c4adce3-7610-4c03-8534-aa6007892138', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_fluid_motion', 'Akışkan Hareket', 'Fluid Motion', 'Su gibi hareket edin. Zorlu arazileri yok sayın ve hareketiniz 2 tur boyunca fırsat saldırılarını tetiklemesin.', 'Move like water. Ignore difficult terrain and your movement does not provoke opportunity attacks for 2 turns.', 'Drunken Style', 55, 450, 3, '{"dkm_swaying_reed"}', '{"x": 1905, "y": -1099}', '{"duration": "2 turns", "ignore_terrain": true, "avoid_opportunity": true}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04744bd1-127a-46f6-bffa-7c2e2d9bd6e3', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_drunken_frenzy', 'Sarhoş Çılgınlığı', 'Drunken Frenzy', 'Her biri 2d6 hasar veren 4 hızlı vuruş serbest bırakın. Eğer Sarhoş iseniz, her vuruşa ÇEV değiştiricinizi ekleyin.', 'Unleash a flurry of 4 rapid strikes, each dealing 2d6 damage. If Drunk, add your DEX modifier to each hit.', 'Drunken Style', 62, 700, 4, '{"dkm_falling_leaf_strike"}', '{"x": 2121, "y": -1224}', '{"hits": 4, "damage_per_hit": "2d6 Bludgeoning", "drunk_bonus": "+DEX"}', '🤛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa6483e6-0ab0-4da5-b930-19d57c8631ca', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_redirecting_flow', 'Yönlendiren Akış', 'Redirecting Flow', 'Yönlendirme sanatını mükemmelleştirin. Sarhoşken, temel yönlendirme şansınız %40 olur. Yönlendirilen saldırılar yeni hedeflerine vurmak için +2 bonus kazanır.', 'Perfect the art of redirection. While Drunk, your baseline redirect chance becomes 40%. Redirected attacks gain a +2 bonus to hit their new target.', 'Drunken Style', 68, 750, 4, '{"dkm_dizzying_parry"}', '{"x": 2338, "y": -1349}', '{"redirect_base": "40%", "redirect_bonus_hit": "+2", "duration": "Passive"}', '🔀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d539b424-0497-4a25-a8b7-db6f6436833c', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_unbreakable_stance', 'Kırılmaz Duruş', 'Unbreakable Stance', 'Kendinizi bir dağ gibi köklendirin, gelen tüm ezme, delme ve kesme hasarını 3 tur boyunca yarıya indirin. Hareket ettirilemezsiniz.', 'Root yourself like a mountain, reducing all incoming bludgeoning, piercing, and slashing damage by half for 3 turns. You cannot be moved.', 'Drunken Style', 75, 800, 4, '{"dkm_fluid_motion"}', '{"x": 2554, "y": -1474}', '{"resistance": "B/P/S", "duration": "3 turns", "immovable": true}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1d5a883-78b7-4a17-9bd3-b6d219d70acf', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_master_of_the_jug', 'Testinin Üstadı', 'Master of the Jug', 'Mataranız asla boşalmaz. İçmek artık bir eylem gerektirmez ve 5m içindeki müttefiklere Sarhoş durumunu (ve onun güçlendirmelerini) verebilirsiniz.', 'Your flask never empties. Drinking no longer costs an action, and you can grant the Drunk status (and its buffs) to allies within 5m.', 'Drunken Style', 82, 1100, 5, '{"dkm_unbreakable_stance"}', '{"x": 2771, "y": -1599}', '{"action_cost": "Free", "aoe_buff": true, "range": "5m"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f5d1feb2-6734-4d6b-a832-0e7514c2e43f', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_illusory_sway', 'Yanılsamalı Salınım', 'Illusory Sway', 'Hareketleriniz o kadar dengesizleşir ki ardıl görüntüler yaratır. 1 dakika boyunca isabetleri emen ve saldırganları şaşırtan 3 ayna görüntüsü kazanın.', 'Your movements become so erratic they create afterimages. Gain 3 mirror images that absorb hits and confuse attackers for 1 minute.', 'Drunken Style', 88, 1200, 5, '{"dkm_redirecting_flow"}', '{"x": 2987, "y": -1724}', '{"images": 3, "duration": "1 minute", "defense": "Mirror Image"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('842cf26f-3c62-406d-b64f-8f91de092d75', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_ultimate_drunken_fist', 'Ulti: Sarhoş Yumruğu', 'Ultimate: Drunken Fist', 'Sarhoş Stili''nin zirvesi. Tüm zırhları yok sayan, 10d10 güç hasarı veren ve hedefin Zırh Sınıfını (AC) kalıcı olarak 2 düşüren yıkıcı bir yumruk indirin.', 'The pinnacle of Drunken Style. Deliver a devastating punch that ignores all armor, dealing 10d10 force damage and permanently reducing the target''s AC by 2.', 'Drunken Style', 95, 1500, 5, '{"dkm_master_of_the_jug", "dkm_illusory_sway"}', '{"x": 3204, "y": -1849}', '{"damage": "10d10 Force", "armor_pen": true, "debuff": "-2 AC"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4848ecf2-a142-4292-8c24-e1d83220f7ce', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_jug_smash', 'Testi Kırma', 'Jug Smash', 'Bir düşmanın kafasında kil bir testiyi kırarak 1d8 ezme hasarı verin ve onları 1 tur boyunca kör edin.', 'Smash a clay jug over an enemy''s head, dealing 1d8 bludgeoning damage and blinding them for 1 turn.', 'Improvisation', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8 Bludgeoning", "status": "Blind", "duration": "1 turn"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e138c9da-a88e-4ecb-b107-3bf994fdd962', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_spit_fire', 'Ateş Tükürme', 'Spit Fire', 'Ağzınızdan yüksek alkollü bir içkiyi ateşleyerek 3m''lik bir koni alanında 2d6 ateş hasarı verin.', 'Ignite high-proof alcohol from your mouth, dealing 2d6 fire damage in a 3m cone.', 'Improvisation', 5, 75, 1, '{}', '{"x": 289, "y": 344}', '{"damage": "2d6 Fire", "area": "3m Cone"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f5154e69-113b-476e-8402-d13fcdd16d35', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_dirty_kick', 'Kirli Tekme', 'Dirty Kick', 'Hızlı, beklenmedik bir belden aşağı vuruşla 1d6 hasar verin ve hedefi 1 tur sersemletmek için %50 şans elde edin.', 'A swift, unexpected low blow dealing 1d6 damage and a 50% chance to stun the target for 1 turn.', 'Improvisation', 9, 100, 1, '{}', '{"x": 449, "y": 536}', '{"damage": "1d6 Bludgeoning", "stun_chance": "50%", "duration": "1 turn"}', '🦵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07264495-7e5a-48cb-8a85-ce2943408295', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_barroom_brawler', 'Meyhane Dövüşçüsü', 'Barroom Brawler', 'Çevreden silahlar doğaçlayın. 15m''ye kadar bir sandalye, kupa veya kaya fırlatarak 2d8 hasar verin.', 'Improvise weapons from the environment. Throw a chair, mug, or rock up to 15m, dealing 2d8 damage.', 'Improvisation', 23, 200, 2, '{"dkm_jug_smash"}', '{"x": 610, "y": 727}', '{"range": "15m", "damage": "2d8 Bludgeoning", "type": "Ranged"}', '🪑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('66748b70-ab4e-4396-8449-e149e400a588', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_bottle_barrage', 'Şişe Yağmuru', 'Bottle Barrage', '12m içindeki en fazla üç hedefe arka arkaya hızla üç şişe fırlatın. Her biri 1d8 kesme hasarı verir.', 'Throw three bottles in quick succession at up to three targets within 12m. Each deals 1d8 slashing damage.', 'Improvisation', 27, 225, 2, '{"dkm_jug_smash"}', '{"x": 771, "y": 919}', '{"hits": 3, "damage_per_hit": "1d8 Slashing", "range": "12m"}', '🍾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0bc104b-6034-4266-a99e-3ea90fcadac4', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_unpredictable_toss', 'Beklenmedik Fırlatma', 'Unpredictable Toss', 'Seken bir nesne fırlatın. Eğer birincil hedefe vurursa, 5m içindeki ikinci bir hedefe sekerek yarım hasar verir.', 'Throw an object that ricochets. If it hits the primary target, it bounces to a second target within 5m for half damage.', 'Improvisation', 33, 250, 2, '{"dkm_barroom_brawler"}', '{"x": 932, "y": 1110}', '{"bounce": 1, "range": "15m / 5m", "damage": "Primary full, Secondary half"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('97375e0d-bb75-4670-b4c2-c15d259b5002', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_toxic_brew', 'Zehirli İksir', 'Toxic Brew', 'Zehirli bir karışım tükürün. 4m koni içindeki düşmanlar 3d8 zehir hasarı alır ve 2 tur boyunca zehirlenirler.', 'Spit a noxious concoction. Enemies in a 4m cone take 3d8 poison damage and are poisoned for 2 turns.', 'Improvisation', 43, 400, 3, '{"dkm_spit_fire"}', '{"x": 1092, "y": 1302}', '{"damage": "3d8 Poison", "area": "4m Cone", "duration": "2 turns"}', '🤢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94f88621-3e79-4631-a8dd-02c80897a6d8', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_improvised_shield', 'Doğaçlama Kalkan', 'Improvised Shield', 'Gelen bir saldırıyı engellemek için bir masa veya büyük bir nesne kapın, tepki olarak bir saldırıya karşı +5 AC kazanın. Nesne parçalanarak saldırgana 1d6 hasar veren şarapnele dönüşür.', 'Grab a table or large object to block an incoming attack, gaining +5 AC against one attack as a reaction. The object shatters into shrapnel dealing 1d6 damage to the attacker.', 'Improvisation', 49, 425, 3, '{"dkm_barroom_brawler"}', '{"x": 1253, "y": 1493}', '{"ac_bonus": "+5", "reaction": true, "recoil_damage": "1d6 Piercing"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc83d91a-fe0a-466c-81cf-5eaabba1c68b', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_keg_roll', 'Fıçı Yuvarlama', 'Keg Roll', '10m''lik bir hatta devasa bir fıçı yuvarlayın. Hedefler kurtarma yapmalı veya 4d6 ezme hasarı alıp yere serilmelidir.', 'Roll a massive keg in a 10m line. Targets must save or take 4d6 bludgeoning damage and be knocked prone.', 'Improvisation', 56, 450, 3, '{"dkm_dirty_kick"}', '{"x": 1414, "y": 1685}', '{"damage": "4d6 Bludgeoning", "area": "10m Line", "condition": "Prone"}', '🛢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('88a106d6-027b-44f7-bd46-c2a788d5a104', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_shattering_crescendo', 'Parçalayan Kreşendo', 'Shattering Crescendo', 'İki devasa şişeyi birbirine çarparak camdan bir şok dalgası yaratın. 5m yarıçapındaki alan 5d8 kesme hasarı alır.', 'Smash two massive bottles together, creating a shockwave of glass. 5m radius area takes 5d8 slashing damage.', 'Improvisation', 63, 700, 4, '{"dkm_bottle_barrage"}', '{"x": 1574, "y": 1876}', '{"damage": "5d8 Slashing", "area": "5m Radius"}', '🥂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7db0724-90c6-477f-9877-1f84d414aaea', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_volatile_spit', 'Patlayıcı Tükürük', 'Volatile Spit', 'Patlayıcı bir iksir tükürün. 15m''ye kadar uzaklıkta, 5m yarıçaplı bir patlamayla 6d6 ateş hasarı verir.', 'Spit an explosive brew. Deals 6d6 fire damage in a 5m radius explosion up to 15m away.', 'Improvisation', 69, 750, 4, '{"dkm_toxic_brew"}', '{"x": 1735, "y": 2068}', '{"damage": "6d6 Fire", "area": "5m Radius", "range": "15m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0c38f782-1853-4878-a69e-9655d7c8a522', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_master_scavenger', 'Usta Çöpçü', 'Master Scavenger', 'Kullandığınız herhangi bir doğaçlama silah büyülü hale gelir, fazladan 2d6 hasar verir ve büyülü olmayan dirençleri yok sayar.', 'Any improvised weapon you wield becomes magical, dealing an extra 2d6 damage and ignoring non-magical resistances.', 'Improvisation', 76, 800, 4, '{"dkm_improvised_shield"}', '{"x": 1896, "y": 2259}', '{"buff": "Improvised Weapons Magical", "bonus_damage": "2d6", "duration": "Passive"}', '🛠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('920f51fe-ec4d-42a2-944b-4a9b7100a188', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_dragon_breath_brew', 'Ejderha Nefesi İksiri', 'Dragon Breath Brew', 'Efsanevi bir iksir için ve 15m''lik devasa bir kavurucu mavi alev konisi üfleyerek 8d10 ateş hasarı verip düşmanları tutuşturun.', 'Drink a legendary brew and exhale a massive 15m cone of searing blue flames, dealing 8d10 fire damage and igniting enemies.', 'Improvisation', 83, 1100, 5, '{"dkm_volatile_spit"}', '{"x": 2056, "y": 2451}', '{"damage": "8d10 Fire", "area": "15m Cone", "condition": "Ignited"}', '🐲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4a81a8da-f7fb-49ed-b107-12d0c4bf5451', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_ultimate_pub_brawl', 'Ulti: Meyhane Kavgası', 'Ultimate: Pub Brawl', 'Savaş alanını kaotik bir meyhane kavgasına çevirin. İpler, sandalyeler ve kupalar her yere uçar. 3 tur boyunca 20m içindeki tüm düşmanlar her tur 4d8 ezme hasarı alır ve tepki kullanamazlar.', 'Turn the battlefield into a chaotic tavern brawl. Ropes, chairs, and mugs fly everywhere. For 3 turns, all enemies in 20m take 4d8 bludgeoning damage each turn and cannot take reactions.', 'Improvisation', 96, 1500, 5, '{"dkm_shattering_crescendo", "dkm_master_scavenger"}', '{"x": 2217, "y": 2642}', '{"damage": "4d8 Bludgeoning / turn", "area": "20m Radius", "duration": "3 turns", "debuff": "No Reactions"}', '🍻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c056acf-52c9-4e44-be47-c7281ef26dab', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_clumsy_charge', 'Sakar Hücum', 'Clumsy Charge', '8m''ye kadar körü körüne hücum edin. Menzil içindeki rastgele bir hedefe 1d10 hasar verirsiniz, ancak menzildeki tek kişi onlarsa bir müttefike de vurabilirsiniz.', 'Charge blindly up to 8m. You hit a random target in range for 1d10 damage, but might also hit an ally if they are the only one in range.', 'Chaos', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d10 Bludgeoning", "range": "8m", "target": "Random"}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ac8f0ab-f668-4f49-b783-9ce161ceee15', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_hiccup_blast', 'Hıçkırık Patlaması', 'Hiccup Blast', 'Sihirli bir şekilde güçlendirilmiş bir hıçkırık sonik bir dalga yayarak bitişik yaratıklara 1d6 gök gürültüsü hasarı verir ve onları 1m uzağa iter.', 'A magically amplified hiccup releases a sonic wave, dealing 1d6 thunder damage to adjacent creatures and pushing them 1m away.', 'Chaos', 6, 75, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "1d6 Thunder", "area": "1m Radius", "knockback": "1m"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81e81c45-2911-4021-922c-1ec70117ff4b', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_trip_and_fall', 'Takılıp Düşme', 'Trip and Fall', '''Yanlışlıkla'' yüzüstü düşerek bir saldırıdan tamamen kaçının ve bitişik bir düşmanı çelmeleyerek 1d4 hasar verip yere serin.', '''Accidentally'' fall prone, dodging an attack completely and tripping an adjacent enemy, dealing 1d4 damage and knocking them prone.', 'Chaos', 10, 100, 1, '{}', '{"x": -449, "y": 536}', '{"dodge": true, "condition": "Prone (Self & Target)", "damage": "1d4 Bludgeoning"}', '🤸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bce7d405-627a-475f-908a-d20a76425b7e', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_erratic_whirlwind', 'Dengesiz Kasırga', 'Erratic Whirlwind', 'Kollarınız açık şekilde çılgınca dönün ve rastgele bir yönde 5m ilerleyin. Yolunuza çıkan herkese 2d6 kesme hasarı verir.', 'Spin wildly with arms outstretched, moving 5m in a random direction. Deals 2d6 slashing damage to anyone in your path.', 'Chaos', 24, 200, 2, '{"dkm_clumsy_charge"}', '{"x": -610, "y": 727}', '{"damage": "2d6 Slashing", "movement": "5m Random"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('12bce0fd-f8af-44a7-aabf-28e81d77b66d', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_infectious_laughter', 'Bulaşıcı Kahkaha', 'Infectious Laughter', 'Gürleyen, sarhoş bir kahkaha atın. 8m içindeki düşmanlar BİL kurtarması yapmalı veya 1 tur boyunca gülmekten yere serilmelidir.', 'Let out a booming, drunken laugh. Enemies within 8m must make a WIS save or fall prone laughing for 1 turn.', 'Chaos', 28, 225, 2, '{"dkm_hiccup_blast"}', '{"x": -771, "y": 919}', '{"area": "8m Radius", "save": "WIS", "condition": "Incapacitated/Prone", "duration": "1 turn"}', '😂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e6629454-9548-4c7e-af33-d3d212663567', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_bouncing_bruiser', 'Zıplayan Kabadayı', 'Bouncing Bruiser', 'Bir düşmana (6m''ye kadar) sıçrayarak 2d6 hasar verin, ardından 4m içindeki başka bir rastgele düşmana sekerek 1d6 hasar verin.', 'Leap at an enemy (up to 6m) for 2d6 damage, then bounce to another random enemy within 4m for 1d6 damage.', 'Chaos', 34, 250, 2, '{"dkm_trip_and_fall"}', '{"x": -932, "y": 1110}', '{"damage": "2d6 -> 1d6 Bludgeoning", "range": "6m -> 4m"}', '🦘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1bdb76db-8a01-4c2c-b159-4f4b27e3f0a5', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_pandemonium_step', 'Kargaşa Adımı', 'Pandemonium Step', 'Görebildiğiniz 10m uzaklıktaki bir noktaya ışınlanın, geride 2m yarıçapındaki düşmanları kör eden kafa karıştırıcı bir toz bulutu bırakın.', 'Teleport up to 10m to a point you can see, leaving behind a cloud of confusing dust that blinds enemies in a 2m radius.', 'Chaos', 44, 400, 3, '{"dkm_erratic_whirlwind"}', '{"x": -1092, "y": 1302}', '{"teleport": "10m", "area": "2m Radius", "status": "Blind"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a501af35-6367-4579-bd33-e2f9b82e8605', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_drunken_aura', 'Sarhoş Aurası', 'Drunken Aura', '3 tur boyunca sarhoş edici dumanlardan oluşan bir aura yayın. 5m içindeki düşmanların hareket hızı yarıya düşer ve ÇEV kurtarmalarında dezavantaj yaşarlar.', 'Emit an aura of intoxicating fumes for 3 turns. Enemies within 5m have their movement speed halved and suffer disadvantage on DEX saves.', 'Chaos', 50, 425, 3, '{"dkm_infectious_laughter"}', '{"x": -1253, "y": 1493}', '{"duration": "3 turns", "area": "5m Aura", "debuff": "Half Speed, Disadv DEX"}', '🥴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93022216-18b9-4301-b9b6-1c86af90da11', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_chaos_brew', 'Kaos İksiri', 'Chaos Brew', 'Gizemli bir iksir için. 1d4 atın: 1=Hız, 2=Büyüme, 3=Görünmezlik, 4=Geğirti (etrafınıza 3d6 gök gürültüsü hasarı verir).', 'Drink a mystery potion. Roll 1d4: 1=Haste, 2=Enlarge, 3=Invisibility, 4=Burp (deals 3d6 thunder damage around you).', 'Chaos', 57, 450, 3, '{"dkm_bouncing_bruiser"}', '{"x": -1414, "y": 1685}', '{"random_buff": "1d4 outcome", "duration": "2 turns"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5bb2b01e-c906-45a8-b6d1-784f9b103d78', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_mad_stampede', 'Çılgın İzdiham', 'Mad Stampede', '12m''lik bir hatta çılgınca koşun. Düşmanların içinden geçerek 4d8 ezme hasarı verir ve sonraki turlarında en yakın yaratığa saldırmaya zorlarsınız.', 'Run wildly in a 12m line. You pass through enemies, dealing 4d8 bludgeoning damage and forcing them to attack the nearest creature on their next turn.', 'Chaos', 64, 700, 4, '{"dkm_pandemonium_step"}', '{"x": -1574, "y": 1876}', '{"damage": "4d8 Bludgeoning", "area": "12m Line", "debuff": "Attack Nearest"}', '🐃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9febfcdf-f0c3-4dbb-acbb-ba022e4c9dd4', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_hallucinatory_vapors', 'Halüsinatif Buharlar', 'Hallucinatory Vapors', '8m yarıçapında akıl almaz buharlar üfleyin. Düşmanlar birden fazla sarhoş usta illüzyonu görür ve 2 tur boyunca tüm saldırılarında %50 ıskalama şansı yaşarlar.', 'Exhale mind-bending vapors in an 8m radius. Enemies see illusions of multiple drunken masters and suffer a 50% miss chance on all attacks for 2 turns.', 'Chaos', 70, 750, 4, '{"dkm_drunken_aura"}', '{"x": -1735, "y": 2068}', '{"area": "8m Radius", "duration": "2 turns", "debuff": "50% Miss Chance"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2a23f193-998a-4c9f-bda7-758b66d25240', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_unpredictable_strikes', 'Beklenmedik Vuruşlar', 'Unpredictable Strikes', '3 yakın dövüş saldırısı yapın. Her saldırı için, 3d8 hasar vermeden önce 10m içindeki rastgele bir düşmana anında ışınlanırsınız.', 'Make 3 melee attacks. For each attack, you instantly teleport to a random enemy within 10m before striking for 3d8 damage.', 'Chaos', 77, 800, 4, '{"dkm_chaos_brew"}', '{"x": -1896, "y": 2259}', '{"hits": 3, "teleport": "10m per hit", "damage": "3d8 per hit"}', '🎲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('59396134-da13-43e8-b3b7-4c1ce2f19985', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_avatar_of_chaos', 'Kaosun Avatarı', 'Avatar of Chaos', '1 dakika boyunca kaosun vücut bulmuş hali olun. Her hasar aldığınızda, rastgele bir yöne 3m ışınlanırsınız ve yeni konumunuza bitişik düşmanlara 2d10 güç hasarı verirsiniz.', 'Become chaos incarnate for 1 minute. Every time you take damage, you teleport 3m in a random direction and deal 2d10 force damage to enemies adjacent to your new location.', 'Chaos', 84, 1100, 5, '{"dkm_mad_stampede", "dkm_hallucinatory_vapors"}', '{"x": -2056, "y": 2451}', '{"duration": "1 minute", "trigger": "On Damage", "reaction_effect": "Teleport + 2d10 Force"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4effbcfb-d26b-4760-b66b-d588357ab4a1', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_ultimate_drunken_god', 'Ulti: Sarhoş Tanrı', 'Ultimate: Drunken God', 'Sarhoş bir tanrılığa yükselin. 3 tur boyunca yönlendirme şansınız %80 olur, tüm durumlara karşı bağışıklık kazanırsınız ve saldırılarınız zar atmak yerine olası maksimum hasarı verir.', 'Ascend to drunken godhood. For 3 turns, your redirect chance becomes 80%, you are immune to all conditions, and your attacks deal maximum possible damage instead of rolling.', 'Chaos', 97, 1500, 5, '{"dkm_avatar_of_chaos", "dkm_unpredictable_strikes"}', '{"x": -2217, "y": 2642}', '{"duration": "3 turns", "redirect_chance": "80%", "buff": "Max Damage, Immunity"}', '🍺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5f80828a-8e43-4795-8f4c-3fd433a10772', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_stumbling_counter', 'Tökezleyen Kontra', 'Stumbling Counter', 'Bir saldırıdan kaçmak için yüzüstü düşün, ardından hemen yerden 2d8 hasar veren ve hedefi şaşırtan bir tekme atın.', 'Fall prone to dodge an attack, then immediately launch a kick from the ground dealing 2d8 damage and confusing the target.', 'Drunken Style, Chaos', 36, 300, 2, '{"dkm_sudden_counter", "dkm_trip_and_fall"}', '{"x": 173, "y": -99}', '{"damage": "2d8 Bludgeoning", "status": "Confused", "dodge": true}', '🤹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24c025c8-0707-49cd-8185-b503d233cb8f', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_exploding_hiccup', 'Patlayan Hıçkırık', 'Exploding Hiccup', 'Zehirli bir hıçkırık etrafınızdaki havayı tutuşturur, 4m yarıçapında 3d6 ateş ve 3d6 zehir hasarı verir.', 'A toxic hiccup ignites the air around you, dealing 3d6 fire and 3d6 poison damage in a 4m radius.', 'Improvisation, Chaos', 58, 500, 3, '{"dkm_hiccup_blast", "dkm_toxic_brew"}', '{"x": 173, "y": -99}', '{"damage": "3d6 Fire + 3d6 Poison", "area": "4m Radius"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e2547c5-c70f-4166-8cd8-42c77a33dc69', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_drunken_juggler', 'Sarhoş Hokkabaz', 'Drunken Juggler', 'Gelen menzilli mermileri yakalayın ve doğaçlama silah hasarı bonuslarınızla hemen saldırgana geri fırlatın.', 'Catch incoming ranged projectiles and immediately throw them back at the attacker with your improvised weapon damage bonuses.', 'Drunken Style, Improvisation', 60, 500, 3, '{"dkm_bottle_barrage", "dkm_swaying_reed"}', '{"x": 173, "y": -99}', '{"counter": "Ranged Attacks", "damage": "Projectile + 1d8"}', '🤹‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1bf97d17-46eb-4d7f-a3f7-ece71e1e9d08', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_mayhem_stance', 'Kargaşa Duruşu', 'Mayhem Stance', 'Maniyak bir duruşa geçin. Bir saldırıyı her yönlendirdiğinizde, otomatik olarak saldırgana 2d10 hasar veren doğaçlama bir eşya fırlatırsınız. 3 tur sürer.', 'Enter a manic stance. Whenever you redirect an attack, you automatically throw an improvised item at the attacker for 2d10 damage. Lasts 3 turns.', 'Drunken Style, Chaos, Improvisation', 78, 900, 4, '{"dkm_unbreakable_stance", "dkm_mad_stampede", "dkm_master_scavenger"}', '{"x": 173, "y": -99}', '{"duration": "3 turns", "trigger": "On Redirect", "damage": "2d10 Ranged"}', '🃏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ef7fdbf-7ca9-44d4-8bae-c7bc0c479ac0', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_laughing_parry', 'Gülen Savuşturma', 'Laughing Parry', 'Çılgınca kıkırdayarak bir darbeyi savuşturun. Saldırgan ve 3m içindeki tüm düşmanlar kurtarma yapmalı veya 1 tur boyunca gülmekten aciz kalmalıdır.', 'Deflect a blow while cackling madly. The attacker and all enemies within 3m must save or be incapacitated by laughter for 1 turn.', 'Drunken Style, Chaos', 80, 900, 4, '{"dkm_dizzying_parry", "dkm_infectious_laughter"}', '{"x": 389, "y": -224}', '{"parry": true, "area": "3m Radius", "condition": "Incapacitated"}', '🤣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cebc4b1c-c74f-46ba-8508-fbf1cc2a4f04', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_catastrophic_brew', 'Felaket İksiri', 'Catastrophic Brew', 'Nihai iksirinizi karıştırın. Onu 20m''ye kadar fırlatın. 10m yarıçapında patlayarak 6d10 ateş hasarı verir ve etkilenen herkese rastgele güçlü bir zayıflatma (sersemletme, körlük veya felç) uygular.', 'Mix your ultimate brew. Hurl it up to 20m. It explodes in a 10m radius, dealing 6d10 fire damage and inflicting a random powerful debuff (stun, blind, or paralyze) to all affected.', 'Improvisation, Chaos', 89, 1300, 5, '{"dkm_dragon_breath_brew", "dkm_avatar_of_chaos"}', '{"x": 389, "y": -224}', '{"range": "20m", "area": "10m Radius", "damage": "6d10 Fire", "random_debuff": true}', '☢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('03cbcb31-044f-48ed-9f4c-6b0a46139ade', 'f63c334c-e944-47aa-a38c-c6a37ab1b974', 'dkm_grand_ultimate_eight_immortals', 'Büyük Ulti: Sekiz Ölümsüz', 'Grand Ultimate: Eight Immortals', 'Efsanevi Sekiz Ölümsüz''ü yönlendirin. 1 tur boyunca sekiz kontrol edilemez sarhoş avatara bölünürsünüz ve 30m içindeki her düşmana sekiz kez vurursunuz. Her vuruş rastgele bir türde 2d12 hasar verir ve bu tur boyunca tüm saldırılardan otomatik olarak kaçınırsınız.', 'Channel the mythical Eight Immortals. You split into eight uncontrollable drunken avatars for 1 turn, striking every enemy within 30m eight times. Each strike deals 2d12 damage of a random type, and you automatically dodge all attacks during this turn.', 'Drunken Style, Improvisation, Chaos', 100, 1500, 5, '{"dkm_ultimate_drunken_fist", "dkm_ultimate_pub_brawl", "dkm_ultimate_drunken_god"}', '{"x": 173, "y": -99}', '{"hits": 8, "damage": "2d12 Random Type per hit", "area": "30m Radius", "buff": "Invincibility for 1 turn"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('495d5e71-e9a3-480a-b4cd-a5b25a850b75', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_sonic_slash', 'Sonik Kesik', 'Sonic Slash', '3m ilerleyen küçük bir ses bıçağı fırlatan ve 1d8 sonik hasar veren yakın dövüş saldırısı.', 'Melee attack that releases a small 3m sound blade dealing 1d8 sonic damage.', 'Sonic', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8", "range": "3m", "damage_type": "sonic"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04eaafcf-f9e2-431c-96cf-1055977a165f', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_sound_dart', 'Ses Oku', 'Sound Dart', '15m uzağa fırlatılan ve 1d6 hasar veren yoğunlaştırılmış bir ses topu.', 'Throws a condensed ball of sound 15m away dealing 1d6 damage.', 'Sonic', 5, 75, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "1d6", "range": "15m", "damage_type": "sonic"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('11939a21-8a3d-4d28-8f4a-e68991e07b24', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_deafening_ring', 'Sağır Edici Çınlama', 'Deafening Ring', '5m içindeki düşmanlar 1d4 hasar alır ve 1 tur boyunca sağır olurlar.', 'Enemies within 5m take 1d4 damage and are deafened for 1 round.', 'Sonic', 10, 100, 1, '{}', '{"x": 606, "y": -349}', '{"damage": "1d4", "range": "5m", "duration": "1 round", "status": "deafened"}', '🔔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d3285a53-00a7-46bc-90ef-8e79aab3fb0c', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_sonic_step', 'Sonik Adım', 'Sonic Step', 'Ses itiş gücünü kullanarak anında 10m ileri atılır.', 'Dash 10m instantly using sound propulsion.', 'Sonic', 15, 150, 1, '{"eb_sonic_slash"}', '{"x": 822, "y": -474}', '{"range": "10m", "type": "movement"}', '👟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5feee8e9-f572-4005-82e0-c4dbca35e8ca', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_screeching_blade', 'Çığlık Atan Kılıç', 'Screeching Blade', 'Silahı çığlık atan bir sesle doldurarak 2d6 sonik hasar ve %20 korkutma şansı ekler.', 'Infuses weapon with screeching sound, adding 2d6 sonic damage and a 20% chance to fear.', 'Sonic', 22, 200, 2, '{"eb_sonic_slash"}', '{"x": 1039, "y": -599}', '{"bonus_damage": "2d6", "status_chance": "20%", "status": "fear"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8a6f76fe-2031-44ae-b4e6-86c7d4b795d3', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_sonic_boom', 'Sonik Patlama', 'Sonic Boom', 'Zıplayıp yere çarparak 6m yarıçapında 3d6 sonik hasar verir.', 'Jump and crash down, dealing 3d6 sonic damage in a 6m radius.', 'Sonic', 28, 250, 2, '{"eb_deafening_ring"}', '{"x": 1255, "y": -724}', '{"damage": "3d6", "range": "6m radius", "damage_type": "sonic"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b2d21807-ef59-4a07-94a5-7f9551e64055', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_soundwave_pulse', 'Ses Dalgası Vuruşu', 'Soundwave Pulse', 'Düşmanları 3m geriye iten ve 2d8 hasar veren 10m''lik bir ses konisi serbest bırakır.', 'Releases a 10m cone of sound pushing enemies back 3m and dealing 2d8 damage.', 'Sonic', 35, 300, 2, '{"eb_sound_dart"}', '{"x": 1472, "y": -849}', '{"damage": "2d8", "range": "10m cone", "push_distance": "3m"}', '📢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4ad976c-0bf5-46cc-92c8-a1b3001837a4', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_shatter_pitch', 'Parçalayan Frekans', 'Shatter Pitch', 'Camı parçalayan ve yapay/kristal düşmanlara 4d8 (diğerlerine 3d8) hasar veren tiz bir ses.', 'A high-pitch sound that shatters glass and deals 4d8 damage to constructs/crystalline enemies (3d8 normal).', 'Sonic', 42, 400, 3, '{"eb_screeching_blade"}', '{"x": 1688, "y": -974}', '{"damage": "3d8", "conditional_damage": "4d8", "condition": "constructs/crystalline"}', '🎼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f3c59d3-4cbb-4fbd-bc2c-77802669130a', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_sonic_tornado', 'Sonik Kasırga', 'Sonic Tornado', '3 tur boyunca tur başına 4d6 hasar veren 5m genişliğinde bir ses kasırgası yaratır.', 'Creates a 5m wide tornado of sound that deals 4d6 damage per turn for 3 turns.', 'Sonic', 48, 450, 3, '{"eb_sonic_boom"}', '{"x": 1905, "y": -1099}', '{"damage": "4d6", "range": "5m width", "duration": "3 turns"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4587df89-f750-4af4-ad0b-fd67a931963b', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_piercing_whistle', 'Delici Islık', 'Piercing Whistle', '20m mesafeden hedefi hedef alan, 5d6 sonik hasar veren ve 1 tur sersemleten delici bir ıslık.', 'A targeted whistle dealing 5d6 sonic damage and stunning for 1 round at 20m.', 'Sonic', 55, 500, 3, '{"eb_soundwave_pulse"}', '{"x": 2121, "y": -1224}', '{"damage": "5d6", "range": "20m", "duration": "1 round", "status": "stunned"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2e0ef5e6-758c-4f8f-956c-6d433f950dcc', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_banshee_wail', 'Ölüm Perisi Feryadı', 'Banshee Wail', '15m yarıçapında 8d6 hasar veren bir feryat yayar; kurtarma zarında başarısız olan düşmanlar felç olur.', 'Emits a wail in a 15m radius dealing 8d6 damage; enemies failing a save are paralyzed.', 'Sonic', 62, 700, 4, '{"eb_shatter_pitch"}', '{"x": 2338, "y": -1349}', '{"damage": "8d6", "range": "15m radius", "status": "paralyzed"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5db26773-6689-42cf-a54d-dd9083d7870b', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_speed_of_sound', 'Ses Hızı', 'Speed of Sound', 'Kendini güçlendirir: 3 tur boyunca hareket hızı 3 katına çıkar ve saldırılar fazladan 3d8 sonik hasar verir.', 'Buffs self: move speed tripled, attacks deal extra 3d8 sonic damage for 3 rounds.', 'Sonic', 68, 800, 4, '{"eb_sonic_step"}', '{"x": 2554, "y": -1474}', '{"buff": "3x move speed", "bonus_damage": "3d8", "duration": "3 rounds"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('85ae1794-3df7-414b-b87d-8c077e8f9ce2', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_sonic_barrage', 'Sonik Yaylım Ateşi', 'Sonic Barrage', '20m içindeki rastgele düşmanlara her biri 2d6 hasar veren 10 adet sonik ok fırlatır.', 'Fires 10 sonic darts, each dealing 2d6 damage to random enemies in 20m.', 'Sonic', 75, 900, 4, '{"eb_sonic_tornado"}', '{"x": 2771, "y": -1599}', '{"projectiles": 10, "damage_per_projectile": "2d6", "range": "20m"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5228709e-3527-42a4-8f25-a46f9aef5971', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_symphony_of_destruction', 'Yıkım Senfonisi', 'Symphony of Destruction', 'Tüm düşmanları sağır eden, 10m geriye iten ve 12d10 sonik hasar veren devasa 30m''lik bir alan saldırısı.', 'A massive 30m AOE dealing 12d10 sonic damage, deafening and pushing all enemies 10m away.', 'Sonic', 90, 1500, 5, '{"eb_banshee_wail", "eb_sonic_barrage"}', '{"x": 2987, "y": -1724}', '{"damage": "12d10", "range": "30m AOE", "push_distance": "10m", "status": "deafened"}', '🎵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('678e0e6e-2d09-43cb-8c54-fab194a5f459', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_echo_strike', 'Yankı Vuruşu', 'Echo Strike', 'Bir düşmana vurduktan sonra, sonraki tur bir yankı ona %50 hasarla tekrar vurur.', 'After hitting an enemy, an echo hits them again next turn for 50% damage.', 'Echo', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"delay": "1 turn", "echo_damage": "50%"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b6c71417-d4b0-4c47-a38b-9d4f3232604b', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_phantom_sound', 'Hayalet Ses', 'Phantom Sound', 'Düşmanları dikkatini dağıtmak için 30m uzağa kadar yanılsamalı ayak sesleri veya sesler yaratır.', 'Creates illusory footsteps or sounds up to 30m away to distract enemies.', 'Echo', 5, 75, 1, '{}', '{"x": 289, "y": 344}', '{"range": "30m", "effect": "distraction"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1843a7fb-3afe-4455-a5e2-e11868a30f7d', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_repeating_edge', 'Tekrarlayan Kenar', 'Repeating Edge', 'Sonraki 3 saldırı 1d4 hasarlık bir yankı etkisi kazanır.', 'The next 3 attacks gain a 1d4 damage echo effect.', 'Echo', 10, 100, 1, '{}', '{"x": 449, "y": 536}', '{"charges": 3, "bonus_damage": "1d4"}', '🔁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cbca7387-f3c7-48d0-9699-dd9f79c58582', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_delay_cut', 'Gecikmeli Kesik', 'Delay Cut', 'Başlangıçta hasar vermeyen ancak 2 tur sonra 3d6 hasar veren bir vuruş.', 'A strike that deals no damage initially, but deals 3d6 damage after 2 rounds.', 'Echo', 15, 150, 1, '{"eb_echo_strike"}', '{"x": 610, "y": 727}', '{"damage": "3d6", "delay": "2 rounds"}', '⏱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4433314-ee15-4984-b374-7ec6c16fd9fd', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_double_echo', 'Çifte Yankı', 'Double Echo', 'Yankı vuruşları artık iki kez vurur ve her biri %30 hasar verir.', 'Echo strikes now hit twice, dealing 30% damage each.', 'Echo', 22, 200, 2, '{"eb_echo_strike"}', '{"x": 771, "y": 919}', '{"hits": 2, "echo_damage": "30% each"}', '👯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('abaab4d1-0be2-4eb7-9b64-15437bb2f57c', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_echo_decoy', 'Yankı Yemi', 'Echo Decoy', 'Sesten yapılmış, 1 vuruş alabilen ve yok olduğunda 3m içinde 2d6 hasarla patlayan bir kopya yaratır.', 'Creates a clone made of sound that takes 1 hit and explodes for 2d6 damage in 3m.', 'Echo', 28, 250, 2, '{"eb_phantom_sound"}', '{"x": 932, "y": 1110}', '{"hp": "1 hit", "explosion_damage": "2d6", "explosion_radius": "3m"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b73b4f7-b3b3-4097-81ef-b60256006f35', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_resounding_parry', 'Çınlayan Savuşturma', 'Resounding Parry', 'Bir saldırıyı savuşturur; engellenen hasar saldırgana 2d8 sonik hasar olarak yankılanır.', 'Parry an attack; the blocked damage echoes back to the attacker as 2d8 sonic damage.', 'Echo', 35, 300, 2, '{"eb_repeating_edge"}', '{"x": 1092, "y": 1302}', '{"type": "reaction", "reflection_damage": "2d8"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0356960a-8076-45b7-a0d4-e738f3ff8050', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_phantom_assault', 'Hayalet Saldırı', 'Phantom Assault', 'Hedefe her biri 3d6 hasar verip kaybolan 3 adet yankı kopyası çağırır.', 'Summons 3 echo clones that each strike a target for 3d6 damage and vanish.', 'Echo', 42, 400, 3, '{"eb_echo_decoy"}', '{"x": 1253, "y": 1493}', '{"clones": 3, "damage_per_clone": "3d6"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('52751891-a900-48ec-ac0d-9caa30ff1fab', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_reverberating_wounds', 'Yankılanan Yaralar', 'Reverberating Wounds', 'Hedefi lanetler: 3 tur boyunca hasar aldıklarında ekstra 2d6 yankı hasarı alırlar.', 'Curses a target: every time they take damage, they take an extra 2d6 echo damage for 3 rounds.', 'Echo', 48, 450, 3, '{"eb_double_echo"}', '{"x": 1414, "y": 1685}', '{"bonus_damage": "2d6", "trigger": "on taking damage", "duration": "3 rounds"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55224e57-2c03-4fcc-a001-a2a9bcdf90e9', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_echo_chamber', 'Yankı Odası', 'Echo Chamber', 'Bir düşmanı 4m''lik bir alana hapseder. İçeride aldıkları herhangi bir hasar duvarlardan sekerek onlara %50 güçle tekrar çarpar.', 'Traps an enemy in a 4m zone. Any damage they take inside bounces off walls, hitting them again for 50%.', 'Echo', 55, 500, 3, '{"eb_resounding_parry"}', '{"x": 1574, "y": 1876}', '{"range": "4m zone", "echo_damage": "50%"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7f6046f-5c61-4548-97d3-5f9f5704d199', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_infinite_echo', 'Sonsuz Yankı', 'Infinite Echo', '6d6 hasar veren bir vuruş. Eğer öldürürse, hasar yakındaki bir düşmana yankılanır ve öldürmeyene kadar sonsuz kez tekrarlanır.', 'A strike dealing 6d6 damage. If it kills, the damage echoes to a nearby enemy, repeating infinitely until it doesn''t kill.', 'Echo', 62, 700, 4, '{"eb_reverberating_wounds"}', '{"x": 1735, "y": 2068}', '{"damage": "6d6", "chain_condition": "on kill"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a146657-30ea-4931-90e3-b0189a1d75ad', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_mirror_of_sound', 'Ses Aynası', 'Mirror of Sound', 'Tüm menzilli mermi saldırılarını 2 tur boyunca saldırganlara geri yansıtır.', 'Reflects all ranged projectile attacks back at attackers for 2 turns.', 'Echo', 68, 800, 4, '{"eb_echo_chamber"}', '{"x": 1896, "y": 2259}', '{"effect": "projectile reflection", "duration": "2 turns"}', '🪩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('43590fa1-7d1e-47c8-be5f-d738a23d3c4c', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_temporal_echo', 'Zamansal Yankı', 'Temporal Echo', 'Konumunuzu ve sağlığınızı 1 tur önceki haline sıfırlar.', 'Resets your position and health to what it was 1 turn ago.', 'Echo', 75, 900, 4, '{"eb_phantom_assault"}', '{"x": 2056, "y": 2451}', '{"effect": "time rewind", "duration": "1 turn"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60dafe2d-954c-4002-bfd8-1cbb7ad9e62a', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_endless_crescendo', 'Sonsuz Kreşendo', 'Endless Crescendo', 'Bir işaret koyar. Hedefe yapılan her saldırı bir yankı ekler. 3 tur sonra, tüm yankılar birikmiş hasarın %100''ü kadar gerçek hasar vermek üzere aynı anda patlar.', 'Places a mark. Every attack on the target adds an echo. After 3 rounds, all echoes detonate at once for 100% accumulated damage as true damage.', 'Echo', 90, 1500, 5, '{"eb_infinite_echo", "eb_temporal_echo"}', '{"x": 2217, "y": 2642}', '{"duration": "3 rounds", "detonation_damage": "100% accumulated", "damage_type": "true damage"}', '🎻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('daa7bf2d-6e5e-4641-84e9-eacab7e5214e', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_vibrating_blade', 'Titreşen Kılıç', 'Vibrating Blade', 'Silah 2 zırh puanını görmezden gelir ve 1d6 hasar ekler.', 'Weapon ignores 2 points of armor, adding 1d6 damage.', 'Vibration', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"armor_pierce": 2, "bonus_damage": "1d6"}', '〰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fc908ecd-32ff-48b4-af72-4bdd1f6d1bf4', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_tremor_sense', 'Sismik His', 'Tremor Sense', '1 saat boyunca 15m sismik his kazanırsınız.', 'Gain 15m tremorsense for 1 hour.', 'Vibration', 5, 75, 1, '{}', '{"x": -289, "y": 344}', '{"range": "15m", "duration": "1 hour", "sense": "tremorsense"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7631981b-160b-4139-a9a8-72a4f04aeb8d', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_shattering_strike', 'Parçalayan Vuruş', 'Shattering Strike', 'Bir kalkana veya zırha vurarak düşmanın Zırh Sınıfını (AC) 1 azaltır.', 'Hits a shield or armor, reducing enemy AC by 1.', 'Vibration', 10, 100, 1, '{}', '{"x": -449, "y": 536}', '{"ac_reduction": 1}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1125874d-cdcb-49c0-bc4a-47bbfdf50e20', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_resonance_touch', 'Rezonans Dokunuşu', 'Resonance Touch', '1d10 içsel hasar veren yakın dövüş dokunuşu.', 'A melee touch dealing 1d10 internal damage.', 'Vibration', 15, 150, 1, '{"eb_vibrating_blade"}', '{"x": -610, "y": 727}', '{"damage": "1d10", "damage_type": "internal"}', '🖐️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bd1a60e6-e5f6-4999-af3b-8a59bc93ee36', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_internal_rupture', 'İçsel Yırtılma', 'Internal Rupture', 'Düşmanın organlarına vurur. 2d8 hasar, hedef 3 tur boyunca tur başına 1d4 kanar.', 'Hits enemy organs. 2d8 damage, target bleeds 1d4 per turn for 3 turns.', 'Vibration', 22, 200, 2, '{"eb_resonance_touch"}', '{"x": -771, "y": 919}', '{"damage": "2d8", "bleed_damage": "1d4 per turn", "duration": "3 turns"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2448f724-814d-4bfd-a67f-4ece0f567099', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_quake_step', 'Deprem Adımı', 'Quake Step', 'Her adım yeri sarsarak etrafınızdaki 3m''lik yarıçapı zorlu araziye dönüştürür.', 'Every step shakes the ground, making a 3m radius difficult terrain around you.', 'Vibration', 28, 250, 2, '{"eb_tremor_sense"}', '{"x": -932, "y": 1110}', '{"range": "3m radius", "effect": "difficult terrain"}', '🥾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca8f234c-7da7-405c-a3b8-d81a7f574ae3', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_armor_bypass', 'Zırh Delme', 'Armor Bypass', 'Sonraki saldırı fiziksel zırhı tamamen görmezden gelir ve gerçek hasar verir.', 'Next attack completely ignores physical armor and deals true damage.', 'Vibration', 35, 300, 2, '{"eb_shattering_strike"}', '{"x": -1092, "y": 1302}', '{"effect": "ignore armor", "damage_type": "true damage"}', '🔓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1cda93b5-f27e-4e58-9115-1717f1523666', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_high_frequency_blade', 'Yüksek Frekanslı Kılıç', 'High Frequency Blade', 'Silah yüksek frekansta titreşir. 4d8 hasar verir ve çeliği kolayca keser.', 'Weapon vibrates at high frequency. Deals 4d8 damage and easily cuts through steel.', 'Vibration', 42, 400, 3, '{"eb_armor_bypass"}', '{"x": -1253, "y": 1493}', '{"damage": "4d8", "material_bypass": "steel"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d71f42f-e1d5-4602-86da-ed5ade11d2b7', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_seismic_wave', 'Sismik Dalga', 'Seismic Wave', 'Yere vurarak 15m''lik sarsılan bir toprak hattı gönderir, 4d6 hasar verir ve yere serer.', 'Strikes the ground, sending a 15m line of trembling earth dealing 4d6 damage and knocking prone.', 'Vibration', 48, 450, 3, '{"eb_quake_step"}', '{"x": -1414, "y": 1685}', '{"damage": "4d6", "range": "15m line", "status": "prone"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e3829799-3be9-4dff-9940-1001bcd7f5b3', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_disrupting_rhythm', 'Bozan Ritim', 'Disrupting Rhythm', 'Hedefe vurarak iç ritmini bozar ve 2 tur boyunca saldırılarda dezavantaj verir.', 'Hits the target, disrupting their internal rhythm and giving disadvantage on attacks for 2 turns.', 'Vibration', 55, 500, 3, '{"eb_internal_rupture"}', '{"x": -1574, "y": 1876}', '{"status": "disadvantage on attacks", "duration": "2 turns"}', '💓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a5d7893b-fc99-4bd3-91d6-4ac0d54fd223', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_molecular_shatter', 'Moleküler Parçalanma', 'Molecular Shatter', 'Hedefin moleküllerini titreştirir. 8d8 hasar, büyülü olmayan giyilen zırhı yok eder.', 'Vibrates the target''s molecules. 8d8 damage, destroying non-magical worn armor.', 'Vibration', 62, 700, 4, '{"eb_high_frequency_blade"}', '{"x": -1735, "y": 2068}', '{"damage": "8d8", "effect": "destroy non-magical armor"}', '⚛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34c9776f-a4a3-462e-8943-5a685810e3ac', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_tectonic_shift', 'Tektonik Kayma', 'Tectonic Shift', 'Fay hatları yaratan ve 6d10 hasar veren devasa 20m''lik bir deprem yaratır.', 'Creates a massive 20m earthquake dealing 6d10 damage and creating fissures.', 'Vibration', 68, 800, 4, '{"eb_seismic_wave"}', '{"x": -1896, "y": 2259}', '{"damage": "6d10", "range": "20m radius", "effect": "fissures"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('940fbec5-cb3e-4795-bd74-9da9f7b88a2a', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_heart_resonance', 'Kalp Rezonansı', 'Heart Resonance', 'Kalbi hedefler. 5d10 hasar verir; hedef %20 Canın altındaysa anında ölüm gerçekleşir.', 'Targets the heart. Deals 5d10 damage; if target is below 20% HP, instant death.', 'Vibration', 75, 900, 4, '{"eb_disrupting_rhythm"}', '{"x": -2056, "y": 2451}', '{"damage": "5d10", "condition": "< 20% HP", "effect": "instant death"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cae8f7ee-c46e-46e3-a194-92019cad5af7', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_absolute_vibration', 'Mutlak Titreşim', 'Absolute Vibration', 'Tüm bedeninizi titreştirerek fiziksel hasara bağışıklık kazandırır ve saldırıların tüm savunmalardan geçerek 3 tur boyunca 10d12 gerçek hasar vermesini sağlar.', 'Vibrates your entire body, making you immune to physical damage and allowing attacks to phase through all defenses, dealing 10d12 true damage for 3 turns.', 'Vibration', 90, 1500, 5, '{"eb_molecular_shatter", "eb_heart_resonance"}', '{"x": -2217, "y": 2642}', '{"buff": "physical immunity", "attack_effect": "ignore all defenses", "damage": "10d12 true damage", "duration": "3 turns"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33ad8916-d8a0-4771-886f-aaa6a29825ad', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_echolocating_dart', 'Yankıyla Yönelen Ok', 'Echolocating Dart', 'Bir ok (1d8) fırlatır. Vurursa, hedef izlenir ve onlara karşı yapılan sonraki saldırı avantajlı olup +1d8 hasar verir.', 'Fires a dart (1d8). If it hits, the target is tracked, and the next attack against them has advantage and deals +1d8.', 'Cross-Branch', 30, 250, 2, '{"eb_sound_dart", "eb_phantom_sound"}', '{"x": -173, "y": -100}', '{"damage": "1d8", "status": "tracked", "next_attack": "advantage + 1d8 damage"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a585c3a-a257-4606-97d1-6124597f4b4a', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_tremor_echo', 'Sismik Yankı', 'Tremor Echo', 'Aynı noktada 1 tur sonra aynı hasarla kendini tekrarlayan bir deprem (2d6, 5m).', 'An earthquake (2d6, 5m) that repeats itself 1 turn later in the same spot for the same damage.', 'Cross-Branch', 35, 280, 2, '{"eb_double_echo", "eb_quake_step"}', '{"x": -389, "y": -225}', '{"damage": "2d6", "range": "5m radius", "delay": "1 turn echo"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fc8498e7-8f7c-4921-b6ea-acf2f4d8000c', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_resonating_boom', 'Rezonans Patlaması', 'Resonating Boom', '6m yarıçapında 3d6 hasar veren ve düşman zırhını 2 azaltan bir sonik patlama.', 'A sonic boom (3d6) that also reduces enemy armor by 2 in a 6m radius.', 'Cross-Branch', 38, 300, 2, '{"eb_shattering_strike", "eb_sonic_boom"}', '{"x": -606, "y": -350}', '{"damage": "3d6", "ac_reduction": 2, "range": "6m radius"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aada504c-8b69-4a2e-97da-4bb9fd9d7e85', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_phantom_siren', 'Hayalet Siren', 'Phantom Siren', 'Tur başına 3d6 sonik hasar veren ve düşmanları kendine doğru çeken (10m çekim) yanılsamalı bir siren yaratır.', 'Creates an illusory siren that wails, dealing 3d6 sonic damage per turn and pulling enemies toward it (10m pull).', 'Cross-Branch', 50, 450, 3, '{"eb_piercing_whistle", "eb_phantom_assault"}', '{"x": -822, "y": -475}', '{"damage": "3d6 per turn", "pull_distance": "10m"}', '🧜‍♀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74641f13-1cb0-4d25-b108-56f46ecfb810', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_shattering_reflection', 'Parçalayan Yansıma', 'Shattering Reflection', 'Vurulduğunuzda yankınız parçalanır, saldırgana 4d6 delici hasar verir ve zırhlarını görmezden gelir.', 'When hit, your echo shatters, dealing 4d6 piercing damage to the attacker and ignoring their armor.', 'Cross-Branch', 55, 480, 3, '{"eb_resounding_parry", "eb_high_frequency_blade"}', '{"x": -1039, "y": -600}', '{"trigger": "on hit", "damage": "4d6 piercing", "effect": "ignore armor"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('013860ef-fc6b-49d8-83ca-68e4eb1b5889', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_sonic_earthquake', 'Sonik Deprem', 'Sonic Earthquake', '15m yarıçapında 5d6 hasar veren ve hedefleri 2 tur boyunca sağır eden bir sarsıntı.', 'A 15m radius quake dealing 5d6 damage and deafening targets for 2 rounds.', 'Cross-Branch', 60, 500, 3, '{"eb_seismic_wave", "eb_sonic_tornado"}', '{"x": -1255, "y": -725}', '{"damage": "5d6", "range": "15m radius", "status": "deafened", "duration": "2 rounds"}', '🫨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('88719cf9-c3c6-4da1-b306-782a70587748', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_harmonic_convergence', 'Harmonik Kavuşum', 'Harmonic Convergence', '3 prensibi birleştirir. Hedefe 8d8 hasar verir, zırhı yoksayar, onları sağır eder ve sonraki tur hasarın %50''sini yankılar.', 'Combines all 3 principles. Deals 8d8 damage to a target, ignores armor, deafens them, and echoes 50% damage next turn.', 'Cross-Branch', 75, 850, 4, '{"eb_banshee_wail", "eb_infinite_echo", "eb_molecular_shatter"}', '{"x": -1472, "y": -850}', '{"damage": "8d8", "effect": "ignore armor", "status": "deafened", "delay": "1 turn", "echo_damage": "50%"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('28d8479d-f7c4-4c1e-98a0-bb3dc6cb3b30', '824a8d7b-e124-4d4f-80f0-2471c1fb3757', 'eb_omega_frequency', 'Omega Frekansı', 'Omega Frequency', 'Kusursuz frekans. Saf ses kullanarak hedefin maddesini siler. 20d12 gerçek hasar. Eğer hayatta kalırlarsa, zırhları kalıcı olarak 0 olur ve kalıcı olarak sağır kalırlar. Menzil 10m.', 'The perfect frequency. Erases the target''s matter using pure sound. 20d12 true damage. If they survive, their armor is permanently 0 and they are permanently deafened. Range 10m.', 'Cross-Branch', 100, 1500, 5, '{"eb_symphony_of_destruction", "eb_endless_crescendo", "eb_absolute_vibration"}', '{"x": -1688, "y": -975}', '{"damage": "20d12 true damage", "range": "10m", "effect_if_survive": "armor becomes 0, permanent deafness"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f256da37-4646-4d20-b3c5-ba5751ad0700', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_ignited_blade', 'Ateşlenmiş Kılıç', 'Ignited Blade', 'Silahına temel ateş büyüsü yönlendir. Vuruşların ek ateş hasarı verir ve 2m yarıçapı aydınlatır.', 'Channel basic fire magic into your weapon. Your strikes deal additional fire damage and illuminate a 2m radius.', 'Flame Sword', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d6 fire", "duration": "1 minute", "range": "Self"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d86765c9-cb6f-40c2-9b9c-f8deda3d1dda', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_searing_slash', 'Yakıcı Kesiş', 'Searing Slash', 'Yoğun ısıyla bezenmiş geniş yatay bir saldırı, menzilini uzatır ve hedefi kavurur.', 'A wide horizontal attack imbued with intense heat, extending your reach and scorching the target.', 'Flame Sword', 3, 75, 1, '{"es_flame_ignited_blade"}', '{"x": 389, "y": -224}', '{"damage": "1d8 fire", "range": "2m reach"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('72113353-48cf-47c4-bb89-158899062ce6', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_ember_deflect', 'Köz Yansıtması', 'Ember Deflection', 'Gelen bir saldırıyı kıvılcım patlamasıyla engellemek için reaksiyonunu kullan; savunmanı artırır ve saldıranı yakar.', 'Use your reaction to block an incoming attack with a burst of sparks, boosting your defense and burning the attacker.', 'Flame Sword', 8, 100, 1, '{"es_flame_ignited_blade"}', '{"x": 606, "y": -349}', '{"ac_bonus": "+2", "damage": "1d4 fire to attacker", "type": "Reaction"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('56b40555-9013-45fa-9cfb-dfea544d1989', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_sweep', 'Alev Savurması', 'Flame Sweep', 'Önündeki tüm düşmanları yakan, geniş açılı bir alev kavisini serbest bırak.', 'Unleash a sweeping arc of fire that burns all enemies in front of you.', 'Flame Sword', 14, 150, 1, '{"es_flame_searing_slash"}', '{"x": 822, "y": -474}', '{"damage": "2d6 fire", "area": "3m cone"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc1e7396-dd34-4c77-bed3-6c4fd1689be8', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_burning_thrust', 'Yanan Saplama', 'Burning Thrust', 'Bir hat üzerindeki birden fazla hedefi deşip geçen yoğun bir ateşli saplama ile ileri atıl ve onları ateşe ver.', 'Lunge forward with a concentrated fiery stab that pierces multiple targets in a line, setting them ablaze.', 'Flame Sword', 21, 200, 2, '{"es_flame_sweep"}', '{"x": 1039, "y": -599}', '{"damage": "3d6 fire", "area": "5m line", "status": "Burn (1d4 fire per turn)"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9562f9e5-a40f-4954-b846-cba6e552938e', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_volcanic_step', 'Volkanik Adım', 'Volcanic Step', 'Savaş alanında hızla atıl ve üzerinden geçen herkese hasar veren aşırı sıcak bir magma izi bırak.', 'Dash swiftly across the battlefield, leaving a trail of superheated magma that damages anyone crossing it.', 'Flame Sword', 25, 220, 2, '{"es_flame_burning_thrust"}', '{"x": 1255, "y": -724}', '{"movement": "Dash up to 6m", "hazard_damage": "2d4 fire per cross", "duration": "2 turns"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb63ace8-6ddf-4e6f-82c1-b9a4c137af22', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_cauterize', 'Dağlayan Vuruş', 'Cauterizing Strike', 'Düşmanın yaralarını kavuran ve onların can yenilemesini engelleyen acımasız bir alevli vuruş.', 'A brutal flaming strike that scorches the enemy''s wounds, preventing them from regaining hit points.', 'Flame Sword', 32, 260, 2, '{"es_flame_burning_thrust"}', '{"x": 1472, "y": -849}', '{"damage": "2d8 fire", "status": "Target cannot heal for 1 turn"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('630f423e-9b19-4b4f-93c5-74c4e74341d5', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_inferno_parry', 'Cehennem Savuşturması', 'Inferno Parry', 'Bir saldırıyı kusursuzca savuşturarak yerel bir ateş patlamasını tetikle; saldırganı ve yakındaki düşmanları havaya uçur.', 'Parry an attack perfectly to trigger a localized explosion of fire, blasting the attacker and nearby foes.', 'Flame Sword', 38, 300, 2, '{"es_flame_ember_deflect"}', '{"x": 1688, "y": -974}', '{"damage": "3d6 fire", "area": "2m radius around attacker", "type": "Reaction"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31e7c873-d9c8-4e1b-94f5-694650b6f239', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_blazing_cyclone', 'Alevli Kasırga', 'Blazing Cyclone', 'Alevler içindeki kılıcınla dönerek düşmanları geriye savuran bir ateş girdabı yarat.', 'Spin with your sword engulfed in flames, creating a vortex of fire that pushes enemies back.', 'Flame Sword', 44, 380, 3, '{"es_flame_cauterize", "es_flame_volcanic_step"}', '{"x": 1905, "y": -1099}', '{"damage": "4d8 fire", "area": "3m radius", "push": "2m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2c346b50-9b5c-4d77-a974-acf5215a2187', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_furnace_heart', 'Fırın Yürek', 'Furnace Heart', 'İç sıcaklığını sınırın ötesine taşı. Ateş ve soğuğa bağışıklık kazan ve tüm vuruşlarında devasa ek ateş hasarı ver.', 'Overclock your internal temperature. Gain immunity to fire and cold, and deal massive extra fire damage on all hits.', 'Flame Sword', 50, 420, 3, '{"es_flame_blazing_cyclone"}', '{"x": 2121, "y": -1224}', '{"buff": "Immune to fire/cold", "bonus_damage": "+1d8 fire on all attacks", "duration": "1 minute"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('224ddb18-2768-4dcc-aeb2-255b9904d800', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_explosive_exec', 'Patlayıcı İnfaz', 'Explosive Execution', 'Yıkıcı bir tek hedef vuruşu yap. Eğer hedef ölürse, bedeni şiddetli bir ateş topuna dönüşerek patlar.', 'Deliver a devastating single-target blow. If the target dies, their body erupts into a violent fireball.', 'Flame Sword', 58, 480, 3, '{"es_flame_blazing_cyclone"}', '{"x": 2338, "y": -1349}', '{"damage": "6d8 fire", "on_kill": "Explodes for 4d6 fire in 4m radius"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95136fe9-8469-49b1-94fb-da3a37690eca', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_meteor_cleave', 'Meteor Yarığı', 'Meteor Cleave', 'Havaya sıçra ve alevli kılıcını yere çarparak devasa erimiş bir krater yarat.', 'Leap high into the air and slam your flaming sword into the earth, creating a massive molten crater.', 'Flame Sword', 66, 700, 4, '{"es_flame_explosive_exec"}', '{"x": 2554, "y": -1474}', '{"leap": "Up to 10m", "damage": "8d8 fire", "area": "6m radius"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('160a76d2-25e1-410f-bf0f-b7488d292926', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_sunblade', 'Güneşkılıcı Uyanışı', 'Sunblade Awakening', 'Kılıcın bir yıldızın yoğunluğuyla yanar. Radyant ve ateş hasarı verir, her vuruşta düşmanları kör etme ihtimali vardır.', 'Your sword burns with the intensity of a star. Deals radiant and fire damage, and has a chance to blind enemies on every hit.', 'Flame Sword', 75, 850, 4, '{"es_flame_meteor_cleave", "es_flame_furnace_heart"}', '{"x": 2771, "y": -1599}', '{"bonus_damage": "+2d10 fire/radiant", "status": "Blind on failed WIS save", "duration": "1 minute"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d26a1f0-2aff-4a9e-abfb-375317b9e6ab', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_flame_supernova', 'Süpernova Vuruşu', 'Supernova Strike', 'ULTİMAT: Alevinin nihai tezahürünü patlat. Dirençleri eriten kozmik bir ateşin felaket getiren patlamasını serbest bırak.', 'ULTIMATE: Detonate the ultimate expression of your flame. Release a catastrophic explosion of cosmic fire that melts through resistances.', 'Flame Sword', 90, 1300, 5, '{"es_flame_sunblade"}', '{"x": 2987, "y": -1724}', '{"damage": "15d10 fire", "area": "15m radius", "special": "Ignores fire resistance, targets burn for 3d10/turn"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf3e2dd8-c32e-4d3b-a2cb-a5d14dc83d37', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_chilling_edge', 'Dondurucu Kenar', 'Chilling Edge', 'Kılıcını ayazla kapla. Vuruşlar ek soğuk hasarı verir ve düşmanın sıcaklığını emerek hareket hızlarını azaltır.', 'Coat your blade in frost. Strikes deal extra cold damage and sap the enemy''s warmth, reducing their movement speed.', 'Frost Sword', 1, 50, 1, '{}', '{"x": 173, "y": 99}', '{"damage": "1d4 cold", "status": "Reduces speed by 3m", "duration": "1 minute"}', '❄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d2024732-8116-464c-a406-0f201615f045', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_piercing_icicle', 'Delici Buzsarkıtı', 'Piercing Icicle', 'Uzak bir düşmana hızlı ve keskin sihirli bir buz parçası fırlatmak için kılıcını sapla.', 'Thrust your sword to launch a fast, sharp shard of magical ice at a distant enemy.', 'Frost Sword', 4, 80, 1, '{"es_frost_chilling_edge"}', '{"x": 389, "y": 224}', '{"damage": "1d8 cold", "range": "10m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e3be145-ebda-4b11-aa65-a902d42081e6', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_frostguard', 'Ayazmuhafızı Duruşu', 'Frostguard Stance', 'Zırhının üzerinde sertleşmiş bir buz tabakası oluştur. Geçici can puanı verir ve yakın dövüş saldırganlarına dondurucu soğukla karşılık verir.', 'Form a layer of hardened ice over your armor. Grants temporary hit points and retaliates against melee attackers with chilling cold.', 'Frost Sword', 9, 110, 1, '{"es_frost_chilling_edge"}', '{"x": 606, "y": 349}', '{"temp_hp": "1d10", "retaliation": "1d4 cold to melee attackers", "duration": "1 minute"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d4ebcde-4aaa-402b-b339-dd0849906e40', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_glacial_sweep', 'Buzul Savurma', 'Glacial Sweep', 'Düşmanlara hasar veren ve bacaklarını yere dondurma riski taşıyan geniş bir dondurucu rüzgar kavisi savur.', 'Swing a wide arc of freezing wind that damages and risks freezing enemies'' legs to the ground.', 'Frost Sword', 15, 160, 1, '{"es_frost_piercing_icicle"}', '{"x": 822, "y": 474}', '{"damage": "2d6 cold", "area": "3m cone", "status": "Speed halved on failed STR save"}', '🌨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3ea94c0-c2c1-4e60-9482-12905385190a', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_hoarfrost_thrust', 'Kırağı Saplaması', 'Hoarfrost Thrust', 'Tırtıklı bir ayaz hattı fırlatan derin bir hamle. İçinde kalan düşmanlar ani donma nedeniyle kısıtlanabilir.', 'A deep lunge that shoots a line of jagged frost. Foes caught within might be restrained by the sudden freeze.', 'Frost Sword', 22, 210, 2, '{"es_frost_glacial_sweep"}', '{"x": 1039, "y": 599}', '{"damage": "3d6 cold", "area": "5m line", "status": "Restrained on failed CON save"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e849e1c-9725-4bf7-91fa-872dbb20630a', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_ice_slide', 'Buz Kayışı', 'Ice Slide', 'Savaş alanında zarafetle süzülmek için kaygan bir buz yolu oluştur; hareket halindeyken savunmanı artırır.', 'Create a slick path of ice to glide gracefully across the battlefield, increasing your defense while moving.', 'Frost Sword', 27, 240, 2, '{"es_frost_hoarfrost_thrust"}', '{"x": 1255, "y": 724}', '{"movement": "Dash up to 8m", "ac_bonus": "+2 during movement", "special": "Ignores difficult terrain"}', '⛸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1690253-d26f-490c-9f66-ae985164e726', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_shattering_strike', 'Parçalayan Vuruş', 'Shattering Strike', 'Donmuş savunmaları kırmak için tasarlanmış ağır bir darbe. Hedef zaten yavaşlamış veya donmuşsa devasa hasar verir.', 'A heavy blow designed to crack frozen defenses. Deals massive damage if the target is already slowed or frozen.', 'Frost Sword', 34, 280, 2, '{"es_frost_hoarfrost_thrust"}', '{"x": 1472, "y": 849}', '{"damage": "4d6 cold", "special": "Damage doubled against slowed/frozen targets"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e763f64-4ec7-48a3-922c-d664c96cf0b7', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_winters_reflection', 'Kışın Yansıması', 'Winter''s Reflection', 'Bir reaksiyon olarak kalın bir buz aynası çağır. Gelen hasarı emer ve kırılarak yarısını soğuk hasarı olarak geri yansıtır.', 'Summon a mirror of thick ice as a reaction. It absorbs incoming damage and shatters to reflect half of it back as cold damage.', 'Frost Sword', 39, 300, 2, '{"es_frost_frostguard"}', '{"x": 1688, "y": 974}', '{"absorb": "up to 3d8 damage", "reflect": "Half of absorbed damage as cold", "type": "Reaction"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8f8a242a-6372-4a96-bf72-f2a71c4304b0', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_avalanche_spin', 'Çığ Dönüşü', 'Avalanche Spin', 'Vahşice dönerek düşmanları ezen ve ayaklarını yerden kesen ağır bir kar ve buz şelalesi serbest bırak.', 'Spin wildly, releasing a cascade of heavy snow and ice that bludgeons enemies and knocks them off their feet.', 'Frost Sword', 45, 390, 3, '{"es_frost_shattering_strike"}', '{"x": 1905, "y": 1099}', '{"damage": "5d6 cold", "area": "4m radius", "status": "Prone on failed STR save"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d2c67f3a-efe6-4295-8296-b8366115c600', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_permafrost', 'Kalıcıbuz Zırhı', 'Permafrost Armor', 'Kendini kırılmaz buzul buzuyla sar. Yüksek fiziksel direnç ve önemli bir zırh takviyesi kazan.', 'Encase yourself in unbreakable glacial ice. Gain high physical resistance and a substantial armor boost.', 'Frost Sword', 52, 440, 3, '{"es_frost_avalanche_spin"}', '{"x": 2121, "y": 1224}', '{"ac_bonus": "+3", "resistance": "Non-magical physical damage", "duration": "1 minute"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('51c53006-deea-4fb6-b28d-f5c391beef64', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_flash_freeze', 'Ani Donma', 'Flash Freeze', 'Hedefin kalbini geçici olarak durduran, onları sersemleten ve tamamen donduran korkutucu derecede soğuk bir isabetli vuruş.', 'A terrifyingly cold precision strike that stops a target''s heart temporarily, stunning and freezing them solid.', 'Frost Sword', 59, 490, 3, '{"es_frost_avalanche_spin"}', '{"x": 2338, "y": 1349}', '{"damage": "4d8 cold", "status": "Stunned (Frozen solid) for 1 turn on failed CON save"}', '🥶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('47539746-104a-440a-b251-2945cbe0d812', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_absolute_zero', 'Mutlak Sıfır Kılıcı', 'Absolute Zero Blade', 'Kılıcın mutlak sıfır derecesine düşer. Vuruşlar zırhı kırılganlaşana kadar dondurarak düşman savunmalarını ciddi şekilde azaltır.', 'Your blade drops to absolute zero. Strikes freeze armor until it becomes brittle, severely reducing enemy defenses.', 'Frost Sword', 68, 750, 4, '{"es_frost_flash_freeze"}', '{"x": 2554, "y": 1474}', '{"damage": "6d8 cold", "range": "3m", "debuff": "-2 AC to target"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('53640031-05c3-4913-94b3-0184d232f978', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_glacier_tomb', 'Buzul Mezarı', 'Glacier Tomb', 'Tek bir hedefi devasa mistik bir buz kütlesinin içine hapset; onları tamamen tuzağa düşürürken aşırı soğukla ezer.', 'Entomb a single target in a massive block of mystical ice, crushing them with extreme cold while trapping them completely.', 'Frost Sword', 76, 880, 4, '{"es_frost_absolute_zero", "es_frost_permafrost"}', '{"x": 2771, "y": 1599}', '{"damage": "8d8 cold per turn trapped", "status": "Trapped in 3x3m ice block", "save": "DEX save to avoid"}', '⚰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41b9da9b-d3bd-44ad-a360-0a5eb1c58dd4', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_frost_epoch_of_ice', 'Buz Çağı', 'Epoch of Ice', 'ULTİMAT: Savaş alanını bölgesel bir buz çağına sok. Havadaki tüm nemi dondurarak düşmanları oldukları yerde durdurur.', 'ULTIMATE: Plunge the battlefield into a localized ice age. Freezes all moisture in the air, halting enemies in their tracks.', 'Frost Sword', 90, 1300, 5, '{"es_frost_glacier_tomb"}', '{"x": 2987, "y": 1724}', '{"damage": "12d10 cold", "area": "20m radius", "status": "Speed becomes 0, lose reactions", "duration": "3 turns"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a285d416-35e5-46e7-875f-918c685da76d', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_sparking_blade', 'Kıvılcımlı Kılıç', 'Sparking Blade', 'Silahını elektriklendir. Vuruşlar ek yıldırım hasarı verir ve kıvılcımlar yakındaki ikincil bir hedefe sıçrayabilir.', 'Electrify your weapon. Hits deal additional lightning damage and sparks can arc to a secondary nearby target.', 'Storm Sword', 1, 50, 1, '{}', '{"x": 0, "y": 200}', '{"damage": "1d4 lightning", "arc_damage": "1d4 to 1 nearby target"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3bc76a2-d508-4607-a8cb-99a3a6ac46b8', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_zephyr_slash', 'Meltem Kesişi', 'Zephyr Slash', 'Savaş alanında yüksek basınçlı kesici bir rüzgar dalgası fırlatmak için kılıcını savur.', 'Swing your blade to launch a slicing wave of highly compressed wind across the battlefield.', 'Storm Sword', 5, 85, 1, '{"es_storm_sparking_blade"}', '{"x": 0, "y": 450}', '{"damage": "1d8 slashing/thunder", "range": "8m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a992e86e-8847-4626-95be-4dee32187acf', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_tailwind_step', 'Kuyrukrüzgarı Adımı', 'Tailwind Step', 'Bir bonus eylem olarak rüzgarı kullanarak kendini ileri it; hızını artır ve düşmanların yanından zarafetle süzül.', 'Use the wind to propel yourself forward as a bonus action, boosting your speed and slipping past enemies gracefully.', 'Storm Sword', 10, 120, 1, '{"es_storm_sparking_blade"}', '{"x": 0, "y": 700}', '{"bonus_movement": "+5m", "special": "Ignores opportunity attacks", "type": "Bonus Action"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e25aebf7-2747-405e-8ab6-d8eb9211df6e', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_thunderclap', 'Gök Gürültüsü Vuruşu', 'Thunderclap Strike', 'Bir fırtınanın yankılanan gücüyle vur. Sonik hasar verir ve hedefi agresif bir şekilde geriye iter.', 'Strike with the echoing force of a tempest. Deals sonic damage and aggressively shoves the target backward.', 'Storm Sword', 16, 165, 1, '{"es_storm_zephyr_slash"}', '{"x": 0, "y": 950}', '{"damage": "1d6 thunder", "push": "3m backward"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('557d1ce9-3c02-417b-82dd-34c448c4767d', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_lightning_lunge', 'Yıldırım Hamlesi', 'Lightning Lunge', 'Saf bir yıldırım okuna dönüş ve hedefe anında ışınlanarak şok edici bir saplama ile ortaya çık.', 'Transform into a bolt of pure lightning and instantly teleport to a target, manifesting with a shocking stab.', 'Storm Sword', 23, 220, 2, '{"es_storm_thunderclap"}', '{"x": 0, "y": 1200}', '{"teleport": "Up to 10m", "damage": "3d6 lightning"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1ccd6ece-a9af-4956-9de3-3591b1b881f4', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_cyclone_parry', 'Siklon Savuşturması', 'Cyclone Parry', 'Kılıcını mini bir kasırgaya çevirerek mermilere reaksiyon göster; atışı savuştur ve ileriye gök gürültülü bir dalga gönder.', 'React to projectiles by spinning your blade into a miniature tornado, deflecting the shot and sending a thunderous wave forward.', 'Storm Sword', 28, 250, 2, '{"es_storm_tailwind_step"}', '{"x": 0, "y": 1450}', '{"deflect": "Ranged attacks", "counter_damage": "2d8 thunder in 3m line", "type": "Reaction"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e8b78b05-1846-45c5-b4fb-e1e0f3bc7ca5', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_chain_lightning', 'Zincirleme Yıldırım Vuruşu', 'Chain Lightning Strike', 'Uçucu elektrik boşaltan ağır bir tepeden vuruş; yakındaki diğer hedeflere şiddetle seker.', 'A heavy overhead strike that discharges volatile electricity, violently arcing to multiple other targets in the vicinity.', 'Storm Sword', 35, 290, 2, '{"es_storm_lightning_lunge"}', '{"x": 0, "y": 1700}', '{"primary_damage": "3d6 lightning", "arc_damage": "2d6 lightning to up to 3 targets in 5m"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3c0a266c-81bb-43b2-a587-6e8d325f387f', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_tempest_aura', 'Fırtına Halesi', 'Tempest Aura', 'Kendini bölgesel bir fırtınayla sar. Sana yaklaşmaya cüret eden düşmanları pasif yıldırımlar çarpar.', 'Surround yourself with a localized storm. Passive lightning strikes zap enemies who dare approach you.', 'Storm Sword', 40, 310, 2, '{"es_storm_lightning_lunge"}', '{"x": 0, "y": 1950}', '{"aura": "2m radius", "damage": "1d8 lightning at start of your turn", "duration": "1 minute"}', '⛈️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fac7f4fb-df9f-4a1f-a2fc-6e64947290b3', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_sonic_boom', 'Ses Patlaması Dönüşü', 'Sonic Boom Spin', 'O kadar şiddetli bir hızla dön ki ses bariyerini kır; düşmanları sağır et ve devasa bir şok dalgasıyla ez.', 'Spin with such ferocious speed that you break the sound barrier, deafening foes and crushing them with a massive shockwave.', 'Storm Sword', 46, 400, 3, '{"es_storm_chain_lightning"}', '{"x": 0, "y": 2200}', '{"damage": "4d8 thunder", "area": "5m radius", "status": "Deafened"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5a3a33d0-ecaa-4679-9c8c-4ee21f6d4274', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_gale_thrust', 'Bora Gücü Saplaması', 'Gale Force Thrust', 'Kılıcının ucundan odaklanmış bir kasırga yönlendir. Devasa bir rüzgar patlaması yolundaki her şeyi geriye iter.', 'Channel a focused hurricane through the tip of your sword. A massive blast of wind pushes back everything in its path.', 'Storm Sword', 53, 450, 3, '{"es_storm_sonic_boom"}', '{"x": 0, "y": 2450}', '{"damage": "5d8 thunder", "area": "15m line", "push": "5m and knocked prone"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0fb1b21d-ef06-4b84-80d3-18e70a68f7dc', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_overcharge', 'Aşırı Yükleme', 'Overcharge', 'Kendi sinir sisteminden devasa bir elektrik enerjisi geçir; tepki sürelerini ve hareketlerini muazzam derecede hızlandırır.', 'Surge immense electrical energy through your own nervous system, vastly accelerating your reaction times and movement.', 'Storm Sword', 60, 500, 3, '{"es_storm_sonic_boom"}', '{"x": 0, "y": 2700}', '{"buff": "Haste (+1 action, +5m speed)", "bonus_damage": "+2d6 lightning on attacks", "duration": "1 minute"}', '🔋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cd935b19-7856-4955-99ec-c247b58e24ae', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_skysplitter', 'Gökyaran', 'Sky-Splitter', 'Hedefinin tam üzerine yok edici bir yıldırım sütunu indirmek için kılıcını göklere kaldır.', 'Raise your blade to the heavens to call down a pillar of annihilating lightning directly upon your target.', 'Storm Sword', 69, 780, 4, '{"es_storm_gale_thrust"}', '{"x": 0, "y": 2950}', '{"damage": "8d8 lightning", "area": "10m vertical column", "radius": "2m"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('138ab697-e552-4a12-8ac9-b1fad4029bdf', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_vacuum_blade', 'Vakum Kılıcı', 'Vacuum Blade', 'Havayı o kadar hızlı kes ki bir vakum tekilliği oluşsun; yakındaki tüm düşmanları şiddetle yakın dövüş menziline çeker ve parçalar.', 'Slice the air so fast it creates a vacuum singularity, violently pulling all nearby enemies into melee range before rending them.', 'Storm Sword', 78, 900, 4, '{"es_storm_skysplitter", "es_storm_overcharge"}', '{"x": 0, "y": 3200}', '{"pull": "All enemies within 10m pulled to 2m", "damage": "6d8 slashing/wind"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2bc35c30-b270-46b7-8acb-730a2cbb68ff', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_storm_eye_of_hurricane', 'Kasırganın Gözü', 'Eye of the Hurricane', 'ULTİMAT: Saf fırtına enerjisine dönüş. Savaş alanında düşmanlar arasında kusursuzca ışınlanarak, onlar tepki veremeden her birine kıyamet gücüyle vur.', 'ULTIMATE: Become pure storm energy. Teleport seamlessly between enemies across the battlefield, striking each with apocalyptic force before they can react.', 'Storm Sword', 90, 1300, 5, '{"es_storm_vacuum_blade"}', '{"x": 0, "y": 3450}', '{"targets": "Up to 8 within 30m", "damage": "10d10 lightning/thunder per target", "special": "Untargetable during execution"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cc4fa12b-00bb-46a0-9867-f414f4922226', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_steam_rend', 'Buhar Yarığı', 'Steam Rend', 'Ateş ve ayazı birleştirerek haşlayıcı bir buhar dalgası sal. Düşmanlara hasar verir ve kalın kör edici bir sis bırakır.', 'Combine fire and frost to unleash a scalding wave of steam. Damages enemies and leaves a thick blinding fog.', 'Hybrid Elements', 30, 280, 2, '{"es_flame_sweep", "es_frost_glacial_sweep"}', '{"x": -173, "y": 99}', '{"damage": "2d6 fire + 2d6 cold", "area": "4m cone", "status": "Blindness (Fog Cloud)"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('871f1bec-8158-4a88-b042-eb009c82b029', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_plasma_arc', 'Plazma Arkı', 'Plasma Arc', 'Yoğun ateşi uçucu yıldırımla birleştirerek yakan ve elektrik çarpan süper ısıtılmış bir plazma hattı fırlat.', 'Merge intense flame with volatile lightning to shoot a line of superheated plasma that ignites and electrocutes.', 'Hybrid Elements', 50, 450, 3, '{"es_flame_burning_thrust", "es_storm_lightning_lunge"}', '{"x": -389, "y": 224}', '{"damage": "4d6 fire + 4d6 lightning", "area": "10m line", "status": "Ignites target, jumps to 1 nearby"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f2ff6465-ffa9-4b4a-8edc-472507ba1016', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_hailstorm_assault', 'Dolu Fırtınası Saldırısı', 'Hailstorm Assault', 'Buzlu bir fırtınaya binerek savaşa gir. İleri atıl ve yere çarparak genişleyen yıkıcı bir dolu ve rüzgar halkası yarat.', 'Ride an icy gale into battle. Leap forward and slam the ground, creating an expanding ring of devastating hail and wind.', 'Hybrid Elements', 55, 475, 3, '{"es_frost_hoarfrost_thrust", "es_storm_thunderclap"}', '{"x": -606, "y": 349}', '{"leap": "Up to 8m", "damage": "4d8 cold/bludgeoning", "push": "3m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a3d0c6b-b62b-450d-b8c5-3123989cef14', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_thermal_shock', 'Termal Şok', 'Thermal Shock', 'Hedefi yakıcı ateşle vur ve anında mutlak soğukla devam et. Ani sıcaklık değişimi zırhlarını paramparça eder.', 'Hit a target with searing fire followed instantly by absolute cold. The rapid temperature change shatters their armor.', 'Hybrid Elements', 70, 800, 4, '{"es_flame_cauterize", "es_frost_shattering_strike"}', '{"x": -822, "y": 474}', '{"damage": "4d8 fire + 4d8 cold", "debuff": "-3 AC on failed CON save"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f5f51f65-4c65-4c40-8e58-5672a886c2c0', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_thunderfire', 'Yıldırım-Alev Püskürmesi', 'Thunderfire Eruption', 'Kılıcını yere çarparak düşmanları havaya uçuran çift elementli bir patlamayı tetikle.', 'Slam your blade down to trigger a dual-elemental explosion that blasts enemies high into the air.', 'Hybrid Elements', 72, 820, 4, '{"es_flame_blazing_cyclone", "es_storm_sonic_boom"}', '{"x": -1039, "y": 599}', '{"damage": "6d8 fire + 4d8 thunder", "area": "8m radius", "status": "Knocked into air (take 2d6 fall damage)"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('766b3d48-1429-41f5-82f2-0ff1f94932be', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_blizzard_conductor', 'Tipi İletkeni', 'Blizzard Conductor', 'Kılıcının içinden vahşi bir kış fırtınası yönlendir. Saldırıların buzun yavaşlatıcı soğuğunu ve yıldırımın sersemletici gücünü taşır.', 'Channel a ferocious winter storm through your blade. Your attacks carry the slowing chill of ice and the stunning force of lightning.', 'Hybrid Elements', 75, 860, 4, '{"es_frost_permafrost", "es_storm_tempest_aura"}', '{"x": -1255, "y": 724}', '{"bonus_damage": "+2d8 cold +2d8 lightning", "status": "Slowed by 5m, lose reactions"}', '🌨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41fcc3d9-cb45-49dc-bb4a-f9ce24a31f64', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_tri_stance', 'Üç Element Duruşu', 'Tri-Elemental Stance', 'Doğanın öfkeleriyle kusursuz bir uyum yakala. Tüm elementlere direnç kazanırsın ve sonraki birkaç vuruşun birleşik element yıkımıyla patlar.', 'Achieve perfect harmony with nature''s furies. You gain resistance to all elements, and your next few strikes erupt with combined elemental destruction.', 'Hybrid Elements', 80, 950, 4, '{"es_flame_sunblade", "es_frost_absolute_zero", "es_storm_skysplitter"}', '{"x": -1472, "y": 849}', '{"resistance": "Fire, Cold, Lightning", "bonus_damage": "+2d6 fire +2d6 cold +2d6 lightning on next 3 attacks"}', '☯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7e9c6977-59f5-42dc-b1fd-d1eea0eb289c', '1396c72f-f712-4586-b3c1-0c6951b05d8f', 'es_cross_cataclysm', 'Kıyamet Dünyakıran', 'Cataclysmic World-Breaker', 'BÜYÜK ULTİMAT: Mutlak sıcaklık ve kinetik enerjiden dövülmüş bir kılıçla gerçekliğin dokusuna vur. Her şeyi harap eden yıkıcı bir yarık açar.', 'GRAND ULTIMATE: Strike the fabric of reality with a blade forged from absolute temperature and kinetic energy. Tears a destructive rift that devastates everything.', 'Hybrid Elements', 100, 1500, 5, '{"es_flame_supernova", "es_frost_epoch_of_ice", "es_storm_eye_of_hurricane"}', '{"x": -1688, "y": 974}', '{"damage": "10d12 fire + 10d12 cold + 10d12 lightning", "area": "30m line, 5m wide", "special": "Tears a rift; permanently reduces stats of survivors"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('380619bd-60dd-4c97-82ad-5bf45d1d82d2', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_ignite_arrow', 'Tutuşturucu Ok', 'Ignite Arrow', 'Ateşle güçlendirilmiş temel saldırı, 1d8 ateş hasarı verir ve hedefi tutuşturur.', 'A basic attack infused with fire, dealing 1d8 fire damage and igniting the target.', 'Thermal_Archery', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8", "burn_chance": "25%", "range": "20m"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8af8b82e-0213-4d6e-aecc-45f5dac634f4', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_frost_shot', 'Ayaz Atışı', 'Frost Shot', 'Hedefin hareket hızını %20 yavaşlatan som buzdan bir ok.', 'An arrow of solid ice that slows the target''s movement by 20%.', 'Thermal_Archery', 3, 60, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "1d8", "slow": "20%", "duration": "2 rounds", "range": "20m"}', '❄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3b377872-2467-4bbb-a616-5a5bb4e044e0', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_thermal_shift', 'Termal Geçiş', 'Thermal Shift', 'Ateş ve buz elementleri arasında hızla geçiş yaparak bir sonraki atışa %10 geçici hasar artışı sağlar.', 'Swiftly swap between fire and ice elements, granting a temporary 10% damage boost to the next shot.', 'Thermal_Archery', 10, 100, 1, '{}', '{"x": 606, "y": -349}', '{"damage_bonus": "+10%", "duration": "1 round"}', '🌗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26764ae9-720d-4963-8528-7f327d826b65', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_blazing_volley', 'Alevli Yaylım', 'Blazing Volley', 'Geniş bir kavisle 3 alevli ok ateşleyerek birden fazla düşmana 2d6 ateş hasarı verir.', 'Fires 3 flaming arrows in a wide arc, hitting multiple enemies for 2d6 fire damage.', 'Thermal_Archery', 22, 180, 2, '{"ea_ignite_arrow"}', '{"x": 822, "y": -474}', '{"damage": "2d6 per arrow", "arrows": "3", "range": "30m"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90b6eb98-d112-4d5a-a9b6-80748208699a', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_glacier_piercer', 'Buzul Delici', 'Glacier Piercer', '15m düz bir çizgideki düşmanları delip geçen yüksek basınçlı bir buz oku.', 'A highly pressurized ice arrow that pieces through enemies in a 15m line.', 'Thermal_Archery', 25, 200, 2, '{"ea_frost_shot"}', '{"x": 1039, "y": -599}', '{"damage": "3d6", "area": "15m line", "pierce": "true"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ffc00138-85c3-450e-947e-fe1b67e6c31e', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_scorch_trap', 'Kavurucu Tuzak', 'Scorch Trap', 'Yere atılan bir ok, bir düşman 3m yakınına geldiğinde alevler içinde patlar.', 'Fires an arrow into the ground that erupts into flames when an enemy steps within 3m.', 'Thermal_Archery', 30, 220, 2, '{"ea_ignite_arrow"}', '{"x": 1255, "y": -724}', '{"damage": "3d8", "trigger_radius": "3m", "duration": "10 minutes"}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bed0d603-728d-428e-99c8-0164314a893c', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_chill_wind', 'Dondurucu Rüzgar', 'Chill Wind', 'Bir okla dondurucu bir rüzgar fırlatarak düşman saldırı hızını %15 azaltır.', 'Releases a gust of freezing wind with an arrow, reducing enemy attack speed by 15%.', 'Thermal_Archery', 35, 250, 2, '{"ea_frost_shot"}', '{"x": 1472, "y": -849}', '{"debuff": "-15% attack speed", "area": "10m cone", "duration": "3 rounds"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45c5cc08-7819-4be1-95d7-7520ed848d04', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_meteor_arrow', 'Meteor Oku', 'Meteor Arrow', 'Ok kılığında alevli bir meteor çağırarak 5m yarıçapta 5d8 ateş hasarı verir.', 'Summons a flaming meteor strike disguised as an arrow, dealing 5d8 fire damage in a 5m radius.', 'Thermal_Archery', 45, 400, 3, '{"ea_blazing_volley"}', '{"x": 1688, "y": -974}', '{"damage": "5d8", "radius": "5m", "range": "40m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3325856a-3ca2-428c-83c5-6832982017c7', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_blizzard_barrage', 'Tipi Yağmuru', 'Blizzard Barrage', '10m''lik bir alana buz parçacıkları yağdırarak düşmanları sürekli dondurur ve hasar verir.', 'Rains down ice shards over a 10m area, continuously freezing and damaging enemies.', 'Thermal_Archery', 48, 420, 3, '{"ea_glacier_piercer"}', '{"x": 1905, "y": -1099}', '{"damage": "4d6 per round", "radius": "10m", "duration": "3 rounds"}', '🌨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f63db06-aec7-4051-a9b3-36d8828eb4bc', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_steam_cloud', 'Buhar Bulutu', 'Steam Cloud', 'Ateş ve buzu birleştirerek kör edici bir buhar bulutu yaratır, görüşü engeller ve 2d6 haşlanma hasarı verir.', 'Combines fire and ice to create a blinding steam cloud, obscuring vision and dealing 2d6 scalding damage.', 'Thermal_Archery', 55, 450, 3, '{"ea_scorch_trap", "ea_chill_wind"}', '{"x": 2121, "y": -1224}', '{"damage": "2d6", "blind_chance": "50%", "radius": "8m"}', '♨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4d8fe3b-c568-405c-afb1-c75d7f179fc3', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_supernova_shot', 'Süpernova Atışı', 'Supernova Shot', 'Ölen bir yıldızın gücüyle patlayan yıkıcı bir ateş oku, 8d10 hasar verir.', 'A devastating fire arrow that explodes with the force of a dying star, dealing 8d10 damage.', 'Thermal_Archery', 65, 700, 4, '{"ea_meteor_arrow"}', '{"x": 2338, "y": -1349}', '{"damage": "8d10", "radius": "12m", "range": "60m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b7688906-ea18-4969-8e95-eb21464a22be', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_absolute_zero_arrow', 'Mutlak Sıfır Oku', 'Absolute Zero Arrow', 'Tek bir hedefi erimeyen buzun içinde 2 tur boyunca tamamen dondurur.', 'Freezes a single target completely in unmelting ice for 2 rounds.', 'Thermal_Archery', 68, 720, 4, '{"ea_blizzard_barrage"}', '{"x": 2554, "y": -1474}', '{"damage": "6d10", "stun": "2 rounds", "range": "50m"}', '🥶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fbab4323-aa3d-4804-90fa-5a55f8dc975d', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_thermal_shock', 'Termal Şok', 'Thermal Shock', 'Hızla aşırı ısı ve ardından soğuk uygulayarak düşman zırhını %30 parçalar.', 'Rapidly applies extreme heat then cold, shattering enemy armor by 30%.', 'Thermal_Archery', 72, 750, 4, '{"ea_steam_cloud"}', '{"x": 2771, "y": -1599}', '{"damage": "5d8", "armor_reduction": "30%", "duration": "3 rounds"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4383af9f-e2b5-4f6b-9603-1c4e5bf4a100', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_phoenix_flight', 'Anka Uçuşu', 'Phoenix Flight', 'Ateş püskürterek okçuyu 15m geriye iter, saldırılardan kaçınır ve arkasında alevden bir iz bırakır.', 'Propels the archer backward 15m with a burst of fire, evading attacks and leaving a trail of flames.', 'Thermal_Archery', 75, 800, 4, '{"ea_thermal_shift"}', '{"x": 2987, "y": -1724}', '{"dash": "15m backward", "trail_damage": "3d6/round", "duration": "2 rounds"}', '🪽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('948362be-2e2e-426f-81db-6301e7a6d692', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_ultimate_thermal_eclipse', 'Termal Tutulma', 'Thermal Eclipse', 'Ateş ve buz fırtınasının aynı anda koptuğu devasa bir alan yaratarak 4 tur boyunca 12d10 hasar verir.', 'Creates a massive zone where fire and ice storm simultaneously, dealing 12d10 damage over 4 rounds.', 'Thermal_Archery', 90, 1200, 5, '{"ea_supernova_shot", "ea_absolute_zero_arrow"}', '{"x": 3204, "y": -1849}', '{"damage": "12d10 total", "radius": "25m", "duration": "4 rounds"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4666c9c8-2284-4b84-80c5-88cf50f92a50', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_spark_arrow', 'Kıvılcım Oku', 'Spark Arrow', 'Hızlı hareket eden ve fazladan bir hedefe seken yıldırım oku.', 'A fast-moving lightning arrow that bounces to one additional target.', 'Geostorm_Archery', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8", "bounce": "1 target", "range": "25m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('544cd93e-0b7a-41b5-9177-139d61d3c5d1', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_stone_tip', 'Taş Uç', 'Stone Tip', 'Hedefi 2m geriye iten ağır, toprakla güçlendirilmiş bir ok.', 'A heavy, earth-infused arrow that knocks the target back 2m.', 'Geostorm_Archery', 4, 65, 1, '{}', '{"x": 289, "y": 344}', '{"damage": "1d10", "knockback": "2m", "range": "15m"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa138146-f928-4c02-9525-94dd1cf87f31', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_static_field', 'Statik Alan', 'Static Field', 'İçindeki herkesi hafifçe çarpan 5m''lik bir statik alan oluşturan bir ok fırlatır.', 'Fires an arrow that deploys a 5m static field, slightly shocking anyone inside.', 'Geostorm_Archery', 12, 110, 1, '{}', '{"x": 449, "y": 536}', '{"damage": "1d4/round", "radius": "5m", "duration": "3 rounds"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d6ef5e2-739d-4976-b51f-e29727768307', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_chain_lightning_shot', 'Zincirleme Yıldırım Atışı', 'Chain Lightning Shot', 'Birbirine 8m mesafede olan 4 düşmana kadar zincirleme seken güçlü bir yıldırım.', 'A powerful bolt that chains up to 4 enemies within 8m of each other.', 'Geostorm_Archery', 23, 190, 2, '{"ea_spark_arrow"}', '{"x": 610, "y": 727}', '{"damage": "3d6", "targets": "4", "bounce_range": "8m"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dbb8270e-abf2-4ed1-9ba7-9fe033d5a35a', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_tremor_shaft', 'Sarsıntı Oku', 'Tremor Shaft', 'Yere çarparak bölgesel bir deprem yaratır ve 6m yarıçaptaki düşmanları yere serer.', 'Strikes the ground to create a localized earthquake, knocking enemies prone in a 6m radius.', 'Geostorm_Archery', 26, 210, 2, '{"ea_stone_tip"}', '{"x": 771, "y": 919}', '{"damage": "2d8", "prone_chance": "60%", "radius": "6m"}', '🫨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3307f8aa-c67d-40ab-92c7-4405731739a5', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_magnetized_target', 'Manyetize Hedef', 'Magnetized Target', 'Bir düşmanı yıldırımla işaretler ve sonraki okların ona güdümlenmesini sağlar.', 'Marks an enemy with lightning, causing subsequent arrows to home in on them.', 'Geostorm_Archery', 31, 230, 2, '{"ea_static_field"}', '{"x": 932, "y": 1110}', '{"tracking": "100% accuracy", "duration": "3 rounds"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b6d9041-95fc-4c41-83c9-20233ea5f1d0', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_boulder_shot', 'Kaya Atışı', 'Boulder Shot', 'Oku uçuş sırasında devasa bir kayaya dönüştürerek zırhı ezer.', 'Transforms the arrow mid-flight into a massive boulder, crushing armor.', 'Geostorm_Archery', 36, 260, 2, '{"ea_tremor_shaft"}', '{"x": 1092, "y": 1302}', '{"damage": "4d6", "armor_break": "15%", "range": "20m"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3bd9437-fe75-4308-8513-7981846c9c5c', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_thunderbolt_snipe', 'Yıldırım Suikastı', 'Thunderbolt Snipe', 'Hedefin fiziksel direncinin %50''sini yok sayan yüksek hızlı bir yıldırım atışı.', 'A high-velocity lightning shot that ignores 50% of the target''s physical resistance.', 'Geostorm_Archery', 46, 410, 3, '{"ea_chain_lightning_shot"}', '{"x": 1253, "y": 1493}', '{"damage": "5d8", "armor_penetration": "50%", "range": "50m"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('454dbe84-7790-42c2-8093-050a71dbb1df', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_petrifying_arrow', 'Taştan Ok', 'Petrifying Arrow', 'Hedefi ağır taşla kaplayarak hareket hızını 1 turluğuna sıfıra indirir.', 'Coats the target in heavy stone, reducing their movement to zero for 1 round.', 'Geostorm_Archery', 49, 430, 3, '{"ea_boulder_shot"}', '{"x": 1414, "y": 1685}', '{"damage": "4d8", "root": "1 round"}', '🗽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d2a171f9-57a5-45d7-bc71-4bfd4b0f714b', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_dust_storm_arrow', 'Kum Fırtınası Oku', 'Dust Storm Arrow', 'Girdap gibi dönen elektrikli bir kum fırtınası yaratarak 3d8 hasar verir ve düşmanları kör eder.', 'Creates a swirling storm of electrified sand, dealing 3d8 damage and blinding enemies.', 'Geostorm_Archery', 56, 460, 3, '{"ea_tremor_shaft", "ea_static_field"}', '{"x": 1574, "y": 1876}', '{"damage": "3d8", "blind": "1 round", "radius": "10m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0170a1d5-24a3-44a1-9888-9659b679afcc', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_plasma_piercer', 'Plazma Delici', 'Plasma Piercer', 'Bariyerleri buharlaştıran ve 7d8 hasar veren aşırı sıcak bir yıldırım oku.', 'An ultra-hot lightning arrow that vaporizes barriers and deals 7d8 damage.', 'Geostorm_Archery', 66, 710, 4, '{"ea_thunderbolt_snipe"}', '{"x": 1735, "y": 2068}', '{"damage": "7d8", "destroys_shields": "true", "range": "40m"}', '🚀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('009f3afa-bdd1-4cec-9816-e192a6aca61b', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_tectonic_rupture', 'Tektonik Çatlak', 'Tectonic Rupture', 'Yerin derinliklerine bir ok fırlatarak toprağı yarar ve 20m''lik bir uçurum yaratır.', 'Fires an arrow deep underground, splitting the earth to create a 20m chasm.', 'Geostorm_Archery', 69, 730, 4, '{"ea_petrifying_arrow"}', '{"x": 1896, "y": 2259}', '{"damage": "6d10", "area": "20m line", "difficult_terrain": "true"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c533719-94fc-4f0d-b909-bf5d2b3143b1', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_fulgurite_spike', 'Fülgerit Dikeni', 'Fulgurite Spike', 'Kum/toprağa yıldırımla vurarak düşmanları deşen ve 8d8 hasar veren camdan bir diken oluşturur.', 'Strikes sand/earth with lightning to form a glass spike that impales enemies for 8d8 damage.', 'Geostorm_Archery', 73, 760, 4, '{"ea_dust_storm_arrow"}', '{"x": 2056, "y": 2451}', '{"damage": "8d8", "bleed": "2d4", "range": "30m"}', '🏜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('df20d3f8-3f7b-4464-90ce-6a3fb231ae77', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_lightning_tether', 'Yıldırım Bağı', 'Lightning Tether', 'Okçuyu oka bağlayarak okun düştüğü yere anında ışınlanmasını sağlar.', 'Tethers the archer to an arrow, allowing them to instantly teleport to where it lands.', 'Geostorm_Archery', 76, 810, 4, '{"ea_magnetized_target"}', '{"x": 2217, "y": 2642}', '{"teleport": "arrow destination", "max_range": "40m"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3ed689c6-9698-4eaa-bba1-1d0742f2445d', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_ultimate_geostorm_cataclysm', 'Jeofırtına Afeti', 'Geostorm Cataclysm', '30m''lik bir alanı yok eden kayalar ve yıldırımlar yağdıran devasa bir gök gürültülü fırtına serbest bırakır.', 'Unleashes a massive thunderstorm that rains boulders and lightning bolts, obliterating a 30m area.', 'Geostorm_Archery', 90, 1200, 5, '{"ea_plasma_piercer", "ea_tectonic_rupture"}', '{"x": 2378, "y": 2834}', '{"damage": "14d10", "stun": "1 round", "radius": "30m"}', '⛈️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4758ad22-a8a6-47f3-8bab-676d62555425', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_primal_attunement', 'İlkel Uyum', 'Primal Attunement', 'Pasif olarak mana yenilenmesini artırır ve okçuyu saf doğal enerjiye uyumlar.', 'Passively increases mana regeneration and attunes the archer to raw natural energy.', 'Primal_Resonance', 5, 70, 1, '{}', '{"x": -128, "y": 153}', '{"mana_regen": "+20%", "duration": "Passive"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d9fdbdb9-613f-4bc9-8606-e4abb27def98', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_elemental_tracer', 'Element İzleyici', 'Elemental Tracer', 'Hedefin 5 dakika boyunca görülmesini sağlayan soluk, büyülü bir ok fırlatır.', 'Fires a faint magical arrow that grants vision of the target for 5 minutes.', 'Primal_Resonance', 15, 120, 1, '{}', '{"x": -289, "y": 344}', '{"vision": "True sight", "duration": "5 minutes"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8e1bb74-7dd7-4a78-84da-1c7a5c6ef0e3', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_mana_infused_bowstring', 'Mana Yüklü Kiriş', 'Mana-Infused Bowstring', 'Yay kirişini saf manayla güçlendirerek saldırı menzilini 10m artırır.', 'Empowers the bowstring with pure mana, increasing attack range by 10m.', 'Primal_Resonance', 24, 195, 2, '{"ea_primal_attunement"}', '{"x": -449, "y": 536}', '{"range_bonus": "+10m", "duration": "10 rounds"}', '🎻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('512d8260-778d-47fa-add4-66022b573372', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_seeking_element', 'Arayan Element', 'Seeking Element', 'Oklar havadayken kavis çizerek hedeflerini bulur ve kısmi siperi yok sayar.', 'Arrows curve mid-air to find their targets, ignoring partial cover.', 'Primal_Resonance', 28, 215, 2, '{"ea_elemental_tracer"}', '{"x": -610, "y": 727}', '{"ignore_cover": "50%", "accuracy": "+20%"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('339363f0-c147-4585-9565-1f0b07304037', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_primal_burst', 'İlkel Patlama', 'Primal Burst', 'Saf, türsüz büyüden oluşan bir ok, 3d8 güç hasarıyla patlar.', 'An arrow of raw untyped magic that explodes for 3d8 force damage.', 'Primal_Resonance', 34, 240, 2, '{"ea_mana_infused_bowstring"}', '{"x": -771, "y": 919}', '{"damage": "3d8 force", "radius": "4m"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d781f12-b039-4075-a57c-b97dbfc3ec11', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_elemental_vortex', 'Element Girdabı', 'Elemental Vortex', 'Düşmanları 5m''lik bir merkeze çeken saf büyüden bir vakum yaratır.', 'Creates a vacuum of raw magic that pulls enemies into a 5m center.', 'Primal_Resonance', 44, 390, 3, '{"ea_primal_burst"}', '{"x": -932, "y": 1110}', '{"pull_radius": "10m to 5m", "damage": "4d6"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6a040823-ae86-43ab-a2b1-e7fc34590db4', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_adaptive_quiver', 'Adaptif Sadak', 'Adaptive Quiver', 'Okları otomatik olarak düşmanın en zayıf olduğu elementle kaplar.', 'Automatically coats arrows in the element the enemy is weakest against.', 'Primal_Resonance', 50, 440, 3, '{"ea_seeking_element"}', '{"x": -1092, "y": 1302}', '{"damage_conversion": "Enemy Weakness", "duration": "3 rounds"}', '🎒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95d58747-fa0c-49e1-b262-adbe44eddce3', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_primal_echo', 'İlkel Yankı', 'Primal Echo', 'Fırlatılan her ok, %50 hasar veren hayalet bir kopya yaratır.', 'Every arrow fired creates a phantom copy that deals 50% damage.', 'Primal_Resonance', 58, 480, 3, '{"ea_elemental_vortex"}', '{"x": -1253, "y": 1493}', '{"echo_damage": "50%", "duration": "2 rounds"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2be1c6f0-28a1-44c8-ba3f-118de77b986e', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_chaos_arrow', 'Kaos Oku', 'Chaos Arrow', 'Rastgele bir elementte 6d12 hasar veren öngörülemez bir ok fırlatır.', 'Fires an unpredictable arrow that deals 6d12 damage of a random element.', 'Primal_Resonance', 64, 690, 4, '{"ea_primal_echo"}', '{"x": -1414, "y": 1685}', '{"damage": "6d12", "element": "Random"}', '🎲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('76bb4151-e995-48ff-9f8f-c5d04896693b', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_elemental_barrage', 'Element Yaylımı', 'Elemental Barrage', 'Her biri farklı bir elementle güçlendirilmiş 10 okluk hızlı bir yaylım ateşi başlatır.', 'Unleashes a rapid stream of 10 arrows, each infused with a different element.', 'Primal_Resonance', 70, 740, 4, '{"ea_adaptive_quiver"}', '{"x": -1574, "y": 1876}', '{"damage": "1d10 per arrow", "hits": "10"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70e5771b-901f-4511-ac31-bfc63917a14a', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_primal_avatar', 'İlkel Avatar', 'Primal Avatar', 'Saf element enerjisinden oluşan bir varlığa dönüşerek tüm element hasarlarına karşı bağışıklık kazanın.', 'Transform into a being of pure elemental energy, gaining immunity to all elemental damage.', 'Primal_Resonance', 78, 850, 4, '{"ea_chaos_arrow"}', '{"x": -1735, "y": 2068}', '{"immunity": "Fire/Ice/Lightning/Earth", "duration": "2 rounds"}', '🦸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e7463ad8-275f-42bf-9156-9ba7adca1d99', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_ultimate_primal_convergence', 'İlkel Yakınsama', 'Primal Convergence', 'Etraftaki tüm element enerjisini bir tekillik okuna çökertir ve 15d10 saf hasar verir.', 'Collapses all surrounding elemental energy into a singularity arrow, dealing 15d10 pure damage.', 'Primal_Resonance', 90, 1200, 5, '{"ea_primal_avatar", "ea_elemental_barrage"}', '{"x": -1896, "y": 2259}', '{"damage": "15d10 force", "bypass_immunity": "true", "range": "80m"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8544ac77-f745-4a2c-895e-15620e4d44bc', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_magma_shot', 'Magma Atışı', 'Magma Shot', 'Toprağı eritip bir magma kütlesine dönüştürerek 4d8 ateş ve 4d8 toprak hasarı verir, erimiş bir havuz bırakır.', 'Melts earth into a glob of magma, dealing 4d8 fire and 4d8 earth damage, leaving a molten pool.', 'Cross-Branch', 52, 450, 3, '{"ea_blazing_volley", "ea_tremor_shaft"}', '{"x": -173, "y": -100}', '{"damage": "8d8 total", "hazard_duration": "3 rounds", "radius": "5m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e11917b9-29ef-4267-b787-63c2a20434a0', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_thunderstorm_volley', 'Fırtına Yaylımı', 'Thunderstorm Volley', 'Düşmanları sersemleten ve 6d6 karışık hasar veren elektrikli dolu yağdırır.', 'Rains down electrified hail that stuns enemies and deals 6d6 mixed damage.', 'Cross-Branch', 54, 460, 3, '{"ea_chill_wind", "ea_chain_lightning_shot"}', '{"x": -389, "y": -225}', '{"damage": "6d6", "stun_chance": "40%", "radius": "10m"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4bcf94d-9914-4a4c-812c-0e6e602a8387', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_plasma_burn', 'Plazma Yanığı', 'Plasma Burn', 'O kadar sıcak bir ok fırlatır ki plazmaya dönüşür, 8d8 hasar verir ve silahları eritir.', 'Fires an arrow so hot it turns into plasma, dealing 8d8 damage and melting weapons.', 'Cross-Branch', 62, 650, 4, '{"ea_meteor_arrow", "ea_thunderbolt_snipe"}', '{"x": -606, "y": -350}', '{"damage": "8d8", "disarm_chance": "50%"}', '🔆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ba94dacd-2f0b-4a22-a36d-4d03a24a4eae', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_glacier_quake', 'Buzul Depremi', 'Glacier Quake', 'Yerden geçerek sivri buz dikenlerine dönüşen bir şok dalgası gönderir.', 'Sends a shockwave through the ground that erupts into jagged ice spikes.', 'Cross-Branch', 67, 715, 4, '{"ea_blizzard_barrage", "ea_petrifying_arrow"}', '{"x": -822, "y": -475}', '{"damage": "7d8", "slow": "50%", "radius": "12m"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90d3fa83-095d-4fd3-b84d-6b32211b77e3', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_primal_meteor', 'İlkel Meteor', 'Primal Meteor', 'Saf element boşluğundan bir meteor çekerek 15m yarıçapta 10d10 ateş/güç hasarı verir.', 'Pulls a meteor from raw elemental space, dealing 10d10 fire/force damage in a 15m radius.', 'Cross-Branch', 74, 780, 4, '{"ea_supernova_shot", "ea_chaos_arrow"}', '{"x": -1039, "y": -600}', '{"damage": "10d10", "radius": "15m"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d11f1a8-7e55-4aaa-8146-a6d8041e4347', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_storm_seeker', 'Fırtına Arayıcı', 'Storm Seeker', 'En tehlikeli düşmanı aktif olarak avlayan bilinçli bir yıldırım oku.', 'A sentient lightning bolt arrow that actively hunts down the most dangerous enemy.', 'Cross-Branch', 77, 820, 4, '{"ea_plasma_piercer", "ea_seeking_element"}', '{"x": -1255, "y": -725}', '{"damage": "9d10", "auto_target": "Highest Threat", "range": "100m"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b84c87ff-6186-4136-878b-adb5bbd10ad9', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_elemental_ascension', 'Element Yükselişi', 'Elemental Ascension', '3 tur boyunca, atılan her ok otomatik olarak ikincil bir ateş, buz, yıldırım ve toprak patlamasını tetikler.', 'For 3 rounds, every arrow fired automatically triggers a secondary fire, ice, lightning, and earth explosion.', 'Cross-Branch', 85, 1100, 5, '{"ea_primal_avatar", "ea_thermal_shock", "ea_fulgurite_spike"}', '{"x": -1472, "y": -850}', '{"bonus_damage": "+4d8 per arrow", "duration": "3 rounds"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c15acb09-fa77-4468-9016-30f5bdcc7798', 'c7d4982f-8ee3-4c4d-81cf-acac95b9ee9f', 'ea_grand_ultimate_elemental_omega_shot', 'Element Omega Atışı', 'Elemental Omega Shot', 'Element okçuluğunun mutlak zirvesi. Dünyanın çekirdek elementlerini içeren bir ok fırlatarak hedefi varoluştan siler.', 'The absolute pinnacle of elemental archery. Fires an arrow containing the world''s core elements, erasing the target from existence.', 'Cross-Branch', 100, 1500, 5, '{"ea_ultimate_thermal_eclipse", "ea_ultimate_geostorm_cataclysm", "ea_ultimate_primal_convergence"}', '{"x": -1688, "y": -975}', '{"damage": "25d12", "execute_threshold": "20%", "range": "150m"}', '🌈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b4e4551-c06d-45c6-b862-fb537ea92aec', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_firebolt', 'Ateş Oku', 'Firebolt', '30m uzaklığa kadar tek bir hedefe küçük bir ateş oku fırlatarak 1d10 ateş hasarı verir.', 'Hurls a small bolt of fire towards a single target up to 30m away, dealing 1d10 fire damage.', 'Fire', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d10", "range": "30m"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c699a154-92ec-465f-b662-40d3a6156f4b', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_ignite', 'Tutuştur', 'Ignite', '20m içindeki bir hedefi tutuşturarak, 3 tur boyunca toplam 2d6 ateş hasarı almasını sağlar.', 'Sets a target ablaze within 20m, causing them to burn for 2d6 fire damage over 3 turns.', 'Fire', 10, 100, 1, '{"em_firebolt"}', '{"x": 389, "y": -224}', '{"damage": "2d6", "duration": "3 turns", "range": "20m"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ab2ed79-76df-455c-b1c3-9a69833656d2', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_fireball', 'Ateş Topu', 'Fireball', '40m uzaklığa kadar gidebilen ve 6m yarıçapta patlayarak 6d6 ateş hasarı veren bir ateş topu fırlatır.', 'Shoots a sphere of flame that detonates in a 6m radius up to 40m away, dealing 6d6 fire damage.', 'Fire', 21, 200, 2, '{"em_ignite"}', '{"x": 606, "y": -349}', '{"damage": "6d6", "range": "40m", "radius": "6m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d59461b3-85be-42c2-a02f-8b8fde5aef61', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_minor_fire_elemental', 'Küçük Ateş Elementali', 'Minor Fire Elemental', 'Küçük bir Ateş Elementali çağırır. İstatistikleri büyücü seviyenizin %50''si ile ölçeklenir. 5 tur sürer.', 'Summons a Minor Fire Elemental. Its stats scale at 50% of your caster level. Lasts 5 turns.', 'Fire', 30, 250, 2, '{"em_fireball"}', '{"x": 822, "y": -474}', '{"duration": "5 turns", "scaling": "50% caster level"}', '🦎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('59b330d8-f95f-41f7-9c92-b7c2c3e677d9', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_wall_of_fire', 'Ateş Duvarı', 'Wall of Fire', '15m uzunluğunda alevden bir duvar yaratır. İçinden geçen her yaratık 5d8 ateş hasarı alır.', 'Creates a 15m long wall of blazing fire. Any creature passing through takes 5d8 fire damage.', 'Fire', 41, 400, 3, '{"em_minor_fire_elemental"}', '{"x": 1039, "y": -599}', '{"damage": "5d8", "length": "15m"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('21192072-0d9a-400e-ab06-7d4da9100f55', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_combustion', 'Yanma', 'Combustion', '20m içindeki düşmanların üzerindeki yanma etkilerini anında patlatarak 8d6 ateş hasarı verir ve 1 tur sersemletir.', 'Instantly detonates burning effects on enemies within 20m, dealing 8d6 fire damage and stunning them for 1 turn.', 'Fire', 50, 450, 3, '{"em_wall_of_fire"}', '{"x": 1255, "y": -724}', '{"damage": "8d6", "range": "20m", "stun": "1 turn"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4eaa8274-382d-4945-9cd4-97a1b4c13633', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_meteor_strike', 'Meteor Çarpması', 'Meteor Strike', 'Gökyüzünden 10m yarıçaplı bir alana devasa bir meteor indirerek 12d6 ateş ve 4d6 ezme hasarı verir. 60m menzil.', 'Calls down a massive meteor from the sky hitting a 10m radius area, dealing 12d6 fire and 4d6 bludgeoning damage. 60m range.', 'Fire', 65, 700, 4, '{"em_combustion"}', '{"x": 1472, "y": -849}', '{"damage": "12d6 fire, 4d6 bludgeoning", "range": "60m", "radius": "10m"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('690d14e0-8b85-4b78-9278-ca437f9bc31f', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_major_fire_elemental', 'Büyük Ateş Elementali', 'Major Fire Elemental', 'İstatistikleri büyücü seviyenizin %100''üne eşit olan Büyük bir Ateş Elementali çağırır. 10 tur sürer.', 'Summons a Major Fire Elemental with stats equal to 100% of your caster level. Lasts for 10 turns.', 'Fire', 75, 850, 4, '{"em_meteor_strike"}', '{"x": 1688, "y": -974}', '{"duration": "10 turns", "scaling": "100% caster level"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16d3c9d9-9d10-4347-9938-935a7d58cd70', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_inferno', 'Cehennem Ateşi', 'Inferno', '15m yarıçaplı bir alanı cehennem ateşiyle kaplayarak 5 tur boyunca 20d6 ateş hasarı verir ve zırhı %30 eritir. 40m menzil.', 'Engulfs a 15m radius in hellfire, dealing 20d6 fire damage over 5 turns and melting armor by 30%. 40m range.', 'Fire', 85, 1200, 5, '{"em_major_fire_elemental"}', '{"x": 1905, "y": -1099}', '{"damage": "20d6", "duration": "5 turns", "range": "40m", "radius": "15m", "armor_reduction": "30%"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6bcc741f-cf65-4820-9f3f-6c44aff1a952', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_firelord_avatar', 'Ateş Lordu Avatarı', 'Firelord Avatar', 'Sizi 5 turluğuna Ateş Lordu Avatarına dönüştürür. Uçma, ateş bağışıklığı kazandırır ve büyüleriniz ekstra 10d6 ateş hasarı verir.', 'Transforms you into a Firelord Avatar for 5 turns. Grants flight, fire immunity, and your spells deal an extra 10d6 fire damage.', 'Fire', 95, 1500, 5, '{"em_inferno"}', '{"x": 2121, "y": -1224}', '{"duration": "5 turns", "bonus_damage": "10d6", "immunity": "fire"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90ffb09a-a0e9-4afa-90fd-ada14724324e', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_water_whip', 'Su Kırbacı', 'Water Whip', '15m uzaktaki bir hedefe su kırbacıyla vurarak 1d8 ezme hasarı verir ve hedefi 5m kendinize çeker.', 'Forms a whip of water to strike a target 15m away, dealing 1d8 bludgeoning damage and pulling them 5m closer.', 'Water', 1, 50, 1, '{}', '{"x": 173, "y": 99}', '{"damage": "1d8", "range": "15m", "pull": "5m"}', '🪢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bfa782e7-3c5c-4d98-9caf-a1233818e28d', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_frostbite', 'Soğuk Isırması', 'Frostbite', '20m içindeki bir hedefi dondurarak 1d6 soğuk hasarı verir ve hareket hızını 2 tur boyunca %50 yavaşlatır.', 'Chills a target within 20m, dealing 1d6 cold damage and slowing their movement speed by 50% for 2 turns.', 'Water', 10, 100, 1, '{"em_water_whip"}', '{"x": 389, "y": 224}', '{"damage": "1d6", "range": "20m", "slow": "50%", "duration": "2 turns"}', '❄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('372fb388-c1cd-4fba-8fc9-a11b2b32d1a8', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_healing_rain', 'Şifa Yağmuru', 'Healing Rain', '30m uzaklığa kadar 8m yarıçaplı bir alana şifa yağmuru indirerek müttefikleri 3d8 HP iyileştirir.', 'Calls down a gentle rain over an 8m radius area up to 30m away, healing allies for 3d8 HP.', 'Water', 21, 200, 2, '{"em_frostbite"}', '{"x": 606, "y": 349}', '{"healing": "3d8", "range": "30m", "radius": "8m"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('14dd2fef-f82e-4069-91db-ab7e9b2505e6', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_minor_water_elemental', 'Küçük Su Elementali', 'Minor Water Elemental', 'Küçük bir Su Elementali çağırır. İstatistikleri büyücü seviyenizin %50''si ile ölçeklenir. 5 tur sürer.', 'Summons a Minor Water Elemental. Its stats scale at 50% of your caster level. Lasts 5 turns.', 'Water', 30, 250, 2, '{"em_healing_rain"}', '{"x": 822, "y": 474}', '{"duration": "5 turns", "scaling": "50% caster level"}', '💧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bbb68b98-4b36-4540-aa9d-338644808fda', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_ice_lance', 'Buz Mızrağı', 'Ice Lance', '30m''ye kadar keskin bir buz mızrağı fırlatarak 5d10 soğuk hasarı verir ve hedefin zırhının %50''sini yok sayar.', 'Fires a sharp lance of ice up to 30m, dealing 5d10 cold damage and ignoring 50% of the target''s armor.', 'Water', 41, 400, 3, '{"em_minor_water_elemental"}', '{"x": 1039, "y": 599}', '{"damage": "5d10", "range": "30m", "armor_pierce": "50%"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bccff3b7-8a67-4472-a98a-3c118eaaf72e', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_tidal_wave', 'Gelgit Dalgası', 'Tidal Wave', '10x10m''lik bir alana su dalgası göndererek 6d8 ezme hasarı verir ve tüm hedefleri yere serer.', 'Unleashes a wave of water in a 10x10m area, dealing 6d8 bludgeoning damage and knocking all targets prone.', 'Water', 50, 450, 3, '{"em_ice_lance"}', '{"x": 1255, "y": 724}', '{"damage": "6d8", "area": "10x10m", "status": "prone"}', '🏄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce1b8097-93c7-4056-84a8-0901b4117630', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_blizzard', 'Kar Fırtınası', 'Blizzard', '15m yarıçaplı bir alanda şiddetli bir kar fırtınası yaratarak 8d8 soğuk hasarı verir ve hedefleri 1 tur dondurur.', 'Creates a raging blizzard in a 15m radius, dealing 8d8 cold damage and freezing targets solid for 1 turn.', 'Water', 65, 700, 4, '{"em_tidal_wave"}', '{"x": 1472, "y": 849}', '{"damage": "8d8", "radius": "15m", "freeze": "1 turn"}', '🌨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('25695e41-eca4-489b-920b-ed79e6022173', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_major_water_elemental', 'Büyük Su Elementali', 'Major Water Elemental', 'İstatistikleri büyücü seviyenizin %100''üne eşit olan Büyük bir Su Elementali çağırır. 10 tur sürer.', 'Summons a Major Water Elemental with stats equal to 100% of your caster level. Lasts for 10 turns.', 'Water', 75, 850, 4, '{"em_blizzard"}', '{"x": 1688, "y": 974}', '{"duration": "10 turns", "scaling": "100% caster level"}', '🐋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45a00667-7294-44fd-ad32-38b73b8ff967', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_tsunami', 'Tsunami', 'Tsunami', 'Düşmanları 30m geriye iten ve 20m genişliğinde bir hatta 15d8 ezme hasarı veren devasa bir tsunami çağırır.', 'Summons a massive tsunami that pushes enemies 30m back, dealing 15d8 bludgeoning damage across a 20m wide line.', 'Water', 85, 1200, 5, '{"em_major_water_elemental"}', '{"x": 1905, "y": 1099}', '{"damage": "15d8", "push": "30m", "width": "20m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb1c9d4b-2459-44da-8cff-79fa47172762', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_leviathan_avatar', 'Leviathan Avatarı', 'Leviathan Avatar', 'Sizi 5 turluğuna Leviathan Avatarına dönüştürür. Devasa yenilenme (50 HP/tur), suda nefes alma ve tüm saldırılarda dondurma etkisi kazandırır.', 'Transforms you into a Leviathan Avatar for 5 turns. Grants massive regeneration (50 HP/turn), water breathing, and applies freeze on all attacks.', 'Water', 95, 1500, 5, '{"em_tsunami"}', '{"x": 2121, "y": 1224}', '{"duration": "5 turns", "regen": "50 HP/turn", "effect": "freeze on attack"}', '🐙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c1572d8-506a-4781-ad4b-46551aecb865', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_magic_stone', 'Sihirli Taş', 'Magic Stone', '25m uzağa büyülü bir taş fırlatarak 1d10 ezme hasarı verir.', 'Hurls a magically imbued stone up to 25m away, dealing 1d10 bludgeoning damage.', 'Earth', 1, 50, 1, '{}', '{"x": 0, "y": 200}', '{"damage": "1d10", "range": "25m"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c79b2bb5-fd32-4e26-8efe-61736a8398ad', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_tremor', 'Sarsıntı', 'Tremor', 'Yere vurarak 10m yarıçapında bir sarsıntı yaratır. 2d6 ezme hasarı verir ve hedefleri %25 ihtimalle yere serer.', 'Strikes the ground, causing a 10m radius tremor that deals 2d6 bludgeoning damage with a 25% chance to knock targets prone.', 'Earth', 10, 100, 1, '{"em_magic_stone"}', '{"x": 0, "y": 450}', '{"damage": "2d6", "radius": "10m", "prone_chance": "25%"}', '🫨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af74bfbb-7f08-439e-98df-9f931f17124d', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_stone_armor', 'Taş Zırh', 'Stone Armor', 'Kendinizi veya bir müttefiki 5 turluğuna taş zırhla kaplayarak +5 AC ve 30 geçici HP kazandırır. 15m menzil.', 'Encases yourself or an ally in stone armor for 5 turns, granting +5 AC and 30 temporary HP. 15m range.', 'Earth', 21, 200, 2, '{"em_tremor"}', '{"x": 0, "y": 700}', '{"bonus_ac": "5", "temp_hp": "30", "duration": "5 turns", "range": "15m"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48dd8e46-d229-4940-a195-48103f64111b', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_minor_earth_elemental', 'Küçük Toprak Elementali', 'Minor Earth Elemental', 'Küçük bir Toprak Elementali çağırır. İstatistikleri büyücü seviyenizin %50''si ile ölçeklenir. 5 tur sürer.', 'Summons a Minor Earth Elemental. Its stats scale at 50% of your caster level. Lasts 5 turns.', 'Earth', 30, 250, 2, '{"em_stone_armor"}', '{"x": 0, "y": 950}', '{"duration": "5 turns", "scaling": "50% caster level"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1442ee58-184a-46a6-9b88-23b1803d696c', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_spike_growth', 'Dikenli Büyüme', 'Spike Growth', '10m yarıçaplı zemini 3 turluğuna acımasız dikenlere çevirir. Bir hedef hareket ettiği her 2m için 4d4 delme hasarı alır.', 'Turns the ground in a 10m radius into vicious spikes for 3 turns. Deals 4d4 piercing damage for every 2m a target moves.', 'Earth', 41, 400, 3, '{"em_minor_earth_elemental"}', '{"x": 0, "y": 1200}', '{"damage": "4d4 per 2m", "radius": "10m", "duration": "3 turns"}', '🌵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d2c32cf-1bf9-4255-b447-99ffd161fe33', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_boulder_toss', 'Kaya Fırlatma', 'Boulder Toss', '30m uzağa devasa bir kaya fırlatarak 8d6 ezme hasarı verir ve hedefi 1 tur sersemletir.', 'Hurls a massive boulder up to 30m away, dealing 8d6 bludgeoning damage and stunning the target for 1 turn.', 'Earth', 50, 450, 3, '{"em_spike_growth"}', '{"x": 0, "y": 1450}', '{"damage": "8d6", "range": "30m", "stun": "1 turn"}', '🎳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f2556e73-af54-43da-a2f5-37c7d9f65ab5', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_earthquake', 'Deprem', 'Earthquake', '20m yarıçaplı bir alanda yıkıcı bir deprem tetikler. 10d6 ezme hasarı verir, hedefleri yere serer ve yapıları yok eder.', 'Triggers a devastating earthquake in a 20m radius. Deals 10d6 bludgeoning damage, knocks targets prone, and destroys structures.', 'Earth', 65, 700, 4, '{"em_boulder_toss"}', '{"x": 0, "y": 1700}', '{"damage": "10d6", "radius": "20m", "status": "prone"}', '🏚️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cfd4a790-1ac4-4930-afe8-a0c412d5e270', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_major_earth_elemental', 'Büyük Toprak Elementali', 'Major Earth Elemental', 'İstatistikleri büyücü seviyenizin %100''üne eşit olan Büyük bir Toprak Elementali çağırır. 10 tur sürer.', 'Summons a Major Earth Elemental with stats equal to 100% of your caster level. Lasts for 10 turns.', 'Earth', 75, 850, 4, '{"em_earthquake"}', '{"x": 0, "y": 1950}', '{"duration": "10 turns", "scaling": "100% caster level"}', '🧌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a6b8cd2-c894-4ca7-a57b-4667c6292b08', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_petrify', 'Taşa Çevirme', 'Petrify', '15m içindeki bir hedefi katı taşa çevirmeye çalışır. Dayanıklılık zarında başarısız olurlarsa kalıcı olarak taşlaşırlar.', 'Attempts to turn a target within 15m into solid stone. If they fail a constitution save, they are permanently petrified.', 'Earth', 85, 1200, 5, '{"em_major_earth_elemental"}', '{"x": 0, "y": 2200}', '{"range": "15m", "status": "permanent petrification"}', '🗽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('51d57002-6331-4f70-8bc2-56f2e0750999', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_titan_avatar', 'Titan Avatarı', 'Titan Avatar', 'Sizi 5 turluğuna Titan Avatarına dönüştürür. +100 Maksimum HP, fiziksel kontrol etkilerine bağışıklık kazandırır ve yakın dövüş saldırıları 8d10 hasar verir.', 'Transforms you into a Titan Avatar for 5 turns. Grants +100 Max HP, immunity to physical control effects, and melee strikes deal 8d10 damage.', 'Earth', 95, 1500, 5, '{"em_petrify"}', '{"x": 0, "y": 2450}', '{"duration": "5 turns", "max_hp_bonus": "100", "melee_damage": "8d10"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2c732309-aa05-46c2-baa5-ba9929301e8c', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_gust', 'Rüzgar Esintisi', 'Gust', '15m içindeki bir hedefe güçlü bir rüzgar esintisi göndererek onları 10m uzağa iter ve büyü yapmalarını engeller.', 'Blasts a target within 15m with a strong gust of wind, pushing them 10m away and interrupting spellcasting.', 'Air', 1, 50, 1, '{}', '{"x": -173, "y": 99}', '{"range": "15m", "push": "10m", "interrupt": "true"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4bb81a2-783c-4447-a843-deb3dcc7e9df', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_static_shock', 'Statik Şok', 'Static Shock', '20m içindeki bir hedefi şoklayarak 2d8 yıldırım hasarı verir, hasar 5m içindeki 1 ek hedefe daha sıçrar.', 'Shocks a target within 20m for 2d8 lightning damage, which then jumps to 1 additional target within 5m.', 'Air', 10, 100, 1, '{"em_gust"}', '{"x": -389, "y": 224}', '{"damage": "2d8", "range": "20m", "jump_targets": "1"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5a25cf5-6762-4404-93fb-1ab2f1e3373f', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_levitate', 'Havaya Kaldırma', 'Levitate', 'Sana 5 tur boyunca havada 10m''ye kadar süzülme yeteneği verir. Zemin tehlikelerini yok sayar ve +%30 hareket hızı kazandırır.', 'Grants you the ability to float up to 10m in the air for 5 turns, ignoring ground hazards and gaining +30% movement speed.', 'Air', 21, 200, 2, '{"em_static_shock"}', '{"x": -606, "y": 349}', '{"duration": "5 turns", "height": "10m", "movement_speed": "+30%"}', '🎈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('54b2d884-65ac-4d33-8e19-879a6658f258', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_minor_air_elemental', 'Küçük Hava Elementali', 'Minor Air Elemental', 'Küçük bir Hava Elementali çağırır. İstatistikleri büyücü seviyenizin %50''si ile ölçeklenir. 5 tur sürer.', 'Summons a Minor Air Elemental. Its stats scale at 50% of your caster level. Lasts 5 turns.', 'Air', 30, 250, 2, '{"em_levitate"}', '{"x": -822, "y": 474}', '{"duration": "5 turns", "scaling": "50% caster level"}', '🧚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dff5a1fb-9cac-4f39-b7f5-912d87d4860f', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_lightning_bolt', 'Yıldırım Düşmesi', 'Lightning Bolt', '30m uzunluğunda bir hat boyunca güçlü bir elektrik enerjisi serbest bırakarak yoluna çıkan herkese 8d6 yıldırım hasarı verir.', 'Unleashes a powerful stroke of electrical energy in a 30m long line, dealing 8d6 lightning damage to all in its path.', 'Air', 41, 400, 3, '{"em_minor_air_elemental"}', '{"x": -1039, "y": 599}', '{"damage": "8d6", "line": "30m"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eeada7d2-41f7-490d-a86f-079a62db9785', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_wind_wall', 'Rüzgar Duvarı', 'Wind Wall', '20m genişliğinde güçlü rüzgar duvarı çağırır. Fiziksel mermileri tamamen engeller ve içinden geçen düşmanlara 4d6 kesme hasarı verir.', 'Summons a 20m wide wall of strong winds. It completely blocks physical projectiles and deals 4d6 slashing damage to enemies crossing it.', 'Air', 50, 450, 3, '{"em_lightning_bolt"}', '{"x": -1255, "y": 724}', '{"width": "20m", "damage": "4d6", "block_projectiles": "true"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26ab93fd-fb84-43ca-9a53-7334fb1567d2', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_chain_lightning', 'Zincirleme Yıldırım', 'Chain Lightning', 'Bir hedefe 10d8 yıldırım hasarı ile vurur, ardından birbirine 10m mesafedeki 4 ek hedefe sıçrar.', 'Strikes a target with 10d8 lightning damage, then jumps to 4 additional targets within 10m of each other.', 'Air', 65, 700, 4, '{"em_wind_wall"}', '{"x": -1472, "y": 849}', '{"damage": "10d8", "jump_targets": "4", "jump_range": "10m"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('80bc8ea1-94d1-4400-afdb-0b4d838685b3', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_major_air_elemental', 'Büyük Hava Elementali', 'Major Air Elemental', 'İstatistikleri büyücü seviyenizin %100''üne eşit olan Büyük bir Hava Elementali çağırır. 10 tur sürer.', 'Summons a Major Air Elemental with stats equal to 100% of your caster level. Lasts for 10 turns.', 'Air', 75, 850, 4, '{"em_chain_lightning"}', '{"x": -1688, "y": 974}', '{"duration": "10 turns", "scaling": "100% caster level"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('196ec008-a69b-40f0-b766-1ec24bebc0c4', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_tornado', 'Kasırga', 'Tornado', '4 tur boyunca tur başına 10m hareket eden devasa bir kasırga (10m genişliğinde) yaratır. 12d6 kesme hasarı verir ve hedefleri havaya kaldırır.', 'Creates a massive 10m wide tornado that moves 10m per turn for 4 turns. It deals 12d6 slashing damage and lifts targets into the air.', 'Air', 85, 1200, 5, '{"em_major_air_elemental"}', '{"x": -1905, "y": 1099}', '{"damage": "12d6", "width": "10m", "movement": "10m per turn", "duration": "4 turns"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4c4ec70a-af63-45a3-adee-d3ea2cc014e5', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_tempest_avatar', 'Fırtına Avatarı', 'Tempest Avatar', 'Sizi 5 turluğuna Fırtına Avatarına dönüştürür. 30m uçma hızı, %50 kaçınma şansı ve 5d6 hasar veren pasif yıldırım aurası kazandırır.', 'Transforms you into a Tempest Avatar for 5 turns. Grants 30m fly speed, 50% dodge chance, and a passive lightning aura dealing 5d6 damage.', 'Air', 95, 1500, 5, '{"em_tornado"}', '{"x": -2121, "y": 1224}', '{"duration": "5 turns", "fly_speed": "30m", "dodge": "50%", "aura_damage": "5d6"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d0c3feb7-6e2d-48b3-b0e4-ff908735ee94', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_steam_cloud', 'Buhar Bulutu', 'Steam Cloud', 'Aşırı ısı ve suyu karıştırarak 15m yarıçaplı kaynar bir buhar bulutu yaratır. İçerideki hedefler 3d6 ateş hasarı alır ve 2 tur boyunca kör olurlar.', 'Mixes extreme heat and water to create a 15m radius scalding steam cloud. Targets inside take 3d6 fire damage and are blinded for 2 turns.', 'Cross-Branch', 35, 250, 2, '{"em_ignite", "em_frostbite"}', '{"x": -173, "y": -100}', '{"damage": "3d6", "radius": "15m", "status": "blind", "duration": "2 turns"}', '♨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f6d75691-dfc8-4e68-9345-0e20e3dbad49', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_magma_eruption', 'Magma Patlaması', 'Magma Eruption', '30m uzağa kadar 10m yarıçaplı bir alanda lav patlamasına neden olur. 6d8 ateş hasarı verir ve alanı her tur 2d6 yanan zorlu araziye dönüştürür.', 'Causes lava to erupt in a 10m radius up to 30m away. Deals 6d8 fire damage and turns the area into difficult terrain burning for 2d6 per turn.', 'Cross-Branch', 45, 400, 3, '{"em_fireball", "em_stone_armor"}', '{"x": -389, "y": -225}', '{"damage": "6d8", "radius": "10m", "burn_damage": "2d6 per turn", "range": "30m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6021ade9-6810-40cd-86c1-afcd7ee4b82d', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_supercell', 'Süper Hücre', 'Supercell', '30m''lik alanı kaplayan ağır bir fırtına çağırır. İçerideki müttefikler tur başına 2d8 iyileşirken, düşmanlara yıldırım çarparak 4d8 hasar verir.', 'Summons a heavy storm covering a 30m area. Allies inside heal for 2d8 per turn while enemies are struck by lightning for 4d8 damage.', 'Cross-Branch', 55, 450, 3, '{"em_healing_rain", "em_lightning_bolt"}', '{"x": -606, "y": -350}', '{"healing": "2d8", "damage": "4d8", "radius": "30m"}', '⛈️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1058a1bb-a595-4220-ab63-c6060a517397', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_sandstorm', 'Kum Fırtınası', 'Sandstorm', 'Tur başına 5d6 kesme hasarı veren, görüş mesafesini 2m''ye düşüren ve içerideki tüm büyücüleri susturan şiddetli bir 15m yarıçaplı kum fırtınası yaratır.', 'Conjures a fierce 15m radius sandstorm that deals 5d6 slashing damage per turn, reduces visibility to 2m, and silences all spellcasters inside.', 'Cross-Branch', 65, 700, 4, '{"em_spike_growth", "em_wind_wall"}', '{"x": -822, "y": -475}', '{"damage": "5d6", "radius": "15m", "visibility": "2m", "status": "silence"}', '🏜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('62c01df6-698e-492f-905f-1d4ded059d2c', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_mudslide', 'Çamur Kayması', 'Mudslide', '20m''lik koni şeklinde yoğun çamur serbest bırakır. 6d6 ezme hasarı verir ve düşmanları tamamen kaplayarak onları 3 tur boyunca %75 yavaşlatır.', 'Unleashes a 20m cone of thick mud. Deals 6d6 bludgeoning damage and completely coats enemies, slowing them by 75% for 3 turns.', 'Cross-Branch', 70, 800, 4, '{"em_tidal_wave", "em_boulder_toss"}', '{"x": -1039, "y": -600}', '{"damage": "6d6", "cone": "20m", "slow": "75%", "duration": "3 turns"}', '🟤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dbb54d26-7eb3-4ef8-b4de-74b86c6b3f43', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_plasma_ray', 'Plazma Işını', 'Plasma Ray', 'Aşırı ısınmış plazmadan oluşan yoğun bir ışın fırlatır. Toplam 12d10 ateş ve yıldırım hasarı verir, hedefin zırhının %50''sini eritir. 40m menzil.', 'Fires a concentrated beam of superheated plasma. Deals 12d10 combined fire and lightning damage, melting 50% of the target''s armor. 40m range.', 'Cross-Branch', 80, 900, 4, '{"em_combustion", "em_chain_lightning"}', '{"x": -1255, "y": -725}', '{"damage": "12d10", "range": "40m", "armor_melt": "50%"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a66a71f8-cd06-4a5c-a377-4b590fd741dc', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_volcanic_ash', 'Volkanik Kül', 'Volcanic Ash', 'Yerden 40m''lik devasa bir kül bulutu yükselir ve 8d6 ateş hasarı verir. Zehirli kül düşmanları boğarak 3 tur boyunca susturma ve %50 ıskalama şansı verir.', 'A massive 40m ash cloud billows from the ground, dealing 8d6 fire damage. The toxic ash chokes enemies, causing silence and a 50% miss chance for 3 turns.', 'Cross-Branch', 85, 1200, 5, '{"em_magma_eruption", "em_sandstorm"}', '{"x": -1472, "y": -850}', '{"damage": "8d6", "radius": "40m", "status": "silence", "miss_chance": "50%", "duration": "3 turns"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c1eefa6-b181-45d6-a65c-f127ed5e7efa', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_glacial_quake', 'Buzul Depremi', 'Glacial Quake', '25m yarıçaplı alanı anında dondurur ve parçalar. 10d8 soğuk hasarı verir, şiddetli kanamaya neden olur ve tüm düşmanları 2 tur sersemletir.', 'Instantly freezes and shatters the ground in a 25m radius. Deals 10d8 cold damage, causes severe bleeding, and stuns all enemies for 2 turns.', 'Cross-Branch', 90, 1300, 5, '{"em_blizzard", "em_earthquake"}', '{"x": -1688, "y": -975}', '{"damage": "10d8", "radius": "25m", "status": "bleed, stun", "stun_duration": "2 turns"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('57a1d51d-c063-40d7-be69-1241877fd20a', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_geyser_surge', 'Gayzer Fışkırması', 'Geyser Surge', '15m yarıçaplı bir alanda kaynar su fışkırır. 12d8 ateş ve 10d8 ezme hasarı verir, hedefleri yere çarpmadan önce 20m havaya kaldırır.', 'Boiling water bursts from the earth in a 15m radius. Deals 12d8 fire and 10d8 bludgeoning damage, lifting targets 20m into the air before they crash down.', 'Cross-Branch', 95, 1400, 5, '{"em_inferno", "em_tsunami"}', '{"x": -1905, "y": -1100}', '{"damage": "12d8 fire, 10d8 bludgeoning", "radius": "15m", "lift": "20m"}', '⛲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8c54e750-d2f7-4c74-a216-35c7ebe60246', 'af89d25d-f951-4fc8-8951-d53ac92c89e6', 'em_elemental_convergence', 'Elementlerin Birleşimi', 'Elemental Convergence', 'Dört elementin hepsini çağırır. Bir Elementbeyi (%150 büyücü seviyesi) çağırır ve 50m''lik devasa bir patlama ile her elementten 10d10 hasar verir. Savaş alanını kalıcı olarak değiştirir.', 'Calls upon all four elements. Summons an Elemental Overlord (150% caster level) and unleashes a 50m blast dealing 10d10 of each element''s damage. Permanently alters the battlefield.', 'Cross-Branch', 100, 1500, 5, '{"em_firelord_avatar", "em_leviathan_avatar", "em_titan_avatar", "em_tempest_avatar"}', '{"x": -2121, "y": -1225}', '{"damage": "40d10 total", "radius": "50m", "summon": "Elemental Overlord (150%)"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('820b1f7d-6db9-4ca8-88a1-83ab82086972', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_ruthless_strike', 'Acımasız Darbe', 'Ruthless Strike', '1d8 fiziksel hasar veren hesaplanmış bir darbe. %20 HP''nin altındaki hedefleri anında infaz etme şansı %50''dir.', 'A calculated strike dealing 1d8 physical damage. Has a 50% chance to instantly execute targets below 20% HP.', 'Execution', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8", "execute_chance": "50%", "execute_threshold": "20% HP"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b33bb71a-a973-4588-a952-db828aeccc57', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_blood_scent', 'Kan Kokusu', 'Blood Scent', 'Pasif. Kanayan hedeflere karşı algı ve iz sürme zarlarında +2 kazan.', 'Passive. Gain +2 to perception and tracking checks against bleeding targets.', 'Execution', 5, 75, 1, '{"ex_ruthless_strike"}', '{"x": 389, "y": -224}', '{"passive": true, "perception_bonus": 2, "tracking_bonus": 2, "condition": "bleeding_targets"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f83be87a-b722-4b43-af7c-55b38fb9a891', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_crippling_blow', 'Sakatlayıcı Darbe', 'Crippling Blow', 'Bacakları hedef alarak 2d6 hasar ver ve hareket hızlarını 2 tur boyunca 3m azalt.', 'Target the legs, dealing 2d6 damage and reducing their movement speed by 3m for 2 turns.', 'Execution', 10, 100, 1, '{"ex_blood_scent"}', '{"x": 606, "y": -349}', '{"damage": "2d6", "speed_reduction": "3m", "duration": "2 turns"}', '🦵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c70a4ec8-e688-4cf3-952c-59d1edd1a56b', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_finishing_touch', 'Bitirici Dokunuş', 'Finishing Touch', '3d6 hasar veren cerrahi bir darbe indir. Bu saldırı için infaz sınırı %25 HP''ye çıkar.', 'Deliver a surgical strike for 3d6 damage. Execute threshold increased to 25% HP for this attack.', 'Execution', 15, 125, 1, '{"ex_crippling_blow"}', '{"x": 822, "y": -474}', '{"damage": "3d6", "execute_chance": "50%", "execute_threshold": "25% HP"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc69e8a5-58b5-40f7-ac70-45d4b97607f8', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_cull_the_weak', 'Zayıfları Ayıkla', 'Cull the Weak', 'Pasif. Saldırıların yavaşlatılmış, sersemlemiş veya sabitlenmiş düşmanlara %20 daha fazla hasar verir.', 'Passive. Your attacks deal 20% more damage to enemies that are slowed, stunned, or rooted.', 'Execution', 21, 175, 2, '{"ex_finishing_touch"}', '{"x": 1039, "y": -599}', '{"passive": true, "damage_bonus": "20%", "condition": "slowed_stunned_rooted"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a836559e-f88e-4196-8f5f-3ed3079018b9', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_guillotine', 'Giyotin', 'Guillotine', '4d8 hasar veren ağır bir dikey kesiş. Şiddetli kanamaya neden olarak 3 tur boyunca her tur 1d8 hasar verir.', 'A heavy vertical chop dealing 4d8 damage. Causes severe bleeding, dealing 1d8 damage per turn for 3 turns.', 'Execution', 28, 225, 2, '{"ex_cull_the_weak"}', '{"x": 1255, "y": -724}', '{"damage": "4d8", "dot": "1d8", "dot_type": "bleeding", "duration": "3 turns"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a48addd9-d797-484a-b69d-e977e7d32fbe', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_lethal_momentum', 'Ölümcül Moment', 'Lethal Momentum', 'Pasif. Bir düşmanı infaz etmek bu tur sana fazladan bir eylem ve 5m hareket hızı kazandırır.', 'Passive. Executing an enemy grants you an extra action and 5m of movement speed this turn.', 'Execution', 35, 275, 2, '{"ex_guillotine"}', '{"x": 1472, "y": -849}', '{"passive": true, "on_kill_extra_action": 1, "on_kill_speed_bonus": "5m"}', '🚀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('28b7ff0f-2855-4585-8029-fc91b1f75f7c', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_sever_artery', 'Atardamar Kesme', 'Sever Artery', 'Hedefin aldığı tüm iyileştirmeleri 3 tur boyunca yarıya indiren 5d6 hasarlık isabetli bir darbe.', 'A precise strike dealing 5d6 damage that halves all healing received by the target for 3 turns.', 'Execution', 42, 350, 3, '{"ex_lethal_momentum"}', '{"x": 1688, "y": -974}', '{"damage": "5d6", "healing_reduction": "50%", "duration": "3 turns"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('044a7207-137c-4d74-92d7-1fba9ada29a0', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_headsman_chop', 'Cellat Vuruşu', 'Headsman Chop', '6d8 hasar veren vahşi bir saldırı. %50 infaz şansı artık %30 HP''nin altındaki hedefler için geçerlidir.', 'A vicious attack dealing 6d8 damage. The 50% execute chance now applies to targets below 30% HP.', 'Execution', 49, 425, 3, '{"ex_sever_artery"}', '{"x": 1905, "y": -1099}', '{"damage": "6d8", "execute_chance": "50%", "execute_threshold": "30% HP"}', '🥩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f7233e6b-c6e9-46da-bb49-abb9bb743333', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_executioner_stance', 'Cellat Duruşu', 'Executioner Stance', '3 tur boyunca ölümcül bir duruşa geç. Saldırıların fiziksel zırhın %20''sini yok sayar ve +%10 infaz hasarı verir.', 'Enter a deadly stance for 3 turns. Your attacks ignore 20% of physical armor and deal +10% execute damage.', 'Execution', 56, 500, 3, '{"ex_headsman_chop"}', '{"x": 2121, "y": -1224}', '{"stance": true, "armor_penetration": "20%", "execute_damage_bonus": "10%", "duration": "3 turns"}', '🧍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb4997c2-0823-424d-b08d-b1c3ade0aca8', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_merciless_judgment', 'Acımasız Yargı', 'Merciless Judgment', 'Hedefe 8d8 hasar ver. Hayatta kalırlarsa, tüm kaynaklardan iki kat kanama hasarı alırlar.', 'Strike the target for 8d8 damage. If they survive, they take double bleeding damage from all sources.', 'Execution', 63, 600, 4, '{"ex_executioner_stance"}', '{"x": 2338, "y": -1349}', '{"damage": "8d8", "bleeding_vulnerability": "200%"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e2064c46-885f-4dcc-8147-85a3fb8c85de', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_decapitate', 'Kafa Koparma', 'Decapitate', 'Hedefin kafasını kesmeye çalış, 8d10 hasar ver. %30 HP''nin altındaki normal düşmanları anında öldürür.', 'Attempt to decapitate the target, dealing 8d10 damage. Instantly kills regular enemies below 30% HP.', 'Execution', 68, 700, 4, '{"ex_merciless_judgment"}', '{"x": 2554, "y": -1474}', '{"damage": "8d10", "execute_threshold": "30% HP", "execute_chance": "100% on normal enemies"}', '👤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c79e36f3-0aad-4715-b09d-986aef993c39', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_fatal_flaw', 'Ölümcül Kusur', 'Fatal Flaw', 'Açık bir zayıf noktadan faydalan. Sonraki saldırın garanti bir kritik vuruştur ve 3x çarpanı vardır.', 'Exploit an exposed weak point. Your next attack is a guaranteed critical hit with a 3x multiplier.', 'Execution', 73, 800, 4, '{"ex_decapitate"}', '{"x": 2771, "y": -1599}', '{"guaranteed_crit": true, "crit_multiplier": 3, "charges": 1}', '🔍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9fcc6af-c8e0-4fbf-a294-5e0371a766fd', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_death_warrant', 'Ölüm Fermanı', 'Death Warrant', 'Bir hedefi ölüm için işaretle. Saldırılarından %30 daha fazla hasar alırlar ve 2 tur boyunca oldukları yere sabitlenirler.', 'Mark a target for death. They take 30% more damage from your attacks and are rooted in place for 2 turns.', 'Execution', 78, 900, 4, '{"ex_fatal_flaw"}', '{"x": 2987, "y": -1724}', '{"mark": true, "damage_vulnerability": "30%", "root": true, "duration": "2 turns"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d35dd63e-cb3e-4312-aac9-ca6249008802', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_final_verdict', 'Son Karar', 'Final Verdict', 'NİHAİ: Nihai cezayı kes. 15d12 hasar ver. Hedef %50 HP''nin altındaysa anında infaz et. Diriltilemez.', 'ULTIMATE: Deliver the ultimate punishment. Deal 15d12 damage. If the target is below 50% HP, execute them instantly. Unrevivable.', 'Execution', 95, 1200, 5, '{"ex_death_warrant"}', '{"x": 3204, "y": -1849}', '{"damage": "15d12", "execute_threshold": "50% HP", "execute_chance": "100%", "unrevivable": true}', '⚰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee2e56f5-6757-4ee9-88ba-db9c2d0d160f', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_heavy_cleave', 'Ağır Yarma', 'Heavy Cleave', 'Silahını geniş bir kavisle savur, 3m ön koni içindeki en fazla 3 düşmana 2d8 hasar ver.', 'Swing your weapon in a wide arc, dealing 2d8 damage to up to 3 enemies within a 3m frontal cone.', 'Blade Mastery', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "2d8", "aoe_cone": "3m", "max_targets": 3}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a5c3718d-708c-4cfd-8b9c-5b2aa27821cc', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_honed_edge', 'Bilenmiş Kesici', 'Honed Edge', 'Pasif. Titiz silah bakımın çift elli kesici silahlarla yapılan saldırı zarlarına +1 kazandırır.', 'Passive. Your meticulous weapon care grants +1 to attack rolls with two-handed bladed weapons.', 'Blade Mastery', 7, 75, 1, '{"ex_heavy_cleave"}', '{"x": 289, "y": 344}', '{"passive": true, "attack_roll_bonus": 1, "weapon_requirement": "two-handed blade"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a9c56810-ced7-4080-8701-deac313f4cca', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_sweeping_blade', 'Süpüren Kılıç', 'Sweeping Blade', '4m yarıçapındaki tüm düşmanlara 3d6 hasar vererek onları 2m geriye savur.', 'Strike all enemies within a 4m radius for 3d6 damage, knocking them back 2m.', 'Blade Mastery', 12, 100, 1, '{"ex_honed_edge"}', '{"x": 449, "y": 536}', '{"damage": "3d6", "aoe_radius": "4m", "knockback": "2m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3926a63a-efab-4ffd-8781-b00b7972f484', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_blade_dash', 'Kılıç Atılımı', 'Blade Dash', 'Düz bir çizgide 8m''ye kadar atıl, içinden geçtiğin tüm düşmanlara 3d8 hasar ver.', 'Dash up to 8m in a straight line, dealing 3d8 damage to all enemies you pass through.', 'Blade Mastery', 17, 125, 1, '{"ex_sweeping_blade"}', '{"x": 610, "y": 727}', '{"damage": "3d8", "dash_range": "8m", "aoe_line": true}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1835d8d5-50ed-48ab-b8ba-24dad0525c8e', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_steel_whirlwind', 'Çelik Kasırgası', 'Steel Whirlwind', 'Hızla kendi etrafında dön, 5m içindeki tüm düşmanlara her biri 2d6 hasar veren iki vuruş yap.', 'Spin rapidly, striking all enemies within 5m twice for 2d6 damage each hit.', 'Blade Mastery', 23, 175, 2, '{"ex_blade_dash"}', '{"x": 771, "y": 919}', '{"damage": "2d6", "hits": 2, "aoe_radius": "5m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('91cfd972-0d82-491b-8833-7a08e08e6104', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_parry_and_riposte', 'Savuşturma ve Karşı Saldırı', 'Parry and Riposte', 'Savunma duruşuna geç. Sana yapılan sonraki yakın dövüş saldırısını iptal et ve 4d8 hasarla karşılık ver.', 'Assume a defensive posture. Negate the next melee attack against you and counter for 4d8 damage.', 'Blade Mastery', 30, 250, 2, '{"ex_steel_whirlwind"}', '{"x": 932, "y": 1110}', '{"parry": true, "counter_damage": "4d8", "trigger": "next_melee_attack"}', '🤺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb0ba95b-714b-4fd8-91f2-d22937721233', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_armor_breaker', 'Zırh Kırıcı', 'Armor Breaker', '4d10 hasar veren ve hedefin Zırh Sınıfını (AC) 3 tur boyunca 3 azaltan ezici bir darbe.', 'A crushing blow that deals 4d10 damage and reduces the target''s Armor Class by 3 for 3 turns.', 'Blade Mastery', 37, 300, 2, '{"ex_parry_and_riposte"}', '{"x": 1092, "y": 1302}', '{"damage": "4d10", "ac_reduction": 3, "duration": "3 turns"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d75030d-b559-4942-a1e0-e8aeb05b14b0', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_bloodied_blade', 'Kanlı Kılıç', 'Bloodied Blade', 'Pasif. Silah saldırıların, eksik HP''nin %5''i kadar ilave fiziksel hasar verir.', 'Passive. Your weapon attacks deal bonus physical damage equal to 5% of your missing HP.', 'Blade Mastery', 44, 350, 3, '{"ex_armor_breaker"}', '{"x": 1253, "y": 1493}', '{"passive": true, "bonus_damage": "5% missing HP"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4b17de0-721e-4910-a4ae-8f6931ae66f8', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_colossal_smash', 'Devasa Ezme', 'Colossal Smash', 'Sıçra ve yere şiddetle vur, 6m yarıçapta 6d8 hasar ver ve düşmanları 1 tur sersemlet.', 'Leap and smash the ground, dealing 6d8 damage in a 6m radius and stunning enemies for 1 turn.', 'Blade Mastery', 51, 425, 3, '{"ex_bloodied_blade"}', '{"x": 1414, "y": 1685}', '{"damage": "6d8", "aoe_radius": "6m", "stun": true, "duration": "1 turn"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5a2faab3-333a-4ed1-8131-1f2ba6c9a697', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_blade_fury', 'Kılıç Öfkesi', 'Blade Fury', 'Tek bir hedefe her biri 3d10 fiziksel hasar veren 3 hızlı darbe yağmuru serbest bırak.', 'Unleash a barrage of 3 rapid strikes, each dealing 3d10 physical damage to a single target.', 'Blade Mastery', 58, 500, 3, '{"ex_colossal_smash"}', '{"x": 1574, "y": 1876}', '{"damage": "3d10", "hits": 3}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6f288582-acfe-4048-9730-ee95eb95cacc', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_slaughtering_swing', 'Katliam Savuruşu', 'Slaughtering Swing', '8m ön konide 8d8 hasar veren devasa yatay bir savuruş.', 'A massive horizontal swing dealing 8d8 damage in an 8m frontal cone.', 'Blade Mastery', 64, 600, 4, '{"ex_blade_fury"}', '{"x": 1735, "y": 2068}', '{"damage": "8d8", "aoe_cone": "8m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f8ee451-ef05-4582-a97b-658e338be81e', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_deflecting_steel', 'Saptıran Çelik', 'Deflecting Steel', 'Bıçağını gelen tüm fiziksel mermileri 2 tur boyunca saptıracak kadar hızlı çevir.', 'Spin your blade fast enough to deflect all incoming physical projectiles for 2 turns.', 'Blade Mastery', 69, 700, 4, '{"ex_slaughtering_swing"}', '{"x": 1896, "y": 2259}', '{"deflect_projectiles": true, "duration": "2 turns"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b5fba0da-bdce-405c-88b6-b8d7a2c684d9', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_phantom_slash', 'Hayalet Kesik', 'Phantom Slash', '15m''lik bir çizgideki düşmanlara 8d10 hasar veren sıkıştırılmış bir bıçak enerjisi dalgası yolla.', 'Send out a compressed wave of blade energy dealing 8d10 damage to enemies in a 15m line.', 'Blade Mastery', 74, 800, 4, '{"ex_deflecting_steel"}', '{"x": 2056, "y": 2451}', '{"damage": "8d10", "aoe_line": "15m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1802d55c-4a3e-474e-9152-301796c92d4c', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_master_of_arms', 'Silah Ustası', 'Master of Arms', 'Pasif. Yüce kılıç ustalığın, hedefin fiziksel direncinin %50''sini yok saymanı sağlar.', 'Passive. Your supreme blade mastery allows you to ignore 50% of the target''s physical resistance.', 'Blade Mastery', 79, 900, 4, '{"ex_phantom_slash"}', '{"x": 2217, "y": 2642}', '{"passive": true, "armor_penetration": "50%"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0229bb3d-a7d8-4c18-8c86-034aa30ea25f', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_blade_of_annihilation', 'Yok Oluş Kılıcı', 'Blade of Annihilation', 'NİHAİ: 10m''lik bir çizgide 20d10 fiziksel hasar veren gerçekliği yırtan tek bir darbe. Tüm zırh ve kalkanları yok sayar.', 'ULTIMATE: A single, reality-tearing strike dealing 20d10 physical damage in a 10m line. Ignores all armor and shields.', 'Blade Mastery', 96, 1200, 5, '{"ex_master_of_arms"}', '{"x": 2378, "y": 2834}', '{"damage": "20d10", "aoe_line": "10m", "ignores_all_armor": true, "ignores_shields": true}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('58112ebb-0d45-4865-b95b-2c3844511296', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_menacing_glare', 'Tehditkar Bakış', 'Menacing Glare', 'Bir hedefle göz göze gelip onu dehşete düşür. Saldırı zarlarını 2 tur boyunca 2 azalt.', 'Lock eyes with a target, terrifying them. Reduces their attack rolls by 2 for 2 turns.', 'Intimidation', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"attack_roll_penalty": -2, "duration": "2 turns"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2a7a6f19-fe91-4604-917f-60d7ab8a0ef5', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_frightening_shout', 'Korkutucu Bağırma', 'Frightening Shout', 'Korkutucu bir kükreme kopar. 8m içindeki düşmanlar kurtarma zarı atamazsa 1 tur korkuya kapılır.', 'Let out a terrifying roar. Enemies within 8m must succeed a save or become feared for 1 turn.', 'Intimidation', 8, 75, 1, '{"ex_menacing_glare"}', '{"x": -289, "y": 344}', '{"fear": true, "aoe_radius": "8m", "duration": "1 turn"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('620b49fa-79ae-419b-a1ad-8822adaeba32', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_aura_of_dread', 'Dehşet Aurası', 'Aura of Dread', 'Pasif. Bir dehşet aurası yayarsın. 5m içindeki düşmanlar tüm kurtarma zarlarına -1 cezası alır.', 'Passive. You radiate an aura of dread. Enemies within 5m of you suffer -1 to all saving throws.', 'Intimidation', 13, 100, 1, '{"ex_frightening_shout"}', '{"x": -449, "y": 536}', '{"passive": true, "aura": "5m", "saving_throw_penalty": -1}', '🥶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f9122d80-9a4c-4247-82f9-4ca5e87a873d', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_stare_down', 'Dik Bakış', 'Stare Down', 'Bir hedefi korkuyla geri çekilmeye zorla. Hedef anında senden 6m uzaklaşır ve reaksiyonunu kaybeder.', 'Force a target to back away in fear. The target instantly moves 6m away from you and loses their reaction.', 'Intimidation', 18, 125, 1, '{"ex_aura_of_dread"}', '{"x": -610, "y": 727}', '{"forced_movement": "6m away", "lose_reaction": true}', '🔙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('39f9d8b8-881d-409b-93ad-a78997551f6e', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_terror_strike', 'Terör Darbesi', 'Terror Strike', 'Bir hedefe 3d8 hasar ver. Hedef korku etkisindeyse, bu saldırı iki kat hasar verir.', 'Strike a target for 3d8 damage. If the target is suffering from fear, this deals double damage.', 'Intimidation', 25, 200, 2, '{"ex_stare_down"}', '{"x": -771, "y": 919}', '{"damage": "3d8", "fear_vulnerability": "200%"}', '😱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7cfc789b-6043-4254-be6c-2f7e669d75e5', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_bloodcurdling_roar', 'Kan Donduran Kükreme', 'Bloodcurdling Roar', '10m yarıçapındaki tüm düşmanlara 4d6 sonik hasar veren ve onları 2 tur korkutan sağır edici bir kükreme.', 'A deafening roar dealing 4d6 sonic damage and fearing all enemies in a 10m radius for 2 turns.', 'Intimidation', 32, 250, 2, '{"ex_terror_strike"}', '{"x": -932, "y": 1110}', '{"damage": "4d6", "damage_type": "sonic", "fear": true, "aoe_radius": "10m", "duration": "2 turns"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('977478fa-ee98-416e-86ab-d09d6b23b458', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_imposing_presence', 'Heybetli Duruş', 'Imposing Presence', 'Pasif. Salt varlığın seni korku ve çekicilik etkilerine karşı tamamen bağışık kılar.', 'Passive. Your sheer presence makes you completely immune to fear and charm effects.', 'Intimidation', 39, 300, 2, '{"ex_bloodcurdling_roar"}', '{"x": -1092, "y": 1302}', '{"passive": true, "immune_fear": true, "immune_charm": true}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c91070aa-72bc-467b-a9f9-4dae815a8f1d', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_panic_wave', 'Panik Dalgası', 'Panic Wave', 'Saf bir panik dalgası yay. 12m içindeki düşmanlar silahlarını düşürür ve 1 tur boyunca kaçarlar.', 'Emit a wave of pure panic. Enemies within 12m drop their weapons and run away for 1 turn.', 'Intimidation', 46, 375, 3, '{"ex_imposing_presence"}', '{"x": -1253, "y": 1493}', '{"panic": true, "disarm": true, "aoe_radius": "12m", "duration": "1 turn"}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ee7da9c-2048-4553-b379-8ab65ec700e8', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_crush_morale', 'Moral Çökertme', 'Crush Morale', 'Yere ezici bir güçle vur. Savaştaki tüm düşmanlar mevcut mana ve dayanıklılıklarının %20''sini kaybeder.', 'Slam the ground with overwhelming force. All enemies in combat lose 20% of their current mana and stamina.', 'Intimidation', 53, 450, 3, '{"ex_panic_wave"}', '{"x": -1414, "y": 1685}', '{"mana_drain": "20% current", "stamina_drain": "20% current", "aoe": "all_combatants"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f801041-26e3-4716-80cb-714f3ad98165', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_fear_toxin', 'Korku Toksini', 'Fear Toxin', 'Pasif. Korkutucu vuruşların psikolojik baskı uygular. 3 yükte hedef en yakın müttefikine saldırır.', 'Passive. Your intimidating strikes apply psychological pressure. At 3 stacks, the target attacks their closest ally.', 'Intimidation', 60, 500, 3, '{"ex_crush_morale"}', '{"x": -1574, "y": 1876}', '{"passive": true, "stack_effect": "madness", "max_stacks": 3, "trigger": "attack_ally"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('11ddde1f-70c5-4511-8ea5-a06306a2fe43', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_hallucination_of_death', 'Ölüm Halüsinasyonu', 'Hallucination of Death', 'Hedef kendi korkunç ölümünü görür, 8d8 psişik hasar alır ve 1 tur boyunca korkudan felç olur.', 'The target sees their own gruesome demise, taking 8d8 psychic damage and paralyzing them with fear for 1 turn.', 'Intimidation', 65, 650, 4, '{"ex_fear_toxin"}', '{"x": -1735, "y": 2068}', '{"damage": "8d8", "damage_type": "psychic", "paralyze": true, "duration": "1 turn"}', '😵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90f38b53-34a2-401b-a76d-261503de6dfd', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_paralyzing_fear', 'Felç Edici Korku', 'Paralyzing Fear', 'Felç edici bir terör yay. Senin 8m yakınına giren herhangi bir düşman anında 1 tur felç olur.', 'Radiate paralyzing terror. Any enemy that steps within 8m of you is immediately paralyzed for 1 turn.', 'Intimidation', 70, 750, 4, '{"ex_hallucination_of_death"}', '{"x": -1896, "y": 2259}', '{"aura": "8m", "paralyze": true, "duration": "1 turn"}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9b64d73a-ab88-4927-9a1b-5417e29188de', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_shatter_will', 'İrade Kırma', 'Shatter Will', 'Hedefin zihnini tamamen kır. Sihirli bir şekilde onarılana kadar kalıcı olarak 4 WIS ve 4 INT kaybederler.', 'Break the target''s mind completely. They permanently lose 4 WIS and 4 INT until magically restored.', 'Intimidation', 75, 850, 4, '{"ex_paralyzing_fear"}', '{"x": -2056, "y": 2451}', '{"stat_penalty_wis": 4, "stat_penalty_int": 4, "permanent": true}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6e4c45b4-e2f0-4a41-a8b1-cab29fe54785', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_lord_of_terror', 'Terör Lordu', 'Lord of Terror', 'Pasif. Korkutucu varlığın mutlaktır. Tüm korku etkilerin düşmanların korku bağışıklığını delip geçer.', 'Passive. Your terrifying presence is absolute. All your fear effects bypass enemy fear immunity.', 'Intimidation', 80, 900, 4, '{"ex_shatter_will"}', '{"x": -2217, "y": 2642}', '{"passive": true, "bypass_fear_immunity": true}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55afb129-10fe-4fd3-b097-8082ab7c999c', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_domain_of_despair', 'Umutsuzluk Alanı', 'Domain of Despair', 'NİHAİ: 30m''lik alanı 3 tur boyunca kabus bölgesine çevir. Düşmanlar tur başına 10d10 psişik hasar alır, %80 yavaşlar ve iyileşemez.', 'ULTIMATE: Turn a 30m area into a nightmare zone for 3 turns. Enemies take 10d10 psychic damage per turn, are slowed by 80%, and cannot heal.', 'Intimidation', 97, 1200, 5, '{"ex_lord_of_terror"}', '{"x": -2378, "y": 2834}', '{"aoe_radius": "30m", "dot": "10d10", "damage_type": "psychic", "slow": "80%", "prevent_healing": true, "duration": "3 turns"}', '🏚️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('649b92be-18d5-49d2-9b01-2d166a93de52', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_bloodbath', 'Kan Banyosu', 'Bloodbath', 'Çapraz Dal: 6m içindeki herkese 6d10 hasar veren bir ölüm kasırgası. Verilen hasarın %50''si kadar iyileşirsin.', 'Cross-Branch: A whirlwind of death dealing 6d10 damage to all within 6m. You heal for 50% of the damage dealt.', 'Cross-Branch', 50, 450, 3, '{"ex_headsman_chop", "ex_colossal_smash"}', '{"x": -173, "y": -100}', '{"damage": "6d10", "aoe_radius": "6m", "lifesteal": "50%"}', '🛁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c138c7a9-3a1d-4de7-8d41-cbf414352dbd', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_frightful_cleave', 'Korkunç Yarma', 'Frightful Cleave', 'Çapraz Dal: 7d8 hasar veren devasa geniş bir savuruş. İsabet alan düşmanlar 3 tur boyunca korkar.', 'Cross-Branch: A massive sweeping cleave dealing 7d8 damage. Enemies hit are feared for 3 turns.', 'Cross-Branch', 55, 500, 3, '{"ex_colossal_smash", "ex_crush_morale"}', '{"x": -389, "y": -225}', '{"damage": "7d8", "aoe_cleave": true, "fear": true, "duration": "3 turns"}', '🪚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce6c023e-dc2b-48df-beeb-67a1847227be', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_dread_juggernaut', 'Korkunç Ezici Güç', 'Dread Juggernaut', 'Çapraz Dal: Durdurulamaz bir cellat ol. 4 tur boyunca kitle kontrole bağışık, +10m hız, +%40 hasar.', 'Cross-Branch: Become an unstoppable executioner. Immune to crowd control, +10m speed, +40% damage for 4 turns.', 'Cross-Branch', 76, 800, 4, '{"ex_death_warrant", "ex_paralyzing_fear"}', '{"x": -606, "y": -350}', '{"cc_immunity": true, "speed_bonus": "10m", "damage_bonus": "40%", "duration": "4 turns"}', '🚂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26c9f931-a0b4-4db6-8689-7c48cf0a3cf6', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_executioner_aspect', 'Cellat Görünümü', 'Executioner Aspect', 'Çapraz Dal Pasif: Tüm düşmanlar %15 daha fazla fiziksel hasar alır. Temel %50 infaz şansın artık %30 HP''de tetiklenir.', 'Cross-Branch Passive: All enemies take 15% more physical damage. Your base 50% execute chance now triggers at 30% HP.', 'Cross-Branch', 90, 1100, 5, '{"ex_fatal_flaw", "ex_master_of_arms", "ex_shatter_will"}', '{"x": -822, "y": -475}', '{"passive": true, "global_damage_vulnerability": "15%", "execute_threshold": "30% HP"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a458fef7-58a4-41b2-afa5-24f49d5f1873', 'e6d48a4a-bb6c-436e-94f3-7eec7579e3b9', 'ex_the_end_of_all', 'Her Şeyin Sonu', 'The End of All', 'BÜYÜK NİHAİ: Tek bir hedefe 30d12 hasar veren feci bir darbe. Ölürlerse ruhları yok olur (diriltilemez) ve haritadaki tüm düşmanlar 5 tur korkar. 3 dalın nihaisini gerektirir.', 'GRAND ULTIMATE: A catastrophic strike on a single target dealing 30d12 damage. If they die, their soul is destroyed (unrevivable) and all enemies map-wide are feared for 5 turns. Requires all 3 branch ultimates.', 'Cross-Branch', 100, 1500, 5, '{"ex_final_verdict", "ex_blade_of_annihilation", "ex_domain_of_despair"}', '{"x": -1039, "y": -600}', '{"damage": "30d12", "soul_destroy": true, "unrevivable": true, "global_fear": true, "duration": "5 turns"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c1a90488-a086-4205-b62f-192bd69f774b', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_fatal_strike', 'Ölümcül Vuruş', 'Fatal Strike', '3d8 fiziksel hasar verir. Eğer hedefin canı %50''nin altındaysa ekstra 2d8 hasar verir.', 'Deals 3d8 physical damage. If the target is below 50% HP, deals an additional 2d8 damage.', 'Perfect Execution', 2, 60, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "3d8", "bonus_damage": "2d8", "range": "2m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('619428c2-3ad4-40e3-b295-5a1d34726ddc', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_precise_cut', 'İsabetli Kesik', 'Precise Cut', 'Hedefin zırhının %30''unu yok sayarak 2d10 fiziksel hasar verir.', 'Deals 2d10 physical damage, ignoring 30% of the target''s armor.', 'Perfect Execution', 5, 80, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "2d10", "armor_penetration": "30%", "range": "2m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ed05336-e174-477d-9884-fc963094780a', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_ruthless_advance', 'Acımasız İlerleme', 'Ruthless Advance', '10m''ye kadar atılır ve 3d6 fiziksel hasar veren bir vuruş yapar.', 'Dash up to 10m and strike for 3d6 physical damage.', 'Perfect Execution', 9, 100, 1, '{"ea_fatal_strike"}', '{"x": 606, "y": -349}', '{"damage": "3d6", "range": "10m"}', '🏃‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('08796a6d-14f5-4783-946a-27ba588e2da3', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_guillotine_blade', 'Giyotin Kılıcı', 'Guillotine Blade', '5d10 fiziksel hasar veren ağır bir tepeden vuruş. Canı %50''nin altındaki patron olmayan düşmanları %15 ihtimalle anında infaz eder.', 'Heavy overhead strike dealing 5d10 physical damage. Has a 15% chance to instantly execute non-boss enemies below 50% HP.', 'Perfect Execution', 22, 200, 2, '{"ea_precise_cut"}', '{"x": 822, "y": -474}', '{"damage": "5d10", "execute_chance": "15%", "range": "2m"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3cfcaab5-e3ef-424a-a1ac-69154f26aacd', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_flawless_technique', 'Kusursuz Teknik', 'Flawless Technique', 'Pasif: Temel infaz eşiğiniz %5 artar (%50 hedefine ulaşmayı kolaylaştırır).', 'Passive: Your base execute threshold is increased by 5% (making it easier to reach the 50% target).', 'Perfect Execution', 26, 220, 2, '{}', '{"x": 1039, "y": -599}', '{"execute_threshold_increase": "5%"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2bded03f-4eb8-4da7-b44e-08e4d4627e09', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_sever_tendon', 'Tendon Koparan', 'Sever Tendon', '3d8 hasar verir, hedefi 3 saniyeliğine %50 yavaşlatır ve 5 saniye boyunca saniyede 2d4 kanama hasarı almasını sağlar.', 'Deals 3d8 damage, slows the target by 50% for 3 seconds, and causes them to bleed for 2d4 damage per second for 5 seconds.', 'Perfect Execution', 32, 250, 2, '{"ea_ruthless_advance"}', '{"x": 1255, "y": -724}', '{"damage": "3d8", "bleed_damage": "2d4/sec", "duration": "5s", "slow": "50%", "range": "2m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('992e6279-111a-4af3-aee7-bb72637776b8', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_decapitate', 'Baş Kesme', 'Decapitate', '8d10 fiziksel hasar verir. Eğer hedefin canı %40''ın altındaysa bu saldırı otomatik olarak kritik vurur.', 'Deals 8d10 physical damage. If the target is below 40% HP, this attack is an automatic critical hit.', 'Perfect Execution', 42, 400, 3, '{"ea_guillotine_blade"}', '{"x": 1472, "y": -849}', '{"damage": "8d10", "auto_crit_threshold": "40%", "range": "2m"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('36cbffd5-dc46-4353-ab77-baabc6cbd171', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_vital_puncture', 'Hayati Delik', 'Vital Puncture', '4d10 hasar verir ve hedefin maksimum canını 1 dakikalığına %15 azaltır.', 'Deals 4d10 damage and reduces the target''s maximum HP by 15% for 1 minute.', 'Perfect Execution', 46, 420, 3, '{"ea_flawless_technique"}', '{"x": 1688, "y": -974}', '{"damage": "4d10", "max_hp_reduction": "15%", "duration": "60s", "range": "2m"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c3b956d2-3226-44e5-9420-06d38feb0bbc', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_merciless_assault', 'Merhametsiz Saldırı', 'Merciless Assault', 'Her vuruşu 2d8 fiziksel hasar veren 4 vuruşluk bir kombo. Son vuruş 1.5 saniyeliğine sersemletir.', 'A 4-hit combo, each hit dealing 2d8 physical damage. The final hit stuns for 1.5 seconds.', 'Perfect Execution', 52, 450, 3, '{"ea_sever_tendon"}', '{"x": 1905, "y": -1099}', '{"damage": "4x 2d8", "stun_duration": "1.5s", "range": "2m"}', '🤺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c5e152a4-8ecb-489e-98fd-02b332977be2', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_absolute_lethality', 'Mutlak Ölümcüllük', 'Absolute Lethality', 'Pasif: Canı %50''nin altındaki hedeflere karşı kritik vuruş hasarınız %50 artar.', 'Passive: Your critical hit damage is increased by 50% against targets below 50% HP.', 'Perfect Execution', 62, 700, 4, '{"ea_decapitate"}', '{"x": 2121, "y": -1224}', '{"crit_damage_bonus": "50%", "condition": "HP < 50%"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('edef82ca-0d83-48f2-b7c4-59cb736cd053', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_swift_demise', 'Ani Ecel', 'Swift Demise', '6d10 hasar veren hızlı bir vuruş. Bu saldırı hedefi öldürürse bekleme süresi sıfırlanır ve maksimum canınızın %10''unu iyileştirirsiniz.', 'A quick strike dealing 6d10 damage. If this attack kills the target, its cooldown is reset and you regain 10% of your max HP.', 'Perfect Execution', 66, 750, 4, '{"ea_vital_puncture"}', '{"x": 2338, "y": -1349}', '{"damage": "6d10", "heal_on_kill": "10%", "range": "2m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30673630-aa27-43e4-b6ea-ef8cfca4d6a9', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_cull_the_weak', 'Zayıfları Ayıkla', 'Cull the Weak', '5d8 fiziksel hasar ve hedefin eksik olan her %1 canı için %1 ekstra hasar verir.', 'Deals 5d8 physical damage plus 1% extra damage for every 1% HP the target is missing.', 'Perfect Execution', 72, 800, 4, '{"ea_merciless_assault"}', '{"x": 2554, "y": -1474}', '{"damage": "5d8", "scaling": "+1% per 1% missing HP", "range": "2m"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6eaf08a0-99ca-443e-915a-6c0ca210a96a', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_perfect_execution', 'Kusursuz İnfaz', 'Perfect Execution', 'Ulti. 15d10 gerçek hasar veren kusursuz bir vuruş. Eğer hedefin canı %50''nin altındaysa anında infaz edilir (patronlar anında ölmek yerine iki kat hasar alır).', 'Ultimate. A flawless strike that deals 15d10 true damage. If the target is below 50% HP, they are instantly executed (bosses take double damage instead).', 'Perfect Execution', 85, 1200, 5, '{"ea_absolute_lethality", "ea_swift_demise"}', '{"x": 2771, "y": -1599}', '{"damage": "15d10 true", "execute_threshold": "50%", "range": "2m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e4cead0d-a761-4a0b-b1a7-fffafcb1f3f4', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_mark_of_doom', 'Kıyamet İşareti', 'Mark of Doom', 'Bir hedefi 10 saniyeliğine işaretler. İşaretli hedefe %15 daha fazla hasar verirsiniz.', 'Marks a target for 10 seconds. You deal 15% more damage to the marked target.', 'Death Sentence', 3, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage_bonus": "15%", "duration": "10s", "range": "15m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c334f7b0-cd8b-48ea-b8ab-eabc404be79d', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_condemn', 'Mahkum Et', 'Condemn', '3d6 büyü hasarı verir ve hedefin aldığı iyileştirmeyi 6 saniyeliğine %50 azaltır.', 'Deals 3d6 magical damage and reduces the target''s healing received by 50% for 6 seconds.', 'Death Sentence', 6, 80, 1, '{}', '{"x": 289, "y": 344}', '{"damage": "3d6", "anti_heal": "50%", "duration": "6s", "range": "10m"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71834192-f96a-4ab2-9180-fc2da4795b1e', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_chilling_verdict', 'Dondurucu Karar', 'Chilling Verdict', '2d8 soğuk hasarı verir, hedefi %40 yavaşlatır ve fiziksel hasar çıktısını 5 saniyeliğine %20 azaltır.', 'Deals 2d8 cold damage, slowing the target by 40% and reducing their physical damage output by 20% for 5 seconds.', 'Death Sentence', 10, 100, 1, '{"ea_mark_of_doom"}', '{"x": 449, "y": 536}', '{"damage": "2d8", "slow": "40%", "damage_reduction": "20%", "duration": "5s", "range": "10m"}', '❄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a62f2b17-edc9-41ab-9629-053eb37e0146', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_inescapable_fate', 'Kaçınılmaz Kader', 'Inescapable Fate', 'İşaretli bir hedefi 15m mesafeden size doğru çeker ve 3d8 fiziksel hasar verir.', 'Pulls a marked target towards you from up to 15m away and deals 3d8 physical damage.', 'Death Sentence', 23, 200, 2, '{"ea_mark_of_doom"}', '{"x": 610, "y": 727}', '{"damage": "3d8", "pull": "15m", "range": "15m"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d48b8d92-6274-434b-b0f0-2747968388c4', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_gavel_strike', 'Tokmak Vuruşu', 'Gavel Strike', 'Hedefe 4d8 fiziksel hasar veren bir vuruş yapar. Eğer hedef işaretliyse 2 saniyeliğine sersemler.', 'Strikes the target for 4d8 physical damage. If the target is marked, they are stunned for 2 seconds.', 'Death Sentence', 28, 230, 2, '{"ea_condemn"}', '{"x": 771, "y": 919}', '{"damage": "4d8", "stun_duration": "2s", "range": "2m"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('47060b58-e7e5-4850-9a15-cc4c83db3c88', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_warrant_of_blood', 'Kan Fermanı', 'Warrant of Blood', 'Pasif: Müttefikleriniz Kıyamet İşareti etkisindeki hedeflere %10 daha fazla hasar verir.', 'Passive: Allies deal 10% more damage to targets affected by your Mark of Doom.', 'Death Sentence', 34, 260, 2, '{"ea_chilling_verdict"}', '{"x": 932, "y": 1110}', '{"ally_damage_bonus": "10%"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('feece126-279d-474c-af08-219359867d6f', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_final_judgement', 'Nihai Yargı', 'Final Judgement', 'Hedefteki işareti tüketerek etrafındaki 5m yarıçapında 6d10 güç hasarı verecek şekilde patlamasına neden olur.', 'Consumes the mark on a target, causing it to explode for 6d10 force damage in a 5m radius around them.', 'Death Sentence', 43, 400, 3, '{"ea_inescapable_fate"}', '{"x": 1092, "y": 1302}', '{"damage": "6d10", "radius": "5m", "range": "15m"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9bcae0af-5ee7-451b-bb0a-5195d4463b41', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_chain_of_guilt', 'Suçluluk Zinciri', 'Chain of Guilt', 'İşaretli hedefi 5 saniyeliğine bulunduğu konuma bağlar. Bu noktadan 5m''den fazla uzaklaşırlarsa 5d10 büyü hasarı alırlar ve geri çekilirler.', 'Binds the marked target to their current location for 5 seconds. If they move further than 5m from that point, they take 5d10 magical damage and are pulled back.', 'Death Sentence', 48, 430, 3, '{"ea_gavel_strike"}', '{"x": 1253, "y": 1493}', '{"damage": "5d10", "leash_radius": "5m", "duration": "5s", "range": "15m"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c88065d3-e456-48c6-888f-a1ba0568ef77', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_silencing_verdict', 'Susturucu Karar', 'Silencing Verdict', '4d8 hasar verir ve işaretli hedefi 3 saniyeliğine susturur.', 'Deals 4d8 damage and silences the marked target for 3 seconds.', 'Death Sentence', 54, 460, 3, '{"ea_warrant_of_blood"}', '{"x": 1414, "y": 1685}', '{"damage": "4d8", "silence_duration": "3s", "range": "10m"}', '🤐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c0dcb7e-8576-4a8f-a35a-ce900d5cbb00', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_doom_approaches', 'Kıyamet Yaklaşıyor', 'Doom Approaches', 'Kıyamet İşareti Geliştirmesi: 5 saniye sonra işaret patlar ve hedefin işaretliyken aldığı hasarın %20''sini bonus gerçek hasar olarak verir.', 'Upgrades Mark of Doom: After 5 seconds, the mark detonates, dealing 20% of the damage the target took while marked as bonus true damage.', 'Death Sentence', 63, 700, 4, '{"ea_final_judgement"}', '{"x": 1574, "y": 1876}', '{"true_damage_detonation": "20% of damage taken"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61e33ee4-df9e-4559-bed8-62ecc6cf599f', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_aura_of_judgement', 'Yargı Aurası', 'Aura of Judgement', '10m içindeki tüm düşmanlara otomatik olarak Kıyamet İşareti uygulayan bir aura yayar. 15 saniye sürer.', 'Emits an aura that automatically applies Mark of Doom to all enemies within 10m. Lasts 15 seconds.', 'Death Sentence', 68, 750, 4, '{"ea_chain_of_guilt"}', '{"x": 1735, "y": 2068}', '{"radius": "10m", "duration": "15s"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0fa7cebc-5376-4ecc-a244-1281c71c656f', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_no_escape', 'Kaçış Yok', 'No Escape', '30m içindeki herhangi bir işaretli hedefe anında ışınlanarak 6d8 fiziksel hasar verir ve onları 2 saniyeliğine yere sabitler.', 'Teleport instantly to any marked target within 30m and deal 6d8 physical damage, rooting them for 2 seconds.', 'Death Sentence', 74, 800, 4, '{"ea_silencing_verdict"}', '{"x": 1896, "y": 2259}', '{"damage": "6d8", "root_duration": "2s", "range": "30m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a5ad5fc-1fe6-4cf6-adfc-2f35c2b0267f', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_death_sentence', 'Ölüm Cezası', 'Death Sentence', 'Ulti. Bir hedefe 10 saniyeliğine kaçınılmaz bir ölüm cezası verir. Bu süre içinde canları %50''nin altına düşerse, tüm bağışıklıkları ve kalkanları hiçe sayarak anında katledilirler.', 'Ultimate. Places an inescapable sentence on a target for 10 seconds. If their HP drops below 50% during this time, they are instantly slain, bypassing all immunities and shields.', 'Death Sentence', 86, 1200, 5, '{"ea_doom_approaches", "ea_no_escape"}', '{"x": 2056, "y": 2451}', '{"execute_threshold": "50%", "duration": "10s", "bypasses_immunities": true, "range": "15m"}', '🪦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2fe5d09c-a462-4b9f-88fd-d8acc8040f74', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_bloody_reap', 'Kanlı Hasat', 'Bloody Reap', '3m''lik ön konideki tüm düşmanlara 3d6 fiziksel hasar veren geniş bir savurma.', 'A wide sweep dealing 3d6 physical damage to all enemies in a 3m frontal cone.', 'Grim Harvest', 4, 60, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "3d6", "cone": "3m"}', '🌾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dfc5cfa2-1a1c-47a4-adf2-ad6be826d38b', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_taste_of_death', 'Ölümün Tadı', 'Taste of Death', 'Pasif: Bir düşmanı her öldürdüğünüzde maksimum canınızın %5''i kadar iyileşirsiniz.', 'Passive: Whenever you kill an enemy, you heal for 5% of your maximum HP.', 'Grim Harvest', 7, 80, 1, '{}', '{"x": -289, "y": 344}', '{"heal_on_kill": "5%"}', '🍷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e007505d-5470-4775-95c9-3fc5e6080e7e', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_fear_the_reaper', 'Azrail''den Kork', 'Fear the Reaper', 'Dehşet verici bir varlık açığa çıkarın. 5m içindeki düşmanlar İrade zarı atmalıdır, başarısız olanlar 3 saniyeliğine korkutulur.', 'Unleash a terrifying presence. Enemies within 5m must make a Will save or be frightened for 3 seconds.', 'Grim Harvest', 11, 110, 1, '{"ea_bloody_reap"}', '{"x": -449, "y": 536}', '{"fear_duration": "3s", "radius": "5m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f7b8343-a1a5-4b9a-9d3a-e950472b307e', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_whirlwind_of_carnage', 'Katliam Kasırgası', 'Whirlwind of Carnage', 'Silahınızla dönerek 4m içindeki tüm düşmanlara 4d6 fiziksel hasar verin. Dönerken hareket edebilirsiniz. Süre: 3 saniye.', 'Spin with your weapon, dealing 4d6 physical damage to all enemies within 4m. Can move while spinning. Duration: 3 seconds.', 'Grim Harvest', 24, 200, 2, '{"ea_bloody_reap"}', '{"x": -610, "y": 727}', '{"damage": "4d6", "radius": "4m", "duration": "3s"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('987cca1e-9cd2-4ebc-9491-620fdf11ff74', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_soul_feast', 'Ruh Ziyafeti', 'Soul Feast', 'Pasif: Bir düşmanı öldürmek size bir Ruh Ziyafeti yükü verir ve maksimum canınızı yük başına %1 artırır (maksimum 20 yük). Çatışma dışında sıfırlanır.', 'Passive: Killing an enemy grants you a stack of Soul Feast, increasing your max HP by 1% per stack (max 20 stacks). Resets out of combat.', 'Grim Harvest', 29, 230, 2, '{"ea_taste_of_death"}', '{"x": -771, "y": 919}', '{"max_hp_bonus_per_kill": "1%", "max_stacks": 20}', '🍽️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ed3418b-2eb5-4606-b078-40eaa9877372', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_dreadful_presence', 'Dehşet Verici Varlık', 'Dreadful Presence', 'Pasif: Bir düşmanı infaz ettiğinizde, 8m içindeki tüm düşmanların %25 ihtimalle 2 saniyeliğine korkma şansı vardır.', 'Passive: Whenever you execute an enemy, all enemies within 8m have a 25% chance to be frightened for 2 seconds.', 'Grim Harvest', 35, 260, 2, '{"ea_fear_the_reaper"}', '{"x": -932, "y": 1110}', '{"fear_chance_on_execute": "25%", "fear_duration": "2s", "radius": "8m"}', '😱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('363d4d1a-e930-43de-a6e0-b66a23e71000', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_harvesting_scythe', 'Hasat Tırpanı', 'Harvesting Scythe', 'Vurulan tüm düşmanlara 5d8 fiziksel hasar veren ve 4 saniye boyunca saniyede 3d4 kanama uygulayan devasa bir 180 derece savurma.', 'A massive 180-degree sweep dealing 5d8 physical damage and applying a bleed for 3d4 damage per second for 4 seconds to all hit enemies.', 'Grim Harvest', 44, 400, 3, '{"ea_whirlwind_of_carnage"}', '{"x": -1092, "y": 1302}', '{"damage": "5d8", "bleed_damage": "3d4/sec", "duration": "4s", "arc": "180_deg", "range": "5m"}', '⛏️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87674397-3acb-41a8-8400-406f89bfb9cf', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_blood_frenzy', 'Kan Cinneti', 'Blood Frenzy', 'Bir düşmanı %50 canın altına düşürdüğünüzde, 5 saniyeliğine %30 saldırı ve hareket hızı kazanırsınız.', 'Upon dropping an enemy below 50% HP, gain 30% increased attack speed and movement speed for 5 seconds.', 'Grim Harvest', 49, 430, 3, '{"ea_soul_feast"}', '{"x": -1253, "y": 1493}', '{"attack_speed": "30%", "movement_speed": "30%", "duration": "5s"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cfee8a67-3e86-4924-80b8-4de5b3b4e0f5', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_corpse_explosion', 'Ceset Patlaması', 'Corpse Explosion', '15m içindeki bir cesedi hedef alın. Ceset patlayarak etrafındaki 5m içindeki tüm düşmanlara 6d8 fiziksel hasar verir.', 'Target a corpse within 15m. It explodes, dealing 6d8 physical damage to all enemies within 5m of the corpse.', 'Grim Harvest', 55, 460, 3, '{"ea_dreadful_presence"}', '{"x": -1414, "y": 1685}', '{"damage": "6d8", "radius": "5m", "range": "15m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bceeb205-3d23-4622-b50a-e145b33ee373', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_massacre', 'Kıyım', 'Massacre', 'Bir alana zıplayın ve her biri 6m yarıçapında 4d8 fiziksel hasar veren 3 hızlı alan saldırısı yapın.', 'Leap to an area and unleash 3 rapid AoE strikes, each dealing 4d8 physical damage in a 6m radius.', 'Grim Harvest', 64, 700, 4, '{"ea_harvesting_scythe"}', '{"x": -1574, "y": 1876}', '{"damage": "3x 4d8", "radius": "6m", "range": "10m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64771c60-ea47-4eb2-8d82-ae102144cf1c', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_reapers_shroud', 'Azrail''in Kefeni', 'Reaper''s Shroud', 'Bir düşmanı infaz ettikten sonra, maksimum canınızın %30''una eşit bir kalkan kazanırsınız ve 4 saniyeliğine kitle kontrol etkilerine bağışıklık kazanırsınız.', 'After executing an enemy, you gain a shield equal to 30% of your maximum HP and become immune to crowd control for 4 seconds.', 'Grim Harvest', 69, 750, 4, '{"ea_blood_frenzy"}', '{"x": -1735, "y": 2068}', '{"shield": "30% max hp", "cc_immunity": "4s"}', '🧥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('274b04a0-f6d1-4276-b316-080d5a5633f1', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_echoes_of_slaughter', 'Katliam Yankıları', 'Echoes of Slaughter', 'Pasif: Bir düşman öldüğünde, 6m içindeki diğer tüm düşmanlar katliamın dehşetinden 4d8 psişik hasar alır.', 'Passive: When an enemy dies, all other enemies within 6m take 4d8 psychic damage from the sheer terror of the slaughter.', 'Grim Harvest', 75, 800, 4, '{"ea_corpse_explosion"}', '{"x": -1896, "y": 2259}', '{"damage": "4d8 psychic", "radius": "6m"}', '🔊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5cef617-67f6-4b44-8c80-7aa305e1c63a', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_grim_harvest', 'Acımasız Hasat', 'Grim Harvest', 'Ulti. 10m yarıçapında bir ölüm dalgası serbest bırakır. 10d10 fiziksel hasar verir. Canı %40''ın altındaki tüm düşmanlar anında infaz edilir. Verilen toplam hasarın %50''si kadar iyileşirsiniz.', 'Ultimate. Unleash a wave of death in a 10m radius. Deals 10d10 physical damage. Any enemy below 40% HP is instantly executed. You heal for 50% of the total damage dealt.', 'Grim Harvest', 87, 1200, 5, '{"ea_massacre", "ea_reapers_shroud"}', '{"x": -2056, "y": 2451}', '{"damage": "10d10", "execute_threshold": "40%", "heal_percentage": "50%", "radius": "10m"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41e7e4de-737a-45be-80dc-f4cabd6d52aa', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_marked_for_harvest', 'Hasat İçin İşaretlendi', 'Marked for Harvest', '4m''lik konide 3d8 hasar veren yarma saldırısı. Vurulan tüm düşmanlara Kıyamet İşareti uygulanır.', 'A cleaving attack that deals 3d8 damage in a 4m cone. All enemies hit are afflicted with Mark of Doom.', 'Cross-Branch', 30, 280, 2, '{"Death Sentence", "Grim Harvest"}', '{"x": -173, "y": -100}', '{"damage": "3d8", "cone": "4m", "applies_mark": true}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5f3a75db-31a6-4084-86d4-0f289ffbd4f0', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_flawless_condemnation', 'Kusursuz Mahkumiyet', 'Flawless Condemnation', '5d8 hasar veren isabetli bir vuruş. Eğer bu saldırı hedefi öldürmezse, otomatik olarak İşaretlenirler ve 2 saniyeliğine susturulurlar.', 'A precise strike dealing 5d8 damage. If this does not kill the target, they are automatically Marked and silenced for 2 seconds.', 'Cross-Branch', 33, 290, 2, '{"Perfect Execution", "Death Sentence"}', '{"x": -389, "y": -225}', '{"damage": "5d8", "silence_duration": "2s", "range": "2m"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d50cc83-7be4-4839-92ff-39aff2ddb96a', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_reapers_precision', 'Azrail''in İsabeti', 'Reaper''s Precision', '15m''lik bir çizgide deşip geçen ve 6d8 hasar veren hayalet bir bıçak fırlatır. Yolundaki en düşük can yüzdesine sahip hedefe %50 daha fazla hasar verir.', 'Throws a phantom blade that pierces in a 15m line, dealing 6d8 damage. It deals 50% more damage to the target with the lowest HP percentage in its path.', 'Cross-Branch', 50, 480, 3, '{"Perfect Execution", "Grim Harvest"}', '{"x": -606, "y": -350}', '{"damage": "6d8", "bonus_damage": "50%", "line": "15m"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('951683a6-ec83-4b9d-8ab6-b50b5642285b', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_inevitable_cull', 'Kaçınılmaz Ayıklama', 'Inevitable Cull', 'Kaçırılamayan veya atlatılamayan hedefli bir vuruş. 7d8 gerçek hasar verir. Eğer hedef işaretliyse, bu saldırı için hedefe karşı infaz eşiği %50''ye çıkar.', 'A targeted strike that cannot miss or be dodged. Deals 7d8 true damage. If the target is marked, the execute threshold against them is increased to 50% for this attack.', 'Cross-Branch', 53, 490, 3, '{"Perfect Execution", "Death Sentence"}', '{"x": -822, "y": -475}', '{"damage": "7d8 true", "execute_threshold_boost": "50%", "range": "3m"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c44a60af-64b1-4de0-b179-ef5fc61d2bf6', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_bloody_verdict', 'Kanlı Karar', 'Bloody Verdict', 'Hedefteki işareti patlatarak 5d10 hasar verir ve verilen hasarın %100''ü kadar kendinizi iyileştirirsiniz.', 'Detonate the mark on a target, dealing 5d10 damage and healing yourself for 100% of the damage dealt.', 'Cross-Branch', 58, 500, 3, '{"Death Sentence", "Grim Harvest"}', '{"x": -1039, "y": -600}', '{"damage": "5d10", "heal_percentage": "100%", "range": "15m"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b7e9c66d-969f-45c5-8366-e71388f28121', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_slaughter_the_condemned', 'Mahkumları Katlet', 'Slaughter the Condemned', '30m içindeki tüm düşmanlardan Kıyamet İşaretini tüketin. Tüketilen her işaret için, o düşmanın etrafındaki 5m yarıçapta 8d8 hasar verin.', 'Consume Mark of Doom from all enemies within 30m. For each mark consumed, deal 8d8 damage in a 5m radius around that enemy.', 'Cross-Branch', 76, 850, 4, '{"Death Sentence", "Grim Harvest"}', '{"x": -1255, "y": -725}', '{"damage": "8d8 per mark", "radius": "5m", "range": "30m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('966e9863-e28b-401f-a0ea-c3e87181ed89', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_flawless_massacre', 'Kusursuz Kıyım', 'Flawless Massacre', 'Pasif: 5 saniye içinde 3 düşman öldürürseniz, ulti olmayan tüm bekleme süreleriniz anında sıfırlanır.', 'Passive: If you kill 3 enemies within 5 seconds, all your non-ultimate cooldowns are instantly reset.', 'Cross-Branch', 78, 880, 4, '{"Perfect Execution", "Grim Harvest"}', '{"x": -1472, "y": -850}', '{"cooldown_reset": true, "condition": "3 kills in 5s"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ef20920c-ecaa-4168-af3c-eb4a356e8595', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_judgment_blade', 'Yargı Kılıcı', 'Judgment Blade', 'Silahınızı 10 saniyeliğine güçlendirin. Saldırılarınız işaretli hedeflere fazladan 3d10 gerçek hasar verir.', 'Enhance your weapon for 10 seconds. Your attacks deal an additional 3d10 true damage to marked targets.', 'Cross-Branch', 79, 900, 4, '{"Perfect Execution", "Death Sentence"}', '{"x": -1688, "y": -975}', '{"bonus_true_damage": "3d10", "duration": "10s"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('82ece92c-3f1d-4b21-9f77-799f5f883092', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_reapers_judgment', 'Azrail''in Yargısı', 'Reaper''s Judgment', 'Pasif: Bir düşmanı infaz etmek, 10 saniyeliğine %10 hasar artışı sağlar (3 defaya kadar birikir) ve 10m içindeki tüm düşmanları işaretleyen bir titreşim yayar.', 'Passive: Executing an enemy grants a 10% damage buff for 10 seconds (stacks up to 3 times) and unleashes a pulse that marks all enemies within 10m.', 'Cross-Branch', 88, 1300, 5, '{"Perfect Execution", "Death Sentence", "Grim Harvest"}', '{"x": -1905, "y": -1100}', '{"damage_buff": "10% per stack", "max_stacks": 3, "duration": "10s", "mark_radius": "10m"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b6b7b7e-948f-4ced-95bb-37730cca04de', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_absolute_carnage', 'Mutlak Katliam', 'Absolute Carnage', '12 saniyeliğine bir katliam durumuna girin. Tüm tek hedefli saldırılarınız 5m''lik yarma saldırısına dönüşür ve canı %50''nin altındaki düşmanlara %20 artırılmış hasar verir.', 'Enter a state of carnage for 12 seconds. All your single-target attacks become 5m cleaves and deal 20% increased damage to enemies below 50% HP.', 'Cross-Branch', 89, 1400, 5, '{"Perfect Execution", "Grim Harvest"}', '{"x": -2121, "y": -1225}', '{"cleave_radius": "5m", "bonus_damage": "20%", "duration": "12s"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('365ace71-3da4-45f6-b4d3-d41fa3ede15d', '320777c7-178e-49ca-9e6a-82fbfa9e064a', 'ea_the_final_execution', 'Son İnfaz', 'The Final Execution', 'Büyük Ulti. Ölümün vücut bulmuş hali olursunuz. 20m yarıçapındaki canı %50''nin altında olan tüm düşmanlar anında infaz edilir. Canı %50''nin üzerinde olan tüm düşmanların canı anında maksimum canlarının %50''sine düşürülür ve 10d10 nekrotik hasar alırlar.', 'Grand Ultimate. You become the embodiment of death. In a 20m radius, all enemies below 50% HP are instantly executed. All enemies above 50% HP are immediately reduced to 50% of their maximum HP and take 10d10 necrotic damage.', 'Cross-Branch', 95, 1500, 5, '{"Perfect Execution", "Death Sentence", "Grim Harvest"}', '{"x": -2338, "y": -1350}', '{"execute_threshold": "50%", "radius": "20m", "hp_reduction": "To 50%", "damage": "10d10 necrotic"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b8de2bd6-763f-4c5f-a959-16abd84a0633', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_card_dart', 'Kart Dartı', 'Card Dart', '15m menzile sahip, 1d4 kesici hasar veren keskin bir oyun kartı fırlatır.', 'Throws a sharp playing card that deals 1d4 slashing damage with a 15m range.', 'Cards', 1, 100, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d4", "range": "15m"}', '🃏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35e24a20-0a2b-4b5d-bfcb-d7b6eeb8c42b', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_shuffle', 'Karıştır', 'Shuffle', 'Fiziksel konumunuzu anında karıştırarak sizi rastgele güvenli bir yöne 5m''ye kadar ışınlar.', 'Instantly shuffles your physical location, teleporting you up to 5m in a random safe direction.', 'Cards', 5, 100, 1, '{}', '{"x": 389, "y": -224}', '{"range": "5m", "mobility": "teleport"}', '🔀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('abc062ef-6e56-4b4c-8647-1a923ddf52ad', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_draw_heart', 'Çekiliş: Kupa', 'Draw: Heart', 'Büyülü bir Kupa kartı çeker, 10m içindeki size veya bir müttefike 1d6+2 Can yeniler.', 'Draws a magical Heart card, restoring 1d6+2 HP to you or an ally within 10m.', 'Cards', 10, 100, 1, '{}', '{"x": 606, "y": -349}', '{"healing": "1d6+2", "range": "10m"}', '♥️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('858cada7-c560-4a8d-b715-7e6aff208fe8', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_draw_spade', 'Çekiliş: Maça', 'Draw: Spade', '15m''ye kadar uzaktan 2d6 delici hasar vuran jilet gibi keskin bir Maça kartı çeker.', 'Draws a razor-sharp Spade card that strikes for 2d6 piercing damage up to 15m away.', 'Cards', 21, 250, 2, '{"gb_card_dart"}', '{"x": 822, "y": -474}', '{"damage": "2d6", "range": "15m"}', '♠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7426b2cd-fec7-4c8b-b6d7-322140acfeb3', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_dealers_choice', 'Dağıtıcının Seçimi', 'Dealer''s Choice', 'Rastgele seçilerek bir sonraki saldırı zarına veya büyü hasarına 1d8 bonus sağlar.', 'Grants a 1d8 bonus to your next attack roll or spell damage, chosen randomly.', 'Cards', 25, 250, 2, '{"gb_shuffle"}', '{"x": 1039, "y": -599}', '{"buff": "+1d8", "duration": "1 attack"}', '🎩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e12d1473-44f7-45c9-bf88-d01659e2b8a9', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_exploding_deck', 'Patlayan Deste', 'Exploding Deck', '3m yarıçapında patlayan ve her biri 1d6 ateş hasarı veren üç uçucu kart fırlatır.', 'Throws three volatile cards that explode in a 3m radius, each dealing 1d6 fire damage.', 'Cards', 35, 250, 2, '{"gb_draw_spade"}', '{"x": 1255, "y": -724}', '{"damage": "3x 1d6", "radius": "3m", "range": "15m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed8344ab-a9d1-454d-bf94-73d9ed961ab5', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_draw_club', 'Çekiliş: Sinek', 'Draw: Club', 'Ağır bir Sinek kartı çeker, 4d6 ezici hasar verir ve hedefi 5m geriye savurur.', 'Draws a heavy Club card, dealing 4d6 bludgeoning damage and knocking the target back 5m.', 'Cards', 41, 400, 3, '{"gb_draw_spade"}', '{"x": 1472, "y": -849}', '{"damage": "4d6", "knockback": "5m", "range": "10m"}', '♣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('614a4f3a-4843-4adf-a274-36df5287c1fb', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_illusionary_hand', 'İllüzyon El', 'Illusionary Hand', '3 tur içinde gelecek olan sonraki 2 saldırıyı mükemmel bir şekilde engelleyen hayalet yüzen kartlar çağırır.', 'Summons spectral floating cards that perfectly block the next 2 attacks within 3 turns.', 'Cards', 45, 400, 3, '{"gb_dealers_choice"}', '{"x": 1688, "y": -974}', '{"defense": "Block 2 attacks", "duration": "3 turns"}', '🖐️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('44dcdf4f-fa50-4671-9fa1-7be6b28f05d0', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_stack_deck', 'Desteyi Ayarla', 'Stack the Deck', 'Kaderi manipüle ederek sonraki 3 ''Çekiliş'' büyünüzün mümkün olan maksimum zarları vermesini garanti eder.', 'Manipulates fate so your next 3 ''Draw'' spells are guaranteed to yield their maximum possible rolls.', 'Cards', 55, 400, 3, '{"gb_exploding_deck"}', '{"x": 1905, "y": -1099}', '{"buff": "Max roll", "duration": "Next 3 Draw spells"}', '📑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('63dd8d6c-64e7-4ae9-afb4-33dc2f57c43b', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_draw_diamond', 'Çekiliş: Karo', 'Draw: Diamond', '20m''lik bir hatta parlak bir Karo ışını ateşler ve vurduğu herkese 6d6 parlak delici hasar verir.', 'Fires a brilliant Diamond beam in a 20m line, dealing 6d6 radiant piercing damage to all hit.', 'Cards', 61, 750, 4, '{"gb_draw_club"}', '{"x": 2121, "y": -1224}', '{"damage": "6d6", "range": "20m line"}', '♦️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f4d8d64b-7873-4579-9128-1fae5fffffec', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_royal_flush', 'Floş Royal', 'Royal Flush', 'Bir hedefe en yüksek beş kartı serbest bırakır. Her biri zırhın %50''sini görmezden gelerek 2d6 gizem hasarı verir.', 'Unleashes the five highest cards at a target. Each deals 2d6 arcane damage, ignoring 50% of armor.', 'Cards', 75, 750, 4, '{"gb_stack_deck"}', '{"x": 2338, "y": -1349}', '{"damage": "5x 2d6", "armor_penetration": "50%", "range": "15m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('15a426b7-c52b-4325-ac29-38a7be9dcb93', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_house_of_cards', 'Ulti: İskambil Evi', 'Ultimate: House of Cards', '10m yarıçapındaki düşmanları çöken bir kart boyutu içine hapseder. 12d6 güç hasarı alırlar ve 2 tur sersemlerler.', 'Traps enemies in a 10m radius within a collapsing card dimension. They take 12d6 force damage and are stunned for 2 turns.', 'Cards', 90, 1200, 5, '{"gb_draw_diamond", "gb_royal_flush"}', '{"x": 2554, "y": -1474}', '{"damage": "12d6", "radius": "10m", "status": "Stun", "duration": "2 turns"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9aada1f1-1072-4f1b-a47d-b350c5a56a69', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_roll_bones', 'Zar At', 'Roll the Bones', 'Büyülü bir 1d6 atar. Çiftler sizi 1d6 Can iyileştirir, tekler 10m içindeki bir hedefe 1d6 güç hasarı verir.', 'Rolls a magical 1d6. Evens heal you for 1d6 HP, odds deal 1d6 force damage to a target within 10m.', 'Dice', 1, 100, 1, '{}', '{"x": 128, "y": 153}', '{"healing": "1d6 (Even)", "damage": "1d6 (Odd)", "range": "10m"}', '🎲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('013737cb-4350-422f-8d6a-7fc4d54d09d0', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_loaded_dice', 'Hileli Zar', 'Loaded Dice', 'Olasılığı eğerek bir sonraki saldırınızda veya kurtarma zarınızda size avantaj sağlar.', 'Tilts probability, granting you advantage on your next attack or saving throw.', 'Dice', 5, 100, 1, '{}', '{"x": 289, "y": 344}', '{"buff": "Advantage", "duration": "Next roll"}', '🎱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f18ef281-2dfc-4285-b330-e0071f8136a6', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_snake_eyes', 'Hepyek', 'Snake Eyes', 'İki tane 1 atmak, 10m''ye kadar uzaktaki bir hedefe 2d4 zehir hasarı veren ikiz zehirli yılanları ortaya çıkarır.', 'Rolling two 1s manifests twin venomous snakes that strike a target up to 10m away for 2d4 poison damage.', 'Dice', 10, 100, 1, '{}', '{"x": 449, "y": 536}', '{"damage": "2d4", "range": "10m"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d74abd66-a483-4857-8bee-8bbe06d2fbd1', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_lucky_sevens', 'Şanslı Yediler', 'Lucky Sevens', '15m yarıçapındaki en fazla 7 hedefe tam olarak 7 gerçek hasar verir.', 'Deals exactly 7 true damage to up to 7 targets within a 15m radius.', 'Dice', 21, 250, 2, '{"gb_roll_bones"}', '{"x": 610, "y": 727}', '{"damage": "7 true", "targets": 7, "radius": "15m"}', '🎰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c9e32f7-b669-4ba4-a6a0-17a75097353b', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_weighted_roll', 'Ağırlıklı Zar', 'Weighted Roll', 'Bir hedefin üzerine inanılmaz derecede ağır bir hayalet zar düşürür, onları 1d4 tur boyunca sabitler ve 2d6 hasar verir.', 'Drops an incredibly heavy phantom die on a target, rooting them for 1d4 turns and dealing 2d6 damage.', 'Dice', 25, 250, 2, '{"gb_loaded_dice"}', '{"x": 771, "y": 919}', '{"damage": "2d6", "status": "Root", "duration": "1d4 turns", "range": "15m"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('05c3b066-1440-425d-b217-a088d4f3ea16', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_boxcars', 'Düşeş', 'Boxcars', '2d6 atar. Toplam kadar hasar verir, ancak eğer çift atarsanız hasar 3 ile çarpılır.', 'Rolls 2d6. Deals damage equal to the total, but if you roll doubles, the damage is multiplied by 3.', 'Dice', 35, 250, 2, '{"gb_snake_eyes"}', '{"x": 932, "y": 1110}', '{"damage": "2d6 (x3 on doubles)", "range": "15m"}', '📦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ef7992b0-b894-4363-8665-1861e0dfbf6d', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_dice_bomb', 'Zar Bombası', 'Dice Bomb', '5m''lik bir alana patlayıcı 6 yüzlü bir zar fırlatır. (1d6) x (1d6) ateş hasarına eşit alan hasarı verir.', 'Throws an explosive 6-sided die into a 5m area. Deals area damage equal to (1d6) x (1d6) fire damage.', 'Dice', 41, 400, 3, '{"gb_lucky_sevens"}', '{"x": 1092, "y": 1302}', '{"damage": "1d6 x 1d6", "radius": "5m", "range": "15m"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff6f50ad-7901-4b7c-8b0e-2f6dc47c1501', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_re_roll', 'Yeniden At', 'Re-Roll', 'Önceki tur içinde aldığınız son hasar durumunu iptal etmek için zamanı geri sarar.', 'Rewinds time to negate the last instance of damage you took within the previous round.', 'Dice', 45, 400, 3, '{"gb_weighted_roll"}', '{"x": 1253, "y": 1493}', '{"healing": "Negate last damage", "duration": "1 round memory"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8a718a4-3f53-42f8-b037-472b0c3899e7', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_critical_roll', 'Kritik Zar', 'Critical Roll', '2 tur içindeki bir sonraki saldırınızın kritik vuruş olmasını garanti etmek için maksimum Canınızın %20''sini feda eder.', 'Sacrifices 20% of your maximum HP to guarantee that your next attack within 2 turns is a critical hit.', 'Dice', 55, 400, 3, '{"gb_boxcars"}', '{"x": 1414, "y": 1685}', '{"cost": "20% Max HP", "buff": "Guaranteed Critical", "duration": "2 turns"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('763f6b20-63af-494e-a2e1-99a50b850243', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_d20_destiny', 'Kaderin 20''liği', 'D20 of Destiny', 'Bir 20''lik zar atın. 1-10: 3d6 hasar alın. 11-19: 15m içindeki bir hedefe 6d6 hasar verin. 20: 10d6 hasar verip sersemletin.', 'Roll a d20. 1-10: Take 3d6 damage. 11-19: Deal 6d6 damage to a 15m target. 20: Deal 10d6 damage and stun.', 'Dice', 61, 750, 4, '{"gb_dice_bomb"}', '{"x": 1574, "y": 1876}', '{"damage_taken": "3d6 (on 1-10)", "damage": "6d6 (on 11-19) / 10d6 (on 20)", "range": "15m"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('82906c74-cb04-42ab-81b5-1c036732206d', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_crapshoot', 'Barbut', 'Crapshoot', '2d6 atın. Eğer 7 veya 11 ise, %50 Can iyileşin. Eğer 2, 3 veya 12 ise, %30 Can hasarı alın. Aksi takdirde, 3 tur boyunca zırh kazanın.', 'Roll 2d6. If 7 or 11, heal 50% HP. If 2, 3, or 12, take 30% HP damage. Otherwise, gain armor equal to roll for 3 turns.', 'Dice', 75, 750, 4, '{"gb_critical_roll"}', '{"x": 1735, "y": 2068}', '{"healing": "50% (on 7, 11)", "damage_taken": "30% (on 2, 3, 12)", "armor": "Roll total (otherwise)", "duration": "3 turns"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1abd8dab-43d9-42a5-ab17-1dfc821aad14', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_gamblers_fallacy', 'Ulti: Kumarbazın Yanılgısı', 'Ultimate: The Gambler''s Fallacy', '3 tur boyunca, kaçırılan her saldırı veya düşük zar hasarınızı kümülatif olarak %50 artırır. Son saldırınız 15d6 gizem hasarı yayar.', 'For 3 turns, every missed attack or low roll cumulatively buffs your damage by 50%. Your final attack releases 15d6 arcane damage.', 'Dice', 90, 1200, 5, '{"gb_d20_destiny", "gb_crapshoot"}', '{"x": 1896, "y": 2259}', '{"buff": "+50% Damage per miss/low roll", "damage": "15d6", "duration": "3 turns"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4af832e-b0f2-4303-9e84-02b54a503e39', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_beginners_luck', 'Acemi Şansı', 'Beginner''s Luck', 'Masum şans, çatışmada size vuran ilk saldırıyı tamamen geçersiz kılar.', 'Innocent fortune completely nullifies the very first attack that hits you in combat.', 'Luck', 1, 100, 1, '{}', '{"x": -128, "y": 153}', '{"defense": "Nullify first attack", "duration": "Passive / Once per combat"}', '🍀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a9b0ac88-a5e3-44c5-a646-93a629d4a106', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_coin_flip', 'Yazı Tura', 'Coin Flip', 'Bir madeni para atar. Yazı +2 Zırh Sınıfı, Tura +2 Saldırı değiştiricisi sağlar. 3 tur sürer.', 'Flips a coin. Heads grants +2 AC, Tails grants +2 Attack modifier. Lasts for 3 turns.', 'Luck', 5, 100, 1, '{}', '{"x": -289, "y": 344}', '{"buff": "+2 AC or +2 Attack", "duration": "3 turns"}', '🪙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09d68a22-9b50-48f9-98e4-9f268be7a2eb', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_misfortune', 'Talihsizlik', 'Misfortune', '10m içindeki bir hedefi lanetler ve bir sonraki saldırı veya kurtarma zarında dezavantaj almalarını sağlar.', 'Curses a target within 10m, forcing them to take disadvantage on their next attack or saving throw.', 'Luck', 10, 100, 1, '{}', '{"x": -449, "y": 536}', '{"debuff": "Disadvantage", "duration": "Next roll", "range": "10m"}', '🐈‍⬛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('873bb4a9-873e-4214-b172-c911391f0002', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_fortunes_favor', 'Şansın Lütfu', 'Fortune''s Favor', '3d6 Can iyileştirir ve %50 şansla bir olumsuz durum etkisini tamamen temizler.', 'Heals for 3d6 HP with a 50% chance to also completely cleanse one negative status effect.', 'Luck', 21, 250, 2, '{"gb_beginners_luck"}', '{"x": -610, "y": 727}', '{"healing": "3d6", "cleanse": "50% chance", "range": "Self"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3779bd1b-6d1b-4d7f-9347-e4c490f79821', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_dodge_fate', 'Kaderden Kaçış', 'Dodge Fate', 'Bir saldırı tarafından hedeflendiğinde, anında 10m''ye kadar rastgele güvenli bir konuma ışınlanarak vuruştan kaçın.', 'When targeted by an attack, instantly teleport up to 10m to a random safe location, avoiding the hit.', 'Luck', 25, 250, 2, '{"gb_coin_flip"}', '{"x": -771, "y": 919}', '{"evasion": "100%", "mobility": "10m random teleport"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e6f4e87-d4cf-4865-bb7d-7ef08d8252b0', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_jinx', 'Uğursuzluk', 'Jinx', 'Bir hedefi uğursuzlaştırarak, 2 tur boyunca gelen tüm saldırılardan fazladan 1d6 hasar almalarına neden olur.', 'Jinxes a target, causing them to take an additional 1d6 damage from all incoming attacks for 2 turns.', 'Luck', 35, 250, 2, '{"gb_misfortune"}', '{"x": -932, "y": 1110}', '{"debuff": "+1d6 damage taken", "duration": "2 turns", "range": "15m"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d59064bd-9fa6-4acc-a2b4-6589e8054cc8', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_karma', 'Karma', 'Karma', '1 tur boyunca, aldığınız tüm hasarın %50''si şiddetli bir şekilde asıl saldıranlara geri yansıtılır.', 'For 1 turn, 50% of all damage you take is violently reflected back to the original attackers.', 'Luck', 41, 400, 3, '{"gb_fortunes_favor"}', '{"x": -1092, "y": 1302}', '{"reflection": "50%", "duration": "1 turn"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0240eebb-6ec0-4834-8800-52162f392c46', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_serendipity', 'Tesadüf', 'Serendipity', 'Mutlu bir kazayı tetikler ve anında size rastgele bir iksir etkisi veya küçük bir savaş güçlendirmesi verir.', 'Triggers a happy accident, instantly granting you a random potion effect or minor combat buff.', 'Luck', 45, 400, 3, '{"gb_dodge_fate"}', '{"x": -1253, "y": 1493}', '{"buff": "Random potion effect", "duration": "Instant"}', '🎁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b0fcaadf-3c15-46b2-aeb6-45bf841fdba6', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_bad_omen', 'Kötü Alâmet', 'Bad Omen', '10m''lik bir alana karanlık bir gölge düşürür. İçerideki düşmanların 3 tur boyunca saldırılarını otomatik olarak ıskalama şansı %25''tir.', 'Casts a dark shadow in a 10m area. Enemies inside have a 25% chance to automatically miss their attacks for 3 turns.', 'Luck', 55, 400, 3, '{"gb_jinx"}', '{"x": -1414, "y": 1685}', '{"debuff": "25% Miss chance", "radius": "10m", "duration": "3 turns"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c664ae57-c8e0-40e0-aef5-bef4c5815f01', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_defy_odds', 'Olasılıklara Meydan Oku', 'Defy Odds', 'Ölümcül olacak bir darbeden kurtulun, tam olarak 1 Can''a düşün ve 1 tur boyunca yenilmez olun.', 'Survive what would be a fatal blow, dropping to exactly 1 HP and becoming invincible for 1 turn.', 'Luck', 61, 750, 4, '{"gb_karma"}', '{"x": -1574, "y": 1876}', '{"survival": "Drop to 1 HP", "buff": "Invincibility", "duration": "1 turn"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95340096-b610-42e0-a1a6-a668a6012ccc', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_lady_lucks_kiss', 'Şans Meleğinin Öpücüğü', 'Lady Luck''s Kiss', 'Size ve 15m içindeki müttefiklerinize 2 tur boyunca tüm yetenek kontrollerinde ve saldırı zarlarında avantaj sağlar.', 'Grants you and allies within 15m advantage on all ability checks and attack rolls for 2 turns.', 'Luck', 75, 750, 4, '{"gb_bad_omen"}', '{"x": -1735, "y": 2068}', '{"buff": "Advantage on everything", "radius": "15m", "duration": "2 turns"}', '💋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7805352f-0b3b-45c3-bc79-a8f729a8aa3f', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_wheel_of_fortune', 'Ulti: Çarkıfelek', 'Ultimate: Wheel of Fortune', '50m yarıçapı etkileyen kozmik bir çarkı döndürür. 4 rastgele sonuca bağlı olarak müttefiklere devasa güçlendirmeler ve düşmanlara yıkıcı zayıflatmalar uygular.', 'Spins a cosmic wheel affecting a 50m radius. Applies massive buffs to allies and devastating debuffs to enemies based on 4 random outcomes.', 'Luck', 90, 1200, 5, '{"gb_defy_odds", "gb_lady_lucks_kiss"}', '{"x": -1896, "y": 2259}', '{"radius": "50m", "buff": "Random massive buff (Allies)", "debuff": "Random devastating debuff (Enemies)"}', '🎡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b01d7ab1-7353-4cce-bdb9-320e41444814', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_trick_sleeve', 'Yen Numarası', 'Trick Sleeve', 'Destenizden rastgele bir kart çekin, ancak şansı manipüle ederek faydalı bir seri olmasını garanti altına alın.', 'Draw a random card from your deck, but manipulate luck so it is guaranteed to be a beneficial suit.', 'Cross-Branch', 25, 250, 2, '{"gb_shuffle", "gb_coin_flip"}', '{"x": -173, "y": -100}', '{"buff": "Beneficial Draw", "duration": "Instant"}', '🧥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af76cfa5-f94a-4eaa-9b5d-a75ae3a7b7a4', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_crap_out', 'Dışarı At', 'Crap Out', '15m içindeki lanetli bir düşmanı bir sonraki saldırılarında veya yetenek kullanımlarında kritik başarısızlığa (1 atmaya) zorlar.', 'Forces a cursed enemy within 15m to critically fail (roll a 1) on their next attack or ability use.', 'Cross-Branch', 30, 250, 2, '{"gb_loaded_dice", "gb_misfortune"}', '{"x": -389, "y": -225}', '{"debuff": "Critical Fail", "range": "15m", "duration": "Next roll"}', '🗑️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a84c9dec-6ec1-4e79-aba0-e6ccc9b9f15a', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_poker_dice', 'Poker Zarı', 'Poker Dice', '5 zar atın ve 5 kart çekin. En iyi ele bağlı olarak 3d6 hasar artı rastgele bir temel element etkisi verir.', 'Roll 5 dice and draw 5 cards. Deals 3d6 damage plus a random elemental effect based on the best hand.', 'Cross-Branch', 35, 250, 2, '{"gb_draw_heart", "gb_roll_bones"}', '{"x": -606, "y": -350}', '{"damage": "3d6", "status": "Random elemental effect", "range": "15m"}', '🎳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd54f390-d633-44ce-814b-c0a21b06aaba', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_russian_roulette', 'Rus Ruleti', 'Russian Roulette', 'Hayalet bir tabanca ateşler. 6''da 1 şansla devasa 10d6 hasar verir, aksi takdirde sadece 1d6 hasar verir.', 'Fires a phantom revolver. 1 in 6 chance to deal a massive 10d6 damage, otherwise deals only 1d6 damage.', 'Cross-Branch', 45, 400, 3, '{"gb_snake_eyes", "gb_jinx"}', '{"x": -822, "y": -475}', '{"damage": "10d6 (1/6 chance) or 1d6", "range": "15m"}', '🔫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81ead8a8-9774-4a32-95ae-f6a384e33808', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_fortune_teller', 'Falcı', 'Fortune Teller', '3 Tarot kartı çeker ve 15m içindeki müttefiklere 3 rastgele güçlü güçlendirme veya düşmanlara lanet uygular.', 'Draws 3 Tarot cards, applying 3 random potent buffs to allies or curses to enemies within 15m.', 'Cross-Branch', 50, 400, 3, '{"gb_dealers_choice", "gb_fortunes_favor"}', '{"x": -1039, "y": -600}', '{"buff": "3 Random Buffs (Allies)", "debuff": "3 Random Curses (Enemies)", "radius": "15m"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('775b9ee8-5271-4c1a-aaef-a470c4098d0c', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_high_roller', 'Yüksek Oynayan', 'High Roller', 'Canınızın %50''sine kadarını bahse koyun. %50 şansla bunu geçici Can olarak ikiye katlarsınız, %50 şansla anında kaybedersiniz.', 'Bet up to 50% of your HP. 50% chance to double it as temporary HP, 50% chance to lose it instantly.', 'Cross-Branch', 55, 400, 3, '{"gb_boxcars", "gb_dodge_fate"}', '{"x": -1255, "y": -725}', '{"cost": "Up to 50% HP", "shield": "Double bet HP (50% chance)", "damage_taken": "Lose bet HP (50% chance)"}', '💰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6b1f5e31-e370-4d9e-ba97-a1b717fe560e', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_blackjack', 'Yirmibir', 'Blackjack', '2d10 hasar verir. Eğer atılan hasar tam olarak 21''e eşitse, hedef iki kat hasar alır ve sersemler.', 'Deals 2d10 damage. If the damage rolled equals exactly 21, the target takes double damage and is stunned.', 'Cross-Branch', 60, 400, 3, '{"gb_draw_spade", "gb_lucky_sevens"}', '{"x": -1472, "y": -850}', '{"damage": "2d10", "status": "Stun and Double Damage (if 21)", "range": "10m"}', '🏴‍☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('38641519-7740-416e-b0d5-a6e434ec6a21', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_dead_mans_hand', 'Ölü Adamın Eli', 'Dead Man''s Hand', 'Pasif bir etki: %10 Can''ın altına düştüğünüzde, her biri 5d6 nekrotik hasar veren 5 hayalet kartı otomatik olarak fırlatır.', 'A passive effect: Upon falling below 10% HP, automatically throw 5 spectral cards dealing 5d6 necrotic damage each.', 'Cross-Branch', 65, 750, 4, '{"gb_exploding_deck", "gb_bad_omen"}', '{"x": -1688, "y": -975}', '{"damage": "5x 5d6", "trigger": "<10% HP", "range": "20m"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74b685a5-1152-40df-810d-02451de211e5', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_yahtzee', 'Yahtzee', 'Yahtzee', '5d6 atın. Hepsi eşleşirse, dünyayı sarsan 20d6 hasar verin. Aksi takdirde, 10m içinde 5d6 alan hasarı verin.', 'Roll 5d6. If all match, deal an earth-shattering 20d6 damage. Otherwise, deal 5d6 area damage in 10m.', 'Cross-Branch', 70, 750, 4, '{"gb_dice_bomb", "gb_serendipity"}', '{"x": -1905, "y": -1100}', '{"damage": "20d6 (all match) or 5d6", "radius": "10m"}', '🎊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c8b0703-0f2f-479d-a324-362f07d48704', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_deck_of_many_things', 'Birçok Şeyin Destesi', 'Deck of Many Things', '1 efsanevi kart çekin. Tam grup iyileştirmesinden devasa meteor çarpmalarına kadar değişen 10 aşırı etkiden birini tetikler.', 'Draw 1 legendary card. Triggers one of 10 extreme effects, ranging from full party heal to massive meteor strikes.', 'Cross-Branch', 75, 750, 4, '{"gb_stack_deck", "gb_critical_roll", "gb_karma"}', '{"x": -2121, "y": -1225}', '{"special": "1 of 10 Extreme Effects", "range": "Variable"}', '🎴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cc73e9bb-78fc-41bf-8870-6b472294a897', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_jackpot', 'Büyük İkramiye', 'Jackpot', 'Her saldırının büyük ikramiyeyi tetikleme şansı %5''tir; 5m yarıçapında 8d6 ezici hasar veren altın sikkeler yağdırır.', 'Every attack has a 5% chance to trigger a jackpot, raining golden coins that deal 8d6 crushing damage in a 5m radius.', 'Cross-Branch', 80, 750, 4, '{"gb_re_roll", "gb_lady_lucks_kiss"}', '{"x": -2338, "y": -1350}', '{"damage": "8d6", "radius": "5m", "trigger": "5% per attack"}', '🤑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('42d409f0-cb28-4285-99ce-cb535979f878', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_all_in', 'Hepsi İçeri', 'All In', 'Kalan tüm Manayı harcayın. Devasa 20m''lik bir konide harcanan her 10 puan için 1d6 büyü hasarı verin.', 'Expend all remaining Mana. Deal 1d6 magical damage per 10 points expended in a massive 20m cone.', 'Cross-Branch', 85, 1200, 5, '{"gb_draw_diamond", "gb_d20_destiny", "gb_defy_odds"}', '{"x": -2554, "y": -1475}', '{"damage": "1d6 per 10 Mana", "range": "20m cone"}', '💸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('729af9d6-adc9-41d9-b6af-fb3547c04bba', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_house_always_wins', 'Kasa Her Zaman Kazanır', 'The House Always Wins', '3 tur boyunca 30m''lik bir kumarhane bölgesi oluşturun. İçeride, düşman kritikleri sizi iyileştirir ve ıskalarınız %50 hasar verir.', 'Create a 30m casino zone for 3 turns. Inside, enemy crits heal you, and your misses deal 50% damage.', 'Cross-Branch', 95, 1200, 5, '{"gb_royal_flush", "gb_crapshoot", "gb_lady_lucks_kiss"}', '{"x": -2771, "y": -1600}', '{"radius": "30m", "healing": "From enemy crits", "damage": "50% on miss", "duration": "3 turns"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5dcf2a80-a467-4971-b374-d4770420b581', '4ef832e0-825d-426b-a9a6-25712e3a095a', 'gb_jackpot_of_cosmos', 'Büyük Ulti: Kozmosun İkramiyesi', 'Grand Ultimate: Jackpot of the Cosmos', 'Gerçeklik sizin kumarhaneniz olur. Zamanı 3 tur boyunca dondurun. Sınırsız kaynağınız ve maksimum zarlarınız olur, düşmanlar otomatik olarak 1 atar.', 'Reality becomes your casino. Freeze time for 3 turns. You have unlimited resources, max rolls, and enemies automatically roll 1s.', 'Cross-Branch', 100, 1500, 5, '{"gb_house_of_cards", "gb_gamblers_fallacy", "gb_wheel_of_fortune"}', '{"x": -2987, "y": -1725}', '{"duration": "3 turns", "status": "Time Stop", "buff": "Max rolls & Infinite resources", "debuff": "Enemies roll 1s"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6a3e2fa7-f52e-423e-b2df-1a03e011368d', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_analyze', 'Zayıflık Analizi', 'Analyze Weakness', 'Bir düşmanın yapısal veya davranışsal kusurlarını analiz ederek 3 tur boyunca Zırh Sınıfını (AC) 2 düşürür.', 'Analyze an enemy to find structural or behavioral flaws, reducing their AC by 2 for 3 turns.', 'Tactics', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"ac_reduction": 2, "duration": "3 turns", "range": "20m"}', '🔍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3f558c7-44b7-4864-923d-be5fe9b3fb1f', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_flank', 'Kanat Manevrası', 'Flanking Maneuver', 'Bir müttefiki düşmanı kanatlaması için yönlendirir, bir sonraki saldırısında avantaj ve 1d6 taktiksel hasar kazandırır.', 'Direct an ally to flank an enemy, granting them advantage on their next attack and adding 1d6 tactical damage.', 'Tactics', 3, 60, 1, '{}', '{"x": 389, "y": -224}', '{"bonus_damage": "1d6", "advantage": true, "range": "15m"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ac053670-ff2e-42b2-87d7-c28d4ade2f01', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_reposition', 'Taktiksel Geri Çekilme', 'Tactical Retreat', 'Bir müttefike fırsat saldırısı tetiklemeden 10m''ye kadar hareket etmesi için emir verir.', 'Command an ally to move up to 10m without provoking opportunity attacks.', 'Tactics', 5, 75, 1, '{"gn_tactics_flank"}', '{"x": 606, "y": -349}', '{"movement": "10m", "range": "20m", "opportunity_attack_immunity": true}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('756ab340-6eee-4869-80cf-996f33faf547', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_command', 'Doğrudan Emir', 'Direct Command', 'Kendi eyleminiz pahasına bir müttefike anında fazladan bir eylem hakkı tanır.', 'Grant an ally an immediate extra action at the cost of your own action.', 'Tactics', 10, 100, 1, '{"gn_tactics_analyze"}', '{"x": 822, "y": -474}', '{"action_granted": 1, "range": "15m"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d9b8d36f-14c1-486f-823b-df6160326be2', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_vulnerability', 'Zayıflık İfşası', 'Expose Vulnerability', 'Kritik bir zayıf noktayı işaret eder. Hedefe yapılan bir sonraki saldırı 18-20 zarlarında kritik vurur ve fazladan 2d8 hasar verir.', 'Point out a critical weak spot. The next attack against the target critically hits on a 18-20 and deals an extra 2d8 damage.', 'Tactics', 22, 180, 2, '{"gn_tactics_analyze"}', '{"x": 1039, "y": -599}', '{"crit_range": "18-20", "bonus_damage": "2d8", "range": "20m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('028c4571-46da-4bfd-8b7c-3830ebe9128a', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_formation', 'Falanks Dizilimi', 'Phalanx Formation', '10m içindeki müttefikleri organize eder. Birbirlerinden en fazla 2m uzakta kaldıkları sürece +3 AC ve fiziksel hasar direnci kazanırlar.', 'Organize allies within 10m. They gain +3 AC and resistance to physical damage as long as they stay within 2m of each other.', 'Tactics', 26, 200, 2, '{"gn_tactics_reposition"}', '{"x": 1255, "y": -724}', '{"ac_bonus": 3, "resistance": "Physical", "radius": "10m", "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed66be3d-0912-495a-b9af-dd29d47a4cc1', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_coordination', 'Kusursuz Koordinasyon', 'Perfect Coordination', '3 müttefike kadar zihinleri bağlar. Biri düşmana vurduğunda, diğerleri o düşmana karşı bir sonraki saldırılarında +2 bonus kazanır.', 'Link the minds of up to 3 allies. Whenever one hits an enemy, the others gain +2 to their next attack roll against that same enemy.', 'Tactics', 32, 240, 2, '{"gn_tactics_command"}', '{"x": 1472, "y": -849}', '{"attack_bonus": 2, "targets": 3, "duration": "4 turns"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('77ee9e84-5e34-44d3-93c3-1027f3a848fa', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_feint', 'Hesaplanmış Şaşırtmaca', 'Calculated Feint', 'Kusursuz bir şaşırtmaca yaparak düşmanın tepki eylemini (reaction) boşa harcatır ve müttefikin ücretsiz bir fırsat saldırısı yapmasına olanak tanır.', 'Execute a perfect feint, forcing an enemy to waste their reaction and leaving them open to a free opportunity attack from an ally.', 'Tactics', 38, 280, 2, '{"gn_tactics_vulnerability"}', '{"x": 1688, "y": -974}', '{"reaction_denial": true, "opportunity_attack": true, "range": "10m"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('65fd6af7-e06e-468d-b99b-66ec5bf310b2', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_overwatch', 'Gözetleme Duruşu', 'Overwatch Stance', '15m''lik konik bir alanı işaretler. Bu alanda hareket eden her düşman, sizden veya bir müttefikten +5 bonuslu anında bir menzilli saldırı tetikler.', 'Designate a 15m cone. Any enemy that moves within this area triggers an immediate ranged attack from you or an ally with a +5 bonus.', 'Tactics', 42, 360, 3, '{"gn_tactics_formation"}', '{"x": 1905, "y": -1099}', '{"area": "15m cone", "attack_bonus": 5, "duration": "1 turn"}', '👀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('56ca3c6d-279d-4527-a34f-43cbf994e804', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_ambush', 'Pusu Kurulumu', 'Setup Ambush', '10m yarıçaplı bir pusu alanı hazırlar. Giren ilk düşman 6d6 sürpriz hasar alır ve 1 tur boyunca sersemler.', 'Prepare an ambush zone (10m radius). The first enemy entering it takes 6d6 surprise damage and is stunned for 1 turn.', 'Tactics', 48, 400, 3, '{"gn_tactics_coordination"}', '{"x": 2121, "y": -1224}', '{"damage": "6d6", "radius": "10m", "condition": "Stunned"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e1d4613-0343-4059-8265-aa76e7f0bb5a', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_exploit', 'Açığı Değerlendirme', 'Exploit Opening', 'Zayıflatılmış bir düşmandan faydalanır. 5d8 fiziksel hasar verir; hedefin herhangi bir olumsuz durumu (debuff) varsa hasar ikiye katlanır.', 'Capitalize on a debuffed enemy. Deal 5d8 physical damage, doubling the damage if the target has any negative conditions.', 'Tactics', 56, 480, 3, '{"gn_tactics_feint"}', '{"x": 2338, "y": -1349}', '{"damage": "5d8", "conditional_damage": "10d8", "range": "10m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d496b89d-e83d-462f-834f-b1f0354b6633', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_checkmate', 'Şah Mat Hazırlığı', 'Checkmate Setup', 'Düşmanı taktiksel bir köşeye sıkıştırır. Tur başına 3m''den fazla hareket edemezler ve sonlarının geldiğini fark etmenin verdiği dehşetle 8d8 psişik hasar alırlar.', 'Trap an enemy in a tactical corner. They cannot move more than 3m per turn and take 8d8 psychic damage from the sheer realization of their doom.', 'Tactics', 62, 620, 4, '{"gn_tactics_overwatch", "gn_tactics_ambush"}', '{"x": 2554, "y": -1474}', '{"damage": "8d8", "movement_limit": "3m", "duration": "2 turns"}', '♟️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e1b2cc0-2516-43a6-bf75-ad7fd2f1ec05', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_synergy', 'Tam Sinerji', 'Total Synergy', '3 tur boyunca tüm müttefikler en yüksek istatistiklerini paylaşır. Bir müttefikin 20 Gücü varsa, tüm müttefikler zarlarında 20 Güç kullanır.', 'For 3 turns, all allies share their highest stats. If one ally has 20 Strength, all allies use 20 Strength for their rolls.', 'Tactics', 70, 750, 4, '{"gn_tactics_exploit"}', '{"x": 2771, "y": -1599}', '{"stat_sharing": true, "duration": "3 turns", "radius": "30m"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('749304b6-9079-41b7-98e8-70447bcc35c9', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_disarray', 'Karmaşa Yaratma', 'Sow Disarray', 'Düşman iletişimini manipüle eder. 20m içindeki tüm düşmanlar Zeka kurtarması yapmalıdır, aksi takdirde bir sonraki turlarında en yakın müttefiklerine saldırırlar.', 'Manipulate enemy communications. All enemies in 20m must make an Intelligence save or attack their nearest ally on their next turn.', 'Tactics', 78, 850, 4, '{"gn_tactics_checkmate"}', '{"x": 2987, "y": -1724}', '{"radius": "20m", "condition": "Confusion", "duration": "1 turn"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c9cb59f5-e3f2-49e7-82ae-b7fd39b2e5b8', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_tactics_masterplan', 'Ana Plan', 'The Master Plan', 'Kusursuz bir strateji uygular. Tüm müttefikler inisiyatif sırasını atlayarak anında tam bir tur hakkı kazanır; tüm zarlarda avantaj ve hasarda +10 bonus elde ederler.', 'Execute a flawless strategy. All allies immediately take a full turn, bypassing the initiative order, with advantage on all rolls and +10 to damage.', 'Tactics', 90, 1200, 5, '{"gn_tactics_synergy", "gn_tactics_disarray"}', '{"x": 3204, "y": -1849}', '{"extra_turn_allies": true, "damage_bonus": 10, "radius": "50m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3730b10-e755-48b9-b005-15d1dd85f917', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_caltrops', 'Yaylı Dikenler', 'Spring-loaded Caltrops', '5m''lik alana mekanik dikenler saçar. Giren düşmanlar 1d8 delici hasar alır ve hızları yarı yarıya düşer.', 'Deploy mechanical caltrops in a 5m area. Enemies entering take 1d8 piercing damage and have their speed reduced by half.', 'Inventions', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8", "area": "5m", "speed_reduction": "50%"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8be9e291-0a1d-4044-9913-d10d422d9367', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_grapple', 'Otomatik Kanca', 'Auto-Grapple', 'Kendinizi 15m''ye kadar bir hedefe çekmek veya orta/küçük boy bir düşmanı size çekmek için mekanik bir kanca fırlatır.', 'Fire a mechanical grappling hook to pull yourself up to 15m to a target location, or pull a medium/small enemy to you.', 'Inventions', 4, 60, 1, '{}', '{"x": 289, "y": 344}', '{"range": "15m", "pull": true}', '🪝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('403e4191-ca27-4092-93b8-ddfa3e8018e3', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_smoke', 'Kimyasal Sis Bombası', 'Chemical Smoke Bomb', '10m yarıçaplı yoğun bir duman bulutu yaratan bir bomba atarak düşmanları kör eder ve tur başına 1d4 zehir hasarı verir.', 'Throw a bomb that creates a 10m radius cloud of thick smoke, blinding enemies and dealing 1d4 poison damage per turn.', 'Inventions', 8, 85, 1, '{"gn_invent_caltrops"}', '{"x": 449, "y": 536}', '{"radius": "10m", "damage": "1d4/turn", "condition": "Blinded"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1efdc053-96ed-449d-bfa1-7e6c64dbc1f4', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_spark', 'Kıvılcım Jeneratörü', 'Spark Generator', 'Elde tutulan bir cihazdan elektrik patlaması yayarak 4m''lik konik alanda 2d6 yıldırım hasarı verir.', 'Release a burst of electricity from a handheld device, dealing 2d6 lightning damage in a 4m cone.', 'Inventions', 12, 110, 1, '{}', '{"x": 610, "y": 727}', '{"damage": "2d6", "area": "4m cone"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('174ac068-3371-4cba-93a7-52d956e07225', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_net', 'Elektrikli Ağ', 'Electrified Net', 'Düşmanı kısıtlayan ağır bir ağ fırlatır; düşmanın tur başlangıçlarında 2d8 yıldırım hasarı verir. Kaçmak için DC 16 Güç kontrolü gerektirir.', 'Launch a heavy net that restrains an enemy and deals 2d8 lightning damage at the start of their turns. Requires a DC 16 Strength check to escape.', 'Inventions', 24, 190, 2, '{"gn_invent_grapple"}', '{"x": 771, "y": 919}', '{"damage": "2d8/turn", "condition": "Restrained", "range": "10m"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0200f66f-8b22-42dc-b263-2ad97b029afd', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_drone', 'Keşif Dronu', 'Recon Drone', 'Görünmez düşmanları açığa çıkaran ve size 10 dakika boyunca 30m yarıçaplı alanda telepatik görüş sağlayan küçük bir uçan dron konuşlandırır.', 'Deploy a small flying drone that reveals invisible enemies and grants you telepathic vision in a 30m radius for 10 minutes.', 'Inventions', 28, 210, 2, '{"gn_invent_smoke"}', '{"x": 932, "y": 1110}', '{"radius": "30m", "truesight": true, "duration": "10 min"}', '🚁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f18505a2-cbbd-4a8d-9a47-ca2583bf13c7', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_barrier', 'Kurulabilir Siper', 'Deployable Cover', '3m genişliğinde, 2m yüksekliğinde titanyum bir barikata dönüşen bir kapsül atar. Tam siper sağlar ve 50 Can Puanı (HP) vardır.', 'Throw a capsule that expands into a 3m wide, 2m tall titanium barricade. Provides full cover and has 50 HP.', 'Inventions', 34, 250, 2, '{}', '{"x": 1092, "y": 1302}', '{"barrier_hp": 50, "width": "3m", "height": "2m", "duration": "Permanent until destroyed"}', '🚧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb81e231-75f2-486d-9478-b7f4dfb30329', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_stim', 'Adrenalin İğnesi', 'Adrenaline Stimulant', 'Bir müttefike güçlü bir kimyasal karışım enjekte eder. 3d8 HP iyileşirler, +3m hareket kazanırlar ve 1 saat boyunca yorgunluğu görmezden gelirler.', 'Inject an ally with a potent chemical mix. They heal for 3d8 HP, gain +3m movement, and ignore exhaustion for 1 hour.', 'Inventions', 38, 290, 2, '{"gn_invent_spark"}', '{"x": 1253, "y": 1493}', '{"healing": "3d8", "movement_bonus": "3m", "duration": "1 hour"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b6e4c9aa-a5cb-46b0-a07c-b90263d955fe', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_turret', 'Otomatik Taret', 'Automated Turret', 'Her tur en yakın düşmana saldırarak 3d10 delici hasar veren sabit bir taret kurar. 4 tur veya yok edilene kadar (60 HP) kalır.', 'Deploy a stationary turret that attacks the nearest enemy each turn, dealing 3d10 piercing damage. Lasts 4 turns or until destroyed (60 HP).', 'Inventions', 44, 370, 3, '{"gn_invent_net"}', '{"x": 1414, "y": 1685}', '{"damage": "3d10/turn", "turret_hp": 60, "duration": "4 turns"}', '🔫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b2dd72c-b95f-4436-b194-d636944af04d', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_mine', 'Yakınlık Mayını', 'Proximity Mine', 'Görünmez bir patlayıcı yerleştirir. 3m içindeki bir düşman tarafından tetiklendiğinde patlayarak 6d8 ateş hasarı verir ve hedefleri yüzüstü düşürür.', 'Plant an invisible explosive. When triggered by an enemy within 3m, it detonates for 6d8 fire damage and knocks targets prone.', 'Inventions', 50, 420, 3, '{"gn_invent_barrier"}', '{"x": 1574, "y": 1876}', '{"damage": "6d8", "trigger_radius": "3m", "condition": "Prone"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('10bf788f-c75f-4015-b359-0a6f25c40523', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_deflector', 'Manyetik Saptırıcı', 'Magnetic Deflector', 'Kendiniz etrafında 3 tur boyunca manyetik bir alan aktive eder. Tüm menzilli mermi saldırılarının saldırgana geri yansıma ihtimali %50''dir.', 'Activate a magnetic field around yourself for 3 turns. All ranged projectile attacks have a 50% chance to be deflected back at the attacker.', 'Inventions', 58, 490, 3, '{"gn_invent_drone"}', '{"x": 1735, "y": 2068}', '{"deflection_chance": "50%", "duration": "3 turns"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('912fd61b-2928-4b86-969a-d288a114d642', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_golem', 'Kurmalı Golem', 'Clockwork Golem', 'Sizin için savaşacak mekanik bir yapı birleştirir. 120 Canı vardır, vuruş başına 4d10 ezme hasarı verir ve size gelen hasarın %30''unu emer.', 'Assemble a mechanical construct to fight for you. It has 120 HP, deals 4d10 bludgeoning damage per hit, and absorbs 30% of damage meant for you.', 'Inventions', 64, 650, 4, '{"gn_invent_turret"}', '{"x": 1896, "y": 2259}', '{"golem_hp": 120, "damage": "4d10", "damage_absorption": "30%", "duration": "10 min"}', '🤖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8c6d314-8532-4288-9cd7-43827ed7b0c5', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_emp', 'EMP Bombası', 'EMP Grenade', '15m yarıçapında bir elektromanyetik dalga patlatır. Büyülü etkileri dağıtır, teknolojik cihazları devre dışı bırakır ve 8d6 güç hasarı verir.', 'Detonate an electromagnetic pulse in a 15m radius. Dispels magical effects, disables technological devices, and deals 8d6 force damage.', 'Inventions', 72, 780, 4, '{"gn_invent_mine"}', '{"x": 2056, "y": 2451}', '{"damage": "8d6", "radius": "15m", "dispel": true}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6a0b128d-a2de-47a6-92e4-8a96668aad63', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_ray', 'Plazma Işını', 'Plasma Ray', '30m''lik bir hatta yoğunlaştırılmış süper ısıtılmış plazma ışını fırlatır. 10d10 ateş/radyant hasarı verir ve zırhı eriterek Zırh Sınıfını (AC) kalıcı olarak 3 düşürür.', 'Fire a concentrated beam of superheated plasma in a 30m line. Deals 10d10 fire/radiant damage and melts armor, reducing AC by 3 permanently.', 'Inventions', 76, 820, 4, '{"gn_invent_deflector"}', '{"x": 2217, "y": 2642}', '{"damage": "10d10", "ac_reduction": 3, "area": "30m line"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f4f79c50-6956-4eda-b0dc-98a17eb6b7ce', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_invent_doomsday', 'Kıyamet Makinesi', 'Doomsday Device', 'Başyapıtınızı konuşlandırır. 2 turluk şarjın ardından 100m yarıçapta patlayarak 25d10 güç hasarı verir, gerçekliği bükerek 100 HP altındaki düşmanları toza çevirir.', 'Deploy your magnum opus. After 2 turns of charging, it detonates in a 100m radius, dealing 25d10 force damage and warping reality, disintegrating enemies under 100 HP.', 'Inventions', 92, 1250, 5, '{"gn_invent_golem", "gn_invent_emp"}', '{"x": 2378, "y": 2834}', '{"damage": "25d10", "radius": "100m", "disintegrate_threshold": 100, "delay": "2 turns"}', '☢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('604d4bee-0ae7-48f8-a8c9-742c041c953f', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_predict', 'Saldırı Öngörüsü', 'Predict Strike', 'Düşmanın kas seğirmelerini analiz ederek bir sonraki yakın dövüş saldırısını öngörür ve ona karşı +4 AC kazandırır.', 'Analyze an enemy''s muscle twitches to predict their next melee attack, gaining +4 AC against it.', 'Foresight', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"ac_bonus": 4, "duration": "1 attack"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('66886575-c3a7-4253-9cc8-43e58ba2492b', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_dodge', 'Hesaplanmış Kaçış', 'Calculated Dodge', 'Gelen bir alan etkisinden tam olarak 1m uzağa çekilerek otomatik olarak yarım hasar veya başarılı bir kurtarmada sıfır hasar alır.', 'Move exactly 1m out of the way of an incoming area effect, taking half damage automatically, or no damage on a successful save.', 'Foresight', 3, 60, 1, '{}', '{"x": -289, "y": 344}', '{"evasion": true, "reaction": true}', '🤸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ecaf04f-f723-4c5b-ac09-4d227168f2b4', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_initiative', 'İnisiyatif Gaspı', 'Seize Initiative', 'Savaş alanını zihinsel olarak hiper hızda işler. İnisiyatif zarına Zeka düzenleyicisini ekler ve hazırlıksız yakalanamazsınız (surprised olmazsınız).', 'Mentally process the battlefield at hyperspeed. Add your Intelligence modifier to your Initiative roll and cannot be surprised.', 'Foresight', 7, 80, 1, '{}', '{"x": -449, "y": 536}', '{"initiative_bonus": "INT mod", "immunity": "Surprise"}', '⏱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f07973d6-f680-48f8-b28b-ba241d2d8596', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_read', 'Niyet Okuma', 'Read Intentions', 'Bir hedefe odaklanarak mevcut Canlarını, dirençlerini, zayıflıklarını ve bir sonraki turdaki planladıkları hedeflerini kesin olarak öğrenir.', 'Focus on a target to learn their exact current HP, resistances, vulnerabilities, and their intended target for their next turn.', 'Foresight', 14, 120, 1, '{"gn_fore_predict"}', '{"x": -610, "y": 727}', '{"info_gathering": true, "range": "20m"}', '📖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('added4b1-5dcd-41c8-9141-eda5913333db', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_counter', 'Beklenen Karşı Saldırı', 'Anticipatory Counter', 'Bir düşman size yakın dövüş saldırısı kaçırdığında, 3d6 hasar veren kaçınılmaz bir vuruşla anında misilleme yapar.', 'When an enemy misses you with a melee attack, instantly retaliate with an unavoidable strike dealing 3d6 damage.', 'Foresight', 21, 175, 2, '{"gn_fore_predict"}', '{"x": -771, "y": 919}', '{"damage": "3d6", "auto_hit": true, "reaction": true}', '🤺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea5524f7-f538-4418-bcb2-d227c9279664', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_glimpse', 'Geleceği Görme', 'Glimpse the Future', 'Geleceğin 3 saniye sonrasına bakar. Sizin veya müttefikinizin attığı bir d20 zarını yeniden atabilir ve yeni sonucu tutarsınız.', 'Look 3 seconds into the future. You may reroll one d20 roll you or an ally makes, keeping the new result.', 'Foresight', 27, 220, 2, '{"gn_fore_read"}', '{"x": -932, "y": 1110}', '{"reroll": true, "duration": "Instant"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('78b89c39-7b8b-4052-8673-021519fa02bc', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_evade', 'Önleyici Kaçınma', 'Preemptive Evasion', 'Tüm mermilerin yörüngelerini önceden hesaplar. Size yapılan menzilli saldırılar 3 tur boyunca dezavantaja sahip olur.', 'Pre-calculate the trajectories of all projectiles. Ranged attacks against you have disadvantage for 3 turns.', 'Foresight', 33, 260, 2, '{"gn_fore_dodge"}', '{"x": -1092, "y": 1302}', '{"disadvantage_ranged": true, "duration": "3 turns"}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3b2e3d8e-84fc-476c-afe8-07d29935f634', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_delay', 'Rakibi Geciktirme', 'Delay Opponent', 'Düşmanı eylemini ikinci kez düşünmeye zorlar. Düşman mevcut tur için inisiyatif sırasının en sonuna itilir.', 'Force an enemy to double-guess their action. They are pushed to the very end of the initiative order for the current round.', 'Foresight', 39, 300, 2, '{"gn_fore_initiative"}', '{"x": -1253, "y": 1493}', '{"initiative_change": "Last", "range": "15m"}', '🐢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09793b83-6e21-47b0-af9a-ec2b2861b7d5', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_timeline', 'Zaman Çizelgesi Hesaplama', 'Calculate Timelines', 'Birden fazla savaş sonucunu simüle eder. Sonraki 2 tur boyunca, herhangi bir düşmanın saldırı zarını doğrudan 10 ile değiştirmeyi seçebilirsiniz.', 'Simulate multiple combat outcomes. For the next 2 turns, you can choose to replace any enemy''s attack roll with a flat 10.', 'Foresight', 45, 380, 3, '{"gn_fore_glimpse"}', '{"x": -1414, "y": 1685}', '{"roll_replacement": 10, "duration": "2 turns"}', '📊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2d74f8c9-21e2-491f-bf33-e65347b628c4', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_outsmart', 'Zekayla Alt Etme', 'Outsmart', 'Düşmanı bariz bir tuzağa çeker. 5d8 psişik hasar verir ve düşman bir sonraki turunu sizin illüzyonunuza saldırarak boşa harcar.', 'Lure an enemy into an obvious trap. Deal 5d8 psychic damage, and they waste their next turn attacking an illusion of you.', 'Foresight', 51, 430, 3, '{"gn_fore_counter"}', '{"x": -1574, "y": 1876}', '{"damage": "5d8", "condition": "Distracted", "duration": "1 turn"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('57f6ac04-f453-48fd-9837-099dd6c69324', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_rewind', 'Zihinsel Geri Sarma', 'Mental Rewind', 'Mevcut turun sadece zihinsel bir simülasyon olduğunu fark eder. Savaş durumunu (Can, konumlar, büyü slotları) mevcut turun başlangıcına sıfırlar. Günde bir kez kullanılır.', 'Realize the current turn was just a mental simulation. Reset the combat state (HP, positions, spell slots) back to the start of the current round. Usable once per day.', 'Foresight', 59, 500, 3, '{"gn_fore_evade"}', '{"x": -1735, "y": 2068}', '{"time_manipulation": "1 round rewind", "uses": "1/day"}', '⏪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60631bc5-006a-4a96-a617-64165249e7e4', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_prescience', 'Savaş Öngörüsü', 'Combat Prescience', 'Tam farkındalık durumuna girer. 1 dakika boyunca, saldıran kişi doğal 20 atmadıkça hiçbir saldırıdan isabet almazsınız.', 'Enter a state of total awareness. For 1 minute, you cannot be hit by attacks unless the attacker rolls a natural 20.', 'Foresight', 63, 630, 4, '{"gn_fore_timeline"}', '{"x": -1896, "y": 2259}', '{"ac_bonus": "Only crit hits", "duration": "1 min"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c905279-066f-426a-8595-fd7d9c052fb0', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_fate', 'Kaderi Belirleme', 'Dictate Fate', 'Düşmanın ölümünü ilan eder. Eğer hedef %30 Canın altındaysa, kehanetinizin yarattığı psikolojik baskıdan kalbi durur ve anında ölür.', 'Declare an enemy''s demise. If the target is below 30% HP, their heart stops from the sheer psychological pressure of your prediction, instantly killing them.', 'Foresight', 71, 760, 4, '{"gn_fore_outsmart"}', '{"x": -2056, "y": 2451}', '{"execute_threshold": "30% HP", "range": "20m"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ea2fa99-b4eb-4a08-bfe7-851e2626c8cf', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_paradox', 'Nedensellik Paradoksu', 'Causal Paradox', 'Bir düşmana o henüz varmadan saldırır. 12d8 güç hasarı verir. Eğer bu hasar onu öldürürse, son 2 turdaki geçmiş eylemleri geri alınır.', 'Attack an enemy before they arrive. Deal 12d8 force damage. If this damage kills them, their past actions in the last 2 turns are undone.', 'Foresight', 79, 860, 4, '{"gn_fore_rewind"}', '{"x": -2217, "y": 2642}', '{"damage": "12d8", "effect_reversal": "2 turns on kill"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6806e1ec-c08c-4c5d-8c56-b1d5aa690ac0', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_fore_omniscience', 'Laplace''ın Şeytanı', 'Laplace''s Demon', 'Savaş alanındaki her atomu işler. 3 tur boyunca her şeyi eksiksiz öngörürsünüz. Tüm saldırılarınız kritik vurur, tüm düşmanlar dezavantaja sahip olur ve tüm kurtarmalarda otomatik başarı sağlarsınız.', 'Process every atom in the battlefield. You foresee absolutely everything for 3 turns. All your attacks critically hit, all enemies have disadvantage, and you automatically succeed on all saves.', 'Foresight', 94, 1300, 5, '{"gn_fore_prescience", "gn_fore_paradox"}', '{"x": -2378, "y": 2834}', '{"auto_crit": true, "auto_save": true, "enemy_disadvantage": true, "duration": "3 turns"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b86623d7-d0a1-46f2-abff-fbd9a2e685fe', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_cb_anticipate', 'Öngörülen Emirler', 'Anticipated Orders', 'Savaş başlamadan önce bir emir verir. Bir müttefik, sürpriz turunda veya inisiyatif sırasından önce ücretsiz bir eylem kazanır.', 'Issue a command before the battle begins. One ally gains a free action during the surprise round or before the first initiative turn.', 'Cross-Branch', 25, 230, 2, '{"gn_tactics_command", "gn_fore_initiative"}', '{"x": -173, "y": -100}', '{"free_action": true, "timing": "Pre-combat"}', '📋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('747559a4-9d5e-4b42-a13f-15c275b6b1b2', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_cb_trap', 'Taktiksel Tuzak', 'Tactical Snare', 'Düşmanı gizli bir yerçekimi tuzağına çeker. 4d10 ezme hasarı verir ve savaş boyunca hareket hızını kalıcı olarak 5m düşürür.', 'Lure an enemy into a hidden gravity trap. Deals 4d10 crushing damage and permanently reduces their movement speed by 5m for the encounter.', 'Cross-Branch', 47, 410, 3, '{"gn_tactics_vulnerability", "gn_invent_net"}', '{"x": -389, "y": -225}', '{"damage": "4d10", "speed_reduction": "5m", "duration": "Encounter"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e669e8c9-8502-4c57-aac4-193afa64671d', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_cb_predictive_shield', 'Öngörülü Kalkan', 'Predictive Shielding', 'Bir sonraki saldırının hasar türünü öngören yapay zeka güdümlü bir kalkan kuşanarak o elemente karşı 1 tur boyunca otomatik bağışıklık sağlar.', 'Equip an AI-driven personal shield that anticipates the damage type of the next attack and automatically grants immunity to that element for 1 turn.', 'Cross-Branch', 55, 470, 3, '{"gn_invent_barrier", "gn_fore_glimpse"}', '{"x": -606, "y": -350}', '{"immunity": "Adaptive", "duration": "1 turn"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e8e77900-3a7a-468e-a7a9-c48acffae235', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_cb_mastermind', 'Dehanın Kumarı', 'Mastermind''s Gambit', 'Savaş alanını aşırı yüklemek için sahada bulunan icatlarınızı feda eder. Her aktif icat 10d10 hasarla patlarken, zarar görmemeniz için siz ve müttefikleriniz gerçeklikten soyutlanırsınız.', 'Sacrifice your deployed inventions to overload the battlefield. Each active invention explodes for 10d10 damage, while you and allies are phased out of reality to avoid harm.', 'Cross-Branch', 80, 900, 4, '{"gn_tactics_checkmate", "gn_invent_emp", "gn_fore_prescience"}', '{"x": -822, "y": -475}', '{"damage": "10d10 per invention", "immunity": "Allies"}', '🧩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c7d9e4ec-0e72-4e5a-a551-a623d1a3603b', 'c3b46298-8994-4bbf-986a-4de60cd04d90', 'gn_grand_ultimate', 'Makinedeki Tanrı', 'Deus Ex Machina', 'Aşırı zekanın nihai gösterimi. Gerçek zamanlı olarak olasılıkları değiştiren bir hiper bilgisayar inşa edersiniz. Savaşın geri kalanında zarları siz kontrol edersiniz. Herhangi bir varlık tarafından atılan bir zarı 1 veya 20 olarak değiştirebilirsiniz.', 'The ultimate display of extreme intellect. You construct a probability-altering hypercomputer in real-time. For the rest of the battle, you control the dice. You can change any roll made by any creature to a 1 or a 20.', 'Cross-Branch', 100, 1500, 5, '{"gn_tactics_masterplan", "gn_invent_doomsday", "gn_fore_omniscience"}', '{"x": -1039, "y": -600}', '{"dice_control": true, "duration": "Rest of encounter", "uses": "Unlimited within encounter"}', '🎲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('08c21446-355c-4f14-88af-bffd2a9a192a', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_holy_strike', 'Kutsal Vuruş', 'Holy Strike', 'Kutsal ışıkla aşılanmış bir silahla tek bir hedefe vurarak 1d8 fiziksel ve 1d6 kutsal hasar verir.', 'Strikes a single target with a weapon infused with holy light, dealing 1d8 physical and 1d6 holy damage.', 'Faith', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8 physical + 1d6 holy", "range": "2m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae7342f1-e23b-40e9-a5e7-f97b47156d44', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_minor_sanctuary', 'Küçük Sığınak', 'Minor Sanctuary', '3m''lik küçük bir güvenli bölge oluşturur. İçerideki müttefikler 10 saniye boyunca saniyede 2 HP yeniler.', 'Creates a small 3m safe zone. Allies inside regenerate 2 HP per second for 10s.', 'Sanctuary', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"healing": "2 HP/sec", "duration": "10s", "range": "3m"}', '🏕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3f011a1a-8059-48e7-a2c0-e5303d330be7', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_aegis_shield', 'Himaye Kalkanı', 'Aegis Shield', 'Kendinize veya 8m içindeki bir müttefike 50 HP''lik koruyucu bir kalkan verir. Kırılana veya 1 dakika geçene kadar sürer.', 'Grants a 50 HP protective shield to yourself or an ally within 8m. Lasts until broken or 1 minute passes.', 'Divine Aegis', 3, 60, 1, '{}', '{"x": -128, "y": 153}', '{"shield": "50 HP", "duration": "60s", "range": "8m"}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f9fd7a8-34f4-4397-b30f-4cda2ed29aff', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_righteous_provoke', 'Haklı Kışkırtma', 'Righteous Provoke', '8m içindeki tüm düşmanları size saldırmaları için kışkırtır ve kendinize 6 saniye boyunca +%15 zırh sağlar.', 'Taunts all enemies within 8m to attack you, granting yourself +15% armor for 6s.', 'Faith', 5, 80, 1, '{}', '{"x": 389, "y": -224}', '{"taunt": "8m", "armor_buff": "+15%", "duration": "6s"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('201bb53a-623d-40c5-981f-c4745af1161e', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_word_of_comfort', 'Teselli Sözü', 'Word of Comfort', 'İlahi bir söz söyleyerek 10m içindeki bir müttefiki 1d8+2 HP iyileştirir ve küçük zayıflatmaları kaldırır.', 'Speaks a divine word, healing a single ally within 10m for 1d8+2 HP and removing minor debuffs.', 'Sanctuary', 8, 90, 1, '{}', '{"x": 289, "y": 344}', '{"healing": "1d8+2", "range": "10m", "cleanse": "1 minor debuff"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('982a2dd6-2d69-42e3-85b1-30bd78187961', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_holy_ward', 'Kutsal Koğuş', 'Holy Ward', 'Bir hedefi kutsal enerjiyle sararak, 10 saniye boyunca alınan tüm büyü hasarını %15 azaltır.', 'Surrounds a target with holy energy, reducing all magic damage taken by 15% for 10s.', 'Divine Aegis', 10, 100, 1, '{}', '{"x": -289, "y": 344}', '{"magic_reduction": "15%", "duration": "10s", "range": "10m"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b5256204-5d8d-482e-a435-63770ffcac77', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_blessed_weapon', 'Kutsanmış Silah', 'Blessed Weapon', 'Silahınızı 30 saniye boyunca ilahi ışıkla doldurur. Saldırılarınız fazladan 1d4 kutsal hasar verir ve 5m''lik alanı aydınlatır.', 'Infuses your weapon with divine light for 30s. Your attacks deal an additional 1d4 holy damage and illuminate the area for 5m.', 'Faith', 15, 120, 1, '{}', '{"x": 606, "y": -349}', '{"damage_bonus": "1d4 holy", "light_radius": "5m", "duration": "30s"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2558b160-de47-4a07-b5a9-81dc190677e8', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_intercepting_light', 'Araya Giren Işık', 'Intercepting Light', '8m içindeki bir müttefike ışık hızında atılarak, 3 saniye içinde onlara yönelik bir sonraki saldırıyı emer.', 'Dash to an ally within 8m at the speed of light, absorbing the next single attack meant for them within 3s.', 'Divine Aegis', 16, 130, 1, '{}', '{"x": -449, "y": 536}', '{"range": "8m", "duration": "3s", "absorb": "1 attack"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a03e1eef-25e1-47b8-a005-bb2c40ab66dd', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_hallowed_ground', 'Kutsal Zemin', 'Hallowed Ground', '5m''lik bir alanı 12 saniyeliğine kutsar. İçeri adım atan düşmanlar saniyede 1d4 kutsal hasar alırken, müttefikler +%10 fiziksel savunma kazanır.', 'Blesses a 5m area for 12s. Enemies taking a step inside suffer 1d4 holy damage per second, while allies gain +10% physical defense.', 'Sanctuary', 18, 140, 1, '{}', '{"x": 449, "y": 536}', '{"range": "5m", "duration": "12s", "damage": "1d4 holy/sec", "defense_buff": "+10%"}', '🔆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ddd419d5-2c41-4b0c-95fd-4e28816a1b58', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_devotion_aura', 'Bağlılık Aurası', 'Aura of Devotion', '10m''lik bir aura yayar. Menzil içindeki tüm müttefikler +%10 kutsal direnç ve +%5 fiziksel hasar kazanır.', 'Emanates a 10m aura. All allies within range gain +10% holy resistance and +5% physical damage.', 'Cross-branch', 20, 150, 1, '{"gof_blessed_weapon", "gof_minor_sanctuary"}', '{"x": 173, "y": -99}', '{"range": "10m", "holy_resistance": "+10%", "physical_damage": "+5%"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0717e30c-3a98-4e0d-86f2-03297b83b601', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_blinding_smite', 'Kör Eden Çarpma', 'Blinding Smite', 'Düşmana parlak bir parlamayla vurarak 2d8 kutsal hasar verir ve onları 3 saniyeliğine kör eder.', 'Strikes the enemy with a brilliant flash, dealing 2d8 holy damage and blinding them for 3s.', 'Faith', 22, 180, 2, '{"gof_holy_strike"}', '{"x": 822, "y": -474}', '{"damage": "2d8 holy", "blind": "3s", "range": "2m"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41cabdbd-b1e0-4dfd-a1c2-df5f77c6d7c4', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_healing_pulse', 'İyileştirici Nabız', 'Healing Pulse', '8m yarıçapında ani bir ışık dalgası yayarak tüm müttefikleri anında 2d6 HP iyileştirir.', 'Releases a sudden wave of light in an 8m radius, instantly healing all allies for 2d6 HP.', 'Sanctuary', 24, 190, 2, '{"gof_word_of_comfort"}', '{"x": 610, "y": 727}', '{"healing": "2d6", "range": "8m"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f9feb730-2eed-4219-ab9f-43588fa29542', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_shimmering_armor', 'Parıldayan Zırh', 'Shimmering Armor', 'Zırhınızı kör edici bir ışıkla kaplar. Size karşı yapılan sonraki 3 fiziksel saldırı %50 daha az hasar verir.', 'Covers your armor in blinding light. The next 3 physical attacks against you deal 50% less damage.', 'Divine Aegis', 25, 200, 2, '{"gof_holy_ward"}', '{"x": -610, "y": 727}', '{"reduction": "50%", "stacks": "3 attacks"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e666b1c9-cb7b-496a-b95e-271825049eda', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_zealous_charge', 'Gayretli Hücum', 'Zealous Charge', '10m ileri hücum ederek, vurulan ilk düşmanı geri savurur ve 2d6 ezici hasar verir.', 'Charge up to 10m forward, knocking back the first enemy hit and dealing 2d6 bludgeoning damage.', 'Faith', 28, 220, 2, '{"gof_righteous_provoke"}', '{"x": 1039, "y": -599}', '{"damage": "2d6", "knockback": "Yes", "range": "10m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4f29169c-223d-4239-be8f-54716748535d', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_cleansing_flame', 'Arındırıcı Alev', 'Cleansing Flame', '5m yarıçapındaki müttefikleri zararsız kutsal ateşle tutuşturarak her birinden 1 olumsuz durum etkisini temizler.', 'Ignites allies in a 5m radius with harmless holy fire, purging 1 negative status effect from each.', 'Sanctuary', 30, 240, 2, '{"gof_hallowed_ground"}', '{"x": 771, "y": 919}', '{"range": "5m", "cleanse": "1 negative effect"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4b10cbc-1d01-4920-9f8b-a5324e96827f', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_guardian_mantle', 'Muhafızın Örtüsü', 'Guardian''s Mantle', '10m içindeki bir müttefiki koruyucu bir pelerine sararak, 15 saniyeliğine maksimum HP''nizin %15''ine eşit bir kalkan verir.', 'Wrap an ally within 10m in a protective cloak, granting a shield equal to 15% of your maximum HP for 15s.', 'Divine Aegis', 32, 250, 2, '{"gof_aegis_shield"}', '{"x": -771, "y": 919}', '{"shield": "15% Max HP", "duration": "15s", "range": "10m"}', '🧥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('554f711a-1462-46c9-a580-4e69f669d835', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_beacon_of_light', 'Işık Feneri', 'Beacon of Light', '15m içindeki bir müttefiki işaretler. 30 saniye boyunca, diğer hedeflere yaptığınız herhangi bir iyileştirmenin %30''unu otomatik olarak alırlar.', 'Marks an ally within 15m. For 30s, they automatically receive 30% of any healing you cast on other targets.', 'Cross-branch', 35, 270, 2, '{"gof_healing_pulse", "gof_guardian_mantle"}', '{"x": 389, "y": -224}', '{"range": "15m", "healing_share": "30%", "duration": "30s"}', '🏮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71d5cf42-d6c2-4aac-80ea-df4a0a3ed870', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_vow_of_enmity', 'Düşmanlık Yemini', 'Vow of Enmity', '15m içindeki bir düşmanı işaretler. 20 saniye boyunca onlardan %10 daha az hasar alır ve onlara %15 daha fazla hasar verirsiniz.', 'Mark an enemy within 15m. For 20s, you take 10% less damage from them and deal 15% more damage to them.', 'Faith', 36, 280, 2, '{"gof_zealous_charge"}', '{"x": 1255, "y": -724}', '{"range": "15m", "damage_taken": "-10%", "damage_dealt": "+15%", "duration": "20s"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('62fa954b-0378-4c2e-9c0b-b005967cbc0c', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_sanctified_barrier', 'Kutsanmış Bariyer', 'Sanctified Barrier', 'Tüm düşman mermilerini engelleyen, 8 saniye süren 6x3m boyutunda katı ışıktan bir duvar oluşturur.', 'Creates a 6x3m wall of solid light for 8s that blocks all hostile projectiles.', 'Sanctuary', 38, 290, 2, '{"gof_cleansing_flame"}', '{"x": 932, "y": 1110}', '{"size": "6x3m", "duration": "8s", "projectile_block": "Yes"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fcb72ae0-fe12-4b59-a43d-6a33206bafd0', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_divine_rebuke', 'İlahi Kınama', 'Divine Rebuke', 'Kalkanınız kırıldığında 4m yarıçapında patlayarak yakındaki düşmanlara 3d6 kutsal hasar verir.', 'When your shield breaks, it detonates in a 4m radius, dealing 3d6 holy damage to nearby enemies.', 'Divine Aegis', 39, 300, 2, '{"gof_intercepting_light"}', '{"x": -932, "y": 1110}', '{"damage": "3d6 holy", "range": "4m", "trigger": "Shield break"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('989b48e6-5166-4744-8fc8-083039cc8769', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_judgement_wave', 'Yargı Dalgası', 'Judgement Wave', '15m''lik öncü bir kutsal enerji dalgası serbest bırakır. Vurulan düşmanlar 3d6 kutsal hasar alırken, müttefikler 40 HP''lik bir kalkan kazanır.', 'Unleashes a 15m frontal wave of holy energy. Enemies hit take 3d6 holy damage, while allies gain a 40 HP shield.', 'Cross-branch', 40, 300, 2, '{"gof_zealous_charge", "gof_shimmering_armor"}', '{"x": 606, "y": -349}', '{"damage": "3d6 holy", "shield": "40 HP", "range": "15m wave"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b25f084-819f-4000-9081-7182464fcd10', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_wrath_of_the_heavens', 'Göklerin Gazabı', 'Wrath of the Heavens', '5m''lik bir alana bir ışık sütunu indirerek içerideki tüm düşmanlara 4d8 kutsal hasar verir.', 'Calls down a pillar of light on a 5m area, dealing 4d8 holy damage to all enemies inside.', 'Faith', 42, 360, 3, '{"gof_blinding_smite"}', '{"x": 1472, "y": -849}', '{"damage": "4d8 holy", "range": "5m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5dcb1817-18dd-4f5c-abf4-c7a32290ede2', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_circle_of_protection', 'Koruma Çemberi', 'Circle of Protection', 'Yere 10 saniyeliğine 8m''lik bir çember çizer. İçinde duran müttefikler düşmanlar tarafından kritik vuruş alamaz.', 'Draws an 8m circle on the ground for 10s. Allies standing inside cannot be critically hit by enemies.', 'Sanctuary', 44, 380, 3, '{"gof_healing_pulse"}', '{"x": 1092, "y": 1302}', '{"range": "8m", "duration": "10s", "immunity": "Critical hits"}', '⭕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e36cf22-5679-403e-b327-e724c3434879', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_bulwark_of_light', 'Işık Siperi', 'Bulwark of Light', 'Önünüzde 5 saniyeliğine devasa uhrevi bir kalkan çağırarak önden gelen tüm hasarın %80''ini engeller.', 'Summons a massive ethereal shield in front of you for 5s, blocking 80% of all incoming frontal damage.', 'Divine Aegis', 45, 390, 3, '{"gof_guardian_mantle"}', '{"x": -1092, "y": 1302}', '{"reduction": "80% frontal", "duration": "5s"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('91327d4c-ec22-4847-b050-07fcb2460a26', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_unyielding_faith', 'Sarsılmaz İnanç', 'Unyielding Faith', 'Pasif: HP''niz %30''un altına düştüğünde, %20 hasar azaltma ile korku ve çekicilik etkilerine bağışıklık kazanırsınız.', 'Passive: Whenever your HP falls below 30%, you gain 20% damage reduction and immunity to fear and charm.', 'Faith', 48, 410, 3, '{"gof_vow_of_enmity"}', '{"x": 1688, "y": -974}', '{"threshold": "30% HP", "reduction": "20%", "immunity": "Fear/Charm"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6db49a00-0892-4c02-a9e4-6eced2751d74', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_mass_restoration', 'Toplu Yenilenme', 'Mass Restoration', 'İlahi enerjiyi yönlendirerek, 15m yarıçapındaki tüm müttefikleri 4d8 + 10 HP iyileştirir.', 'Channels divine energy, healing all allies within a 15m radius for 4d8 + 10 HP.', 'Sanctuary', 50, 440, 3, '{"gof_circle_of_protection"}', '{"x": 1253, "y": 1493}', '{"healing": "4d8+10", "range": "15m"}', '🌸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7ac5d4ba-5bab-4f34-82b1-46f22e4e9a06', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_soul_link', 'Ruh Bağı', 'Soul Link', 'Ruhunuzu 20 saniyeliğine 15m içindeki bir müttefikle bağlar. Aldıkları hasarın %30''u bunun yerine size yönlendirilir.', 'Links your soul with an ally within 15m for 20s. 30% of the damage they take is redirected to you instead.', 'Divine Aegis', 52, 450, 3, '{"gof_divine_rebuke"}', '{"x": -1253, "y": 1493}', '{"redirect": "30%", "duration": "20s", "range": "15m"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e2c2aaaa-4d47-4e44-a6af-a1f282ef4c19', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_crusader_strike', 'Haçlı Vuruşu', 'Crusader''s Strike', '5d6 fiziksel hasar veren ve sizi verilen hasarın %50''si kadar iyileştiren yıkıcı bir yakın dövüş saldırısı.', 'A devastating melee attack dealing 5d6 physical damage, healing you for 50% of the damage dealt.', 'Faith', 55, 480, 3, '{"gof_wrath_of_the_heavens"}', '{"x": 1905, "y": -1099}', '{"damage": "5d6 physical", "lifesteal": "50%", "range": "2m"}', '⚒️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a168e4a7-4580-4bfa-ac1e-460e8051339e', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_martyrs_grace', 'Şehidin Lütfu', 'Martyr''s Grace', 'Mevcut HP''nizin %20''sini feda ederek 10m içindeki tüm müttefiklere anında feda edilen miktarın iki katına eşit bir kalkan verir.', 'Sacrifices 20% of your current HP to instantly grant all allies within 10m a shield equal to double the sacrificed amount.', 'Cross-branch', 56, 480, 3, '{"gof_unyielding_faith", "gof_soul_link"}', '{"x": 822, "y": -474}', '{"sacrifice": "20% HP", "shield_multiplier": "2x", "range": "10m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ddeb0a27-fb7e-45a4-93e2-ac532affaa1c', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_angelic_presence', 'Meleksi Varlık', 'Angelic Presence', '12m''lik bir huşu aurası yayar. Aura içindeki düşmanların saldırılarını ıskalama ihtimali %20''dir.', 'Radiates a 12m aura of awe. Enemies within the aura have a 20% chance to miss their attacks.', 'Sanctuary', 58, 490, 3, '{"gof_sanctified_barrier"}', '{"x": 1414, "y": 1685}', '{"miss_chance": "20%", "range": "12m"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('483645c7-1e47-4aa8-899f-7f31b8e162ed', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_aegis_of_retribution', 'İntikam Himayesi', 'Aegis of Retribution', 'Kalkanlarınızla korunan müttefikler, aldıkları yakın dövüş hasarının %20''sini kutsal hasar olarak saldırgana yansıtır.', 'Allies protected by your shields reflect 20% of received melee damage back to the attacker as holy damage.', 'Divine Aegis', 59, 500, 3, '{"gof_bulwark_of_light"}', '{"x": -1414, "y": 1685}', '{"reflect": "20% melee", "damage_type": "Holy"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('05e25371-1b8b-421a-989c-c63fa797ee08', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_divine_storm', 'İlahi Fırtına', 'Divine Storm', 'Etrafınızda 8m''lik dönen kutsal bir fırtına yaratarak düşmanlara 3d8 kutsal hasar verir ve müttefikleri aynı miktarda iyileştirir.', 'Creates a swirling holy storm 8m around you, dealing 3d8 holy damage to enemies and healing allies for the same amount.', 'Cross-branch', 60, 500, 3, '{"gof_wrath_of_the_heavens", "gof_mass_restoration"}', '{"x": 1039, "y": -599}', '{"damage": "3d8 holy", "healing": "3d8", "range": "8m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8966e105-8675-4aa4-8393-f45486309856', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_heavenly_sword', 'Cennet Kılıcı', 'Heavenly Sword', '10x2m''lik bir hatta yere çakılan devasa uhrevi bir kılıç çağırarak 6d8 kutsal hasar verir ve 2 saniyeliğine sersemletir.', 'Summons a giant ethereal sword that crashes down in a 10x2m line, dealing 6d8 holy damage and stunning for 2s.', 'Faith', 62, 650, 4, '{"gof_crusader_strike"}', '{"x": 2121, "y": -1224}', '{"damage": "6d8 holy", "stun": "2s", "area": "10x2m line"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('380359af-3e25-44d0-a919-e388b5e20c1d', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_sanctuary_of_the_ancients', 'Kadimlerin Sığınağı', 'Sanctuary of the Ancients', '15m yarıçapı 6 saniyeliğine kutsar. İçerideki müttefikler kitle kontrolüne ve olumsuz durum etkilerine karşı tamamen bağışıktır.', 'Blesses a 15m radius for 6s. Allies inside are completely immune to crowd control and negative status effects.', 'Sanctuary', 64, 680, 4, '{"gof_mass_restoration"}', '{"x": 1574, "y": 1876}', '{"range": "15m", "duration": "6s", "immunity": "CC & Debuffs"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('460291d9-1ad2-4d45-9a1b-2ec2a073f6ea', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_impervious_bastion', 'Aşılamaz Tabya', 'Impervious Bastion', '8 saniyeliğine taşınmaz bir nesneye dönüşürsünüz. %90 hasar azaltma kazanırsınız, hareket ettirilemezsiniz ve 15m içindeki tüm düşmanları kışkırtırsınız.', 'Turn into an immovable object for 8s. You gain 90% damage reduction, cannot be moved, and taunt all enemies within 15m.', 'Divine Aegis', 65, 700, 4, '{"gof_soul_link"}', '{"x": -1574, "y": 1876}', '{"reduction": "90%", "duration": "8s", "range": "15m", "taunt": "Yes"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aa01c66e-25d7-46a7-900a-28789f4cc16c', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_fervent_zeal', 'Hararetli Şevk', 'Fervent Zeal', 'Kendinizi 12 saniyeliğine şevkle doldurur. +%30 saldırı hızı, +%20 hareket hızı kazanırsınız ve saldırılarınız yakındaki düşmanlara kutsal hasar sıçratır.', 'Infuses yourself with zeal for 12s. Gain +30% attack speed, +20% movement speed, and your attacks splash holy damage to nearby enemies.', 'Faith', 68, 720, 4, '{"gof_heavenly_sword"}', '{"x": 2338, "y": -1349}', '{"attack_speed": "+30%", "movement_speed": "+20%", "splash_damage": "Yes", "duration": "12s"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('922611b5-52b8-4c99-b9e2-651143ba4800', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_breath_of_life', 'Hayat Nefesi', 'Breath of Life', '5m içinde yeni düşmüş bir müttefike ilahi enerji üfleyerek onları anında maksimum HP''lerinin %30''u ile canlandırır.', 'Breathes divine energy into a recently fallen ally within 5m, reviving them instantly with 30% of their maximum HP.', 'Sanctuary', 72, 780, 4, '{"gof_angelic_presence"}', '{"x": 1735, "y": 2068}', '{"revive": "30% HP", "range": "5m"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('50f977ba-3d56-4639-b8fb-e380df0a84c8', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_wings_of_protection', 'Koruma Kanatları', 'Wings of Protection', '15 saniyeliğine uçmayı sağlayan altın kanatlar çıkarır. Her 3 saniyede bir, 20m içindeki tüm müttefikler yenilenen 100 HP''lik bir kalkan alır.', 'Sprout golden wings for 15s, allowing flight. Every 3s, all allies within 20m receive a refreshing 100 HP shield.', 'Divine Aegis', 74, 820, 4, '{"gof_aegis_of_retribution"}', '{"x": -1735, "y": 2068}', '{"shield": "100 HP every 3s", "flight": "Yes", "range": "20m", "duration": "15s"}', '🪽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('281812b0-5e1b-43f2-98c9-1ddcf90e461f', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_purgatory_flames', 'Araf Alevleri', 'Purgatory Flames', '12m''lik kutsal ateşten bir halka çağırır. İçinden geçen düşmanlar 5d10 hasar alır; içinden geçen müttefikler %30 hareket hızı kazanır.', 'Summons a 12m ring of holy fire. Enemies passing through take 5d10 damage; allies passing through gain 30% movement speed.', 'Cross-branch', 75, 840, 4, '{"gof_fervent_zeal", "gof_sanctuary_of_the_ancients"}', '{"x": 1255, "y": -724}', '{"damage": "5d10 holy", "movement_buff": "+30%", "range": "12m ring"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bab2f46f-e5d6-48d5-900a-b02366108c27', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_divine_execution', 'İlahi İnfaz', 'Divine Execution', '8d10 kutsal hasar veren kudretli bir darbe. Hedef %20 HP''nin altındaysa, bu saldırı tüm zırh ve kalkanları yok sayar.', 'A mighty blow dealing 8d10 holy damage. If the target is below 20% HP, this attack ignores all armor and shields.', 'Faith', 76, 850, 4, '{"gof_fervent_zeal"}', '{"x": 2554, "y": -1474}', '{"damage": "8d10 holy", "execute_threshold": "20% HP", "armor_pierce": "Yes"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3428e7aa-83c4-4ab9-b8a6-752804bcb1ba', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_blessed_communion', 'Kutsanmış Birlik', 'Blessed Communion', 'En fazla 4 müttefikin yaşam gücünü 20 saniyeliğine birbirine bağlar. Bir müttefikin aldığı herhangi bir iyileştirme, diğerlerini bu miktarın %40''ı kadar iyileştirir.', 'Connects the life force of up to 4 allies for 20s. Any healing received by one ally heals the others by 40% of that amount.', 'Sanctuary', 78, 880, 4, '{"gof_sanctuary_of_the_ancients"}', '{"x": 1896, "y": 2259}', '{"targets": "4 allies", "healing_share": "40%", "duration": "20s"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('be12792a-1932-49ff-9609-ac11adfa3e04', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_heavenly_reflection', 'Cennet Yansıması', 'Heavenly Reflection', '1 hedeflenmiş büyüyü orijinal atanına mükemmel bir şekilde geri yansıtan, 4 saniye süren 5m''lik ayna bir kalkan oluşturur.', 'Creates a 5m mirror shield for 4s that perfectly bounces 1 targeted spell back to its original caster.', 'Divine Aegis', 79, 890, 4, '{"gof_impervious_bastion"}', '{"x": -1896, "y": 2259}', '{"reflect": "1 spell", "duration": "4s", "range": "5m"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('77982dc5-7264-4666-a905-8db81e93104a', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_aegis_of_the_fallen', 'Düşmüşlerin Himayesi', 'Aegis of the Fallen', 'Ölümcül hasar aldığınızda, 4 saniyeliğine hasar görmez olursunuz, HP''nizi tamamen yeniler ve kutsal enerjiyle patlarsınız. Uzun dinlenme başına bir kez tetiklenir.', 'When you take fatal damage, become invulnerable for 4s, fully restore your HP, and explode with holy energy. Triggers once per long rest.', 'Cross-branch', 80, 900, 4, '{"gof_divine_execution", "gof_impervious_bastion"}', '{"x": 1472, "y": -849}', '{"invulnerability": "4s", "heal": "100%", "trigger": "Fatal damage"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8026baf7-30bc-49f2-adb0-2841583948ed', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_avatar_of_conquest', 'Fetih Avatarı', 'Avatar of Conquest', '20 saniyeliğine bir savaş avatarına dönüşürsünüz. +%50 kutsal hasar kazanırsınız ve tüm saldırılarınız 5m genişliğinde bir yarma ile vurur.', 'Transform into an avatar of war for 20s. Gain +50% holy damage, and all your attacks strike in a 5m wide cleave.', 'Faith', 85, 1100, 5, '{"gof_divine_execution"}', '{"x": 2771, "y": -1599}', '{"damage_bonus": "+50% holy", "cleave": "5m", "duration": "20s"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fe2c90f2-a8b8-4353-b552-502fbd4856b1', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_eden_garden', 'Cennet Bahçesi', 'Garden of Eden', '15 saniyeliğine 20m''lik bir cennet bölgesi oluşturur. İçerideki müttefikler saniyede %5 maksimum HP iyileşir ve HP''leri 1''in altına düşemez.', 'Creates a 20m paradise zone for 15s. Allies inside heal 5% max HP per second and their HP cannot drop below 1.', 'Sanctuary', 88, 1200, 5, '{"gof_blessed_communion"}', '{"x": 2056, "y": 2451}', '{"healing": "5% max HP/sec", "immortality": "Yes", "duration": "15s", "range": "20m"}', '🏞️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a205b50-24a6-4b4e-949d-e46b1d3732c3', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_shield_of_the_creator', 'Yaratıcının Kalkanı', 'Shield of the Creator', 'Pasif: Maksimum HP''nizin %50''sine eşit kalıcı bir kalkan verir. Çatışma dışındayken saniyede %5 oranında yenilenir.', 'Passive: Grants a permanent shield equal to 50% of your max HP. It regenerates by 5% per second while out of combat.', 'Divine Aegis', 90, 1300, 5, '{"gof_heavenly_reflection"}', '{"x": -2056, "y": 2451}', '{"shield": "50% max HP", "regen": "5%/sec OOC"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3b18d3fb-6737-4cd8-b48a-511c51ca5ca2', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_judgement_day', 'Kıyamet Günü', 'Judgement Day', '20m''lik bir alana çakılan devasa bir ışık çekici çağırarak 15d10 kutsal hasar verir ve zayıf şeytani varlıkları yok eder.', 'Summons a colossal hammer of light that crashes into a 20m area, dealing 15d10 holy damage and obliterating weak unholy entities.', 'Faith', 95, 1400, 5, '{"gof_avatar_of_conquest"}', '{"x": 2987, "y": -1724}', '{"damage": "15d10 holy", "obliterate": "Weak undead", "range": "20m"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33723b41-edda-444e-aee1-b72be28a429f', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_divine_intervention', 'İlahi Müdahale', 'Divine Intervention', 'Savaş alanındaki tüm müttefikleri tamamen iyileştirmek ve arındırmak, tüm büyü yuvalarını yenilemek ve tüm lanetleri kaldırmak için bir tanrıya yakarır.', 'Calls upon a deity to fully heal and cleanse all allies on the battlefield, restoring all their spell slots and removing all curses.', 'Sanctuary', 96, 1450, 5, '{"gof_eden_garden"}', '{"x": 2217, "y": 2642}', '{"heal": "100%", "cleanse": "All", "restore_slots": "Yes", "range": "Global"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5fd44ddb-90f1-4dfa-82e1-9f559b3ab64e', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_absolute_aegis', 'Mutlak Himaye', 'Absolute Aegis', '15 saniyeliğine katı ışıktan devasa 30m''lik bir kubbe diker. Hiçbir düşman giremez ve hiçbir düşman mermisi veya büyüsü içinden geçemez.', 'Erects a massive 30m dome of solid light for 15s. No enemy can enter, and no hostile projectile or spell can pass through.', 'Divine Aegis', 98, 1480, 5, '{"gof_shield_of_the_creator"}', '{"x": -2217, "y": 2642}', '{"dome_size": "30m", "duration": "15s", "impenetrable": "Yes"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f637a79b-c9b0-4786-90c9-d8a2fe08d2df', '6109ccf1-2d81-4d0d-8047-0c027397aa04', 'gof_guardian_of_faith_ascension', 'İnanç Muhafızı Yükselişi', 'Guardian of Faith Ascension', '30 saniyeliğine tanrılığa yükselirsiniz. Tüm auralarınız küresel hale gelir. Müttefikler tamamen hasar görmez olur. Saldırılarınız %300 kutsal hasar verir ve tüm müttefikleri verilen hasar kadar küresel olarak iyileştirir.', 'Ascend to godhood for 30s. All your auras become global. Allies become totally invulnerable. Your attacks deal 300% holy damage and heal all allies globally for the damage dealt.', 'Cross-branch', 100, 1500, 5, '{"gof_judgement_day", "gof_divine_intervention", "gof_absolute_aegis"}', '{"x": 1688, "y": -974}', '{"damage_bonus": "300% holy", "invulnerability": "Allies", "global_auras": "Yes", "duration": "30s"}', '🔱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45594c33-45d0-4439-8c99-8b0bae711b76', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_quick_draw', 'Hızlı Çekim', 'Quick Draw', 'Silahınızı anında çekin. Savaştaki ilk saldırınız fazladan 1d8 hasar verir.', 'Draw your weapon instantly. Your first attack in combat deals an additional 1d8 damage.', 'Rapid Fire', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8", "action": "free"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('070b358b-6922-41fd-8025-78fa4c854d7f', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_double_tap', 'Çifte Vuruş', 'Double Tap', '15m içindeki bir hedefe iki hızlı atış yapın. Her atış 1d6 delici hasar verir.', 'Fire two quick shots at a single target within 15m. Each shot deals 1d6 piercing damage.', 'Rapid Fire', 5, 80, 1, '{"gs_quick_draw"}', '{"x": 389, "y": -224}', '{"damage": "2x 1d6", "range": "15m"}', '✌️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d07eee22-b9e6-4ff5-a2d7-fe378202ca2b', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_fanning_the_hammer', 'Tetik Tokatlama', 'Fanning the Hammer', '5m''lik bir koni içine 6 hızlı atış yapın. Her atış 1d4 delici hasar verir.', 'Unleash up to 6 rapid shots in a 5m cone. Each shot deals 1d4 piercing damage.', 'Rapid Fire', 12, 120, 1, '{"gs_double_tap"}', '{"x": 606, "y": -349}', '{"damage": "6x 1d4", "area": "5m cone"}', '🖐️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d37ddd9-b22c-4e3a-b940-8a0bd75bd0b0', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_hail_of_bullets', 'Mermi Dolusu', 'Hail of Bullets', '10m''lik bir koniye mermi püskürtün. Hedefler 3d6 hasar alır ve hareket hızları 1 tur yarıya iner.', 'Spray bullets in a 10m cone. Targets take 3d6 damage and their movement speed is halved for 1 turn.', 'Rapid Fire', 22, 200, 2, '{"gs_fanning_the_hammer"}', '{"x": 822, "y": -474}', '{"damage": "3d6", "area": "10m cone", "slow": "50%"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7ef73d7b-5215-4cc6-9983-c738253dcfe5', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_suppressive_fire', 'Baskı Ateşi', 'Suppressive Fire', '15m yarıçaplı bir alanı hedef alın. İçerideki düşmanlar yoğun ateş nedeniyle saldırı zarlarında -2 ceza alır.', 'Target a 15m radius area. Enemies within suffer a -2 penalty to their attack rolls due to heavy fire.', 'Rapid Fire', 28, 240, 2, '{"gs_hail_of_bullets"}', '{"x": 1039, "y": -599}', '{"area": "15m radius", "debuff": "-2 Attack"}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29d96a0e-95f3-45c8-b1b1-5c046a6b5a2d', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_rapid_reload', 'Seri Dolduruş', 'Rapid Reload', 'Silahlarınızı serbest eylem olarak anında doldurun ve 2 tur boyunca +%20 saldırı hızı kazanın.', 'Reload your weapons instantly as a free action and gain +20% attack speed for 2 turns.', 'Rapid Fire', 35, 280, 2, '{"gs_suppressive_fire"}', '{"x": 1255, "y": -724}', '{"buff": "+20% Attack Speed", "duration": "2 turns"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49708191-3129-4f90-adca-c6a08b03a787', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_bullet_storm', 'Mermi Fırtınası', 'Bullet Storm', '15m yarıçap içindeki en fazla 8 hedefe aynı anda ateş ederek her birine 2d8 hasar verin.', 'Simultaneously shoot up to 8 targets within a 15m radius, dealing 2d8 damage to each.', 'Rapid Fire', 42, 380, 3, '{"gs_rapid_reload"}', '{"x": 1472, "y": -849}', '{"damage": "2d8 per target", "area": "15m radius"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3f7de60-5724-4440-a21c-3d02ba0b011a', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_relentless_assault', 'Aralıksız Saldırı', 'Relentless Assault', 'Aynı hedefe yapılan her ardışık isabet, bir sonraki atışa +1d6 hasar ekler.', 'Each consecutive hit on the same target adds +1d6 damage to the next shot.', 'Rapid Fire', 48, 420, 3, '{"gs_bullet_storm"}', '{"x": 1688, "y": -974}', '{"buff": "+1d6 Damage per hit"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c428506d-8e1e-403a-b828-00ae839d8d77', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_akimbo_fury', 'Çifte Öfke', 'Akimbo Fury', 'Çifte silah ustalığı size 3 tur boyunca +%30 saldırı hızı ve +%10 kritik vuruş şansı sağlar.', 'Mastery of dual wielding grants you +30% attack speed and +10% critical strike chance for 3 turns.', 'Rapid Fire', 55, 480, 3, '{"gs_relentless_assault"}', '{"x": 1905, "y": -1099}', '{"buff": "+30% Attack Speed, +10% Crit", "duration": "3 turns"}', '🔫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('567fbeec-4115-402a-8c54-210f7905b1c4', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_lead_rain', 'Kurşun Yağmuru', 'Lead Rain', 'Devasa bir 20m koni içine kurşun yağdırarak içerideki herkese 6d6 delici hasar verin.', 'Rain down bullets in a massive 20m cone, dealing 6d6 piercing damage to all caught inside.', 'Rapid Fire', 62, 650, 4, '{"gs_akimbo_fury"}', '{"x": 2121, "y": -1224}', '{"damage": "6d6", "area": "20m cone"}', '☔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cdb35b54-1496-4da3-b876-5531340be474', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_execution_volley', 'İnfaz Yaylımı', 'Execution Volley', '%30 HP altındaki tek bir hedefe 4 ölümcül atış yapın. Her atış 2d10 hasar verir.', 'Fire 4 lethal shots at a single target below 30% HP. Each shot deals 2d10 damage.', 'Rapid Fire', 70, 750, 4, '{"gs_lead_rain"}', '{"x": 2338, "y": -1349}', '{"damage": "4x 2d10", "condition": "Target <30% HP"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('562f1811-e7eb-4f8e-ac15-a6f8ee3e08a1', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_frenzy_fire', 'Çılgın Ateş', 'Frenzy Fire', '3 tur boyunca her eylem için 3 saldırı kazanın, ancak isabetliliğiniz %10 azalır.', 'Gain 3 attacks per action for 3 turns, but your accuracy is reduced by 10%.', 'Rapid Fire', 78, 850, 4, '{"gs_execution_volley"}', '{"x": 2554, "y": -1474}', '{"buff": "3 attacks per action", "debuff": "-10% Accuracy", "duration": "3 turns"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48309b32-8051-4543-965e-e8380db11efd', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_showdown', 'Büyük Hesaplaşma', 'Showdown', 'Ulti. 30m yarıçap içindeki tüm düşmanlara anında 12 yıkıcı atış yapın. Her atış 3d10 hasar verir.', 'Ultimate. Instantly fire 12 devastating shots at all enemies within a 30m radius. Each shot deals 3d10 damage.', 'Rapid Fire', 90, 1200, 5, '{"gs_frenzy_fire"}', '{"x": 2771, "y": -1599}', '{"damage": "12x 3d10", "area": "30m radius"}', '🤠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('968df0c5-f3e3-4e1b-b075-87113c510057', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_ricochet_shot', 'Seken Atış', 'Ricochet Shot', 'Hedeften 5m içindeki 1 ek düşmana seken bir mermi ateşleyin. İkisine de 1d8 hasar verir.', 'Fire a bullet that bounces from the target to 1 additional enemy within 5m. Deals 1d8 damage to both.', 'Trick Shot', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8", "bounce": "1 target within 5m"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('208f91f8-886f-4c95-b8e7-fab7306e9e1d', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_knee_capper', 'Diz Kırıcı', 'Knee Capper', 'Bacaklara nişan alarak 1d10 hasar verin ve hedefin hızını 2 tur boyunca %50 azaltın.', 'Aim for the legs, dealing 1d10 damage and reducing the target''s speed by 50% for 2 turns.', 'Trick Shot', 6, 90, 1, '{"gs_ricochet_shot"}', '{"x": 289, "y": 344}', '{"damage": "1d10", "slow": "50%", "duration": "2 turns"}', '🦵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('116f262f-0cb8-4c5a-b808-42b39e7e372d', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_piercing_bullet', 'Delici Kurşun', 'Piercing Bullet', 'Tüm düşmanların içinden geçen 20m''lik bir hatta yüksek hızlı bir mermi ateşleyerek 2d6 hasar verin.', 'Fire a high-velocity round in a 20m line that passes through all enemies, dealing 2d6 damage.', 'Trick Shot', 14, 130, 1, '{"gs_knee_capper"}', '{"x": 449, "y": 536}', '{"damage": "2d6", "area": "20m line"}', '🧵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e9d6ff6-97d0-48cf-b85a-5a4cb1bfb47e', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_disarming_shot', 'Silah Düşüren Atış', 'Disarming Shot', '2d8 hasar veren ve hedefi silahını düşürmeye veya 1 tur boyunca %30 hasar kaybetmeye zorlayan hassas bir atış.', 'A precision shot that deals 2d8 damage and forces the target to drop their weapon or lose 30% damage for 1 turn.', 'Trick Shot', 24, 210, 2, '{"gs_piercing_bullet"}', '{"x": 610, "y": 727}', '{"damage": "2d8", "debuff": "Disarm or -30% Damage"}', '🧤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4aa61d6e-ceba-4dfc-a58a-509a024e485f', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_explosive_round', 'Patlayıcı Mermi', 'Explosive Round', '5m yarıçapında patlayan özel bir mermi ateşleyerek 3d6 ateş hasarı verin.', 'Fire a specialized bullet that detonates in a 5m radius, dealing 3d6 fire damage.', 'Trick Shot', 30, 250, 2, '{"gs_disarming_shot"}', '{"x": 771, "y": 919}', '{"damage": "3d6 Fire", "area": "5m radius"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b19968c-43e4-43f7-8569-e10fc13a6e46', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_blind_fire', 'Kör Ateş', 'Blind Fire', 'Bakmadan siperden ateş edin. Siper AC bonuslarının %50''sini yok sayar ve 2d8 hasar verir.', 'Shoot from cover without looking. Ignores 50% of cover AC bonuses and deals 2d8 damage.', 'Trick Shot', 36, 290, 2, '{"gs_explosive_round"}', '{"x": 932, "y": 1110}', '{"damage": "2d8", "bypass": "50% Cover"}', '🙈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fecc9bda-ce0e-4b47-828b-30fd1e4df38c', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_heart_seeker', 'Kalp Arayan', 'Heart Seeker', 'Hedefin zırhını tamamen yok sayan, hesaplanmış bir atış, 4d6 delici hasar verir.', 'A calculated shot that completely ignores the target''s armor, dealing 4d6 piercing damage.', 'Trick Shot', 44, 400, 3, '{"gs_blind_fire"}', '{"x": 1092, "y": 1302}', '{"damage": "4d6", "bypass": "Armor"}', '💘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6a364081-ee68-4b9c-b330-00b5cb195a81', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_shrapnel_burst', 'Şarapnel Patlaması', 'Shrapnel Burst', 'Mermi havada parçalanarak 15m''lik bir koniye dağılır, 4d8 delici hasar ve kanama (1d6/tur) verir.', 'The bullet shatters mid-air into a 15m cone, dealing 4d8 piercing damage and causing bleeding (1d6/turn).', 'Trick Shot', 50, 440, 3, '{"gs_heart_seeker"}', '{"x": 1253, "y": 1493}', '{"damage": "4d8", "area": "15m cone", "dot": "1d6 Bleed"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b62a637e-0a16-4ec0-addd-94c3b2984cdd', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_chain_reaction', 'Zincirleme Reaksiyon', 'Chain Reaction', 'Birbirinden 10m uzaklıktaki hedefler arasında 4 defaya kadar seken, her sekmede +1d6 hasar kazanan hileli bir atış.', 'A trick shot that ricochets up to 4 times between targets within 10m of each other, gaining +1d6 damage per bounce.', 'Trick Shot', 58, 490, 3, '{"gs_shrapnel_burst"}', '{"x": 1414, "y": 1685}', '{"bounce": "4 targets", "damage_scaling": "+1d6 per bounce"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c8747f2-3d88-406d-8f6c-825b5b600bd7', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_fatal_rebound', 'Ölümcül Sekiş', 'Fatal Rebound', 'Kör noktasındaki bir düşmanı mükemmel şekilde vurmak için mermiyi 3 duvardan sektirerek 6d8 hasar veren otomatik bir kritik vuruş yapın.', 'Bounce a bullet off 3 walls to hit an enemy perfectly in their blind spot for an automatic critical hit dealing 6d8 damage.', 'Trick Shot', 64, 680, 4, '{"gs_chain_reaction"}', '{"x": 1574, "y": 1876}', '{"damage": "6d8", "guarantee": "Critical Hit"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f272c2c-34e6-4191-941b-19bf36a1e694', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_dead_eye', 'Ölü Gözü', 'Dead Eye', 'Bir sonraki menzilli saldırınız %100 kritik şansı kazanır ve kritik hasar çarpanı iki katına çıkar.', 'Your next ranged attack gains 100% critical chance and its critical damage multiplier is doubled.', 'Trick Shot', 72, 780, 4, '{"gs_fatal_rebound"}', '{"x": 1735, "y": 2068}', '{"buff": "100% Crit, 2x Crit Multiplier"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('44aaee55-daa0-4bd8-a83e-04cb56eb1abb', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_incendiary_shot', 'Kundakçı Atışı', 'Incendiary Shot', '4d10 hasar veren ve hedefi 3 tur boyunca tur başına 2d6 yanık hasarıyla ateşe veren aşırı ısınmış bir mermi ateşleyin.', 'Fire a super-heated bullet that deals 4d10 damage and sets the target ablaze for 2d6 burn damage per turn for 3 turns.', 'Trick Shot', 76, 820, 4, '{"gs_dead_eye"}', '{"x": 1896, "y": 2259}', '{"damage": "4d10", "dot": "2d6 Burn", "duration": "3 turns"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('997f8501-d347-48bd-b4f3-3f929c113953', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_bullet_time', 'Mermi Zamanı', 'Bullet Time', 'Ulti. Zaman 2 tur boyunca büyük ölçüde yavaşlar. Tur başına 2 ekstra eylem kazanırsınız ve menzilli saldırılarınız otomatik olarak isabet eder.', 'Ultimate. Time drastically slows for 2 turns. You gain 2 extra actions per turn, and your ranged attacks automatically hit.', 'Trick Shot', 90, 1200, 5, '{"gs_incendiary_shot"}', '{"x": 2056, "y": 2451}', '{"buff": "+2 Actions, Auto-hit", "duration": "2 turns"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('92bbfe79-38d5-4019-88b7-3dc2461009e1', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_combat_roll', 'Savaş Taklası', 'Combat Roll', 'Fırsat saldırılarını kışkırtmadan 5m''ye kadar takla atın. Bir sonraki saldırınız avantaj kazanır.', 'Roll up to 5m without provoking opportunity attacks. Your next attack gains advantage.', 'Agility', 3, 70, 1, '{}', '{"x": -128, "y": 153}', '{"movement": "5m", "buff": "Advantage"}', '🤸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4f949d4-c15e-41b1-ba5c-9c7b688ee448', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_evasive_maneuver', 'Kaçınma Manevrası', 'Evasive Maneuver', 'Reflekslerinizi güçlendirerek 2 tur boyunca +3 AC ve +%10 kaçınma şansı kazanın.', 'Heighten your reflexes, gaining +3 AC and +10% dodge chance for 2 turns.', 'Agility', 8, 100, 1, '{"gs_combat_roll"}', '{"x": -289, "y": 344}', '{"buff": "+3 AC, +10% Dodge", "duration": "2 turns"}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31a1652f-37ed-4476-b969-66ed8085426f', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_quick_step', 'Hızlı Adım', 'Quick Step', 'Hareket hızınızı 3 tur boyunca 10m artırarak sizi kaygan bir hedef haline getirir.', 'Increase your movement speed by 10m for 3 turns, making you a slippery target.', 'Agility', 16, 140, 1, '{"gs_evasive_maneuver"}', '{"x": -449, "y": 536}', '{"buff": "+10m Speed", "duration": "3 turns"}', '👟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f129b133-8838-46f5-94fc-3f91bb6968fe', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_sidestep', 'Yana Kayma', 'Sidestep', 'Gelen bir menzilli saldırıdan %75 başarı oranıyla tamamen kaçınmak için tepkinizi kullanın.', 'Use your reaction to completely dodge an incoming ranged attack with a 75% success rate.', 'Agility', 26, 220, 2, '{"gs_quick_step"}', '{"x": -610, "y": 727}', '{"action": "Reaction", "dodge_chance": "75%"}', '🚶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fec6d961-9c23-4b9e-ad4a-74dc26c4f8ca', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_dash_and_shoot', 'Atıl ve Vur', 'Dash and Shoot', 'Hızınız kadar hareket edin ve hareket sırasında herhangi bir noktada ateş ederek 2d8 hasar verin.', 'Move up to your speed and fire a shot at any point during the movement, dealing 2d8 damage.', 'Agility', 32, 260, 2, '{"gs_sidestep"}', '{"x": -771, "y": 919}', '{"movement": "Speed", "damage": "2d8"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7e75776d-3032-46f6-ac54-930e5d0b5fc9', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_smoke_screen', 'Sis Perdesi', 'Smoke Screen', '10m''lik bir bulut oluşturan ve 3 tur boyunca yoğun gizlenme sağlayan bir sis bombası atın.', 'Throw a smoke bomb that creates a 10m cloud, granting heavy obscurement for 3 turns.', 'Agility', 38, 300, 2, '{"gs_dash_and_shoot"}', '{"x": -932, "y": 1110}', '{"area": "10m radius", "buff": "Heavy Obscurement", "duration": "3 turns"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2aa4c72a-9152-42d6-9ac7-f1c9bae506ff', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_phantom_dodge', 'Hayalet Kaçışı', 'Phantom Dodge', '3 tur boyunca, tamamen faz dışı kalıp gelen herhangi bir saldırıyı boşa çıkarma şansınız %30''dur.', 'For 3 turns, you have a 30% chance to completely phase out and negate any incoming attack.', 'Agility', 46, 410, 3, '{"gs_smoke_screen"}', '{"x": -1092, "y": 1302}', '{"buff": "30% Negate Attack", "duration": "3 turns"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7f95cfa3-0064-4b78-8297-41ae07c57f85', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_return_fire', 'Karşı Ateş', 'Return Fire', 'Bir düşman size yaptığı saldırıyı ıskaladığında, tepki kullanarak onu anında vurup 3d6 hasar verebilirsiniz.', 'When an enemy misses you with an attack, you can use a reaction to instantly shoot them for 3d6 damage.', 'Agility', 52, 450, 3, '{"gs_phantom_dodge"}', '{"x": -1253, "y": 1493}', '{"action": "Reaction", "damage": "3d6"}', '🔙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0332ec0-644e-4777-bd85-a64626781051', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_adrenaline_rush', 'Adrenalin Patlaması', 'Adrenaline Rush', 'Maksimum HP''nizin %20''sini iyileştirin ve hareketi kısıtlayan tüm etkileri anında temizleyin.', 'Heal for 20% of your maximum HP and instantly clear all movement-impairing effects.', 'Agility', 60, 500, 3, '{"gs_return_fire"}', '{"x": -1414, "y": 1685}', '{"heal": "20% Max HP", "cleanse": "Movement Impairments"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b6ec45b0-4195-412a-8f0d-5f0d37bd76fd', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_mirage_step', 'Serap Adımı', 'Mirage Step', '15m''ye kadar ışınlanın ve arkanızda düşmanların dikkatini dağıtan kafa karıştırıcı bir görüntü bırakın.', 'Teleport up to 15m, leaving behind a confusing afterimage that distracts enemies.', 'Agility', 66, 700, 4, '{"gs_adrenaline_rush"}', '{"x": -1574, "y": 1876}', '{"movement": "15m Teleport", "summon": "Afterimage Decoy"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3a701ef-2431-4a5d-8f9f-767e2866d04d', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_untouchable', 'Dokunulmaz', 'Untouchable', '1 tur boyunca tüm menzilli saldırılara ve alan etkili hasara karşı tamamen bağışık olun.', 'Become completely immune to all ranged attacks and area-of-effect damage for 1 turn.', 'Agility', 74, 800, 4, '{"gs_mirage_step"}', '{"x": -1735, "y": 2068}', '{"buff": "Immune to Ranged/AoE", "duration": "1 turn"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74a6ae38-3aba-49a9-bf0a-ef3232da1a7f', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_gun_fu', 'Silah Sanatı', 'Gun Fu', 'Menzilli saldırılarınız yakın dövüş mesafesinde artık dezavantaj çekmez ve 3m içindeki düşmanlara +4d6 bonus hasar verirsiniz.', 'Your ranged attacks no longer suffer disadvantage in melee range, and you deal +4d6 bonus damage to enemies within 3m.', 'Agility', 80, 900, 4, '{"gs_untouchable"}', '{"x": -1896, "y": 2259}', '{"buff": "No melee penalty, +4d6 damage within 3m"}', '🥋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d9c3f1e-cb7b-4834-aeb2-f24e40300c0a', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_western_wind', 'Batı Rüzgarı', 'Western Wind', 'Ulti. 3 tur boyunca hareket hızınız iki katına çıkar, her tur ilk 3 saldırıdan otomatik olarak kaçınırsınız ve doldurma anında gerçekleşir.', 'Ultimate. For 3 turns, your movement speed is doubled, you automatically dodge the first 3 attacks each turn, and reloading is instantaneous.', 'Agility', 90, 1200, 5, '{"gs_gun_fu"}', '{"x": -2056, "y": 2451}', '{"buff": "2x Speed, 3 Auto-dodges/turn", "duration": "3 turns"}', '🌵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('991e53aa-1161-40b3-93c7-a4c5e0c5da5f', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_sliding_shot', 'Kayan Atış', 'Sliding Shot', 'Agresif bir şekilde 8m''ye kadar kayın ve kayma sırasında 2 hızlı atış yapın. 2x 2d6 hasar verir.', 'Slide aggressively up to 8m and fire 2 quick shots during the slide. Deals 2x 2d6 damage.', 'Cross-Branch', 28, 250, 2, '{"gs_combat_roll", "gs_double_tap"}', '{"x": -173, "y": -100}', '{"movement": "8m Slide", "damage": "2x 2d6"}', '🏂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70f44c63-1fd1-4602-b410-a4505eeb4b34', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_vaulting_trick', 'Atlama Hilesi', 'Vaulting Trick', 'Bir engelin üzerinden dinamik bir şekilde atlarken 2 hedefe 3d6 hasar veren seken bir mermi ateşleyin.', 'Leap dynamically over an obstacle while firing a ricocheting bullet that deals 3d6 damage to 2 targets.', 'Cross-Branch', 35, 280, 2, '{"gs_evasive_maneuver", "gs_ricochet_shot"}', '{"x": -389, "y": -225}', '{"damage": "3d6", "targets": "2"}', '🦘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f7d28d4-98f2-45b8-8dfb-f007a1df5084', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_running_gunner', 'Koşan Nişancı', 'Running Gunner', 'Yolunuz etrafındaki 10m yarıçapa baskı ateşi püskürterek 15m koşun ve 3d8 hasar verin.', 'Sprint 15m while spraying suppressive fire in a 10m radius around your path, dealing 3d8 damage.', 'Cross-Branch', 45, 420, 3, '{"gs_suppressive_fire", "gs_dash_and_shoot"}', '{"x": -606, "y": -350}', '{"movement": "15m Sprint", "damage": "3d8", "area": "10m radius around path"}', '🏇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2eed6999-56bb-4cee-9939-ef1f6bfe31e0', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_scatter_shot', 'Saçmalı Atış', 'Scatter Shot', '15m''lik bir koni içinde mini patlayıcılara dönüşen özel bir fişek ateşleyerek 4d6 ateş ve delici hasar verin.', 'Fire a customized shell that breaks into mini-explosives in a 15m cone, dealing 4d6 fire and piercing damage.', 'Cross-Branch', 55, 480, 3, '{"gs_explosive_round", "gs_hail_of_bullets"}', '{"x": -822, "y": -475}', '{"damage": "4d6 Fire/Piercing", "area": "15m cone"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('78599e82-fd35-4adc-9694-da4167eab2e0', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_acrobatic_ricochet', 'Akrobatik Sekme', 'Acrobatic Ricochet', 'Kaçınmak için geriye doğru takla atın ve 5 kez sekerek vuruş başına 2d8 hasar veren hileli bir mermi ateşleyin.', 'Perform a backflip to dodge and fire a trick bullet that ricochets 5 times, dealing 2d8 damage per hit.', 'Cross-Branch', 58, 490, 3, '{"gs_phantom_dodge", "gs_chain_reaction"}', '{"x": -1039, "y": -600}', '{"movement": "5m Flip", "damage": "5x 2d8"}', '🎪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e7f62dc7-6a97-4b43-9ef1-60aa7529e056', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_dance_of_death', 'Ölüm Dansı', 'Dance of Death', 'Size saldıran herhangi bir düşmana otomatik olarak karşılık vererek tepki başına 3d10 hasar verdiğiniz 2 turluk bir transa girin.', 'Enter a trance for 2 turns where you automatically fire back at any enemy that attacks you, dealing 3d10 damage per reaction.', 'Cross-Branch', 65, 700, 4, '{"gs_bullet_storm", "gs_return_fire"}', '{"x": -1255, "y": -725}', '{"buff": "Auto-counter attacks", "damage": "3d10 per counter", "duration": "2 turns"}', '💃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a9c76251-222c-455a-91d5-05b33354a7fe', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_focused_fury', 'Odaklanmış Öfke', 'Focused Fury', 'Saldırganlığınızı kusursuz bir isabetliliğe kanalize edin. Sonraki 2 saldırınız 5d8 hasar veren garantili kritik vuruşlardır.', 'Channel your aggression into pristine accuracy. Your next 2 attacks are guaranteed critical hits dealing 5d8 damage.', 'Cross-Branch', 75, 820, 4, '{"gs_dead_eye", "gs_akimbo_fury"}', '{"x": -1472, "y": -850}', '{"damage": "2x 5d8", "guarantee": "Critical Hits"}', '😡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4f4310d6-b349-4e91-9340-25c63f934efe', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_shadow_bullet', 'Gölge Kurşun', 'Shadow Bullet', 'Bir sis perdesinin içinden 6d8 hasar veren ve büyülü kalkanları tamamen atlayan gizli, zırh delici bir atış yapın.', 'Fire a covert, armor-piercing shot from within a smokescreen that deals 6d8 damage and entirely bypasses magical shields.', 'Cross-Branch', 78, 860, 4, '{"gs_smoke_screen", "gs_heart_seeker"}', '{"x": -1688, "y": -975}', '{"damage": "6d8", "bypass": "Shields & Armor"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a1b65b90-0e90-40e5-abc0-526af478b321', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_desperado_tactics', 'Eşkıya Taktikleri', 'Desperado Tactics', '20m''lik bir alan içindeki rastgele 3 yere ışınlanın ve her birinden 4d8 hasar veren güçlü bir delici atış yapın.', 'Teleport to 3 random locations within a 20m area, firing a powerful piercing shot from each that deals 4d8 damage.', 'Cross-Branch', 85, 1100, 4, '{"gs_lead_rain", "gs_fatal_rebound", "gs_mirage_step"}', '{"x": -1905, "y": -1100}', '{"movement": "3x Teleports", "damage": "3x 4d8"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d05d15e6-8de6-421f-a36d-ce42247487f8', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_high_noon', 'Tam Öğle Vakti', 'High Noon', 'Güneş göz kamaştırır. 50m içinde 6''ya kadar düşmanı hedef alın. 10d10 hasar alırlar veya küçük düşmanlarsa anında öldürülürler.', 'The sun glares down. Target up to 6 enemies within 50m. They take 10d10 damage, or are instantly killed if they are minor foes.', 'Cross-Branch', 95, 1400, 5, '{"gs_incendiary_shot", "gs_execution_volley", "gs_gun_fu"}', '{"x": -2121, "y": -1225}', '{"damage": "10d10", "targets": "6", "special": "Instant kill minor foes"}', '🕛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48e2644b-8ed4-4dd8-87e5-78f943710ee9', '3fd26916-b2ef-4914-8bf5-3f75c8518a64', 'gs_gunslingers_requiem', 'Silahşorun Ağıtı', 'Gunslinger''s Requiem', 'Görkemli Ulti. Zaman donar. 60m içindeki düşmanlara dağıtılarak her biri 4d10 hasar veren 24 ruhani atış serbest bırakın. Zamanın devam etmesi hayatta kalanları 1 tur sersemletir.', 'Grand Ultimate. Time freezes. Unleash 24 ethereal shots dealing 4d10 damage each, distributed among enemies within 60m. Resuming time stuns survivors for 1 turn.', 'Cross-Branch', 100, 1500, 5, '{"gs_showdown", "gs_bullet_time", "gs_western_wind"}', '{"x": -2338, "y": -1350}', '{"damage": "24x 4d10", "area": "60m radius", "debuff": "Stun", "duration": "1 turn"}', '🪦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0de52c9f-34f4-440f-afd3-b1ea067a73e5', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_imp', 'Küçük İblis', 'Minor Imp', 'Çatışmada size yardım etmesi için küçük bir iblis çağırır.', 'Summons a minor imp to aid you in combat.', 'Demon', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"health": 20, "damage": "1d6 piercing", "range": "10m"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee5b9a38-c501-49e7-b616-3914d1d94303', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_claws', 'İblis Pençeleri', 'Demonic Claws', 'Ellerinizde iblis pençeleri oluşturarak düşmanları biçmenizi sağlar.', 'Manifests demonic claws on your hands, allowing you to slash enemies.', 'Demon', 5, 75, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "2d6 slashing", "range": "2m"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0222fe9-a100-457b-a6ff-5ba4ae0c9353', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_vigor', 'Şeytani Zindelik', 'Fiendish Vigor', 'Kendinize geçici sağlık puanı sağlamak için hiçlik enerjisine kanalize olursunuz.', 'Channel abyssal energy to grant yourself temporary hit points.', 'Demon', 10, 100, 1, '{"hb_demon_imp"}', '{"x": 606, "y": -349}', '{"temp_hp": "2d8", "duration": "1 hour"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('54184cc1-2733-48d3-9b6f-f39ed4ac8a18', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_sight', 'Hiçlik Görüşü', 'Abyssal Sight', 'Hem normal hem de büyülü karanlıkta kusursuz görmenizi sağlar.', 'Allows you to see perfectly in both normal and magical darkness.', 'Demon', 15, 120, 1, '{"hb_demon_claws"}', '{"x": 822, "y": -474}', '{"range": "30m", "duration": "8 hours"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('671d3bc6-7386-4753-9b7f-880905f3effc', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_hellhound', 'Cehennem Tazısı Çağrısı', 'Summon Hellhound', 'Ateş püskürten ve düşmanları ısıran vahşi bir cehennem tazısı çağırır.', 'Calls forth a ferocious hellhound that breathes fire and bites enemies.', 'Demon', 22, 200, 2, '{"hb_demon_vigor"}', '{"x": 1039, "y": -599}', '{"health": 45, "damage": "2d6+2 fire", "duration": "1 hour"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('367e9776-dc7a-4652-a438-880b1ac2a977', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_command', 'İblis Emri', 'Command Demon', 'Çağrılmış veya düşman bir iblisi tek kelimelik emrinize uymaya zorlarsınız.', 'Force a summoned or hostile demon to obey your single word command.', 'Demon', 28, 225, 2, '{"hb_demon_sight"}', '{"x": 1255, "y": -724}', '{"range": "20m", "save": "Wisdom"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3ffcf594-4c1d-4a09-823d-31895dfe6f9f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_shield', 'İblis Kalkanı', 'Demonic Shield', 'Sizi şeytani enerjiden oluşan spektral bir kalkanla sararak savunmanızı artırır.', 'Surrounds you with a spectral shield of demonic energy, increasing your defense.', 'Demon', 34, 250, 2, '{"hb_demon_hellhound"}', '{"x": 1472, "y": -849}', '{"ac_bonus": "+3", "duration": "10 mins"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('746acef7-e741-488f-90e5-7d94fcd82140', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_blood_sacrifice', 'Kan Adağı', 'Blood Sacrifice', 'Kendi sağlığınızı feda ederek çağırdığınız iblisleri cinnetle güçlendirirsiniz.', 'Sacrifice your own health to empower your summoned demons with frenzy.', 'Demon', 38, 275, 2, '{"hb_demon_hellhound"}', '{"x": 1688, "y": -974}', '{"hp_cost": 10, "summon_damage_bonus": "+2d6", "duration": "1 min"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('11b57f60-85c4-4460-b5e9-ee8aae2f53b1', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_succubus', 'Succubus Çağrısı', 'Summon Succubus', 'Düşmanlarınızı manipüle etmek ve tüketmek için çekici bir succubus veya incubus çağırır.', 'Summons a charming succubus or incubus to manipulate and drain your foes.', 'Demon', 45, 350, 3, '{"hb_demon_shield"}', '{"x": 1905, "y": -1099}', '{"health": 60, "charm_chance": "40%", "duration": "2 hours"}', '💋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d12a3ba-8d45-49a9-8501-7f25f7e4e76c', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_wings', 'İblis Kanatları', 'Demonic Wings', 'Sırtınızdan yarasa benzeri deri kanatlar çıkararak uçmanızı sağlar.', 'Sprout leathery, bat-like wings from your back, granting you flight.', 'Demon', 50, 400, 3, '{"hb_demon_blood_sacrifice"}', '{"x": 2121, "y": -1224}', '{"fly_speed": "15m", "duration": "10 mins"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e18ff6c-134a-4cf9-9dee-034f0c174d21', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_rift', 'Hiçlik Yarığı', 'Abyssal Rift', 'Hiçliğe bir yarık açarak sürekli küçük iblislerin ortaya çıkmasını sağlar.', 'Tears open a rift to the abyss, constantly spawning lesser demons.', 'Demon', 58, 450, 3, '{"hb_demon_succubus"}', '{"x": 2338, "y": -1349}', '{"spawn_rate": "1 demon/turn", "max_demons": 3, "duration": "5 mins", "range": "15m"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('305f8576-ab3d-4857-856f-13e26de54b02', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_pit_fiend', 'Çukur İblisi Çağrısı', 'Summon Pit Fiend', 'Muazzam bir güce sahip yüksek rütbeli bir şeytan olan çukur iblisi çağırır.', 'Summons a terrifying pit fiend, a high-ranking devil of immense power.', 'Demon', 65, 650, 4, '{"hb_demon_rift"}', '{"x": 2554, "y": -1474}', '{"health": 150, "damage": "4d10+5 fire/slashing", "duration": "1 hour"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3bb3f803-a826-4dd2-9234-29cac4aafd28', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_legions_call', 'Lejyonun Çağrısı', 'Legion''s Call', 'Savaş alanına küçük bir şeytan ordusu çağırmak için şeytani bir borazan çalarsınız.', 'Blow a demonic horn to summon a small army of fiends to the battlefield.', 'Demon', 75, 800, 4, '{"hb_demon_pit_fiend", "hb_demon_wings"}', '{"x": 2771, "y": -1599}', '{"summons": 10, "demon_type": "Minor Fiends", "duration": "10 mins", "range": "30m"}', '📯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('78245b4b-0665-4883-9f97-ca9dd3eb9eee', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_demon_ultimate', 'İblis Lordunun Avatarı', 'Demon Lord''s Avatar', 'Bir İblis Lordunun bedeni haline gelerek kıyametvari bir boyuta, sağlığa ve yıkıcı şeytani saldırılara sahip olursunuz.', 'Become the vessel for a Demon Lord, gaining apocalyptic size, health, and devastating demonic attacks.', 'Demon', 90, 1200, 5, '{"hb_demon_legions_call"}', '{"x": 2987, "y": -1724}', '{"health_bonus": 300, "damage": "8d10 necrotic/fire", "duration": "10 mins"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74e57bed-a777-41a2-9cd5-998df19fca8f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_ignite', 'Cehennem Tutuşması', 'Hellish Ignite', 'Hedefi anında kutsal olmayan alevlerle tutuşturmak için parmaklarınızı şıklatırsınız.', 'Snaps your fingers to instantly ignite a target in unholy flames.', 'Hellfire', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8 fire", "range": "15m"}', '🕯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('051bdb99-a7b0-4d8e-9ae8-5b7c064898ab', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_rebuke', 'Cehennem Azarı', 'Hellish Rebuke', 'Darbe aldığınızda, saldıran kişiye anında bir cehennem ateşi patlamasıyla karşılık verirsiniz.', 'When struck, you instantly lash out with a burst of hellfire at your attacker.', 'Hellfire', 5, 75, 1, '{}', '{"x": 289, "y": 344}', '{"damage": "2d10 fire", "range": "15m", "trigger": "Reaction"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7e01361d-d13b-4344-aa29-e02e80cb432b', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_embers', 'Kükürt Közleri', 'Brimstone Embers', 'Yere yanan kükürtler saçar, üzerine basan herkesi yakar.', 'Scatters burning brimstone on the ground, burning anyone who steps on it.', 'Hellfire', 10, 100, 1, '{"hb_fire_ignite"}', '{"x": 449, "y": 536}', '{"damage": "1d6 fire/turn", "radius": "5m", "duration": "1 min"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('88c47ffa-faf2-4c94-9e19-248bc7177b6f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_ray', 'Kavurucu Işın', 'Scorching Ray', 'Düşmanlarınıza birden fazla yoğunlaştırılmış cehennem ateşi ışını fırlatır.', 'Fires multiple beams of concentrated hellfire at your enemies.', 'Hellfire', 15, 120, 1, '{"hb_fire_rebuke"}', '{"x": 610, "y": 727}', '{"damage": "3x 2d6 fire", "range": "30m"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a2a62da-1662-49c8-8bec-6d2e3da55bc4', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_wall', 'Cehennem Ateşi Duvarı', 'Hellfire Wall', 'İçinden geçen herkesi yakan, karanlık ateşten kavurucu bir duvar oluşturur.', 'Creates a blazing wall of dark fire that sears anyone passing through.', 'Hellfire', 22, 200, 2, '{"hb_fire_embers"}', '{"x": 771, "y": 919}', '{"damage": "4d8 fire", "length": "15m", "duration": "1 min"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1bcddd87-2502-4117-ad50-677943cb901f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_chains', 'Cehennem Zincirleri', 'Infernal Chains', 'Hedefi yanan demir zincirlerle sararak hareketlerini kısıtlar ve onları kavurur.', 'Wraps the target in burning iron chains, restricting their movement and roasting them.', 'Hellfire', 28, 225, 2, '{"hb_fire_ray"}', '{"x": 932, "y": 1110}', '{"damage": "2d6 fire/turn", "range": "15m", "condition": "Restrained", "duration": "1 min"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6da6d433-d5c6-456e-891b-4f64b0006826', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_rain', 'Kükürt Yağmuru', 'Brimstone Rain', 'Geniş bir alana yanan meteorlardan oluşan bir sağanak indirir.', 'Calls down a shower of burning meteors over a wide area.', 'Hellfire', 34, 250, 2, '{"hb_fire_wall"}', '{"x": 1092, "y": 1302}', '{"damage": "3d8 fire", "radius": "10m", "range": "40m"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e9b32e1-f696-4235-aedf-2dac617a8d2a', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_breath', 'Kül Nefesi', 'Ashen Breath', 'Boğucu bir kül ve karanlık ateş konisi üflersiniz.', 'Exhale a cone of suffocating ash and dark fire.', 'Hellfire', 38, 275, 2, '{"hb_fire_chains"}', '{"x": 1253, "y": 1493}', '{"damage": "4d6 fire", "cone": "10m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f55906ee-1598-4cd5-a01b-bdea3c50f013', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_blast', 'Cehennem Ateşi Patlaması', 'Hellfire Blast', 'Çarpma anında patlayan devasa bir cehennem ateşi küresi fırlatır.', 'Hurls a massive sphere of hellfire that detonates on impact.', 'Hellfire', 45, 350, 3, '{"hb_fire_rain"}', '{"x": 1414, "y": 1685}', '{"damage": "6d8 fire", "radius": "10m", "range": "40m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5cb06a4c-75b1-4725-8b9f-f5058643905f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_soul_burn', 'Ruh Yanığı', 'Soul Burn', 'Hedefin ruhunu tutuşturarak yıkıcı nekrotik ve ateş hasarı verir.', 'Ignites the very soul of the target, dealing devastating necrotic and fire damage.', 'Hellfire', 52, 400, 3, '{"hb_fire_breath"}', '{"x": 1574, "y": 1876}', '{"damage": "4d10 necrotic + 4d10 fire", "range": "20m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b5e011c-b96e-463d-999a-4126759cab6a', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_eruption', 'Şeytani Patlama', 'Demonic Eruption', 'Yerin şiddetle magma ve cehennem ateşiyle patlamasına neden olur.', 'Causes the ground to violently erupt with magma and hellfire.', 'Hellfire', 58, 450, 3, '{"hb_fire_blast"}', '{"x": 1735, "y": 2068}', '{"damage": "8d6 fire", "radius": "15m", "range": "30m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5f40ce3f-3549-4967-9cac-b64e664b612f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_meteor', 'Hiçlik Meteoru', 'Meteor of the Abyss', 'Her şeyi ezmek ve yakmak için gökyüzünden devasa bir şeytani meteor çeker.', 'Pulls a massive demonic meteor from the sky to crush and incinerate everything.', 'Hellfire', 65, 650, 4, '{"hb_fire_eruption"}', '{"x": 1896, "y": 2259}', '{"damage": "12d6 fire + 6d6 bludgeoning", "radius": "20m", "range": "100m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a2e7d5ca-08ae-47f5-a064-c6de67c894eb', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_sea', 'Cehennem Ateşi Denizi', 'Sea of Hellfire', 'Tüm savaş alanını bitmek bilmeyen karanlık alevlerden oluşan dalgalı bir denizle sular altında bırakır.', 'Floods the entire battlefield in an undulating wave of unending dark flames.', 'Hellfire', 75, 800, 4, '{"hb_fire_soul_burn", "hb_fire_meteor"}', '{"x": 2056, "y": 2451}', '{"damage": "10d8 fire", "radius": "30m", "duration": "1 min"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84dd3ff0-41be-46d7-ab76-6bdcb3b83a5b', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_fire_ultimate', 'Cehennem Kıyameti', 'Infernal Apocalypse', 'Cehennemin saf yıkıcı gücünü serbest bırakarak alanı anında kavrulmuş bir ölüm çoraklığına çevirir.', 'Unleashes the raw destructive power of hell itself, instantly turning the area into a scorched wasteland of death.', 'Hellfire', 92, 1200, 5, '{"hb_fire_sea"}', '{"x": 2217, "y": 2642}', '{"damage": "20d10 fire + 10d10 necrotic", "radius": "50m", "range": "100m"}', '☢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('911af5d5-e6f5-4711-8e26-10d1f4645303', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_blood', 'Kan Anlaşması', 'Blood Pact', 'Bir sonraki büyülü saldırınızı güçlendirmek için kendi sağlığınızın küçük bir kısmını feda edersiniz.', 'Sacrifice a small amount of your own health to empower your next magical attack.', 'Pact', 2, 50, 1, '{}', '{"x": -128, "y": 153}', '{"hp_cost": "1d8", "damage_bonus": "+1d8", "duration": "Next attack"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7031c884-c72b-4c71-89a8-27e249cf6c0f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_whispers', 'Karanlık Fısıltılar', 'Dark Whispers', 'Bir hedefin zihnini hiçlikten gelen çıldırtıcı fısıltılarla doldurarak onları korkutursunuz.', 'Fill a target''s mind with maddening whispers from the abyss, frightening them.', 'Pact', 6, 75, 1, '{}', '{"x": -289, "y": 344}', '{"range": "15m", "condition": "Frightened", "duration": "1 min"}', '🦻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b5862f2e-b5d1-4b30-9c56-d366b4e79ad9', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_siphon', 'Hayat Sömürüsü', 'Siphon Life', 'Kendi yaralarınızı iyileştirmek için bir düşmanın yaşam gücünü sömürürsünüz.', 'Drain the life force of an enemy to heal your own wounds.', 'Pact', 12, 100, 1, '{"hb_pact_blood"}', '{"x": -449, "y": 536}', '{"damage": "2d6 necrotic", "healing": "100% of damage", "range": "10m"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c2c21748-a52d-4323-8374-34ef0aaf271d', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_bargain', 'Şeytanın Pazarlığı', 'Devil''s Bargain', 'Bir sonraki eyleminizde anında avantaj kazanırsınız, ancak bir sonraki savunmanızda dezavantaj yaşarsınız.', 'Gain an immediate advantage on your next action, but suffer disadvantage on your next defense.', 'Pact', 18, 120, 1, '{"hb_pact_whispers"}', '{"x": -610, "y": 727}', '{"buff": "Advantage", "debuff": "Disadvantage", "duration": "10 mins"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cddc1361-229c-4ff1-84b4-dee1fc2a77a8', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_blade', 'Kılıç Anlaşması', 'Pact of the Blade', 'Karanlık anlaşmalardan oluşan büyülü bir silah çağırarak onu elinize bağlar.', 'Summons a magical weapon formed from dark pacts, binding it to your hand.', 'Pact', 24, 200, 2, '{"hb_pact_siphon"}', '{"x": -771, "y": 919}', '{"damage": "1d8 + Charisma modifier", "duration": "1 hour"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b32a6d6-c2c7-48f5-9f16-b88e60ec1c77', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_chain', 'Ruh Zinciri', 'Soul Chain', 'Ruhunuzu bir müttefiğe bağlayarak gelen tüm hasarı aranızda eşit olarak böler.', 'Links your soul to an ally, splitting all incoming damage evenly between you.', 'Pact', 30, 225, 2, '{"hb_pact_bargain"}', '{"x": -932, "y": 1110}', '{"range": "15m", "damage_split": "50%", "duration": "10 mins"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3d1bb95-0d50-439a-8c5c-f43a2d4b5c6e', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_resilience', 'Cehennem Direnci', 'Infernal Resilience', 'Vücudunuz şeytani bir sertlikle güçlenerek ateşe ve zehre karşı direnç kazanır.', 'Your body hardens with demonic toughness, granting resistance to fire and poison.', 'Pact', 35, 250, 2, '{"hb_pact_blade"}', '{"x": -1092, "y": 1302}', '{"resistances": "Fire, Poison", "duration": "1 hour"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a17751e6-24fc-44e4-9740-aa6c02acf57d', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_sacrifice', 'Sağlık Feda Etme', 'Sacrifice Health', 'Ölmekte olan bir müttefiğe sağlığınızın büyük bir bölümünü anında aktarmak için kendi etinizi kesersiniz.', 'Cut your own flesh to instantly transfer a large portion of your health to a dying ally.', 'Pact', 40, 275, 2, '{"hb_pact_chain"}', '{"x": -1253, "y": 1493}', '{"hp_cost": 20, "healing": 30, "range": "10m"}', '❤️‍🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('27a5f878-85d1-4b44-ab13-38e50d00f249', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_agony', 'Izdırap Anlaşması', 'Pact of Agony', 'Bir hedefi lanetleyerek muazzam bir acı çekmelerine ve tüm saldırılardan ekstra hasar almalarına neden olur.', 'Curses a target, causing them to suffer immense pain and take extra damage from all attacks.', 'Pact', 48, 350, 3, '{"hb_pact_resilience"}', '{"x": -1414, "y": 1685}', '{"damage_vulnerability": "+1d6 per hit", "duration": "1 min"}', '😫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0dfe4e73-25a0-4b99-bbf6-33b6bff6f810', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_deal', 'Şeytani Anlaşma', 'Diabolic Deal', 'Düşmüş bir müttefiği anında canlandırır, ancak dinlenene kadar her ikinizin de maksimum sağlığını kalıcı olarak azaltır.', 'Revives a fallen ally instantly, but permanently reduces both of your maximum health until rested.', 'Pact', 54, 400, 3, '{"hb_pact_sacrifice"}', '{"x": -1574, "y": 1876}', '{"healing": "50% max HP", "penalty": "-25% max HP", "range": "Touch"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d90b8f0-2a9a-4b9d-867a-a66ef1080713', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_exchange', 'Ruh Takası', 'Soul Exchange', 'Bir müttefik veya düşmanla anında fiziksel konumlarınızı değiştirirsiniz.', 'Instantly swap physical locations with an ally or an enemy.', 'Pact', 60, 450, 3, '{"hb_pact_agony"}', '{"x": -1735, "y": 2068}', '{"range": "30m"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3a63769-7dd1-4d0b-be34-3bb6c321842d', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_immortality', 'Ölümsüzlük Anlaşması', 'Pact of Immortality', 'Ölümcül bir darbe alırsanız, anında 1 canla canlanırsınız, ancak maksimum canınız bir gün boyunca yarıya iner.', 'If you are struck with a fatal blow, you instantly revive at 1 HP, but your max HP is halved for a day.', 'Pact', 68, 650, 4, '{"hb_pact_deal", "hb_pact_exchange"}', '{"x": -1896, "y": 2259}', '{"duration": "24 hours", "penalty": "Max HP halved on trigger"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('263e9fe7-28c0-4cc8-843b-2b2840836019', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_doom', 'Kıyamet Sözleşmesi', 'Contract of Doom', 'Bir düşmanı işaretler. Sizi üç tur içinde öldüremezlerse, ruhları ezilerek muazzam bir hasar alır.', 'Marks an enemy. If they fail to kill you within three turns, their soul is crushed for massive damage.', 'Pact', 78, 800, 4, '{"hb_pact_immortality"}', '{"x": -2056, "y": 2451}', '{"damage": "15d10 necrotic", "duration": "3 turns"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30f968f6-7cc1-44a8-a9fd-9e2e5a8615dd', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_pact_ultimate', 'Gerçek İblis Yükselişi', 'True Demonic Ascension', 'İnsanlığınızdan tamamen vazgeçerek fani kurallarına bağlı olmayan durdurulamaz bir şeytana dönüşürsünüz.', 'Forfeit your humanity entirely, transforming into an unstoppable fiend bound by no mortal rules.', 'Pact', 94, 1200, 5, '{"hb_pact_doom"}', '{"x": -2217, "y": 2642}', '{"temp_hp": 150, "bonus_damage": "3d8 necrotic", "duration": "10 mins"}', '👿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('69a409d9-4cf2-449e-83f8-d3e30392426c', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_cross_flaming_familiar', 'Alevli Yoldaş', 'Flaming Familiar', 'Çevresindeki düşmanları yakan, cehennem ateşiyle sarılmış küçük bir iblis çağırır.', 'Summons a small imp wreathed in hellfire that burns enemies near it.', 'Cross-Branch', 25, 250, 2, '{"hb_demon_imp", "hb_fire_ignite"}', '{"x": -173, "y": -100}', '{"health": 30, "aura_damage": "1d6 fire", "range": "10m"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60801b07-154a-4242-926a-40e440f17fa2', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_cross_blood_demon', 'Kan Bağı İblisi', 'Bloodbound Demon', 'Kendi kanınızdan dövülmüş bir iblis çağırır. Sağlık havuzunuzu paylaşır ancak eşsiz bir vahşetle saldırır.', 'Summons a demon forged from your own blood. It shares your health pool but attacks with unmatched ferocity.', 'Cross-Branch', 45, 450, 3, '{"hb_demon_blood_sacrifice", "hb_pact_blood"}', '{"x": -389, "y": -225}', '{"health": "Shares 50% of your HP", "damage": "3d8 slashing"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6b025193-7979-4cab-aabb-dd06a982d575', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_cross_hellfire_curse', 'Cehennem Ateşi Laneti', 'Hellfire Curse', 'Hedefe korkunç bir lanet yerleştirerek, her saldırdıklarında onları içeriden cehennem ateşiyle yakar.', 'Places a horrific curse on the target, burning them from the inside with hellfire every time they attack.', 'Cross-Branch', 55, 500, 3, '{"hb_fire_chains", "hb_pact_agony"}', '{"x": -606, "y": -350}', '{"damage": "2d8 fire per attack", "duration": "1 min"}', '🤬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60e4ba9a-9b4f-4679-8891-82f85ca71123', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_cross_balor_whip', 'Balor''un Kırbacı', 'Balor''s Whip', 'Bir Balor''un yanan kırbacını çağırarak düşmanlara vurmanızı, onları yakmanızı ve kendinize doğru çekmenizi sağlar.', 'Summons a blazing whip of a Balor, allowing you to strike, burn, and pull enemies toward you.', 'Cross-Branch', 65, 750, 4, '{"hb_demon_succubus", "hb_fire_blast"}', '{"x": -822, "y": -475}', '{"damage": "6d6 fire + 3d6 slashing", "range": "10m pull"}', '🪢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c8246d72-f21a-4ed5-8456-51b1646507c8', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_cross_soul_devourer', 'Ruh Yiyen İblis', 'Soul Devourer', 'Düşman ruhlarıyla beslenen ve hasar verdikçe sağlığınızı geri kazandıran korkutucu, spektral bir iblis çağırır.', 'Summons a terrifying spectral demon that feeds on enemy souls, restoring your health as it deals damage.', 'Cross-Branch', 70, 800, 4, '{"hb_demon_rift", "hb_pact_siphon"}', '{"x": -1039, "y": -600}', '{"health": 100, "healing": "50% of damage dealt"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fd5a8719-57ee-43d3-adf1-edcdd972bb77', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_cross_pact_of_ash', 'Kül Anlaşması', 'Pact of Ash', 'Ruhunuzu cehennem ateşine bağlarsınız. Öldüğünüzde ateşli bir patlamayla havaya uçar ve küllerinizden yeniden doğarsınız.', 'Bind your soul to hellfire. Upon death, you explode in a fiery blast and resurrect from the ashes.', 'Cross-Branch', 80, 900, 4, '{"hb_fire_meteor", "hb_pact_immortality"}', '{"x": -1255, "y": -725}', '{"explosion_damage": "10d6 fire", "revive_hp": "25% max HP"}', '⚱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3637556f-2d8d-427a-bbd2-ce803e6b7877', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_cross_abyssal_gate', 'Hiçlik Kapısı', 'Gate to the Abyss', 'Nihai geçidi açarsınız. Cehennem ateşi fışkırır ve sağlığınızın yarısı pahasına düşmanlarınızı yok etmek için üç yüksek seviyeli iblis ortaya çıkar.', 'Tear open the ultimate gateway. Hellfire spews forth, and three high-tier demons emerge to destroy your enemies at the cost of half your health.', 'Cross-Branch', 85, 1200, 5, '{"hb_demon_legions_call", "hb_fire_sea", "hb_pact_doom"}', '{"x": -1472, "y": -850}', '{"hp_cost": "50% max HP", "damage": "10d10 fire", "summons": "3 T4 Demons"}', '⛩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7b9bf3e9-1a57-4d9e-b0ce-05f5ac57699f', '736a0e7b-bfe6-4439-9d5e-f808b5f23da2', 'hb_grand_ultimate', 'Baş İblisin Mutlak Anlaşması', 'Archdemon''s Absolute Pact', 'Nihai fedakarlık. Cehennem Ateşi Baş İblisi olursunuz; iblisler, alevler ve yaşamın kendisi üzerinde mutlak hakimiyet kurarak neredeyse yenilmez hale gelirsiniz.', 'The ultimate sacrifice. You become the Archdemon of Hellfire, gaining absolute dominion over demons, flames, and life itself, becoming nearly invincible.', 'Cross-Branch', 100, 1500, 5, '{"hb_demon_ultimate", "hb_fire_ultimate", "hb_pact_ultimate"}', '{"x": -1688, "y": -975}', '{"hp_cost": "99% of current HP", "buff": "Invincible Archdemon Form", "duration": "1 hour"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c34bb44-bd87-4fb2-b3da-94f96a51e119', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_copycat_strike', 'Kopyacı Vuruşu', 'Copycat Strike', '10m içindeki bir hedefin yaptığı son fiziksel saldırıyı taklit eder.', 'Replicate the last physical attack made by a target within 10m.', 'Mimicry', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "100% of copied attack", "range": "10m"}', '🐒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8edb8f68-641a-4522-8b9f-2bdb6d042d62', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_echo_word', 'Yankı Sözü', 'Echo Word', 'Geçen tur yakında yapılan 1. Aşama bir büyüyü tekrarlar.', 'Repeat a Tier 1 spell cast nearby in the last round.', 'Mimicry', 3, 75, 1, '{}', '{"x": 389, "y": -224}', '{"range": "15m", "duration": "Instant"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ef5279a1-fa5e-427d-848c-15b1f0f7d422', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_borrow_skill', 'Yetenek Ödünç Al', 'Borrow Skill', 'Gönüllü bir müttefikten geçici olarak temel bir yetenek ödünç alır.', 'Temporarily borrow a basic skill from a willing ally.', 'Mimicry', 5, 100, 1, '{}', '{"x": 606, "y": -349}', '{"duration": "3 turns", "range": "5m"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1daf0b30-cd79-48c3-b626-fa449dd60fb7', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_stolen_vigor', 'Çalınmış Canlılık', 'Stolen Vigor', 'Bir düşmandan yararlı bir güçlendirmeyi çalar.', 'Steal a beneficial buff from an enemy.', 'Mimicry', 21, 200, 2, '{"ip_borrow_skill"}', '{"x": 822, "y": -474}', '{"range": "10m", "duration": "5 turns"}', '🩸');
