INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca516312-6aef-4d27-9445-06ad7f82ada3', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_spell_thief', 'Büyü Hırsızı', 'Spell Thief', '1. veya 2. Aşama bir büyüyü engeller ve bir kez yapmak için ezberler.', 'Counter a Tier 1 or 2 spell and memorize it to cast once.', 'Mimicry', 25, 250, 2, '{"ip_echo_word"}', '{"x": 1255, "y": -724}', '{"range": "20m", "memorize_duration": "1 hour"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70b14b38-df74-4308-a4a7-75139297497d', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_doppelganger_reflex', 'Doppelganger Refleksi', 'Doppelganger Reflex', 'Saldıranın hareketlerini kusursuz bir şekilde taklit ederek bir saldırıdan otomatik kaçınır.', 'Auto-dodge an attack by perfectly mimicking the attacker''s movements.', 'Mimicry', 41, 400, 3, '{"ip_mirror_stance"}', '{"x": 1472, "y": -849}', '{"dodge_chance": "100%", "duration": "1 attack"}', '🤸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dfe0cc4a-7b9a-49a9-817d-44e88da54918', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_aura_theft', 'Aura Hırsızlığı', 'Aura Theft', 'Bir düşmandan aktif bir aurayı çalarak faydalarını kendinize çevirir.', 'Steal an active aura from an enemy, turning its benefits to yourself.', 'Mimicry', 43, 420, 3, '{"ip_stolen_vigor"}', '{"x": 1688, "y": -974}', '{"range": "15m", "duration": "10 minutes"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cbbda5c5-1cad-4ab3-b23e-b6b21214e473', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_skill_drain', 'Yetenek Sömürüsü', 'Skill Drain', 'Bir düşmanın belirli bir yeteneğini devre dışı bırakır ve 3 tur boyunca kullanımını kazanır.', 'Disable an enemy''s specific skill and gain its use for 3 turns.', 'Mimicry', 45, 450, 3, '{"ip_spell_thief"}', '{"x": 1905, "y": -1099}', '{"range": "10m", "duration": "3 turns"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('128113c5-51f1-40a3-98d5-8278a5141e1f', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_mimic_mastery', 'Taklit Ustalığı', 'Mimic Mastery', 'Bir hedefin pasif yeteneğini 1 saatliğine kopyalar.', 'Copy a target''s passive ability for 1 hour.', 'Mimicry', 61, 700, 4, '{"ip_skill_drain"}', '{"x": 2121, "y": -1224}', '{"range": "20m", "duration": "1 hour"}', '🧩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f6cac2c6-e267-4ad8-8180-9423b7865bf1', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_grand_theft_spell', 'Büyük Büyü Hırsızlığı', 'Grand Theft Spell', 'Bir düşmanın zihninden 3. veya 4. Aşama bir büyüyü çalarak, onların yapmasını engeller.', 'Steal a Tier 3 or 4 spell from an enemy''s mind, preventing them from casting it.', 'Mimicry', 63, 750, 4, '{"ip_aura_theft"}', '{"x": 2338, "y": -1349}', '{"range": "25m", "cooldown": "24 hours"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('365489b8-a23e-44e9-8a6a-1ded20f62b82', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_twin_cast', 'İkiz Büyü', 'Twin Cast', 'Kopyaladığınız veya çaldığınız herhangi bir büyüyü çift olarak atın.', 'Dual cast any spell you have copied or stolen.', 'Mimicry', 65, 800, 4, '{"ip_doppelganger_reflex"}', '{"x": 2554, "y": -1474}', '{"multiplier": "2x effect", "mana_cost": "1.5x"}', '👯');
