INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16b9ec93-1c9d-470b-9543-9eb1b8540901', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_phantom_pain', 'Hayalet Acı', 'Phantom Pain', 'Zırhı aşan ve 2d8 zihinsel hasar veren illüzyon bir saldırı.', 'An illusionary attack that bypasses armor, dealing 2d8 mental damage.', 'Deception', 27, 260, 2, '{"ip_minor_illusion"}', '{"x": -932, "y": 1110}', '{"damage": "2d8 psychic", "range": "10m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('011c53d2-89f6-494e-8657-a2cb699b2a3c', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_smoke_and_mirrors', 'Duman ve Aynalar', 'Smoke and Mirrors', 'Arkanızda inandırıcı bir illüzyon bırakarak 15m''ye kadar ışınlanın.', 'Teleport up to 15m away, leaving a convincing illusion behind.', 'Deception', 42, 410, 3, '{"ip_false_target"}', '{"x": -1092, "y": 1302}', '{"teleport_range": "15m", "illusion_duration": "3 turns"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('56e8d580-1738-40bc-b21e-05ecea5eddd7', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_treachery', 'İhanet', 'Treachery', 'Bir düşmanın en yakın müttefikini siz olarak algılamasını sağlayarak saldırtın.', 'Make an enemy perceive their closest ally as you, causing them to attack.', 'Deception', 44, 430, 3, '{"ip_phantom_pain"}', '{"x": -1253, "y": 1493}', '{"range": "20m", "duration": "1 turn"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b17f4b7f-b295-4474-b424-bbe2722fa3e6', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_betrayer_strike', 'Hainin Vuruşu', 'Betrayer''s Strike', 'Hedef sizi bir müttefik olarak görüyorsa iki kat hasar veren devasa bir vuruş.', 'A massive strike that deals double damage if the target considered you an ally.', 'Deception', 47, 460, 3, '{"ip_backstab"}', '{"x": -1414, "y": 1685}', '{"base_damage": "4d8", "multiplier": "2x against allies"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('224472f5-6218-41c1-89ed-99ec94396e70', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_gaslight', 'Akıl Oyunu', 'Gaslight', 'Bir hedefin yakın zamandaki anılarını (1 saate kadar) değiştirerek gerçeklikten şüphe etmesini sağlayın.', 'Alter a target''s recent memories (up to 1 hour), making them doubt reality.', 'Deception', 62, 720, 4, '{"ip_treachery"}', '{"x": -1574, "y": 1876}', '{"range": "10m", "memory_alteration": "1 hour"}', '🕯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('155a255b-cf7a-4f9c-818b-34332480d62e', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_hallucinatory_terrain', 'Halüsinatif Arazi', 'Hallucinatory Terrain', 'Düşmanları kandırmak için 50m''lik bir alanın görünümünü, sesini ve kokusunu değiştirin.', 'Change the appearance, sound, and smell of a 50m area to deceive enemies.', 'Deception', 64, 760, 4, '{"ip_smoke_and_mirrors"}', '{"x": -1735, "y": 2068}', '{"radius": "50m", "duration": "24 hours"}', '🏜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e03dd03-90b0-420d-897f-e80351d9fe2e', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_puppet_strings', 'Kukla İpleri', 'Puppet Strings', 'Kandırılmış bir hedefin hareketlerini 3 tur boyunca kurnazca kontrol edin.', 'Subtly control the movements of a deceived target for 3 turns.', 'Deception', 67, 810, 4, '{"ip_gaslight"}', '{"x": -1896, "y": 2259}', '{"range": "20m", "duration": "3 turns"}', '🧶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3f6cd09-293a-483b-8038-f68628f5c465', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_fatal_ruse', 'Ölümcül Hile', 'Fatal Ruse', 'Bir düşmanı 8d10 hasar veren ölümcül, görünmez bir illüzyon tuzağına çekin.', 'Lure an enemy into a deadly, invisible illusionary trap dealing 8d10 damage.', 'Deception', 70, 860, 4, '{"ip_betrayer_strike"}', '{"x": -2056, "y": 2451}', '{"damage": "8d10 force", "trigger_radius": "5m"}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('576ebfe2-c700-476c-9119-a38f90115cc1', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_master_of_lies', 'Yalanların Efendisi', 'Master of Lies', 'Gerçeklik yalanlarınıza boyun eğer; seçtiğiniz bir illüzyon 1 saatliğine katı ve gerçek olur.', 'Reality bends to your lies; an illusion of your choice becomes solid and real for 1 hour.', 'Deception', 88, 1250, 5, '{"ip_hallucinatory_terrain", "ip_puppet_strings", "ip_fatal_ruse"}', '{"x": -2217, "y": 2642}', '{"duration": "1 hour", "reality_warp": "True Form"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('15a8ea56-1256-42fd-ace7-d6286220e094', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_phantom_thief', 'Hayalet Hırsız', 'Phantom Thief', 'Görünmez bir illüzyon el kullanarak 20m uzaktan bir eşya çalın.', 'Steal an item from 20m away using an invisible illusionary hand.', 'Cross-Branch', 30, 280, 2, '{"ip_minor_illusion", "ip_borrow_skill"}', '{"x": -173, "y": -100}', '{"range": "20m", "item_weight": "Max 5kg"}', '🧤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e840e48-ef2f-4a89-803c-dae3b625daad', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_illusory_copy', 'İllüzyon Kopya', 'Illusory Copy', '5 dakika boyunca bağımsız hareket edebilen kusursuz, somut bir kopyanızı yaratın.', 'Create a perfect, tangible clone of yourself that can act independently for 5 minutes.', 'Cross-Branch', 50, 480, 3, '{"ip_impersonate", "ip_smoke_and_mirrors"}', '{"x": -389, "y": -225}', '{"duration": "5 minutes", "hp": "20% of Max HP"}', '🪆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90098565-31d5-4ad5-af75-5daa30b7af13', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_memory_parasite', 'Hafıza Paraziti', 'Memory Parasite', 'Kılığınızı kusursuzlaştırmak için bir hedefin yüzeysel anılarını ve tavırlarını emin.', 'Absorb the surface memories and mannerisms of a target to perfect your disguise.', 'Cross-Branch', 52, 490, 3, '{"ip_aura_theft", "ip_flesh_sculpt"}', '{"x": -606, "y": -350}', '{"range": "Touch", "disguise_bonus": "+100"}', '🦠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9ca35c36-3cd2-4dff-b254-6c96ec956aaf', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_traitor_blade', 'Hainin Bıçağı', 'Traitor''s Blade', 'Hedefin element zayıflığını taklit eden ve illüzyon savunmalarını aşan bir vuruş.', 'A strike that mimics the target''s elemental weakness and bypasses illusionary defenses.', 'Cross-Branch', 72, 880, 4, '{"ip_betrayer_strike", "ip_essence_replica"}', '{"x": -822, "y": -475}', '{"damage": "6d8 adaptive", "defense_bypass": "True"}', '🦂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87e4555c-1aec-4f65-ab4d-32fc2d93992b', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_legion_of_one', 'Tek Kişilik Ordu', 'Legion of One', 'Her biri farklı bir düşman kılığında ve onların yeteneklerini taklit eden 4 kopya yaratın.', 'Create 4 clones, each disguised as a different enemy and mimicking their skills.', 'Cross-Branch', 74, 890, 4, '{"ip_mass_disguise", "ip_twin_cast"}', '{"x": -1039, "y": -600}', '{"clones": 4, "duration": "3 turns"}', '👨‍👨‍👦‍👦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f9599741-f1c3-4d93-b2c4-abcc12a39fd1', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_false_reality', 'Sahte Gerçeklik', 'False Reality', 'En fazla 5 hedefi, algılarını kontrol ettiğiniz yerel bir illüzyon dünyasına hapsedin.', 'Trap up to 5 targets in a localized illusionary world where you control their perceptions.', 'Cross-Branch', 76, 900, 4, '{"ip_hallucinatory_terrain", "ip_steal_identity"}', '{"x": -1255, "y": -725}', '{"radius": "30m", "duration": "1 minute", "targets": 5}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70b22a57-c2bb-4be8-b657-6aeafd499091', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_ultimate_betrayal', 'Nihai İhanet', 'Ultimate Betrayal', 'Düşman saflarına kılık değiştirerek sızın, liderlerinin nihai yeteneğini taklit edin ve alan etkili bir sırtından bıçaklama gerçekleştirin.', 'Infiltrate enemy ranks disguised, mimic their leader''s ultimate, and execute an AoE backstab.', 'Cross-Branch', 78, 950, 4, '{"ip_traitor_blade", "ip_legion_of_one", "ip_false_reality"}', '{"x": -1472, "y": -850}', '{"damage": "10d10", "radius": "20m", "condition": "Requires Disguise"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b127734f-7e92-4718-85d3-caa83f1737a1', 'ea7224b3-fc77-4c2c-bc75-e923eab4c7f6', 'ip_absolute_fraud', 'Mutlak Sahtekarlık', 'Absolute Fraud', 'Büyük Nihai. Haklı hükümdar veya galip olduğunuzu iddia etmek için gerçekliği yeniden yazın. Düşmanın tüm varlığını ve güçlerini kalıcı olarak (NPC''ler) veya 24 saatliğine (Oyuncular) çalın.', 'Grand Ultimate. Rewrite reality to assert you are the rightful ruler or victor. Steal the enemy''s entire existence and powers permanently (NPCs) or for 24 hours (Players).', 'Cross-Branch', 99, 1500, 5, '{"ip_perfect_imitation", "ip_many_faced_god", "ip_master_of_lies"}', '{"x": -1688, "y": -975}', '{"reality_rewrite": "Total", "duration": "Permanent or 24h", "range": "100m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d44afda6-82cf-4669-b4d3-c324ebe0f52c', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_basic_mark', 'Temel İşaret', 'Basic Mark', '30m''ye kadar uzaktaki bir hedefi işaretle. Onlara karşı saldırıların +1 isabet oranına sahip olur ve fazladan 1d4 hasar verir. 1 dakika sürer.', 'Mark a target up to 30m away. Your attacks against them have +1 to hit and deal an extra 1d4 damage. Lasts 1 minute.', 'Mark', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d4", "range": "30m", "duration": "1 minute"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a2e914d7-2ad8-4504-a21a-4b59043e4b9e', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_homing_shot', 'Güdümlü Atış', 'Homing Shot', '40m içindeki işaretli bir hedefi takip eden, yarım ve üç çeyrek siperi yok sayan bir mermi ateşle. 2d6 delici hasar verir.', 'Fire a projectile that tracks a marked target within 40m, ignoring half and three-quarters cover. Deals 2d6 piercing damage.', 'Mark', 5, 80, 1, '{"ix_basic_mark"}', '{"x": 389, "y": -224}', '{"damage": "2d6", "range": "40m", "ignore_cover": "75%"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49f3b6c7-447c-4e5c-9075-2a02336c5e62', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_extended_mark', 'Genişletilmiş İşaret', 'Extended Mark', 'İşaretlerinizin maksimum menzilini 30m artırır ve sürelerini 5 dakikaya uzatır.', 'Increases the maximum range of your marks by 30m and extends their duration to 5 minutes.', 'Mark', 10, 100, 1, '{"ix_basic_mark"}', '{"x": 606, "y": -349}', '{"range_increase": "30m", "duration": "5 minutes"}', '🔭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a1bd1c6-94c6-4a2f-81cc-183100c455c2', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_multi_mark', 'Çoklu İşaret', 'Multi Mark', 'Artık aynı anda 3 adede kadar aktif işareti koruyabilirsiniz. Her işaretli hedef 1d4 yerine fazladan 1d6 hasar alır.', 'You can now maintain up to 3 active marks simultaneously. Each marked target takes 1d6 extra damage instead of 1d4.', 'Mark', 21, 200, 2, '{"ix_extended_mark"}', '{"x": 822, "y": -474}', '{"max_marks": 3, "damage": "1d6"}', '🎛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3753dc09-0375-4f77-aab7-85b4b0c01bd1', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_mark_detonation', 'İşaret Patlaması', 'Mark Detonation', 'Hedefteki bir işareti tüketerek etraflarında 5m yarıçapında 3d6 kuvvet hasarı veren ani bir patlamaya neden olun.', 'Consume a mark on a target to cause a sudden explosion, dealing 3d6 force damage in a 5m radius around them.', 'Mark', 25, 250, 2, '{"ix_homing_shot"}', '{"x": 1039, "y": -599}', '{"damage": "3d6", "radius": "5m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('15c55889-5d4c-402c-beaa-42eadb95dc19', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_beacon_flare', 'İşaret Fişeği', 'Beacon Flare', '100m''ye kadar uzaktaki bir hedefe fişek fırlat. 1 dakika boyunca kesin konumları tüm müttefikler tarafından görünür hale gelir ve görünmezliği tamamen iptal eder.', 'Fire a flare at a target up to 100m away. For 1 minute, their exact location is visible to all allies, entirely negating invisibility.', 'Mark', 30, 280, 2, '{"ix_extended_mark"}', '{"x": 1255, "y": -724}', '{"range": "100m", "duration": "1 minute", "negate_invisibility": true}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f2e5b291-919f-441e-a23b-a1e65ab2f977', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_inescapable_mark', 'Kaçınılmaz İşaret', 'Inescapable Mark', '40m uzaklığa kadar uygulanan, hedefin 30 saniye boyunca ışınlanma veya düzlemsel seyahat kullanmasını engelleyen özel bir işaret.', 'A specialized mark applied up to 40m away that prevents the target from using teleportation or planar travel for 30 seconds.', 'Mark', 41, 400, 3, '{"ix_multi_mark"}', '{"x": 1472, "y": -849}', '{"range": "40m", "duration": "30 seconds", "prevent_teleport": true}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7fa394eb-d64a-4001-bf1d-8ffe16ec21c8', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_curving_bullet', 'Kavisli Mermi', 'Curving Bullet', 'Menzilli atışlarınız engellerin etrafından kavis çizer. 50m içindeki işaretli bir hedefe açık bir yol varsa tam siperi tamamen yok sayarsınız.', 'Your ranged attacks curve around obstacles. You completely ignore full cover if an open path exists to a marked target within 50m.', 'Mark', 45, 450, 3, '{"ix_mark_detonation"}', '{"x": 1688, "y": -974}', '{"range": "50m", "ignore_cover": "100%"}', '↪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3ab3cc2b-1c48-43e1-a877-0fc1f4f1ae2c', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_mark_transfer', 'İşaret Transferi', 'Mark Transfer', 'İşaretli bir hedef öldüğünde, işareti otomatik olarak 15m içindeki en yakın düşmana aktarılır ve süresi yenilenir.', 'When a marked target dies, their mark automatically transfers to the nearest enemy within 15m, refreshing its duration.', 'Mark', 50, 480, 3, '{"ix_multi_mark"}', '{"x": 1905, "y": -1099}', '{"range": "15m", "duration": "refreshed"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cec852e6-2447-487e-84e1-ee82340537ac', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_death_mark', 'Ölüm İşareti', 'Death Mark', '50m''ye kadar ölümcül bir işaret uygula. Bu işaretli hedefe karşı ilk saldırınız kesinlikle kritik vurur ve fazladan 5d8 nekrotik hasar verir.', 'Apply a deadly mark up to 50m. Your first attack against this marked target is a guaranteed critical hit and deals an extra 5d8 necrotic damage.', 'Mark', 61, 700, 4, '{"ix_inescapable_mark"}', '{"x": 2121, "y": -1224}', '{"range": "50m", "damage": "5d8", "guaranteed_crit": true}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ba826a2c-226e-4b8f-ab94-5ab63226fca2', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_swarm_homing', 'Sürü Güdümü', 'Swarm Homing', '60m içindeki işaretli hedefleri agresif bir şekilde arayan 5 mermilik bir yaylım ateşi açın. Her mermi 2d8 hasar verir.', 'Fire a volley of 5 projectiles that aggressively seek out marked targets within 60m. Each projectile deals 2d8 damage.', 'Mark', 65, 750, 4, '{"ix_curving_bullet"}', '{"x": 2338, "y": -1349}', '{"projectiles": 5, "damage": "2d8", "range": "60m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8cc1d3ee-92b2-40d4-8078-69c84c21e19d', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_soul_mark', 'Ruh İşareti', 'Soul Mark', 'İşaretinizi 24 saat boyunca hedefin ruhuna yerleştirin. Büyülü yollarla kaldırılamaz ve boyutlar arası takibe olanak tanır.', 'Embed your mark into the target''s soul for 24 hours. It cannot be removed by magical means, allowing cross-dimensional tracking.', 'Mark', 70, 800, 4, '{"ix_death_mark"}', '{"x": 2554, "y": -1474}', '{"duration": "24 hours", "cross_dimensional": true}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d5ecb40-c3e3-4406-98db-312ec02f0e36', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_omni_mark', 'Mutlak İşaret', 'Omni Mark', 'Etrafınızdaki 30m yarıçapındaki tüm düşmanları anında işaretleyin. Tüm müttefikler onlara karşı +2d6 hasar verir.', 'Instantly mark all enemies within a 30m radius of yourself. All allies deal +2d6 damage against them.', 'Mark', 81, 1100, 5, '{"ix_soul_mark", "ix_swarm_homing"}', '{"x": 2771, "y": -1599}', '{"radius": "30m", "damage_bonus": "2d6", "targets": "all enemies"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2d721fd2-2ee1-43ba-a7a2-f705d50d5466', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_ultimate_execution', 'Nihai İnfaz', 'Ultimate Execution', '500m içinde herhangi bir yerden yıkıcı bir atış yapmak için Ruh İşaretini tüket. 12d10 kuvvet hasarı verir ve sağlığı %15''in altındaki hedefleri infaz eder.', 'Consume a Soul Mark to fire a devastating shot from anywhere within 500m. Deals 12d10 force damage and executes targets below 15% health.', 'Mark', 90, 1500, 5, '{"ix_omni_mark"}', '{"x": 2987, "y": -1724}', '{"range": "500m", "damage": "12d10", "execute_threshold": "15%"}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de36c14f-7ce0-4e03-8ffb-e11934fa2635', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_scent_trail', 'Koku İzi', 'Scent Trail', 'Bölgeden son 1 saat içinde geçen yaratıkların bıraktığı parlayan izleri pasif olarak görebilirsiniz. Menzil: 20m.', 'You can passively see glowing trails left by creatures that passed through the area within the last 1 hour. Range: 20m.', 'Tracker', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "20m", "duration": "1 hour"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5721e902-67ee-465a-9535-2b007cfe805a', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_hunter_vision', 'Avcı Görüşü', 'Hunter''s Vision', '30m''ye kadar karanlık görüşü kazanın ve gizlenmiş veya kılık değiştirmiş düşmanları bulmak için tüm algı zarlarında avantaj elde edin.', 'Gain darkvision up to 30m and advantage on all perception checks to locate hidden or disguised enemies.', 'Tracker', 5, 80, 1, '{"ix_scent_trail"}', '{"x": 289, "y": 344}', '{"range": "30m", "advantage": "perception"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('502cabd5-3755-4fb2-8bbf-5962bbe1d3f9', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_ignore_cover_1', 'Sekme Atışı', 'Ricochet Shot', '25m içindeki siper arkasına saklanan düşmanları vurmak için atışınızı sert bir yüzeyden sektirin. 1d10 delici hasar verir.', 'Bounce your shot off a hard surface to hit enemies hiding behind cover within 25m. Deals 1d10 piercing damage.', 'Tracker', 10, 100, 1, '{"ix_hunter_vision"}', '{"x": 449, "y": 536}', '{"range": "25m", "damage": "1d10"}', '🎱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f7bf1c67-3ee3-4d27-ab23-2a3f403cbeb2', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_sonar_pulse', 'Sonar Darbesi', 'Sonar Pulse', '40m içindeki hareket eden tüm yaratıkları 10 saniye boyunca duvarların arkasından çizen sessiz bir darbe yayın.', 'Emit a silent pulse that outlines all moving creatures within 40m through walls for 10 seconds.', 'Tracker', 21, 200, 2, '{"ix_hunter_vision"}', '{"x": 610, "y": 727}', '{"range": "40m", "duration": "10 seconds"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af912859-9525-4f4c-bc2f-caaff358ffd1', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_thermal_scope', 'Termal Dürbün', 'Thermal Scope', 'Isı izlerini 1 dakika boyunca görmek için dürbününüzü etkinleştirin. 60m içindeki görünmezliği, sisi ve büyülü karanlığı yok sayar.', 'Activate your scope to see heat signatures for 1 minute. Negates invisibility, fog, and magical darkness within 60m.', 'Tracker', 25, 250, 2, '{"ix_sonar_pulse"}', '{"x": 771, "y": 919}', '{"range": "60m", "duration": "1 minute"}', '🌡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bd3369d8-7ab0-4adf-9548-0e821b989b82', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_relentless_pursuit', 'Amansız Takip', 'Relentless Pursuit', 'Takip edilen bir hedefe doğru hareket ederken, hareket hızınız 5m artar ve zorlu araziyi tamamen yok sayarsınız.', 'While moving towards a tracked target, your movement speed increases by 5m and you completely ignore difficult terrain.', 'Tracker', 30, 280, 2, '{"ix_ignore_cover_1"}', '{"x": 932, "y": 1110}', '{"speed": "+5m", "ignore_terrain": true}', '🏃‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de60eded-7dd8-4f46-b6d0-0de315af818b', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_wall_piercer', 'Duvar Delici', 'Wall Piercer', '1m''ye kadar katı taş veya metali delen ağır bir atış yapın, arkasında kalan düşmanlara 4d8 delici hasar verir.', 'Fire a heavy shot that penetrates up to 1m of solid stone or metal, dealing 4d8 piercing damage to enemies caught behind it.', 'Tracker', 41, 400, 3, '{"ix_thermal_scope"}', '{"x": 1092, "y": 1302}', '{"penetration": "1m", "damage": "4d8"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('58bc9395-a16e-4402-9086-25fe564d65c0', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_blood_tracker', 'Kan Takipçisi', 'Blood Tracker', 'Bir düşmana hasar verdiğinizde, 1000m içinde kaldıkları sürece onlara olan kesin mesafeyi ve yönü içgüdüsel olarak bilirsiniz.', 'Once you damage an enemy, you intrinsically know the exact distance and direction to them as long as they remain within 1000m.', 'Tracker', 45, 450, 3, '{"ix_relentless_pursuit"}', '{"x": 1253, "y": 1493}', '{"range": "1000m", "duration": "until target heals"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41469d44-bbd3-416d-8867-07ce93c93ac1', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_trap_sense', 'Tuzak Hissi', 'Trap Sense', '15m yarıçapındaki mekanik ve büyülü tuzakları pasif olarak algılar ve onları hafifçe aydınlatır.', 'Passively detects mechanical and magical traps within a 15m radius, illuminating them slightly.', 'Tracker', 50, 480, 3, '{"ix_sonar_pulse"}', '{"x": 1414, "y": 1685}', '{"range": "15m", "passive": true}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9ddf5e06-f6de-4815-99df-8a08ebeec7ac', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_ghost_hunter', 'Hayalet Avcısı', 'Ghost Hunter', 'Takibiniz ve saldırılarınız bedensiz kaçışı yok sayar. Ruhani hedeflere tam hasar verebilirsiniz.', 'Your tracking and attacks ignore incorporeal evasion. You can hit ethereal targets for full damage.', 'Tracker', 61, 700, 4, '{"ix_blood_tracker"}', '{"x": 1574, "y": 1876}', '{"hit_ethereal": true, "passive": true}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('51025965-9a6a-4af7-8a5e-aa37ea62e381', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_clairvoyant_shot', 'Görüş Ötesi Atış', 'Clairvoyant Shot', '100m''ye kadar tamamen gizlenmiş bir alana körlemesine ateş et. Takipçi büyüsü mermiyi bir düşmana vurması için yönlendirir, 5d10 hasar verir.', 'Fire blindly into a completely obscured area up to 100m away. Tracker magic guides the bullet to hit an enemy for 5d10 damage.', 'Tracker', 65, 750, 4, '{"ix_wall_piercer"}', '{"x": 1735, "y": 2068}', '{"range": "100m", "damage": "5d10"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b95051f0-c159-4939-85d4-17936450401b', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_no_escape', 'Kaçış Yok', 'No Escape', 'Takip edilen bir düşman hızla koşmaya veya geri çekilmeye çalıştığında, avantajlı bir şekilde ücretsiz silah saldırısı yapmak için reaksiyon kullanın.', 'When a tracked enemy attempts to dash or disengage, take a reaction to make a free weapon attack against them with advantage.', 'Tracker', 70, 800, 4, '{"ix_ghost_hunter"}', '{"x": 1896, "y": 2259}', '{"reaction": true, "advantage": true}', '🚷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9720877f-bbeb-4315-93b3-1aea5a3d1313', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_predator_instinct', 'Yırtıcı İçgüdüsü', 'Predator Instinct', '1 dakika boyunca duyularınız yükselir: şaşırtılamazsınız, 60m''ye kadar gerçek görüş kazanırsınız ve hareket hızınız iki katına çıkar.', 'For 1 minute, your senses elevate: you cannot be surprised, gain truesight up to 60m, and your movement speed is doubled.', 'Tracker', 81, 1100, 5, '{"ix_no_escape", "ix_clairvoyant_shot"}', '{"x": 2056, "y": 2451}', '{"truesight": "60m", "duration": "1 minute", "speed": "x2"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('73acedcc-8d3e-47cd-a968-ec65ab86208a', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_eye_of_the_tracker', 'Takipçinin Gözü', 'Eye of the Tracker', 'Mevcut düzleminizin herhangi bir yerindeki bir hedefi belirleyin. 24 saat boyunca onların gözünden görür, duyduklarını duyar ve kesin koordinatlarını bilirsiniz.', 'Designate a target anywhere on your current plane. For 24 hours, you see through their eyes, hear what they hear, and know their exact coordinates.', 'Tracker', 90, 1500, 5, '{"ix_predator_instinct"}', '{"x": 2217, "y": 2642}', '{"range": "infinite", "duration": "24 hours"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('555d675f-fb19-41b6-b233-cf15dd350474', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_scan_target', 'Hedef Taraması', 'Scan Target', 'Bonus eylem olarak, 30m içindeki bir hedefi analiz edin. En düşük kurtarma zarını ve tüm hasar zafiyetlerini anında ortaya çıkarın.', 'As a bonus action, analyze a target within 30m. Instantly reveal its lowest saving throw and any damage vulnerabilities.', 'Analysis', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"range": "30m", "information": "vulnerabilities and low saves"}', '🔍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29388173-6464-494a-aefb-ecae87c92077', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_weak_point_strike', 'Zayıf Nokta Vuruşu', 'Weak Point Strike', 'Taranmış hedefin yapısal bir kusurunu sömür. Saldırı fazladan 2d6 hasar verir ve bu hasar türüne olan direnci yok sayar.', 'Exploit a scanned target''s structural flaw. The attack deals an extra 2d6 damage and ignores resistance to that damage type.', 'Analysis', 5, 80, 1, '{"ix_scan_target"}', '{"x": -289, "y": 344}', '{"damage": "2d6", "ignore_resistance": true}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3712cac0-ad6e-4fce-b460-42d9509445aa', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_armor_calc', 'Zırh Hesaplaması', 'Armor Calculation', 'Düşmanın zırh yapısını analiz edin. Onlara karşı saldırılarınız kalıcı olarak +2 isabet kazanır ve Zırh Sınıflarının 2 puanını atlar.', 'Analyze an enemy''s armor structure. Your attacks against them permanently gain +2 to hit and bypass 2 points of their Armor Class.', 'Analysis', 10, 100, 1, '{"ix_weak_point_strike"}', '{"x": -449, "y": 536}', '{"hit_bonus": "+2", "armor_reduction": "2"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d18f7535-f930-4816-9858-40dde480f951', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_critical_focus', 'Kritik Odak', 'Critical Focus', 'Taranan hedeflere karşı kesin silah saldırılarınız artık 19 veya 20 zarda kritik vuruş yapar.', 'Your precise weapon attacks against scanned targets now score a critical hit on a roll of 19 or 20.', 'Analysis', 21, 200, 2, '{"ix_weak_point_strike"}', '{"x": -610, "y": 727}', '{"crit_range": "19-20", "passive": true}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e877e44c-c8e2-433d-be02-3721b8f8ae8e', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_shatter_armor', 'Zırh Parçala', 'Shatter Armor', 'Zırhtaki önemli bir zayıf noktayı yok eden, hedefin AC''sini 1 dakika boyunca 2 azaltan kesin bir atış. 3d8 hasar verir.', 'A precise shot that destroys a key weak point in armor, reducing the target''s AC by 2 for 1 minute. Deals 3d8 damage.', 'Analysis', 25, 250, 2, '{"ix_armor_calc"}', '{"x": -771, "y": 919}', '{"damage": "3d8", "ac_reduction": "2", "duration": "1 minute"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('829816da-e599-4801-a780-1e89433cc2e2', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_predictive_aim', 'Öngörülü Nişan', 'Predictive Aim', 'Hedefin gelecekteki yolunu hesapla ve önceden ateş et. Hedef bir sonraki turda hareket ederse, otomatik olarak 4d6 hasar alır.', 'Calculate a target''s future path and pre-fire. If the target moves on their next turn, they automatically take 4d6 damage.', 'Analysis', 30, 280, 2, '{"ix_critical_focus"}', '{"x": -932, "y": 1110}', '{"damage": "4d6", "trigger": "movement"}', '🕰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a082d4ea-0319-4d3b-88b2-d6ba449fc82f', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_anatomical_knowledge', 'Anatomik Bilgi', 'Anatomical Knowledge', 'Biyoloji konusundaki derin anlayışınız, tüm canavarlara, insansılara ve yaratıklara 1d8 ekstra hassasiyet hasarı vermenizi sağlar.', 'Your deep understanding of biology allows you to deal 1d8 extra precision damage to all beasts, humanoids, and monsters.', 'Analysis', 41, 400, 3, '{"ix_critical_focus"}', '{"x": -1092, "y": 1302}', '{"damage": "1d8", "passive": true}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d94f58f2-ada1-4674-b27d-fe2becbdba6e', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_vital_shot', 'Hayati Atış', 'Vital Shot', 'Doğrudan hayati bir organa nişan al. 5d8 delici hasar verir ve bir Dayanıklılık zarına zorlar. Başarısız olursa hedef 1 tur sersemler.', 'Aim directly for a vital organ. Deals 5d8 piercing damage and forces a Constitution save. On fail, the target is stunned for 1 turn.', 'Analysis', 45, 450, 3, '{"ix_anatomical_knowledge"}', '{"x": -1253, "y": 1493}', '{"damage": "5d8", "stun": "1 turn"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('268a74e8-e073-4537-a59d-3c97322fa722', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_disarm_shot', 'Silahsızlandırma Atışı', 'Disarm Shot', 'Bir düşmanın silah elini hedef al. 3d10 hasar verir ve tuttukları şeyi düşürmeye zorlayarak saldırılarda 1 tur dezavantaj verir.', 'Target an enemy''s weapon hand. Deals 3d10 damage and forces them to drop what they hold, giving disadvantage on attacks for 1 turn.', 'Analysis', 50, 480, 3, '{"ix_shatter_armor"}', '{"x": -1414, "y": 1685}', '{"damage": "3d10", "drop_weapon": true, "debuff": "1 turn"}', '🔫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa68aefe-65d3-4581-9f46-9fab779be6fc', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_surgical_precision', 'Cerrahi Hassasiyet', 'Surgical Precision', 'Taranan hedeflere karşı kritik vuruşlarınız artık iki katı yerine üç katı hasar verir.', 'Your critical hits against scanned targets now deal triple damage instead of double.', 'Analysis', 61, 700, 4, '{"ix_vital_shot"}', '{"x": -1574, "y": 1876}', '{"crit_multiplier": "x3"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('507af63c-e4d4-4bc1-993b-7247316c60bf', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_flaw_exploitation', 'Kusur Sömürüsü', 'Flaw Exploitation', 'Bir düşman sana karşı yaptığı saldırıyı ıskalarsa, ona karşı yapacağın bir sonraki saldırı avantajlı olur ve büyük bir +4d6 bonus hasar verir.', 'If an enemy misses an attack against you, your next attack against them has advantage and deals a massive +4d6 bonus damage.', 'Analysis', 65, 750, 4, '{"ix_anatomical_knowledge"}', '{"x": -1735, "y": 2068}', '{"damage": "+4d6", "advantage": true, "trigger": "enemy miss"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('faf76655-00c7-4d39-ac2c-66b08873ac4f', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_system_failure', 'Sistem Çöküşü', 'System Failure', 'Bir yaratığın sinirsel veya büyülü çekirdeğini hedef al. 6d10 hasar verir ve onları 3 tur boyunca tamamen susturur (büyü yapmalarını engeller).', 'Target the neural or magical core of a creature. Deals 6d10 damage and completely silences them (preventing casting) for 3 turns.', 'Analysis', 70, 800, 4, '{"ix_disarm_shot"}', '{"x": -1896, "y": 2259}', '{"damage": "6d10", "silence": "3 turns"}', '🔌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a79b3c94-1aeb-4768-a07c-c1c5f8b65bc2', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_absolute_calculation', 'Mutlak Hesaplama', 'Absolute Calculation', 'En yüksek bilişsel işlevlerini etkinleştir. 3 tur boyunca tüm saldırı zarlarını sanki 20 atmışsın gibi değerlendir.', 'Activate your highest cognitive functions. For 3 turns, treat all your attack rolls as if you rolled a 20.', 'Analysis', 81, 1100, 5, '{"ix_surgical_precision", "ix_flaw_exploitation"}', '{"x": -2056, "y": 2451}', '{"duration": "3 turns", "attack_roll": "20"}', '🧮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aedd01de-544d-4081-b6bb-ca65e5777ec3', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_perfect_analysis', 'Kusursuz Analiz', 'Perfect Analysis', 'Nihai Analiz. Tüm istatistikleri, dirençleri ve bağışıklıkları anında bil. 1 saat boyunca dirençlerini yok sayar ve bağışıklıklarını direnç olarak kabul edersin.', 'Ultimate Analysis. Instantly know all stats, resistances, and immunities. You ignore their resistances and treat immunities as resistances for 1 hour.', 'Analysis', 90, 1500, 5, '{"ix_absolute_calculation"}', '{"x": -2217, "y": 2642}', '{"duration": "1 hour", "ignore_resistance": true, "reduce_immunity": true}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8a64689-c5c1-453c-8b19-5e02927f8ac8', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_marked_weakness', 'İşaretli Zayıflık', 'Marked Weakness', 'Bir hedefi işaretlediğinde otomatik olarak taranır ve bir sonraki saldırının hasar türüne karşı savunmasız hale gelir.', 'When you mark a target, they are automatically scanned, and they become vulnerable to your next attack''s damage type.', 'Cross-Branch', 25, 250, 2, '{"ix_basic_mark", "ix_scan_target"}', '{"x": -173, "y": -100}', '{"vulnerability": "next attack"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('627f3c31-e38d-4392-8f29-80548fa7a0ac', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_tracking_mark', 'Takip İşareti', 'Tracking Mark', 'Temel işaretleriniz artık bir takipçinin faydalarını sağlar ve 1000m uzağa kadar hedefin kesin konumunu ortaya çıkarır.', 'Your basic marks now provide the benefits of a tracker, revealing the target''s exact location up to 1000m away.', 'Cross-Branch', 25, 250, 2, '{"ix_basic_mark", "ix_hunter_vision"}', '{"x": -389, "y": -225}', '{"range": "1000m", "location": "revealed"}', '🗺️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7e2a26e3-75ae-4174-8250-dbc0cfa61bea', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_analyzed_trail', 'Analiz Edilmiş İz', 'Analyzed Trail', 'Bir yaratığı takip ederken, onunla çatışmaya girmeden önce kesin HP''sini, seviyesini ve yaratık türünü matematiksel olarak çıkarabilirsiniz.', 'When tracking a creature, you can mathematically deduce its exact HP, level, and creature type before engaging.', 'Cross-Branch', 45, 450, 3, '{"ix_sonar_pulse", "ix_armor_calc"}', '{"x": -606, "y": -350}', '{"information": "hp, level, type"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('228f7488-b26b-4271-8c4e-c5928316d418', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_homing_vital', 'Güdümlü Hayati Vuruş', 'Homing Vital', 'Asla ıskalamayan kusursuz bir mermi. Hayati bir organı arar, 4d8 hasar verir ve hedefi 1 tur sersemletir.', 'A perfect projectile that never misses. It seeks out a vital organ, dealing 4d8 damage and stunning the target for 1 turn.', 'Cross-Branch', 50, 480, 3, '{"ix_homing_shot", "ix_vital_shot"}', '{"x": -822, "y": -475}', '{"damage": "4d8", "stun": "1 turn", "never_miss": true}', '💘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('794d7ddf-0d99-48b2-84b5-2fa573b16fd8', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_omnipresent_sniper', 'Her Yerdeki Keskin Nişancı', 'Omnipresent Sniper', '200m içindeki herhangi bir işaretli veya takip edilen hedefe anında ışınlanarak vardığınızda 6d8 kuvvet hasarı veren bir atış yapın.', 'Teleport instantly to any marked or tracked target within 200m, firing a shot upon arrival that deals 6d8 force damage.', 'Cross-Branch', 65, 750, 4, '{"ix_death_mark", "ix_wall_piercer"}', '{"x": -1039, "y": -600}', '{"teleport": "200m", "damage": "6d8"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('76188338-09b8-46d3-9914-35ea9e1361b4', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_calculated_ricochet', 'Hesaplanmış Sekme', 'Calculated Ricochet', 'Taranan bir ortamda duvarlar ve düşmanlar arasında bir atışı 5 defaya kadar sektirin. İsabet alan her düşman 3d10 hasar alır.', 'Bounce a shot up to 5 times between walls and enemies in a scanned environment. Each enemy hit takes 3d10 damage.', 'Cross-Branch', 65, 750, 4, '{"ix_ignore_cover_1", "ix_flaw_exploitation"}', '{"x": -1255, "y": -725}', '{"bounces": 5, "damage": "3d10 per hit"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46c8b4f9-c366-49e4-8b35-9885c9ee8335', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_hunter_killer_drone', 'Avcı-Katil Dron', 'Hunter-Killer Drone', '50m içindeki düşmanları 1 dakika boyunca otomatik olarak takip eden, işaretleyen ve analiz eden, tur başına 2d6 hasar veren küçük lazerler ateşleyen bir yapı konuşlandır.', 'Deploy a construct that automatically tracks, marks, and analyzes enemies within 50m for 1 minute, firing small lasers dealing 2d6 damage per turn.', 'Cross-Branch', 75, 850, 4, '{"ix_curving_bullet", "ix_ghost_hunter", "ix_surgical_precision"}', '{"x": -1472, "y": -850}', '{"duration": "1 minute", "range": "50m", "damage": "2d6/turn"}', '🛸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c1b93bba-a900-4e0b-8441-c900bcd0b5b7', 'aac08113-2d23-4de6-ab87-9f2e2e9607bd', 'ix_the_index', 'Endeks', 'The Index', 'Büyük Nihai Yetenek. ''Endeks''ini açarak zamanı 6 saniye durdur. Tüm hedefleri kusursuzca analiz et, işaretle ve ateş et. Zaman devam ettiğinde, tüm atışlar aynı anda vurur. Her hedef 10d12 hasar alır ve 1 tur sersemler.', 'The Grand Ultimate. Open your ''Index'', halting time for 6 seconds. Perfectly analyze, mark, and fire at any targets. When time resumes, all shots hit simultaneously. Each target takes 10d12 damage and is stunned for 1 turn.', 'Cross-Branch', 95, 1500, 5, '{"ix_ultimate_execution", "ix_eye_of_the_tracker", "ix_perfect_analysis"}', '{"x": -1688, "y": -975}', '{"time_stop": "6 seconds", "damage": "10d12", "stun": "1 turn"}', '📖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94dbd486-cead-467b-b6c2-5d7c9aa1b896', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_iron_skin', 'Demir Deri', 'Iron Skin', 'Deriyi sertleştirerek gelen tüm fiziksel hasarı 1d4 azaltır.', 'Hardens the skin, reducing all incoming physical damage by 1d4.', 'Iron Body', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage_reduction": "1d4 physical", "duration": "passive"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f0fd5ec7-9488-4aa7-bd09-cb3c5146a985', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_heavy_punch', 'Ağır Yumruk', 'Heavy Punch', '1d10 ezici hasar veren ve Zırh Sınıfını 1 puan yok sayan güçlü bir silahsız vuruş.', 'A forceful unarmed strike that deals 1d10 bludgeoning damage and ignores 1 point of Armor Class.', 'Crushing Blow', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d10 bludgeoning", "armor_penetration": "1 AC", "range": "melee"}', '🤜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9d71652b-e5e0-4e10-8123-a5cf761860c5', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_bull_rush', 'Boğa Hücumu', 'Bull Rush', '8m''ye kadar ileri atılarak 1d6 hasar verir ve hedefi 2m geriye itersiniz.', 'Charge forward up to 8m, dealing 1d6 damage and pushing the target back 2m.', 'Unstoppable', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d6 bludgeoning", "range": "8m", "knockback": "2m"}', '🐂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('73785cfa-9d0d-46a3-ac94-c05239de084c', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_tempered_bones', 'Tavlanmış Kemikler', 'Tempered Bones', 'Maksimum can puanını %10 artırır ve düşme hasarına karşı direnç sağlar.', 'Increases maximum hit points by 10% and grants resistance to falling damage.', 'Iron Body', 8, 100, 1, '{"if_iron_skin"}', '{"x": 389, "y": -224}', '{"max_hp_increase": "10%", "resistance": "falling damage"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('38aaed22-063f-47d9-8605-2497b84e86f7', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_shatter_guard', 'Siper Kırma', 'Shatter Guard', '1d8 hasar vurarak hedefin 1 tur boyunca kalkan kullanma veya blok yapma yeteneğini devre dışı bırakır.', 'Strikes for 1d8 damage, disabling the target''s ability to block or use shields for 1 turn.', 'Crushing Blow', 9, 100, 1, '{"if_heavy_punch"}', '{"x": 289, "y": 344}', '{"damage": "1d8 bludgeoning", "debuff": "block disabled", "duration": "1 turn"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9aaba4da-7d80-462a-a44e-e7d1aeecd57f', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_relentless_step', 'Acımasız Adım', 'Relentless Step', '3 tur boyunca zorlu araziden kaynaklanan hareket cezalarını yok saymanızı sağlar.', 'Allows you to ignore movement penalties from difficult terrain for 3 turns.', 'Unstoppable', 11, 100, 1, '{"if_bull_rush"}', '{"x": -289, "y": 344}', '{"buff": "ignore difficult terrain", "duration": "3 turns"}', '🥾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07fbe6fe-be4e-4c5b-a687-a7036d050023', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_deflecting_palm', 'Yön Değiştiren Avuç', 'Deflecting Palm', 'Gelen menzilli mermi saldırılarını tamamen savuşturmak için %20 pasif şans verir.', 'Gives a 20% passive chance to deflect incoming projectile attacks completely.', 'Iron Body', 16, 150, 1, '{"if_tempered_bones"}', '{"x": 606, "y": -349}', '{"deflection_chance": "20%", "target": "projectiles"}', '✋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2be6536b-a084-4d44-9bc5-36496b5f650f', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_armor_pierce', 'Zırh Delme', 'Armor Pierce', 'Enerjinizi odaklayarak bir sonraki silahsız vuruşunuzun hedefin zırhının %50''sini yok saymasını sağlar.', 'Focuses energy to make your next unarmed strike ignore 50% of the target''s armor.', 'Crushing Blow', 17, 150, 1, '{"if_shatter_guard"}', '{"x": 449, "y": 536}', '{"armor_penetration": "50%", "duration": "1 strike"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b6af3218-5152-4be3-b502-43acd2e42f76', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_momentum_build', 'Momentum İnşası', 'Momentum Build', 'Vurmadan önce hareket ettiğiniz her metre için bir sonraki saldırınız +1 hasar verir (maksimum +10).', 'For each meter you move before striking, your next attack deals +1 damage (max +10).', 'Unstoppable', 18, 150, 1, '{"if_relentless_step"}', '{"x": -449, "y": 536}', '{"bonus_damage": "+1 per meter", "cap": "+10 damage"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cd7cfd4a-b0c1-4633-abe0-0e21d14620c7', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_steel_stance', 'Çelik Duruş', 'Steel Stance', 'Sert bir duruş alın. 2 tur boyunca +3 Zırh Sınıfı kazanırsınız ancak hareket hızınız 3m azalır.', 'Adopt a rigid stance. Gain +3 AC for 2 turns, but your movement speed is reduced by 3m.', 'Iron Body', 22, 200, 2, '{"if_iron_skin"}', '{"x": 822, "y": -474}', '{"ac_bonus": "+3", "movement_penalty": "-3m", "duration": "2 turns"}', '🥋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fe6a2ff4-1b97-4113-8451-5582aeb75843', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_concussion_blow', 'Sarsıcı Vuruş', 'Concussion Blow', 'Kafaya indirilen ve 2d8 hasar veren, %30 ihtimalle hedefi 1 tur sersemleten acımasız bir darbe.', 'A brutal blow to the head dealing 2d8 damage with a 30% chance to stun the target for 1 turn.', 'Crushing Blow', 24, 200, 2, '{"if_heavy_punch"}', '{"x": 610, "y": 727}', '{"damage": "2d8 bludgeoning", "stun_chance": "30%", "duration": "1 turn"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0b75feb-a15b-4cc3-a461-ab1c209b5272', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_break_chains', 'Zincir Kırma', 'Break Chains', 'Kaslarınızı anında sıkarak kavramalardan, sabitlemelerden veya yavaşlatma etkilerinden kurtulun.', 'Instantly flex your muscles to free yourself from grapples, roots, or slowing effects.', 'Unstoppable', 26, 200, 2, '{"if_relentless_step"}', '{"x": -610, "y": 727}', '{"cleanse": "grapple, root, slow", "action": "instant"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f1a956dc-d7d4-4ca0-989e-bbe7f8cee5c9', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_iron_charge', 'Demir Hücum', 'Iron Charge', '8m ileri hücum edip çarpışmaya hazırlanın, maksimum canınızın %10''u kadar kalkan kazanın.', 'Charge forward 8m and brace for impact, gaining a shield equal to 10% of your max HP.', 'Cross-Branch', 28, 250, 2, '{"if_iron_skin", "if_bull_rush"}', '{"x": -173, "y": -100}', '{"range": "8m", "shield": "10% max HP"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d2b10b1-d69d-493c-91e0-600a1197436c', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_adamantine_block', 'Adamantiyum Blok', 'Adamantine Block', 'Gelen bir fiziksel saldırıyı tamamen bloke ederek tüm hasarını ve etkilerini sıfırlar. Çarpışma başına bir kez kullanılabilir.', 'Completely block one incoming physical attack, negating all of its damage and effects. Usable once per encounter.', 'Iron Body', 30, 250, 2, '{"if_steel_stance"}', '{"x": 1039, "y": -599}', '{"block": "100% negation", "limit": "once per encounter"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d0dcbb17-00b0-470b-9d7f-87799a7f71ce', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_internal_damage', 'İç Hasar', 'Internal Damage', 'Hedefin organlarına vurarak herhangi bir geçici kalkanı veya zırhı aşan, doğrudan can puanına 2d6 hasar verir.', 'Strikes the target''s organs, dealing 2d6 damage directly to their HP, bypassing any temporary shields or armor.', 'Crushing Blow', 32, 250, 2, '{"if_armor_pierce"}', '{"x": 771, "y": 919}', '{"damage": "2d6 true damage", "bypass": "shields and armor"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9bc062f9-42e1-43a4-aa5a-6acdc80c733f', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_meteor_charge', 'Meteor Hücumu', 'Meteor Charge', 'Düz bir çizgide 12m''ye kadar atılın ve vurulan ilk hedefe 3d6 ezici hasar verin.', 'Dash up to 12m in a straight line, dealing 3d6 bludgeoning damage to the first target hit.', 'Unstoppable', 34, 250, 2, '{"if_bull_rush"}', '{"x": -771, "y": 919}', '{"damage": "3d6 bludgeoning", "range": "12m dash"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('36e62568-c89d-4b36-b2c5-a006132fa319', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_crushing_counter', 'Ezen Kontra', 'Crushing Counter', 'Gelen bir saldırıyı engelleyin ve anında 2d10 hasar veren zırh delici bir vuruşla misilleme yapın.', 'Block an incoming attack and immediately retaliate with an armor-piercing strike that deals 2d10 damage.', 'Cross-Branch', 36, 250, 2, '{"if_heavy_punch", "if_steel_stance"}', '{"x": -389, "y": -225}', '{"damage": "2d10 bludgeoning", "armor_penetration": "100%", "trigger": "on block"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf15ec6a-85dc-4bb8-8a1f-fa39bf73ee92', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_counter_strike', 'Karşı Saldırı', 'Counter Strike', 'Yakın dövüş saldırısı aldığınızda, refleks olarak saldıran kişiye anında 1d8 fiziksel hasar geri verir.', 'When hit by a melee attack, immediately deal 1d8 physical damage back to the attacker as a reflex.', 'Iron Body', 38, 300, 2, '{"if_deflecting_palm"}', '{"x": 1255, "y": -724}', '{"damage": "1d8 physical", "trigger": "when hit in melee"}', '🥊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b5851594-d9ae-4a30-8cc7-77d87387f65d', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_cratering_smash', 'Krater Vuruşu', 'Cratering Smash', 'Yere vurarak 3m yarıçapındaki tüm düşmanlara 3d6 alan hasarı verir.', 'Slam the ground, dealing 3d6 area damage to all enemies within a 3m radius.', 'Crushing Blow', 39, 300, 2, '{"if_concussion_blow"}', '{"x": 932, "y": 1110}', '{"damage": "3d6 bludgeoning", "radius": "3m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3858a2cc-909c-45dd-ac06-d3f8dfd4638f', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_unstoppable_force', 'Durdurulamaz Güç', 'Unstoppable Force', 'Kaslarınızı gererek 2 tur boyunca tüm kitle kontrol etkilerine karşı tamamen bağışıklık kazanın.', 'Tense your muscles, becoming completely immune to all crowd control effects for 2 turns.', 'Unstoppable', 40, 300, 2, '{"if_break_chains"}', '{"x": -932, "y": 1110}', '{"immunity": "all crowd control", "duration": "2 turns"}', '🚂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0296a75b-1337-44b8-aa50-f923697385fe', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_titan_skin', 'Titan Derisi', 'Titan Skin', 'Deriniz taşa dönüşerek gelen tüm fiziksel hasarı kalıcı olarak 1d8+4 azaltır.', 'Your skin turns to stone, permanently reducing all incoming physical damage by 1d8+4.', 'Iron Body', 44, 400, 3, '{"if_adamantine_block"}', '{"x": 1472, "y": -849}', '{"damage_reduction": "1d8+4 physical", "duration": "passive"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8348b871-3aee-4120-aead-8e0daf0ce824', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_bone_breaker', 'Kemik Kıran', 'Bone Breaker', '3d10 hasar veren ve hedefin hareket hızını 2 tur boyunca 5m azaltan sakatlayıcı bir vuruş.', 'A crippling strike that deals 3d10 damage and reduces the target''s movement speed by 5m for 2 turns.', 'Crushing Blow', 45, 400, 3, '{"if_concussion_blow"}', '{"x": 1092, "y": 1302}', '{"damage": "3d10 bludgeoning", "movement_penalty": "-5m", "duration": "2 turns"}', '🩻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d3889145-9722-4507-a70d-c3e302489b3e', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_juggernaut_sprint', 'Juggernaut Koşusu', 'Juggernaut Sprint', 'Hareket hızını 8m artırır. Düşmanların içinden geçmek onlara 2d8 ezme hasarı verir.', 'Increases movement speed by 8m. Moving through enemies deals 2d8 trampling damage.', 'Unstoppable', 47, 400, 3, '{"if_meteor_charge"}', '{"x": -1092, "y": 1302}', '{"speed_bonus": "+8m", "damage": "2d8 bludgeoning", "duration": "2 turns"}', '🏃‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('36db1373-5a37-4735-b823-4082eecb708a', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_momentum_smash', 'Momentum Vuruşu', 'Momentum Smash', '10m''ye kadar atılın. Maksimum mesafe katedilirse hasar 1.5 katına çıkar. Temel hasar 4d8''dir.', 'Charge up to 10m. Damage is multiplied by 1.5x if maximum distance is covered. Deals 4d8 base damage.', 'Cross-Branch', 50, 450, 3, '{"if_cratering_smash", "if_meteor_charge"}', '{"x": -606, "y": -350}', '{"damage": "4d8 bludgeoning", "modifier": "1.5x at max range", "range": "10m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('148fb7a6-f5e3-4ce8-a2d6-ed5e9e93c8a0', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_kinetic_absorption', 'Kinetik Emilim', 'Kinetic Absorption', 'Alınan hasarın %20''sini emerek bir sonraki silahsız vuruşunuza ilave hasar olarak eklersiniz.', 'Absorb 20% of taken damage and add it as bonus damage to your next unarmed strike.', 'Iron Body', 52, 450, 3, '{"if_counter_strike"}', '{"x": 1688, "y": -974}', '{"absorption": "20%", "buff": "adds to next attack"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d607d386-35db-4749-bf2f-3c67bb4002d2', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_heart_stopper', 'Kalp Durduran', 'Heart Stopper', 'Göğse indirilen hassas darbe 4d8 hasar verir. Hedefi 2 tur boyunca büyü/yetenek kullanmaktan susturur.', 'A precision blow to the chest dealing 4d8 damage. Silences the target from using spells/abilities for 2 turns.', 'Crushing Blow', 54, 450, 3, '{"if_internal_damage"}', '{"x": 1253, "y": 1493}', '{"damage": "4d8 bludgeoning", "debuff": "silence", "duration": "2 turns"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5425d6f-7fa4-49ea-b686-ef742d1f9e9c', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_battering_ram', 'Koçbaşı', 'Battering Ram', 'Engelleri, kapıları veya ince duvarları kolayca yok ederek 10m''ye kadar atılır ve yaratıklara 4d6 hasar verir.', 'Charge up to 10m, easily destroying obstacles, doors, or thin walls, and dealing 4d6 damage to creatures.', 'Unstoppable', 55, 450, 3, '{"if_juggernaut_sprint"}', '{"x": -1253, "y": 1493}', '{"damage": "4d6 bludgeoning", "destruction": "obstacles and walls", "range": "10m"}', '🐏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93fdacdf-85e2-4f3e-bd6c-b674ea8c1127', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_kinetic_discharge', 'Kinetik Deşarj', 'Kinetic Discharge', 'Depolanan tüm emilmiş hasarı etrafınızda 8m''lik devasa bir şok dalgası olarak serbest bırakır.', 'Release all stored absorbed damage as a massive 8m AoE shockwave around you.', 'Cross-Branch', 58, 450, 3, '{"if_counter_strike", "if_internal_damage"}', '{"x": -822, "y": -475}', '{"damage": "100% of stored absorption", "radius": "8m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7883e9bf-1b77-419d-8cec-f0516f46c56c', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_unyielding_mass', 'Boyun Eğmez Kütle', 'Unyielding Mass', 'Devasa yoğunluğunuz sizi geri itilmelere, çekilmelere veya yere düşürülmelere karşı kalıcı olarak bağışık kılar.', 'Your immense density makes you permanently immune to being knocked back, pulled, or knocked prone.', 'Iron Body', 58, 500, 3, '{"if_titan_skin"}', '{"x": 1905, "y": -1099}', '{"immunity": "knockback, pull, prone", "duration": "passive"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9fb26340-b037-49e1-a073-35f3487d21a4', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_mountain_cleaver', 'Dağ Yaran', 'Mountain Cleaver', 'Şok dalgası yaratan süpürücü bir karate kesişi, 5m''lik bir çizgide 5d8 hasar verir.', 'A sweeping karate chop that generates a shockwave, dealing 5d8 damage in a 5m line.', 'Crushing Blow', 60, 500, 3, '{"if_cratering_smash"}', '{"x": 1414, "y": 1685}', '{"damage": "5d8 force", "area": "5m line"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('acae5f94-e006-4900-9f6f-5b4542c3b338', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_endless_stamina', 'Sonsuz Dayanıklılık', 'Endless Stamina', 'Maksimum dayanıklılığınızın %30''unu anında yeniler ve 1 saat boyunca tüm yorgunluk etkilerini yok sayarsınız.', 'Regain 30% of your maximum stamina immediately and ignore all exhaustion effects for 1 hour.', 'Unstoppable', 60, 500, 3, '{"if_unstoppable_force"}', '{"x": -1414, "y": 1685}', '{"restore": "30% stamina", "immunity": "exhaustion", "duration": "1 hour"}', '🔋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b88d76cf-e337-492f-8720-d33fa8905348', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_diamond_flesh', 'Elmas Et', 'Diamond Flesh', 'Deriniz kristalleşerek gelen tüm fiziksel hasarın %25''ini saldırgana geri yansıtır.', 'Your skin crystallizes, reflecting 25% of all incoming physical damage back to the attacker.', 'Iron Body', 64, 700, 4, '{"if_unyielding_mass"}', '{"x": 2121, "y": -1224}', '{"reflection": "25% physical damage", "duration": "passive"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b636d536-e32f-4ba1-a94a-68871565498d', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_unstoppable_juggernaut', 'Durdurulamaz Juggernaut', 'Unstoppable Juggernaut', 'Fırsat saldırılarını tetiklemeden düşmanların içinden geçin, hareket halindeyken +5 Zırh Sınıfı kazanın.', 'Move through enemies without provoking attacks of opportunity, gaining +5 AC while moving.', 'Cross-Branch', 65, 750, 4, '{"if_unyielding_mass", "if_juggernaut_sprint"}', '{"x": -1039, "y": -600}', '{"buff": "no opportunity attacks", "ac_bonus": "+5 during movement"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d021e4b9-f6e3-48dc-a117-04f209dbe78c', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_nullify_armor', 'Zırh İptali', 'Nullify Armor', 'Bir sonraki vuruşunuz savunmaların içinden titreşerek giyilen zırhtan gelen tüm Zırh Sınıfı bonuslarını tamamen yok sayar.', 'Your next strike vibrates through defenses, completely ignoring all AC bonuses from worn armor.', 'Crushing Blow', 66, 700, 4, '{"if_bone_breaker"}', '{"x": 1574, "y": 1876}', '{"armor_penetration": "100%", "duration": "1 strike"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5238f1bf-c027-4c37-b663-092c0dcdec44', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_fury_rush', 'Hiddet Akını', 'Fury Rush', '15m içindeki 3 hedefe kadar aralarında atılarak her birine art arda 4d8 hasar verirsiniz.', 'Dash between up to 3 targets within 15m, dealing 4d8 damage to each in rapid succession.', 'Unstoppable', 68, 700, 4, '{"if_battering_ram"}', '{"x": -1574, "y": 1876}', '{"damage": "4d8 bludgeoning per target", "targets": "up to 3", "range": "15m"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ec9aee6e-65c0-4fa1-97d2-bd01bc5e7914', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_iron_will', 'Demir İrade', 'Iron Will', 'Zihinsel metanetiniz bedeninizle eşleşir. Tüm kurtarma zarlarında kalıcı avantaj kazanırsınız.', 'Your mental fortitude matches your body. You gain permanent advantage on all saving throws.', 'Iron Body', 72, 800, 4, '{"if_diamond_flesh"}', '{"x": 2338, "y": -1349}', '{"advantage": "all saving throws", "duration": "passive"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1334a52f-5f97-4ef9-b974-34eec9baf0bb', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_devastating_uppercut', 'Yıkıcı Aparkat', 'Devastating Uppercut', '6d8 hasar veren efsanevi bir yumruk. Hedef havaya 5m fırlatılır ve yere düştüğünde düşme hasarı alır.', 'A legendary punch dealing 6d8 damage. The target is knocked 5m into the air, taking fall damage upon landing.', 'Crushing Blow', 74, 800, 4, '{"if_mountain_cleaver"}', '{"x": 1735, "y": 2068}', '{"damage": "6d8 bludgeoning", "knockup": "5m", "additional": "fall damage"}', '🚀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('516c671f-6204-4d81-844d-2aae33f991c7', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_earthquake_stomp', 'Deprem Ezmesi', 'Earthquake Stomp', 'Yere titanik bir güçle basın. 10m içindeki düşmanlar 5d6 hasar alır ve zar atamazlarsa yere düşerler.', 'Stomp the ground with titanic force. Enemies within 10m take 5d6 damage and must save or fall prone.', 'Unstoppable', 75, 800, 4, '{"if_fury_rush"}', '{"x": -1735, "y": 2068}', '{"damage": "5d6 bludgeoning", "radius": "10m", "status": "prone"}', '🦶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9bf649a2-ad2d-4d3f-b609-308b2ed51f79', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_shattering_charge', 'Parçalayan Hücum', 'Shattering Charge', '15m atılın. Yolunuz üzerindeki hedeflerin büyülü veya fiziksel kalkanlarını anında parçalar, 6d8 hasar verirsiniz.', 'Dash 15m. You instantly shatter any magical or physical shields on targets in your path, dealing 6d8 damage.', 'Cross-Branch', 76, 750, 4, '{"if_bone_breaker", "if_battering_ram"}', '{"x": -1255, "y": -725}', '{"damage": "6d8 bludgeoning", "shield_break": "100%", "range": "15m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98fe7944-d8c1-4530-b074-a31562ff1780', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_pain_to_power', 'Acıdan Güce', 'Pain to Power', 'Canınız %30''un altına düştüğünde, silahsız vuruşlarınız fazladan +3d6 hasar kazanır.', 'When your HP drops below 30%, your unarmed strikes gain an additional +3d6 damage.', 'Iron Body', 78, 900, 4, '{"if_kinetic_absorption"}', '{"x": 2554, "y": -1474}', '{"condition": "HP < 30%", "bonus_damage": "+3d6"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6229ff9b-a5be-433a-9924-ae40ddef406a', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_pressure_point', 'Basınç Noktası', 'Pressure Point', 'Hayati bir sinire vurarak 4d10 hasar verin. Hedef alacağı bir sonraki saldırıdan iki kat hasar alır.', 'Strike a crucial nerve for 4d10 damage. The target takes double damage from the next attack they receive.', 'Crushing Blow', 79, 900, 4, '{"if_heart_stopper"}', '{"x": 1896, "y": 2259}', '{"damage": "4d10 piercing", "debuff": "vulnerable to next attack"}', '📍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a756fd57-0019-4cd0-8882-60d0aa2496cf', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_defy_death', 'Ölümle Alay', 'Defy Death', '0 Cana düştüğünüzde, bunun yerine 1 Cana düşersiniz ve anında ücretsiz 5m hareket kazanırsınız (Uzun dinlenme başına bir kez).', 'When reduced to 0 HP, you instead drop to 1 HP and immediately gain a free 5m movement (Once per long rest).', 'Unstoppable', 80, 900, 4, '{"if_endless_stamina"}', '{"x": -1896, "y": 2259}', '{"survival": "drop to 1 HP instead of 0", "bonus_movement": "5m", "limit": "once per long rest"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9d738a57-ff9f-437e-903e-41f0b89a2998', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_impenetrable_fortress', 'Aşılmaz Kale', 'Impenetrable Fortress', 'Mutlak savunmanızı yönlendirin. 3 tur boyunca tüm kaynaklardan %50 daha az hasar alırsınız.', 'Channel your absolute defense. For 3 turns, you take 50% less damage from all sources.', 'Iron Body', 82, 1200, 5, '{"if_iron_will", "if_pain_to_power"}', '{"x": 2771, "y": -1599}', '{"damage_reduction": "50% all sources", "duration": "3 turns"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('05ddb0fc-2b3b-4d2b-ab79-e762fa068239', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_vibrating_palm', 'Titreşimli Avuç', 'Vibrating Palm', 'Hedefe ölümcül titreşimler yerleştirin. 3 tur sonra hedef patlayarak 10d10 ölümcül hasar alır.', 'Plant fatal vibrations in the target. After 3 turns, the target erupts, taking 10d10 lethal damage.', 'Crushing Blow', 84, 1200, 5, '{"if_nullify_armor", "if_pressure_point"}', '{"x": 2056, "y": 2451}', '{"delayed_damage": "10d10 force", "delay": "3 turns"}', '🖐️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9a2969af-61fc-4c74-b592-d095d897276f', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_relentless_assault', 'Kesintisiz Saldırı', 'Relentless Assault', 'Vücudunuzu sınırlarının ötesine zorlayarak anında ardışık 2 tur hakkı elde edersiniz.', 'Push your body beyond its limits, taking 2 consecutive turns immediately.', 'Unstoppable', 86, 1200, 5, '{"if_earthquake_stomp", "if_defy_death"}', '{"x": -2056, "y": 2451}', '{"extra_turns": "2", "action": "instant"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7af06f28-9f5a-4e02-833b-ee18e33514ac', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_body_of_destruction', 'Yıkım Bedeni', 'Body of Destruction', 'Bedeniniz canlı bir silaha dönüşür. Silahsız vuruşlar kalıcı olarak +3d8 hasar verir ve kitle kontrol direnci kazanırsınız.', 'Your body becomes a living weapon. Unarmed strikes permanently deal +3d8 damage, and you gain permanent CC resistance.', 'Cross-Branch', 88, 1250, 5, '{"if_diamond_flesh", "if_nullify_armor", "if_earthquake_stomp"}', '{"x": -1472, "y": -850}', '{"bonus_damage": "+3d8 permanently", "resistance": "crowd control"}', '⚛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d814ccb3-6f59-43fa-8c2f-5113d3f32473', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_ultimate_iron_god', 'Demir Tanrı Avatarı', 'Iron God Avatar', 'Ulti: 10 tur boyunca Demir Tanrı olun. +10 ZS ve fiziksel hasara karşı tam bağışıklık kazanın, ancak büyü ile iyileştirilemezsiniz.', 'Ultimate: Become the Iron God for 10 turns. Gain +10 AC and total immunity to physical damage, but you cannot be healed by magic.', 'Iron Body', 92, 1500, 5, '{"if_impenetrable_fortress"}', '{"x": 2987, "y": -1724}', '{"ac_bonus": "+10", "immunity": "all physical damage", "debuff": "cannot be healed magically", "duration": "10 turns"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a556ce00-01a4-43eb-8054-84204fdd58a2', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_ultimate_world_breaker', 'Dünya Kıran Vuruş', 'World Breaker Strike', 'Ulti: Tüm zırhları yok sayarak 20d10 hasar veren dünyayı sarsan bir vuruş indirin. Diğerlerine yarı hasar veren 10m''lik bir şok dalgası yaratır.', 'Ultimate: Deliver an earth-shattering blow for 20d10 damage, ignoring all armor. Creates a 10m shockwave dealing half damage to others.', 'Crushing Blow', 94, 1500, 5, '{"if_vibrating_palm"}', '{"x": 2217, "y": 2642}', '{"damage": "20d10 force", "armor_penetration": "100%", "aoe_damage": "half damage in 10m radius"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3dcdda1-cd0b-47c8-a4e5-28edf3d940be', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_ultimate_colossus', 'Devasanın Yürüyüşü', 'March of the Colossus', 'Ulti: 5 tur boyunca hareket hızınız iki katına çıkar. Düşmanların içinden geçerek 5d10 hasar verebilir ve tamamen durdurulamaz olursunuz.', 'Ultimate: For 5 turns, your movement speed is doubled. You can walk through enemies, dealing 5d10 damage, and become completely unstoppable.', 'Unstoppable', 95, 1500, 5, '{"if_relentless_assault"}', '{"x": -2217, "y": 2642}', '{"speed_multiplier": "2x", "trample_damage": "5d10 bludgeoning", "immunity": "all CC", "duration": "5 turns"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1b7be54-3eec-4a3c-8c7f-7d3723c8c7d4', '67ec3dc1-08f9-4b08-aab5-4db32e708d9a', 'if_grand_ultimate_fist_of_the_north', 'Kuzey Yıldızı Yumruğu', 'Fist of the North Star', 'Büyük Ulti: 30m atılın ve hedefe bulanık bir hızda 100 kez vurun. 50d10 gerçek hasar verir, bağışıklıkları yok sayar ve zırhlarını kalıcı olarak yok eder.', 'Grand Ultimate: Dash 30m and strike a target 100 times in a blur. Deals 50d10 true damage, ignores immunities, and permanently destroys their armor.', 'Cross-Branch', 100, 2000, 5, '{"if_ultimate_iron_god", "if_ultimate_world_breaker", "if_ultimate_colossus"}', '{"x": -1688, "y": -975}', '{"damage": "50d10 true damage", "armor_destruction": "permanent", "bypass": "immunities", "range": "30m"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4555c9d-6c7e-49bd-85d5-87e7c373b5dc', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_twin_strike', 'İkiz Vuruş', 'Twin Strike', 'Çift silahınla iki kez vurarak her vuruşta 1d6 fiziksel hasar ver.', 'Strike twice with your dual weapons, dealing 1d6 physical damage per hit.', 'Twin Slash', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "2x 1d6 physical", "range": "2m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fdff5828-e28f-4195-9587-173a9fef0c58', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_swift_draw', 'Çevik Çekiş', 'Swift Draw', 'Silahlarını aniden çekerek 4m''lik bir hatta saldır, 2d6 hasar ver ve hareket hızını 1 tur boyunca 2m artır.', 'Instantly draw your weapons and strike in a 4m line, dealing 2d6 damage and increasing your movement speed by 2m for 1 turn.', 'Twin Slash', 5, 75, 1, '{"ls_twin_strike"}', '{"x": 389, "y": -224}', '{"damage": "2d6 physical", "range": "4m line", "buff": "+2m movement speed (1 turn)"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2ae2632a-8ea6-47ee-bb28-fb83d381ed97', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_crossing_blades', 'Kesişen Bıçaklar', 'Crossing Blades', 'Bıçaklarını çaprazlayarak X şeklinde saldır, 3d6 hasar ver ve kanama etkisi uygula (2 tur boyunca tur başına 1d4).', 'Cross your blades to attack in an X pattern, dealing 3d6 damage and inflicting a bleeding effect (1d4 per turn for 2 turns).', 'Twin Slash', 10, 100, 1, '{"ls_swift_draw"}', '{"x": 606, "y": -349}', '{"damage": "3d6 physical", "range": "3m", "condition": "Bleeding (1d4/turn, 2 turns)"}', '❌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e25d8ca1-9753-4ff3-a34e-b67fdad4c5d5', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_dancing_blade', 'Dans Eden Kesik', 'Dancing Blade', 'Etrafında dönerek 3m içindeki tüm düşmanlara 2d8 hasar ver ve 1 tur boyunca %10 kaçınma kazan.', 'Perform a spinning attack hitting all enemies within 3m for 2d8 damage and gaining 10% evasion for 1 turn.', 'Twin Slash', 15, 125, 1, '{"ls_crossing_blades"}', '{"x": 822, "y": -474}', '{"damage": "2d8 physical", "range": "3m radius", "buff": "10% Evasion (1 turn)"}', '💃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30541b1b-c2d5-48b3-956b-0596e14d5ec1', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_dual_flurry', 'Çifte Bora', 'Dual Flurry', 'Peş peşe 4 hızlı vuruş yap, her biri 1d8 hasar verir. Kritik vuruşlar 5 enerji yeniler.', 'Unleash a rapid series of 4 strikes, dealing 1d8 damage each. Critical hits restore 5 stamina.', 'Twin Slash', 25, 200, 2, '{"ls_dancing_blade"}', '{"x": 1039, "y": -599}', '{"damage": "4x 1d8 physical", "range": "2m", "special": "Crits restore 5 stamina"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8ac59edc-a25e-46dc-bf42-e7fb27c1910e', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_whirlwind_slash', 'Kasırga Kesiti', 'Whirlwind Slash', 'Hareketli bir kasırga saldırısı. 5m''ye kadar ilerle, yolunun 2m yakınındaki düşmanlara 3d8 hasar ver.', 'A moving whirlwind attack. Move up to 5m, dealing 3d8 damage to enemies within 2m of your path.', 'Twin Slash', 30, 225, 2, '{"ls_dual_flurry"}', '{"x": 1255, "y": -724}', '{"damage": "3d8 physical", "range": "5m movement, 2m radius"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d02aa8e-4141-4819-81ba-f12784386b48', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_gale_strikes', 'Fırtına Vuruşları', 'Gale Strikes', 'Saldırılarına rüzgar aşılanır, yakın dövüş menzilini 2m artırır ve 3 tur boyunca fazladan 1d6 rüzgar hasarı verir.', 'Your attacks become infused with wind, extending your melee range by 2m and dealing an extra 1d6 wind damage for 3 turns.', 'Twin Slash', 35, 250, 2, '{"ls_whirlwind_slash"}', '{"x": 1472, "y": -849}', '{"buff": "+2m melee range, +1d6 wind damage", "duration": "3 turns"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0917cff6-f301-434b-9524-e4df94a1ac7b', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_phantom_swords', 'Hayalet Kılıçlar', 'Phantom Swords', 'Saldırılarını taklit eden spektral kılıçlar çağır, 3 tur boyunca verdiğin hasarın %50''si kadar güç (force) hasarı verir.', 'Summon spectral blades that mimic your attacks for 3 turns, dealing 50% of your damage as force damage.', 'Twin Slash', 45, 400, 3, '{"ls_gale_strikes"}', '{"x": 1688, "y": -974}', '{"buff": "Additional 50% damage as Force", "duration": "3 turns"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9dc9e2e0-5534-41a6-9170-713e1206f1e2', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_severing_wind', 'Koparan Rüzgar', 'Severing Wind', 'Bıçaklarını savurarak 10m''lik bir koni şeklinde rüzgar şoku gönder, 6d8 kesici hasar ver ve düşmanları 3m geri it.', 'Swing your blades to unleash a shockwave of wind in a 10m cone, dealing 6d8 slashing damage and pushing enemies back 3m.', 'Twin Slash', 55, 450, 3, '{"ls_phantom_swords"}', '{"x": 1905, "y": -1099}', '{"damage": "6d8 slashing", "range": "10m cone", "condition": "Pushback 3m"}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('deff461b-d55e-4cf8-b9c5-8c85edc61e62', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_thousand_cuts', 'Bin Kesik', 'Thousand Cuts', '5m içindeki bir düşmanı hedef al. Etrafında ışınlanarak her biri 1d10 hasar veren 10 vuruş yap. Kullanıcı bu saldırı sırasında hasar görmez.', 'Target an enemy within 5m. Teleport around them, striking 10 times for 1d10 damage each. User is invulnerable during this attack.', 'Twin Slash', 65, 650, 4, '{"ls_severing_wind"}', '{"x": 2121, "y": -1224}', '{"damage": "10x 1d10 physical", "range": "5m", "buff": "Invulnerability (during cast)"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7bf0d96-fcf5-4116-936c-361acee6e22f', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_crescent_dance', 'Hilal Dansı', 'Crescent Dance', '8m''lik bir yarıçapta savuran saldırılar yap, 8d8 hasar ver ve sonraki tur saldırıyı yarı hasarla tekrarlayan bir ardıl görüntü bırak.', 'Perform sweeping attacks in an 8m radius, dealing 8d8 damage and leaving an afterimage that repeats the attack next turn for half damage.', 'Twin Slash', 75, 750, 4, '{"ls_thousand_cuts"}', '{"x": 2338, "y": -1349}', '{"damage": "8d8 physical", "range": "8m radius", "special": "Repeats next turn (50% damage)"}', '🌙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7fd74d75-f929-4815-b976-1f5be4b62251', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_eclipse_slashes', 'Tutulma Kesikleri', 'Eclipse Slashes', '15m''ye kadar atıl, yolundaki tüm düşmanlara anında vur. 10d10 hasar verir ve Derin Yaralar (3 tur boyunca 3d6 kanama) açar.', 'Dash up to 15m, instantly striking all enemies in your path. Deals 10d10 damage and inflicts Deep Wounds (3d6 bleed for 3 turns).', 'Twin Slash', 85, 1000, 5, '{"ls_crescent_dance"}', '{"x": 2554, "y": -1474}', '{"damage": "10d10 physical", "range": "15m dash", "condition": "Deep Wounds (3d6 bleed/turn, 3 turns)"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf1a2e9f-08a3-4d04-bcda-f8528c8c586c', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_twin_dragon_rend', 'Çifte Ejder Yırtışı', 'Twin Dragon Rend', 'Savaş alanını yutan iki hayalet ejderha yarat. 20m''lik bir alanda 15d12 hasar verir ve 3 tur boyunca düşman zırhını %50 azaltır.', 'Manifest twin spectral dragons that consume the battlefield. Deals 15d12 damage in a 20m radius and reduces enemy armor by 50% for 3 turns.', 'Twin Slash', 95, 1250, 5, '{"ls_eclipse_slashes"}', '{"x": 2771, "y": -1599}', '{"damage": "15d12 force/slashing", "range": "20m radius", "debuff": "-50% Armor (3 turns)"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1cd63c8a-fd16-4e7c-a37d-ad31430bc69c', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_honorable_stance', 'Onurlu Duruş', 'Honorable Stance', 'Savunmacı bir duruşa geçerek 3 tur boyunca zırhını +2 artır ve alınan fiziksel hasarı %10 azalt.', 'Adopt a defensive stance, increasing armor by +2 and reducing physical damage taken by 10% for 3 turns.', 'Honor', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"buff": "+2 Armor, 10% Physical Resistance", "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('697b1b9f-14c0-4372-babc-eeef7daac819', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_samurai_challenge', 'Samuray Meydan Okuması', 'Samurai Challenge', '10m içindeki bir düşmanı düelloya davet et. Senden başkasına yapacakları saldırılarda dezavantaja sahip olurlar ve sen onlara karşı 3 tur boyunca +1d4 hasar kazanırsın.', 'Challenge an enemy within 10m to a duel. They have disadvantage on attacks against anyone other than you, and you gain +1d4 damage against them for 3 turns.', 'Honor', 5, 75, 1, '{"ls_honorable_stance"}', '{"x": 289, "y": 344}', '{"range": "10m", "debuff": "Disadvantage vs others", "buff": "+1d4 damage vs target", "duration": "3 turns"}', '🎌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2c753d02-0c57-4381-a3e7-e7b44f2986dd', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_focused_mind', 'Odaklanmış Zihin', 'Focused Mind', 'Zihnini dikkat dağıtıcılardan arındır. Zihinsel bir rahatsızlığı (büyülenme, korku vb.) iyileştir ve 2 tur boyunca Bilgelik kurtarma zarlarına avantaj kazan.', 'Clear your mind of distractions. Cure one mental ailment (charm, fear, etc.) and gain advantage on Wisdom saving throws for 2 turns.', 'Honor', 10, 100, 1, '{"ls_samurai_challenge"}', '{"x": 449, "y": 536}', '{"cleanse": "Cure 1 mental status", "buff": "Advantage on WIS saves (2 turns)"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60846ab7-b416-4415-a205-9a4f65dfdd8e', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_deflecting_steel', 'Sektiren Çelik', 'Deflecting Steel', 'Bir reaksiyon olarak, gelen menzilli fiziksel saldırıları sektirerek hasarı 1d10 + seviyen kadar azalt.', 'As a reaction, deflect incoming ranged physical attacks, reducing damage by 1d10 + your level.', 'Honor', 15, 125, 1, '{"ls_focused_mind"}', '{"x": 610, "y": 727}', '{"mitigation": "1d10 + Level damage reduction vs ranged"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e3dcc40-e308-442c-86b0-064f2a228652', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_warriors_resolve', 'Savaşçının Azmi', 'Warrior''s Resolve', 'Sağlığın %50''nin altına düştüğünde, 3d8+10 HP iyileş ve 2 tur boyunca %15 fiziksel direnç kazan.', 'When your health falls below 50%, heal for 3d8+10 HP and gain 15% physical resistance for 2 turns.', 'Honor', 25, 200, 2, '{"ls_deflecting_steel"}', '{"x": 771, "y": 919}', '{"trigger": "HP < 50%", "healing": "3d8+10 HP", "buff": "15% Physical Resistance (2 turns)"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b214bf19-2359-42e2-8523-eca89bff1657', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_vengeful_counter', 'İntikamcı Kontra', 'Vengeful Counter', 'Savuşturma duruşuna geç. Sana yapılan ilk yakın dövüş saldırısı engellenir ve anında 4d8 hasarla karşı saldırı yaparsın.', 'Enter a parry stance. The next melee attack against you is negated, and you instantly counterattack for 4d8 damage.', 'Honor', 30, 225, 2, '{"ls_warriors_resolve"}', '{"x": 932, "y": 1110}', '{"buff": "Negate next melee attack", "damage": "4d8 physical counterattack"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb964a0d-83d6-4752-9a07-6dc85c9e8662', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_stoic_guard', 'Metanetli Koruma', 'Stoic Guard', '5m''lik bir azim halesi yansıt. Haledeki müttefikler 3 tur boyunca +3 zırh ve korku etkilerine karşı direnç kazanır.', 'Project a 5m aura of resolve. Allies within the aura gain +3 armor and resistance to fear effects for 3 turns.', 'Honor', 35, 250, 2, '{"ls_vengeful_counter"}', '{"x": 1092, "y": 1302}', '{"range": "5m aura", "buff": "+3 Armor, Fear resistance", "duration": "3 turns"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d331fbd-4d5e-4e17-bf92-728634bf6b8c', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_ancestral_guidance', 'Ataların Rehberliği', 'Ancestral Guidance', 'Geçmiş samurayların ruhlarını çağır. Sonraki 3 saldırın avantajlı olur ve fazladan 2d8 ruhani hasar verir.', 'Call upon the spirits of past samurais. Your next 3 attacks have advantage and deal an extra 2d8 spiritual damage.', 'Honor', 45, 400, 3, '{"ls_stoic_guard"}', '{"x": 1253, "y": 1493}', '{"buff": "Advantage & +2d8 spirit damage on next 3 attacks"}', '🏮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74382cbe-5af5-4b14-ab7a-271c3214d3f2', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_iron_will', 'Demir İrade', 'Iron Will', '2 tur boyunca tüm kitle kontrol etkilerine bağışıklık kazan ve maksimum sağlığının %20''si kadar geçici HP elde et.', 'Become immune to all crowd control effects for 2 turns and gain temporary HP equal to 20% of your max HP.', 'Honor', 55, 450, 3, '{"ls_ancestral_guidance"}', '{"x": 1414, "y": 1685}', '{"buff": "CC Immunity (2 turns)", "healing": "20% Max HP as Temp HP"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff5226f6-c6f9-4293-a9dc-b99cf0462621', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_unyielding_spirit', 'Boyun Eğmez Ruh', 'Unyielding Spirit', '0 HP''ye düştüğünde, %25 HP ile anında diril ve 1 tur boyunca dokunulmazlık kazan. (Uzun dinlenmede bir kez kullanılır).', 'When reduced to 0 HP, immediately revive with 25% HP and gain invulnerability for 1 turn. (Usable once per long rest).', 'Honor', 65, 650, 4, '{"ls_iron_will"}', '{"x": 1574, "y": 1876}', '{"trigger": "On 0 HP", "healing": "Revive at 25% HP", "buff": "Invulnerability (1 turn)", "special": "Once per long rest"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c8b78d84-0f02-4701-8daa-14e883bd9e2e', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_last_stand', 'Son Direniş', 'Last Stand', 'Yerine sağlam bas. 3 tur boyunca hareket hızın 0 olur, ancak %50 daha az hasar alırsın ve kontra saldırılarda iki kat hasar verirsin.', 'Plant your feet. For 3 turns, your movement speed becomes 0, but you take 50% less damage and deal double damage on counterattacks.', 'Honor', 75, 750, 4, '{"ls_unyielding_spirit"}', '{"x": 1735, "y": 2068}', '{"debuff": "Movement 0", "buff": "50% Damage Reduction, 2x Counterattack Damage", "duration": "3 turns"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('27ce7b94-0466-4b8d-91c5-f75b9b9d30f5', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_immortal_honor', 'Ölümsüz Onur', 'Immortal Honor', 'Saf onur enerjisi yay. 15m içindeki müttefikler 2 tur boyunca 1 HP''nin altına düşürülemez.', 'Radiate pure honorable energy. Allies within 15m cannot be reduced below 1 HP for 2 turns.', 'Honor', 85, 1000, 5, '{"ls_last_stand"}', '{"x": 1896, "y": 2259}', '{"range": "15m radius", "buff": "Allies cannot fall below 1 HP", "duration": "2 turns"}', '🪷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('773aa8ee-cfa7-4bd3-8db1-a0073861fa58', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_bushido_incarnate', 'Bushido Tecellisi', 'Bushido Incarnate', 'Nihai savaşçı kodunu cisimleştir. 5 tur boyunca +%50 tüm dirençler, +%50 hasar kazanırsın ve sana vuran her düşman 5d10 yansıma hasarı alır.', 'Embody the ultimate warrior code. For 5 turns, you gain +50% all resistances, +50% damage, and any enemy striking you takes 5d10 reflective damage.', 'Honor', 95, 1250, 5, '{"ls_immortal_honor"}', '{"x": 2056, "y": 2451}', '{"buff": "+50% All Resistances, +50% Damage", "damage": "5d10 reflective damage", "duration": "5 turns"}', '👺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('307d2385-6492-41bc-b6de-922a9fe04fee', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_heavy_cleave', 'Ağır Yarma', 'Heavy Cleave', 'Güçlü iki elli bir tepeden vuruş, 2d8 fiziksel hasar verir ve hedefin hareketini 1 tur boyunca 2m yavaşlatır.', 'A powerful two-handed overhead strike dealing 2d8 physical damage and slowing the target''s movement by 2m for 1 turn.', 'Legendary Blade', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "2d8 physical", "range": "2m", "condition": "Slow 2m (1 turn)"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7f8f6df3-0f06-4b3e-ae5f-ff5b18269008', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_piercing_thrust', 'Delici Hamle', 'Piercing Thrust', 'Kılıcını 5m''lik bir hattan ileri sapla, 2d10 hasar ver. Hedefin zırhının %50''sini yok sayar.', 'Thrust your sword forward in a 5m line, dealing 2d10 damage. Ignores 50% of the target''s armor.', 'Legendary Blade', 5, 75, 1, '{"ls_heavy_cleave"}', '{"x": -289, "y": 344}', '{"damage": "2d10 physical", "range": "5m line", "special": "Ignores 50% Armor"}', '🔱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fec98611-5a51-4aae-b701-39f0b4cff162', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_spirit_blade', 'Ruhani Kılıç', 'Spirit Blade', 'Kılıcına ruh enerjisi aşıla. 2 tur içindeki bir sonraki saldırın fazladan 3d6 güç hasarı verir ve %100 isabet oranına sahip olur.', 'Infuse your sword with spirit energy. Your next attack within 2 turns deals an extra 3d6 force damage and has 100% accuracy.', 'Legendary Blade', 10, 100, 1, '{"ls_piercing_thrust"}', '{"x": -449, "y": 536}', '{"buff": "Next attack gains +3d6 force damage, 100% Hit", "duration": "2 turns"}', '❇️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('050a703b-738d-4bcb-a075-ca9f98782192', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_earth_shatter', 'Yeryüzü Parçalayan', 'Earth Shatter', 'Kılıcını yere çarparak 4m''lik bir koni içindeki düşmanlara 3d8 hasar ver ve onları yere ser (prone).', 'Slam your blade into the ground, dealing 3d8 damage to enemies in a 4m cone and knocking them prone.', 'Legendary Blade', 15, 125, 1, '{"ls_spirit_blade"}', '{"x": -610, "y": 727}', '{"damage": "3d8 physical", "range": "4m cone", "condition": "Prone"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('265c0d4f-ec7f-457e-95fc-95cb2acdbcaf', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_mythic_strike', 'Mistik Vuruş', 'Mythic Strike', '3m genişliğinde, 6m uzunluğundaki bir hat boyunca düşmanlara 4d10 hasar veren efsanevi yatay bir kesik.', 'A legendary horizontal slash that deals 4d10 damage to enemies within a 3m wide, 6m long line.', 'Legendary Blade', 25, 200, 2, '{"ls_earth_shatter"}', '{"x": -771, "y": 919}', '{"damage": "4d10 physical", "range": "6m line (3m wide)"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2753bb63-988e-4a46-8041-9a384ddd9c88', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_dragon_fang', 'Ejderha Dişi', 'Dragon Fang', '8m''ye kadar zıpla ve yıkıcı bir vuruşla yere inerek 3m''lik yarıçapta 5d8 hasar ver.', 'Leap up to 8m and crash down with a devastating strike, dealing 5d8 damage in a 3m radius.', 'Legendary Blade', 30, 225, 2, '{"ls_mythic_strike"}', '{"x": -932, "y": 1110}', '{"damage": "5d8 physical", "range": "8m leap, 3m radius"}', '🦷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cd231f65-6669-4231-9fdf-a210aa234d49', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_void_slash', 'Hiçlik Kesiği', 'Void Slash', 'Uzay dokusunu kes. 10m''ye kadar uzaklıktaki bir düşmanı hedef al; yerinden hareket etmeden anında 4d12 güç hasarı ver.', 'Slash through the fabric of space. Target an enemy up to 10m away; deal 4d12 force damage instantly without moving.', 'Legendary Blade', 35, 250, 2, '{"ls_dragon_fang"}', '{"x": -1092, "y": 1302}', '{"damage": "4d12 force", "range": "10m"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('37c0b00a-418b-41ec-ad79-214afb34b811', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_heavenly_descent', 'Cennetin İnişi', 'Heavenly Descent', 'Gökten 5m yarıçapında yere çakılan devasa bir spektral kılıç çağır, 6d10 parlak hasar ver ve düşmanları 1 tur sersemlet.', 'Summon a massive spectral sword from the sky that crashes down in a 5m radius, dealing 6d10 radiant damage and stunning enemies for 1 turn.', 'Legendary Blade', 45, 400, 3, '{"ls_void_slash"}', '{"x": -1253, "y": 1493}', '{"damage": "6d10 radiant", "range": "5m radius", "condition": "Stun (1 turn)"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f93b1593-4130-49da-9a1d-8aaac24d209e', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_crimson_arc', 'Kızıl Kavis', 'Crimson Arc', '8m''lik bir konide geniş çaplı savurma saldırısı. 7d8 kesici hasar verir ve verilen hasarın %20''si kadar seni iyileştirir.', 'A wide sweeping attack in an 8m cone. Deals 7d8 slashing damage and heals you for 20% of the damage dealt.', 'Legendary Blade', 55, 450, 3, '{"ls_heavenly_descent"}', '{"x": -1414, "y": 1685}', '{"damage": "7d8 slashing", "range": "8m cone", "healing": "20% Lifesteal"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33365f0a-ea7f-403f-92c9-962070308533', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_mountain_cleaver', 'Dağ Yaran', 'Mountain Cleaver', 'Dağları bölebilecek efsanevi bir vuruş. Tek bir hedefe 10d12 hasar verir. Eğer hedefi öldürürse, kalan hasar 5m içindeki başka bir düşmana isabet eder.', 'A legendary strike capable of splitting mountains. Deals 10d12 damage to a single target. If it kills them, the remaining damage hits another enemy within 5m.', 'Legendary Blade', 65, 650, 4, '{"ls_crimson_arc"}', '{"x": -1574, "y": 1876}', '{"damage": "10d12 physical", "range": "Melee", "special": "Overkill damage leaps to 5m"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7bbd954-f712-41bb-a416-d939eadda1a4', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_star_fall_strike', 'Yıldız Düşüren Vuruş', 'Star Fall Strike', 'Bıçağına kozmik enerji kanalize et. 10m''lik bir hatta 12d10 hasar verir ve 3 tur boyunca yanan bir yıldız ışığı izi (tur başına 2d8 hasar) bırakır.', 'Channel cosmic energy into your blade. Deals 12d10 damage in a 10m line and leaves a trail of burning starlight (2d8 damage per turn) for 3 turns.', 'Legendary Blade', 75, 750, 4, '{"ls_mountain_cleaver"}', '{"x": -1735, "y": 2068}', '{"damage": "12d10 radiant", "range": "10m line", "area_effect": "2d8 damage/turn trail (3 turns)"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33319c98-a6fd-407d-8d40-171bbe563a3a', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_soul_render', 'Ruh Parçalayan', 'Soul Render', 'Doğrudan ruhu hedef alan bir vuruş. Tüm zırh ve kalkanları yok sayarak 15d10 nekrotik hasar verir. Menzil: 3m.', 'A strike that targets the soul directly. Deals 15d10 necrotic damage, bypassing all armor and shields. Range: 3m.', 'Legendary Blade', 85, 1000, 5, '{"ls_star_fall_strike"}', '{"x": -1896, "y": 2259}', '{"damage": "15d10 necrotic", "range": "3m", "special": "Ignores Armor and Shields"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c2b6ee90-349d-4ead-adb4-a9ff11112de4', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_blade_of_antiquity', 'Kadimlerin Kılıcı', 'Blade of Antiquity', '3 tur boyunca nihai efsanevi kılıcı çağır. Saldırıların fazladan 8d12 parlak hasar verir ve yakın dövüş menzilini 10m''ye çıkarır.', 'Summon the ultimate legendary blade for 3 turns. Your attacks deal an additional 8d12 radiant damage and extend your melee range to 10m.', 'Legendary Blade', 95, 1250, 5, '{"ls_soul_render"}', '{"x": -2056, "y": 2451}', '{"buff": "+8d12 radiant damage, 10m Melee Range", "duration": "3 turns"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fc5f2e09-d2e9-4ff4-93e2-72d5d5f0c5e5', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_honorable_twins', 'Onurlu İkizler', 'Honorable Twins', 'İki silah kullanırken +2 Zırh Sınıfı kazanırsın. Bir saldırıyı savuşturduğunda, her iki silahla da 3d6 hasarlık karşılık verirsin.', 'While wielding two weapons, you gain +2 AC. When you parry an attack, you strike back with both weapons for 3d6 damage each.', 'Cross-Branch', 30, 250, 2, '{"ls_dual_flurry", "ls_vengeful_counter"}', '{"x": -173, "y": -100}', '{"buff": "+2 AC", "trigger": "On parry: 2x 3d6 damage"}', '♊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8bdf619a-3234-42e5-bf94-381917950cac', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_legendary_flurry', 'Efsanevi Bora', 'Legendary Flurry', 'Tek bir hedefe her vuruşta 2d10 hasar veren, sıçramalı 5 vuruşluk bir kombo yap. Menzil: 6m.', 'Perform a leaping 5-hit combo, dealing 2d10 damage per hit to a single target. Range: 6m.', 'Cross-Branch', 35, 275, 2, '{"ls_whirlwind_slash", "ls_dragon_fang"}', '{"x": -389, "y": -225}', '{"damage": "5x 2d10 physical", "range": "6m leap"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a00cbe74-db16-4619-a53f-a297a7bd5b8c', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_stoic_strike', 'Metanetli Vuruş', 'Stoic Strike', 'Gelen bir saldırıyı absorbe et ve enerjisini yönlendirerek 4m''lik konide 5d10 + (Emilen Hasar) kadar odaklı bir vuruş yap.', 'Absorb an incoming attack and redirect its energy into a focused strike dealing 5d10 + (Absorbed Damage) in a 4m cone.', 'Cross-Branch', 40, 300, 2, '{"ls_stoic_guard", "ls_void_slash"}', '{"x": -606, "y": -350}', '{"damage": "5d10 + Absorbed Damage", "range": "4m cone"}', '🗻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ab1b53b4-1859-4610-98b3-da976a0003ed', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_phantom_guard', 'Hayalet Koruma', 'Phantom Guard', 'Hayalet kılıçların senin için saldırıları aktif olarak savuşturur, 3 tur boyunca %25 kaçınma sağlar ve saldıranlara 2d8 hasar verir.', 'Your phantom swords actively parry attacks for you, granting 25% evasion and dealing 2d8 damage to attackers for 3 turns.', 'Cross-Branch', 50, 450, 3, '{"ls_phantom_swords", "ls_ancestral_guidance"}', '{"x": -822, "y": -475}', '{"buff": "25% Evasion", "damage": "2d8 counter damage", "duration": "3 turns"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('66718fa8-fdf1-4e40-ad41-f684ae678efa', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_void_twins', 'Hiçlik İkizleri', 'Void Twins', 'Çifte kılıçla uzayı yırtarak 6m''lik bir vakum bölgesi oluştur. İçerideki düşmanlar tur başına 5d8 güç hasarı alır ve hareket hızları 3 tur yarıya düşer.', 'Rip through space with dual blades, creating a 6m zone of vacuum. Enemies inside take 5d8 force damage per turn and have movement halved for 3 turns.', 'Cross-Branch', 60, 500, 3, '{"ls_severing_wind", "ls_heavenly_descent"}', '{"x": -1039, "y": -600}', '{"range": "6m zone", "damage": "5d8 force/turn", "debuff": "Movement Halved", "duration": "3 turns"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a6e4aa67-90e6-4514-a181-54ec97a9bb91', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_ancestral_arc', 'Ataların Kavisi', 'Ancestral Arc', 'Ataların tarafından desteklenen bir saldırı. 10m''lik konide 8d12 parlak hasar verir ve alandaki tüm müttefikleri 3d8 HP iyileştirir.', 'An attack fueled by your ancestors. Deals 8d12 radiant damage in a 10m cone and heals all allies in the area for 3d8 HP.', 'Cross-Branch', 70, 700, 4, '{"ls_unyielding_spirit", "ls_mountain_cleaver"}', '{"x": -1255, "y": -725}', '{"damage": "8d12 radiant", "healing": "3d8 AoE heal", "range": "10m cone"}', '🌈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5cd253a7-88f0-44a3-9a57-bfd1958903e8', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_hurricane_of_honor', 'Onur Kasırgası', 'Hurricane of Honor', 'Sabit bir kılıç fırtınası. 2 tur boyunca yer değiştirme etkilerine bağışık olursun ve 5m yarıçapına giren düşmanlar tur başına 6d10 hasar alır.', 'A stationary whirlwind of blades. For 2 turns, you are immune to displacement, and enemies entering a 5m radius take 6d10 damage per turn.', 'Cross-Branch', 75, 800, 4, '{"ls_thousand_cuts", "ls_last_stand"}', '{"x": -1472, "y": -850}', '{"buff": "Immune to displacement", "range": "5m radius", "damage": "6d10 physical/turn", "duration": "2 turns"}', '🎐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('df6b20a9-31ee-4db8-8e24-439d2b46d3b9', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_mountain_whirlwind', 'Dağ Kasırgası', 'Mountain Whirlwind', 'Efsanevi bir güçle dönerek 15m''den düşmanları içine çeken bir hortum yarat ve 10d10 kesici hasar ver.', 'Spin with legendary force, creating a tornado that pulls enemies in from 15m and deals 10d10 slashing damage.', 'Cross-Branch', 80, 900, 4, '{"ls_crescent_dance", "ls_star_fall_strike"}', '{"x": -1688, "y": -975}', '{"range": "15m pull", "damage": "10d10 slashing"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e0d090f-e256-4fb4-b208-3c2d680837f7', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_unyielding_myth', 'Boyun Eğmez Efsane', 'Unyielding Myth', 'Efsanevi bir figüre dönüş. 3 tur boyunca tüm kitle kontrolünü görmezden gelirsin ve tek hedefe yaptığın saldırılar hedefin 5m çevresindeki tüm düşmanlara isabet eder.', 'Become a mythic figure. For 3 turns, you ignore all crowd control, and your single-target attacks hit all enemies within 5m of the target.', 'Cross-Branch', 85, 1000, 5, '{"ls_immortal_honor", "ls_soul_render"}', '{"x": -1905, "y": -1100}', '{"buff": "CC Immunity", "special": "Single-target attacks splash in 5m radius", "duration": "3 turns"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9ad8e79-5f3e-4c43-ac12-16722db7b260', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_tri_style_mastery', 'Üçlü Stil Ustalığı', 'Tri-Style Mastery', 'Pasif: Çifte saldırıların %15 zırh delmeye sahiptir, savuşturmaların maks HP''nin %10''unu iyileştirir ve ağır vuruşlarının %20 sersemletme şansı vardır.', 'Passive: Your dual attacks have 15% armor penetration, your parries heal 10% max HP, and your heavy strikes have a 20% chance to stun.', 'Cross-Branch', 90, 1200, 5, '{"ls_eclipse_slashes", "ls_last_stand", "ls_star_fall_strike"}', '{"x": -2121, "y": -1225}', '{"passive": "Dual attacks ignore 15% Armor", "healing": "Parries heal 10% Max HP", "status": "Heavy strikes 20% Stun chance"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c3f7cc9-4b38-4f97-b11b-ead2bc768b38', '24b18355-7389-4396-ad86-68f268ceab48', 'ls_the_last_samurai', 'Son Samuray', 'The Last Samurai', 'Nihai gizli sanatı serbest bırak. Zaman 1 tur durur. Savaş alanında 30m içindeki tüm düşmanlara 20d20 toplam hasar veren 10 devasa vuruş yaparsın ve %20 HP altındaki düşmanları infaz eden yıkıcı bir kılıç kınına sokma hareketiyle bitirirsin.', 'Unleash the ultimate secret art. Time stops for 1 turn. You perform 10 massive strikes across the battlefield, dealing 20d20 total damage to all enemies within 30m, finishing with a devastating sheath that executes enemies below 20% HP.', 'Cross-Branch', 100, 1500, 5, '{"ls_twin_dragon_rend", "ls_bushido_incarnate", "ls_blade_of_antiquity"}', '{"x": -2338, "y": -1350}', '{"special": "Time stop (1 turn)", "damage": "20d20 physical/radiant", "range": "30m radius", "condition": "Execute enemies below 20% HP"}', '🌸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1858655b-6bfc-426b-91e9-2f6dc001e8f4', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_delayed_shot', 'Gecikmeli Atış', 'Delayed Shot', 'Hedefe saplanan bir mermi ateşler. 3 saniye sonra patlayarak 2d6 delici hasar verir.', 'Fires a projectile that lodges into the target. After 3 seconds, it detonates, dealing 2d6 piercing damage.', 'Delay', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "2d6", "delay": "3s"}', '⏱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('82108ce2-6c60-454a-979c-d92d153df394', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_patience', 'Sabır', 'Patience', '1 tur boyunca saldırmazsanız, bir sonraki saldırınız +3d6 hasar verir ve %10 zırhı yok sayar.', 'If you do not attack for 1 turn, your next attack deals +3d6 damage and ignores 10% armor.', 'Delay', 5, 75, 1, '{}', '{"x": 389, "y": -224}', '{"damage_bonus": "3d6", "armor_pen": "10%"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b06e25dd-3599-4732-8fb3-d12b276c18c1', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_time_bomb_arrow', 'Saatli Bomba Oku', 'Time Bomb Arrow', '2 tur boyunca sayan bir ok atar. Patladığında 5m yarıçapındaki alana 4d6 ateş hasarı verir.', 'Shoot an arrow that ticks for 2 turns. Upon detonation, it deals 4d6 fire damage in a 5m radius.', 'Delay', 10, 100, 1, '{}', '{"x": 606, "y": -349}', '{"damage": "4d6", "radius": "5m", "duration": "2 turns"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4fd280d2-529b-46a5-9c0e-a423e9c6972b', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_deferred_pain', 'Ertelenmiş Acı', 'Deferred Pain', '3 tur boyunca verdiğiniz hasarın %20''sini depolar. Süre sonunda, tüm hasarı gerçek hasar olarak vurulan son hedefe aktarır.', 'Store 20% of the damage you deal for 3 turns. At the end, release it all at once as true damage to the last target hit.', 'Delay', 22, 190, 2, '{"lc_patience"}', '{"x": 822, "y": -474}', '{"damage_stored": "20%", "duration": "3 turns"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5202ab6b-b433-4664-9705-ce826b2eb123', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_lingering_wound', 'Kalıcı Yara', 'Lingering Wound', '5 tur boyunca her tur 1d6 kanama hasarı veren bir yara açar. Eğer temizlenirse, şiddetli bir şekilde patlayarak 4d6 anlık hasar verir.', 'Applies a wound dealing 1d6 bleed damage every turn for 5 turns. If dispelled, it violently ruptures for 4d6 burst damage.', 'Delay', 28, 230, 2, '{"lc_delayed_shot"}', '{"x": 1039, "y": -599}', '{"damage": "1d6/turn", "burst_damage": "4d6", "duration": "5 turns"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b6a25d33-6572-4778-832f-fde6a517de06', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_tactical_pause', 'Taktiksel Duraklama', 'Tactical Pause', '2 turluğuna taktiksel bir duruşa geçin. Hareket 0m''ye düşer, ancak saldırı menzili 10m ve kritik şansı %20 artar.', 'Enter a tactical stance for 2 turns. Movement drops to 0m, but attack range increases by 10m and critical chance by 20%.', 'Delay', 35, 270, 2, '{"lc_patience"}', '{"x": 1255, "y": -724}', '{"range_bonus": "10m", "crit_chance": "+20%", "duration": "2 turns"}', '⏸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c9793905-2ab1-48ea-95d0-195fd53185e2', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_echoing_strike', 'Yankılanan Vuruş', 'Echoing Strike', 'Bir hedefe her vurduğunuzda, 2 tur sonra hayalet bir ok onlara tekrar çarparak orijinal hasarın %50''sini verir.', 'Whenever you hit a target, a phantom arrow strikes them again 2 turns later for 50% of the original damage.', 'Delay', 42, 370, 3, '{"lc_lingering_wound"}', '{"x": 1472, "y": -849}', '{"damage": "50% original", "delay": "2 turns"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90bfc714-ad62-4e9d-b4bd-10be76af2e08', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_hourglass_trap', 'Kum Saati Tuzağı', 'Hourglass Trap', 'Görünmez bir tuzak (3m yarıçap) yerleştirir. Onu tetikleyen düşmanlar %50 yavaşlar ve 1 tur gecikmeyle 6d8 güç hasarı alırlar.', 'Place an invisible trap (3m radius). Enemies triggering it are slowed by 50% and take 6d8 force damage after a 1 turn delay.', 'Delay', 48, 410, 3, '{"lc_time_bomb_arrow"}', '{"x": 1688, "y": -974}', '{"damage": "6d8", "slow": "50%", "radius": "3m"}', '⌛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('efc5e61c-7b3a-4b18-8a33-bffe1da35be2', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_stasis_shot', 'Durağanlık Atışı', 'Stasis Shot', 'Hedef 1 tur boyunca sersemler ve hasar görmez olur. Durağanlık bittiğinde anında 8d6 güç hasarı alırlar.', 'Target is stunned and invulnerable for 1 turn. When stasis ends, they instantly take 8d6 force damage.', 'Delay', 55, 460, 3, '{"lc_deferred_pain"}', '{"x": 1905, "y": -1099}', '{"damage": "8d6", "duration": "1 turn"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b647913d-6b33-407b-a619-efac7be502b3', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_inevitable_end', 'Kaçınılmaz Son', 'Inevitable End', 'Bir düşmanı işaretler. Tam 3 tur sonra 12d10 gerçek hasar alırlar. Bu hasardan kaçınılamaz veya hasar azaltılamaz.', 'Mark an enemy. In exactly 3 turns, they take 12d10 true damage. This damage cannot be evaded or mitigated.', 'Delay', 62, 620, 4, '{"lc_echoing_strike"}', '{"x": 2121, "y": -1224}', '{"damage": "12d10", "delay": "3 turns"}', '🕰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45df072c-de8e-4c8e-a860-39261034a78d', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_karma_bullet', 'Karma Mermisi', 'Karma Bullet', 'Hedefin 2 tur boyunca verdiği tüm hasarı emen ve ardından %50''sini ışık hasarı olarak geri yansıtan bir ok ateşler.', 'Fires an arrow that absorbs all damage the target deals for 2 turns, then reflects 50% of it back as radiant damage.', 'Delay', 70, 700, 4, '{"lc_stasis_shot"}', '{"x": 2338, "y": -1349}', '{"reflection": "50%", "duration": "2 turns"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1ee42209-7375-400f-b24b-6549d70506ff', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_chronal_detonation', 'Zamansal Patlama', 'Chronal Detonation', '30m içindeki hedeflerde bulunan tüm gecikmeli etkilerinizi anında patlatarak toplam hasarlarını %30 artırır.', 'Detonate all your delayed effects on targets within 30m immediately, amplifying their total damage by 30%.', 'Delay', 78, 790, 4, '{"lc_hourglass_trap"}', '{"x": 2554, "y": -1474}', '{"damage_amp": "30%", "radius": "30m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f1cca6b5-e409-424b-b87e-df49e5a957e2', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_doomsday_clock', 'Kıyamet Saati', 'Doomsday Clock', 'Ulti. Hedefe bir işaret yerleştirir. 4 tur sonra, yörüngesel bir vuruş 20d12 hasar verir ve 2 tur sersemletir. Öldürürse bekleme süresi sıfırlanır.', 'Ultimate. Place a mark on a target. After 4 turns, an orbital strike hits them for 20d12 damage and stuns for 2 turns. Resets cooldown on kill.', 'Delay', 90, 1300, 5, '{"lc_inevitable_end", "lc_chronal_detonation"}', '{"x": 2771, "y": -1599}', '{"damage": "20d12", "stun": "2 turns", "delay": "4 turns"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8d773590-4506-4ab6-9e94-dcb10e830b5a', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_hunter_mark', 'Avcı İşareti', 'Hunter''s Mark', '40m''ye kadar bir hedefi işaretler. Onları net olarak görürsünüz ve +1d6 fazladan hasar verirsiniz. 10 dakika sürer.', 'Mark a target up to 40m away. You gain true sight of them and deal +1d6 damage. Lasts 10 minutes.', 'Tracking', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage_bonus": "1d6", "range": "40m", "duration": "10 mins"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9cba7c55-d6bd-4f3e-98a3-5e1018aa45db', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_blood_scent', 'Kan Kokusu', 'Blood Scent', 'Pasif. %50 HP''nin altındaki düşmanlara doğru hareket ederken +5m hareket hızı kazanırsınız.', 'Passive. Gain +5m movement speed when moving towards enemies with less than 50% HP.', 'Tracking', 8, 90, 1, '{}', '{"x": 289, "y": 344}', '{"speed_bonus": "5m", "condition": "Enemy <50% HP"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4c6be68a-d0d0-4e17-b7fa-f6131481dd9e', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_revealing_flare', 'Açığa Çıkaran İşaret Fişeği', 'Revealing Flare', '20m yarıçapı aydınlatan bir işaret fişeği ateşleyerek gizlenmiş düşmanları açığa çıkarır ve 3 tur boyunca kaçınmalarını %10 azaltır.', 'Fire a flare illuminating a 20m radius, revealing stealthed enemies and reducing their evasion by 10% for 3 turns.', 'Tracking', 15, 130, 1, '{}', '{"x": 449, "y": 536}', '{"radius": "20m", "evasion_reduction": "10%", "duration": "3 turns"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f5ec670-6647-4f59-a1a8-2bca577b2ba2', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_relentless_pursuit', 'Amansız Takip', 'Relentless Pursuit', 'İşaretli bir hedefe doğru 10m atılın. Bir sonraki saldırınız onların zırhının %20''sini yok sayar.', 'Dash 10m towards a marked target. Your next attack ignores 20% of their armor.', 'Tracking', 24, 200, 2, '{"lc_hunter_mark"}', '{"x": 610, "y": 727}', '{"dash": "10m", "armor_pen": "20%"}', '🏃‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c800e087-82a7-4bc6-996d-dc0819eb5862', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_sniper_focus', 'Keskin Nişancı Odaklanması', 'Sniper''s Focus', 'İşaretli hedeflere karşı menzilinizi 20m artırır. Onlara yapılan saldırılar dezavantaj alamaz.', 'Increase your range against marked targets by 20m. Attacks against them cannot suffer disadvantage.', 'Tracking', 30, 240, 2, '{"lc_hunter_mark"}', '{"x": 771, "y": 919}', '{"range_bonus": "20m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1027e786-06d4-49b4-afd0-e14ef09ad07f', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_crippling_tracker', 'Sakatlayan Takipçi', 'Crippling Tracker', 'Kaçan bir düşmanı vurmak, 2 tur boyunca hareket hızlarını %50 azaltır ve +2d8 fiziksel hasar verir.', 'Hitting a fleeing enemy reduces their movement speed by 50% for 2 turns and deals +2d8 physical damage.', 'Tracking', 36, 280, 2, '{"lc_blood_scent"}', '{"x": 932, "y": 1110}', '{"slow": "50%", "damage": "2d8", "duration": "2 turns"}', '🦿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('edff2323-9faf-4ee1-9784-db6afd2f70ef', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_no_escape', 'Kaçış Yok', 'No Escape', 'Son 24 saat içinde size hasar veren düşmanları pasif olarak takip edin. İzlerini sürerken +10m hız kazanın.', 'Passively track enemies that damaged you in the last 24 hours. Gain +10m speed when following their trail.', 'Tracking', 45, 390, 3, '{"lc_relentless_pursuit"}', '{"x": 1092, "y": 1302}', '{"speed_bonus": "10m"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95d0c805-ac5f-42ad-8c07-f4c9d4feca7f', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_piercing_gaze', 'Delici Bakış', 'Piercing Gaze', 'İşaretli hedeflere karşı saldırılarınız 1m kalınlığa kadar duvarlardan geçebilir ve %80 hasar verir.', 'Your attacks against marked targets can pass through walls up to 1m thick, dealing 80% damage.', 'Tracking', 52, 450, 3, '{"lc_sniper_focus"}', '{"x": 1253, "y": 1493}', '{"wall_pen": "1m", "damage_mod": "80%"}', '🔭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de8767ba-f6f0-492f-b8d9-585e4b08f9b0', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_tether_shot', 'Bağlayan Atış', 'Tether Shot', '3 turluğuna bir bağ takar. Hedef çarpma noktasından 15m''den fazla uzaklaşırsa, geri çekilir ve 6d8 hasar alır.', 'Attach a tether for 3 turns. If the target moves more than 15m from the impact point, they are pulled back and take 6d8 damage.', 'Tracking', 58, 490, 3, '{"lc_crippling_tracker"}', '{"x": 1414, "y": 1685}', '{"damage": "6d8", "pull_radius": "15m", "duration": "3 turns"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dafe56f8-21c7-4938-b9f1-5035c513488a', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_omnipresent_hunter', 'Her Yerde Olan Avcı', 'Omnipresent Hunter', 'İşaretli hedefinize doğrudan görüş alanınız olan 30m içindeki bir konuma ışınlanın.', 'Teleport up to 30m to a location where you have a direct line of sight to your marked target.', 'Tracking', 65, 650, 4, '{"lc_no_escape"}', '{"x": 1574, "y": 1876}', '{"teleport": "30m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('412004ec-805a-4422-a6d7-c4fa2ba3a573', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_death_warrant', 'Ölüm Fermanı', 'Death Warrant', 'İşaretiniz artık hedefin aldığı iyileşmeyi %100 azaltır ve onların tam HP''sini ve zayıflıklarını grubunuza gösterir.', 'Your mark now reduces the target''s healing received by 100% and reveals their exact HP and weaknesses to your party.', 'Tracking', 72, 720, 4, '{"lc_piercing_gaze"}', '{"x": 1735, "y": 2068}', '{"anti_heal": "100%", "reveal": "Weaknesses & HP"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4731ebd8-8172-4439-b908-e322f6e923fd', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_shadow_hound', 'Gölge Tazısı', 'Shadow Hound', 'İşaretli bir hedefi kovalayan, tur başına 4d10 hasar veren ve onları haritada açığa çıkaran hayalet bir tazı çağırın.', 'Summon a spectral hound that chases a marked target, dealing 4d10 damage per turn and revealing them across the map.', 'Tracking', 78, 800, 4, '{"lc_tether_shot"}', '{"x": 1896, "y": 2259}', '{"damage": "4d10/turn", "reveal": "Global"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('96802a6e-6724-482c-a3ee-ded347037dc8', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_inescapable_hunt', 'Kaçınılmaz Av', 'Inescapable Hunt', 'Ulti. 100m içindeki tüm düşmanları işaretler. Engellerin arkasını görürsünüz. 3 tur boyunca oklar işaretli hedefleri otomatik olarak bulur ve +%50 hasar verir.', 'Ultimate. Mark all enemies within 100m. See through obstacles. For 3 turns, arrows automatically hit marked targets for +50% damage.', 'Tracking', 92, 1350, 5, '{"lc_omnipresent_hunter", "lc_shadow_hound"}', '{"x": 2056, "y": 2451}', '{"radius": "100m", "damage_bonus": "50%", "duration": "3 turns"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48ad6552-39e3-4255-9ec8-0cd7c955454d', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_coup_de_grace', 'Merhamet Vuruşu', 'Coup de Grace', '3d6 hasar verir. Hedefin HP''si %30''un altındaysa, ek olarak 2d6 hasar verir.', 'Deal 3d6 damage. If the target is below 30% HP, deal an additional 2d6 damage.', 'Execute', 3, 60, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "3d6", "bonus_damage": "2d6"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d9872db1-cc4b-45d8-8147-c5846d6e626b', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_merciless_aim', 'Acımasız Nişan', 'Merciless Aim', 'HP''si %50''nin altındaki düşmanlara karşı kritik vuruş aralığınız 1 artar (örneğin 19-20).', 'Your critical strike range increases by 1 (e.g., 19-20) against enemies below 50% HP.', 'Execute', 7, 85, 1, '{}', '{"x": -289, "y": 344}', '{"crit_range": "+1"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d1801cb-2e03-4699-b7b1-064d3c91fe66', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_bleeding_edge', 'Kanayan Kenar', 'Bleeding Edge', 'Saldırılar Kanama uygular. Bir düşman %20 HP''nin altına düştüğünde, tüm Kanama yükleri kalan hasarlarını anında verir.', 'Attacks apply Bleed. When an enemy drops below 20% HP, all Bleed stacks instantly deal their remaining damage.', 'Execute', 12, 110, 1, '{}', '{"x": -449, "y": 536}', '{"execute_trigger": "20% HP", "effect": "Pop all bleeds"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('878c023b-53b6-44fc-9b4a-19946843ec59', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_fatal_draw', 'Ölümcül Çekiş', 'Fatal Draw', '4d8 hasar verir. Bu, hedefi 0 HP''ye düşürürse, anında bir eylem puanı geri kazanırsınız.', 'Deal 4d8 damage. If this reduces the target to 0 HP, you immediately regain an action point.', 'Execute', 21, 180, 2, '{"lc_coup_de_grace"}', '{"x": -610, "y": 727}', '{"damage": "4d8", "on_kill": "+1 Action Point"}', '🃏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95600f98-1ce4-4f7b-9777-4a0c87f3324f', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_cull_the_weak', 'Zayıfları Ayıkla', 'Cull the Weak', 'Hedefin eksik olan her %10 HP''si için %10 daha fazla hasar verir.', 'Deal 10% more damage for every 10% HP the target is missing.', 'Execute', 27, 220, 2, '{"lc_merciless_aim"}', '{"x": -771, "y": 919}', '{"damage_scaling": "10% per 10% missing HP"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('73f3f0a5-1f7e-4ff6-b60d-77a3327b195d', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_heartseeker_arrow', 'Kalp Arayan Ok', 'Heartseeker Arrow', '5d6 hasar veren bir ok ateşler. Hedef 3 tur içinde %15 HP''nin altına düşerse anında ölür (patronlar 10d10 alır).', 'Fires an arrow dealing 5d6 damage. If the target falls below 15% HP within 3 turns, they instantly die (bosses take 10d10).', 'Execute', 34, 260, 2, '{"lc_bleeding_edge"}', '{"x": -932, "y": 1110}', '{"damage": "5d6", "execute_threshold": "15%", "duration": "3 turns"}', '💘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dad577bc-569c-4557-a89f-44d0a048d7a7', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_executioner_stance', 'Cellat Duruşu', 'Executioner''s Stance', '3 turluğuna bir duruşa geçin. Hedefin HP''si %40''ın altındaysa saldırılarınız kalkanları ve bariyerleri yok sayar.', 'Enter a stance for 3 turns. Your attacks ignore shields and barriers if the target is below 40% HP.', 'Execute', 41, 360, 3, '{"lc_fatal_draw"}', '{"x": -1092, "y": 1302}', '{"duration": "3 turns", "condition": "Target <40% HP"}', '🧍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('adb40895-82a6-4377-8759-4e1103dfbb24', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_death_spiral', 'Ölüm Sarmalı', 'Death Spiral', 'Her biri 2d8 hasar veren 3 hızlı atış yapın. Hedefin HP''si azalıyorsa, sonraki her atış +%25 hasar verir.', 'Fire 3 rapid shots dealing 2d8 damage each. Each subsequent shot deals +25% damage if the target''s HP is decreasing.', 'Execute', 48, 410, 3, '{"lc_cull_the_weak"}', '{"x": -1253, "y": 1493}', '{"damage": "3x 2d8", "scaling": "+25% per hit"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('58d8e170-93f7-49a3-bd7a-ca7f82242dd7', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_guillotine_shot', 'Giyotin Atışı', 'Guillotine Shot', '8d8 fiziksel hasar verir. Hedef %50 HP''nin altındaysa hasar zarları d12''ye dönüşür.', 'Deals 8d8 physical damage. The damage dice become d12s if the target is below 50% HP.', 'Execute', 56, 480, 3, '{"lc_heartseeker_arrow"}', '{"x": -1414, "y": 1685}', '{"damage": "8d8 or 8d12"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('126ce51b-5f8a-4146-b972-01eb90612231', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_reaper_toll', 'Azrail''in Bedeli', 'Reaper''s Toll', '%25 HP''lik bir eşik işaretler (minyonlar için %40). Bu eşiğin altındayken onlara vuran saldırılarınız kesin kritik vuruş olur.', 'Mark a threshold of 25% HP (40% for minions). Your attacks hitting them below this threshold are guaranteed critical hits.', 'Execute', 64, 640, 4, '{"lc_executioner_stance"}', '{"x": -1574, "y": 1876}', '{"threshold": "25% or 40%"}', '🪙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb668469-340b-4953-ae6d-8f86deb69c4f', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_final_breath', 'Son Nefes', 'Final Breath', 'HP''si %30''un altındaki bir hedefi 2 tur susturur ve 10d10 nekrotik hasar verir.', 'Silences a target below 30% HP for 2 turns and deals 10d10 necrotic damage.', 'Execute', 72, 730, 4, '{"lc_death_spiral"}', '{"x": -1735, "y": 2068}', '{"damage": "10d10", "silence": "2 turns"}', '🫁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8d3abd2-7d8b-46fe-828f-d07d9e06ff52', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_soul_piercer', 'Ruh Delici', 'Soul Piercer', 'Zırhı ve dirençleri yok sayarak, hedefin eksik canının %20''sine eşit gerçek hasar verir.', 'Bypass armor and resistances, dealing true damage equal to 20% of the target''s missing health.', 'Execute', 77, 780, 4, '{"lc_guillotine_shot"}', '{"x": -1896, "y": 2259}', '{"damage": "20% missing HP"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a1160e3-017e-41fa-971a-f3b531bf55ba', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_judgement_day', 'Kıyamet Günü', 'Judgement Day', 'Ulti. 20d10 hasar verir. %30 HP''nin altındaki hedefleri anında infaz eder. İnfaz durumunda, maksimum HP''nin %50''si kadar iyileşin.', 'Ultimate. Deals 20d10 damage. Executes targets below 30% HP instantly. On execute, heal for 50% max HP.', 'Execute', 94, 1400, 5, '{"lc_reaper_toll", "lc_soul_piercer"}', '{"x": -2056, "y": 2451}', '{"damage": "20d10", "execute_threshold": "30%", "healing": "50% max HP"}', '🪬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cb789fbe-66d6-42a7-a1d4-e3b18316e7a4', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_marked_for_death', 'Ölüm İçin İşaretli', 'Marked for Death', 'Gecikmeli işaret. 2 tur sonra hedef 4d8 hasar + eksik HP''lerinin %20''si kadar hasar alır.', 'Delayed mark. After 2 turns, target takes 4d8 damage + 20% of their missing HP.', 'Cross-Branch', 35, 280, 2, '{"lc_delayed_shot", "lc_coup_de_grace"}', '{"x": -173, "y": -100}', '{"damage": "4d8 + 20% missing HP", "delay": "2 turns"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af90b312-2b28-49a9-8b65-997211f06729', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_stalker_patience', 'İz Sürücünün Sabrı', 'Stalker''s Patience', 'Bir işareti sabit durarak takip ederken görünmezlik kazanın. Gizlilikten yapılan ilk atış +4d6 hasar verir.', 'While stationary tracking a mark, gain invisibility. First shot from stealth deals +4d6 damage.', 'Cross-Branch', 38, 290, 2, '{"lc_patience", "lc_hunter_mark"}', '{"x": -389, "y": -225}', '{"damage_bonus": "4d6", "stealth": "Yes"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c3c695ab-1850-414d-8495-a0363a08cbf6', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_bloodhound_bomb', 'Av Köpeği Bombası', 'Bloodhound Bomb', 'Güzeümlü patlayıcı ok, işareti 30m''ye kadar kovalar. 1 tur sonra patlayarak 8d6 ateş hasarı verir.', 'Homing explosive arrow chases mark up to 30m. Explodes after 1 turn for 8d6 fire damage.', 'Cross-Branch', 48, 420, 3, '{"lc_revealing_flare", "lc_time_bomb_arrow"}', '{"x": -606, "y": -350}', '{"damage": "8d6", "delay": "1 turn", "range": "30m"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d43f59a4-869a-481a-a638-d4b1e68403f2', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_vulture_instinct', 'Akbaba İçgüdüsü', 'Vulture''s Instinct', 'Takip edilen bir düşman %20 HP''nin altına düştüğünde, onlara doğru ücretsiz bir atılma ve ücretsiz bir saldırı kazanın.', 'When a tracked enemy falls below 20% HP, gain a free dash towards them and a free attack.', 'Cross-Branch', 55, 470, 3, '{"lc_relentless_pursuit", "lc_heartseeker_arrow"}', '{"x": -822, "y": -475}', '{"dash": "Free", "attack": "Free"}', '🪶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d18a9448-cff5-49a3-8fcf-83852f2676c9', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_delayed_execution', 'Gecikmeli İnfaz', 'Delayed Execution', 'Hedefin aldığı hasarı 3 tur boyunca kaydeder. Sonunda, kaydedilen hasarın %30''unu infaz olarak alırlar.', 'Record damage taken by target for 3 turns. At the end, they take 30% of recorded damage as an execute.', 'Cross-Branch', 66, 660, 4, '{"lc_deferred_pain", "lc_guillotine_shot"}', '{"x": -1039, "y": -600}', '{"damage": "30% recorded", "duration": "3 turns"}', '🎬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cfe4a4db-ed50-42f1-a6a2-063b550b62b3', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_predator_countdown', 'Yırtıcının Geri Sayımı', 'Predator''s Countdown', 'Saldırmadan bir işareti takip ettiğiniz her tur, onlara karşı infaz eşiğiniz %5 artar (maksimum %25).', 'Every turn you track a mark without attacking, your execute threshold against them increases by 5% (max 25%).', 'Cross-Branch', 74, 750, 4, '{"lc_sniper_focus", "lc_tactical_pause", "lc_cull_the_weak"}', '{"x": -1255, "y": -725}', '{"threshold_increase": "5%/turn", "max": "25%"}', '🔢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b9469a1-566a-465c-911d-05b0ae4aefdb', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_chaser_climax', 'Takipçinin Zirvesi', 'Chaser''s Climax', 'Gecikmeli bir büyüyle işarete vurmak gecikmeyi 1 tur azaltır ve patlama 20m içindeki diğer işaretli düşmanları takip eder.', 'Hitting a mark with a delayed spell reduces delay by 1 turn and explosion tracks other marked enemies within 20m.', 'Cross-Branch', 82, 1050, 5, '{"lc_chronal_detonation", "lc_death_warrant"}', '{"x": -1472, "y": -850}', '{"delay_reduction": "1 turn", "radius": "20m"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9362d33c-fbc7-4f12-a43c-54cd8f284f43', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_inevitable_cull', 'Kaçınılmaz Kıyım', 'Inevitable Cull', '%50 HP''nin altındaki bir işaretin arkasına ışınlanın. 15d10 gerçek hasar için yakın mesafeden ateş edin. Menzil: 50m.', 'Teleport behind a mark below 50% HP. Fire a point-blank shot for 15d10 true damage. Range: 50m.', 'Cross-Branch', 85, 1100, 5, '{"lc_omnipresent_hunter", "lc_soul_piercer"}', '{"x": -1688, "y": -975}', '{"damage": "15d10", "range": "50m"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('241f35ac-bb02-4cf5-9529-5d2d21ae0caf', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_patience_of_the_reaper', 'Azrail''in Sabrı', 'Patience of the Reaper', '2 tur meditasyon yapın (alınan hasar -%50). Sonraki saldırı 3 kat hasar verir ve %40 HP altı patron olmayanları infaz eder.', 'Meditate for 2 turns (-50% damage taken). Next attack deals 3x damage and executes non-bosses below 40% HP.', 'Cross-Branch', 88, 1200, 5, '{"lc_inevitable_end", "lc_reaper_toll"}', '{"x": -1905, "y": -1100}', '{"damage_mitigation": "50%", "damage_multiplier": "3x", "execute_threshold": "40%"}', '📿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf7c68e7-d6d9-4507-abb0-d0f3464b1849', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_master_of_the_hunt', 'Avın Ustası', 'Master of the Hunt', 'Gecikmeli etkiler otomatik olarak işaret uygular. İşaretli hedefler infaz yeteneklerinden iki kat hasar alır.', 'Delayed effects auto-apply mark. Marked targets take double damage from execute abilities.', 'Cross-Branch', 96, 1450, 5, '{"lc_chronal_detonation", "lc_shadow_hound", "lc_soul_piercer"}', '{"x": -2121, "y": -1225}', '{"damage_amp": "2x from executes"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d063a799-544b-4fca-9981-4f579fa04dc2', '457006e7-a9ee-41c4-baf7-e892a7008bb3', 'lc_the_late_chaser', 'Geç Kalan Takipçi', 'The Late Chaser', 'Görkemli Ulti. Tüm düşmanları 3 tur işaretler. Hareket etmek adım başına 1d10 hasar verir. %30 HP''nin altına düşmek, 30d12 gerçek hasarlı yörüngesel bir infazı tetikler.', 'Grand Ultimate. Mark all enemies for 3 turns. Moving deals 1d10 damage/step. Falling below 30% HP triggers a 30d12 true damage orbital execute.', 'Cross-Branch', 100, 1500, 5, '{"lc_doomsday_clock", "lc_inescapable_hunt", "lc_judgement_day"}', '{"x": -2338, "y": -1350}', '{"damage": "1d10/step", "execute_damage": "30d12", "duration": "3 turns"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40d2c51a-a531-45e3-b1b7-4ffb3167d9f8', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_blood_pact', 'Kan Anlaşması', 'Blood Pact', 'Mevcut canınızın %10''unu feda ederek bir müttefikinizi 2d8 artı feda edilen miktar kadar iyileştirirsiniz.', 'Sacrifice 10% of your current HP to heal an ally for 2d8 plus the sacrificed amount.', 'Life', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"healing": "2d8 + sacrificed HP", "cost": "10% HP", "range": "5m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d15e58a7-102b-4f15-ada8-5270cbdabf5f', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_life_tether', 'Yaşam Bağı', 'Life Tether', 'Yaşam gücünüzü bir müttefike bağlarsınız. 1 dakika boyunca onların aldığı hasarın %20''si size yönlendirilir.', 'Link your life force to an ally. For 1 minute, 20% of the damage they take is redirected to you.', 'Life', 5, 80, 1, '{}', '{"x": 389, "y": -224}', '{"range": "10m", "duration": "1 minute", "redirect": "20% damage"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b70e3651-3e1a-4f77-8904-7fe016f705c6', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_martyrs_strike', 'Şehit Vuruşu', 'Martyr''s Strike', 'Ekstra 1d8 parlak hasar veren ağır bir yakın dövüş saldırısı. Verilen toplam hasarın yarısı kadar iyileşirsiniz.', 'A heavy melee attack that deals an extra 1d8 radiant damage. You are healed for half the total damage dealt.', 'Life', 10, 120, 1, '{}', '{"x": 606, "y": -349}', '{"damage": "1d8 radiant", "healing": "50% of damage", "range": "Melee"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b4ad5846-369e-407d-99f9-2db03224660c', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_sanguine_shield', 'Kan Kalkanı', 'Sanguine Shield', 'Maksimum canınızın %15''ini feda ederek bir müttefike kendi maksimum canınızın %30''u kadar bir kalkan sağlarsınız.', 'Sacrifice 15% of your max HP to grant an ally a shield equal to 30% of your max HP for 1 minute.', 'Life', 22, 200, 2, '{"lg_blood_pact"}', '{"x": 822, "y": -474}', '{"shield": "30% of caster''s Max HP", "cost": "15% Max HP", "duration": "1 minute", "range": "10m"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('209bf489-4a83-4a3f-a409-658c12dc0419', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_draw_life', 'Yaşam Çekimi', 'Draw Life', 'Ön saflardaki varlığınızı korumak için 5m içindeki bir düşmandan 3d6 can çeker ve kendinizi aynı miktarda iyileştirirsiniz.', 'Drain 3d6 HP from an enemy within 5m, healing yourself for the same amount to sustain your frontline presence.', 'Life', 28, 250, 2, '{"lg_martyrs_strike"}', '{"x": 1039, "y": -599}', '{"damage": "3d6 necrotic", "healing": "100% of damage", "range": "5m"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0121a124-2749-450d-9f34-62976129f732', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_shared_burden', 'Paylaşılan Yük', 'Shared Burden', 'Bir müttefikin üzerindeki olumsuz durumu (zehir, felç, korku vb.) kendinize aktarır ve etkilerine karşı 1 turluğuna direnç kazanırsınız.', 'Transfer a negative condition (poison, paralyze, fear, etc.) from an ally to yourself, gaining resistance to its effects for 1 turn.', 'Life', 35, 280, 2, '{"lg_life_tether"}', '{"x": 1255, "y": -724}', '{"range": "15m", "condition_transfer": "1 negative effect", "duration": "Instant"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('297cc485-1fea-4368-a156-73c3cad9219c', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_crimson_aura', 'Kızıl Hale', 'Crimson Aura', '10m''lik bir hale yayarsınız. Turunuzun başında 2d4 can kaybedersiniz, ancak haledeki tüm müttefikler 3d4 can iyileşir.', 'Emit a 10m aura. You lose 2d4 HP at the start of your turn, but all allies in the aura heal for 3d4 HP.', 'Life', 42, 380, 3, '{"lg_sanguine_shield"}', '{"x": 1472, "y": -849}', '{"aura_range": "10m", "self_damage": "2d4 per turn", "ally_healing": "3d4 per turn"}', '🔴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('195abf02-49be-48d1-9553-86daff43c6ff', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_life_surge', 'Yaşam Dalgası', 'Life Surge', 'Mevcut canınızın %50''sine kadarını harcarsınız. 10m içinde bir enerji patlaması yayarak, harcanan canın iki katını seçilen müttefiklere dağıtırsınız.', 'Expend up to 50% of your current HP. Release a burst of energy within 10m, distributing double the expended HP among chosen allies.', 'Life', 48, 420, 3, '{"lg_draw_life"}', '{"x": 1688, "y": -974}', '{"healing": "200% of expended HP", "range": "10m", "cost": "Up to 50% HP"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bdb4ee7e-a3fc-4cff-b0e6-2b79675ba1ff', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_sacrificial_pact', 'Kurban Yemini', 'Sacrificial Pact', '10m içindeki bir müttefik 0 cana düştüğünde, otomatik olarak 1 cana düşer ve kaybettiğiniz can miktarı kadar onları iyileştirirsiniz.', 'When an ally within 10m drops to 0 HP, you automatically drop to 1 HP to heal them for the exact amount of HP you lost.', 'Life', 55, 480, 3, '{"lg_shared_burden"}', '{"x": 1905, "y": -1099}', '{"trigger": "Ally reaches 0 HP", "self_hp": "Drops to 1", "range": "10m"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f084091c-b694-42de-a447-3e19c5d94ff0', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_blood_barricade', 'Kanlı Barikat', 'Blood Barricade', 'Maksimum canınızın %20''sini harcayarak 5m genişliğinde kristalleşmiş kandan bir duvar yaratırsınız. Duvar 500 hasara kadar emer.', 'Create a 5m wide wall of crystallized blood by spending 20% of your max HP. The wall absorbs up to 500 damage.', 'Life', 65, 650, 4, '{"lg_crimson_aura"}', '{"x": 2121, "y": -1224}', '{"wall_hp": 500, "width": "5m", "cost": "20% Max HP"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0078b051-20f2-4c6e-a493-6d47fbe6f93a', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_undying_vow', 'Ölümsüzlük Yemini', 'Undying Vow', '3 tur boyunca 1 canın altına düşemezsiniz. Bu süre zarfında alacağınız tüm iyileştirmeler otomatik olarak 20m içindeki en düşük canlı müttefike yönlendirilir.', 'You cannot drop below 1 HP for 3 turns. Any healing you would receive during this time is automatically redirected to the lowest HP ally within 20m.', 'Life', 72, 750, 4, '{"lg_sacrificial_pact"}', '{"x": 2338, "y": -1349}', '{"duration": "3 turns", "effect": "Immortality at 1 HP", "redirect_range": "20m"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('91dc5a86-eafa-4bd6-a5b0-96d1b4f9c9bc', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_vital_transfer', 'Hayati Aktarım', 'Vital Transfer', '5m içindeki bir müttefikle can yüzdelerinizi takas edersiniz. Hemen ardından azaltılamaz 3d10 nekrotik hasar alırsınız.', 'Swap HP percentages with an ally within 5m. Immediately after, you take 3d10 necrotic damage that cannot be reduced.', 'Life', 78, 850, 4, '{"lg_life_surge"}', '{"x": 2554, "y": -1474}', '{"range": "5m", "recoil_damage": "3d10 necrotic", "effect": "Swap HP %"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c211450f-3eeb-4304-b940-48b39a0d5ff7', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_martyrs_apotheosis', 'Şehidin Yükselişi', 'Martyr''s Apotheosis', 'Nihai Yetenek. 30m içindeki tüm müttefikleri anında diriltir ve tamamen iyileştirirsiniz. Derhal bilincinizi kaybedip 0 cana düşersiniz ve 3 tur boyunca diriltilemez veya iyileştirilemezsiniz.', 'Ultimate. Instantly revive and fully heal all allies within 30m. You immediately fall unconscious, drop to 0 HP, and cannot be revived or healed for 3 turns.', 'Life', 90, 1200, 5, '{"lg_blood_barricade", "lg_undying_vow", "lg_vital_transfer"}', '{"x": 2771, "y": -1599}', '{"range": "30m", "ally_effect": "Mass Revive + 100% Heal", "self_effect": "Unconscious, unhealable for 3 turns"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb6193da-c060-4bdc-9fd4-957066c9361f', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_healing_touch', 'Şifa Dokunuşu', 'Healing Touch', 'Temel bir onarım büyüsü. Bir müttefike dokunarak onu 1d8 + Bilgelik değiştiricisi kadar iyileştirirsiniz.', 'A fundamental mending spell. Touch an ally to heal them for 1d8 + Wisdom modifier.', 'Mending', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"healing": "1d8 + WIS", "range": "Touch"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb268c71-d894-4ef4-8c45-67064fda585e', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_cleanse_wounds', 'Yara Temizliği', 'Cleanse Wounds', 'Bir müttefike dokunarak bir zehir veya kanama etkisini iyileştirir ve ona 1d4 can verirsiniz.', 'Touch an ally to cure one poison or bleed effect and heal them for 1d4.', 'Mending', 6, 80, 1, '{}', '{"x": 289, "y": 344}', '{"healing": "1d4", "cure": "1 poison or bleed", "range": "Touch"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a22cfdb-dc0c-4e08-8132-2abb22cbea03', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_mending_pulse', 'Şifa Nabzı', 'Mending Pulse', '5m''lik bir yenileyici büyü nabzı yayarsınız. Alandaki tüm müttefikler 1d6 can iyileşir.', 'Release a 5m pulse of restorative magic. All allies in the area heal for 1d6.', 'Mending', 12, 120, 1, '{}', '{"x": 449, "y": 536}', '{"healing": "1d6", "range": "5m AOE"}', '🪄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0507c83-0ec7-4e9d-82bf-27c296ce0acf', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_soothing_mist', 'Yatıştırıcı Sis', 'Soothing Mist', '3 tur boyunca 10m''lik bir sis bulutu yaratırsınız. İçerdeki müttefikler tur başına 1d4 iyileşir ve Dayanıklılık kurtarma zarlarında avantaj kazanır.', 'Create a 10m cloud of mist for 3 turns. Allies inside heal 1d4 per turn and gain advantage on Constitution saving throws.', 'Mending', 24, 200, 2, '{"lg_mending_pulse"}', '{"x": 610, "y": 727}', '{"healing": "1d4 per turn", "buff": "Advantage on CON saves", "range": "10m", "duration": "3 turns"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3be9af0-b6e1-4eb5-a68f-35bb004a8fb5', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_knit_bone', 'Kemik Kaynatma', 'Knit Bone', 'Bir hedefi 3d8 iyileştirir. Ayrıca ''Kırık Kemik'', ''Sakatlanma'' veya benzeri ağır fiziksel durumları anında ortadan kaldırır.', 'Heal a target for 3d8. Also instantly removes the ''Broken Bone'', ''Crippled'', or similar severe physical conditions.', 'Mending', 30, 250, 2, '{"lg_cleanse_wounds"}', '{"x": 771, "y": 919}', '{"healing": "3d8", "cure": "Physical injuries/cripples", "range": "Touch"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b079f66-4331-4a74-9f54-c9f51bde5db7', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_burst_of_mending', 'Şifa Patlaması', 'Burst of Mending', '15m içindeki bir müttefike hızlı ve yoğun bir büyü patlaması göndererek onları anında 4d6 iyileştirirsiniz.', 'Send a rapid burst of concentrated magic to an ally within 15m, healing them instantly for 4d6.', 'Mending', 36, 280, 2, '{"lg_healing_touch"}', '{"x": 932, "y": 1110}', '{"healing": "4d6", "range": "15m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0fbb80dc-fee4-4482-b85e-33571c918cbf', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_regenerative_plating', 'Yenileyici Zırh', 'Regenerative Plating', 'Ağır bir zırhı efsunlarsınız. Giyen kişi 1 dakika boyunca turunun başında 2d6 can yeniler.', 'Enchant a set of heavy armor. The wearer regenerates 2d6 HP at the start of their turn for 1 minute.', 'Mending', 44, 380, 3, '{"lg_knit_bone"}', '{"x": 1092, "y": 1302}', '{"healing": "2d6 per turn", "duration": "1 minute", "range": "Touch"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4635b6ed-5f3a-44e3-81ca-5593cd93a5d0', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_mass_cleanse', 'Toplu Arınma', 'Mass Cleanse', '15m içindeki tüm müttefiklerin üzerindeki olumsuz durum etkilerini, hastalıkları ve lanetleri kaldırırsınız.', 'Remove all negative status effects, diseases, and curses from all allies within 15m.', 'Mending', 50, 420, 3, '{"lg_soothing_mist"}', '{"x": 1253, "y": 1493}', '{"range": "15m", "effect": "Remove all debuffs"}', '🚿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b2da56d0-043a-43e1-96d2-7f24309b7d97', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_healing_ward', 'Şifa Totemi', 'Healing Ward', 'Yere sihirli bir totem yerleştirirsiniz. 5 tur boyunca her tur, 10m içindeki en düşük canlı müttefiki 3d8 iyileştirir.', 'Place a magical ward on the ground. Every turn for 5 turns, it heals the lowest HP ally within 10m for 3d8.', 'Mending', 56, 480, 3, '{"lg_burst_of_mending"}', '{"x": 1414, "y": 1685}', '{"healing": "3d8 per turn", "target": "Lowest HP ally", "range": "10m", "duration": "5 turns"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('449b5f30-009a-4775-bc07-1e80532b46dd', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_breath_of_life', 'Yaşam Nefesi', 'Breath of Life', 'Saf şifa enerjisinden oluşan 10m''lik bir koni üflersiniz. Müttefikleri 6d8 iyileştirir ve onlara 2d8 geçici can verir.', 'Exhale a 10m cone of pure mending energy. Heals allies for 6d8 and grants them 2d8 temporary HP.', 'Mending', 66, 650, 4, '{"lg_mass_cleanse"}', '{"x": 1574, "y": 1876}', '{"healing": "6d8", "temp_hp": "2d8", "range": "10m cone"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1c0ffdb-5cbc-4748-8aca-4c9f0eea9c16', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_reconstruct', 'Yeniden İnşa', 'Reconstruct', 'Kopmuş uzuvları yeniden takmak veya tamamen parçalanmış organları onarmak için 1 dakika boyunca odaklanırsınız. Bu süreçte hedefi 10d10 can iyileştirirsiniz.', 'Channel for 1 minute to reattach severed limbs or restore completely ruined organs, healing the target for 10d10 HP in the process.', 'Mending', 74, 750, 4, '{"lg_regenerative_plating"}', '{"x": 1735, "y": 2068}', '{"healing": "10d10", "effect": "Restore limbs/organs", "cast_time": "1 minute"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8313d93d-b477-4db8-b38c-035c24914ce8', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_panacea', 'Her Derde Deva', 'Panacea', 'Hedef bir müttefik tüm durumlara karşı bağışıklık kazanır ve 3 tur boyunca tur başına 5d8 iyileşir.', 'A target ally becomes immune to all conditions and heals 5d8 per turn for 3 turns.', 'Mending', 79, 850, 4, '{"lg_healing_ward"}', '{"x": 1896, "y": 2259}', '{"healing": "5d8 per turn", "immunity": "All conditions", "duration": "3 turns", "range": "10m"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a64d918e-e065-4f8f-a2e3-546d8252ee96', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_fountain_of_mending', 'Şifa Pınarı', 'Fountain of Mending', 'Nihai Yetenek. 1 dakika boyunca durdurulamaz bir şifa pınarına dönüşürsünüz. 20m içindeki herhangi bir müttefik turuna başladığında 5d10 can iyileşir ve tüm zayıflatmalardan arınır.', 'Ultimate. For 1 minute, you become an unstoppable fountain of mending. Any ally within 20m that starts their turn is healed for 5d10 HP and cleansed of all debuffs.', 'Mending', 92, 1200, 5, '{"lg_breath_of_life", "lg_reconstruct", "lg_panacea"}', '{"x": 2056, "y": 2451}', '{"healing": "5d10 per turn per ally", "cleanse": "All debuffs", "duration": "1 minute", "range": "20m aura"}', '⛲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('557c3bb3-4937-4912-a75d-9458d7321672', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_vitality_aura', 'Zindelik Halesi', 'Vitality Aura', '5m''lik saf bir dayanıklılık halesi yansıtırsınız. İçerdeki müttefikler Dayanıklılık kurtarma zarlarına +2 bonus kazanır.', 'Project a 5m aura of sheer endurance. Allies within gain a +2 bonus to Constitution saving throws.', 'Vitality', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"buff": "+2 CON saves", "range": "5m aura"}', '💚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5fc4ef94-9581-415e-8e39-72cb72d75f2a', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_bolster_health', 'Sağlık Takviyesi', 'Bolster Health', 'Bir müttefike dokunarak onun maksimum canını 1 saatliğine 10 artırırsınız.', 'Touch an ally to increase their maximum HP by 10 for 1 hour.', 'Vitality', 8, 80, 1, '{}', '{"x": -289, "y": 344}', '{"max_hp": "+10", "duration": "1 hour", "range": "Touch"}', '📈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd11220f-2621-4dcb-8199-2afe60ff3491', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_iron_endurance', 'Demir Dayanıklılığı', 'Iron Endurance', 'Kendinize veya bir müttefike 3 tur boyunca ezici, delici veya kesici hasara karşı direnç sağlarsınız.', 'Grant yourself or an ally resistance to bludgeoning, piercing, or slashing damage for 3 turns.', 'Vitality', 15, 120, 1, '{}', '{"x": -449, "y": 536}', '{"resistance": "Physical types", "duration": "3 turns", "range": "Touch"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94647d16-52c4-4f82-8387-d1d2c536fa1e', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_thick_skin', 'Kalın Deri', 'Thick Skin', 'Hedef bir müttefik +2 Zırh Sınıfı kazanır ve 1 dakika boyunca gelen herhangi bir fiziksel saldırının ilk 5 hasarını yok sayar.', 'A target ally gains +2 AC and ignores the first 5 damage of any incoming physical attack for 1 minute.', 'Vitality', 26, 200, 2, '{"lg_iron_endurance"}', '{"x": -610, "y": 727}', '{"ac_bonus": "+2", "damage_reduction": "5 physical", "duration": "1 minute"}', '🦏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('143d9aea-7475-4491-83a0-4271f1b604a4', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_aura_of_fortitude', 'İrade Halesi', 'Aura of Fortitude', '10m''lik hale. İçerdeki müttefiklerin maksimum canı düşman etkileriyle azaltılamaz ve hastalıklara karşı bağışıklık kazanırlar.', '10m aura. Allies inside cannot have their max HP reduced by enemy effects and are immune to diseases.', 'Vitality', 32, 250, 2, '{"lg_vitality_aura"}', '{"x": -771, "y": 919}', '{"immunity": "Max HP reduction, Disease", "range": "10m aura"}', '⚕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('478fc1a2-9a04-4731-829f-19a6786c86fe', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_invigorating_shout', 'Canlandırıcı Nida', 'Invigorating Shout', 'Muazzam bir yaşam gücüyle bağırırsınız. 15m içindeki müttefikler 1 dakika boyunca 2d10 geçici can ve +3m hareket hızı kazanır.', 'Shout with immense life force. Allies within 15m gain 2d10 temporary HP and +3m movement speed for 1 minute.', 'Vitality', 38, 280, 2, '{"lg_bolster_health"}', '{"x": -932, "y": 1110}', '{"temp_hp": "2d10", "movement": "+3m", "range": "15m", "duration": "1 minute"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('58c6f2dd-2a71-41eb-bdd8-c4e74d2f47af', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_giants_vitality', 'Dev Zindeliği', 'Giant''s Vitality', 'Bir müttefikin boyutunu bir kategori büyütürsünüz. 10 dakika boyunca +50 Maksimum Can ve Güç zarlarında Avantaj kazanırlar.', 'Increase an ally''s size by one category. They gain +50 Max HP and Advantage on Strength checks for 10 minutes.', 'Vitality', 46, 380, 3, '{"lg_bolster_health"}', '{"x": -1092, "y": 1302}', '{"size": "+1 Category", "max_hp": "+50", "buff": "Advantage on STR", "duration": "10 minutes"}', '🧗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bcf865dc-d4d0-4f7e-a336-0d0edc599d59', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_damage_dampener', 'Hasar Sönümleyici', 'Damage Dampener', '10m''lik yoğun bir zindelik büyüsü alanı yaratırsınız. Alandaki düşmanların verdiği tüm hasar %20 azalır.', 'Create a 10m zone of dense vitality magic. All damage dealt by enemies inside the zone is reduced by 20%.', 'Vitality', 52, 420, 3, '{"lg_thick_skin"}', '{"x": -1253, "y": 1493}', '{"damage_reduction": "20% from enemies", "range": "10m zone"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('32fdfae7-000b-424a-8249-ff45ef28f703', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_relentless_vitality', 'Amansız Zindelik', 'Relentless Vitality', 'Pasif güçlendirme. 0 cana düştüğünüzde, devasa zindeliğinizi yönlendirerek bunun yerine 1 cana düşebilirsiniz. Uzun dinlenme başına bir kez kullanılabilir.', 'Passive buff. When you are reduced to 0 HP, you can channel your massive vitality to drop to 1 HP instead. Usable once per long rest.', 'Vitality', 58, 480, 3, '{"lg_aura_of_fortitude"}', '{"x": -1414, "y": 1685}', '{"survive": "Drop to 1 HP instead of 0", "cooldown": "1/Long Rest", "type": "Passive"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4f59963d-e651-4b3f-8d52-c8b155e7112f', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_aegis_of_health', 'Sağlık Kalkanı', 'Aegis of Health', 'Bir müttefike maksimum canlarına %+20 ekleyen ve bozulana kadar nekrotik hasara karşı kalıcı direnç sağlayan güçlü bir etki verirsiniz.', 'Grant an ally a powerful buff that adds +20% to their max HP and gives them permanent resistance to necrotic damage until dispelled.', 'Vitality', 68, 650, 4, '{"lg_giants_vitality"}', '{"x": -1574, "y": 1876}', '{"max_hp": "+20%", "resistance": "Necrotic", "duration": "Until dispelled"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33a4c23d-f4d7-42db-829b-f23d76754ad2', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_indomitable_aura', 'Boyun Eğmez Hale', 'Indomitable Aura', 'Varlığınızı 15m''lik bir haleye genişletirsiniz. İçerdeki müttefikler tüm büyülü hasar türlerine karşı direnç kazanır.', 'Expand your presence into a 15m aura. Allies inside have resistance to all magical damage types.', 'Vitality', 76, 750, 4, '{"lg_damage_dampener"}', '{"x": -1735, "y": 2068}', '{"resistance": "All magical damage", "range": "15m aura"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('78ad1c6c-0b86-4162-8384-eabc3c449878', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_vital_anchor', 'Hayati Çıpa', 'Vital Anchor', 'Bir müttefikin ruhunu bedenine çıpalarsınız. Önümüzdeki 10 dakika içinde ölürlerse, anında %50 canla dirilirler.', 'Anchor an ally''s soul to their body. If they die within the next 10 minutes, they immediately resurrect with 50% HP.', 'Vitality', 80, 850, 4, '{"lg_relentless_vitality"}', '{"x": -1896, "y": 2259}', '{"resurrection": "50% HP on death", "duration": "10 minutes", "range": "Touch"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84516e37-968b-4160-b84e-5d23a0ab2b98', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_avatar_of_vitality', 'Zindelik Avatarı', 'Avatar of Vitality', 'Nihai Yetenek. 3 tur boyunca maksimum canınız üç katına çıkar. 30m içindeki tüm düşmanların dikkatini (aggro) üzerinize çekersiniz ve tüm kaynaklardan %75 daha az hasar alırsınız.', 'Ultimate. For 3 turns, your max HP is tripled. You draw aggro from all enemies within 30m, and take 75% reduced damage from all sources.', 'Vitality', 94, 1200, 5, '{"lg_aegis_of_health", "lg_indomitable_aura", "lg_vital_anchor"}', '{"x": -2056, "y": 2451}', '{"max_hp": "x3", "damage_reduction": "75%", "taunt_range": "30m", "duration": "3 turns"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d7b4fad-4ecf-442f-8b66-86af530599f1', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_mending_tether', 'Şifa Bağı', 'Mending Tether', '15m içindeki bir müttefike bağlanırsınız. Aldığınız tüm doğrudan iyileştirmeler onları da bu miktarın %50''si kadar iyileştirir.', 'Link to an ally within 15m. Any direct healing you receive also heals them for 50% of the amount.', 'Cross-Branch', 35, 300, 2, '{"lg_life_tether", "lg_healing_touch"}', '{"x": -173, "y": -100}', '{"healing_share": "50% to target", "range": "15m", "duration": "1 minute"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('59c355af-5ce2-40cb-a400-5bc40f00ea1f', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_blood_fortitude', 'Kan İradesi', 'Blood Fortitude', '10m içindeki tüm müttefiklere 1 dakika boyunca %20 Maksimum Can artışı sağlamak için %15 canınızı feda edersiniz.', 'Sacrifice 15% HP to grant all allies within 10m a 20% Max HP boost for 1 minute.', 'Cross-Branch', 39, 300, 2, '{"lg_blood_pact", "lg_bolster_health"}', '{"x": -389, "y": -225}', '{"max_hp": "+20%", "cost": "15% HP", "range": "10m", "duration": "1 minute"}', '💪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c827d002-c001-4fac-97e6-3c5061199003', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_vital_pulse', 'Zindelik Nabzı', 'Vital Pulse', 'Müttefikleri 3d8 iyileştiren ve fazladan yapılan tüm iyileştirmeleri maksimum 30 olacak şekilde geçici cana dönüştüren bir dalga yayarsınız.', 'Release a wave that heals allies for 3d8 and converts any overhealing into temporary HP up to a maximum of 30.', 'Cross-Branch', 54, 500, 3, '{"lg_mending_pulse", "lg_invigorating_shout"}', '{"x": -606, "y": -350}', '{"healing": "3d8", "overheal_conversion": "Temp HP (Max 30)", "range": "10m"}', '💓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8dc12e04-215e-4731-9fae-43dec56a4ca6', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_sacrificial_cleanse', 'Kurban Arınması', 'Sacrificial Cleanse', '10m içindeki hedef bir müttefikten tüm lanetleri, hastalıkları ve zehirleri anında kaldırmak için kendinize 2d8 hasar verirsiniz.', 'Take 2d8 damage yourself to instantly dispel all curses, diseases, and poisons from a target ally within 10m.', 'Cross-Branch', 57, 500, 3, '{"lg_shared_burden", "lg_cleanse_wounds"}', '{"x": -822, "y": -475}', '{"self_damage": "2d8", "cleanse": "All debuffs", "range": "10m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c1bda6ae-61f7-495b-9230-e376519490c9', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_aura_of_the_martyr', 'Şehit Halesi', 'Aura of the Martyr', '10m''lik hale. Müttefikler 50 geçici can kazanır. Bir müttefikin bu büyüden kazandığı geçici canı hasar alarak her tükendiğinde, siz 5 hasar alırsınız.', '10m aura. Allies gain 50 temporary HP. Whenever an ally''s temporary HP from this spell is depleted by damage, you take 5 damage.', 'Cross-Branch', 60, 500, 3, '{"lg_crimson_aura", "lg_aura_of_fortitude"}', '{"x": -1039, "y": -600}', '{"temp_hp": "50", "backlash_damage": "5 when depleted", "range": "10m aura"}', '🕯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98b71f01-bce4-4786-ab2c-7a688ef28813', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_healing_phalanx', 'Şifa Falanksı', 'Healing Phalanx', '15m içindeki müttefiklerin etrafında ruhani kalkanlar çağırırsınız. 3 tur boyunca her blok yaptıklarında veya fiziksel hasar aldıklarında 2d8 can iyileşirler.', 'Summon ethereal shields around allies within 15m. For 3 turns, every time they block or take physical damage, they are healed for 2d8 HP.', 'Cross-Branch', 71, 900, 4, '{"lg_healing_ward", "lg_damage_dampener"}', '{"x": -1255, "y": -725}', '{"trigger_heal": "2d8 on hit/block", "duration": "3 turns", "range": "15m"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('880433e3-2458-44cb-b685-ca532639e266', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_life_conduit', 'Yaşam İletkeni', 'Life Conduit', '4 müttefike kadar bağlantı kurarsınız. Gruptan herhangi birinin aldığı tüm hasar grup arasında eşit olarak paylaştırılır ve birine uygulanan tüm iyileştirme eşit olarak dağıtılır.', 'Connect up to 4 allies. All damage taken by any member is distributed evenly among the group, and all healing applied to one is distributed evenly.', 'Cross-Branch', 75, 900, 4, '{"lg_life_surge", "lg_mass_cleanse"}', '{"x": -1472, "y": -850}', '{"targets": "Up to 4 allies", "damage_share": "Evenly split", "healing_share": "Evenly split", "duration": "1 minute"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d83149de-90d4-4b4a-9bb4-a2e80b822244', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_blood_titan', 'Kan Titanı', 'Blood Titan', '20m içindeki tüm gönüllü müttefiklerin canının %10''unu çekersiniz. Boyutunuz büyür, çekilen miktar kadar Maksimum Can kazanırsınız ve tüm saldırılarda +2d10 hasar verirsiniz.', 'Drain 10% HP from all willing allies within 20m. You grow in size, gaining Max HP equal to the drained amount and dealing +2d10 damage on all attacks.', 'Cross-Branch', 79, 900, 4, '{"lg_blood_barricade", "lg_giants_vitality"}', '{"x": -1688, "y": -975}', '{"ally_cost": "10% HP", "self_max_hp": "+ Drained Amount", "damage_bonus": "+2d10", "duration": "1 minute"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b2182fa-8fdf-4896-88ce-1ace9481f2f1', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_bastion_of_renewal', 'Yenilenme Kalesi', 'Bastion of Renewal', '20m''lik mutlak bir sığınak alanı yaratırsınız. İçerdeki müttefikler kritik vuruşlara karşı bağışıklıdır, tur başına 4d10 iyileşir ve maksimum canları azaltılamaz. 1 dakika sürer.', 'Create a 20m zone of ultimate sanctuary. Allies inside are immune to critical hits, heal 4d10 per turn, and their max HP cannot be reduced. Lasts 1 minute.', 'Cross-Branch', 85, 1300, 5, '{"lg_panacea", "lg_indomitable_aura"}', '{"x": -1905, "y": -1100}', '{"healing": "4d10 per turn", "immunity": "Critical hits, Max HP reduction", "duration": "1 minute", "range": "20m zone"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16962215-f4d2-4d4f-81e2-5f9664cde394', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_vampiric_aegis', 'Vampir Kalkanı', 'Vampiric Aegis', 'Bir müttefike 100 geçici canı olan kanlı bir kalkan verirsiniz. Kalkan dayandığı sürece, verdikleri hasarın %50''si onlara iyileştirme olarak geri döner.', 'Grant an ally a bloody shield with 100 temporary HP. While the shield holds, 50% of the damage they deal is returned to them as healing.', 'Cross-Branch', 88, 1300, 5, '{"lg_vital_transfer", "lg_vital_anchor"}', '{"x": -2121, "y": -1225}', '{"temp_hp": 100, "lifesteal": "50% of damage dealt", "duration": "Until Temp HP breaks", "range": "15m"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c1a11193-73c2-49af-bf67-9e9e6c320f29', '49803aae-f03d-4737-83dd-d77a696bcfd2', 'lg_domain_of_the_life_guardian', 'Yaşam Muhafızının Alanı', 'Domain of the Life Guardian', 'Büyük Nihai Yetenek. Halenizi 50m''ye genişletirsiniz. 5 tur boyunca tüm müttefikler ölümsüzdür (1 canın altına düşemez). Süre sonunda tüm müttefikler tamamen iyileşir, ancak siz bitkin düşersiniz ve 24 saat boyunca büyü yapamazsınız.', 'Grand Ultimate. Expand your aura to 50m. For 5 turns, all allies are immortal (cannot drop below 1 HP). At the end of the duration, all allies are fully healed, but you become exhausted and cannot cast spells for 24 hours.', 'Cross-Branch', 100, 1500, 5, '{"lg_martyrs_apotheosis", "lg_fountain_of_mending", "lg_avatar_of_vitality"}', '{"x": -2338, "y": -1350}', '{"range": "50m aura", "duration": "5 turns", "ally_effect": "Immortal (1 HP min) then 100% Heal", "self_penalty": "Exhausted, 24h silence"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('606ea611-1454-468c-bd01-c2bec6615f38', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_drain', 'Mana Sömürüsü', 'Mana Drain', 'Menzilli bir hedeften büyü gücü çeker ve kendi mananızı yeniler.', 'Drains magic from a target at range, restoring your own mana.', 'Absorption', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d6", "range": "10m", "mana_steal": "1d6"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('20e2e17f-c7c9-44b3-8c5f-65116d8b6715', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_arcane_sponge', 'Arkana Süngeri', 'Arcane Sponge', 'Size isabet eden bir sonraki büyünün hasarını pasif olarak %25 azaltır ve mana olarak emer.', 'Passively reduces the damage of the next spell that hits you by 25%, absorbing it as mana.', 'Absorption', 5, 100, 1, '{"mm_mana_drain"}', '{"x": 389, "y": -224}', '{"damage_reduction": "25%", "mana_restore": "10%"}', '🧽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5125f43c-f326-4429-935e-e6f2b9701255', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_siphon_essence', 'Öz Çekimi', 'Siphon Essence', 'Sürekli bir sömürü ışını yönlendirerek hedeften sağlık ve mana çeker.', 'Channels a draining beam, continuously pulling health and mana from the target.', 'Absorption', 10, 150, 1, '{"mm_mana_drain"}', '{"x": 606, "y": -349}', '{"damage": "1d4 per turn", "range": "15m", "duration": "3 turns"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1541ee7a-b031-4d1c-a837-5a9e17ce4cfc', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_absorbing_barrier', 'Emici Bariyer', 'Absorbing Barrier', 'Sihirli bir kalkan oluşturur. Kalkana verilen herhangi bir büyü hasarının %50''si sizi iyileştirir.', 'Creates a magical shield. Any magic damage dealt to the shield heals you for 50% of the damage absorbed.', 'Absorption', 15, 150, 1, '{"mm_arcane_sponge"}', '{"x": 822, "y": -474}', '{"shield_hp": "20", "heal_conversion": "50%"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3071dcc-1d8a-44c8-b339-4fe781e2da33', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_leeching_grasp', 'Sülük Dokunuşu', 'Leeching Grasp', 'Hedefin manasını koparıp hasar veren yakın dövüş büyü saldırısı.', 'A melee magic attack that tears mana out of the target and deals damage.', 'Absorption', 22, 200, 2, '{"mm_siphon_essence"}', '{"x": 1039, "y": -599}', '{"damage": "2d6", "range": "Melee", "mana_steal": "2d6"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a13ea998-8aac-48be-8873-8b6c0c80d868', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_spell_eater', 'Büyü Yiyen', 'Spell Eater', 'Büyü hasarı almaya tepki olarak etkinleşir, etkinin %50''sini emerek bir sonraki saldırınızı güçlendirir.', 'As a reaction to taking magic damage, absorb 50% of the impact to empower your next attack.', 'Absorption', 28, 250, 2, '{"mm_absorbing_barrier"}', '{"x": 1255, "y": -724}', '{"damage_reduction": "50%", "next_attack_bonus": "+1d6"}', '🍽️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('03bc6edd-8e5f-4e4d-a307-92b60bcfe397', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_vacuum', 'Mana Vakumu', 'Mana Vacuum', 'Bölgedeki tüm düşmanlardan mana çeken yerel bir vakum oluşturur.', 'Creates a localized vacuum that pulls mana from all enemies in an area.', 'Absorption', 32, 250, 2, '{"mm_leeching_grasp", "mm_spell_eater"}', '{"x": 1472, "y": -849}', '{"mana_drain": "2d4", "radius": "5m", "range": "10m"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b5a2da4-5718-49da-9ea9-e80bf0807c78', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_energy_conversion', 'Enerji Dönüşümü', 'Energy Conversion', 'Mananızı sağlığa veya sağlığınızı serbestçe manaya dönüştürün.', 'Freely convert your mana into health, or health into mana.', 'Absorption', 38, 300, 2, '{"mm_mana_vacuum"}', '{"x": 1688, "y": -974}', '{"conversion_ratio": "1:1", "max_conversion": "20 points"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93cf0b00-4a8f-4709-b7c8-254b86e1f301', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_hunger_void', 'Hiçliğin Açlığı', 'Hunger of the Void', 'Büyülerin iki kat mana bedeline sahip olduğu bir bölge çağırır ve fazla manayı siz toplarsınız.', 'Summons a zone where spells cost double mana to cast, and you harvest the excess.', 'Absorption', 42, 400, 3, '{"mm_energy_conversion"}', '{"x": 1905, "y": -1099}', '{"radius": "10m", "mana_cost_multiplier": "2x", "duration": "3 turns"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c4efc7d-d9ad-450b-9f5f-bce5026f1f49', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_devour_magic', 'Büyü Yutma', 'Devour Magic', 'Sihirli bir güçlendirmeyi veya zayıflatmayı anında dağıtarak size sağlık kazandırır.', 'Instantly dispels a magical buff or debuff, restoring health to you.', 'Absorption', 48, 450, 3, '{"mm_mana_vacuum"}', '{"x": 2121, "y": -1224}', '{"heal": "3d8", "range": "15m"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3d099a5-b0df-472e-996c-bbd8833cd29b', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_magical_parasite', 'Büyülü Parazit', 'Magical Parasite', 'Hedefe bulaşır. Büyü yaptıklarında hasar alırlar ve mana bedelinin bir kısmını siz çalarsınız.', 'Infects a target. Whenever they cast a spell, they take damage and you steal a portion of the mana cost.', 'Absorption', 55, 500, 3, '{"mm_hunger_void"}', '{"x": 2338, "y": -1349}', '{"damage": "2d8", "mana_steal": "20%", "duration": "1 minute"}', '🦠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cd89be7e-7be1-4e8e-8b48-7a62346015ec', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_nullification_field', 'İptal Alanı', 'Nullification Field', 'Sizin ve müttefikleriniz için gelen tüm büyü hasarını azaltan bir auro yansıtır.', 'Projects an aura that reduces all incoming magic damage for you and your allies.', 'Absorption', 62, 650, 4, '{"mm_devour_magic"}', '{"x": 2554, "y": -1474}', '{"magic_damage_reduction": "30%", "radius": "15m", "duration": "1 minute"}', '🚧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2a963093-2c68-47a4-ae67-ac4fa7e3d34c', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_black_hole_core', 'Kara Delik Çekirdeği', 'Black Hole Core', 'Yakınında yapılan sonraki 3 hedefli büyüyü emen yüzen karanlık bir küre çağırır.', 'Summons a floating dark orb that absorbs the next 3 targeted spells cast near it.', 'Absorption', 70, 750, 4, '{"mm_magical_parasite"}', '{"x": 2771, "y": -1599}', '{"spell_absorption_charges": "3", "radius": "10m"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a49c700b-e6b0-4e06-b352-78f6416e932d', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_arcane_gluttony', 'Arkana Oburluğu', 'Arcane Gluttony', 'Kısa bir süre için her tur size isabet eden ilk büyünün %100''ünü emersiniz.', 'For a short duration, you absorb 100% of the first spell that hits you each turn.', 'Absorption', 75, 850, 4, '{"mm_nullification_field"}', '{"x": 2987, "y": -1724}', '{"duration": "3 turns", "absorption_rate": "100%"}', '👄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2d468e98-5845-425e-8ec0-7674f2686aa7', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_absolute_absorption', 'Mutlak Emilim', 'Absolute Absorption', 'Sonsuz bir hiçliğe dönüşürsünüz. Yakındaki tüm düşman büyülerini emerek her yutulan büyü için muazzam güç kazanırsınız.', 'You become an endless void. Absorbs all hostile magic nearby, gaining immense power for each spell consumed.', 'Absorption', 90, 1200, 5, '{"mm_black_hole_core", "mm_arcane_gluttony"}', '{"x": 3204, "y": -1849}', '{"radius": "20m", "duration": "5 turns", "damage_bonus_per_spell": "+5"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16204fc4-cfc8-48fd-8e8f-3ade75e7d89c', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_minor_deflection', 'Küçük Saptırma', 'Minor Deflection', 'Büyülü bir mermiyi anında saptırarak ona karşı geçici bir zırh sınıfı artışı sağlar.', 'Reactively deflects a magic projectile, gaining a temporary armor class boost against it.', 'Counterspell', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"ac_bonus": "+2", "trigger": "Reaction"}', '🖐️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7e6c920f-96ff-4321-853a-7376ebac817b', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_arcane_disruption', 'Arkana Bozulması', 'Arcane Disruption', 'Hedefin odağını bozar ve bir sonraki büyülerinin mana bedelini %50 artırır.', 'Scrambles the target''s focus, increasing the mana cost of their next spell by 50%.', 'Counterspell', 6, 100, 1, '{"mm_minor_deflection"}', '{"x": 289, "y": 344}', '{"mana_cost_increase": "50%", "duration": "1 turn"}', '🧩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f8a19dbf-be23-4f57-a6dc-d962b310189b', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_silence', 'Susturma', 'Silence', 'Hiçbir sesin olmadığı, sözlü bileşenlere sahip büyülerin yapılmasını engelleyen küresel bir bölge oluşturur.', 'Creates a spherical zone where no sound exists, preventing the casting of spells with verbal components.', 'Counterspell', 12, 150, 1, '{"mm_arcane_disruption"}', '{"x": 449, "y": 536}', '{"radius": "5m", "duration": "1 minute"}', '🔇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c54626a-f1be-4bfc-a130-10ad65a25866', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_rebuke', 'Azarlama', 'Rebuke', 'Düşman büyülerini ani bir psişik veya büyülü geri bildirim sarsıntısıyla cezalandırır.', 'Punishes enemy spellcasting with a sudden jolt of psychic or magical feedback.', 'Counterspell', 18, 150, 1, '{"mm_arcane_disruption"}', '{"x": 610, "y": 727}', '{"damage": "2d6", "range": "15m", "trigger": "Reaction"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f540e010-d848-4d1e-8687-d8b89fea23d1', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_counterspell', 'Karşı Büyü', 'Counterspell', 'Büyü yapma sürecindeki bir yaratığı anında kesintiye uğratarak büyünün başarısız olmasına neden olur.', 'Instantly interrupts a creature in the process of casting a spell, causing it to fail.', 'Counterspell', 21, 200, 2, '{"mm_silence"}', '{"x": 771, "y": 919}', '{"range": "18m", "trigger": "Reaction"}', '❌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3c17c728-4f5e-4ed7-bbda-1fff8b9d36c6', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_spell_turning', 'Büyü Çevirme', 'Spell Turning', 'Tek hedefli bir büyüyü doğrudan yapana geri yansıtır.', 'Reflects a single-target spell directly back at the caster.', 'Counterspell', 26, 250, 2, '{"mm_rebuke", "mm_counterspell"}', '{"x": 932, "y": 1110}', '{"trigger": "Reaction", "reflection": "100%"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('47bd7ba7-b9ae-495b-9229-a6da912986f7', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_magical_feedback', 'Büyülü Geri Bildirim', 'Magical Feedback', 'Düşmanlara yakın zamanda ne kadar mana harcadıklarına bağlı olarak hasar veren bir dalga yayar.', 'Releases a wave that damages enemies based on how much mana they have spent recently.', 'Counterspell', 34, 250, 2, '{"mm_counterspell"}', '{"x": 1092, "y": 1302}', '{"damage": "1d4 per mana spent", "radius": "10m"}', '📻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f1a72d4-3e75-48e7-85a0-dbc95816923b', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_dispelling_strike', 'Dağıtan Vuruş', 'Dispelling Strike', 'Yakın dövüş saldırınıza anti-büyü aşılar ve hedeften bir olumlu sihirli etkiyi kaldırır.', 'Imbues your melee attack with anti-magic, removing one positive magical effect from the target.', 'Counterspell', 39, 300, 2, '{"mm_spell_turning"}', '{"x": 1253, "y": 1493}', '{"damage": "Weapon+1d8", "buff_removal": "1 effect"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('06220982-ace9-436b-989f-f6ed7257e696', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_arcane_reflection', 'Arkana Yansıması', 'Arcane Reflection', 'Size yöneltilen bir sonraki büyüyü otomatik olarak yansıtan kalıcı, ayna benzeri bir kalkan çağırır.', 'Summons a persistent mirror-like shield that automatically reflects the next spell directed at you.', 'Counterspell', 44, 400, 3, '{"mm_spell_turning"}', '{"x": 1414, "y": 1685}', '{"duration": "1 minute", "charges": "1"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b811d66-6bb6-4615-b3b4-61fc6bd29831', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mute', 'Dilsiz Bırakma', 'Mute', 'Hedefin büyü yapma yeteneğini kısa bir süre için tamamen mühürler.', 'Completely seals the target''s ability to cast spells for a short duration.', 'Counterspell', 50, 450, 3, '{"mm_silence", "mm_magical_feedback"}', '{"x": 1574, "y": 1876}', '{"duration": "2 turns", "range": "10m"}', '🤐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60fbcbe6-cd4a-4984-a596-0a7baceacc29', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_spell_shatter', 'Büyü Parçalama', 'Spell Shatter', 'Büyülü yapıları, bariyerleri ve çağrılmış duvarları yok ederek patlamalarına ve alan hasarı vermelerine neden olur.', 'Destroys magical constructs, barriers, and summoned walls, causing them to explode and deal area damage.', 'Counterspell', 58, 500, 3, '{"mm_dispelling_strike"}', '{"x": 1735, "y": 2068}', '{"damage": "4d6 force", "radius": "5m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('861d47b3-063e-478b-8e2a-8901fe9cafef', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_aura_denial', 'Reddetme Aurası', 'Aura of Denial', 'Düşmanları odaklanmakta zorlanmaya zorlayan bir auro yansıtır. Başarısız odaklanma büyüyü tamamen boşa harcar.', 'Projects an aura that forces enemies to struggle to focus. Failed concentration completely wastes their spell.', 'Counterspell', 64, 650, 4, '{"mm_arcane_reflection"}', '{"x": 1896, "y": 2259}', '{"radius": "10m", "spell_failure_chance": "30%"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34782b5d-da3e-4ea2-8c71-1dbbc369ce9f', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_reflective_carapace', 'Yansıtıcı Kabuk', 'Reflective Carapace', 'Sizi ve yakındaki müttefikleri, düşük seviyeli büyüleri geri seken yansıtıcı bir kubbeye hapseder.', 'Encases you and nearby allies in a reflective dome that bounces low-tier spells away.', 'Counterspell', 72, 750, 4, '{"mm_mute"}', '{"x": 2056, "y": 2451}', '{"radius": "5m", "duration": "1 minute", "reflects": "Tier 1 & 2"}', '🐢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c9019f8-5dde-4372-848a-b83edc3a6ebb', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_magic_seal', 'Büyü Mührü', 'Magic Seal', 'Hedefin belirli bir büyü dalını geçici olarak kilitleyerek en güçlü büyülerini işe yaramaz hale getirir.', 'Temporarily locks a specific branch of magic for the target, rendering its most powerful spells useless.', 'Counterspell', 78, 850, 4, '{"mm_spell_shatter"}', '{"x": 2217, "y": 2642}', '{"duration": "3 turns", "target": "Highest Tier Branch"}', '🔒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('03b690e0-11cb-4ee6-818d-eb5b70e1ae9a', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_anti_magic_dominion', 'Anti-Büyü Hakimiyeti', 'Anti-Magic Dominion', 'Hiçbir düşmanın büyü yapamayacağı ve tüm aktif düşman etkilerinin büyük ölçüde bastırıldığı devasa bir bölge oluşturur.', 'Creates a massive zone where no enemy can cast magic, and all active hostile effects are heavily suppressed.', 'Counterspell', 92, 1200, 5, '{"mm_aura_denial", "mm_reflective_carapace", "mm_magic_seal"}', '{"x": 2378, "y": 2834}', '{"radius": "30m", "duration": "1 minute", "suppression": "100%"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('82781cf3-eab2-474f-bd0f-2bfdc94773c5', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_dart', 'Mana Oku', 'Mana Dart', 'Hedefe yoğunlaştırılmış saf mana oku fırlatır.', 'Fires a concentrated bolt of raw mana at the target.', 'Mana Manipulation', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d4+1 force", "range": "20m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea94197a-868c-4fb3-9156-01a4f021bd9b', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_arcane_flux', 'Arkana Akısı', 'Arcane Flux', 'Yapılmakta olan herhangi bir büyünün temel hasar türünü değiştirmenizi sağlar.', 'Allows you to change the elemental damage type of any spell as it is being cast.', 'Mana Manipulation', 4, 100, 1, '{"mm_mana_dart"}', '{"x": -289, "y": 344}', '{"damage_type_change": "Any Element", "duration": "1 spell"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e0c990b-1402-4b5e-b299-632ee91ec7d4', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_transfer_mana', 'Mana Aktarımı', 'Transfer Mana', 'Kendi mananızı bir müttefike aktararak büyülü rezervlerini yeniler.', 'Transfers your own mana into an ally, restoring their magical reserves.', 'Mana Manipulation', 8, 150, 1, '{"mm_mana_dart"}', '{"x": -449, "y": 536}', '{"mana_transfer": "Up to 10 points", "range": "10m"}', '👐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af53ab55-e92d-4cdb-854e-2827649e75c8', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_shield', 'Mana Kalkanı', 'Mana Shield', 'Gelen hasarı sağlığınız yerine doğrudan mana havuzunuza yönlendirir.', 'Diverts incoming damage directly to your mana pool instead of your health.', 'Mana Manipulation', 16, 150, 1, '{"mm_transfer_mana"}', '{"x": -610, "y": 727}', '{"damage_to_mana": "2 damage per 1 mana", "duration": "10 minutes"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2574ba08-278e-4661-978b-2e4b9fbc1d8c', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_burn', 'Mana Yakma', 'Mana Burn', 'Hedefin mana havuzunu tutuşturarak yok edilen mana kadar hasar verir.', 'Ignites the target''s mana pool, dealing damage equal to the mana destroyed.', 'Mana Manipulation', 24, 200, 2, '{"mm_arcane_flux"}', '{"x": -771, "y": 919}', '{"damage": "2d6", "mana_destroyed": "2d6", "range": "15m"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1de2ba14-8bd8-4714-92db-6d79e3a359ae', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_leyline_tap', 'Ley Hattı Çekimi', 'Leyline Tap', 'Dünyadaki gizli büyülü akımlara dokunarak mananızı zamanla hızla yeniler.', 'Taps into hidden magical currents in the earth, regenerating your mana rapidly over time.', 'Mana Manipulation', 30, 250, 2, '{"mm_transfer_mana"}', '{"x": -932, "y": 1110}', '{"mana_regen": "5 per turn", "duration": "3 turns"}', '🛤️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('859d9ba3-f615-4536-8ad0-08b28b544d2e', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_overcharge', 'Aşırı Yükleme', 'Overcharge', 'Bir sonraki büyünüzü devasa hasar verecek şekilde güçlendirir, ancak dengesiz enerjiden kendinize zarar verirsiniz.', 'Empowers your next spell to deal massive damage, at the cost of damaging yourself from the unstable energy.', 'Mana Manipulation', 35, 250, 2, '{"mm_mana_shield", "mm_mana_burn"}', '{"x": -1092, "y": 1302}', '{"damage_bonus": "50%", "self_damage": "20% of total"}', '📈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5c9596d-2170-41d4-87f6-ee911306f17e', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_arcane_infusion', 'Arkana İnfüzyonu', 'Arcane Infusion', 'Bir müttefikin silahına saf büyü aşılayarak vuruşlarına güç hasarı ekler.', 'Infuses an ally''s weapon with raw magic, adding force damage to their strikes.', 'Mana Manipulation', 40, 300, 2, '{"mm_leyline_tap"}', '{"x": -1253, "y": 1493}', '{"bonus_damage": "1d6 force", "duration": "1 minute"}', '🪄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33fd466d-19d7-48e6-b042-ffd0335a866c', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_storm', 'Mana Fırtınası', 'Mana Storm', 'Düşmanlara hasar veren ve odaklarını bozan kaotik bir büyü fırtınası çağırır.', 'Summons a chaotic tempest of magic that damages enemies and breaks their concentration.', 'Mana Manipulation', 45, 400, 3, '{"mm_overcharge"}', '{"x": -1414, "y": 1685}', '{"damage": "3d6 force", "radius": "10m", "concentration_break_DC": "15"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('75476250-6c60-4569-b64e-8ee4c6f9e52e', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_empowering_flow', 'Güçlendirici Akış', 'Empowering Flow', 'Yakınınızdaki tüm müttefiklerin yaşam gücünü pekiştirerek maksimum manalarını pasif olarak artırır.', 'Passively increases the maximum mana of all allies near you by reinforcing their life force.', 'Mana Manipulation', 52, 450, 3, '{"mm_arcane_infusion"}', '{"x": -1574, "y": 1876}', '{"max_mana_bonus": "10%", "radius": "15m"}', '🔋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2e26e8b5-747a-45b8-b9e1-2cc334f2266a', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_energy_severance', 'Enerji Koparması', 'Energy Severance', 'Hedefin büyü ile olan bağlantısını geçici olarak kopararak mana yenilenmesini ve sihirli iyileşmeyi engeller.', 'Temporarily severs the target''s connection to magic, preventing mana regeneration and magical healing.', 'Mana Manipulation', 60, 500, 3, '{"mm_mana_storm"}', '{"x": -1735, "y": 2068}', '{"duration": "3 turns", "heal_block": "100%", "regen_block": "100%"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16ea1484-d3af-4617-9388-27ac1d479ee0', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_arcane_eruption', 'Arkana Patlaması', 'Arcane Eruption', 'Saf manadan oluşan şiddetli bir gayzerin patlamasına neden olarak düşmanları havaya savurur.', 'Causes a violent geyser of pure mana to erupt, knocking enemies into the air.', 'Mana Manipulation', 66, 650, 4, '{"mm_empowering_flow"}', '{"x": -1896, "y": 2259}', '{"damage": "6d6 force", "radius": "15m", "status": "Prone"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('17735b43-7855-4af6-aa2f-df2c395bbc0c', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_weaver_trance', 'Mana Dokumacısının Transı', 'Mana Weaver''s Trance', 'Büyülerinizin mana gerektirmediği ve birbirine kusursuzca aktığı derin bir odaklanmaya girin.', 'Enter a deep focus where your spells cost no mana and flow flawlessly into one another.', 'Mana Manipulation', 74, 750, 4, '{"mm_energy_severance"}', '{"x": -2056, "y": 2451}', '{"mana_cost": "0", "extra_spell_cast": "1 per turn", "duration": "3 turns"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('187999c7-b315-4ae0-9838-ea4f147f19ea', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_pure_energy_blast', 'Saf Enerji Patlaması', 'Pure Energy Blast', 'Düşmanları ve engelleri delip geçen yoğunlaştırılmış enerjiden yıkıcı bir ışın fırlatır.', 'Fires a devastating beam of concentrated energy that pierces through enemies and obstacles.', 'Mana Manipulation', 80, 850, 4, '{"mm_arcane_eruption"}', '{"x": -2217, "y": 2642}', '{"damage": "8d8 force", "area": "30m line", "width": "2m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fec4db60-140e-4055-aa01-aa4ed45fdd4c', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_omnipresent_mana', 'Her Yerde Bulunan Mana', 'Omnipresent Mana', 'Saf büyülü enerji varlığına dönüşün. Fiziksel saldırılara karşı bağışıklık, sınırsız mana ve anında ışınlanma yeteneği kazanın.', 'Transform into an entity of pure magical energy. Gain immunity to physical attacks, limitless mana, and the ability to instantly teleport.', 'Mana Manipulation', 94, 1200, 5, '{"mm_mana_weaver_trance", "mm_pure_energy_blast"}', '{"x": -2378, "y": 2834}', '{"duration": "5 turns", "immunity": "Physical", "teleport": "20m bonus action"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('206d2b2e-49d2-4def-a993-8ba2886069d4', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_reactive_shield', 'Tepkisel Kalkan', 'Reactive Shield', 'Çift amaçlı bir bariyer. Bir büyü tarafından parçalanırsa, büyünün geri kalan etkisini otomatik olarak engeller ve size mana iade eder.', 'A dual-purpose barrier. If shattered by a spell, it automatically counters the rest of the spell''s effect and refunds mana to you.', 'Cross-Branch', 25, 250, 2, '{"mm_absorbing_barrier", "mm_counterspell"}', '{"x": -173, "y": -100}', '{"shield_hp": "20", "counter_effect": "Automatic on break"}', '♻️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('acc2ddd6-130f-4f57-9a01-a5d2bf5d5b3c', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_feedback_loop', 'Geri Bildirim Döngüsü', 'Feedback Loop', 'Bir hedefi lanetler; böylece büyü yaptıklarında iki kat mana bedeli kaybederler ve kaybedilen mana kadar hasar alırlar.', 'Curses a target so that whenever they cast a spell, they lose double the mana cost and take damage equal to the mana lost.', 'Cross-Branch', 46, 450, 3, '{"mm_magical_feedback", "mm_mana_burn"}', '{"x": -389, "y": -225}', '{"mana_loss": "2x cost", "damage": "Equal to mana lost", "duration": "3 turns"}', '🔁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9ab6393c-8849-4aaa-9c3a-816918de6a6a', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_siphoning_storm', 'Sömüren Fırtına', 'Siphoning Storm', 'Düşmanları sürekli olarak tüketen, hem sağlığınızı hem de mananızı besleyen dönen bir büyü fırtınası oluşturur.', 'Creates a swirling storm of magic that continuously drains enemies, feeding both your health and mana.', 'Cross-Branch', 68, 700, 4, '{"mm_devour_magic", "mm_mana_storm"}', '{"x": -606, "y": -350}', '{"damage": "5d6 per turn", "radius": "15m", "absorb_ratio": "50%"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1c61fc6-4955-4488-ba57-f4e3f5ac07b1', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_mana_paradox', 'Mana Paradoksu', 'Mana Paradox', 'Bir alandaki büyü kurallarını değiştirir. Düşmanlar her tur maksimum mana kaybederken, müttefikler zahmetsizce büyü yapabilir.', 'Alters the rules of magic in an area. Enemies lose maximum mana each turn, while allies can cast spells effortlessly.', 'Cross-Branch', 80, 850, 4, '{"mm_black_hole_core", "mm_aura_denial", "mm_mana_weaver_trance"}', '{"x": -822, "y": -475}', '{"radius": "20m", "enemy_mana_loss": "10% max per turn", "ally_mana_cost": "0"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee303ef2-8411-41dc-94d9-50635be7c9c5', '639e3303-56a5-4eee-a513-c8c5e9426d24', 'mm_source_singularity', 'Kaynak Tekilliği', 'The Source Singularity', 'Büyünün mutlak merkezi olun. Yakında yapılan tüm büyüleri otomatik olarak emersiniz ve bunları hiçbir mana bedeli olmadan anında yansıtabilir veya yeniden yapabilirsiniz.', 'Become the absolute center of magic. You automatically absorb all spells cast nearby and can instantly reflect or re-cast them without any mana cost.', 'Grand Ultimate', 100, 1500, 5, '{"mm_absolute_absorption", "mm_anti_magic_dominion", "mm_omnipresent_mana"}', '{"x": 173, "y": -99}', '{"radius": "100m", "duration": "1 minute", "auto_absorb": "100%", "free_cast": "Legendary Action"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93db1f21-cd67-4c18-be08-5384b686d351', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_barter', 'Takas', 'Barter', 'Maksimum HP''nizin %10''unu 50 MP karşılığında takas edin.', 'Trade 10% of your maximum HP for a burst of 50 MP.', 'Trade', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"cost": "10% HP", "gain": "50 MP"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('58304415-ebed-4d23-98b6-0a58bf9a8d78', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_appraisal', 'Değer Biçme', 'Appraisal', 'Hedefi analiz ederek zayıf noktalarını ortaya çıkarın ve 30 saniye boyunca Zırh Sınıfını (AC) 2 azaltın. Menzil 15m.', 'Analyze the target, revealing weak points and reducing their Armor Class by 2 for 30s. Range 15m.', 'Trade', 5, 75, 1, '{"mc_trade_barter"}', '{"x": 389, "y": -224}', '{"armor_reduction": "2", "duration": "30s", "range": "15m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8d3d7d86-cea3-4f19-a476-cd4d5510acea', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_delivery', 'Ekspres Teslimat', 'Express Delivery', 'Envanterinizden rastgele ağır bir eşyayı yüksek hızda fırlatarak 2d6 ezici hasar verin. Menzil 15m.', 'Throw a random heavy item from your inventory at high speed, dealing 2d6 bludgeoning damage. Range 15m.', 'Trade', 10, 100, 1, '{"mc_trade_appraisal"}', '{"x": 606, "y": -349}', '{"damage": "2d6 bludgeoning", "range": "15m"}', '📦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c86926d7-71e7-4161-8277-6dc624140d87', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_coin_toss', 'Madeni Para Atışı', 'Coin Toss', 'Kinetik büyüyle aşılanmış altın bir madeni parayı fırlatarak 1d8 delici hasar verin. Menzil 20m.', 'Flick a gold coin infused with kinetic magic, dealing 1d8 piercing damage. Range 20m.', 'Wealth', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8 piercing", "range": "20m"}', '🪙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('14113728-9527-482b-8e29-dd5117610260', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_golden_shield', 'Altın Kalkan', 'Golden Shield', '20 altın harcayarak 10 saniye boyunca 30 hasara kadar emen parıldayan bir kalkan oluşturun.', 'Consume 20 gold to create a shimmering shield that absorbs up to 30 damage for 10s.', 'Wealth', 5, 75, 1, '{"mc_wealth_coin_toss"}', '{"x": 289, "y": 344}', '{"shield": "30 HP", "duration": "10s", "cost": "20 gold"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('25037ae2-0d5e-4409-8d2c-bf55e58a647a', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_pocket_change', 'Bozukluk', 'Pocket Change', '5m''lik bir koni alanına bir avuç bozuk para saçarak isabet alan tüm düşmanlara 1d6 hasar verin.', 'Scatter a handful of coins in a 5m cone, dealing 1d6 damage to all enemies hit.', 'Wealth', 10, 100, 1, '{"mc_wealth_golden_shield"}', '{"x": 449, "y": 536}', '{"damage": "1d6", "radius": "5m cone"}', '💰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09232a14-dead-45ae-804d-d743eeef6012', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_handshake', 'Sıkı El Sıkışma', 'Firm Handshake', 'Hedefin elini sihirli bir bağla tutun. 1d6 ezici hasar verir ve 3 saniye boyunca sizden 2m''den fazla uzaklaşmalarını engeller.', 'Grab the target''s hand in a magical binding grip. Deals 1d6 bludgeoning damage and prevents them from moving further than 2m from you for 3s.', 'Deal', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d6 bludgeoning", "duration": "3s", "range": "melee"}', '🫱🏼‍🫲🏾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('50365932-2ecd-4c19-993a-7de1fab4e81d', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_fine_print', 'İnce Yazı', 'The Fine Print', 'Bir düşmana okuması zor küçük bir lanet yerleştirin. 10 saniye boyunca, her büyü yaptıklarında 1d4 psişik hasar alırlar. Menzil 15m.', 'Place a tiny, hard-to-read curse on an enemy. For 10s, they take 1d4 psychic damage every time they cast a spell. Range 15m.', 'Deal', 5, 75, 1, '{"mc_deal_handshake"}', '{"x": -289, "y": 344}', '{"damage": "1d4 psychic per cast", "duration": "10s", "range": "15m"}', '📄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f31019da-a6bc-4b74-9236-fe85735a2dba', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_loan', 'Kredi', 'Loan', 'Bir müttefike anında 20 geçici HP verin, ancak 15 saniye sonra etki bittiğinde 5 engellenemez hasar alırlar. Menzil 10m.', 'Grant an ally 20 temporary HP instantly, but they take 5 irreducible damage when the effect ends after 15s. Range 10m.', 'Deal', 10, 100, 1, '{"mc_deal_fine_print"}', '{"x": -449, "y": 536}', '{"temp_hp": "20", "damage_after": "5", "duration": "15s", "range": "10m"}', '📝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0437deb-2ca0-4d3e-aad1-26c20734a1d6', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_fair_exchange', 'Adil Değişim', 'Fair Exchange', '10m içindeki bir düşmandan kendinize olumlu bir statü etkisini alın ve kendi olumsuz etkinizi onlara aktarın.', 'Swap one negative status effect from yourself with one positive status effect from an enemy within 10m.', 'Trade', 21, 200, 2, '{"mc_trade_delivery"}', '{"x": 822, "y": -474}', '{"range": "10m", "target": "1 enemy"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6902763a-452e-48c9-9973-533a2412bc36', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_smuggle', 'Kaçakçılık', 'Smuggle', 'Bir müttefiki 15m''ye kadar gizlice boş bir alana ışınlayın.', 'Secretly teleport an ally up to 15m to an unoccupied space.', 'Trade', 25, 225, 2, '{"mc_trade_fair_exchange"}', '{"x": 1039, "y": -599}', '{"range": "15m", "target": "1 ally"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('23ffecf1-6deb-429e-bb13-2ad454c5a69c', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_discount', 'İndirim', 'Discount', 'Kendinize veya bir müttefike sihirli bir kupon uygulayarak bir sonraki büyünün MP bedelini %50 azaltın.', 'Apply a magical coupon to yourself or an ally, reducing the MP cost of the next spell cast by 50%.', 'Trade', 30, 250, 2, '{"mc_trade_smuggle"}', '{"x": 1255, "y": -724}', '{"cost_reduction": "50%", "target": "self or ally"}', '🏷️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b8eb269d-b486-4d25-99ec-8f66f7f23986', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_pay_to_win', 'Kazanmak İçin Öde', 'Pay to Win', '50 altın harcayarak bir sonraki saldırınızın veya büyünüzün otomatik olarak kritik vuruş olmasını sağlayın.', 'Spend 50 gold to automatically make your next attack or spell a critical hit.', 'Wealth', 21, 200, 2, '{"mc_wealth_pocket_change"}', '{"x": 610, "y": 727}', '{"cost": "50 gold", "buff": "guaranteed critical hit"}', '💳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7b4ab025-ce40-41e2-a032-0962499226b4', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_money_bag', 'Ağır Para Kesesi', 'Heavy Money Bag', 'İnanılmaz derecede ağır bir para kesesini savurarak 3d8 ezici hasar verin ve hedefi 3m geri savurun. Yakın dövüş menzili.', 'Swing an incredibly heavy bag of coins, dealing 3d8 bludgeoning damage and knocking the target back 3m. Melee range.', 'Wealth', 25, 225, 2, '{"mc_wealth_pay_to_win"}', '{"x": 771, "y": 919}', '{"damage": "3d8 bludgeoning", "knockback": "3m", "range": "melee"}', '🎒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8a2ba68-d757-4134-ad9c-0ad1a1e53c2b', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_bribe_guard', 'Muhafıza Rüşvet', 'Bribe the Guard', '10m içindeki insansı bir düşmana bir kese altın atarak bir sonraki turlarını pas geçmelerini sağlayın.', 'Toss a pouch of gold to an enemy humanoid within 10m, forcing them to skip their next action.', 'Wealth', 30, 250, 2, '{"mc_wealth_money_bag"}', '{"x": 932, "y": 1110}', '{"range": "10m", "effect": "skip turn"}', '🤫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8c97c19-1807-41b4-a191-dbfe24117099', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_contract', 'Kan Sözleşmesi', 'Blood Contract', 'Yaşam gücünüzü 15 saniyeliğine bir düşmana bağlayın. Aldığınız tüm hasarın %30''u onlara da yansıtılır. Menzil 15m.', 'Bind your life force to an enemy for 15s. 30% of all damage you take is also dealt to them. Range 15m.', 'Deal', 21, 200, 2, '{"mc_deal_loan"}', '{"x": -610, "y": 727}', '{"duration": "15s", "damage_share": "30%", "range": "15m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cb9e9898-0034-4e17-9cd8-96c5c76101fb', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_debt_collection', 'Borç Tahsilatı', 'Debt Collection', 'Size borçlu olunanı şiddetle tahsil edin. 3d6 nekrotik hasar ve hedefteki her zayıflatma için ek 1d6 hasar verir. Yakın dövüş.', 'Violently extract what you are owed. Deals 3d6 necrotic damage, plus an additional 1d6 for every debuff on the target. Melee range.', 'Deal', 25, 225, 2, '{"mc_deal_contract"}', '{"x": -771, "y": 919}', '{"damage": "3d6 necrotic + 1d6 per debuff", "range": "melee"}', '💼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('06282882-f411-4833-94e6-0a0dfc1302d0', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_interest_rate', 'Faiz Oranı', 'Interest Rate', 'Bir düşmanı lanetleyerek hareket hızlarını 10 saniye boyunca her saniye %5 azaltın. Menzil 15m.', 'Curse an enemy so their movement speed decreases by 5% every second for 10s. Range 15m.', 'Deal', 30, 250, 2, '{"mc_deal_debt_collection"}', '{"x": -932, "y": 1110}', '{"speed_reduction": "5% per sec", "duration": "10s", "range": "15m"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f53ba8df-b6a1-4772-bb7a-76a83d7425fe', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_insurance_fraud', 'Sigorta Dolandırıcılığı', 'Insurance Fraud', 'Hasar aldıktan sonra, 100 altın harcayarak hasarın %200''ünü saldıran kişiye güç hasarı olarak geri yansıtın.', 'After taking damage, immediately reflect 200% of that damage back to the attacker as force damage, consuming 100 gold.', 'Cross-Branch', 35, 275, 2, '{"mc_trade_fair_exchange", "mc_deal_contract"}', '{"x": -173, "y": -100}', '{"damage_reflection": "200%", "cost": "100 gold", "damage_type": "force"}', '🤕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de654dfc-0847-408f-ab35-210e563686fb', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_mercenary_payoff', 'Paralı Asker Ödemesi', 'Mercenary Payoff', '200 altın harcayarak 30 saniye boyunca sizinle birlikte savaşacak iki usta paralı asker çağırın.', 'Spend 200 gold to instantly summon two veteran mercenaries to fight alongside you for 30s.', 'Cross-Branch', 35, 275, 2, '{"mc_trade_smuggle", "mc_wealth_pay_to_win"}', '{"x": -389, "y": -225}', '{"summons": "2 mercenaries", "duration": "30s", "cost": "200 gold"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('767c9a03-5ce5-4fb3-be7e-c6bb997194e9', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_bulk_buy', 'Toplu Alım', 'Bulk Buy', 'Tek seferde birden fazla güçlendirme satın alın. 150 altın harcayarak kendinize ve 10m içindeki tüm müttefiklere 1 dakika boyunca +2 AC ve +10m hareket hızı sağlayın.', 'Purchase multiple enhancements at once. Spend 150 gold to grant yourself and all allies within 10m +2 AC and +10m movement speed for 1 minute.', 'Trade', 41, 400, 3, '{"mc_trade_discount"}', '{"x": 1472, "y": -849}', '{"cost": "150 gold", "ac_bonus": "2", "speed_bonus": "10m", "duration": "60s", "radius": "10m"}', '🛒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0117e8d-5b7c-41bb-b9c5-135c74d1d739', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_outsourcing', 'Taşeronluk', 'Outsourcing', 'Bildiğiniz bir büyüyü yapması için sihirli bir vekil çağırın. Hiçbir MP harcamaz ancak 100 altın tüketir.', 'Summon a magical proxy to cast a spell you know, costing no MP but consuming 100 gold.', 'Trade', 45, 425, 3, '{"mc_trade_bulk_buy"}', '{"x": 1688, "y": -974}', '{"cost": "100 gold", "mp_cost": "0", "summon": "spell proxy"}', '👷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a2faef5-1717-4a39-803f-031b12cd1fc4', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_monopoly', 'Tekel', 'Monopoly', 'Yaşam gücü üzerinde tekel kurun. 15 saniye boyunca, 20m içindeki düşmanlara uygulanan tüm iyileştirmeler size yönlendirilir.', 'Claim exclusive rights to vitality. For 15s, any healing applied to enemies within 20m is redirected to you.', 'Trade', 50, 450, 3, '{"mc_trade_outsourcing"}', '{"x": 1905, "y": -1099}', '{"duration": "15s", "radius": "20m", "effect": "steal healing"}', '🎩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aeb2ef90-33cf-456f-9318-9b99377a074e', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_coin_shower', 'Madeni Para Yağmuru', 'Coin Shower', '10m''lik bir alanda şiddetli bir ağır madeni para yağmuru başlatarak içerideki tüm düşmanlara 4d6 ezici hasar verin. Menzil 20m.', 'Cause a torrential downpour of heavy coins in a 10m radius, dealing 4d6 bludgeoning damage to all enemies inside. Range 20m.', 'Wealth', 41, 400, 3, '{"mc_wealth_bribe_guard"}', '{"x": 1092, "y": 1302}', '{"damage": "4d6 bludgeoning", "radius": "10m", "range": "20m"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48b15663-b61d-4096-8a94-9dfd30acfc8f', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_gilded_armor', 'Yaldızlı Zırh', 'Gilded Armor', 'Kendinizi som altınla kaplayarak +5 AC kazanın ve 30 saniye boyunca yakın dövüş saldırganlarına 2d6 delici hasar yansıtın. Hareket hızınız yarıya iner.', 'Coat yourself in solid gold, gaining +5 AC and reflecting 2d6 piercing damage to melee attackers for 30s. Movement speed is halved.', 'Wealth', 45, 425, 3, '{"mc_wealth_coin_shower"}', '{"x": 1253, "y": 1493}', '{"ac_bonus": "5", "damage_reflection": "2d6 piercing", "duration": "30s", "speed_reduction": "50%"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('76d37061-b84f-46fa-a465-3a66323506b6', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_bounty', 'Ödül Koyma', 'Place Bounty', '30 saniyeliğine bir düşmanı ölüm için işaretleyin. Bu düşmana hasar veren herhangi bir müttefik, verdiği hasarın %20''si kadar iyileşir. Menzil 20m.', 'Mark an enemy for death for 30s. Any ally who damages this enemy heals for 20% of the damage dealt. Range 20m.', 'Wealth', 50, 450, 3, '{"mc_wealth_gilded_armor"}', '{"x": 1414, "y": 1685}', '{"duration": "30s", "heal_ratio": "20% of damage", "range": "20m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8c84ccc-d5bc-4134-8896-58780d846135', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_nda', 'Gizlilik Anlaşması', 'Non-Disclosure Agreement', 'Bir düşmanın dudaklarını sihirle mühürleyerek onları susturun ve 5 saniye boyunca sözlü büyü yapmalarını engelleyin. Menzil 15m.', 'Magically seal an enemy''s lips, silencing them and preventing verbal spellcasting for 5s. Range 15m.', 'Deal', 41, 400, 3, '{"mc_deal_interest_rate"}', '{"x": -1092, "y": 1302}', '{"duration": "5s", "effect": "silence", "range": "15m"}', '🤐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c2db62d7-0e73-432c-aef8-0a07c0ea0eec', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_loophole', 'Yasal Boşluk', 'Loophole', 'Gerçekliğin kurallarında bir kusur bulun. Sonraki 10 saniye boyunca, gelen herhangi bir saldırıdan veya büyüden tamamen kaçınma şansınız %50 olur.', 'Find a flaw in reality''s rules. For the next 10s, you have a 50% chance to completely evade any incoming attack or spell.', 'Deal', 45, 425, 3, '{"mc_deal_nda"}', '{"x": -1253, "y": 1493}', '{"evasion_chance": "50%", "duration": "10s"}', '🔍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('615c79f2-9f8e-40a0-93cf-5c69c0d80785', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_breach_of_contract', 'Sözleşme İhlali', 'Breach of Contract', 'Kendinize bir tuzak kurun. 30 saniye içinde size saldıran ilk düşman 4d8 yıldırım hasarı alır ve 2 saniye boyunca sersemler.', 'Set a trap on yourself. The next enemy to attack you within 30s takes 4d8 lightning damage and is stunned for 2s.', 'Deal', 50, 450, 3, '{"mc_deal_loophole"}', '{"x": -1414, "y": 1685}', '{"damage": "4d8 lightning", "stun_duration": "2s", "trap_duration": "30s"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1231957-8038-47e7-8a60-dd7e2b7afed9', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_golden_handshake', 'Altın El Sıkışma', 'Golden Handshake', 'Bir düşmanın elini zorla sıkarak 200 altın harcayın ve 5d6 güç hasarı verip sonraki tur eylemlerini çalın. Yakın dövüş.', 'Forcefully shake an enemy''s hand, spending 200 gold to deal 5d6 force damage and steal their next action phase. Melee range.', 'Cross-Branch', 55, 475, 3, '{"mc_wealth_bounty", "mc_deal_loophole"}', '{"x": -606, "y": -350}', '{"damage": "5d6 force", "cost": "200 gold", "effect": "steal action", "range": "melee"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b52c5285-6335-45af-8b5f-8d9c911307d3', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_insider_trading', 'İçeriden Öğrenenlerin Ticareti', 'Insider Trading', 'Hedefin niyetini okuyarak 15 saniye boyunca onların saldırılarına karşı +10 AC ve büyülerine karşı kurtarma zarlarına avantaj kazanın. Menzil 15m.', 'Read the target''s intentions, gaining +10 AC against their attacks and advantage on saving throws against their spells for 15s. Range 15m.', 'Cross-Branch', 55, 475, 3, '{"mc_trade_monopoly", "mc_deal_nda"}', '{"x": -822, "y": -475}', '{"ac_bonus": "10", "saving_throw": "advantage", "duration": "15s", "range": "15m"}', '📈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d718b83-6b79-4e8a-b8d9-1aa2a11de413', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_asset_freeze', 'Mal Varlığı Dondurma', 'Asset Freeze', 'Bir düşmanın envanterini ve manasını sihirle kilitleyin. 6 saniye boyunca eşya kullanamaz veya büyü yapamazlar. Menzil 20m.', 'Magically lock an enemy''s inventory and mana. They cannot use items or cast spells for 6s. Range 20m.', 'Cross-Branch', 55, 475, 3, '{"mc_wealth_gilded_armor", "mc_trade_bulk_buy"}', '{"x": -1039, "y": -600}', '{"duration": "6s", "effect": "item and spell lock", "range": "20m"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5857d6f3-47fe-4a66-a2c5-df41761704fa', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_hostile_takeover', 'Düşmanca Devralma', 'Hostile Takeover', 'Bir düşman yaratığını veya zihin kontrollü varlığı hedef alın ve sadakatlerini satın alın. Ölünceye kadar kalıcı müttefikiniz olurlar. Menzil 20m.', 'Target an enemy summon or mind-controlled entity and buy out their loyalty. They become your permanent ally until they die. Range 20m.', 'Trade', 61, 700, 4, '{"mc_trade_monopoly"}', '{"x": 2121, "y": -1224}', '{"range": "20m", "effect": "mind control summon"}', '🏢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d636954-0cf7-4888-b95a-b3bc9d6c6b34', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_black_market', 'Kara Borsa', 'Black Market', 'Yasadışı güçlere erişin. Bir müttefike 20 saniye boyunca +%50 hasar verin, ancak süre boyunca maksimum HP''leri %25 azalır.', 'Tap into illicit powers. Grant an ally +50% damage for 20s, but their maximum HP is reduced by 25% for the duration.', 'Trade', 65, 750, 4, '{"mc_trade_hostile_takeover"}', '{"x": 2338, "y": -1349}', '{"damage_bonus": "50%", "max_hp_reduction": "25%", "duration": "20s"}', '🕶️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ee407f7-a4df-44bf-9a17-d7d9dec51bae', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_free_shipping', 'Ücretsiz Kargo', 'Free Shipping', '50m içindeki herhangi bir müttefike anında ışınlanarak onları 4d8+20 HP iyileştiren devasa bir şifa kasası bırakın.', 'Instantly teleport to any ally within 50m, dropping a massive healing crate that heals them for 4d8+20 HP.', 'Trade', 70, 800, 4, '{"mc_trade_black_market"}', '{"x": 2554, "y": -1474}', '{"healing": "4d8+20", "range": "50m", "effect": "teleport"}', '📦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('765632f8-e026-4519-863e-378ec8347bda', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_rain_of_wealth', 'Servet Yağmuru', 'Rain of Wealth', '15m yarıçapında felaket getiren bir külçe altın fırtınası çağırarak 8d6 ezici hasar verin ve düşmanları 3 saniyeliğine yere sabitleyin. Menzil 30m.', 'Summon a catastrophic storm of gold bars in a 15m radius, dealing 8d6 bludgeoning damage and rooting enemies for 3s. Range 30m.', 'Wealth', 61, 700, 4, '{"mc_wealth_bounty"}', '{"x": 1574, "y": 1876}', '{"damage": "8d6 bludgeoning", "radius": "15m", "root_duration": "3s", "range": "30m"}', '☔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3376282f-06a3-42ca-80de-ec9028ec91a9', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_liquidation', 'Nakde Çevirme', 'Liquidation', 'Bir düşmanın zırhını parçalayarak 6d10 güç hasarı verin ve AC''sini savaşın geri kalanı boyunca kalıcı olarak 5 azaltın. Menzil 10m.', 'Shatter an enemy''s armor, dealing 6d10 force damage and permanently reducing their AC by 5 for the rest of the encounter. Range 10m.', 'Wealth', 65, 750, 4, '{"mc_wealth_rain_of_wealth"}', '{"x": 1735, "y": 2068}', '{"damage": "6d10 force", "ac_reduction": "5", "range": "10m"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a4a77ee-eab4-4051-8aca-14a55260855c', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_midas_touch', 'Midas Dokunuşu', 'Midas Touch', 'Bir düşmana dokunarak onları 5 saniyeliğine som altına dönüştürün. Sersemlerler ve hasara karşı bağışıklık kazanırlar, ancak etki bittiğinde 500 altın düşürürler. Yakın dövüş.', 'Touch an enemy, transforming them into solid gold for 5s. They are stunned and immune to damage, but drop 500 gold when the effect ends. Melee.', 'Wealth', 70, 800, 4, '{"mc_wealth_liquidation"}', '{"x": 1896, "y": 2259}', '{"duration": "5s", "effect": "stun and invulnerability", "gold_drop": "500", "range": "melee"}', '🥇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1feefcee-9724-432f-ae40-cc768a7f170b', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_repo', 'Geri Alma', 'Repossession', 'Bir düşmanın kuşandığı silahına 5 saniyeliğine sihirle el koyarak fiziksel hasarlarını %100 azaltın ve silah yeteneklerini engelleyin. Menzil 15m.', 'Magically confiscate an enemy''s equipped weapon for 5s, reducing their physical damage by 100% and preventing weapon skills. Range 15m.', 'Deal', 61, 700, 4, '{"mc_deal_breach_of_contract"}', '{"x": -1574, "y": 1876}', '{"duration": "5s", "damage_reduction": "100%", "range": "15m"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a1447cd-cd03-4581-8de8-63b246ad65cf', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_compound_interest', 'Bileşik Faiz', 'Compound Interest', 'Tıklayan bir lanet uygulayın. Hedef 2d6 nekrotik hasar alır. Sonraki 4 tur boyunca her tur hasar ikiye katlanır (4d6, 8d6, 16d6). Menzil 20m.', 'Apply a ticking curse. The target takes 2d6 necrotic damage. Every turn for 4 turns, the damage doubles (4d6, 8d6, 16d6). Range 20m.', 'Deal', 65, 750, 4, '{"mc_deal_repo"}', '{"x": -1735, "y": 2068}', '{"base_damage": "2d6 necrotic", "turns": "4", "scaling": "doubles per turn", "range": "20m"}', '📈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0212c8a3-ed29-4b39-bf2e-d2307cb923ef', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_sell_soul', 'Ruh Satışı', 'Sell Soul', 'Düşmüş bir müttefiki tam HP ile diriltin, ancak önümüzdeki bir saat boyunca hem sizin hem de diriltilen müttefikin maksimum HP''si yarıya iner.', 'Resurrect a fallen ally with full HP, but both you and the resurrected ally have your maximum HP halved for the next hour.', 'Deal', 70, 800, 4, '{"mc_deal_compound_interest"}', '{"x": -1896, "y": 2259}', '{"healing": "100%", "max_hp_reduction": "50%", "duration": "1 hour"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('82507a13-8df1-4759-bd93-222faac7d07f', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_extortion', 'Haraç Kesme', 'Extortion', 'Bir düşmandan ödeme talep edin. Anında toplam altınlarının %10''unu size vermeliler, aksi takdirde 10d6 psişik hasar alırlar. Menzil 15m.', 'Demand payment from an enemy. They must instantly give you 10% of their total gold or suffer 10d6 psychic damage. Range 15m.', 'Cross-Branch', 75, 850, 4, '{"mc_wealth_liquidation", "mc_deal_compound_interest"}', '{"x": -1255, "y": -725}', '{"gold_steal": "10%", "damage": "10d6 psychic", "range": "15m"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d0348f7-0a31-4605-b73e-b15d87527b5a', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_corporate_espionage', 'Kurumsal Casusluk', 'Corporate Espionage', '30m içindeki bir düşmanın yaptığı son büyüyü çalın. Onu bir dakika içinde MP bedeli ödemeden bir kez yapabilirsiniz.', 'Steal the last spell cast by an enemy within 30m. You can cast it once within the next minute without paying its MP cost.', 'Cross-Branch', 75, 850, 4, '{"mc_trade_hostile_takeover", "mc_deal_repo"}', '{"x": -1472, "y": -850}', '{"range": "30m", "effect": "copy spell", "duration": "60s"}', '🕵️‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2b4f4c41-ef29-47ca-950b-c78418a711b0', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_blood_money', 'Kan Parası', 'Blood Money', 'Kendi yaşam gücünüzü ölümcül bir mermiye dönüştürün. 50 HP''ye kadar feda edin; feda edilen HP''nin iki katı güç hasarı verin. Menzil 20m.', 'Convert your own vitality into a lethal projectile. Sacrifice up to 50 HP; deal force damage equal to twice the sacrificed HP. Range 20m.', 'Cross-Branch', 75, 850, 4, '{"mc_wealth_midas_touch", "mc_deal_sell_soul"}', '{"x": -1688, "y": -975}', '{"cost": "up to 50 HP", "damage": "2x HP cost", "damage_type": "force", "range": "20m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f76dd9b9-05be-49d6-bdc9-df3044fe8cf7', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_economic_collapse', 'Ekonomik Çöküş', 'Economic Collapse', 'Sihirli ekonomiyi çökertin. 20m''lik bir alandaki düşmanlardan tüm olumlu güçlendirmeleri kaldırarak, kaldırılan her güçlendirme için 4d8 güç hasarı verin.', 'Crash the magical economy. Strip all positive buffs from enemies in a 20m radius, dealing 4d8 force damage for each buff removed.', 'Cross-Branch', 78, 875, 4, '{"mc_trade_black_market", "mc_wealth_rain_of_wealth"}', '{"x": -1905, "y": -1100}', '{"radius": "20m", "damage_per_buff": "4d8 force"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a9d75db0-01f3-49e7-b1d4-3bc242ae3812', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_trade_ultimate_merchant_prince', 'Tüccar Prensin Fermanı', 'Merchant Prince''s Decree', 'Mutlak bir emir verin. 30 saniye boyunca tüm müttefikler +%50 hasar ve +%50 hareket hızı kazanır. Bir müttefike saldırmaya çalışan herhangi bir düşman, saldırı başına 5d10 psişik hasar alır.', 'Issue an absolute command. For 30s, all allies gain +50% damage and +50% movement speed. Any enemy that attempts to attack an ally takes 5d10 psychic damage per attack.', 'Trade', 90, 1200, 5, '{"mc_trade_free_shipping"}', '{"x": 2771, "y": -1599}', '{"damage_bonus": "50%", "speed_bonus": "50%", "punish_damage": "5d10 psychic per attack", "duration": "30s"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea3e468c-f27f-498e-8146-f7772e18b37f', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_wealth_ultimate_avalanche_of_gold', 'Altın Çığı', 'Avalanche of Gold', 'Düşmanlarınızı devasa servetinizin ağırlığı altında ezin. 20m''lik bir alana gerçek bir madeni para dağı düşürerek 20d10 ezici hasar verin ve düşmanları 5 saniye boyunca diri diri gömerek sersemletin. Menzil 40m.', 'Crush your foes under the weight of immense wealth. Drops a literal mountain of coins in a 20m radius, dealing 20d10 bludgeoning damage and burying enemies (stunned) for 5s. Range 40m.', 'Wealth', 90, 1200, 5, '{"mc_wealth_midas_touch"}', '{"x": 2056, "y": 2451}', '{"damage": "20d10 bludgeoning", "radius": "20m", "stun_duration": "5s", "range": "40m"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e18b96a6-ce50-4450-998e-57a4422e092b', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_deal_ultimate_devils_bargain', 'Şeytanın Pazarlığı', 'Devil''s Bargain', 'Karşı konulmaz bir anlaşma sunun. 30m içindeki tüm düşmanlar bir kurtarma zarı atmalıdır, aksi takdirde büyülenerek kendi müttefiklerine saldırır ve 15 saniye boyunca sizin için savaşırlar.', 'Offer an irresistible deal. All enemies within a 30m radius must make a saving throw or be charmed, turning on their allies and fighting for you for 15s.', 'Deal', 90, 1200, 5, '{"mc_deal_sell_soul"}', '{"x": -2056, "y": 2451}', '{"radius": "30m", "effect": "charm", "duration": "15s"}', '👿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f296c77a-c38d-4e5a-bf89-08469c2bc509', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_cross_hostile_merger', 'Düşmanca Birleşme', 'Hostile Merger', 'Kendinizi hedeflenen bir düşman veya müttefikle 20 saniyeliğine birleştirin. Birleştirilmiş varlığı kontrol edersiniz, onların mevcut HP''sini geçici HP olarak kazanır ve tüm büyülerine erişim sağlarsınız.', 'Fuse yourself with a targeted enemy or ally for 20s. You control the combined entity, gaining their current HP as temporary HP and access to all their spells.', 'Cross-Branch', 95, 1300, 5, '{"mc_trade_ultimate_merchant_prince", "mc_deal_ultimate_devils_bargain"}', '{"x": -2121, "y": -1225}', '{"duration": "20s", "effect": "fusion"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b75ae07-7113-47a6-a402-004664b77c98', 'ddd97410-17c6-4279-ba2c-c8a7f3f93923', 'mc_grand_ultimate_capitalism', 'Gem Vurulmamış Kapitalizm', 'Unfettered Capitalism', 'Her şeyi nakde çevirin. Toplam altınınız %10''unu tüketin. 100m içindeki tüm düşmanlara tüketilen altının 10''a bölümü kadar mutlak hasar verin. Tüm düşmüş müttefikleri tam HP ile diriltin ve onlara 10 saniye boyunca yenilmezlik kalkanları verin.', 'Liquidate everything. Consume 10% of your total gold. Deal absolute damage equal to the gold consumed divided by 10 to all enemies within 100m. Revive all fallen allies with full HP and grant them invincible shields for 10s.', 'Cross-Branch', 100, 1500, 5, '{"mc_trade_ultimate_merchant_prince", "mc_wealth_ultimate_avalanche_of_gold", "mc_deal_ultimate_devils_bargain"}', '{"x": -2338, "y": -1350}', '{"cost": "10% total gold", "damage": "gold/10 absolute", "radius": "100m", "shield_duration": "10s", "healing": "100%"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('824e4d4e-ed72-45ab-8c18-72e5d3198f05', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_psychic_push', 'Zihinsel İtiş', 'Psychic Push', 'Zihinsel bir güçle hedefi 5m uzağa iter ve 1d6 psişik hasar verirsiniz.', 'Push a target 5m away using mental force, dealing 1d6 psychic damage.', 'Psychic', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d6", "damage_type": "psychic", "knockback": "5m"}', '🫸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4148fd5d-5c1b-45ea-a6a9-e68543dfd754', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mind_shield', 'Zihin Kalkanı', 'Mind Shield', 'Zihninizi görünmez bir bariyerle sararak 10 dakika boyunca zihinsel saldırılara karşı +2 Zırh Sınıfı kazanırsınız.', 'Surround your mind with an invisible barrier, gaining +2 AC against mental attacks for 10 minutes.', 'Psychic', 5, 80, 1, '{"mh_psychic_push"}', '{"x": 389, "y": -224}', '{"bonus_ac": 2, "duration": "10 minutes"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a6215418-c3c9-4eaa-b489-605828028d7f', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_telekinetic_pebble', 'Telekinetik Taş', 'Telekinetic Pebble', 'Zihninizle küçük bir nesneyi 15m''ye kadar fırlatarak 2d4 ezici hasar verirsiniz.', 'Hurl a small object with your mind up to 15m, dealing 2d4 bludgeoning damage.', 'Psychic', 10, 100, 1, '{"mh_mind_shield"}', '{"x": 606, "y": -349}', '{"damage": "2d4", "damage_type": "bludgeoning", "range": "15m"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cad50e7a-d7bf-4dd7-b944-5b021d8b65bf', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_psychic_wave', 'Zihinsel Dalga', 'Psychic Wave', '10m''lik bir koni şeklinde psişik enerji serbest bırakırsınız. Düşmanlar 3d6 psişik hasar alır ve 3m geri itilir.', 'Unleash a 10m cone of psychic energy. Enemies take 3d6 psychic damage and are pushed 3m.', 'Psychic', 21, 200, 2, '{"mh_telekinetic_pebble"}', '{"x": 822, "y": -474}', '{"damage": "3d6", "damage_type": "psychic", "area": "10m cone", "knockback": "3m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('473d12fe-1cc4-4e2e-8dcb-1068d50ee907', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_levitate', 'Yükselme', 'Levitate', 'Telekinezi kullanarak 1 dakika boyunca havada 5m''ye kadar yükselirsiniz.', 'Float up to 5m in the air using telekinesis, lasting for 1 minute.', 'Psychic', 25, 220, 2, '{"mh_psychic_wave"}', '{"x": 1039, "y": -599}', '{"height": "5m", "duration": "1 minute"}', '🪶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bde96543-80f6-4091-bc98-80239f759d69', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_brain_static', 'Beyin Paraziti', 'Brain Static', 'Hedefin düşüncelerini bozarsınız. 2d8 psişik hasar alırlar ve bir sonraki saldırılarında dezavantajlı olurlar.', 'Disrupt a target''s thoughts. They take 2d8 psychic damage and have disadvantage on their next attack.', 'Psychic', 35, 280, 2, '{"mh_levitate"}', '{"x": 1255, "y": -724}', '{"damage": "2d8", "damage_type": "psychic", "debuff": "Disadvantage on next attack"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0c73e0ca-ba68-48ca-8976-32bcb8c02dba', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_telekinetic_grasp', 'Telekinetik Kavrama', 'Telekinetic Grasp', 'Bir hedefi telekinezi ile 15m uzaktan havada tutarsınız. 2 tur boyunca kısıtlanırlar.', 'Hold a target in the air with telekinesis up to 15m away. They are restrained for 2 rounds.', 'Psychic', 41, 350, 3, '{"mh_brain_static"}', '{"x": 1472, "y": -849}', '{"range": "15m", "status": "Restrained", "duration": "2 rounds"}', '🖐️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ebda15c-ba10-428c-9be5-013d0de1abc4', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_psychic_blast', 'Psikolojik Patlama', 'Psychic Blast', '20m uzunluğunda yoğunlaştırılmış zihinsel güç ateşlersiniz, yolundaki herkese 6d6 psişik hasar verirsiniz.', 'Fire a 20m line of concentrated mental force, dealing 6d6 psychic damage to all in its path.', 'Psychic', 50, 400, 3, '{"mh_telekinetic_grasp"}', '{"x": 1688, "y": -974}', '{"damage": "6d6", "damage_type": "psychic", "area": "20m line"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b69693c-f565-4d93-8a6b-e7bb53f974f3', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mind_barrier', 'Zihinsel Bariyer', 'Mind Barrier', '5m yarıçapında sert ışık ve psişik enerjiden oluşan bir kubbe yaratırsınız. 3 tur boyunca fiziksel mermileri engeller.', 'Create a 5m radius dome of hard light and psychic energy. Blocks physical projectiles for 3 rounds.', 'Psychic', 55, 450, 3, '{"mh_psychic_blast"}', '{"x": 1905, "y": -1099}', '{"radius": "5m", "duration": "3 rounds", "utility": "Blocks projectiles"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f70495f-01fb-4cd0-a6ee-469d8f32c2af', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_telekinetic_crush', 'Telekinetik Ezme', 'Telekinetic Crush', 'Kısıtlanmış bir hedefi görünmez bir basınçla ezerek 8d8 ezici hasar verirsiniz.', 'Crush a restrained target with invisible pressure, dealing 8d8 bludgeoning damage.', 'Psychic', 65, 700, 4, '{"mh_mind_barrier"}', '{"x": 2121, "y": -1224}', '{"damage": "8d8", "damage_type": "bludgeoning", "requirement": "Target must be restrained"}', '🗜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('32ec79e2-4e36-4192-b4b4-34b4e5362b2f', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_psychic_storm', 'Zihinsel Fırtına', 'Psychic Storm', '15m yarıçapında zihinsel bir parazit fırtınası yaratırsınız. İçindeki düşmanlar 10d6 psişik hasar alır. 1 dakika sürer.', 'Conjure a 15m radius storm of mental static. Enemies inside take 10d6 psychic damage. Lasts 1 minute.', 'Psychic', 75, 850, 4, '{"mh_telekinetic_crush"}', '{"x": 2338, "y": -1349}', '{"damage": "10d6", "damage_type": "psychic", "radius": "15m", "duration": "1 minute"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f76e2078-a6f9-4441-a9f5-7e242e25b8ed', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mind_maelstrom', 'Zihin Girdabı', 'Mind Maelstrom', '20m yarıçapında psişik bir girdap oluşturursunuz. Düşmanlar 12d8 psişik hasar alır ve 10m merkeze çekilir.', 'Form a 20m radius psychic vortex. Enemies take 12d8 psychic damage and are pulled 10m to the center.', 'Psychic', 85, 1100, 5, '{"mh_psychic_storm"}', '{"x": 2554, "y": -1474}', '{"damage": "12d8", "damage_type": "psychic", "radius": "20m", "pull": "10m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c11f7a4-7fc2-499f-beed-cfeb296ddf21', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_astral_singularity', 'Astral Tekillik', 'Astral Singularity', 'Psişik enerjiden bir kara delik yaratırsınız. 15m yarıçapındaki düşmanlara 15d10 psişik hasar verir ve 2 tur sersemletir.', 'Create a black hole of psychic energy. Deals 15d10 psychic damage and stuns enemies in a 15m radius for 2 rounds.', 'Psychic', 95, 1400, 5, '{"mh_mind_maelstrom"}', '{"x": 2771, "y": -1599}', '{"damage": "15d10", "damage_type": "psychic", "radius": "15m", "status": "Stunned", "duration": "2 rounds"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('415f9017-445c-40a2-9f2c-49b806309a49', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_sense_minds', 'Zihin Sezgisi', 'Sense Minds', '30m içindeki zeki yaratıkların varlığını ve tam konumunu 10 dakika boyunca algılarsınız.', 'Detect the presence and exact location of intelligent creatures within 30m for 10 minutes.', 'Telepathy', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"radius": "30m", "duration": "10 minutes", "utility": "Detect intelligent creatures"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('107d27d1-cac0-4bc3-b8ad-2f84f5ce66e5', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_whisper', 'Fısıltı', 'Whisper', '100m uzaklığa kadar bir hedefin zihnine doğrudan telepatik bir mesaj gönderirsiniz.', 'Send a telepathic message directly into a target''s mind up to 100m away.', 'Telepathy', 5, 75, 1, '{"mh_sense_minds"}', '{"x": 289, "y": 344}', '{"range": "100m", "utility": "Telepathic communication"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('962be23c-a6c8-4e59-ae1b-394545fbbafb', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_read_surface_thoughts', 'Yüzeysel Düşünce Okuma', 'Read Surface Thoughts', '15m içindeki bir hedefin anlık düşüncelerini 1 dakika boyunca okursunuz.', 'Read the immediate thoughts of a target within 15m for 1 minute.', 'Telepathy', 12, 120, 1, '{"mh_whisper"}', '{"x": 449, "y": 536}', '{"range": "15m", "duration": "1 minute"}', '📖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dffb890f-ec80-4add-a27f-ee94f065c0b3', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mind_track', 'Zihinsel Takip', 'Mind Track', 'Bir hedefi zihinsel olarak işaretlersiniz. 24 saat boyunca konumunu ve mesafesini her zaman bilirsiniz.', 'Mentally mark a target. You always know their location and distance for 24 hours.', 'Telepathy', 22, 180, 2, '{"mh_read_surface_thoughts"}', '{"x": 610, "y": 727}', '{"duration": "24 hours", "utility": "Perfect tracking"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce1983cc-8afe-4ccf-9948-42209c9589b7', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_false_memory', 'Sahte Anı', 'False Memory', 'Bir hedefin zihnine 5 dakikaya kadar süren zararsız bir sahte anı yerleştirirsiniz.', 'Implant a harmless memory up to 5 minutes long in a target''s mind.', 'Telepathy', 28, 240, 2, '{"mh_mind_track"}', '{"x": 771, "y": 919}', '{"utility": "Implant 5 minute memory"}', '💭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b745df45-6afb-427f-9c4d-a56c65a17ac8', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_confusion', 'Kafa Karışıklığı', 'Confusion', 'Hedefin duyularını karıştırırsınız. 2 tur boyunca rastgele hareket ederler ve en yakın yaratığa saldırırlar.', 'Scramble a target''s senses. They move randomly and attack the nearest creature for 2 rounds.', 'Telepathy', 36, 290, 2, '{"mh_false_memory"}', '{"x": 932, "y": 1110}', '{"status": "Confused", "duration": "2 rounds"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('91795548-c02a-4f7e-8b81-8fb5aa103b36', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_probe_mind', 'Zihin Sondası', 'Probe Mind', 'Hedefin zihninden derin ve belirli bir anıyı çıkarırsınız. Sonda yaptığınız her tur başına 3d6 psişik hasar alırlar.', 'Extract a specific deep memory from a target. They take 3d6 psychic damage per round of probing.', 'Telepathy', 42, 360, 3, '{"mh_confusion"}', '{"x": 1092, "y": 1302}', '{"damage": "3d6 per round", "damage_type": "psychic", "utility": "Extract deep memory"}', '🪛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b38d9a3-02b0-4aca-91be-8e035e0ebb10', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_illusory_reality', 'Yanılsamalı Gerçeklik', 'Illusory Reality', 'Hedefin zihninde derin duyusal yanılsamalar yaratırsınız. 1 dakika boyunca orada olmayan şeyleri görür, duyar ve hissederler.', 'Create profound sensory illusions in a target''s mind. They see, hear, and feel things that aren''t there for 1 minute.', 'Telepathy', 48, 420, 3, '{"mh_probe_mind"}', '{"x": 1253, "y": 1493}', '{"duration": "1 minute", "utility": "Complete sensory illusion"}', '🌈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('575c437f-8c6c-4034-9f21-3111570cdd11', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mass_paranoia', 'Kitle Paranoyası', 'Mass Paranoia', '10m yarıçapında yoğun bir paranoya aşılarsınız. Düşmanlar 3 tur boyunca birbirlerini düşman olarak görürler.', 'Instill intense paranoia in a 10m radius. Enemies treat each other as hostile for 3 rounds.', 'Telepathy', 58, 480, 3, '{"mh_illusory_reality"}', '{"x": 1414, "y": 1685}', '{"radius": "10m", "status": "Paranoia", "duration": "3 rounds"}', '👀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ddb44298-b71c-40ec-a6a3-232146e8b2f8', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_dominate_will', 'İrade Hâkimiyeti', 'Dominate Will', '1 dakika boyunca hedefin zihnini tamamen kontrol edersiniz. Telepatik olarak emirler verebilirsiniz.', 'Take total mental control of a target for 1 minute. You can issue commands telepathically.', 'Telepathy', 66, 720, 4, '{"mh_mass_paranoia"}', '{"x": 1574, "y": 1876}', '{"duration": "1 minute", "status": "Mind Controlled"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d4f3b08-a2d0-45af-9c85-c0ebb5db4244', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_memory_wipe', 'Hafıza Silme', 'Memory Wipe', 'Hedefin hafızasından 24 saate kadar olan bir süreyi silersiniz. Hedef travma nedeniyle 5d10 psişik hasar alır.', 'Erase up to 24 hours of memory from a target. The target suffers 5d10 psychic damage from the trauma.', 'Telepathy', 78, 880, 4, '{"mh_dominate_will"}', '{"x": 1735, "y": 2068}', '{"damage": "5d10", "damage_type": "psychic", "utility": "Erase 24 hours of memory"}', '🧽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6998bd63-bf7c-4a95-a4c0-3cfed1ad2a77', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_psychic_lobotomy', 'Zihinsel Lobotomi', 'Psychic Lobotomy', 'Hedefin zihnini mahvedersiniz. Kalıcı olarak 1d4 Zeka kaybederler ve 10d10 psişik hasar alırlar.', 'Devastate a target''s mind. They permanently lose 1d4 Intelligence and take 10d10 psychic damage.', 'Telepathy', 86, 1200, 5, '{"mh_memory_wipe"}', '{"x": 1896, "y": 2259}', '{"damage": "10d10", "damage_type": "psychic", "debuff": "-1d4 Intelligence permanently"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8fdc23c6-b3c2-48f7-8ace-06b1dede0b45', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_hive_mind_control', 'Kovan Zihni Kontrolü', 'Hive Mind Control', '30m içindeki en fazla 5 hedefi 1 saat boyunca kontrol edersiniz. Sizin emriniz altında senkronize bir kovan zihni gibi hareket ederler.', 'Dominate up to 5 targets within 30m for 1 hour. They act as a synchronized hive mind under your command.', 'Telepathy', 95, 1450, 5, '{"mh_psychic_lobotomy"}', '{"x": 2056, "y": 2451}', '{"radius": "30m", "targets": 5, "duration": "1 hour", "status": "Mind Controlled"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d7c9d1bc-3b2c-40e3-aeb9-2838def1432f', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_psychic_blade', 'Psişik Bıçak', 'Psychic Blade', 'Silahınızı zihinsel enerjiyle aşılarsınız. 1 dakika boyunca ek 1d4 psişik hasar verir.', 'Infuse your weapon with mental energy. It deals an additional 1d4 psychic damage for 1 minute.', 'Mind Strike', 2, 60, 1, '{}', '{"x": -128, "y": 153}', '{"bonus_damage": "1d4 psychic", "duration": "1 minute"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d913a2cb-cbaa-4509-8a23-f727b226c476', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_nerve_strike', 'Sinir Vuruşu', 'Nerve Strike', 'Sinir sistemine zarar veren hassas bir yakın dövüş saldırısı; hedefin hareket hızını 1 tur boyunca 5m azaltır.', 'A precision melee attack that damages the nervous system, reducing the target''s movement speed by 5m for 1 round.', 'Mind Strike', 6, 85, 1, '{"mh_psychic_blade"}', '{"x": -289, "y": 344}', '{"debuff": "-5m movement", "duration": "1 round"}', '🥢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93a6fe47-b4b3-4b6b-a8b9-90fcda1b283a', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_phantom_dagger', 'Hayalet Hançer', 'Phantom Dagger', 'Saf düşünceden oluşan bir hançeri 15m''ye kadar fırlatırsınız. 1d8 psişik hasar verir ve fiziksel zırhı yok sayar.', 'Throw a dagger made of pure thought up to 15m. Deals 1d8 psychic damage and ignores physical armor.', 'Mind Strike', 15, 130, 1, '{"mh_nerve_strike"}', '{"x": -449, "y": 536}', '{"damage": "1d8", "damage_type": "psychic", "range": "15m", "utility": "Ignores Armor"}', '🪒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd358e50-b9e8-4512-b9c5-d7a86f8eb37d', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_synapse_overload', 'Sinaps Aşırı Yüklemesi', 'Synapse Overload', 'Hedefin sinirlerine vurursunuz. Ek 2d6 psişik hasar alırlar ve bir sonraki turunuza kadar tepki veremezler.', 'Strike a target''s nerves. They take an extra 2d6 psychic damage and cannot take reactions until your next turn.', 'Mind Strike', 23, 210, 2, '{"mh_phantom_dagger"}', '{"x": -610, "y": 727}', '{"bonus_damage": "2d6 psychic", "debuff": "Cannot take reactions"}', '🔌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('22913094-378d-4403-bb8b-80b069aab255', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_blinding_strike', 'Kör Eden Vuruş', 'Blinding Strike', 'Görsel kortekse keskin bir zihinsel vuruş. İsabet ettiğinde hedef 1 tur boyunca kör olur.', 'A sharp mental strike to the visual cortex. On a hit, the target is blinded for 1 round.', 'Mind Strike', 30, 250, 2, '{"mh_synapse_overload"}', '{"x": -771, "y": 919}', '{"status": "Blinded", "duration": "1 round"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('21dc8f64-814d-467c-aec7-f3f58c4d55c5', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mind_rend', 'Zihin Yırtılması', 'Mind Rend', 'Hedefin zihnini yırtarsınız. Silahınız +2d6 psişik hasar verir ve zihinsel kurtarma zarlarını 2 azaltır.', 'Tear at a target''s psyche. Your weapon deals +2d6 psychic damage and reduces their mental saving throws by 2.', 'Mind Strike', 38, 300, 2, '{"mh_blinding_strike"}', '{"x": -932, "y": 1110}', '{"bonus_damage": "2d6 psychic", "debuff": "-2 to mental saves"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d5de6e47-9bbf-43c9-b208-3fc0668429ef', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_paralyzing_blow', 'Felç Eden Darbe', 'Paralyzing Blow', 'Omuriliğe yıkıcı bir darbe. Hedef zar atıp başaramazsa 1 tur boyunca felç olur.', 'A devastating strike to the spinal cord. The target must save or be paralyzed for 1 round.', 'Mind Strike', 44, 380, 3, '{"mh_mind_rend"}', '{"x": -1092, "y": 1302}', '{"status": "Paralyzed", "duration": "1 round"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0700d1be-8b45-4c8e-bdaa-60b6bf4a0b8c', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_echo_strike', 'Yankı Vuruşu', 'Echo Strike', 'Vuruşunuz psişik bir iz bırakır. Bir tur sonra, hedef tam olarak aynı hasarı tekrar psişik hasar olarak alır.', 'Your strike leaves a psychic imprint. One round later, the target takes the exact same damage again as psychic damage.', 'Mind Strike', 52, 440, 3, '{"mh_paralyzing_blow"}', '{"x": -1253, "y": 1493}', '{"utility": "Repeat damage after 1 round", "damage_type": "psychic"}', '🔔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('498604a0-f47f-4c25-90cb-505b3091b1f3', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_brain_hemorrhage', 'Beyin Kanaması', 'Brain Hemorrhage', 'Beyindeki bir kan damarını patlatırsınız. Hedef sonraki 3 turunun başında 3d8 psişik hasar alır.', 'Rupture a blood vessel in the brain. The target takes 3d8 psychic damage at the start of their next 3 turns.', 'Mind Strike', 59, 490, 3, '{"mh_echo_strike"}', '{"x": -1414, "y": 1685}', '{"damage": "3d8 per turn", "damage_type": "psychic", "duration": "3 rounds"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4cebecba-5d80-4713-98a9-253f14da93f8', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_decapitating_thought', 'Baş Kesen Düşünce', 'Decapitating Thought', '20m menzilli zihinsel bir saldırı. 8d8 psişik hasar verir. Hedefin Can Puanı 50''nin altına düşerse, anında ölüm zarı atmalıdır.', 'A 20m ranged mental attack. Deals 8d8 psychic damage. If the target drops below 50 HP, they must make an instant death save.', 'Mind Strike', 68, 750, 4, '{"mh_brain_hemorrhage"}', '{"x": -1574, "y": 1876}', '{"damage": "8d8", "damage_type": "psychic", "range": "20m", "utility": "Death save if under 50 HP"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3049acc8-f5f0-4b8f-9e6b-6434adaee5c8', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_nervous_system_collapse', 'Sinir Sistemi Çöküşü', 'Nervous System Collapse', 'Silahınızı 5m''lik bir koni şeklinde savurursunuz. Tüm hedefler 6d8 psişik hasar alır ve yoğun acı nedeniyle yere serilir.', 'Sweep your weapon in a 5m cone. All targets take 6d8 psychic damage and are knocked prone by intense pain.', 'Mind Strike', 76, 860, 4, '{"mh_decapitating_thought"}', '{"x": -1735, "y": 2068}', '{"damage": "6d8", "damage_type": "psychic", "area": "5m cone", "status": "Prone"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee7345f3-d71d-427c-9cfd-00ec55c9f22f', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_psychic_execution', 'Psişik İnfaz', 'Psychic Execution', 'Bir hedefe 12d10 psişik hasar verirsiniz. Bu onları öldürürse, kafaları patlar ve bitişik düşmanlara 4d6 hasar verir.', 'Deal 12d10 psychic damage to a target. If this kills them, their head explodes, dealing 4d6 damage to adjacent enemies.', 'Mind Strike', 88, 1250, 5, '{"mh_nervous_system_collapse"}', '{"x": -1896, "y": 2259}', '{"damage": "12d10", "damage_type": "psychic", "on_kill": "4d6 damage to adjacent enemies"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c3ac7cf3-ac40-41ba-8c13-6da78890a5e4', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_cerebral_assassination', 'Serebral Suikast', 'Cerebral Assassination', '50m içindeki bir hedefe ışınlanır ve anında vurursunuz. Tüm dirençleri yok sayarak 20d10 psişik hasar verir.', 'Teleport to a target within 50m and strike instantly. Deals 20d10 psychic damage, ignoring all resistances.', 'Mind Strike', 98, 1480, 5, '{"mh_psychic_execution"}', '{"x": -2056, "y": 2451}', '{"damage": "20d10", "damage_type": "psychic", "range": "50m teleport", "utility": "Ignores resistances"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aa4bae50-1080-45c3-b4c3-bbd3a8f5a2af', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_telekinetic_weapon', 'Telekinetik Silah', 'Telekinetic Weapon', 'Telekinezi ile bir silahı canlandırırsınız. 1 dakika boyunca sizden 10m uzağa kadar otonom olarak savaşır.', 'Animate a weapon with telekinesis. It fights autonomously up to 10m away from you for 1 minute.', 'Cross-Branch', 25, 230, 2, '{"mh_telekinetic_pebble", "mh_psychic_blade"}', '{"x": -173, "y": -100}', '{"range": "10m", "duration": "1 minute", "utility": "Autonomous attacks"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e9cf26a2-9f0c-465a-88a4-6f995828aaa6', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_read_intentions', 'Niyet Okuma', 'Read Intentions', 'Hedefin dövüş hamlelerini okursunuz. Takip edilen bir hedefe karşı 3 tur boyunca tüm saldırı zarlarında avantaj kazanırsınız.', 'Read a target''s combat moves. Gain advantage on all attack rolls against a tracked target for 3 rounds.', 'Cross-Branch', 32, 270, 2, '{"mh_sense_minds", "mh_nerve_strike"}', '{"x": -389, "y": -225}', '{"buff": "Advantage on attack rolls", "duration": "3 rounds"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f199e47c-71a6-46e2-a96a-54672e82aa57', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_illusory_decoy', 'Yanılsamalı Hedef', 'Illusory Decoy', 'Havaya yükselen fiziksel bir kopya yaratırsınız. Saldırıya uğrarsa patlar ve saldırgana 4d6 psişik hasar verir.', 'Create a levitating physical clone. If attacked, it explodes, dealing 4d6 psychic damage to the attacker.', 'Cross-Branch', 45, 390, 3, '{"mh_false_memory", "mh_levitate"}', '{"x": -606, "y": -350}', '{"damage": "4d6", "damage_type": "psychic", "utility": "Explodes on hit"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b06b0686-624b-46cb-a30a-f6ba08d02e75', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mind_tether', 'Zihin Bağı', 'Mind Tether', '20m uzağa kadar bir hedefle zihinsel bir bağ kurarsınız. Aldığınız her hasarın yarısını onlar da alır.', 'Form a mental link with a target up to 20m away. Any damage you take, they take half of it.', 'Cross-Branch', 55, 460, 3, '{"mh_mind_track", "mh_mind_shield"}', '{"x": -822, "y": -475}', '{"range": "20m", "utility": "Shared damage"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d3a42578-0610-4a30-a15f-a7abb9bb8978', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_neurological_sabotage', 'Nörolojik Sabotaj', 'Neurological Sabotage', 'Sinir sistemini karıştırmak için vurursunuz. 3d6 psişik hasar verir ve 2 tur boyunca Kafa Karışıklığı uygular.', 'Strike to confuse the nervous system. Deals 3d6 psychic damage and applies Confusion for 2 rounds.', 'Cross-Branch', 56, 470, 3, '{"mh_confusion", "mh_synapse_overload"}', '{"x": -1039, "y": -600}', '{"damage": "3d6", "damage_type": "psychic", "status": "Confused", "duration": "2 rounds"}', '🕹️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce876848-d8f1-4d31-8c48-d6b1e31576ee', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_astral_projection_strike', 'Astral Projeksiyon Vuruşu', 'Astral Projection Strike', 'Ruhunuzu 30m''ye kadar yansıtıp bir düşmana 10d8 psişik hasar veren bir vuruş yapar ve ardından anında vücudunuza geri dönersiniz.', 'Project your spirit up to 30m, strike an enemy for 10d8 psychic damage, then instantly snap back to your body.', 'Cross-Branch', 65, 710, 4, '{"mh_telekinetic_grasp", "mh_echo_strike"}', '{"x": -1255, "y": -725}', '{"damage": "10d8", "damage_type": "psychic", "range": "30m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c1c122ed-2710-4c33-ae9e-2a4ff3f7ee84', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mass_mind_wipe', 'Toplu Zihin Silme', 'Mass Mind Wipe', '15m yarıçapında bir amnezi dalgası yayarsınız. Düşmanlar 1d4 tur boyunca kiminle savaştıklarını unutur ve tüm saldırıları durdururlar.', 'Release a wave of amnesia in a 15m radius. Enemies forget who they are fighting for 1d4 rounds, stopping all attacks.', 'Cross-Branch', 72, 820, 4, '{"mh_mass_paranoia", "mh_psychic_blast"}', '{"x": -1472, "y": -850}', '{"radius": "15m", "status": "Amnesia", "duration": "1d4 rounds"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46e70e84-c7c3-42d1-98c8-15364b0d05f8', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_cerebral_tracking', 'Serebral Takip', 'Cerebral Tracking', 'Bir hedefin zihnini sondaladığınızda, onlara karşı yapılan her saldırı kritik vuruşlarda iki kat hasar verir. 10 dakika sürer.', 'Once you probe a target''s mind, every attack against them deals double damage on critical hits. Lasts 10 minutes.', 'Cross-Branch', 77, 890, 4, '{"mh_probe_mind", "mh_mind_rend"}', '{"x": -1688, "y": -975}', '{"buff": "Double crit damage", "duration": "10 minutes"}', '🔎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('293bc457-0018-4cb5-b9c0-1036224170e9', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_telekinetic_execution', 'Telekinetik İnfaz', 'Telekinetic Execution', 'Bir hedefi havaya kaldırırsınız, 10d10 ezici hasarla ezer ve sonra onları şiddetle yere düşürürsünüz.', 'Lift a target high into the air, crush them for 10d10 bludgeoning damage, then violently drop them.', 'Cross-Branch', 85, 1150, 5, '{"mh_telekinetic_crush", "mh_paralyzing_blow"}', '{"x": -1905, "y": -1100}', '{"damage": "10d10", "damage_type": "bludgeoning", "utility": "Fall damage applied"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e06547fd-a2b5-4899-be61-272be15357be', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_master_of_puppets', 'Kukla Efendisi', 'Master of Puppets', '3 düşmanın kontrolünü ele geçirir ve onları kendi müttefiklerine karşı en güçlü yeteneklerini kullanmaya zorlarsınız.', 'Seize control of 3 enemies and force them to cast their most powerful abilities on their own allies.', 'Cross-Branch', 89, 1300, 5, '{"mh_dominate_will", "mh_telekinetic_grasp"}', '{"x": -2121, "y": -1225}', '{"targets": 3, "utility": "Forced friendly fire"}', '🧵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca65efff-dfeb-481f-9b15-8ce064512976', '10799c87-b680-4d06-861c-9ec600b7ac1a', 'mh_mindscape_collapse', 'Zihin Boyutu Çöküşü', 'Mindscape Collapse', '50m içindeki tüm düşmanları 1 dakika boyunca kendi zihinsel boyutunuza çekersiniz. İçeride iki kat hasar verirsiniz ve onlar her tur 5d10 psişik hasar alırlar.', 'Drag all enemies within 50m into your mental realm for 1 minute. Inside, you deal double damage and they take 5d10 psychic damage per round.', 'Cross-Branch', 100, 1500, 5, '{"mh_astral_singularity", "mh_hive_mind_control", "mh_cerebral_assassination"}', '{"x": -2338, "y": -1350}', '{"radius": "50m", "damage": "5d10 per round", "damage_type": "psychic", "buff": "Double damage dealt", "duration": "1 minute"}', '🤯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e725eec2-c133-4fcb-bab1-f6e4632cc865', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_rapid_strikes', 'Seri Vuruşlar', 'Rapid Strikes', '2m içindeki bir hedefe her biri 1d8 fiziksel hasar veren iki hızlı vuruş yapar.', 'Unleashes a quick barrage of two strikes dealing 1d8 physical damage each to a target within 2m.', 'Martial Arts', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "2d8", "range": "2m"}', '🥊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e253171b-1bf9-4c1c-a277-473420acd735', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_sweeping_kick', 'Süpüren Tekme', 'Sweeping Kick', '2m''lik bir koni içindeki düşmanlara 1d6 fiziksel hasar veren ve onları yere düşüren alçak bir tekme.', 'A low kick that deals 1d6 physical damage and knocks enemies prone in a 2m cone.', 'Martial Arts', 3, 75, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "1d6", "aoe": "2m cone", "condition": "Prone"}', '🦵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1901b93-0ac1-44e3-9fc3-1231b21ba77c', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_deflecting_palm', 'Saptıran Avuç', 'Deflecting Palm', 'Gelen bir yakın dövüş saldırısını saptırmak için reaksiyonunuzu kullanın, hasarını 1d10 + Çeviklik değiştiricisi kadar azaltın.', 'Use your reaction to deflect an incoming melee attack, reducing its damage by 1d10 + Dexterity modifier.', 'Martial Arts', 5, 100, 1, '{}', '{"x": 606, "y": -349}', '{"damage_reduction": "1d10+dex", "trigger": "Reaction"}', '🤚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a66f25d6-8a9c-4f2b-9d0f-9ec78fbb059c', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_tiger_claw', 'Kaplan Pençesi', 'Tiger Claw', '2m içindeki hedefe 2d6 kesici hasar verin, 2 tur boyunca tur başına 1d4 kanama hasarı almalarına neden olun.', 'Slash the target for 2d6 slashing damage within 2m, causing them to bleed for 1d4 damage per turn for 2 turns.', 'Martial Arts', 10, 150, 1, '{}', '{"x": 822, "y": -474}', '{"damage": "2d6", "dot": "1d4/turn", "duration": "2 turns", "range": "2m"}', '🐅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f5c6959-40b9-46cc-bd6f-844515825cb1', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_flying_kick', 'Uçan Tekme', 'Flying Kick', 'Bir düşmana doğru 10m''ye kadar sıçrayın ve güçlü bir tekme atarak çarpma anında 3d6 fiziksel hasar verin.', 'Leap up to 10m towards an enemy and deliver a powerful kick, dealing 3d6 physical damage upon impact.', 'Martial Arts', 22, 200, 2, '{"mk_sweeping_kick"}', '{"x": 1039, "y": -599}', '{"damage": "3d6", "range": "10m jump"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81d9b1a8-86ad-4c8e-b03f-9b3fc8eb45f1', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_pressure_point', 'Basınç Noktası', 'Pressure Point', '2m içindeki hayati bir sinire vurarak 2d8 fiziksel hasar verin ve hedefin 1 tur boyunca reaksiyon kullanmasını engelleyin.', 'Strike a vital nerve within 2m, dealing 2d8 physical damage and preventing the target from using reactions for 1 turn.', 'Martial Arts', 25, 225, 2, '{"mk_rapid_strikes"}', '{"x": 1255, "y": -724}', '{"damage": "2d8", "condition": "No Reactions", "duration": "1 turn", "range": "2m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4dca63b3-7931-4386-b5b1-4b2da3f966da', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_flurry_of_blows', 'Yumruk Fırtınası', 'Flurry of Blows', '2m içindeki bir hedefe her biri 1d6 fiziksel hasar veren 4 hızlı yumruktan oluşan yıkıcı bir fırtına serbest bırakın.', 'Unleash a devastating flurry of 4 rapid punches, each dealing 1d6 physical damage to a target within 2m.', 'Martial Arts', 30, 250, 2, '{"mk_rapid_strikes"}', '{"x": 1472, "y": -849}', '{"damage": "4d6", "range": "2m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f1f05783-b453-412e-b124-5091a1494255', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_crane_stance', 'Turna Duruşu', 'Crane Stance', 'Savunma duruşuna geçerek 2 tur boyunca +3 Zırh Sınıfı kazanın. Bir düşman size karşı yakın dövüş saldırısını kaçırırsa, 1d8 fiziksel hasarla karşı saldırı yapın.', 'Adopt a defensive stance, gaining +3 AC for 2 turns. If an enemy misses a melee attack against you, counterattack for 1d8 physical damage.', 'Martial Arts', 35, 300, 2, '{"mk_deflecting_palm"}', '{"x": 1688, "y": -974}', '{"buff": "+3 AC", "counterattack": "1d8", "duration": "2 turns"}', '🦩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('00a9f860-29a7-4883-b69c-85d6fb682181', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_dragon_punch', 'Ejderha Yumruğu', 'Dragon Punch', '4d8 ezici hasar veren ve hedefi 5m geriye savuran güçlü bir aparkat atın.', 'Deliver a mighty uppercut that deals 4d8 bludgeoning damage and knocks the target back 5m.', 'Martial Arts', 42, 400, 3, '{"mk_flurry_of_blows"}', '{"x": 1905, "y": -1099}', '{"damage": "4d8", "knockback": "5m", "range": "2m"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a55ba64-9a7d-46e1-911d-9467c8ac2965', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_one_inch_punch', 'Bir İnçlik Yumruk', 'One Inch Punch', 'Yakın mesafeden muazzam bir güç yönlendirin. 2m içinde zırhı tamamen yok sayarak 5d8 güç hasarı verir.', 'Channel immense force from close range. Deals 5d8 force damage within 2m, completely ignoring armor.', 'Martial Arts', 48, 450, 3, '{"mk_pressure_point"}', '{"x": 2121, "y": -1224}', '{"damage": "5d8", "armor_penetration": "100%", "range": "2m"}', '📏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('315a5c4e-d443-4975-a5bb-80d7d16b9acc', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_whirlwind_kick', 'Kasırga Tekmesi', 'Whirlwind Kick', 'Bacaklarınız açıkken hızla dönerek 3m yarıçapındaki tüm düşmanlara 4d6 fiziksel hasar verin.', 'Spin rapidly with extended legs, dealing 4d6 physical damage to all enemies within a 3m radius.', 'Martial Arts', 55, 500, 3, '{"mk_flying_kick"}', '{"x": 2338, "y": -1349}', '{"damage": "4d6", "aoe": "3m radius"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fc2b7a9c-6144-45e3-9b91-1544da903cb1', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_shattering_strike', 'Parçalayan Vuruş', 'Shattering Strike', '6d8 fiziksel hasar veren ve hedefteki tüm büyülü bariyerleri veya kalkanları anında parçalayan odaklanmış bir vuruş.', 'A focused strike that deals 6d8 physical damage and instantly shatters any magical barriers or shields on the target.', 'Martial Arts', 65, 700, 4, '{"mk_dragon_punch", "mk_one_inch_punch"}', '{"x": 2554, "y": -1474}', '{"damage": "6d8", "utility": "Shatters Shields", "range": "2m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('99e4394b-bfc0-4f23-a412-814a4b613e77', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_quivering_palm', 'Titreyen Avuç', 'Quivering Palm', 'Hedefin vücudunda ölümcül titreşimler oluşturun. 2m içinde 8d8 nekrotik hasar verir; hedef kurtarma zarı atamazsa 1 tur sersemler.', 'Set up lethal vibrations in the target''s body. Deals 8d8 necrotic damage within 2m; target must save or be stunned for 1 turn.', 'Martial Arts', 75, 850, 4, '{"mk_one_inch_punch", "mk_whirlwind_kick"}', '{"x": 2771, "y": -1599}', '{"damage": "8d8", "condition": "Stunned", "duration": "1 turn", "range": "2m"}', '🫨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c85cec48-b3f6-490a-8bc5-892340439455', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_hundred_fists', 'Yükselenin Yüz Yumruğu', 'Hundred Fists of the Ascendant', 'Nihai dövüş tekniği. 3m içinde 12d6 ezici hasar veren ve hedefi 1 tur felç bırakan durdurulamaz bir vuruş yağmuru yapın.', 'Ultimate martial technique. Deliver an unstoppable barrage of strikes dealing 12d6 bludgeoning damage within 3m and leaving the target paralyzed for 1 turn.', 'Martial Arts', 90, 1200, 5, '{"mk_shattering_strike", "mk_quivering_palm"}', '{"x": 2987, "y": -1724}', '{"damage": "12d6", "condition": "Paralyzed", "duration": "1 turn", "range": "3m"}', '💯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dccfadbe-f312-4de8-ba3e-702e5d822e82', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_inner_peace', 'İç Huzur', 'Inner Peace', 'Kendinize 2d6 + Bilgelik değiştiricisi kadar Can Puanı yenilemek ve küçük zayıflatmaları kaldırmak için meditasyon yapın.', 'Meditate to restore 2d6 + Wisdom modifier HP to yourself and remove minor debuffs.', 'Meditation', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"healing": "2d6+wis", "utility": "Cleanse Debuffs"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5303e362-84cb-40fa-ab02-fd4bc7a0bcd3', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_mindful_step', 'Bilinçli Adım', 'Mindful Step', 'Zihninizi harekete odaklayarak 1 tur boyunca +5m hareket hızı ve fırsat saldırılarına karşı bağışıklık kazanın.', 'Focus your mind on movement, gaining +5m movement speed and immunity to opportunity attacks for 1 turn.', 'Meditation', 4, 75, 1, '{}', '{"x": 289, "y": 344}', '{"buff": "+5m speed", "immunity": "Opportunity Attacks", "duration": "1 turn"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b44a748-bebf-474a-8232-16766484d939', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_focus_breath', 'Odaklanmış Nefes', 'Focused Breath', '5 dayanıklılık yenilemek ve bir sonraki saldırınıza 1d6 güç hasarı eklemek için derin bir nefes alın.', 'Take a deep breath to regain 5 stamina and add 1d6 force damage to your next attack.', 'Meditation', 8, 100, 1, '{}', '{"x": 449, "y": 536}', '{"restore": "5 Stamina", "buff": "+1d6 damage next attack"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a7d1f13c-c64d-4880-80cd-7c8a74d16eb4', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_iron_skin', 'Demir Deri', 'Iron Skin', 'Vücudunuzu ki ile sertleştirin, 10 geçici Can Puanı ve 3 tur boyunca fiziksel hasara karşı direnç kazanın.', 'Harden your body with ki, gaining 10 temporary HP and resistance to physical damage for 3 turns.', 'Meditation', 12, 150, 1, '{}', '{"x": 610, "y": 727}', '{"temp_hp": "10", "resistance": "Physical", "duration": "3 turns"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34ad9b70-6595-47a1-a90d-e623725fa317', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_stillness_of_mind', 'Zihnin Durgunluğu', 'Stillness of Mind', 'Zihninizi boşaltın, her türlü çekicilik veya korku etkisini iyileştirin ve 2 tur boyunca bunlara karşı bağışıklık kazanın.', 'Clear your mind, curing any charm or fear effects and becoming immune to them for 2 turns.', 'Meditation', 24, 200, 2, '{"mk_inner_peace"}', '{"x": 771, "y": 919}', '{"cleanse": "Charm/Fear", "immunity": "Charm/Fear", "duration": "2 turns"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e6fb3e3-c8a0-4ba6-982c-939cbef9f152', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_healing_trance', 'İyileştiren Trans', 'Healing Trance', 'Derin bir transa girerek 2 tur boyunca 4d6 Can Puanı iyileşin. Trans aktifken hareket edemezsiniz.', 'Enter a deep trance, healing 4d6 HP over 2 turns. You cannot move while the trance is active.', 'Meditation', 28, 250, 2, '{"mk_inner_peace"}', '{"x": 932, "y": 1110}', '{"healing": "4d6", "condition": "Immobile", "duration": "2 turns"}', '🛌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84f107a2-bbb8-4118-85e6-595d7daafed7', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_empty_body', 'Boş Beden', 'Empty Body', '2 tur boyunca görünmez olun ve güç hasarı hariç tüm hasar türlerine karşı direnç kazanın.', 'Turn invisible for 2 turns and gain resistance to all damage types except force damage.', 'Meditation', 32, 275, 2, '{"mk_mindful_step"}', '{"x": 1092, "y": 1302}', '{"buff": "Invisibility", "resistance": "All except Force", "duration": "2 turns"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1134ea5b-7ae8-43fa-bccf-a10ee69be431', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_diamond_soul', 'Elmas Ruh', 'Diamond Soul', 'Ruhunuzu güçlendirin. Başarısız bir kurtarma zarını yeniden atın ve 2 tur boyunca tüm kurtarma zarlarına +2 kazanın.', 'Fortify your soul. Reroll a failed saving throw and gain +2 to all saving throws for 2 turns.', 'Meditation', 38, 300, 2, '{"mk_iron_skin"}', '{"x": 1253, "y": 1493}', '{"utility": "Reroll Save", "buff": "+2 Saves", "duration": "2 turns"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b99c98d-edea-435d-b469-41f6e2aeb62d', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_zen_state', 'Zen Hali', 'Zen State', 'Mükemmel dengeye ulaşarak 3 tur boyunca +4 Zırh Sınıfı ve tüm kurtarma zarlarına +4 kazanın.', 'Achieve perfect balance, gaining +4 AC and +4 to all saving throws for 3 turns.', 'Meditation', 45, 400, 3, '{"mk_stillness_of_mind"}', '{"x": 1414, "y": 1685}', '{"buff": "+4 AC, +4 Saves", "duration": "3 turns"}', '☯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a9c45e15-2ec7-48b5-a626-0161540101bc', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_purity_of_body', 'Bedenin Saflığı', 'Purity of Body', 'Sisteminizi arındırarak tüm hastalıkları ve zehirleri iyileştirin ve 1 saat boyunca bunlara karşı bağışıklık kazanın.', 'Purify your system, curing all diseases and poisons, and gaining immunity to them for 1 hour.', 'Meditation', 50, 450, 3, '{"mk_healing_trance"}', '{"x": 1574, "y": 1876}', '{"cleanse": "Disease/Poison", "immunity": "Disease/Poison", "duration": "1 hour"}', '🌿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ec747850-99cc-476a-aaeb-e138b031ea3f', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_timeless_body', 'Zamansız Beden', 'Timeless Body', '5 tur boyunca tüm yorgunluk seviyelerini yok sayın, yaşlanma etkilerini durdurun ve anında 5d8 Can Puanı iyileşin.', 'Ignore all exhaustion levels for 5 turns, halt aging effects, and instantly heal 5d8 HP.', 'Meditation', 58, 500, 3, '{"mk_diamond_soul"}', '{"x": 1735, "y": 2068}', '{"healing": "5d8", "utility": "Ignore Exhaustion", "duration": "5 turns"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8463ac9-8716-4980-9693-3a0dbf29bcb9', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_astral_refuge', 'Astral Sığınak', 'Astral Refuge', '1 tur boyunca gerçeklikten astral düzleme geçerek tüm hasarlara karşı bağışıklık kazanın ve 8d8 Can Puanı iyileşin.', 'Phase out of reality into the astral plane for 1 turn, becoming immune to all damage and healing 8d8 HP.', 'Meditation', 68, 700, 4, '{"mk_empty_body", "mk_zen_state"}', '{"x": 1896, "y": 2259}', '{"healing": "8d8", "immunity": "All Damage", "duration": "1 turn"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('958cbfc5-cf47-49d0-9468-6900e66d637f', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_mantra_of_resilience', 'Direnç Mantrası', 'Mantra of Resilience', '10m''lik bir aura yayan bir mantra söyleyin. İçerideki müttefikler 20 geçici Can Puanı ve kurtarma zarlarına +3 kazanır.', 'Chant a mantra that projects a 10m aura. Allies inside gain 20 temporary HP and +3 to saving throws.', 'Meditation', 78, 850, 4, '{"mk_purity_of_body", "mk_timeless_body"}', '{"x": 2056, "y": 2451}', '{"aoe": "10m aura", "temp_hp": "20", "buff": "+3 Saves"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7687be05-c935-4736-930f-d0e08247b1f0', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_nirvana_incarnate', 'Nirvana''nın Vücut Bulmuş Hali', 'Nirvana Incarnate', 'Nihai meditasyon. 4 tur boyunca saf aydınlanmaya dönüşün. Tam Can Puanına iyileşin, kitle kontrolüne karşı bağışıklık kazanın ve tüm saldırılarla fazladan 4d8 parlak hasar verin.', 'Ultimate meditation. Transform into pure enlightenment for 4 turns. Heal to full HP, become immune to crowd control, and deal 4d8 extra radiant damage with all attacks.', 'Meditation', 92, 1200, 5, '{"mk_astral_refuge", "mk_mantra_of_resilience"}', '{"x": 2217, "y": 2642}', '{"healing": "100%", "immunity": "CC", "buff": "+4d8 Radiant damage", "duration": "4 turns"}', '🪷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e28b6174-38c2-4351-b06b-ebd928ddbeb8', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_ki_blast', 'Ki Patlaması', 'Ki Blast', 'Bir düşmana 15m''ye kadar mesafeden yoğunlaştırılmış ki enerjisi patlaması ateşleyerek 1d10 güç hasarı verin.', 'Fire a concentrated blast of ki energy at an enemy, dealing 1d10 force damage up to 15m away.', 'Ki Energy', 2, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d10", "range": "15m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0672189-1eb5-42a8-92cf-3d21c68968ca', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_spirit_dart', 'Ruh Oku', 'Spirit Dart', 'İki parlayan ruh enerjisi oku fırlatın. Her ok 20m menzille 1d6 güç hasarı verir.', 'Shoot two glowing darts of spirit energy. Each dart deals 1d6 force damage with a 20m range.', 'Ki Energy', 6, 75, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "2d6", "range": "20m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dfb0f002-06a9-4fd2-a217-66e41bebc210', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_ki_shield', 'Ki Kalkanı', 'Ki Shield', 'Reaksiyon olarak bir ki kalkanı yansıtın ve 1 tur boyunca menzilli saldırılara karşı +4 Zırh Sınıfı kazanın.', 'Project a shield of ki as a reaction, gaining +4 AC against ranged attacks for 1 turn.', 'Ki Energy', 9, 100, 1, '{}', '{"x": -449, "y": 536}', '{"buff": "+4 AC vs Ranged", "trigger": "Reaction", "duration": "1 turn"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('037c5330-d17c-4a02-8c74-503a0b4594bc', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_elemental_fist', 'Element Yumruğu', 'Elemental Fist', 'Yumruklarınızı saf ki ile doldurarak 2 tur boyunca silahsız vuruşlarınıza 1d6 ateş, soğuk veya yıldırım hasarı ekleyin.', 'Infuse your fists with raw ki, adding 1d6 fire, cold, or lightning damage to your unarmed strikes for 2 turns.', 'Ki Energy', 15, 150, 1, '{}', '{"x": -610, "y": 727}', '{"buff": "+1d6 Elemental Damage", "duration": "2 turns"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d2f64efd-8ef6-4c7c-836b-e51d9669d186', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_ki_wave', 'Ki Dalgası', 'Ki Wave', '10m''lik bir hatta ki dalgası yayarak 3d6 güç hasarı verin ve düşmanları 2m geriye itin.', 'Release a wave of ki in a 10m line, dealing 3d6 force damage and pushing enemies back 2m.', 'Ki Energy', 21, 200, 2, '{"mk_ki_blast"}', '{"x": -771, "y": 919}', '{"damage": "3d6", "knockback": "2m", "aoe": "10m line"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b583dfcc-4112-4b4c-af7f-13ab5afb0a50', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_sun_soul_beam', 'Güneş Ruhu Işını', 'Sun Soul Beam', '15m''lik bir hatta 4d6 hasar veren kör edici bir parlak enerji ışını ateşleyin. Hedefler kurtarma zarı atamazsa 1 tur kör olur.', 'Fire a blinding beam of radiant energy dealing 4d6 damage in a 15m line. Targets must save or be blinded for 1 turn.', 'Ki Energy', 26, 250, 2, '{"mk_spirit_dart"}', '{"x": -932, "y": 1110}', '{"damage": "4d6", "condition": "Blinded", "duration": "1 turn", "aoe": "15m line"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49d09c64-3dc8-4cea-894a-93d0af958fc7', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_spirit_burst', 'Ruh Patlaması', 'Spirit Burst', 'Ruhsal enerjiyi her yöne atarak 5m yarıçapındaki tüm düşmanlara 3d8 güç hasarı verin.', 'Expel spiritual energy in all directions, dealing 3d8 force damage to all enemies within a 5m radius.', 'Ki Energy', 34, 275, 2, '{"mk_ki_blast"}', '{"x": -1092, "y": 1302}', '{"damage": "3d8", "aoe": "5m radius"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('76db1170-7c6e-4b38-8794-ecc4fda2aaac', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_ki_healing', 'Ki Şifası', 'Ki Healing', 'Yaşam gücünüzü 10m içindeki bir müttefike yönlendirerek onları 3d8 Can Puanı iyileştirin.', 'Channel your life force to an ally within 10m, healing them for 3d8 HP.', 'Ki Energy', 40, 300, 2, '{"mk_ki_shield"}', '{"x": -1253, "y": 1493}', '{"healing": "3d8", "range": "10m"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('02ffed51-a6c9-439a-843a-0c8e53ed7d13', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_aura_sphere', 'Aura Küresi', 'Aura Sphere', 'Yoğunlaştırılmış bir aura küresi oluşturup 20m fırlatın. Çarpma anında patlayarak 3m yarıçapında 5d8 güç hasarı verir.', 'Form a condensed sphere of aura and hurl it 20m. It explodes on impact, dealing 5d8 force damage in a 3m radius.', 'Ki Energy', 44, 400, 3, '{"mk_ki_wave"}', '{"x": -1414, "y": 1685}', '{"damage": "5d8", "aoe": "3m radius", "range": "20m"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('65d03ebf-9f00-4680-a619-484a27b58b86', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_wind_stance', 'Rüzgar Duruşu', 'Wind Stance', 'Kendinizi dönen rüzgarlarla çevreleyin. Menzilli saldırılar size karşı dezavantajlı olur ve vuruşlarınız 3 tur boyunca ekstra 2d8 gök gürültüsü hasarı verir.', 'Surround yourself with swirling winds. Ranged attacks have disadvantage against you, and your strikes deal 2d8 extra thunder damage for 3 turns.', 'Ki Energy', 52, 450, 3, '{"mk_elemental_fist"}', '{"x": -1574, "y": 1876}', '{"buff": "Ranged Disadvantage, +2d8 Thunder damage", "duration": "3 turns"}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0691a2c-c16a-400d-8704-7697404fb9b0', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_ki_eruption', 'Ki Püskürmesi', 'Ki Eruption', 'Yere vurarak ki''nin 10m yarıçapında patlamasına neden olun. 6d6 ateş hasarı verir ve zemini 2 tur yanar halde bırakır.', 'Slam the ground, causing ki to erupt in a 10m radius. Deals 6d6 fire damage and leaves the ground burning for 2 turns.', 'Ki Energy', 60, 500, 3, '{"mk_spirit_burst"}', '{"x": -1735, "y": 2068}', '{"damage": "6d6", "dot": "Burning ground", "duration": "2 turns", "aoe": "10m radius"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('294ab82d-5b01-4cf0-b19e-73873398cf30', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_meteor_strike', 'Meteor Vuruşu', 'Meteor Strike', 'Havaya 20m''ye kadar sıçrayıp bir meteor gibi aşağı çakılın, 5m yarıçapında 8d8 ateş ve ezici hasar verin.', 'Leap up to 20m into the air and crash down like a meteor, dealing 8d8 fire and bludgeoning damage in a 5m radius.', 'Ki Energy', 66, 700, 4, '{"mk_ki_eruption", "mk_wind_stance"}', '{"x": -1896, "y": 2259}', '{"damage": "8d8", "aoe": "5m radius", "range": "20m leap"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84e38ff6-1933-432e-a600-ac21c0037232', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_spirit_dragon', 'Ruh Ejderhası', 'Spirit Dragon', 'Ki''den yapılmış devasa bir ejderha çağırın ve 20m''lik bir hatta ilerleyerek yolundaki herkese 8d8 güç hasarı verin.', 'Summon a massive dragon made of ki that surges forward in a 20m line, dealing 8d8 force damage to all in its path.', 'Ki Energy', 76, 850, 4, '{"mk_aura_sphere", "mk_sun_soul_beam"}', '{"x": -2056, "y": 2451}', '{"damage": "8d8", "aoe": "20m line"}', '🐲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13f81ef6-c702-47d1-ba05-816c1d2ea934', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_grand_ki_beam', 'Yüce Ki Işını', 'Grand Ki Beam', 'Nihai Ki tekniği. 30m uzunluğunda ve 4m genişliğinde devasa, sürekli bir saf enerji ışını serbest bırakarak her şeyi 12d10 güç hasarıyla yok edin.', 'Ultimate Ki technique. Unleash a massive, sustained beam of pure energy in a 30m line and 4m width, obliterating everything for 12d10 force damage.', 'Ki Energy', 94, 1200, 5, '{"mk_meteor_strike", "mk_spirit_dragon"}', '{"x": -2217, "y": 2642}', '{"damage": "12d10", "aoe": "30x4m line"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('042d5c2e-880b-460f-89bc-33005f83c548', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_flowing_water_strike', 'Akan Su Vuruşu', 'Flowing Water Strike', 'Dövüş sanatları ve meditasyonu harmanlayan akıcı bir vuruş. 2m içinde 2d8 fiziksel hasar verir ve verilen hasarın yarısı kadar sizi iyileştirir.', 'A fluid strike blending martial arts and meditation. Deals 2d8 physical damage within 2m and heals you for half the damage dealt.', 'Martial Arts, Meditation', 25, 250, 2, '{"mk_rapid_strikes", "mk_inner_peace"}', '{"x": 173, "y": -99}', '{"damage": "2d8", "lifesteal": "50%", "range": "2m"}', '💧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9caf4b52-6725-4233-bf23-600bc6af3a6e', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_ki_infused_block', 'Ki Yüklü Blok', 'Ki Infused Block', 'Saldırıyı yoğunlaştırılmış ki ile engellemek için reaksiyonunuzu kullanın. Gelen hasarı 3d10 azaltın ve saldırgana 1d10 güç hasarı yansıtın.', 'Use your reaction to block an attack with concentrated ki. Reduce incoming damage by 3d10 and reflect 1d10 force damage back to the attacker.', 'Meditation, Ki Energy', 35, 300, 2, '{"mk_iron_skin", "mk_ki_shield"}', '{"x": 173, "y": -99}', '{"damage_reduction": "3d10", "reflect": "1d10", "trigger": "Reaction"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('942f3a6c-c0af-4328-8cb3-1cdeeacb386d', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_burning_soul_fist', 'Yanan Ruh Yumruğu', 'Burning Soul Fist', 'Yumruğunuzu ruh ateşiyle tutuşturun. 2m içinde 4d8 ateş ve fiziksel hasar verir ve hedefi 3 tur boyunca tur başına 1d8 ateş hasarıyla yakar.', 'Ignite your fist with soul fire. Deals 4d8 fire and physical damage within 2m, and ignites the target for 1d8 fire damage per turn for 3 turns.', 'Martial Arts, Ki Energy', 46, 450, 3, '{"mk_flurry_of_blows", "mk_elemental_fist"}', '{"x": 173, "y": -99}', '{"damage": "4d8", "dot": "1d8/turn", "duration": "3 turns", "range": "2m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ebb99d75-40ee-4c15-a769-dc67a9572272', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_tranquil_aura', 'Sakinlik Aurası', 'Tranquil Aura', '10m''ye kadar derin bir barış aurası yayın. Müttefikler tur başına 2d6 Can Puanı iyileşirken, düşmanlar saldırılarında 1d4 hasar kaybeder. 3 tur sürer.', 'Radiate an aura of profound peace up to 10m. Allies heal 2d6 HP per turn, while enemies lose 1d4 damage on their attacks. Lasts 3 turns.', 'Meditation, Ki Energy', 56, 500, 3, '{"mk_healing_trance", "mk_ki_healing"}', '{"x": 389, "y": -224}', '{"aoe": "10m aura", "healing": "2d6/turn", "debuff": "-1d4 enemy damage", "duration": "3 turns"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('257483d4-61fe-4fd9-b659-7831658ed8e4', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_echoing_strikes', 'Yankılanan Vuruşlar', 'Echoing Strikes', 'Sonraki 3 dövüş saldırınızı ki ile doldurun. Her vuruş fazladan 3d8 güç hasarı verir ve hedefin arkasında 5m''lik bir güç konisi yansıtır.', 'Infuse your next 3 martial attacks with ki. Each strike deals an additional 3d8 force damage and projects a 5m cone of force behind the target.', 'Martial Arts, Ki Energy', 64, 700, 4, '{"mk_dragon_punch", "mk_aura_sphere"}', '{"x": 389, "y": -224}', '{"buff": "+3d8 Force damage", "aoe": "5m cone behind target", "charges": "3 attacks"}', '🔊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1707a99f-a213-47e6-b592-f5683ddfaec2', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_shadow_step_strike', 'Gölge Adımı Vuruşu', 'Shadow Step Strike', 'Bir düşmana 15m''ye kadar anında ışınlanın, onlara 6d8 psişik ve fiziksel hasar verin, ardından 1 tur boyunca görünmez olun.', 'Teleport instantly up to 15m to an enemy, striking them for 6d8 psychic and physical damage, then turn invisible for 1 turn.', 'Martial Arts, Meditation', 72, 800, 4, '{"mk_flying_kick", "mk_empty_body"}', '{"x": 389, "y": -224}', '{"damage": "6d8", "range": "15m teleport", "buff": "Invisibility", "duration": "1 turn"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('442ec5f5-c7c0-4566-8ff0-2913c41e0b77', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_radiant_soul_avatar', 'Parlak Ruh Avatarı', 'Radiant Soul Avatar', 'Ki''nizi 3 tur boyunca parlak bir avatar olarak tezahür ettirin. 15m uçuş hızı kazanın, 20m ışık yayın, ışıktaki müttefikleri tur başına 4d6 iyileştirin ve düşmanları 4d6 parlak hasarla yakın.', 'Manifest your ki as a radiant avatar for 3 turns. Gain 15m fly speed, emit 20m light, heal allies in light for 4d6 per turn, and burn enemies for 4d6 radiant damage.', 'Meditation, Ki Energy', 80, 900, 4, '{"mk_zen_state", "mk_sun_soul_beam"}', '{"x": 606, "y": -349}', '{"buff": "15m Fly Speed", "aoe": "20m aura", "healing": "4d6/turn", "damage": "4d6/turn", "duration": "3 turns"}', '🔆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f8379661-ca21-424e-8d90-1021d257ca5a', '845bea40-0852-439d-8add-2f1c78cb3ef0', 'mk_asura_wrath', 'Asura''nın Gazabı', 'Wrath of the Asura', 'Görkemli Nihai. 5 tur boyunca korkunç Asura formuna yükselin. Ruhani kollar büyüterek +10m hız, 50 geçici Can Puanı kazanın ve her saldırı ekstra 6d10 güç hasarı için 3 kez vurur.', 'Grand Ultimate. Ascend to the fearsome Asura form for 5 turns. Grow ethereal arms, gaining +10m speed, 50 temporary HP, and every attack hits 3 times for an extra 6d10 force damage.', 'Martial Arts, Meditation, Ki Energy', 100, 1500, 5, '{"mk_hundred_fists", "mk_nirvana_incarnate", "mk_grand_ki_beam"}', '{"x": 173, "y": -99}', '{"buff": "Asura Form", "speed": "+10m", "temp_hp": "50", "damage_boost": "x3 hits, +6d10 Force", "duration": "5 turns"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a5a77f8-783e-4b2d-bac3-d03da0215c82', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_raise_skeleton_warrior', 'İskelet Savaşçı Dirilt', 'Raise Skeleton Warrior', 'Senin için savaşması amacıyla bir cesetten iskelet savaşçı diriltir. Yok edilene kadar kalır.', 'Raise a skeleton warrior from a corpse to fight for you. It remains until destroyed.', 'Skeleton', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"summons": "1 Skeleton Warrior", "health": "20 HP", "damage": "1d6 physical"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ac161e8-f548-47d8-9f95-d7d712a9bc35', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_splinter', 'Kemik Kıymığı', 'Bone Splinter', 'Uzaktan bir düşmana keskin bir kemik kıymığı fırlatır.', 'Fire a sharp splinter of bone at an enemy from a distance.', 'Bone', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d6 piercing", "range": "18m"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dfd835c2-1ec7-44a7-a013-b7835196d644', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_touch_of_decay', 'Çürüme Dokunuşu', 'Touch of Decay', 'Hedefin etini zamanla çürüten yakın dövüş büyü saldırısı.', 'A melee spell attack that rots the target''s flesh over time.', 'Plague', 3, 60, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d4 necrotic/sec", "duration": "5s", "range": "Melee"}', '🦠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c6064b7-7140-4af3-a776-8777c5014078', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_skeleton_mastery', 'İskelet Ustalığı', 'Skeleton Mastery', 'Diriltilen tüm iskeletlerin sağlığını ve hasarını pasif olarak artırır.', 'Passively increases the health and damage of all raised skeletons.', 'Skeleton', 5, 80, 1, '{"nc_raise_skeleton_warrior"}', '{"x": 389, "y": -224}', '{"health_bonus": "+20%", "damage_bonus": "+15%"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('be45a134-7b28-4c65-9b55-0805de55b34f', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_armor', 'Kemik Zırh', 'Bone Armor', 'Kendini fiziksel hasarı emen, yörüngede dönen kemiklerden oluşan bir kalkanla çevreler.', 'Surround yourself with a shield of orbiting bones that absorbs physical damage.', 'Bone', 8, 100, 1, '{"nc_bone_splinter"}', '{"x": 289, "y": 344}', '{"absorb": "30 damage", "duration": "1 hour"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4457104f-445d-441b-913e-d2258d394769', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_poison_cloud', 'Zehir Bulutu', 'Poison Cloud', 'Belirli bir alanda kalan küçük bir zehirli gaz bulutu yaratır.', 'Conjure a small cloud of toxic gas that lingers in an area.', 'Plague', 10, 110, 1, '{"nc_touch_of_decay"}', '{"x": -289, "y": 344}', '{"damage": "1d6 poison/sec", "radius": "4m", "duration": "10s"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('47d73edd-de16-4603-9f70-3ece41105527', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_undead_frenzy', 'Ölümsüz Çılgınlığı', 'Undead Frenzy', 'Hedef ölümsüz minyon kısa süreliğine devasa saldırı ve hareket hızı kazanır.', 'Target undead minion gains immense attack speed and movement speed for a short time.', 'Skeleton', 12, 120, 1, '{"nc_skeleton_mastery"}', '{"x": 606, "y": -349}', '{"attack_speed": "+50%", "movement_speed": "+30%", "duration": "10s"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1c1729d5-447a-4b35-9a40-0fd643974b63', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_calcify', 'Kireçlenme', 'Calcify', 'Bir hedefin kemiklerini sertleştirerek zırhını artırır ancak hareket hızını düşürür.', 'Harden a target''s bones, increasing their armor but reducing movement speed.', 'Bone', 15, 140, 1, '{"nc_bone_armor"}', '{"x": 449, "y": 536}', '{"armor_bonus": "+5", "speed_reduction": "-3m/s", "duration": "1 minute"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3c425115-9f35-437a-bb78-6d927c788fb0', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_weaken', 'Zayıflatma', 'Weaken', 'Bir düşmanı lanetleyerek fiziksel hasar çıkışını azaltır.', 'Curse an enemy, reducing their physical damage output.', 'Plague', 18, 150, 1, '{"nc_poison_cloud"}', '{"x": -449, "y": 536}', '{"damage_reduction": "25%", "duration": "12s", "range": "15m"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('afe30d12-9df6-43c9-be59-9a7412b37302', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_raise_skeleton_archer', 'İskelet Okçu Dirilt', 'Raise Skeleton Archer', 'Uzaktan saldıran bir iskelet okçu diriltir.', 'Raise a skeleton archer that attacks from a distance.', 'Skeleton', 22, 180, 2, '{"nc_raise_skeleton_warrior"}', '{"x": 822, "y": -474}', '{"summons": "1 Skeleton Archer", "range": "15m", "damage": "1d8 physical"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('537f2433-86f7-4dc8-8266-427b7229691d', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_corpse_explosion', 'Ceset Patlaması', 'Corpse Explosion', 'Yakındaki bir cesedi patlatarak etrafındaki tüm düşmanlara devasa hasar verir.', 'Detonate a nearby corpse, dealing massive damage to all enemies around it.', 'Plague', 24, 210, 2, '{"nc_poison_cloud"}', '{"x": -610, "y": 727}', '{"damage": "15% of corpse max HP", "radius": "6m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9050bc7-b7a8-44df-935b-448f886cecc0', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_spear', 'Kemik Mızrak', 'Bone Spear', 'Düz bir çizgideki birden fazla düşmanı deşip geçen büyük bir kemik mızrak yaratır.', 'Conjure a large bone spear that pierces through multiple enemies in a line.', 'Bone', 25, 200, 2, '{"nc_bone_splinter"}', '{"x": 610, "y": 727}', '{"damage": "3d8 piercing", "range": "20m line", "piercing": "true"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('89547abc-0002-43e8-b62a-97d025281cda', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_skeletal_repair', 'İskelet Onarımı', 'Skeletal Repair', 'Karanlık büyüye odaklanarak bir alandaki ölümsüz minyonlarını iyileştirir.', 'Channel dark magic to heal your undead minions in an area.', 'Skeleton', 28, 220, 2, '{"nc_raise_skeleton_archer", "nc_undead_frenzy"}', '{"x": 1039, "y": -599}', '{"heal": "3d8", "radius": "10m", "cooldown": "30s"}', '🔧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fbdb5909-5ec5-49f1-947e-6f9dd388abcc', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_wall', 'Kemik Duvar', 'Bone Wall', 'Yolları kapatmak veya müttefikleri korumak için yerden sağlam bir kemik duvar çıkartır.', 'Erupt a solid wall of bone from the ground to block paths or protect allies.', 'Bone', 30, 240, 2, '{"nc_bone_spear", "nc_calcify"}', '{"x": 771, "y": 919}', '{"length": "6m", "health": "50 HP", "duration": "30s"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('001f6ddd-0d72-4067-bc99-d20ccf14011a', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_blight', 'Solgunluk', 'Blight', 'Zemini yozlaştırarak, içindeki düşmanların nekrotik hasar almasına ve iyileşme etkilerinin azalmasına neden olur.', 'Corrupt a patch of ground, causing enemies within to take necrotic damage and lose healing effectiveness.', 'Plague', 32, 260, 2, '{"nc_corpse_explosion", "nc_weaken"}', '{"x": -771, "y": 919}', '{"damage": "2d6 necrotic/sec", "healing_reduction": "50%", "radius": "8m"}', '🤢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('27f62b30-05e5-4d00-affd-23c787e8d66f', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_plague_zombies', 'Veba Zombileri', 'Plague Zombies', 'İskeletler yerine şişkin veba zombileri diriltir. Yavaş hareket ederler ancak öldüklerinde zehir bulutu yayarak patlarlar.', 'Raise bloated plague zombies instead of skeletons. They move slowly but explode in a poison cloud upon death.', 'Cross-Branch', 34, 280, 2, '{"nc_raise_skeleton_warrior", "nc_corpse_explosion"}', '{"x": -173, "y": -100}', '{"summons": "2 Plague Zombies", "death_explosion": "3d6 poison, 4m radius"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8db44dca-530f-417a-a2dd-7f1e3790ca79', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_skeleton_vanguard', 'İskelet Öncüsü', 'Skeleton Vanguard', 'İskelet savaşçılara saldırıları bloklama ve düşmanları kışkırtma şansı veren pasif yetenek.', 'Passively grants skeleton warriors a chance to block attacks and briefly taunt enemies.', 'Skeleton', 35, 280, 2, '{"nc_skeletal_repair"}', '{"x": 1255, "y": -724}', '{"block_chance": "15%", "taunt_duration": "3s"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e6900ebb-8d50-4fae-a59a-0a5b13fb3dd1', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_marrow_extraction', 'İlik Çekimi', 'Marrow Extraction', 'Bir hedefin kemiklerinden yaşam özünü söküp alarak hasar verir ve kendini iyileştirir.', 'Rip the life essence from a target''s bones, dealing damage and healing yourself.', 'Bone', 38, 290, 2, '{"nc_bone_wall"}', '{"x": 932, "y": 1110}', '{"damage": "2d6 necrotic", "heal": "100% of damage", "range": "10m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('726f9652-5939-47fc-a071-afd789862092', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_plague_bearer', 'Veba Taşıyıcısı', 'Plague Bearer', 'Bir hedefe ölümcül bir veba bulaştırır. Ölürlerse, veba yakındaki düşmanlara yayılır.', 'Infect a target with a virulent plague. If they die, the plague spreads to nearby enemies.', 'Plague', 39, 300, 2, '{"nc_blight"}', '{"x": -932, "y": 1110}', '{"damage": "2d8 poison/sec", "spread_radius": "5m", "duration": "8s"}', '🐀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f2010c52-c033-432d-b14e-3a4b4fbc826c', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_archers', 'Kemik Okçular', 'Bone Archers', 'İskelet okçularını, birden fazla düşmanı delip geçen kemik mızraklar fırlatacak şekilde geliştirir.', 'Upgrade your skeleton archers to fire bone spears that pierce through multiple enemies.', 'Cross-Branch', 40, 320, 2, '{"nc_raise_skeleton_archer", "nc_bone_spear"}', '{"x": -389, "y": -225}', '{"projectile": "Bone Spear", "pierce": "true", "damage_bonus": "+2d8"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6f6354a6-81cd-49d4-a870-02287f6bbed1', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_raise_skeleton_mage', 'İskelet Büyücü Dirilt', 'Raise Skeleton Mage', 'Uzaktan nekrotik mermiler fırlatan bir iskelet büyücü çağırır.', 'Summons a skeleton mage that casts necrotic bolts from afar.', 'Skeleton', 42, 380, 3, '{"nc_raise_skeleton_archer"}', '{"x": 1472, "y": -849}', '{"summons": "1 Skeleton Mage", "damage": "2d6 necrotic", "range": "20m"}', '🧙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e3a3e940-7c47-443a-8e29-054f1b8b02fd', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_prison', 'Kemik Hapishanesi', 'Bone Prison', 'Tek bir hedefi kemikten dairesel bir kafese hapsederek tuzağa düşürür.', 'Encase a single target in a circular cage of bone, trapping them.', 'Bone', 45, 390, 3, '{"nc_bone_wall"}', '{"x": 1092, "y": 1302}', '{"health": "80 HP", "radius": "2m", "duration": "15s"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('12021b5c-ce59-459b-8f03-a29d322c91ea', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_decrepify', 'Yıpratma', 'Decrepify', 'Düşmanları büyük ölçüde yavaşlatan ve saldırı hızlarını düşüren zayıflatıcı bir lanet.', 'A debilitating curse that drastically slows enemies and reduces their attack speed.', 'Plague', 46, 380, 3, '{"nc_blight"}', '{"x": -1092, "y": 1302}', '{"movement_slow": "40%", "attack_speed_reduction": "30%", "radius": "10m"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f792976b-7c4c-410c-8501-abb22f21f062', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_command', 'Kemik Komutası', 'Bone Command', 'Tüm minyonlarının tek bir hedefe saldırmasını sağlayarak onlara bonus hasar kazandırır.', 'Focus all your minions to attack a single target, granting them bonus damage.', 'Skeleton', 48, 420, 3, '{"nc_raise_skeleton_mage", "nc_skeleton_vanguard"}', '{"x": 1688, "y": -974}', '{"damage_bonus": "+40%", "duration": "8s", "range": "20m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c35ccee5-a50d-4966-8327-f9c3bac0efbe', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_noxious_eruption', 'Zehirli Patlama', 'Noxious Eruption', 'Enfekte olmuş bir hedefin şiddetle patlayarak etrafındaki her şeye zehir hasarı vermesini sağlar.', 'Cause an infected target to violently erupt, dealing poison damage to everything around them.', 'Plague', 50, 430, 3, '{"nc_decrepify", "nc_plague_bearer"}', '{"x": -1253, "y": 1493}', '{"damage": "5d8 poison", "radius": "6m", "removes_infection": "true"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('865edd22-df65-4b67-9bf8-d82136b7d41b', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_spirit', 'Kemik Ruhu', 'Bone Spirit', 'Hedefe güdümlü giden ve patlayan intikamcı bir kemik ruhu serbest bırakır.', 'Release a vengeful spirit of bone that homes in on a target and explodes.', 'Bone', 52, 440, 3, '{"nc_bone_prison", "nc_marrow_extraction"}', '{"x": 1253, "y": 1493}', '{"damage": "4d10 necrotic", "radius": "4m", "range": "25m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('15448128-4beb-409d-a046-2dd612a5cb18', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_corrosive_marrow', 'Aşındırıcı İlik', 'Corrosive Marrow', 'Kemik büyülerin artık zırhı eriten ve zamanla hasar veren aşındırıcı bir asit izi bırakır.', 'Your bone spells now leave behind a trail of corrosive acid that melts armor and deals damage over time.', 'Cross-Branch', 54, 460, 3, '{"nc_bone_spirit", "nc_noxious_eruption"}', '{"x": -606, "y": -350}', '{"acid_damage": "2d6/sec", "armor_reduction": "-3", "duration": "5s"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b51860b8-f87c-4a24-a40d-b339cabf28fe', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_undead_swarm', 'Ölümsüz Sürüsü', 'Undead Swarm', 'Düşmanın üzerine çullanıp onları alt eden geçici ve kırılgan iskeletler anında çağırır.', 'Instantly summon multiple temporary fragile skeletons that rush and overwhelm the enemy.', 'Skeleton', 55, 480, 3, '{"nc_bone_command"}', '{"x": 1905, "y": -1099}', '{"summons": "5 Swarm Skeletons", "duration": "15s", "damage": "1d4 each"}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46a2c995-8b7a-4883-a5da-d1726ae43777', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_splintering_shield', 'Parçalanan Kalkan', 'Splintering Shield', 'Kemik Zırhın yok edildiğinde kıymıklara ayrılarak yakındaki düşmanlara hasar verir.', 'Your Bone Armor now explodes into splinters when destroyed, damaging nearby enemies.', 'Bone', 58, 490, 3, '{"nc_bone_spirit"}', '{"x": 1414, "y": 1685}', '{"damage": "3d6 piercing", "radius": "5m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('38457a29-d9ce-45dc-8de4-00567e6939b6', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_wither', 'Kurutma', 'Wither', 'Bir hedefi hızla yaşlandırarak uzun dinlenmeye kadar maksimum sağlığını ve zırhını kalıcı olarak düşürür.', 'Rapidly age a target, reducing their maximum health and armor permanently until a long rest.', 'Plague', 59, 490, 3, '{"nc_noxious_eruption"}', '{"x": -1414, "y": 1685}', '{"max_health_reduction": "15%", "armor_reduction": "2", "duration": "Until Rest"}', '🍂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d06b6b7-03fb-4453-ab70-432f4eee2da4', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_skeletal_siege_engine', 'İskelet Kuşatma Makinesi', 'Skeletal Siege Engine', 'İskeletler tarafından kullanılan ve uzaktan bölgeleri bombalayan devasa kemik bir mancınık inşa eder.', 'Construct a massive catapult made of bone, manned by skeletons, to bombard areas from afar.', 'Cross-Branch', 60, 500, 3, '{"nc_bone_prison", "nc_undead_swarm"}', '{"x": -822, "y": -475}', '{"summons": "1 Siege Engine", "range": "50m", "damage": "6d10 bludgeoning/necrotic", "radius": "8m"}', '⚙️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5de87407-111c-4433-bd1a-1109c7da79d1', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_storm', 'Kemik Fırtınası', 'Bone Storm', 'Etrafında girdap gibi dönen kemik parçalarından oluşan, düşmanlara hasar veren ve onları yaralayan bir fırtına yaratır.', 'Create a vortex of swirling bone fragments around you, damaging and lacerating enemies.', 'Bone', 62, 620, 4, '{"nc_bone_spirit"}', '{"x": 1574, "y": 1876}', '{"damage": "4d6 slashing/sec", "radius": "8m", "duration": "10s"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('69d0a5c7-fbad-4b01-8761-5cab701216aa', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_epidemic', 'Salgın', 'Epidemic', 'Devasa bir hastalık dalgası salar. Büyük bir alandaki tüm düşmanlara en güçlü zehrini bulaştırır.', 'Unleash a massive wave of disease. All enemies in a huge area become infected with your strongest poison.', 'Plague', 64, 640, 4, '{"nc_decrepify"}', '{"x": -1574, "y": 1876}', '{"radius": "30m", "damage": "3d8 poison/sec", "duration": "10s"}', '🟢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('91900b31-b448-4ceb-84fc-093ad847ad72', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_raise_skeletal_behemoth', 'İskelet Dev Dirilt', 'Raise Skeletal Behemoth', 'Devasa bir iskelet canavar diriltmek için birden fazla cesedi tüketir.', 'Consume multiple corpses to raise a massive skeletal brute.', 'Skeleton', 65, 650, 4, '{"nc_raise_skeleton_mage"}', '{"x": 2121, "y": -1224}', '{"summons": "1 Skeletal Behemoth", "health": "150 HP", "damage": "3d10 physical"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74697b95-3470-44d2-b5f3-47b41bb529d6', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_prison_of_the_damned', 'Lanetliler Hapishanesi', 'Prison of the Damned', 'Kemik hapishanende mahsur kalan düşmanlar, onları aşağı çeken iskelet eller tarafından sürekli saldırıya uğrar.', 'Enemies trapped in your bone prison are continuously attacked by skeletal hands dragging them down.', 'Cross-Branch', 66, 680, 4, '{"nc_bone_prison", "nc_raise_skeletal_behemoth"}', '{"x": -1039, "y": -600}', '{"damage": "3d8 slashing/sec", "root": "true", "radius": "3m"}', '🪦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eff9455b-0234-4013-aaf0-6ce9c43664c7', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_ossified_carapace', 'Kemikleşmiş Kabuk', 'Ossified Carapace', 'Bir müttefiki veya kendini delinmez bir kemik kabukla kaplayarak dokunulmazlık verir, ancak hedefi sersemletir.', 'Encase an ally or yourself in an impenetrable bone shell, granting immunity but stunning the target.', 'Bone', 68, 700, 4, '{"nc_bone_storm", "nc_splintering_shield"}', '{"x": 1735, "y": 2068}', '{"invulnerability": "true", "stun": "true", "duration": "4s"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('39b37c0f-1f78-418c-b8a7-8554d41c6e86', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_legions_vigor', 'Lejyonun Kudreti', 'Legion''s Vigor', 'Ölümsüz minyonlarının sağlığını sürekli olarak yenileyen bir aura kazandırır.', 'Grants an aura that constantly regenerates the health of your undead minions.', 'Skeleton', 70, 720, 4, '{"nc_raise_skeletal_behemoth", "nc_undead_swarm"}', '{"x": 2338, "y": -1349}', '{"regeneration": "5 HP/s", "radius": "15m"}', '❤️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fcc6cd80-44ac-4b1b-a781-66936b019ee9', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_soul_rot', 'Ruh Çürümesi', 'Soul Rot', 'Hedefin ruhunu yozlaştırarak susturur ve yaşamını emer.', 'Corrupts the target''s very soul, silencing them and draining their life.', 'Plague', 72, 730, 4, '{"nc_epidemic", "nc_wither"}', '{"x": -1735, "y": 2068}', '{"silence": "true", "damage": "4d10 necrotic/sec", "duration": "4s"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6e611021-3a44-45b9-abcd-debcbec3092a', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_skeletal_amalgamation', 'İskelet Birleşimi', 'Skeletal Amalgamation', 'İki iskeleti feda ederek onları gelişmiş yeteneklere sahip korkunç bir kemik yapıya dönüştürür.', 'Sacrifice two skeletons to merge them into a horrific bone construct with enhanced abilities.', 'Skeleton', 75, 800, 4, '{"nc_legions_vigor"}', '{"x": 2554, "y": -1474}', '{"sacrifice": "2 Minions", "stats_multiplier": "2.5x", "duration": "Infinite"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('341bc1f4-060d-40f3-ad99-c0ab33c05ccb', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_aura_of_decay', 'Çürüme Aurası', 'Aura of Decay', 'Etrafındaki ölümsüz olmayan varlıkların sağlığını sürekli çürüten bir aura yayarsın.', 'You emit an aura that constantly rots away the health of non-undead entities around you.', 'Plague', 76, 820, 4, '{"nc_soul_rot"}', '{"x": -1896, "y": 2259}', '{"damage": "3d6 necrotic/sec", "radius": "10m", "toggle": "true"}', '☢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('76013dbd-ecc4-45d1-b7ec-c8d0f757d0e1', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_bone_crush', 'Kemik Kırma', 'Bone Crush', 'Bir düşmanın kemiklerine şiddetle sıkışmalarını emrederek devasa hasar verir ve sakatlanmalarına neden olur.', 'Command the bones of an enemy to violently compress, dealing massive damage and causing crippling.', 'Bone', 78, 850, 4, '{"nc_ossified_carapace"}', '{"x": 1896, "y": 2259}', '{"damage": "8d8 bludgeoning", "cripple": "50% slow", "duration": "5s"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('54b90e09-9cdc-4e5e-ad2a-f1df0bcc28ef', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_miasma_golem', 'Miasma Golemi', 'Miasma Golem', 'Ölümcül bir miasma yayan, kemik ve çürüyen etten oluşan korkutucu bir golem inşa eder.', 'Construct a terrifying golem of bone and rotting flesh that exudes a deadly miasma.', 'Cross-Branch', 80, 880, 4, '{"nc_epidemic", "nc_bone_crush", "nc_skeletal_amalgamation"}', '{"x": -1255, "y": -725}', '{"summons": "1 Miasma Golem", "health": "300 HP", "aura_damage": "4d6 poison/sec", "aura_radius": "8m"}', '🧌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d0e3f3f1-8ae1-4a4f-9959-f591d2351c41', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_fortress_of_bones', 'Kemik Kalesi', 'Fortress of Bones', 'Topraktan savunma kalesi olarak hizmet edecek, tamamen kemikten oluşan bir yapı yükseltir.', 'Raise an entire fortress structure of bone from the earth to serve as a defensive stronghold.', 'Bone', 82, 1050, 5, '{"nc_bone_crush"}', '{"x": 2056, "y": 2451}', '{"structure_health": "500 HP", "size": "15x15m", "duration": "10 minutes"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9316f476-f2e1-4c48-96f9-566024bf7f32', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_army_of_the_dead', 'Ölüler Ordusu', 'Army of the Dead', 'Cesetlere ihtiyaç duymadan topraktan geçici devasa bir iskelet ordusu diriltir.', 'Raise a temporary massive army of skeletons from the ground, regardless of corpses.', 'Skeleton', 85, 1100, 5, '{"nc_skeletal_amalgamation"}', '{"x": 2771, "y": -1599}', '{"summons": "12 Skeletons", "duration": "30s", "radius": "20m"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9849b571-5d73-4474-9623-257937a76c06', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_cloud_of_death', 'Ölüm Bulutu', 'Cloud of Death', 'İçindeki her şeyi yok eden saf nekrotik enerjiden oluşan devasa, yavaş hareket eden bir bulut çağırır.', 'Summon a massive, slow-moving cloud of pure necrotic energy that annihilates everything inside.', 'Plague', 88, 1150, 5, '{"nc_aura_of_decay"}', '{"x": -2056, "y": 2451}', '{"damage": "10d10 necrotic/sec", "radius": "15m", "speed": "2m/s", "duration": "15s"}', '☁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81ca7cda-5b8b-4873-bb77-33a6feb72d4b', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_death_knight', 'Ölüm Şövalyesi', 'Death Knight', 'Kemik zırhı ve veba aşılanmış silahları olan elit bir ölümsüz şampiyon olan Ölüm Şövalyesi''ni çağırır.', 'Summon a Death Knight, an elite undead champion wielding bone armor and plague-infused weapons.', 'Cross-Branch', 90, 1200, 5, '{"nc_army_of_the_dead", "nc_fortress_of_bones", "nc_cloud_of_death"}', '{"x": -1472, "y": -850}', '{"summons": "1 Death Knight", "health": "500 HP", "damage": "6d10", "aura": "Provides buffs to allies"}', '🏇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b478a4a9-e304-4aee-8f2e-2ead1eabbb87', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_avatar_of_marrow_ultimate', 'ULTIMATE: İlik Avatarı', 'ULTIMATE: Avatar of Marrow', 'Saf kemikten devasa bir varlığa dönüşerek devasa zırh, sağlık ve yakın dövüş hasarı kazanırsın.', 'Transform into a towering entity of pure bone, gaining immense armor, health, and melee damage.', 'Bone', 92, 1450, 5, '{"nc_fortress_of_bones"}', '{"x": 2217, "y": 2642}', '{"health_bonus": "+200", "armor_bonus": "+20", "melee_damage": "4d12", "duration": "1 minute"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29f8bc40-b138-43c0-b002-3a7ba7f9b3f5', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_lord_of_skulls_ultimate', 'ULTIMATE: Kafatasları Efendisi', 'ULTIMATE: Lord of Skulls', 'Kafatasları Efendisi olarak çağrılarını kısa süreliğine ölümsüz yapar ve çağrı sınırını devasa oranda artırırsın.', 'Become the Lord of Skulls, making your summons immortal for a duration and massively increasing your summon limit.', 'Skeleton', 95, 1400, 5, '{"nc_army_of_the_dead"}', '{"x": 2987, "y": -1724}', '{"immortality_duration": "15s", "summon_limit": "+10", "bonus_damage": "+100%"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0c53396-22bb-4c6c-8bd2-4581f0a5be46', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_harbinger_of_pestilence_ultimate', 'ULTIMATE: Veba Habercisi', 'ULTIMATE: Harbinger of Pestilence', 'Vebanın vücut bulmuş hali olursun. Büyülerin karşı konulamaz çürüme uygular ve verilen tüm nekrotik hasardan iyileşirsin.', 'Become the embodiment of plague. Your spells apply irresistible rot, and you heal from all necrotic damage dealt.', 'Plague', 96, 1480, 5, '{"nc_cloud_of_death"}', '{"x": -2217, "y": 2642}', '{"rot_damage": "5d10/sec", "lifesteal": "100%", "duration": "30s"}', '🪰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a3ffd66-6b9d-4ee2-8b80-e3e3632979f5', 'a9dd4af5-b3dc-4bef-a8ab-884bec3486ab', 'nc_ascendance_of_the_lich_king_ultimate', 'GRAND ULTIMATE: Lich Kralının Yükselişi', 'GRAND ULTIMATE: Ascendance of the Lich King', 'Lich Kralı olarak yükselirsin. Devasa bir ölüm aurası, sınırsız çağrı, delinmez zırh ve ölüm dokunuşu kazanırsın.', 'Ascend to become the Lich King. You gain a massive aura of death, unlimited summons, impenetrable armor, and touch of death.', 'Cross-Branch', 100, 2000, 5, '{"nc_lord_of_skulls_ultimate", "nc_avatar_of_marrow_ultimate", "nc_harbinger_of_pestilence_ultimate"}', '{"x": -1688, "y": -975}', '{"summon_limit": "Infinite", "armor": "+50", "death_aura": "50m radius, 10d10 necrotic/sec", "duration": "1 minute"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e313cac6-b1e1-4a8d-8f54-ae8fd37280bb', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_creeping_dread', 'Sürünen Dehşet', 'Creeping Dread', 'Hedefe yayılan bir dehşet hissi aşılayarak, hareket hızlarını 3m ve saldırı zarlarını 3 tur boyunca 1d4 düşürür.', 'Instills a creeping sense of dread in a target, reducing their movement speed by 3m and attack rolls by 1d4 for 3 turns.', 'Fear', 3, 60, 1, '{}', '{"x": 173, "y": -99}', '{"range": "15m", "duration": "3 turns", "speed_reduction": "3m", "attack_penalty": "-1d4"}', '🕷️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca10c796-2cec-49be-a4b8-0e5f59e7a301', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_spook', 'Ürkütme', 'Spook', 'Hedefi 1 tur boyunca sizden tam hızla uzaklaşmaya zorlayan ani bir korkutma.', 'A sudden scare that forces a target to move away from you at full speed for 1 turn.', 'Fear', 7, 80, 1, '{}', '{"x": 389, "y": -224}', '{"range": "10m", "fear": "1 turn"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9380391-7305-4729-b0f3-41f22496c438', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_paranoid_whispers', 'Paranoyak Fısıltılar', 'Paranoid Whispers', 'Hedefin zihnini paranoyak fısıltılarla doldurur. Sizin yerinize bir müttefiğe saldırma ihtimalleri 2 tur boyunca %25''tir.', 'Fills the target''s mind with paranoid whispers. They have a 25% chance to attack an ally instead of you for 2 turns.', 'Fear', 12, 110, 1, '{}', '{"x": 606, "y": -349}', '{"range": "20m", "duration": "2 turns", "misdirection_chance": "25%"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b75b5687-1d85-4b40-9e13-043d197bb9b6', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_sudden_fright', 'Ani Korku', 'Sudden Fright', '3d6 psişik hasar verir ve hedefi saf korkudan dolayı 1 tur boyunca olduğu yere sabitler.', 'Deals 3d6 psychic damage and roots the target in place out of pure fear for 1 turn.', 'Fear', 22, 180, 2, '{"ns_creeping_dread", "ns_spook"}', '{"x": 822, "y": -474}', '{"range": "15m", "damage": "3d6", "root": "1 turn"}', '🙀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('65fe7598-91d5-4bb5-bb35-4610173684b0', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_aura_of_unease', 'Huzursuzluk Aurası', 'Aura of Unease', '8 metre içindeki tüm düşmanların savunmasını 2 ve direncini %10 azaltan bir aura yayarsınız.', 'Radiate an aura that reduces the defense by 2 and resistance by 10% of all enemies within 8 meters.', 'Fear', 28, 220, 2, '{"ns_spook"}', '{"x": 1039, "y": -599}', '{"radius": "8m", "defense_penalty": "-2", "resistance_penalty": "-10%"}', '〰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf9b5872-8782-42a8-a6a0-743d40e7181e', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_hallucination', 'Halüsinasyon', 'Hallucination', 'Hedefin korkunç halüsinasyonlar görmesine neden olarak, 2 tur boyunca saldırılarını %50 ıskalamalarını sağlar.', 'Causes the target to see horrifying hallucinations, making them miss 50% of their attacks for 2 turns.', 'Fear', 35, 270, 2, '{"ns_paranoid_whispers"}', '{"x": 1255, "y": -724}', '{"range": "20m", "duration": "2 turns", "miss_chance": "50%"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9314be68-2a71-4441-be38-76b6a62b3a78', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_panic_attack', 'Panik Atak', 'Panic Attack', 'Hedef şiddetli bir panik atak geçirir, 5d6 psişik hasar alır ve silahlarını 1 tur boyunca düşürür.', 'The target suffers a severe panic attack, taking 5d6 psychic damage and dropping their weapons for 1 turn.', 'Fear', 42, 360, 3, '{"ns_sudden_fright"}', '{"x": 1472, "y": -849}', '{"range": "15m", "damage": "5d6", "disarm": "1 turn"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('001bc785-92d7-4fe9-8e4b-e5fdc08ee017', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_phobia_manifestation', 'Fobi Tezahürü', 'Phobia Manifestation', 'Hedefin en derin fobisini tezahür ettirir. 4d8 psişik hasar alırlar ve 2 tur boyunca korkutulurlar.', 'Manifests the target''s deepest phobia. They take 4d8 psychic damage and are feared for 2 turns.', 'Fear', 48, 410, 3, '{"ns_aura_of_unease", "ns_hallucination"}', '{"x": 1688, "y": -974}', '{"range": "15m", "damage": "4d8", "fear": "2 turns"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c541521b-cdd2-446f-9a75-878dd32881dc', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_fear_toxin', 'Korku Toksini', 'Fear Toxin', '6m yarıçapında bir gaz bulutu salar. İçindeki düşmanlar tur başına 2d8 zehir hasarı alır ve 3 tur boyunca aşırı paranoyaya yakalanır.', 'Releases a 6m radius gas cloud. Enemies inside take 2d8 poison damage per turn and are afflicted with extreme paranoia for 3 turns.', 'Fear', 55, 460, 3, '{"ns_hallucination"}', '{"x": 1905, "y": -1099}', '{"range": "10m", "radius": "6m", "poison_damage": "2d8/turn", "duration": "3 turns"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e8c301a6-a993-40c9-8773-7fb98039c43b', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_mass_hysteria', 'Kitlesel Histeri', 'Mass Hysteria', 'En fazla 5 hedefe histeri bulaştırır. 6d8 psişik hasar alırlar ve 2 tur boyunca rastgele koşarlar.', 'Infects up to 5 targets with hysteria. They take 6d8 psychic damage and run randomly for 2 turns.', 'Fear', 62, 620, 4, '{"ns_panic_attack", "ns_fear_toxin"}', '{"x": 2121, "y": -1224}', '{"range": "20m", "targets": 5, "damage": "6d8", "fear": "2 turns"}', '😵‍💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f17dfea5-1aaa-427e-b16c-ec0574194e01', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_heart_stopping_gaze', 'Kalp Durduran Bakış', 'Heart-Stopping Gaze', 'Kalbi durduracak kadar korkunç bir bakış. 8d10 psişik hasar verir ve patron olmayan hedefleri %10 ihtimalle anında öldürür.', 'A gaze so terrifying it can stop a heart. Deals 8d10 psychic damage and has a 10% chance to instakill non-boss targets.', 'Fear', 70, 750, 4, '{"ns_phobia_manifestation"}', '{"x": 2338, "y": -1349}', '{"range": "15m", "damage": "8d10", "instakill_chance": "10%"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f08f44fb-38e3-4691-9a5d-06c31eaf7b7c', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_shatter_courage', 'Cesaret Kırma', 'Shatter Courage', 'Hedefin iradesini kalıcı olarak azaltır ve korku etkilerine karşı bağışıklıklarını ortadan kaldırır. 6d10 psişik hasar verir.', 'Permanently reduces the target''s willpower and removes their immunity to fear effects. Deals 6d10 psychic damage.', 'Fear', 76, 820, 4, '{"ns_phobia_manifestation"}', '{"x": 2554, "y": -1474}', '{"range": "15m", "damage": "6d10", "remove_immunity": "fear", "duration": "permanent"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e363d1d-a9dc-4cfe-8d72-89d6da76e2fb', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_endless_dread', 'Sonsuz Dehşet', 'Endless Dread', 'Hedefi sonsuz bir dehşet döngüsüne hapseder, 4 tur boyunca 10d10 psişik hasar verir ve onları felç eder.', 'Traps the target in an endless cycle of dread, dealing 10d10 psychic damage over 4 turns and paralyzing them.', 'Fear', 85, 1100, 5, '{"ns_mass_hysteria", "ns_shatter_courage"}', '{"x": 2771, "y": -1599}', '{"range": "20m", "damage": "10d10 over 4 turns", "paralysis": "4 turns"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90565c44-d3d6-4a21-8c0f-037ca76a9b51', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_avatar_of_fear', 'Korku Avatarı', 'Avatar of Fear', '3 tur boyunca Korku Avatarına dönüşün. Hasara karşı bağışıksınız ve size bakan düşmanlar 8d10 psişik hasar alıp kaçarlar.', 'Transform into the Avatar of Fear for 3 turns. You are immune to damage, and enemies that look at you take 8d10 psychic damage and flee.', 'Fear', 92, 1350, 5, '{"ns_heart_stopping_gaze", "ns_endless_dread"}', '{"x": 2987, "y": -1724}', '{"duration": "3 turns", "immunity": "all", "aura_damage": "8d10", "aura_fear": "true"}', '👿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5589a64a-7d68-4d5e-a12f-dae8a27bafd9', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_drowsy_dust', 'Uyku Tozu', 'Drowsy Dust', 'Hedefin yüzüne sihirli bir toz üfleyerek onları uykulu hale getirir. 2 tur boyunca eylem puanlarını 1 azaltır.', 'Blows magical dust into a target''s face, making them drowsy. Reduces their action points by 1 for 2 turns.', 'Dream', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "5m", "duration": "2 turns", "ap_reduction": 1}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd68d33a-092d-486e-b76e-0e8d3c62b10c', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_lucid_strike', 'Berrak Vuruş', 'Lucid Strike', 'Rüya büyüsüyle aşılanmış bir vuruş. 2d6 psişik hasar verir ve fiziksel zırhı yok sayar.', 'A strike infused with dream magic. Deals 2d6 psychic damage and ignores physical armor.', 'Dream', 6, 75, 1, '{}', '{"x": 289, "y": 344}', '{"range": "Melee", "damage": "2d6", "ignore_armor": "true"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('82330e50-a875-410e-86bf-28e4e11b1ee3', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_dream_whisper', 'Rüya Fısıltısı', 'Dream Whisper', 'Uyuyan bir hedefin zihnine fısıldayarak bilgi çıkarır veya 24 saatliğine bir telkin yerleştirir.', 'Whispers into a sleeping target''s mind to extract information or implant a suggestion for 24 hours.', 'Dream', 14, 120, 1, '{}', '{"x": 449, "y": 536}', '{"range": "Touch", "duration": "24 hours", "utility": "true"}', '💭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('97dc53a9-d07e-457f-abe0-8df97589317d', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_slumber_hex', 'Uyku Laneti', 'Slumber Hex', 'Bir hedefi 2 tur boyunca derin bir uykuya dalması için lanetler. Alınan herhangi bir hasar uykuyu bozar.', 'Curses a target to fall into a deep sleep for 2 turns. Any damage taken breaks the sleep.', 'Dream', 21, 175, 2, '{"ns_drowsy_dust"}', '{"x": 610, "y": 727}', '{"range": "15m", "sleep": "2 turns", "breaks_on_damage": "true"}', '💤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0fc46535-6ca7-4f7d-8064-8a763672be95', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_somnambulism', 'Uyurgezerlik', 'Somnambulism', 'Uyuyan bir hedefi uyurgezer olmaya ve seçtiğiniz bir düşmana temel bir saldırı yapmaya zorlar.', 'Forces a sleeping target to sleepwalk and perform a basic attack against an enemy of your choice.', 'Dream', 27, 215, 2, '{"ns_lucid_strike", "ns_dream_whisper"}', '{"x": 771, "y": 919}', '{"range": "20m", "control": "sleeping_target", "duration": "1 action"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9658e525-2f24-40ec-9545-2d8a1c97dffe', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_dream_walk', 'Rüya Yürüyüşü', 'Dream Walk', '15 metreye kadar başka bir konuma ışınlanmak için rüya diyarına adım atın. Duvarların içinden geçebilir.', 'Step into the dream realm to teleport up to 15 meters to another location. Can pass through walls.', 'Dream', 33, 260, 2, '{"ns_dream_whisper"}', '{"x": 932, "y": 1110}', '{"teleport": "15m", "bypass_walls": "true"}', '🚪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('994c1337-380d-4f83-b674-d7af943ec6eb', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_night_terrors', 'Gece Terörü', 'Night Terrors', 'Uyuyan bir hedefi kabuslarla rahatsız eder. Uyanmadan 6d6 psişik hasar alırlar.', 'Haunts a sleeping target with nightmares. They take 6d6 psychic damage without waking up.', 'Dream', 43, 370, 3, '{"ns_slumber_hex", "ns_somnambulism"}', '{"x": 1092, "y": 1302}', '{"range": "20m", "damage": "6d6", "does_not_wake": "true"}', '🛌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3fd8522-897e-4875-9418-55b5d5209fe2', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_sleep_paralysis', 'Uyku Felci', 'Sleep Paralysis', 'Hedefi 2 tur boyunca uyku felcine hapseder. Uyanıktırlar, hareket edemezler ve tüm kaynaklardan iki kat hasar alırlar.', 'Traps the target in sleep paralysis for 2 turns. They are awake, cannot move, and take double damage from all sources.', 'Dream', 49, 420, 3, '{"ns_slumber_hex"}', '{"x": 1253, "y": 1493}', '{"range": "15m", "duration": "2 turns", "paralyze": "true", "damage_multiplier": "2x"}', '🚷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f11ac154-44f1-4b2c-a634-165e7fc18253', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_mind_invader', 'Zihin İstilacısı', 'Mind Invader', 'Bir hedefin zihnini istila edin. 3 tur boyunca onların gördüğünü görürsünüz ve Rüya büyülerini onlardan kaynaklanıyormuş gibi yapabilirsiniz.', 'Invade a target''s mind. For 3 turns, you see what they see and can cast Dream spells originating from them.', 'Dream', 56, 480, 3, '{"ns_somnambulism", "ns_dream_walk"}', '{"x": 1414, "y": 1685}', '{"range": "20m", "duration": "3 turns", "proxy_casting": "true"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2ab33040-0fb6-4bb3-8f16-333a6d932a66', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_comatose', 'Komatöz', 'Comatose', 'Hedefi 3 tur boyunca komatöz bir duruma sokar. Sadece bir büyü bozma veya sürenin bitmesi onları uyandırabilir.', 'Plunges the target into a comatose state for 3 turns. Only a dispel or the duration ending can wake them.', 'Dream', 64, 640, 4, '{"ns_night_terrors", "ns_sleep_paralysis"}', '{"x": 1574, "y": 1876}', '{"range": "15m", "sleep": "3 turns", "breaks_on_damage": "false"}', '🏥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('511a19c6-3388-4536-a898-48cba8d95b35', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_dream_eater', 'Rüya Yiyen', 'Dream Eater', 'Uyuyan bir hedefin rüyalarını yutarak 8d8 psişik hasar verir ve verilen hasarın %100''ü kadar kendinizi iyileştirirsiniz.', 'Devour the dreams of a sleeping target, dealing 8d8 psychic damage and healing yourself for 100% of the damage dealt.', 'Dream', 71, 760, 4, '{"ns_sleep_paralysis"}', '{"x": 1735, "y": 2068}', '{"range": "10m", "damage": "8d8", "lifesteal": "100%"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('abb57129-147d-422b-90ed-c4f17a27ba3d', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_illusionary_realm', 'İllüzyon Diyarı', 'Illusionary Realm', '15 metre yarıçapında bir rüya alanı yaratır. İçerdeki düşmanlar 1 tur sonra uykuya dalar ve içeride kaldıkları sürece uyumaya devam ederler. 4 tur sürer.', 'Creates a 15m radius field of dreams. Enemies inside fall asleep after 1 turn and stay asleep as long as they remain inside. Lasts 4 turns.', 'Dream', 77, 830, 4, '{"ns_mind_invader"}', '{"x": 1896, "y": 2259}', '{"range": "10m", "radius": "15m", "sleep_aura": "true", "duration": "4 turns"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('572714c3-9b12-4e48-92e6-43061fc3914f', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_eternal_slumber', 'Ebedi Uyku', 'Eternal Slumber', 'Hedef ebedi bir uykuya dalar. Güçlü bir yenileme büyüsü kullanılmadığı sürece ölü kabul edilirler. Patronlar direnir.', 'The target falls into an eternal slumber. They are considered dead unless a powerful restoration magic is used. Bosses resist.', 'Dream', 84, 1080, 5, '{"ns_comatose", "ns_dream_eater"}', '{"x": 2056, "y": 2451}', '{"range": "Touch", "instakill_sleep": "true", "boss_resist": "true"}', '⚰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f0de5b7a-1f03-48c1-b68d-16cf86dccb89', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_lord_of_dreams', 'Rüyaların Efendisi', 'Lord of Dreams', 'Rüya diyarının tam kontrolünü elinize alın. 30 metre içindeki tüm düşmanlar 3 tur boyunca uyur. Uyuyan hedeflere onları uyandırmadan özgürce saldırabilirsiniz.', 'Take complete control over the dream realm. All enemies in 30 meters fall asleep for 3 turns. You can freely attack sleeping targets without waking them.', 'Dream', 94, 1400, 5, '{"ns_illusionary_realm", "ns_eternal_slumber"}', '{"x": 2217, "y": 2642}', '{"radius": "30m", "sleep": "3 turns", "does_not_wake": "true", "duration": "3 turns"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e71fbaee-0073-4e0e-b460-c8f341ed5174', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_shadow_hound', 'Gölge Tazısı', 'Shadow Hound', 'Bir düşmana saldırması için bir Gölge Tazısı çağırır. 1d8 kesici ve 1d6 nekrotik hasar verir.', 'Summons a Shadow Hound to attack an enemy. Deals 1d8 slashing and 1d6 necrotic damage.', 'Terror', 4, 65, 1, '{}', '{"x": -128, "y": 153}', '{"range": "10m", "damage": "1d8+1d6"}', '🐕‍🦺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0391a55c-0083-45e7-91ea-3fe1d0e04288', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_terror_strike', 'Terör Vuruşu', 'Terror Strike', '2d8 fiziksel hasar veren acımasız bir yakın dövüş saldırısı. Hedef korkmuşsa %50 daha fazla hasar verir.', 'A vicious melee strike that deals 2d8 physical damage. Deals 50% more damage if the target is frightened.', 'Terror', 8, 90, 1, '{}', '{"x": -289, "y": 344}', '{"range": "Melee", "damage": "2d8", "bonus_multiplier": "1.5x on fear"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fc02f457-9f2e-4b89-9561-baf46b474b54', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_predators_mark', 'Yırtıcı İşareti', 'Predator''s Mark', 'Bir hedefi 3 turluğuna işaretler. Onlara doğru hareket ederken 5m ekstra hareket hızı kazanırsınız ve fiziksel zırhlarını yok sayarsınız.', 'Marks a target for 3 turns. You gain 5m extra movement speed when moving toward them and ignore their physical armor.', 'Terror', 16, 130, 1, '{}', '{"x": -449, "y": 536}', '{"range": "20m", "duration": "3 turns", "bonus_speed": "5m", "ignore_armor": "true"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e40d00be-935e-4bac-9cf3-8b9d76cd2985', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_summon_nightmare', 'Kabus Çağırma', 'Summon Nightmare', '2 tur boyunca bir Kabus Atı çağırır. Düşmanlara hücum ederek 3d8 ezici hasar verir ve onları yere serer.', 'Summons a Nightmare Steed for 2 turns. It charges at enemies, dealing 3d8 bludgeoning damage and knocking them prone.', 'Terror', 24, 190, 2, '{"ns_shadow_hound"}', '{"x": -610, "y": 727}', '{"range": "15m", "summon": "nightmare", "damage": "3d8", "knockdown": "true", "duration": "2 turns"}', '🐎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce79a1f4-1180-4ccd-a7ef-67d54a2a8cfe', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_execute_the_weak', 'Zayıfları İnfaz Et', 'Execute the Weak', 'Uyuyan veya korkmuş patron olmayan bir hedefi sağlığı %25''in altındaysa anında öldürür. Aksi takdirde 4d8 hasar verir.', 'Instantly kills a sleeping or feared non-boss target if they are below 25% health. Otherwise, deals 4d8 damage.', 'Terror', 29, 230, 2, '{"ns_terror_strike", "ns_predators_mark"}', '{"x": -771, "y": 919}', '{"range": "Melee", "execute": "25%", "damage": "4d8"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('107efc36-8767-4200-8d6d-af7c7f630501', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_beast_claws', 'Canavar Pençeleri', 'Beast Claws', 'Elleriniz 3 turluğuna gölge pençelerine dönüşür. Yakın dövüş saldırıları fazladan 2d8 nekrotik hasar verir ve kanama uygular.', 'Your hands transform into shadow claws for 3 turns. Melee attacks deal an extra 2d8 necrotic damage and inflict bleed.', 'Terror', 36, 280, 2, '{"ns_terror_strike"}', '{"x": -932, "y": 1110}', '{"duration": "3 turns", "bonus_damage": "2d8", "bleed": "1d6/turn"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea20d29d-81da-4ae2-8ac7-c6aa1a1f1ef1', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_shadow_swarm', 'Gölge Sürüsü', 'Shadow Swarm', '10m''lik bir koni içindeki tüm düşmanlara 4d6 nekrotik hasar veren ve onları 1 tur kör eden gölge yarasaları sürüsü salar.', 'Releases a swarm of shadowy bats that deal 4d6 necrotic damage to all enemies in a 10m cone and blind them for 1 turn.', 'Terror', 44, 380, 3, '{"ns_summon_nightmare"}', '{"x": -1092, "y": 1302}', '{"aoe": "cone 10m", "damage": "4d6", "blind": "1 turn"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9a99cabd-574c-47ea-addd-20c908682e0c', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_feed_on_fear', 'Korkuyla Beslen', 'Feed on Fear', '15 metre içindeki düşmanların korkusunu tüketin. Korkutulmuş her düşman için 2d10 HP iyileşin ve 3 tur boyunca +2 saldırı hasarı kazanın.', 'Consume the fear of enemies within 15 meters. For each feared enemy, heal 2d10 HP and gain +2 attack damage for 3 turns.', 'Terror', 51, 430, 3, '{"ns_summon_nightmare", "ns_execute_the_weak"}', '{"x": -1253, "y": 1493}', '{"radius": "15m", "heal": "2d10/target", "buff": "+2 damage/target", "duration": "3 turns"}', '🍽️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d64847cc-ed35-4ebc-8c7d-366b139c49f9', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_terror_frenzy', 'Terör Çılgınlığı', 'Terror Frenzy', '2 tur boyunca çılgınlığa girersiniz. Her eylemde iki kez saldırırsınız ancak savunma yeteneklerini kullanamazsınız.', 'Enter a frenzy for 2 turns. You attack twice per action but cannot use defensive skills.', 'Terror', 58, 490, 3, '{"ns_beast_claws"}', '{"x": -1414, "y": 1685}', '{"duration": "2 turns", "double_attack": "true", "lock_defense": "true"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7ef6321b-6caa-4ace-9c57-278d444dc334', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_behemoth_of_the_dark', 'Karanlığın Behemotu', 'Behemoth of the Dark', '3 tur boyunca devasa bir Gölge Behemotu çağırır. 200 canı vardır ve saldırıları 6d10 hasar verir.', 'Summons a massive Shadow Behemoth for 3 turns. It has 200 HP and attacks deal 6d10 damage.', 'Terror', 66, 660, 4, '{"ns_shadow_swarm", "ns_feed_on_fear"}', '{"x": -1574, "y": 1876}', '{"duration": "3 turns", "summon": "behemoth", "summon_hp": 200, "summon_damage": "6d10"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f14ef87-3c22-4315-9e7f-a0a060c1910e', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_merciless_cull', 'Acımasız İtlaf', 'Merciless Cull', 'Bir hedefe doğru 15m''ye kadar sıçrayın. Eğer kitle kontrolü (korkmuş, uyuyan, felçli) altındalarsa, kritik vuruş olarak otomatik 10d8 fiziksel hasar verin.', 'Leap up to 15m to a target. If they are CC''d (feared, sleeping, paralyzed), deal 10d8 physical damage automatically as a critical hit.', 'Terror', 73, 780, 4, '{"ns_feed_on_fear", "ns_terror_frenzy"}', '{"x": -1735, "y": 2068}', '{"dash": "15m", "damage": "10d8", "auto_crit": "true on CC"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('88f88f7d-21d1-436a-8401-c23d5e523470', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_terror_nova', 'Terör Novası', 'Terror Nova', 'Korkunç gölge enerjisiyle patlayın. 10m içindeki düşmanlar 8d8 nekrotik hasar alır ve 5 metre geriye savrulurlar.', 'Explode with terrifying shadowy energy. Enemies within 10m take 8d8 necrotic damage and are knocked back 5 meters.', 'Terror', 79, 850, 4, '{"ns_terror_frenzy"}', '{"x": -1896, "y": 2259}', '{"radius": "10m", "damage": "8d8", "knockback": "5m"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b353c312-2090-4fc6-8c4e-a14d83a9b4e2', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_manifest_nightmare', 'Kabus Tezahürü', 'Manifest Nightmare', 'Hedefin en kötü kabusunu fiziksel gerçekliğe çekerek onlara 4 tur boyunca saldıran ve tur başına 6d12 hasar veren korkunç bir varlığa dönüştürür.', 'Pulls a target''s worst nightmare into physical reality as a monstrous entity that attacks them for 4 turns, dealing 6d12 damage per turn.', 'Terror', 86, 1120, 5, '{"ns_behemoth_of_the_dark", "ns_terror_nova"}', '{"x": -2056, "y": 2451}', '{"range": "20m", "duration": "4 turns", "summon": "nightmare_entity", "damage": "6d12/turn"}', '🦑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26675f49-497c-4870-ab2a-99e443d92607', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_harbinger_of_terror', 'Terör Müjdecisi', 'Harbinger of Terror', 'Nihai yırtıcı olun. 3 tur boyunca tüm saldırılarınız sağlığı %30''un altındaki hedeflerde anında infazdır ve hareket hızınız üç katına çıkar.', 'Become the ultimate predator. For 3 turns, all your attacks are instant executions on targets below 30% health, and your movement speed is tripled.', 'Terror', 96, 1450, 5, '{"ns_merciless_cull", "ns_manifest_nightmare"}', '{"x": -2217, "y": 2642}', '{"duration": "3 turns", "execute_threshold": "30%", "speed_multiplier": "3x"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5316d19c-9c58-4cf1-b81a-7c5b9f858093', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_frightening_slumber', 'Korkutucu Uyku', 'Frightening Slumber', 'Hedefi 2 tur boyunca uyumaya zorlar. Uyandıklarında dehşete düşerler ve 4d6 psişik hasar alırlar.', 'Forces the target to sleep for 2 turns. When they wake up, they are terrified and take 4d6 psychic damage.', 'Cross-Branch', 31, 250, 2, '{"ns_sudden_fright", "ns_slumber_hex"}', '{"x": -173, "y": -100}', '{"range": "15m", "sleep": "2 turns", "wakeup_damage": "4d6", "fear": "1 turn"}', '😱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49511a21-00d6-4fc9-9ecc-374230999c56', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_beast_of_the_mind', 'Zihin Canavarı', 'Beast of the Mind', 'Uyuyan bir hedefin rüyasında hayalet bir canavar yaratır. 6d8 psişik hasar verir ve onları çığlık atarak uyandırıp 1 tur susturur.', 'Spawns a phantom beast inside a sleeping target''s dream. It deals 6d8 psychic damage and wakes them up screaming, silencing them for 1 turn.', 'Cross-Branch', 53, 450, 3, '{"ns_night_terrors", "ns_shadow_swarm"}', '{"x": -389, "y": -225}', '{"range": "20m", "damage": "6d8", "wakes_target": "true", "silence": "1 turn"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('933a968e-f1a2-416f-899b-96208640f6e2', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_paralyzing_roar', 'Felç Edici Kükreme', 'Paralyzing Roar', 'Korkunç bir kükreme salın. 15m yarıçapındaki düşmanlar 5d6 sonik hasar alır ve 1 tur boyunca korkuyla felç olurlar.', 'Let out a monstrous roar. Enemies in a 15m radius take 5d6 sonic damage and are paralyzed with fear for 1 turn.', 'Cross-Branch', 59, 500, 3, '{"ns_panic_attack", "ns_terror_frenzy"}', '{"x": -606, "y": -350}', '{"radius": "15m", "damage": "5d6", "paralyze": "1 turn"}', '🦖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0674df89-3144-4d81-892d-0aeb26a2e61d', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_nightmare_execution', 'Kabus İnfazı', 'Nightmare Execution', 'Uyuyan bir hedefe anında ışınlanın ve 12d10 hasar verin. Eğer bu onları öldürürse, vücutları bir gölge novasına dönüşerek yakındaki düşmanlara 6d8 hasar verir.', 'Instantly teleport to a sleeping target and deal 12d10 damage. If this kills them, their body explodes into a shadow nova, dealing 6d8 damage to nearby enemies.', 'Cross-Branch', 74, 800, 4, '{"ns_comatose", "ns_merciless_cull"}', '{"x": -822, "y": -475}', '{"range": "30m", "teleport": "melee", "damage": "12d10", "on_kill_explosion": "6d8"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f51a3ca-4ab6-485f-900c-2c7f9c676799', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_aura_of_despair', 'Umutsuzluk Aurası', 'Aura of Despair', 'Saf bir umutsuzluk aurası yayın. 10m içindeki düşmanlar iyileşemez ve her turunuzun başında 4d8 psişik hasar alırlar.', 'Emit an aura of pure despair. Enemies within 10m cannot heal, and they take 4d8 psychic damage at the start of each of your turns.', 'Cross-Branch', 78, 880, 4, '{"ns_mass_hysteria", "ns_terror_nova"}', '{"x": -1039, "y": -600}', '{"radius": "10m", "heal_block": "true", "damage": "4d8/turn", "duration": "3 turns"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('404561ac-b0ce-43fc-b8f6-7b532e09b011', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_dream_devourer', 'Rüya Yokedici', 'Dream Devourer', 'Rüya diyarını tüketen devasa bir varlığı serbest bırakın. 20m içindeki tüm düşmanlar uykuya zorlanır ve kabusları sökülüp alındığı için anında 15d10 hasar alırlar.', 'Unleash a massive entity that consumes the dreamscape. All enemies in 20m are forced into sleep, and immediately take 15d10 damage as their nightmares are ripped out.', 'Cross-Branch', 88, 1200, 5, '{"ns_endless_dread", "ns_eternal_slumber", "ns_manifest_nightmare"}', '{"x": -1255, "y": -725}', '{"radius": "20m", "sleep": "1 turn", "damage": "15d10"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('326f9197-4edc-4405-a478-e5f40354d801', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_shadow_realm_ambush', 'Gölge Diyarı Pususu', 'Shadow Realm Ambush', 'Hedefi 2 tur boyunca gölge diyarına sürükleyin. Oradayken tüm korkuları tarafından saldırıya uğrarlar ve 20d8 psişik hasar alırlar, siz ise savaş alanından kaybolursunuz.', 'Drag the target into the shadow realm for 2 turns. While there, they are attacked by all their fears, taking 20d8 psychic damage, while you vanish from the battlefield.', 'Cross-Branch', 89, 1250, 5, '{"ns_endless_dread", "ns_eternal_slumber", "ns_manifest_nightmare"}', '{"x": -1472, "y": -850}', '{"range": "15m", "vanish": "2 turns", "banish": "2 turns", "damage": "20d8"}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e7461bb5-bc87-46ef-aec6-59dac68d86f4', '82fd6006-b419-4842-a601-cfd4a7eb95fb', 'ns_waking_nightmare', 'Uyanık Kabus', 'Waking Nightmare', 'Rüya diyarını gerçeklikle birleştirin. 5 tur boyunca tüm düşmanlar sürekli korkar, tur başına 10d10 hasar alır ve Gölge Canavarlarınız eylem puanı harcamadan anında çağrılır. Bir terör alanı genişlemesi.', 'Merge the dream realm with reality. For 5 turns, all enemies are constantly frightened, take 10d10 damage per turn, and your Shadow Beasts are summoned instantly without action cost. A domain expansion of terror.', 'Cross-Branch', 100, 1500, 5, '{"ns_avatar_of_fear", "ns_lord_of_dreams", "ns_harbinger_of_terror"}', '{"x": -1688, "y": -975}', '{"duration": "5 turns", "global_fear": "true", "damage": "10d10/turn", "free_summons": "true"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ec4e03d9-3216-49d4-bb26-6c7945f62390', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_shadow_step', 'Gölge Adımı', 'Shadow Step', '10m mesafeye kadar bir gölgeye ışınlanırsınız. 3 saniyeliğine görünmezlik kazandırır.', 'Teleport up to 10m into a shadow. Gain stealth for 3s.', 'Stealth', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "10m", "stealth_duration": "3s"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ddb79007-c6a5-4a27-8651-8b5c31590372', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_hidden_blade', 'Gizli Bıçak', 'Hidden Blade', 'Görünmezlikten yapılan ilk saldırınız fazladan 1d8 fiziksel hasar verir.', 'Your first attack from stealth deals an extra 1d8 physical damage.', 'Stealth', 5, 80, 1, '{"nj_stealth_shadow_step"}', '{"x": 389, "y": -224}', '{"damage": "1d8"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b877bb6-2c0b-4a19-b1ef-ac0e0f0a1b65', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_cloak', 'Gece Pelerini', 'Cloak of Night', '10 saniyeliğine tamamen görünmez olursunuz. Hareket hızı %20 artar.', 'Become fully invisible for 10s. Movement speed increased by 20%.', 'Stealth', 15, 120, 1, '{"nj_stealth_hidden_blade"}', '{"x": 606, "y": -349}', '{"duration": "10s", "speed_buff": "20%"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49f106cd-d48c-4ee8-ac78-dd36dc28924e', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_assassinate', 'Suikast', 'Assassinate', '3d6 hasar veren hassas bir vuruş. Görünmezlikten saldırırsanız kritik vuruş şansı iki katına çıkar.', 'A precision strike dealing 3d6 damage. Critical chance is doubled if attacking from stealth.', 'Stealth', 22, 200, 2, '{"nj_stealth_cloak"}', '{"x": 822, "y": -474}', '{"damage": "3d6", "crit_chance_multiplier": 2}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('331d5f47-bb73-4588-a404-43e586cf0454', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_blend', 'Gölge Karışımı', 'Shadow Blend', 'Pasif: Loş ışıkta doğal kamuflaj kazanarak düşman tespit yarıçapını 5m azaltırsınız.', 'Passive: Gain natural camouflage in dim light, reducing enemy detection radius by 5m.', 'Stealth', 28, 250, 2, '{"nj_stealth_assassinate"}', '{"x": 1039, "y": -599}', '{"stealth_buff": "5m"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55dc43ed-2169-4bab-aff8-48a76572e8d6', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_takedown', 'Sessiz İnfaz', 'Silent Takedown', '4d6 hasar veren ve hedefi 3 saniyeliğine susturan yakın dövüş saldırısı.', 'Melee strike dealing 4d6 damage and silencing the target for 3s.', 'Stealth', 35, 300, 2, '{"nj_stealth_blend"}', '{"x": 1255, "y": -724}', '{"damage": "4d6", "silence": "3s"}', '🤫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de8b6ff8-0342-4e4e-b778-3bbef60481a1', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_vanish', 'Gözden Kaybolma', 'Vanish', 'Anında hedef kilitlerini kırar, yakındaki düşmanları 2 saniye kör eder ve 8 saniye boyunca görünmez olursunuz.', 'Instantly break target locks, blind nearby enemies for 2s, and become invisible for 8s.', 'Stealth', 42, 400, 3, '{"nj_stealth_takedown"}', '{"x": 1472, "y": -849}', '{"blind_duration": "2s", "stealth_duration": "8s"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5625a9b6-9177-42ac-9074-e9be06a5a5b7', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_shadow_strike', 'Gölge Vuruşu', 'Shadow Strike', 'Bir hedefe 15m ışınlanarak 5d6 hasar vurursunuz ve 1.5 saniye sersemletirsiniz.', 'Teleport 15m to a target and strike for 5d6 damage, stunning them for 1.5s.', 'Stealth', 50, 450, 3, '{"nj_stealth_vanish"}', '{"x": 1688, "y": -974}', '{"range": "15m", "damage": "5d6", "stun": "1.5s"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('50ba6d05-2ea1-4006-ad2b-60ef345fbabb', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_phantom_step', 'Hayalet Adım', 'Phantom Step', 'Görünmezken 2m kalınlığa kadar katı engellerin içinden geçebilirsiniz. Süre 5s.', 'While stealthed, you can walk through solid obstacles up to 2m thick. Duration 5s.', 'Stealth', 58, 500, 3, '{"nj_stealth_shadow_strike"}', '{"x": 1905, "y": -1099}', '{"wall_thickness": "2m", "duration": "5s"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f7ab2344-683a-4c13-b5d2-82f530905beb', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_shadow_realm', 'Gölge Diyarı', 'Shadow Realm', '5 saniyeliğine gölge diyarına geçerek tüm hasar ve etkilere karşı bağışıklık kazanırsınız, ancak saldıramazsınız.', 'Phase into the shadow realm for 5s, becoming immune to all damage and effects, but unable to attack.', 'Stealth', 65, 650, 4, '{"nj_stealth_phantom_step"}', '{"x": 2121, "y": -1224}', '{"immunity_duration": "5s"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16b6017e-0fb8-4b9b-aad5-e3760e871b83', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_execution', 'İdam', 'Execution', '8d6 hasar verirsiniz. Hedefin canı %20''nin altındaysa, bu saldırı üç kat hasar verir.', 'Deal 8d6 damage. If the target is below 20% HP, this attack deals triple damage.', 'Stealth', 72, 750, 4, '{"nj_stealth_shadow_realm"}', '{"x": 2338, "y": -1349}', '{"damage": "8d6", "execute_threshold": "20%", "multiplier": 3}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('52a5d818-e7d0-4f86-8807-ce99f2aa28db', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_aura', 'Karanlık Halesi', 'Aura of Darkness', '10 saniyeliğine 15m yarıçapında büyülü bir karanlık yaratır. İçerideki düşmanlar kör olur.', 'Create a 15m radius of magical darkness for 10s. Enemies inside are blinded.', 'Stealth', 78, 850, 4, '{"nj_stealth_execution"}', '{"x": 2554, "y": -1474}', '{"radius": "15m", "duration": "10s", "status": "Blind"}', '🌚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8001c8ae-21a2-4ca3-aa54-833c55329d22', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_one_with_shadows', 'Gölgelerle Bir', 'One with Shadows', 'Önümüzdeki 10 saniye boyunca saldırmak artık görünmezliğinizi bozmaz.', 'Attacking no longer breaks your invisibility for the next 10s.', 'Stealth', 85, 1100, 5, '{"nj_stealth_aura"}', '{"x": 2771, "y": -1599}', '{"duration": "10s"}', '🌒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee96271d-4c2a-416c-b551-d5077adcd231', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_stealth_ultimate_nightfall', 'Ulti: Alacakaranlık Suikastçısı', 'Ultimate: Nightfall Assassin', '20m içindeki tüm düşmanlar arasında anında atılarak her birine 12d6 hasar verir ve başlangıç konumunuza görünmez olarak dönersiniz.', 'Dash instantly between all enemies within 20m, dealing 12d6 damage to each and returning to your starting position in stealth.', 'Stealth', 90, 1500, 5, '{"nj_stealth_one_with_shadows"}', '{"x": 2987, "y": -1724}', '{"range": "20m", "damage": "12d6"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c80e9031-e747-4dfc-b7db-ad4bd93645d8', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_smoke_bomb', 'Sis Bombası', 'Smoke Bomb', 'Görüşü engelleyen ve görünmezlik sağlayan, 5 saniyeliğine 5m''lik bir sis bulutu yaratan bir bomba atar.', 'Throw a bomb that creates a 5m smoke cloud for 5s, blocking vision and granting stealth.', 'Ninjutsu', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"radius": "5m", "duration": "5s"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2ad50ad0-4b6e-4567-924e-700babc3934f', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_substitution', 'Yer Değiştirme Jutsusu', 'Substitution Jutsu', 'Vurulduğunda tahta bir kütükle yer değiştirerek hasarı sıfırlar ve 5m uzağa ışınlanırsınız.', 'When struck, swap places with a wooden log, negating the damage and teleporting 5m away.', 'Ninjutsu', 8, 80, 1, '{"nj_ninjutsu_smoke_bomb"}', '{"x": 289, "y": 344}', '{"teleport": "5m", "damage_negated": "100%"}', '🪵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('318d2249-b88e-479b-821f-155c1b97ac96', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_water_walk', 'Su Yürüyüşü', 'Water Walk', 'Çakranızı yönlendirerek 1 saat boyunca su ve diğer sıvı yüzeylerde yürürsünüz.', 'Channel chakra to walk on water and other liquid surfaces for 1 hour.', 'Ninjutsu', 18, 120, 1, '{"nj_ninjutsu_substitution"}', '{"x": 449, "y": 536}', '{"duration": "1h"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f620cc19-730d-4d00-8099-458477fadcea', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_caltrops', 'Çivili Kapan', 'Caltrops', '5m''lik bir alana kapanlar saçar. Giren düşmanlar 2d4 hasar alır ve %50 yavaşlar.', 'Scatter caltrops over a 5m area. Enemies entering take 2d4 damage and are slowed by 50%.', 'Ninjutsu', 25, 200, 2, '{"nj_ninjutsu_water_walk"}', '{"x": 610, "y": 727}', '{"radius": "5m", "damage": "2d4", "slow": "50%"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af6c6f01-512a-4ffe-9b45-e33ecbb6b960', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_fire_breath', 'Ateş Nefesi', 'Fire Breath', '10m''lik bir koni şeklinde alev üfleyerek 4d6 ateş hasarı verir ve hedefleri 3 saniye yakarsınız.', 'Exhale a 10m cone of flames, dealing 4d6 fire damage and igniting targets for 3s.', 'Ninjutsu', 30, 250, 2, '{"nj_ninjutsu_caltrops"}', '{"x": 771, "y": 919}', '{"cone": "10m", "damage": "4d6", "burn_duration": "3s"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf9b7130-c252-4e60-971a-8721bb5b06c7', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_shadow_clone', 'Gölge Klonu', 'Shadow Clone', 'Düşmanların dikkatini dağıtan ve 10 saniye boyunca temel saldırılarınızı taklit eden illüzyon bir kopyanızı yaratırsınız.', 'Create an illusory clone of yourself that distracts enemies and mimics your basic attacks for 10s.', 'Ninjutsu', 38, 300, 2, '{"nj_ninjutsu_fire_breath"}', '{"x": 932, "y": 1110}', '{"clones": 1, "duration": "10s"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('75131576-b661-405d-bbd3-bb8d0c90980a', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_poison_fog', 'Zehirli Sis', 'Poison Fog', '8 saniyeliğine 10m''lik zehirli gaz bulutu salar. İçerideki düşmanlar saniyede 3d6 zehir hasarı alır.', 'Release a 10m cloud of toxic gas for 8s. Enemies inside take 3d6 poison damage per second.', 'Ninjutsu', 45, 400, 3, '{"nj_ninjutsu_shadow_clone"}', '{"x": 1092, "y": 1302}', '{"radius": "10m", "duration": "8s", "damage_per_sec": "3d6"}', '🤢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f03ecf02-9603-410b-8ac4-ae12aba89a42', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_earth_wall', 'Toprak Duvar', 'Earth Wall', 'Mermileri ve hareketi engellemek için 3m genişliğinde, 2m yüksekliğinde bir taş duvar yükseltir. 15s sürer.', 'Raise a 3m wide, 2m tall rock wall to block projectiles and movement. Lasts 15s.', 'Ninjutsu', 52, 450, 3, '{"nj_ninjutsu_poison_fog"}', '{"x": 1253, "y": 1493}', '{"width": "3m", "height": "2m", "duration": "15s"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d9035a0b-7634-4689-8054-6d60e8ba8e0e', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_lightning_speed', 'Yıldırım Hızı', 'Lightning Speed', 'Vücudunuza yıldırım enjekte ederek 6 saniyeliğine hareket hızınızı %100 ve saldırı hızınızı %50 artırırsınız.', 'Infuse your body with lightning, increasing movement speed by 100% and attack speed by 50% for 6s.', 'Ninjutsu', 59, 500, 3, '{"nj_ninjutsu_earth_wall"}', '{"x": 1414, "y": 1685}', '{"speed_buff": "100%", "attack_speed": "50%", "duration": "6s"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('862efc71-af17-4810-abcd-3a72b33b9cac', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_exploding_tags', 'Patlayıcı Kağıtlar', 'Exploding Tags', 'Bir hedefe veya yüzeye patlayıcı mühür yapıştırır. 2 saniye sonra 5m yarıçapında 6d6 ateş hasarı ile patlar.', 'Attach an explosive seal to a target or surface. Detonates after 2s for 6d6 fire damage in a 5m radius.', 'Ninjutsu', 66, 650, 4, '{"nj_ninjutsu_lightning_speed"}', '{"x": 1574, "y": 1876}', '{"delay": "2s", "damage": "6d6", "radius": "5m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2745a7c0-3759-4534-b8cc-5dbab65fcf33', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_multi_clone', 'Çoklu Gölge Klonu', 'Multi Shadow Clone', '3 gölge klonu çağırır. Hasarınızın %20''sini verirler ve maksimum canınızın %10''una sahiptirler. 15s sürer.', 'Summon 3 shadow clones. They deal 20% of your damage and have 10% of your max HP. Lasts 15s.', 'Ninjutsu', 74, 750, 4, '{"nj_ninjutsu_exploding_tags"}', '{"x": 1735, "y": 2068}', '{"clones": 3, "damage_modifier": "20%", "hp_modifier": "10%", "duration": "15s"}', '👬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c6622a89-7457-459b-a0c9-3bccffd5c0ee', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_wind_scythe', 'Rüzgar Tırpanı', 'Wind Scythe', '20m ilerleyen hilal şeklinde bir rüzgar bıçağı serbest bırakır. 7d6 kesici hasar verir ve düşmanları 5m geri savurur.', 'Unleash a crescent blade of wind traveling 20m. Deals 7d6 slashing damage and knocks enemies back 5m.', 'Ninjutsu', 80, 850, 4, '{"nj_ninjutsu_multi_clone"}', '{"x": 1896, "y": 2259}', '{"range": "20m", "damage": "7d6", "knockback": "5m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60a09b3f-05a5-4fc8-816d-5a6656421d40', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_demon_seal', 'İblis Mührü', 'Demon Sealing', 'Bir hedefe karmaşık bir mühür yerleştirerek onu 3 saniye felç eder ve büyülerini/yeteneklerini 10 saniye mühürlersiniz.', 'Place a complex seal on a target, paralyzing them for 3s and sealing their magic/skills for 10s.', 'Ninjutsu', 86, 1100, 5, '{"nj_ninjutsu_wind_scythe"}', '{"x": 2056, "y": 2451}', '{"paralysis": "3s", "silence": "10s"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('029d9e67-cb20-421c-b482-959d33daf0fe', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_ninjutsu_ultimate_kage', 'Ulti: Kage Bunshin Ordusu', 'Ultimate: Kage Bunshin Army', '20 saniyeliğine 10 elit klon çağırır. Hasarınızın %50''sini verirler, temel shuriken atabilirler ve düşmanların aklını karıştırırlar.', 'Summon 10 elite clones for 20s. They deal 50% of your damage, can cast basic shuriken, and confuse enemies.', 'Ninjutsu', 92, 1500, 5, '{"nj_ninjutsu_demon_seal"}', '{"x": 2217, "y": 2642}', '{"clones": 10, "damage_modifier": "50%", "duration": "20s"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('608ff76a-e3f8-42ba-ac61-7ad8ab0574cb', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_throw', 'Shuriken Fırlat', 'Throw Shuriken', '15m içindeki bir hedefe hızla shuriken fırlatarak 1d6 fiziksel hasar verirsiniz.', 'Quickly throw a shuriken at a target within 15m, dealing 1d6 physical damage.', 'Shuriken', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"range": "15m", "damage": "1d6"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('813aacc5-f78b-401f-b2a5-449d6db38ba8', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_kunai_barrage', 'Kunai Yağmuru', 'Kunai Barrage', '15m''lik bir koni içinde 3 hedefe kadar aynı anda 3 kunai fırlatır. Her biri 2d4 hasar verir.', 'Throw 3 kunai simultaneously at up to 3 targets in a 15m cone. Each deals 2d4 damage.', 'Shuriken', 10, 80, 1, '{"nj_shuriken_throw"}', '{"x": -289, "y": 344}', '{"range": "15m", "projectiles": 3, "damage_per_projectile": "2d4"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('349359de-73d7-42d8-af0b-de0b851802ef', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_poison_blade', 'Zehirli Bıçak', 'Poisoned Blade', 'Bir sonraki fırlatılan silahınızı zehirle kaplayarak 4 saniye içinde fazladan 2d6 zehir hasarı verirsiniz.', 'Coat your next thrown weapon in poison, dealing an extra 2d6 poison damage over 4s.', 'Shuriken', 16, 120, 1, '{"nj_shuriken_kunai_barrage"}', '{"x": -449, "y": 536}', '{"damage": "2d6", "duration": "4s"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c943fbb-aebd-4cc4-ab7b-cba8620f1fee', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_piercing', 'Delici Yıldız', 'Piercing Star', '20m''lik bir çizgideki tüm düşmanları delen ve 3d6 hasar veren yüksek hızlı bir shuriken fırlatır.', 'Throw a high-velocity shuriken that pierces through all enemies in a 20m line, dealing 3d6 damage.', 'Shuriken', 24, 200, 2, '{"nj_shuriken_poison_blade"}', '{"x": -610, "y": 727}', '{"range": "20m", "damage": "3d6"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bcd04ff8-0b0b-4315-ad37-b30d246a0c06', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_homing', 'Güdümlü Kunai', 'Homing Kunai', '25m içinde hedefini asla ıskalamayan çakra güdümlü bir kunai fırlatarak 4d4 hasar verirsiniz.', 'Throw a chakra-guided kunai that never misses its target within 25m, dealing 4d4 damage.', 'Shuriken', 32, 250, 2, '{"nj_shuriken_piercing"}', '{"x": -771, "y": 919}', '{"range": "25m", "damage": "4d4"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95a31626-dd1f-4e4b-b526-49455f7d714e', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_fan', 'Bıçak Yelpazesi', 'Fan of Knives', 'Kendi etrafınızda dönerek 360 derecelik bir yayla bıçaklar fırlatır ve 5m içindeki düşmanlara 4d6 hasar verirsiniz.', 'Spin and release knives in a 360-degree arc around you, dealing 4d6 damage to enemies within 5m.', 'Shuriken', 36, 300, 2, '{"nj_shuriken_homing"}', '{"x": -932, "y": 1110}', '{"radius": "5m", "damage": "4d6"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('02087797-5b89-418a-b759-735dca2c0504', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_exploding', 'Patlayan Shuriken', 'Exploding Shuriken', 'Patlayıcı kağıtla donatılmış bir shuriken fırlatır. Çarptığında 4m yarıçapında 5d6 alan etkili ateş hasarı verir.', 'Throw a shuriken rigged with an explosive tag. Deals 5d6 AoE fire damage in a 4m radius upon impact.', 'Shuriken', 44, 400, 3, '{"nj_shuriken_fan"}', '{"x": -1092, "y": 1302}', '{"radius": "4m", "damage": "5d6"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d7d25af-3b0e-407a-aa22-0c5884079529', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_twin', 'İkiz İblis Yıldızları', 'Twin Demon Stars', '15m uçan ve size geri dönen iki devasa shuriken fırlatır, her iki yönde de 4d6 hasar verir.', 'Throw two massive shurikens that fly 15m and return to you, dealing 4d6 damage both ways.', 'Shuriken', 50, 450, 3, '{"nj_shuriken_exploding"}', '{"x": -1253, "y": 1493}', '{"range": "15m", "damage": "4d6"}', '♊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1780000-66ac-4476-9809-f149a5d08059', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_paralysis', 'Felç Dartı', 'Paralysis Dart', '20m''den nörotoksin kaplı hassas bir dart atarak hedefi 3 saniye sersemletirsiniz.', 'Shoot a precise dart coated in neurotoxin from up to 20m, stunning the target for 3s.', 'Shuriken', 56, 500, 3, '{"nj_shuriken_twin"}', '{"x": -1414, "y": 1685}', '{"range": "20m", "stun": "3s"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bff2bd83-ea79-4e82-b273-f53358aa76c0', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_storm', 'Shuriken Fırtınası', 'Shuriken Storm', 'Havaya sıçrayarak 10m yarıçapına düzinelerce shuriken yağdırır ve içeridekilere 8d6 hasar verirsiniz.', 'Leap into the air and rain down dozens of shurikens in a 10m radius, dealing 8d6 damage to all inside.', 'Shuriken', 64, 650, 4, '{"nj_shuriken_paralysis"}', '{"x": -1574, "y": 1876}', '{"radius": "10m", "damage": "8d6"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e9a99367-3186-4ae1-81e3-9da2a3c7325b', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_windmill', 'Dev Rüzgargülü Shuriken', 'Giant Windmill Shuriken', '30m ilerleyen devasa bir fūma shuriken fırlatır. Düşmanları geri iter ve derin kanamaya (3 saniye boyunca saniyede 3d6) neden olur.', 'Throw a massive fūma shuriken traveling 30m. It pushes enemies back and inflicts deep bleeding (3d6 per sec for 3s).', 'Shuriken', 70, 750, 4, '{"nj_shuriken_storm"}', '{"x": -1735, "y": 2068}', '{"range": "30m", "bleed": "3d6/s", "duration": "3s"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f31615fb-38ac-4768-87ce-c8c8edb75f8d', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_vipers_kiss', 'Engerek Öpücüğü', 'Viper''s Kiss', 'Zehirli bir iğne fırlatır. Hedefi, 5 saniye içinde maksimum canının %5''i kadar hasar veren bir zehirle etkiler.', 'Throw a toxic needle. Afflicts target with venom that deals 5% of their max HP over 5s.', 'Shuriken', 76, 850, 4, '{"nj_shuriken_windmill"}', '{"x": -1896, "y": 2259}', '{"damage": "5% Max HP", "duration": "5s"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('292393d1-7242-469e-b7ae-92fb441d569c', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_infinite', 'Sonsuz Cephanelik', 'Infinite Arsenal', 'Önümüzdeki 10 saniye boyunca tüm shuriken ve kunai yeteneklerinin bekleme süresi 0 olur ve dayanıklılık/mana harcamaz.', 'For the next 10s, all shuriken and kunai skills have 0 cooldown and cost no stamina/mana.', 'Shuriken', 84, 1100, 5, '{"nj_shuriken_vipers_kiss"}', '{"x": -2056, "y": 2451}', '{"duration": "10s", "cooldown_reduction": "100%"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a2ddcbeb-8cda-41e9-8eae-6df4843b9159', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_shuriken_ultimate_dance', 'Ulti: Rüzgarın Bıçak Dansı', 'Ultimate: Blade Dance of the Wind', 'Bir bıçak girdabına dönüşürsünüz. 15m yarıçapındaki her yöne 100 shuriken fırlatarak 15d6 fiziksel hasar verir ve tüm hedefleri ağır şekilde kanatırsınız.', 'Become a vortex of blades. Throw 100 shurikens in all directions across a 15m radius, dealing 15d6 physical damage and heavily bleeding all targets.', 'Shuriken', 94, 1500, 5, '{"nj_shuriken_infinite"}', '{"x": -2217, "y": 2642}', '{"radius": "15m", "damage": "15d6", "bleed": "Heavy"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('37973649-8e4c-4ab6-b899-7901b130ab0a', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_cross_shadow_shuriken', 'Gölge Shuriken', 'Shadow Shuriken', 'Görünmezlikten bir shuriken fırlatır. Çarptığında, hedefin arkasında bir gölge klonuna dönüşür ve saldırır.', 'Throw a shuriken from stealth. Upon impact, it materializes into a shadow clone behind the target and strikes.', 'Stealth, Shuriken', 35, 300, 2, '{"nj_stealth_blend", "nj_shuriken_piercing"}', '{"x": 173, "y": -99}', '{"clone": 1, "strike": "Auto"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24b33db3-4a47-4b46-b254-7f51743a7033', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_cross_smoke_kunai', 'Sis Kunaisi', 'Smoke Kunai', 'Çarptığında 8m kalınlığında bir sis bulutuna dönüşerek içerideki düşmanları kör eden bir kunai fırlatır.', 'Throw a kunai that detonates into a 8m thick smoke cloud on impact, blinding enemies inside.', 'Ninjutsu, Shuriken', 42, 400, 3, '{"nj_ninjutsu_shadow_clone", "nj_shuriken_fan"}', '{"x": 173, "y": -99}', '{"radius": "8m", "status": "Blind"}', '☁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1cf886b1-fc23-43f4-8533-e82e56a2769b', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_cross_silent_clone', 'Sessiz Klon', 'Silent Clone', 'Hedefe yaklaşan ve ücretsiz bir Sessiz İnfaz uygulayan görünmez bir gölge klonu yaratır.', 'Create an invisible shadow clone that approaches the target and delivers a free Silent Takedown.', 'Stealth, Ninjutsu', 48, 450, 3, '{"nj_stealth_vanish", "nj_ninjutsu_shadow_clone"}', '{"x": 173, "y": -99}', '{"clone_stealth": true, "free_cast": "Silent Takedown"}', '👤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24c90d12-8181-40c3-9045-828604cbf215', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_cross_poison_clone', 'Zehirli Klon Patlaması', 'Poison Clone Explosion', 'Klonlarınız artık yok edildiklerinde 5m''lik bir Zehirli Sis yayarak yakındaki düşmanlara ağır hasar verir.', 'Your clones now erupt into a 5m Poison Fog when destroyed, heavily damaging nearby enemies.', 'Ninjutsu, Shuriken', 55, 500, 3, '{"nj_ninjutsu_poison_fog", "nj_shuriken_exploding"}', '{"x": 389, "y": -224}', '{"radius": "5m", "trigger": "Clone Death"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('799c8b7f-752b-4204-9ecb-3d73e7ba3df6', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_cross_shuriken_teleport', 'Uçan Yıldırım Işınlanması', 'Flying Thunder Teleport', 'İşaretli bir kunaiyi 30m''ye kadar fırlatır ve anında o konuma ışınlanırsınız. Görünmez iseniz, bozulmaz.', 'Throw a marked kunai up to 30m, and instantly teleport to its location. If in stealth, it is not broken.', 'Stealth, Shuriken', 65, 650, 4, '{"nj_stealth_phantom_step", "nj_shuriken_twin"}', '{"x": 389, "y": -224}', '{"range": "30m", "stealth_preserved": true}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('761623b4-e281-451b-9b0d-1297f51c98ac', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_cross_nightfall_trap', 'Alacakaranlık Tuzağı', 'Nightfall Trap', 'Görünmez bir patlayıcı mühür bırakır. Tetiklendiğinde 8d6 hasar verir ve anında Karanlık Halesi uygular.', 'Leave an invisible explosive seal. When triggered, it deals 8d6 damage and casts Aura of Darkness instantly.', 'Stealth, Ninjutsu', 75, 750, 4, '{"nj_stealth_execution", "nj_ninjutsu_exploding_tags"}', '{"x": 389, "y": -224}', '{"damage": "8d6", "trigger_spell": "Aura of Darkness"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('637745e7-f505-439c-899e-420ab293382e', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_cross_elemental_blade', 'Element Bıçak Fırtınası', 'Elemental Blade Storm', 'Ateş, yıldırım ve rüzgarla aşılanmış bir Bıçak Yelpazesi serbest bırakır. 10d6 karma element hasarı verir ve düşmanları iter.', 'Unleash a Fan of Knives infused with fire, lightning, and wind. Deals 10d6 mixed elemental damage and pushes enemies.', 'Ninjutsu, Shuriken', 85, 1100, 5, '{"nj_ninjutsu_wind_scythe", "nj_shuriken_vipers_kiss"}', '{"x": 606, "y": -349}', '{"damage": "10d6", "elements": "Fire, Lightning, Wind", "pushback": "5m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7ff25bfa-c390-4b05-9027-bc219a806de7', 'badddee7-0723-4049-bf7a-1b4fab340f40', 'nj_grand_ultimate_master_unseen', 'Büyük Ulti: Susanoo''nun Gölgesi', 'Grand Ultimate: Susanoo''s Shadow', 'Nihai ninja tanrısı olun. Dev Rüzgargülü Shuriken ve Zehirli Sis kullanan 10 klon çıkarırken, siz 20 saniye boyunca kalıcı olarak görünmez olur ve hasara karşı bağışıklık kazanırsınız.', 'Become the ultimate ninja god. Spawn 10 clones that spam Windmill Shurikens and Poison Fog, while you remain permanently invisible and immune to damage for 20 seconds.', 'Stealth, Ninjutsu, Shuriken', 100, 2000, 5, '{"nj_stealth_ultimate_nightfall", "nj_ninjutsu_ultimate_kage", "nj_shuriken_ultimate_dance"}', '{"x": 173, "y": -99}', '{"clones": 10, "duration": "20s", "immunity": true, "permanent_stealth": true}', '👺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3fed539-3dfe-4968-827a-6d046747ab88', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_charge_stance', 'Güç Toplama Duruşu', 'Charge Stance', 'Sabit bir duruşa geçersiniz. Hareket edemezsiniz ancak bir sonraki menzilli saldırınız fazladan 1d8 hasar kazanır.', 'Assume a stationary stance. You cannot move, but your next ranged attack gains +1d8 damage.', 'Charge', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "+1d8", "movement": "0m"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bbe243c2-7b7e-4810-9444-6ac44862ecc3', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_deep_breath', 'Derin Nefes', 'Deep Breath', 'Nefesinizi kontrol etmek için bir bonus eylem harcarsınız. Bir sonraki hasar zarınızdaki 1 ve 2''leri yeniden atmanızı sağlar.', 'Spend a bonus action to control your breathing, allowing you to reroll 1s and 2s on your next damage roll.', 'Charge', 3, 75, 1, '{}', '{"x": 389, "y": -224}', '{"reroll": "1-2"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c0b95cd-0f3a-4d78-b69e-a85c7e8448e9', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_heavy_draw', 'Ağır Çekim', 'Heavy Draw', 'Silahınızı aşırı bir güçle çekersiniz. Saldırınız inisiyatif sırasında 1 sıra gecikir ancak +1d10 hasar verir.', 'Pull your weapon with extreme force. Your attack is delayed by 1 initiative count, but deals +1d10 damage.', 'Charge', 5, 100, 1, '{}', '{"x": 606, "y": -349}', '{"damage": "+1d10", "initiative": "-1"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('554b7abc-36db-47e7-ba00-d439ea3a7a06', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_patience', 'Sabır', 'Patience', 'Eğer turunuzu saldırmadan bitirirseniz, bir sonraki turdaki ilk saldırınız Avantaj kazanır.', 'If you end your turn without attacking, your first attack on the next turn gains Advantage.', 'Charge', 7, 120, 1, '{}', '{"x": 822, "y": -474}', '{"advantage": "next turn"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a357e3c-8aa2-4fad-bc5d-c8a6360f53c4', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_focused_sight', 'Odaklanmış Görüş', 'Focused Sight', 'Uzak bir hedefe odaklanırsınız. Bir sonraki atışınız için maksimum etkili menzilinizi 20m artırır.', 'Concentrate on a distant target. Increases your maximum effective range by 20m for the next shot.', 'Charge', 10, 150, 1, '{}', '{"x": 1039, "y": -599}', '{"range": "+20m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('73fae8c9-4a1b-4a4e-8232-68f52e44af37', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_crushing_shot', 'Ezen Atış', 'Crushing Shot', '2d8 ezme hasarı veren ve hedefi 2m geriye iten ağır bir mermi atarsınız.', 'A heavy projectile that deals 2d8 bludgeoning damage and pushes the target back 2m.', 'Destruction', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "2d8", "knockback": "2m"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40189550-ffa0-406c-9682-61a21f17be72', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_shatter_cover', 'Sipere Yıkım', 'Shatter Cover', 'Atışınız büyülü olmayan nesnelere, kapılara ve yapısal siperlere iki kat hasar verir.', 'Your shot deals double damage to non-magical objects, doors, and structural cover.', 'Destruction', 4, 80, 1, '{}', '{"x": 289, "y": 344}', '{"damage_multiplier": "2x to objects"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35ee31fb-0068-4456-a7bd-a8df752566b8', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_concussive_blast', 'Sarsıcı Patlama', 'Concussive Blast', 'Atışınızın ham gücü bir ses patlaması yaratır. Hedef Dayanıklılık kurtarmasında başarısız olursa 1 tur boyunca sağır ve sersemlemiş olur.', 'The sheer force of your shot creates a sonic boom. The target must succeed on a Constitution save or be deafened and dazed for 1 turn.', 'Destruction', 8, 130, 1, '{}', '{"x": 449, "y": 536}', '{"duration": "1 turn", "status": "Deafened/Dazed"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af3bc151-a184-4603-922f-2d7f14e7d23d', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_heavy_caliber', 'Ağır Kalibre', 'Heavy Caliber', 'Pasif. Özel, yoğun mühimmat kullanırsınız. Tüm menzilli saldırılarınız fazladan sabit +2 hasar verir.', 'Passive. You use specialized, dense ammunition. All your ranged attacks deal a flat +2 extra damage.', 'Destruction', 12, 150, 1, '{}', '{"x": 610, "y": 727}', '{"damage": "+2"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0cd1e93c-9944-46f0-9e64-9312d621214f', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_armor_pierce', 'Zırh Delici', 'Armor Pierce', 'Kesin atışınız zırhın zayıf noktalarını hedefler ve bu saldırıya karşı hedefin Zırh Sınıfını (AC) 2 düşürür.', 'Your precise shot targets the weak points of armor, effectively reducing the target''s Armor Class by 2 against this attack.', 'Penetration', 2, 60, 1, '{}', '{"x": -128, "y": 153}', '{"armor_reduction": "2"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b35c2b95-74ff-4bb7-a191-841ae97d29f9', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_needle_shot', 'İğne Atışı', 'Needle Shot', 'Fiziksel kalkanlardan gelen AC bonuslarını yok sayan ve 1d10 delici hasar veren kusursuz aerodinamik bir atış.', 'A perfectly streamlined shot dealing 1d10 piercing damage that ignores AC bonuses from physical shields.', 'Penetration', 6, 110, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "1d10", "ignores": "shield AC"}', '🪡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4fbbc50c-53b6-453d-a2b0-816793fdae72', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_clean_through', 'Delip Geçen', 'Clean Through', 'Eğer bu saldırı bir hedefin canını 0''a düşürürse, mermi devam eder ve hemen arkasındaki 5m içindeki bir düşmana yarı hasar verir.', 'If this attack reduces a target to 0 HP, the projectile continues, hitting an enemy directly behind them within 5m for half damage.', 'Penetration', 9, 140, 1, '{}', '{"x": -449, "y": 536}', '{"range": "5m", "damage": "half damage to second target"}', '🧵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('52b41677-e568-488c-9205-7f09b6279fd0', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_vital_spot', 'Hayati Nokta', 'Vital Spot', 'Nişan almak için en az bir bonus eylem harcarsanız, silah saldırınız 19 veya 20 zarında kritik vuruş yapar.', 'If you spend at least one bonus action aiming, your weapon attack scores a critical hit on a roll of 19 or 20.', 'Penetration', 13, 150, 1, '{}', '{"x": -610, "y": 727}', '{"crit_range": "19-20"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49792c2c-191c-4ead-bb0d-06c04d934f76', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_steady_hands', 'Titremeyen Eller', 'Steady Hands', 'Gereksinim: Güç Toplama Duruşu, Zırh Delici. Güç toplanmış atışlarınız artık 1.5m içindeki düşmanlardan dolayı dezavantaj almaz.', 'Requires: Charge Stance, Armor Pierce. Your charged shots no longer suffer disadvantage from enemies within 1.5m.', 'Cross-Branch', 15, 150, 1, '{"os_charge_stance", "os_armor_pierce"}', '{"x": -173, "y": -100}', '{"negates_disadvantage": "within 1.5m"}', '🤲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('186fcff6-8c98-4acb-8800-b67303087f99', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_brutal_impact', 'Acımasız Çarpışma', 'Brutal Impact', 'Gereksinim: Ezen Atış, Ağır Çekim. 3d10 hasar veren ve hedefi yere seren (prone) gecikmeli ağır bir saldırı.', 'Requires: Crushing Shot, Heavy Draw. A delayed heavy attack that deals 3d10 damage and knocks the target prone.', 'Cross-Branch', 18, 150, 1, '{"os_crushing_shot", "os_heavy_draw"}', '{"x": -389, "y": -225}', '{"damage": "3d10", "status": "Prone"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3574574f-8274-4135-b092-6c38fe28edb5', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_overcharge', 'Aşırı Yükleme', 'Overcharge', 'Saldırınızı ateş etmeden 3 tura kadar bekletebilirsiniz. Bekletilen her tur için nihai atışa +2d10 hasar eklenir.', 'You can hold your attack for up to 3 turns without firing. For each turn held, add +2d10 damage to the eventual shot.', 'Charge', 22, 180, 2, '{"os_charge_stance"}', '{"x": 1255, "y": -724}', '{"damage": "+2d10 per turn", "max_turns": "3"}', '🔋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d0d2b446-0b23-4514-b389-bf026a0e646e', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_zen_focus', 'Zen Odaklanması', 'Zen Focus', 'Nişan alırken veya güç toplarken hasar almanız konsantrasyonunuzu bozamaz.', 'While aiming or charging a shot, you cannot have your concentration broken by taking damage.', 'Charge', 26, 200, 2, '{"os_patience"}', '{"x": 1472, "y": -849}', '{"concentration": "unbreakable by damage"}', '🪷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35c36b3f-866d-4ebd-82d9-f02012169121', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_heartbeat_sync', 'Kalp Atışı Senkronu', 'Heartbeat Sync', 'Atışınızı kalp atışlarınızın arasına denk getirirsiniz. Bir sonraki saldırınız saldırı zarına +5 bonus kazanır.', 'Time your shot between your heartbeats. Your next attack gains a +5 bonus to the attack roll.', 'Charge', 30, 250, 2, '{"os_deep_breath"}', '{"x": 1688, "y": -974}', '{"attack_bonus": "+5"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('62e13932-2de7-4b96-aca0-853929dec4d1', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_devastating_strike', 'Yıkıcı Vuruş', 'Devastating Strike', '4d10 hasar veren vahşi bir atış. Hedefler Güç kurtarmasında başarılı olamazsa 4m geriye itilir ve yere serilir.', 'Fires a brutal shot dealing 4d10 damage. Targets must succeed on a Strength saving throw or be pushed 4m and knocked prone.', 'Destruction', 24, 190, 2, '{"os_crushing_shot"}', '{"x": 771, "y": 919}', '{"damage": "4d10", "knockback": "4m", "status": "Prone"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('039a47cc-31c2-4853-9db6-5bdc9c963402', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_explosive_tip', 'Patlayıcı Uç', 'Explosive Tip', 'Merminizin çarpma anında patlamasını sağlar; 3m yarıçaptaki tüm yaratıklara fazladan 2d6 ateş hasarı verir.', 'Modifies your projectile to detonate on impact, dealing an additional 2d6 fire damage to all creatures within a 3m radius.', 'Destruction', 28, 220, 2, '{"os_concussive_blast"}', '{"x": 932, "y": 1110}', '{"damage": "2d6 fire", "radius": "3m"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea58adba-055e-4fab-8ca9-2fd84e5380db', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_sunder_armor', 'Zırh Parçalama', 'Sunder Armor', 'Ekipmana hasar veren hedefli bir vuruş. Zırhları onarılana kadar hedefin AC değerini kalıcı olarak 1 düşürür.', 'A targeted strike that damages equipment. Permanently reduces the target''s AC by 1 until their armor is repaired.', 'Destruction', 32, 280, 2, '{"os_shatter_cover"}', '{"x": 1092, "y": 1302}', '{"armor_reduction": "1 permanent"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e075c5f-40a7-488e-abc6-d41dfd00f4a1', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_line_breaker', 'Hat Kırıcı', 'Line Breaker', 'Atışınız ilk hedefi delip geçerek düz bir çizgideki ikinci hedefi de vurur, her ikisine de tam hasar verir.', 'Your shot pierces through the first target to strike a second target in a straight line, dealing full damage to both.', 'Penetration', 25, 200, 2, '{"os_clean_through"}', '{"x": -771, "y": 919}', '{"pierce": "2 targets"}', '➖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f612a4d4-63ef-4187-b6f2-57199fb44898', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_find_the_gap', 'Boşluğu Bul', 'Find the Gap', 'İnanılmaz isabet oranınız sayesinde saldırılarınız yarım siperi ve üç çeyrek siperi yok sayar.', 'Your incredible accuracy allows your attacks to ignore half cover and three-quarters cover.', 'Penetration', 29, 240, 2, '{"os_armor_pierce"}', '{"x": -932, "y": 1110}', '{"ignores": "half and 3/4 cover"}', '🧩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('596a9796-372e-4028-b840-c55c7732d335', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_shield_breaker', 'Kalkan Kırıcı', 'Shield Breaker', 'Özel bir anti-büyü atışı. ''Kalkan'' (Shield) büyüsünü anında paramparça eder ve 3d8 delici hasar verir.', 'A specialized anti-magic shot. Instantly shatters the ''Shield'' spell and deals 3d8 piercing damage.', 'Penetration', 34, 290, 2, '{"os_needle_shot"}', '{"x": -1092, "y": 1302}', '{"damage": "3d8", "dispels": "Shield spell"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('50505852-045a-46b5-a911-b64593fc4ee8', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_perfect_aim', 'Kusursuz Nişan', 'Perfect Aim', 'Gereksinim: Zen Odaklanması, Boşluğu Bul. Tam bir turu nişan almaya harcamak, bir sonraki atışınızın otomatik olarak isabet etmesini garanti eder (zar atılmaz).', 'Requires: Zen Focus, Find the Gap. Spending a full turn aiming guarantees that your next shot automatically hits (no attack roll needed).', 'Cross-Branch', 36, 300, 2, '{"os_zen_focus", "os_find_the_gap"}', '{"x": -606, "y": -350}', '{"accuracy": "Auto-hit after 1 turn aim"}', '💯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('da8418a0-1f76-4ea1-8b5f-1b7b290bd643', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_collateral_damage', 'İkincil Hasar', 'Collateral Damage', 'Gereksinim: Patlayıcı Uç, Hat Kırıcı. Delici atışlarınız her hedeften çıkışında patlayarak, her çıkış noktasında 2m yarıçapta 2d6 güç hasarı verir.', 'Requires: Explosive Tip, Line Breaker. Your piercing shots explode upon exiting each target, dealing 2d6 force damage in a 2m radius at every exit point.', 'Cross-Branch', 38, 300, 2, '{"os_explosive_tip", "os_line_breaker"}', '{"x": -822, "y": -475}', '{"damage": "2d6 force", "radius": "2m per exit"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fafc7e6d-4b0e-445a-99bd-0a2e96417a87', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_momentum_shift', 'Momentum Kayması', 'Momentum Shift', 'Gereksinim: Aşırı Yükleme, Yıkıcı Vuruş. En az 1 tur güç toplanmış bir atışı yaptıktan hemen sonra, ücretsiz eylem olarak ikinci bir saldırı yapabilirsiniz.', 'Requires: Overcharge, Devastating Strike. Immediately after firing a shot charged for at least 1 turn, you can take a second attack as a free action.', 'Cross-Branch', 40, 300, 2, '{"os_overcharge", "os_devastating_strike"}', '{"x": -1039, "y": -600}', '{"extra_attack": "Free action"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('009099ac-9bd1-4682-8ec9-e85ab1d39e1c', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_lethal_tempo', 'Ölümcül Tempo', 'Lethal Tempo', 'Başarılı isabet sağladığınız her ardışık tur, kritik hasar çarpanınız 0.5x artar (maksimum 3x hasara kadar).', 'Each consecutive turn you land a successful hit, your critical multiplier increases by 0.5x (up to a max of 3x damage).', 'Charge', 42, 350, 3, '{"os_heartbeat_sync"}', '{"x": 1905, "y": -1099}', '{"crit_multiplier": "+0.5x per turn", "max_multiplier": "3x"}', '🎼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('450c3149-2327-4a20-928a-5f3ba4348e8e', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_absolute_stillness', 'Mutlak Hareketsizlik', 'Absolute Stillness', 'Nişan alırken çevrenizle mükemmel bir şekilde bütünleşirsiniz; hareket etmediğiniz veya konuşmadığınız sürece görünmez olursunuz.', 'While aiming, you blend perfectly with your surroundings, becoming invisible as long as you do not move or speak.', 'Charge', 46, 380, 3, '{"os_zen_focus"}', '{"x": 2121, "y": -1224}', '{"status": "Invisibility"}', '🫥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('822b4880-a93d-4c95-9311-2a252de36040', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_annihilation_round', 'Yok Ediş Mermisi', 'Annihilation Round', '6d12 hasar veren ve hedefi 5m havaya fırlatan son derece yıkıcı bir mermi ateşler.', 'Fires a devastating projectile dealing 6d12 damage and throwing the target 5m into the air.', 'Destruction', 44, 360, 3, '{"os_devastating_strike"}', '{"x": 1253, "y": 1493}', '{"damage": "6d12", "knockup": "5m"}', '☢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e55fc9af-0277-40fd-8b0a-e706044f57ce', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_rupture_organs', 'Organ Parçalama', 'Rupture Organs', 'Vuruşun kinetik şok dalgası iç organlara hasar verir. Hedef 3 tur boyunca her turunun başında 1d10 kanama hasarı alır.', 'The kinetic shockwave of the hit damages internal organs. The target bleeds for 1d10 damage at the start of their turns for 3 turns.', 'Destruction', 48, 400, 3, '{"os_explosive_tip"}', '{"x": 1414, "y": 1685}', '{"damage": "1d10 bleed", "duration": "3 turns"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e9e63d33-a91f-4ab7-89e0-469c7719ec0b', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_bunker_buster', 'Sığınak Delici', 'Bunker Buster', 'Tüm fiziksel siperleri yok sayar. Hedefi vurmak için 1m kalınlığa kadar taş, tahta veya toprak duvarları tamamen delip geçer.', 'Ignores all physical cover. Completely punches through stone walls, wood, or dirt up to 1m thick to hit the target.', 'Destruction', 52, 450, 3, '{"os_sunder_armor"}', '{"x": 1574, "y": 1876}', '{"ignores": "all physical cover", "penetration": "1m thick walls"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5a6fcdde-f8bf-4ea9-9466-589dcb209705', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_railgun_shot', 'Elektromanyetik Atış', 'Railgun Shot', '50m uzunluğunda ve 1m genişliğinde bir çizgideki tüm yaratıkları vuran hiper hızlı bir atış. Herkese 5d10 delici hasar verir.', 'Fires a hyper-velocity shot that hits every creature in a 50m long, 1m wide line. Deals 5d10 piercing damage to all.', 'Penetration', 45, 370, 3, '{"os_line_breaker"}', '{"x": -1253, "y": 1493}', '{"damage": "5d10", "area": "50m line", "width": "1m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ea30cfb-5971-4aff-a328-5877ab7490cf', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_ignore_resistance', 'Direnci Yok Say', 'Ignore Resistance', 'Saldırılarınız o kadar güçlüdür ki hedefin hasar direncini normalmiş gibi, hasar bağışıklığını ise dirençmiş gibi kabul eder.', 'Your attacks are so forceful they treat the target''s damage resistance as normal, and damage immunity as resistance.', 'Penetration', 49, 420, 3, '{"os_find_the_gap"}', '{"x": -1414, "y": 1685}', '{"penetration": "bypasses resistance/immunity"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dab14963-af5d-4bac-9489-4618cbab69c0', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_phantom_bullet', 'Hayalet Mermi', 'Phantom Bullet', 'Mermi gerçeklikten çıkar. Hedefin içinde maddileşmeden önce tamamen katı engellerin içinden 5m''ye kadar seyahat eder.', 'The projectile phases out of reality. It travels up to 5m through completely solid barriers before materializing into the target.', 'Penetration', 54, 460, 3, '{"os_shield_breaker"}', '{"x": -1574, "y": 1876}', '{"penetration": "5m through solid barriers"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('528fc800-abcd-43ed-8a99-baeb9e57f276', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_inevitable_end', 'Kaçınılmaz Son', 'Inevitable End', 'Gereksinim: Kalp Atışı Senkronu, Yok Ediş Mermisi. Çarpma anında, en az 2 tur güç toplanmış bir atış 50 Canın altındaki herhangi bir hedefi anında infaz eder.', 'Requires: Heartbeat Sync, Annihilation Round. A shot charged for at least 2 turns instantly executes any target below 50 HP upon impact.', 'Cross-Branch', 56, 500, 3, '{"os_heartbeat_sync", "os_annihilation_round"}', '{"x": -1255, "y": -725}', '{"execute": "< 50 HP"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('244dc9c1-48d5-449d-9d24-7f276f172d39', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_triple_pierce', 'Üçlü Delme', 'Triple Pierce', 'Gereksinim: Hat Kırıcı, Organ Parçalama. Atış bir çizgideki en fazla 3 hedefi deler ve her noktada 2d8 gök gürültüsü hasarı veren 3m''lik bir ses patlaması yaratır.', 'Requires: Line Breaker, Rupture Organs. The shot pierces up to 3 targets in a line, creating a 3m sonic boom dealing 2d8 thunder damage at each point.', 'Cross-Branch', 58, 500, 3, '{"os_line_breaker", "os_rupture_organs"}', '{"x": -1472, "y": -850}', '{"pierce": "3 targets", "damage": "2d8 thunder per hit"}', '🍢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24eb4998-5f22-4f42-890f-8a6075f9c1d6', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_breathless_focus', 'Nefessiz Odak', 'Breathless Focus', 'Gereksinim: Mutlak Hareketsizlik, Boşluğu Bul. 2 tur boyunca nişan almak, atışınızın büyülü olmayan zırhları tamamen es geçerek hedefin AC''sini 10 + Çeviklik olarak kabul etmesini sağlar.', 'Requires: Absolute Stillness, Find the Gap. Aiming for 2 turns allows your shot to completely bypass non-magical armor, treating the target''s AC as 10 + their Dexterity.', 'Cross-Branch', 60, 500, 3, '{"os_absolute_stillness", "os_find_the_gap"}', '{"x": -1688, "y": -975}', '{"armor_bypass": "Target AC = 10 + Dex"}', '😶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d694e2ae-86aa-40b7-acac-6cefc577714b', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_supreme_charge', 'Yüce Güç Toplama', 'Supreme Charge', 'Artık saldırınızı 5 tura kadar bekletebilirsiniz. Bekletilen her tur, nihai atışa +3d12 hasar ekler.', 'You can now hold your attack for up to 5 turns. Each turn adds +3d12 damage to the final shot.', 'Charge', 64, 650, 4, '{"os_overcharge"}', '{"x": 2338, "y": -1349}', '{"damage": "+3d12 per turn", "max_turns": "5"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b078baba-5054-4b78-9a90-b02d67ba6081', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_time_dilation_aim', 'Zaman Genleşmeli Nişan', 'Time Dilation Aim', 'Algınız hızlanır. Tek bir turda iki Nişan Alma veya Güç Toplama eylemi yapabilir, böylece hazırlık süresini yarıya indirebilirsiniz.', 'Your perception accelerates. You can take two Aim or Charge actions in a single turn, halving the preparation time.', 'Charge', 68, 750, 4, '{"os_absolute_stillness"}', '{"x": 2554, "y": -1474}', '{"action": "2 Aim/Charge per turn"}', '🕰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4e41e12a-937f-4f97-bb61-4c458f82e893', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_cataclysmic_impact', 'Afet Yaratan Çarpışma', 'Cataclysmic Impact', '10d10 hasar veren ve 10m yarıçapındaki zemini tamamen parçalayarak zorlu araziye çeviren yıkıcı bir vuruş.', 'A devastating strike that deals 10d10 damage and completely shatters the ground in a 10m radius, turning it into difficult terrain.', 'Destruction', 65, 650, 4, '{"os_annihilation_round"}', '{"x": 1735, "y": 2068}', '{"damage": "10d10", "radius": "10m", "terrain": "Difficult Terrain"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6aae5500-9193-4ff6-92b3-cb7e10a9f520', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_limb_sever', 'Uzuv Koparma', 'Limb Sever', 'İsabet oranınız korkutucudur. Eğer kritik vuruş yaparsanız, hedefin uzuvlarından birini kopararak onları kalıcı olarak sakatlarsınız.', 'Your accuracy is terrifying. If you score a critical hit, you sever one of the target''s limbs, permanently maiming them.', 'Destruction', 72, 800, 4, '{"os_rupture_organs"}', '{"x": 1896, "y": 2259}', '{"crit_effect": "Sever Limb"}', '🪚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8f2aa6a-6353-49db-b681-b84cbb211ab2', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_absolute_pierce', 'Mutlak Delme', 'Absolute Pierce', 'Merminiz fiziksel sınırları aşar. Güç Duvarı (Wall of Force) veya Prizmatik Küre dahil hiçbir yöntemle engellenemez veya saptırılamaz.', 'Your projectile transcends physical limits. It cannot be blocked or deflected by any means, including Wall of Force or Prismatic Sphere.', 'Penetration', 66, 700, 4, '{"os_ignore_resistance"}', '{"x": -1735, "y": 2068}', '{"ignores": "Magical barriers"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a1af4942-ad22-4ace-a47f-c42590e871bf', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_infinite_line', 'Sonsuz Çizgi', 'Infinite Line', 'Çizgi delen atışlarınızın menzili çıplak gözle görebildiğiniz maksimum sınıra kadar uzatılır, sadece aşılamaz arazilerde durur.', 'The range of your line-piercing shots is extended to the maximum limit of your unaided vision, stopping only at impenetrable terrain.', 'Penetration', 74, 850, 4, '{"os_railgun_shot"}', '{"x": -1896, "y": 2259}', '{"range": "Visual limit"}', '📏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ebb86f8-448d-4668-b198-c544181fc613', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_god_killer_round', 'Tanrı Katili Mermisi', 'God Killer Round', 'Gereksinim: Sığınak Delici, Direnci Yok Say. İlahi karşıtı özle aşılanmış bir atış. Hasar dokunulmazlıklarını ve geçici can puanlarını tamamen yok sayar.', 'Requires: Bunker Buster, Ignore Resistance. A shot imbued with anti-divine essence. It ignores damage invulnerabilities and temporary hit points entirely.', 'Cross-Branch', 76, 900, 4, '{"os_bunker_buster", "os_ignore_resistance"}', '{"x": -1905, "y": -1100}', '{"ignores": "Invulnerability, Temp HP"}', '🔱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4034e6d-c064-4937-a230-8f8caa890b40', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_stored_potential', 'Depolanmış Potansiyel', 'Stored Potential', 'Gereksinim: Yüce Güç Toplama, Afet Yaratan Çarpışma. Eğer tam güç toplanmış atışınız isabet etmezse, kinetik enerji 1 dakika içindeki bir sonraki atışınız için büyülü olarak korunur.', 'Requires: Supreme Charge, Cataclysmic Impact. If your fully charged shot misses, the kinetic energy is magically preserved for your next shot within 1 minute.', 'Cross-Branch', 80, 900, 4, '{"os_supreme_charge", "os_cataclysmic_impact"}', '{"x": -2121, "y": -1225}', '{"miss_recovery": "Keep charge on miss"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f5fe42aa-f1d6-48dc-b592-bfb36f1152d8', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_ultimate_golden_ratio', 'Ulti: Altın Oran', 'Ultimate: The Golden Ratio', 'Güç Toplama Ultisi. 3 tur nişan alın. Bir sonraki saldırınız otomatik olarak mümkün olan en yüksek hasarı atar ve nihai toplamı 3 ile çarpar.', 'Charge Ultimate. Aim for 3 turns. Your next attack automatically rolls maximum possible damage and multiplies the final total by 3.', 'Charge', 90, 1200, 5, '{"os_supreme_charge", "os_time_dilation_aim"}', '{"x": 2771, "y": -1599}', '{"damage": "Max roll * 3", "cast_time": "3 turns"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0986da3c-6a7f-441c-864d-fcaa443b8a2f', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_ultimate_meteor_strike', 'Ulti: Meteor Çarpması', 'Ultimate: Meteor Strike', 'Yıkım Ultisi. Ana hedefe 20d12 hasar veren bir atış yapar. Ortaya çıkan patlama 30m yarıçapında 10d12 ateş/ezme hasarı verir.', 'Destruction Ultimate. Fires a shot dealing 20d12 damage to the primary target. The resulting explosion deals 10d12 fire/bludgeoning damage in a 30m radius.', 'Destruction', 90, 1200, 5, '{"os_cataclysmic_impact", "os_limb_sever"}', '{"x": 2056, "y": 2451}', '{"damage": "20d12 target, 10d12 aoe", "radius": "30m"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d449c351-ed7d-4d7d-803b-b6353f8c5174', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_ultimate_tachyon_arrow', 'Ulti: Takyon Oku', 'Ultimate: Tachyon Arrow', 'Delme Ultisi. Mermi zamandan daha hızlı seyahat eder. Hedef tepki veremeden otomatik olarak vurur; tüm zırhları, kalkanları ve bağışıklıkları yok sayar.', 'Penetration Ultimate. The projectile travels faster than time. Automatically hits before the target can react, ignoring all armor, shields, and immunities.', 'Penetration', 90, 1200, 5, '{"os_absolute_pierce", "os_infinite_line"}', '{"x": -2056, "y": 2451}', '{"accuracy": "Auto-hit", "ignores": "All defenses/immunities"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c7cb6dc-32b5-473e-9d6e-3741702ad395', '3fd2b279-3823-4fb3-b17e-f5029feb2cdd', 'os_grand_ultimate_big_bang', 'Büyük Ulti: Büyük Patlama', 'Grand Ultimate: The Big Bang', 'Tüm Ultileri gerektirir. 5 tur nişan alın. 1000m''lik bir çizgideki her şeyi delen, 50d20 hasar veren tek bir atış. 50m yarıçaplı bir yok oluş tetikler. 10d20 geri tepme hasarı alırsınız.', 'Requires all Ultimates. Aim for 5 turns. A single shot dealing 50d20 damage, piercing everything in a 1000m line. Triggers a 50m radius annihilation. You take 10d20 recoil damage.', 'Cross-Branch', 100, 1500, 5, '{"os_ultimate_golden_ratio", "os_ultimate_meteor_strike", "os_ultimate_tachyon_arrow"}', '{"x": -2338, "y": -1350}', '{"damage": "50d20", "range": "1000m line", "radius": "50m", "recoil": "10d20 damage"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e6ac43b5-58d5-468e-91f7-5ef6d71ddc37', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_glimpse', 'Yarından Bir Bakış', 'Glimpse of Tomorrow', 'Gelecekten bir anlık kesit görerek yaklaşan bir saldırıdan kaçının. 1 tur boyunca kaçınma şansını %15 artırır.', 'See a glimpse of the immediate future to avoid an incoming attack. Increases dodge chance by 15% for 1 turn.', 'Prophecy', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"buff": "Dodge +15%", "duration": "1 turn"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e672cb99-a25f-49a8-a321-dc41c0fc032f', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_strike', 'Kehanet Vuruşu', 'Prophetic Strike', 'Düşmanın kaçış hareketlerini tahmin edin ve tam olarak olacakları yere vurun. 10m''ye kadar 2d6 arkana hasarı verir.', 'Predict the enemy''s evasive movements and strike exactly where they will be. Deals 2d6 arcane damage up to 10m.', 'Prophecy', 5, 100, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "2d6 arcane", "range": "10m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9cd4b3fc-cc74-4623-a0a1-f8595f53e04a', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_warning', 'Tehlike Alâmeti', 'Omen of Danger', 'Öngörülen bir pusu veya tuzağa karşı uyarıda bulunun. 15m yarıçapındaki müttefiklere bir sonraki kurtarma zarlarında +2 kazandırır.', 'Shout a warning of a predicted ambush or trap. Grants allies in a 15m radius +2 to their next saving throw.', 'Prophecy', 10, 150, 1, '{}', '{"x": 606, "y": -349}', '{"radius": "15m", "buff": "+2 Saving Throw"}', '⚠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e48f346f-6544-42f1-a133-e8322c2dfb75', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_echo', 'Geleceğin Yankıları', 'Echoes of the Future', 'Bir hedefe gelecekte yankılanan arkana enerjisiyle vurarak 3d8 hasar verin. Aynı hasar bir sonraki turlarında tekrarlanır.', 'Strike a target with a blast of arcane energy that echoes into the future, dealing 3d8 damage. The same damage repeats on their next turn.', 'Prophecy', 21, 200, 2, '{"om_prophecy_strike"}', '{"x": 822, "y": -474}', '{"damage": "3d8 arcane (x2)", "range": "20m"}', '⏱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('607afb46-7399-4431-8c7f-d35c184ee60a', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_delay', 'Gecikmiş Kader', 'Delayed Destiny', 'Size veya bir müttefikinize yönelen bir büyüyü veya etkiyi 1 tur geciktirerek hazırlanmak için zaman kazanın. Menzil 20m.', 'Delay an incoming spell or effect targeting you or an ally by 1 turn, allowing time to prepare. Range 20m.', 'Prophecy', 25, 250, 2, '{}', '{"x": 1039, "y": -599}', '{"range": "20m", "duration": "1 turn delay"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9b544c87-7059-44bf-a2e8-314a86ac4d74', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_shield', 'Öngörü Kalkanı', 'Shield of Foresight', 'Saldırıları önlemek için hareket eden öngörüsel bir kalkan oluşturun. 40 hasara kadar emer. Süre: 3 tur.', 'Create a predictive shield that moves to intercept attacks. Absorbs up to 40 damage. Duration: 3 turns.', 'Prophecy', 30, 300, 2, '{"om_prophecy_glimpse"}', '{"x": 1255, "y": -724}', '{"shield": "40 HP", "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4a3df770-fce1-40a5-a531-9c6339487232', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_vision', 'Gerçek Görüş', 'True Vision', '30m içindeki düşmanların yakın taktiksel niyetlerini okuyun. Bir sonraki saldırıları dezavantajlı olur.', 'Read the immediate tactical intent of enemies within 30m. Their next attacks have disadvantage.', 'Prophecy', 41, 400, 3, '{"om_prophecy_echo"}', '{"x": 1472, "y": -849}', '{"radius": "30m", "debuff": "Disadvantage on next attack"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c560bc9a-d237-4c93-9c10-0f83c2e949f7', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_paradox', 'Küçük Paradoks', 'Minor Paradox', 'Bölgesel bir zaman paradoksu yaratarak düşmanı son eylemini birebir tekrarlamaya zorlayın, ancak %50 başarısız olma ihtimaliyle.', 'Cause a localized time paradox, forcing an enemy to repeat their last action exactly, but with a 50% chance to fail.', 'Prophecy', 45, 450, 3, '{}', '{"x": 1688, "y": -974}', '{"range": "20m", "debuff": "Repeat action (50% fail)"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bc433d42-0abc-451f-993b-020bc07d0abf', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_convergence', 'Yakınsama', 'Convergence', 'Birden fazla gelecek zaman çizelgesini hizalayarak bir sonraki büyünüzün kesinlikle maksimum hasar vermesini sağlayın. 1 tur sürer.', 'Align multiple future timelines so that your next spell is guaranteed to deal maximum damage. Lasts 1 turn.', 'Prophecy', 50, 500, 3, '{"om_prophecy_delay"}', '{"x": 1905, "y": -1099}', '{"buff": "Max spell damage", "duration": "1 turn"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca2b0739-e45c-4775-9643-c85f9e9f3406', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_inevitable', 'Kaçınılmaz Yıkım', 'Inevitable Ruin', 'Kaçınılması imkansız yıkıcı bir vuruş çağırın. 40m uzaklığa kadar tek bir hedefe 6d10 arkana hasarı verir.', 'Call down a ruinous strike that cannot be avoided. Deals 6d10 arcane damage to a single target up to 40m away.', 'Prophecy', 61, 650, 4, '{"om_prophecy_vision"}', '{"x": 2121, "y": -1224}', '{"damage": "6d10 arcane", "range": "40m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('da1189c9-0b4c-4a68-b9fc-ddce8bd3daff', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_clairvoyant', 'Basiret Duruşu', 'Clairvoyant Stance', 'Saldırıları gerçekleşmeden önce algıladığınız bir transa girin. 3 tur boyunca %30 kaçınma ve tüm kurtarma zarlarında avantaj kazanın.', 'Enter a trance where you perceive attacks before they happen. Gain 30% evasion and advantage on all saves for 3 turns.', 'Prophecy', 65, 700, 4, '{}', '{"x": 2338, "y": -1349}', '{"buff": "+30% Evasion, Advantage on saves", "duration": "3 turns"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('794d133a-c164-4347-bf2a-dd0890dd3cdf', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_rewind', 'Zamanın Geri Sarımı', 'Time''s Ebb', '20m uzaklığa kadar tek bir müttefik için zamanı geri alarak HP''lerini yenileyin ve son turda uygulanan durumları kaldırın.', 'Rewind time for a single ally up to 20m away, restoring their HP and removing conditions applied in the last turn.', 'Prophecy', 70, 750, 4, '{"om_prophecy_paradox"}', '{"x": 2554, "y": -1474}', '{"range": "20m", "healing": "1 turn revert", "cleanse": "Yes"}', '⏪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae9033b9-1180-4ffb-a33c-6c528fcdab31', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_oracle', 'Kâhinin Sözleri', 'Words of the Oracle', 'Kehanet gücüyle dolu sözler söyleyin. 15m yarıçapındaki düşmanlar 5d8 psişik hasar alır ve 1 tur susturulur.', 'Speak words of prophetic power. Enemies in a 15m radius take 5d8 psychic damage and are silenced for 1 turn.', 'Prophecy', 75, 800, 4, '{}', '{"x": 2771, "y": -1599}', '{"radius": "15m", "damage": "5d8 psychic", "debuff": "Silence 1 turn"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('740a6fe0-0f1b-45c4-9060-dde0e6297467', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_prophecy_ultimate', 'Mutlak Kehanet', 'Absolute Prophecy', 'Savaş alanını mutlak bir kehanete kilitleyin. 3 tur boyunca tüm müttefik saldırıları isabet eder ve tüm düşman kurtarma zarları başarısız olur. Menzil: 50m.', 'Lock the battlefield into an absolute prophecy. For 3 turns, all allied attacks hit and all enemy saves fail. Range: 50m.', 'Prophecy', 90, 1200, 5, '{"om_prophecy_inevitable", "om_prophecy_rewind"}', '{"x": 2987, "y": -1724}', '{"range": "50m", "duration": "3 turns", "buff": "Guaranteed hits", "debuff": "Guaranteed save fails"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c21b314-0e3d-4362-9ab5-33946153447f', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_thread', 'Kader İpliği', 'Thread of Fate', 'Bir düşmanı bağlayan kader ipliğini görün ve çekin. 1d8 hasar verir ve 2 tur boyunca hareket hızlarını 3m azaltır.', 'See the thread of fate binding an enemy and pull it. Deals 1d8 damage and reduces their movement speed by 3m for 2 turns.', 'Fate', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8", "range": "20m", "debuff": "-3m speed", "duration": "2 turns"}', '🧵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('43574e21-c34b-4fbb-ad08-62c61335d0d1', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_jinx', 'Uğursuzluk', 'Jinx', 'Bir düşmanın şansını lanetleyin. 3 tur boyunca saldırı ve kurtarma zarlarından 1d4 çıkarmaları gerekir. Menzil 20m.', 'Curse an enemy''s luck. They must subtract 1d4 from their attack rolls and saving throws for 3 turns. Range 20m.', 'Fate', 5, 100, 1, '{}', '{"x": 289, "y": 344}', '{"range": "20m", "debuff": "-1d4 to rolls", "duration": "3 turns"}', '🐈‍⬛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8d05a146-8575-4a8a-9188-1db8022fea5a', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_boon', 'Talihin Lütfu', 'Fortune''s Boon', 'Bir müttefiki iyi şansla kutsayın. 2 tur içinde bir sonraki saldırı veya kurtarma zarında avantaj kazanırlar.', 'Bless an ally with good fortune. They gain advantage on their next attack roll or saving throw within 2 turns.', 'Fate', 10, 150, 1, '{}', '{"x": 449, "y": 536}', '{"range": "20m", "buff": "Advantage next roll", "duration": "2 turns"}', '🍀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('42ace7c7-090c-45bc-bd37-f024de39a041', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_link', 'Karmik Bağ', 'Karmic Link', '15m içindeki iki düşmanın kaderini bağlayın. Biri hasar aldığında, diğeri bu hasarın %50''sini alır. 3 tur sürer.', 'Bind the fates of two enemies within 15m. When one takes damage, the other takes 50% of that damage. Lasts 3 turns.', 'Fate', 21, 200, 2, '{"om_fate_thread"}', '{"x": 610, "y": 727}', '{"range": "15m", "debuff": "Shared Damage (50%)", "duration": "3 turns"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2611d3a4-b7dd-4b0f-acc0-f65b5620bacc', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_twist', 'Kaderin Cilvesi', 'Twist of Fate', 'Yakın zamandaki bir olayın sonucunu tersine çevirin. Bir müttefike yapılan kritik vuruşu normal bir vuruşa, veya bir düşman için tam tersine çevirin.', 'Reverse the outcome of a recent event. Turn a critical hit against an ally into a normal hit, or vice versa for an enemy.', 'Fate', 25, 250, 2, '{"om_fate_jinx"}', '{"x": 771, "y": 919}', '{"range": "30m", "effect": "Reverse outcome"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cedb00a2-d78b-49ee-a98b-d8ca078a035a', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_sever', 'İpliği Koparmak', 'Sever the Thread', 'Yaralı bir düşmanın kader ipliğini koparın. Eğer HP''leri %20''nin altındaysa, anında 4d10 nekrotik hasar alırlar.', 'Sever the thread of fate of a wounded enemy. If they are below 20% HP, they instantly take 4d10 necrotic damage.', 'Fate', 30, 300, 2, '{"om_fate_link"}', '{"x": 932, "y": 1110}', '{"range": "10m", "damage": "4d10 necrotic (if <20% HP)"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4671ada-383b-4d4b-a2c8-1537ad09f554', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_scales', 'Kaderin Terazisi', 'Scales of Destiny', 'Kaderin terazisini dengeleyin. 10m yarıçapındaki tüm müttefiklerin ve düşmanların HP''sini ortalayın. Menzil 30m.', 'Balance the scales of destiny. Average the HP of all allies and enemies in a 10m radius. Range 30m.', 'Fate', 41, 400, 3, '{}', '{"x": 1092, "y": 1302}', '{"range": "30m", "radius": "10m", "effect": "Average HP"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7dc4e357-c60e-49f4-b53e-7fe0bd5c51fc', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_weavers', 'Dokumacının Dokunuşu', 'Weaver''s Touch', 'Savaş alanını kontrol etmek için ruhani iplikler çağırın. Düşmanların yarı hızda hareket ettiği ve 3d6 hasar aldığı 20m''lik bir alan yaratır.', 'Summon ethereal threads to control the battlefield. Creates a 20m zone where enemies move at half speed and take 3d6 damage.', 'Fate', 45, 450, 3, '{"om_fate_twist"}', '{"x": 1253, "y": 1493}', '{"radius": "20m", "damage": "3d6", "debuff": "Half speed"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ffffaae8-dad3-4711-8d19-047607979e05', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_doom', 'Yaklaşan Kıyamet', 'Impending Doom', 'Bir düşmanı yaklaşan kıyametle işaretleyin. 3 tur sonra 8d8 arkana hasarı alırlar. Temizlenebilir.', 'Mark an enemy with impending doom. After 3 turns, they take 8d8 arcane damage. Can be cleansed.', 'Fate', 50, 500, 3, '{"om_fate_sever"}', '{"x": 1414, "y": 1685}', '{"range": "20m", "damage": "8d8 arcane after 3 turns"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ad4d6e41-a9fd-4f12-8f8b-531ea99307f7', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_puppet', 'Kaderin Kuklası', 'Puppet of Destiny', 'Bir düşmanın kaderinin kontrolünü elinize alın. Onları 10m''ye kadar hareket etmeye ve seçtiğiniz bir hedefe temel saldırı yapmaya zorlayın.', 'Take control of an enemy''s fate. Force them to move up to 10m and make a basic attack against a target of your choice.', 'Fate', 61, 650, 4, '{"om_fate_weavers"}', '{"x": 1574, "y": 1876}', '{"range": "20m", "effect": "Forced movement & attack"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('382cc610-e1b7-46b4-8d94-68834493f51d', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_rewrite', 'Tarihi Yeniden Yazmak', 'Rewrite History', 'Tarihi hafifçe yeniden yazın. Son turda kaçırılan bir büyüyü seçin ve kaynak harcamadan tekrar yapın.', 'Rewrite history slightly. Choose a missed spell from the last turn and cast it again without consuming resources.', 'Fate', 65, 700, 4, '{"om_fate_scales"}', '{"x": 1735, "y": 2068}', '{"effect": "Free recast of missed spell"}', '✒️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31c2aaab-15ce-43c3-a241-4fdecca082fe', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_chain', 'Kader Zincirleri', 'Chains of Destiny', '4 düşmana kadar birbirine zincirleyin. Birine uygulanan herhangi bir durum etkisi diğerlerine yayılır. Süre 3 tur, 20m menzil.', 'Chain up to 4 enemies together. Any status effect applied to one spreads to the others. Duration 3 turns, 20m range.', 'Fate', 70, 750, 4, '{}', '{"x": 1896, "y": 2259}', '{"range": "20m", "effect": "Link up to 4 targets", "duration": "3 turns"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('082cbd4c-d61d-418e-a3d5-30d0019462f2', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_ward', 'Talih Tılsımı', 'Ward of Fortune', 'Bir müttefikin üzerine mutlak talih tılsımı yerleştirin. Onları 1 HP''nin altına düşürecek bir sonraki hasar durumu, bunun yerine 1 HP''de bırakır.', 'Place a ward of absolute fortune on an ally. The next instance of damage that would drop them below 1 HP leaves them at 1 HP instead.', 'Fate', 75, 800, 4, '{"om_fate_doom"}', '{"x": 2056, "y": 2451}', '{"range": "15m", "buff": "Survive at 1 HP"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('003c7539-81a2-4158-9ba7-6bc5a7a2061c', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_fate_ultimate', 'Kaderlerin Efendisi', 'Master of Destinies', 'Kaderlerin Efendisi olun. 4 tur boyunca 40m yarıçapındaki tüm yazı tura, zar atışları ve rastgele etkilerin sonucuna siz karar verirsiniz.', 'Become the Master of Destinies. For 4 turns, you decide the outcome of all coin flips, dice rolls, and random effects in a 40m radius.', 'Fate', 90, 1200, 5, '{"om_fate_puppet", "om_fate_rewrite"}', '{"x": 2217, "y": 2642}', '{"radius": "40m", "duration": "4 turns", "effect": "Control RNG"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d73410b4-b115-4532-9807-610e75483338', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_sense', 'Aura Sezisi', 'Aura Sense', '20m içinde duvarların ardındaki büyü ve canlı varlıkların mevcudiyetini hissedin. Gizlenmiş veya görünmez varlıkları ortaya çıkarır.', 'Sense the presence of magic and living beings through walls within 20m. Reveals hidden or invisible entities.', 'Divination', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"radius": "20m", "effect": "Detect magic & entities"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f4654ef9-63ad-4750-906c-6214ca549880', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_scrying', 'Gözlem Gözü', 'Scrying Eye', '100m uzağa kadar görünmez bir sensör çağırarak o konumdan 10 dakikaya kadar görüp duyun.', 'Summon an invisible sensor up to 100m away to see and hear from that location for up to 10 minutes.', 'Divination', 5, 100, 1, '{}', '{"x": -289, "y": 344}', '{"range": "100m", "duration": "10 minutes", "effect": "Invisible sensor"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('372158b9-d193-42a4-be0b-edf0f54b14cb', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_truth', 'Doğruluk Alanı', 'Zone of Truth', '10m''lik bir alan yaratın. İçindeki varlıklar kasıtlı olarak yalan söyleyemez. 5 dakika sürer.', 'Create a 10m zone. Entities within cannot speak deliberate lies. Lasts 5 minutes.', 'Divination', 10, 120, 1, '{}', '{"x": -449, "y": 536}', '{"radius": "10m", "duration": "5 minutes", "effect": "No lies"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('15ec6d27-bcb8-4699-a892-92de546a057e', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_reveal', 'Gizleneni Açığa Çıkar', 'Reveal the Hidden', 'Bir düşmanın zayıf noktalarını açığa çıkarın. Onlara karşı yapılacak bir sonraki saldırı tüm zırh ve dirençleri yok sayar. Menzil 30m.', 'Reveal the weak points of an enemy. The next attack against them ignores all armor and resistances. Range 30m.', 'Divination', 15, 150, 1, '{}', '{"x": -610, "y": 727}', '{"range": "30m", "debuff": "Ignore armor/resist next attack"}', '🔦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d0c07f0c-4767-4599-b1d8-d2ab68e70703', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_mind', 'Zihin Sondası', 'Mind Probe', '15m içindeki bir düşmanın yüzeysel düşüncelerini sondalayın. Bir sonraki hamlelerine dair içgörü kazanarak onlara karşı avantaj elde edin.', 'Probe the surface thoughts of an enemy within 15m. Gain insight into their next move, granting you advantage against them.', 'Divination', 21, 200, 2, '{"om_divination_sense"}', '{"x": -771, "y": 919}', '{"range": "15m", "buff": "Advantage next turn"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d4201e41-42d9-4dc9-85f2-99b70fd4e350', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_path', 'Yol Bulucu', 'Pathfinder', 'Bir konuma giden en güvenli veya en hızlı yolu bulun. 2 tur boyunca tüm müttefiklere +%20 hareket hızı kazandırır.', 'Find the safest or fastest path to a location. Grants +20% movement speed to all allies for 2 turns.', 'Divination', 25, 250, 2, '{"om_divination_scrying"}', '{"x": -932, "y": 1110}', '{"radius": "30m", "buff": "+20% Move Speed", "duration": "2 turns"}', '🧭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3bf49ce-89cd-4c74-af0e-69eda4fbd9f6', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_pierce', 'Delici Bakış', 'Piercing Gaze', 'Bakışlarınız 40m içindeki illüzyonları ve büyülü kılıkları delip geçer. Bu tür büyüleri kullanan hedeflere 2d8 psişik hasar verir.', 'Your gaze pierces illusions and magical disguises within 40m. Deals 2d8 psychic damage to targets using such magic.', 'Divination', 30, 300, 2, '{"om_divination_truth"}', '{"x": -1092, "y": 1302}', '{"range": "40m", "damage": "2d8 psychic", "effect": "Dispels illusions"}', '🔭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b8e1932d-57d7-46a0-b9ef-b97093eb7c5d', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_omniscience', 'Her Şeyi Bilme Parıltıları', 'Flashes of Omniscience', 'Her şeyi bilme parıltısı yaşayın. 30m içindeki tüm düşmanların zayıflıklarını, dirençlerini ve mevcut HP''lerini tanımlayın.', 'Experience a flash of omniscience. Identify all vulnerabilities, resistances, and current HP of all enemies within 30m.', 'Divination', 41, 400, 3, '{"om_divination_mind"}', '{"x": -1253, "y": 1493}', '{"radius": "30m", "effect": "Reveal stats/weaknesses"}', '💡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b9914e6-5ef2-4e6f-bc76-52227b5230a9', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_soul', 'Ruhu Okumak', 'Read the Soul', 'Hedefin ruhunu okuyarak en derin korkularını öğrenin. Bilgelik kurtarma zarı atmalıdırlar, aksi takdirde 2 tur boyunca Korkmuş olurlar. Menzil 25m.', 'Read the target''s soul, learning their deepest fears. They must make a Wisdom save or become Frightened for 2 turns. Range 25m.', 'Divination', 45, 450, 3, '{"om_divination_pierce"}', '{"x": -1414, "y": 1685}', '{"range": "25m", "debuff": "Frightened", "duration": "2 turns"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2adc2dbd-429f-42d9-b24f-f77480d537a7', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_map', 'Astral Harita', 'Astral Map', 'Savaş alanının astral bir haritasını yansıtın. Müttefikler bir sonraki turlarında görünür herhangi bir konuma 10m''ye kadar ışınlanabilirler.', 'Project an astral map of the battlefield. Allies can teleport up to 10m to any visible location on their next turn.', 'Divination', 50, 500, 3, '{"om_divination_path"}', '{"x": -1574, "y": 1876}', '{"radius": "50m", "effect": "Teleport up to 10m next turn"}', '🗺️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2fab16fe-a6aa-4a52-81c4-d6d93d418409', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_secrets', 'Sırların Fısıltıları', 'Whispers of Secrets', 'Bölge veya bir eşya hakkındaki gizli bilgileri ortaya çıkarın. Ayrıca 15m yarıçapındaki tüm tuzakları veya büyülü kilitleri dağıtır.', 'Uncover hidden knowledge about the area or an item. Also dispels any traps or magical locks within a 15m radius.', 'Divination', 61, 650, 4, '{"om_divination_soul"}', '{"x": -1735, "y": 2068}', '{"radius": "15m", "effect": "Dispel traps/locks, uncover secrets"}', '🤫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('849b9a83-f447-48de-9797-ffd5b41738ad', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_eye', 'Her Şeyi Gören Göz', 'The All-Seeing Eye', 'Savaş alanının üzerinde Her Şeyi Gören Göz''ü çağırın. Büyü yapmaya çalışan düşmanlara ışınlar ateşleyerek 4d6 hasar verir.', 'Summon the All-Seeing Eye above the battlefield. It fires beams at enemies who attempt to cast spells, dealing 4d6 damage.', 'Divination', 65, 700, 4, '{"om_divination_omniscience"}', '{"x": -1896, "y": 2259}', '{"radius": "40m", "damage": "4d6 arcane", "effect": "Counter-attack casters"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb5bec53-567e-40de-a6f4-562b0ffced90', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_judgment', 'Yargı Gözü', 'Eye of Judgment', 'Bir hedefi geçmiş günahlarına göre yargılayın. Karşılaşmada öldürdükleri her düşman için 1d10 parlak hasar verir. Menzil 30m.', 'Judge a target based on their past sins. Deals 1d10 radiant damage for every enemy they have killed in the encounter. Range 30m.', 'Divination', 70, 750, 4, '{}', '{"x": -2056, "y": 2451}', '{"range": "30m", "damage": "1d10 radiant per kill"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('181cedd1-7747-4b8b-aed3-031028584186', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_divination_ultimate', 'Mutlak Bilgelik Varlığı', 'Omniscient Presence', 'Mutlak Bilgelik Varlığı olun. 3 tur boyunca harita tamamen açılır, görünmezlik iptal olur ve duvarların arkasından büyü yapabilirsiniz. Menzil: Küresel.', 'Become an Omniscient Presence. For 3 turns, the map is fully revealed, invisibility is nullified, and you can cast spells through walls. Range: Global.', 'Divination', 90, 1200, 5, '{"om_divination_secrets", "om_divination_eye"}', '{"x": -2217, "y": 2642}', '{"range": "Global", "duration": "3 turns", "effect": "Full vision, cast through walls"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff58d032-4dd2-45ab-b62a-0eb83115fd8e', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_cross_clairvoyant_strike', 'Basiretli Vuruş', 'Clairvoyant Strike', 'Öngörü ve bilgeliği birleştirin. Bir düşmanın zayıf noktasına o daha açığa çıkarmadan vurun. Kalkanları yok sayarak 4d8 hasar verir.', 'Combine foresight with omniscience. Strike an enemy''s precise weak point before they expose it. Deals 4d8 damage, ignoring shields.', 'Cross-Branch', 35, 300, 2, '{"om_prophecy_strike", "om_divination_sense"}', '{"x": -173, "y": -100}', '{"damage": "4d8", "range": "Weapon/Spell", "effect": "Ignores shields"}', '⚔️👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cc571dae-965f-41eb-9eef-8ab4e5008eee', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_cross_fated_vision', 'Kaderin Görüsü', 'Fated Vision', 'Kaderin ve niyetin iç içe geçen ipliklerini görün. Tüm müttefikler, daha düşük HP''ye sahip düşmanlara karşı %20 kritik vuruş şansı kazanır.', 'See the intertwining threads of destiny and intent. All allies gain a 20% critical hit chance against enemies with lower HP.', 'Cross-Branch', 55, 500, 3, '{"om_fate_twist", "om_divination_pierce"}', '{"x": -389, "y": -225}', '{"radius": "50m", "buff": "+20% Crit vs lower HP targets"}', '🔮🧵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('426f3c8c-dddf-44c6-a728-395b4b6a06b6', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_cross_prophetic_link', 'Kehanet Bağı', 'Prophetic Link', 'Bir müttefikin kaderini gelecekteki bir olaya bağlayın. Eğer 2 tur içinde ölürlerse, zaman 1 tur geri alınır ve tam sağlığa kavuşurlar.', 'Link an ally''s fate to a future event. If they die within 2 turns, time rewinds 1 turn and they are restored to full health.', 'Cross-Branch', 58, 500, 3, '{"om_prophecy_delay", "om_fate_link"}', '{"x": -606, "y": -350}', '{"range": "30m", "duration": "2 turns", "effect": "Auto-revive via time rewind"}', '🔗⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('212b75c9-1436-4240-a75f-d402b089d9b8', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_cross_thread_viewer', 'İplik Görücü', 'Thread Viewer', 'Düşmanlar arasındaki somut bağlantı ipliklerini görün. Bir hedefe 5d6 hasar verin; bu hasar onların güçlendirdiği herkese sıçrar.', 'See the literal threads of connection between enemies. Deal 5d6 damage to a target; this damage cascades to anyone they have buffed.', 'Cross-Branch', 75, 800, 4, '{"om_fate_weavers", "om_divination_map"}', '{"x": -822, "y": -475}', '{"range": "30m", "damage": "5d6", "effect": "Damage cascades to buffed targets"}', '👁️🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6399d00a-5d84-4218-88c8-9c38473f43a0', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_cross_time_weaver', 'Zaman Dokuyucu', 'Time Weaver', 'Zamanı ve kaderi birlikte dokuyun. 15m yarıçapındaki düşmanları 1 tur dondururken, aldıkları hasarı kalıcı olarak %15 artıracak şekilde kaderlerini değiştirin.', 'Weave time and fate together. Freeze enemies in a 15m radius for 1 turn while permanently altering their fate to increase damage taken by 15%.', 'Cross-Branch', 78, 850, 4, '{"om_prophecy_paradox", "om_fate_scales"}', '{"x": -1039, "y": -600}', '{"radius": "15m", "duration": "1 turn", "debuff": "Freeze & +15% Damage Taken"}', '🕰️✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a660c8bd-3210-4979-8506-1d3c2aa371f6', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_cross_all_knowing_strike', 'Her Şeyi Bilen Vuruş', 'All-Knowing Strike', 'Hedefin gelecekte yapacağı her hatayı sömüren zihinsel bir saldırı. 8d8 psişik hasar verir ve 1 tur sersemletir.', 'A mental attack that exploits every future mistake the target will make. Deals 8d8 psychic damage and stuns for 1 turn.', 'Cross-Branch', 80, 900, 4, '{"om_prophecy_vision", "om_divination_omniscience"}', '{"x": -1255, "y": -725}', '{"range": "20m", "damage": "8d8 psychic", "debuff": "Stun 1 turn"}', '⚡🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cbcb7061-4941-43be-a652-581c3d0eeb0d', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_cross_reality_shift', 'Gerçeklik Kayması', 'Reality Shift', 'Gerçekliği takımınızın kazandığı alternatif bir zaman çizelgesine kaydırın. Tüm müttefikleri maks HP''lerinin %30''u kadar iyileştirin ve tüm bekleme sürelerini 1 azaltın.', 'Shift reality to an alternate timeline where your team is winning. Heal all allies for 30% of max HP and reduce all cooldowns by 1.', 'Cross-Branch', 85, 1100, 5, '{"om_prophecy_rewind", "om_fate_rewrite"}', '{"x": -1472, "y": -850}', '{"radius": "Global", "healing": "30% Max HP", "effect": "Reduce cooldowns by 1"}', '🌌🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('21dac097-3d2e-45ed-80a6-b670742ffd3b', 'eb28a661-21fd-4a50-9992-eb7328fad584', 'om_grand_ultimate', 'Akaşik Kayıtlar', 'The Akashic Record', 'Tüm geçmişlerin, bugünlerin ve geleceklerin arşivi olan Akaşik Kayıtlara erişin. 5 tur boyunca savaşın akışını kontrol edersiniz: düşmanlar iki kat hasar alır, müttefikler yarı hasar alır ve tüm düşman eylemlerini tahmin edersiniz. Menzil: 100m.', 'Access the Akashic Record, the archive of all pasts, presents, and futures. For 5 turns, you control the flow of battle: enemies take double damage, allies take half damage, and you predict all enemy actions. Range: 100m.', 'Cross-Branch', 100, 1500, 5, '{"om_prophecy_ultimate", "om_fate_ultimate", "om_divination_ultimate"}', '{"x": -1688, "y": -975}', '{"range": "100m", "duration": "5 turns", "effect": "Double enemy dmg taken, half ally dmg taken, predict actions"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('724593a3-59a9-4978-a7d6-87c830f9ed67', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_celestial_mote', 'Semavi Zerre', 'Celestial Mote', 'Düşmanları vurması için parlayan semavi bir zerre çağırır. 1d6 parlak hasar verir.', 'Summon a glowing celestial mote to strike foes. Deals 1d6 radiant damage.', 'Celestial', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d6", "range": "10m", "damage_type": "radiant"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70978056-5b36-4dfe-929a-542bf84b9591', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_star_sprite', 'Yıldız Perisi', 'Star Sprite', 'Işık saçan ve 1 dostu 2 tur boyunca 1d4 SB iyileştiren küçük bir yıldız perisi çağırır.', 'Summon a tiny star sprite that provides light and heals 1 ally for 1d4 HP over 2 turns.', 'Celestial', 3, 80, 1, '{}', '{"x": 389, "y": -224}', '{"healing": "1d4", "duration": "2 turns", "range": "5m"}', '🧚‍♀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24423076-bc27-492a-aa61-953e01dcc3c8', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_minor_angel', 'Küçük Melek', 'Minor Angel', 'Işıktan kılıcıyla saldıran küçük bir melek çağırır, bir düşmana 1d8 parlak hasar verir.', 'Summon a minor angel that attacks with a light blade, dealing 1d8 radiant damage to an enemy.', 'Celestial', 8, 100, 1, '{"ors_celestial_mote"}', '{"x": 606, "y": -349}', '{"damage": "1d8", "range": "5m", "damage_type": "radiant"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c80ac79-cb90-429d-b384-7e55326e930d', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_aegis_orb', 'Kalkan Küresi', 'Aegis Orb', 'Bir dostun etrafında dönen ve 3 tur boyunca +2 ZS sağlayan bir ışık küresi çağırır.', 'Summon an orb of light that orbits an ally, granting +2 AC for 3 turns.', 'Celestial', 15, 130, 1, '{"ors_star_sprite"}', '{"x": 822, "y": -474}', '{"ac_bonus": 2, "duration": "3 turns", "range": "10m"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b92adf3-442a-4623-878a-a1fae96ddc88', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_celestial_hound', 'Semavi Tazı', 'Celestial Hound', 'Düşmanın izini süren ve onu ısırarak 2d6 parlak hasar veren semavi bir tazı çağırır. Vurmak için 15m''ye kadar hareket eder.', 'Summon a celestial hound that tracks and bites an enemy for 2d6 radiant damage. It moves up to 15m to strike.', 'Celestial', 22, 180, 2, '{"ors_minor_angel"}', '{"x": 1039, "y": -599}', '{"damage": "2d6", "range": "15m", "damage_type": "radiant"}', '🐕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29c41081-ac9c-40bd-a385-44c9022c9a30', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_sun_flare_wisp', 'Güneş Parıltısı Alevciği', 'Sun Flare Wisp', '5m yarıçapında patlayarak 3d6 parlak/ateş hasarı veren ve %30 ihtimalle 1 tur kör eden bir alevcik çağırır.', 'Summon a wisp that explodes in a 5m radius, dealing 3d6 radiant/fire damage with a 30% chance to blind for 1 turn.', 'Celestial', 28, 220, 2, '{"ors_aegis_orb"}', '{"x": 1255, "y": -724}', '{"damage": "3d6", "radius": "5m", "blind_chance": "30%", "duration": "1 turn"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('38b49b47-5f58-457d-8b4f-979308719e3b', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_guardian_cherub', 'Koruyucu Kerub', 'Guardian Cherub', 'Bir dosta yönelik her tur 1 saldırının arasına giren ve 3 tur boyunca 15 hasara kadar emen bir kerub çağırır.', 'Summon a cherub that intercepts 1 attack per turn targeting an ally, absorbing up to 15 damage for 3 turns.', 'Celestial', 35, 280, 2, '{"ors_sun_flare_wisp"}', '{"x": 1472, "y": -849}', '{"damage_absorption": 15, "duration": "3 turns", "range": "10m"}', '👶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13b72273-41a5-44e0-a380-cae64f579094', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_starlight_valkyrie', 'Yıldızışığı Valkür', 'Starlight Valkyrie', 'Aşağı süzülerek 20m''lik bir hat üzerindeki hedeflere 4d8 parlak hasar veren bir valkür çağırır.', 'Summon a valkyrie that swoops down, dealing 4d8 radiant damage to targets in a 20m line.', 'Celestial', 42, 380, 3, '{"ors_celestial_hound"}', '{"x": 1688, "y": -974}', '{"damage": "4d8", "area": "20m line", "damage_type": "radiant"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ed44e50-ec0f-47ff-8b12-99c55c0b4b1a', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_constellation_weaver', 'Takımyıldız Dokumacı', 'Constellation Weaver', 'Düşmanları yıldızlı iplerle bağlayarak kısıtlayan ve 3d6 parlak hasar veren bir dokumacı çağırır.', 'Summon a weaver that ties enemies in starry threads, restraining them and dealing 3d6 radiant damage.', 'Celestial', 50, 420, 3, '{"ors_starlight_valkyrie"}', '{"x": 1905, "y": -1099}', '{"damage": "3d6", "status": "restrained", "range": "15m"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('27094b1d-1df5-4e1b-8072-e1c1d9ba4cc0', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_moon_blessing_spirit', 'Ay Kutsaması Ruhu', 'Moon Blessing Spirit', 'Bir alanı ay ışığıyla yıkayarak 10m içindeki tüm dostları 3d8 SB iyileştiren bir ruh çağırır.', 'Summons a spirit that bathes an area in moonlight, restoring 3d8 HP to all allies within 10m.', 'Celestial', 58, 480, 3, '{"ors_guardian_cherub"}', '{"x": 2121, "y": -1224}', '{"healing": "3d8", "radius": "10m"}', '🌕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a548fbdb-43ab-4308-b7b2-78b3baf89f48', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_archangel_avatar', 'Başmelek Avatarı', 'Archangel Avatar', '6d8 parlak hasar veren ve 15m içindeki dostlara +4 ZS sağlayan bir aura yayan güçlü bir başmelek avatarı çağırır.', 'Summon a powerful archangel avatar that deals 6d8 radiant damage and projects an aura granting +4 AC to allies in 15m.', 'Celestial', 65, 650, 4, '{"ors_starlight_valkyrie"}', '{"x": 2338, "y": -1349}', '{"damage": "6d8", "ac_bonus": 4, "aura_radius": "15m"}', '🪽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64c79925-086b-4b44-bd88-01de7662428e', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_solar_charioteer', 'Güneş Savaş Arabacısı', 'Solar Charioteer', 'Düşmanların arasından geçerek 15m''lik bir hatta 8d6 parlak hasar veren ve onları yere seren ateşten bir savaş arabası çağırır.', 'Summon a fiery chariot that crashes through enemies in a 15m line, dealing 8d6 radiant damage and knocking them prone.', 'Celestial', 72, 750, 4, '{"ors_constellation_weaver"}', '{"x": 2554, "y": -1474}', '{"damage": "8d6", "area": "15m line", "status": "prone"}', '🌞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f2fdfe6-cf66-4f1d-8171-129262476c20', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_supernova_elemental', 'Süpernova Elementali', 'Supernova Elemental', '3 tur boyunca 10m içindeki tüm düşmanlara her tur 4d6 parlak/ateş hasarı yayan ölen bir yıldızın elementalini çağırır.', 'Summon an elemental of dying star energy that radiates 4d6 radiant/fire damage per turn to all enemies within 10m for 3 turns.', 'Celestial', 78, 850, 4, '{"ors_moon_blessing_spirit"}', '{"x": 2771, "y": -1599}', '{"damage": "4d6", "radius": "10m", "duration": "3 turns"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1405060c-6ade-43d8-8c89-69dc4dfafd9d', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_seraph_of_the_cosmos', 'Kozmosun Serafı', 'Seraph of the Cosmos', '(Ulti) Çok kanatlı bir Seraf çağırır. 20m yarıçapında 12d10 parlak hasar verir ve 3 tur boyunca karanlık büyüye mutlak bağışıklık sağlar.', '(Ultimate) Summon a multi-winged Seraph. Deals 12d10 radiant damage in a 20m radius and grants absolute immunity to dark magic for 3 turns.', 'Celestial', 90, 1200, 5, '{"ors_archangel_avatar", "ors_solar_charioteer", "ors_supernova_elemental"}', '{"x": 2987, "y": -1724}', '{"damage": "12d10", "radius": "20m", "immunity": "dark magic", "duration": "3 turns"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70e0a826-7dcc-4d2b-9ced-dd8aafe04d1f', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_echo_spirit', 'Yankı Ruhu', 'Echo Spirit', 'Çağırıcının son büyüsünü veya saldırısını %50 güçle kusursuzca taklit eden bir ruh çağırır.', 'Summon a spirit that perfectly mimics the summoner''s last spell or attack at 50% power.', 'Spirit', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"power_scaling": "50%"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7dd290ab-805f-4da9-97c1-0c6acbee22ef', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_ancestral_shield', 'Atasal Kalkan', 'Ancestral Shield', '10m içindeki bir dosta 10 geçici SB sağlaması için atalardan bir ruh çağırır.', 'Summon a spirit ancestor to grant 10 temporary HP to an ally within 10m.', 'Spirit', 6, 90, 1, '{}', '{"x": 289, "y": 344}', '{"temp_hp": 10, "range": "10m"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('faa09cfb-8afb-44fb-b1b6-32a65e5c3a78', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_future_wisp', 'Gelecek Alevciği', 'Future Wisp', 'Bir dostun elini yönlendirerek sonraki saldırı zarına +1d4 ekleyen gelecekten bir alevcik çağırır.', 'Summon a wisp from the future that guides an ally''s hand, granting +1d4 to their next attack roll.', 'Spirit', 12, 110, 1, '{"ors_echo_spirit"}', '{"x": 449, "y": 536}', '{"attack_bonus": "1d4", "range": "15m"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('007b2f8d-2af4-431f-adb7-f60e38b1d7c3', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_poltergeist_shove', 'Gürültücü Ruh İtişi', 'Poltergeist Shove', 'Bir düşmanı agresifçe 5m geriye iten ve 1d6 güç hasarı veren gürültücü bir ruh çağırır.', 'Summon a poltergeist to aggressively push an enemy 5m backwards and deal 1d6 force damage.', 'Spirit', 18, 140, 1, '{"ors_ancestral_shield"}', '{"x": 610, "y": 727}', '{"damage": "1d6", "knockback": "5m", "damage_type": "force"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8cef1b59-b079-44d5-a6df-63bc6b6aa43f', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_ethereal_knight', 'Ruhani Şövalye', 'Ethereal Knight', 'Düşmana hayalet bir kılıçla saldırarak 2d8 güç hasarı veren ruhani bir şövalye çağırır.', 'Summon an ethereal knight that strikes an enemy with a spectral sword for 2d8 force damage.', 'Spirit', 24, 190, 2, '{"ors_future_wisp"}', '{"x": 771, "y": 919}', '{"damage": "2d8", "range": "5m", "damage_type": "force"}', '🤺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4e356fc7-f3f6-451d-b00e-33299982460a', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_spirit_link_totem', 'Ruh Bağı Totemi', 'Spirit Link Totem', '3 turluğuna hayalet bir totem çağırır. 10m içindeki dostların aldığı hasar aralarında eşit olarak paylaştırılır.', 'Summon a spectral totem for 3 turns. Damage taken by allies within 10m is split evenly among them.', 'Spirit', 32, 240, 2, '{"ors_poltergeist_shove"}', '{"x": 932, "y": 1110}', '{"damage_split": true, "duration": "3 turns", "radius": "10m"}', '🪬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d455ffa7-6538-4bf2-a1ac-8fb8dbcb244d', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_phantom_steed', 'Hayalet Binek', 'Phantom Steed', '1 saatliğine binicisine +20m hareket hızı ve küçük engellerin içinden geçme yeteneği sağlayan hızlı bir ruhani binek çağırır.', 'Summon a fast spirit steed for 1 hour, granting the rider +20m movement speed and the ability to move through minor obstacles.', 'Spirit', 38, 290, 2, '{"ors_spirit_link_totem"}', '{"x": 1092, "y": 1302}', '{"speed_bonus": "20m", "duration": "1 hour"}', '🐎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09d548c1-fe12-45b8-938a-da4b323b93ff', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_guardian_of_tomorrow', 'Yarının Muhafızı', 'Guardian of Tomorrow', 'Yaklaşan saldırılara karşı uyararak 10m içindeki dostlara 2 tur boyunca kurtarma zarlarında avantaj sağlayan bir muhafız çağırır.', 'Summon a guardian that warns of impending attacks, granting advantage on saving throws to allies in 10m for 2 turns.', 'Spirit', 45, 390, 3, '{"ors_ethereal_knight"}', '{"x": 1253, "y": 1493}', '{"advantage_saves": true, "radius": "10m", "duration": "2 turns"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('891995e4-2724-408b-a515-add0a89fcb48', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_vengeful_wraith', 'İntikamcı İfrit', 'Vengeful Wraith', 'Çağırıcıya hasar veren son düşmana acımasızca saldırarak 4d6 nekrotik/güç hasarı veren bir ifrit çağırır.', 'Summon a wraith that relentlessly attacks the last enemy who damaged the summoner, dealing 4d6 necrotic/force damage.', 'Spirit', 52, 440, 3, '{"ors_spirit_link_totem"}', '{"x": 1414, "y": 1685}', '{"damage": "4d6", "damage_type": "necrotic/force"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aba45004-9986-4b86-8eca-4202d34adbf2', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_spirit_storm_caller', 'Ruh Fırtınası Çağırıcısı', 'Spirit Storm Caller', '10m yarıçapında ruhani yıldırımlar yağdırarak düşmanlara 5d6 yıldırım/güç hasarı veren bir ruh çağırır.', 'Summon a spirit that rains ethereal lightning in a 10m radius, dealing 5d6 lightning/force damage to enemies.', 'Spirit', 59, 490, 3, '{"ors_phantom_steed"}', '{"x": 1574, "y": 1876}', '{"damage": "5d6", "radius": "10m", "damage_type": "lightning/force"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3450c38-a7ac-44be-a547-eb695b8c9619', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_future_self_echo', 'Gelecekteki Benlik Yankısı', 'Future Self Echo', 'Gelecekteki benliğinizin bir yankısını çağırır. 2 tur boyunca, yaptığınız her büyüyü aynı hedeflere %50 etkiyle kopyalar.', 'Summon an echo of your future self. For 2 turns, it copies every spell you cast at the same targets for 50% effect.', 'Spirit', 68, 700, 4, '{"ors_guardian_of_tomorrow"}', '{"x": 1735, "y": 2068}', '{"spell_copy": "50%", "duration": "2 turns"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('37bae30f-83dc-4fda-922b-7f5e6559c68e', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_legion_of_ancestors', 'Atalar Lejyonu', 'Legion of Ancestors', '15m''lik bir duvar oluşturan ruhlardan bir falanks çağırır. Düşman hareketini engeller ve geçmeye çalışanlara 6d6 güç hasarı verir.', 'Summon a phalanx of spirits forming a 15m wall. Blocks enemy movement and deals 6d6 force damage to those attempting to cross.', 'Spirit', 74, 800, 4, '{"ors_vengeful_wraith"}', '{"x": 1896, "y": 2259}', '{"damage": "6d6", "wall_length": "15m", "movement_block": true}', '🎖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6650698d-3d35-4023-b2ef-7571a79a2b32', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_ethereal_dragon', 'Ruhani Ejderha', 'Ethereal Dragon', '15m''lik bir koni şeklinde ruhani ateş püskürten, 8d8 güç hasarı veren ve tüm zırhları yok sayan hayalet bir ejderha çağırır.', 'Summon a spectral dragon that breathes ethereal fire in a 15m cone, dealing 8d8 force damage and ignoring all armor.', 'Spirit', 79, 880, 4, '{"ors_spirit_storm_caller"}', '{"x": 2056, "y": 2451}', '{"damage": "8d8", "area": "15m cone", "armor_penetration": true}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb58aafb-8ec0-4848-9ca6-a439fadafaf3', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_spirit_king_incarnate', 'Ruh Kralı Tezahürü', 'Spirit King Incarnate', '(Ulti) Ruh Kralı''nı çağırır. Tüm dostlara 50 Geçici SB sağlar ve 30m içindeki tüm düşmanlara 10d10 güç hasarı veren bir şok dalgası salar.', '(Ultimate) Summon the Spirit King. Grants 50 Temp HP to all allies and unleashes a shockwave dealing 10d10 force damage to all enemies within 30m.', 'Spirit', 92, 1300, 5, '{"ors_future_self_echo", "ors_legion_of_ancestors", "ors_ethereal_dragon"}', '{"x": 2217, "y": 2642}', '{"temp_hp": 50, "damage": "10d10", "radius": "30m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fdc69ace-03a9-4537-a0db-fce4fd563590', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_omen_raven', 'Alamet Kuzgunu', 'Omen Raven', 'Bir hedefi işaretleyen bir öngörü kuzgunu çağırır. Ona yapılan sonraki saldırı fazladan 1d8 hasar verir.', 'Summon a raven of premonition that marks a target. The next attack against them deals an additional 1d8 damage.', 'Premonition', 4, 70, 1, '{}', '{"x": -128, "y": 153}', '{"bonus_damage": "1d8", "range": "20m"}', '🐦‍⬛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e39965d3-716e-41a3-9b00-82fea4192094', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_delayed_strike_ward', 'Gecikmeli Vuruş Mührü', 'Delayed Strike Ward', 'Çağrılmış ruhani bir tuzak yerleştirir. Bir düşman 3m''lik alanına girdiğinde tetiklenir ve 2d6 psişik hasar vurur.', 'Place a summoned ethereal trap. It triggers when an enemy enters its 3m space, striking for 2d6 psychic damage.', 'Premonition', 9, 100, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "2d6", "trigger_radius": "3m", "damage_type": "psychic"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7887fd6f-5213-48e8-893c-d808bfb3f889', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_glimpse_sprite', 'Görü Perisi', 'Glimpse Sprite', 'Bir dosta yakın geleceğin kısa bir görüsünü sağlayarak sonraki saldırı zarında avantaj veren bir peri çağırır.', 'Summon a sprite that grants 1 ally a brief vision of the immediate future, granting advantage on their next attack roll.', 'Premonition', 14, 120, 1, '{"ors_omen_raven"}', '{"x": -449, "y": 536}', '{"advantage_attack": true, "range": "15m"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('df39558b-65af-4b3c-99d4-7b4712a95f66', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_fates_dice', 'Kaderin Zarları', 'Fate''s Dice', 'Kaderi belirlemek için hayalet zarlar çağırır. 1d6 atılır: tekler hedef düşmana 2d6 psişik hasar verir, çiftler hedef dostu 2d6 SB iyileştirir.', 'Summon spectral dice to decide fate. Roll 1d6: odds deal 2d6 psychic damage to target enemy, evens heal a targeted ally for 2d6 HP.', 'Premonition', 19, 150, 1, '{"ors_delayed_strike_ward"}', '{"x": -610, "y": 727}', '{"damage": "2d6", "healing": "2d6", "range": "15m"}', '🎲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b914166-7cb5-4a35-8c3d-a3481a131fe1', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_prophecy_weaver', 'Kehanet Dokumacı', 'Prophecy Weaver', 'Düşmanın zaman çizelgesini karıştıran, hızını 5m ve ZS''sini 2 azaltan bir dokumacı çağırır, 3 tur sürer.', 'Summon a weaver that tangles an enemy''s timeline, reducing their speed by 5m and AC by 2 for 3 turns.', 'Premonition', 25, 200, 2, '{"ors_glimpse_sprite"}', '{"x": -771, "y": 919}', '{"speed_reduction": "5m", "ac_reduction": 2, "duration": "3 turns"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ff50c4b-9c16-4b47-96e8-85004ff9cdec', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_trap_of_foresight', 'Öngörü Tuzağı', 'Trap of Foresight', 'Görünmez ruhani bir tuzak çağırır. Bir düşman yakınında büyü yapmaya çalışırsa şiddetle tetiklenerek 3d8 güç hasarı verir.', 'Summon an invisible ethereal trap. It violently triggers for 3d8 force damage if an enemy attempts to cast a spell near it.', 'Premonition', 30, 230, 2, '{"ors_fates_dice"}', '{"x": -932, "y": 1110}', '{"damage": "3d8", "trigger": "spell cast", "range": "15m"}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1c92b377-b170-4325-8092-e07e692c70e8', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_visionary_owl', 'Vizyoner Baykuş', 'Visionary Owl', '20m yarıçapındaki tüm görünmez, gizlenmiş veya kılık değiştirmiş varlıkları ortaya çıkaran saf öngörüden oluşmuş bir baykuş çağırır.', 'Summon an owl of pure foresight that reveals all invisible, stealthed, or disguised entities within a 20m radius.', 'Premonition', 36, 270, 2, '{"ors_prophecy_weaver"}', '{"x": -1092, "y": 1302}', '{"reveal": true, "radius": "20m"}', '🦉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('968b0847-63d9-4402-951d-1fb9ae67e086', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_oracle_sphinx', 'Kahin Sfenks', 'Oracle Sphinx', 'Bilmeceler soran bir sfenks çağırır. Hedef ZEKA zarı atmalıdır, başarısız olursa 1 tur felç olur ve 4d8 psişik hasar alır.', 'Summon a sphinx that asks a riddle. Target must make an INT save or be paralyzed for 1 turn and take 4d8 psychic damage.', 'Premonition', 44, 400, 3, '{"ors_trap_of_foresight"}', '{"x": -1253, "y": 1493}', '{"damage": "4d8", "status": "paralyzed", "duration": "1 turn", "save": "INT"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3f43282c-67b8-4462-9bd4-b7d0a18a7fbd', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_karma_mirror', 'Karma Aynası', 'Karma Mirror', 'Bir dostun etrafını saran ve gelen tüm hasarın %50''sini 3 tur boyunca saldıranlara geri yansıtan bir ayna varlık çağırır.', 'Summon a mirror entity that surrounds an ally, reflecting 50% of all incoming damage back to attackers for 3 turns.', 'Premonition', 51, 450, 3, '{"ors_visionary_owl"}', '{"x": -1414, "y": 1685}', '{"reflect": "50%", "duration": "3 turns"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b7842b87-373a-46c9-a1d8-c01c07d31821', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_timeline_fracture', 'Zaman Çizelgesi Kırılması', 'Timeline Fracture', '10m yarıçapında zamansal bir anormallik çağırır. Düşmanlar 5d6 psişik hasar alır ve 2 tur boyunca kurtarma zarlarını iki kez atıp düşük olanı kullanmak zorundadır.', 'Summon a temporal anomaly in a 10m radius. Enemies take 5d6 psychic damage and must roll twice and use the lower result for saves for 2 turns.', 'Premonition', 57, 480, 3, '{"ors_oracle_sphinx"}', '{"x": -1574, "y": 1876}', '{"damage": "5d6", "disadvantage_saves": true, "duration": "2 turns", "radius": "10m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0fac6d91-4425-42bf-9bca-c6b6cc9ba0ff', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_doombringer_herald', 'Kıyamet Habercisi', 'Doombringer Herald', 'Sonun habercisini çağırır. 2 turluk gecikmenin ardından kaçınılmaz bir kıyametle patlayarak 20m yarıçapında 10d6 nekrotik/psişik hasar verir.', 'Summon a herald of the end. After a 2-turn delay, it explodes in inevitable doom, dealing 10d6 necrotic/psychic damage in a 20m radius.', 'Premonition', 66, 680, 4, '{"ors_oracle_sphinx"}', '{"x": -1735, "y": 2068}', '{"damage": "10d6", "radius": "20m", "delay": "2 turns"}', '🔔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('154ff4d9-77ba-4696-8125-cc594833d770', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_fate_rewinder', 'Kader Geri Sarıcı', 'Fate Rewinder', '1 dost için zamanı geriye saran ve canını anında bir önceki turunun başındaki haline getiren bir ruh çağırır.', 'Summon a spirit that rewinds time for 1 ally, instantly restoring their HP to what it was at the start of their last turn.', 'Premonition', 75, 780, 4, '{"ors_karma_mirror"}', '{"x": -1896, "y": 2259}', '{"healing": "restore previous state", "range": "15m"}', '⏪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6fe5c6b6-b2b8-4264-8ec4-a522584b7cec', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_destiny_warden', 'Kader Muhafızı', 'Destiny Warden', '15m içindeki dostlara gelecek olan sonraki 3 kritik vuruşu veya ölümcül darbeyi tamamen geçersiz kılan bir kader muhafızı çağırır.', 'Summon a warden of fate that completely nullifies the next 3 critical hits or fatal blows against any allies within 15m.', 'Premonition', 80, 900, 4, '{"ors_timeline_fracture"}', '{"x": -2056, "y": 2451}', '{"nullify_crits": 3, "radius": "15m"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('db726b3f-b9c5-44ef-b98a-401a00084653', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_avatar_of_fate', 'Kaderin Avatarı', 'Avatar of Fate', '(Ulti) Kaderin Avatarını çağırır. Girişte 10d10 psişik hasar verir. 2 tur boyunca 20m içindeki tüm dost saldırıları otomatik kritik vurur ve düşman saldırıları dezavantajlı olur.', '(Ultimate) Summon the Avatar of Fate. 10d10 psychic damage on entry. For 2 turns, all ally attacks in 20m auto-crit, and all enemy attacks have disadvantage.', 'Premonition', 94, 1400, 5, '{"ors_doombringer_herald", "ors_fate_rewinder", "ors_destiny_warden"}', '{"x": -2217, "y": 2642}', '{"damage": "10d10", "auto_crit": true, "disadvantage_attacks": true, "duration": "2 turns", "radius": "20m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e43014ac-3de5-4341-9ceb-92b102156990', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_star_ghost', 'Yıldız Hayaleti', 'Star Ghost', 'Yıldız ışığından dokunmuş bir ruh çağırır. Engellerin içinden süzülerek bir hedefe 3d6 parlak ve 1d6 güç hasarı verir.', 'Summon a spirit woven of starlight. It floats through obstacles and strikes a target for 3d6 radiant and 1d6 force damage.', 'Cross-Branch', 31, 250, 2, '{"ors_aegis_orb", "ors_ethereal_knight"}', '{"x": -173, "y": -100}', '{"damage": "3d6 radiant, 1d6 force", "range": "15m", "ignore_cover": true}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('971c7880-3757-4177-b2dc-c73f248c80b4', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_constellation_of_destiny', 'Kader Takımyıldızı', 'Constellation of Destiny', 'Yerde yıldızlı bir harita çağırır (10m yarıçap). Üzerinde duran dostlar 3 tur boyunca +3 ZS kazanır ve saldırılarına +1d6 parlak hasar ekler.', 'Summon a starry map on the ground (10m radius). Allies standing on it gain +3 AC and add +1d6 radiant to their attacks for 3 turns.', 'Cross-Branch', 48, 420, 3, '{"ors_starlight_valkyrie", "ors_trap_of_foresight"}', '{"x": -389, "y": -225}', '{"ac_bonus": 3, "bonus_damage": "1d6 radiant", "duration": "3 turns", "radius": "10m"}', '🗺️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40533845-05af-4232-91ea-d3de477f5f0f', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_echo_of_doom', 'Kıyamet Yankısı', 'Echo of Doom', 'Düşmanın gelecekteki ölümünü taklit eden korkutucu bir ruh çağırır. 6d6 psişik/güç hasarı verir ve hedefi 1 tur korkutur.', 'Summon a terrifying spirit that mimics an enemy''s future death. Deals 6d6 psychic/force damage and frightens the target for 1 turn.', 'Cross-Branch', 55, 460, 3, '{"ors_guardian_of_tomorrow", "ors_oracle_sphinx"}', '{"x": -606, "y": -350}', '{"damage": "6d6", "status": "frightened", "duration": "1 turn", "range": "15m"}', '😱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c2d42cd-8f68-40d1-b9d5-305ea11ef69d', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_trinity_wisp', 'Üçleme Alevciği', 'Trinity Wisp', 'Etrafınızda dönen, tüm kurtarma zarlarına +4, 20 Geçici SB sağlayan ve saldıranlara 2d8 parlak hasarla karşılık veren üç farklı alevcik çağırır.', 'Summon three distinct wisps that orbit you, granting +4 to all saves, 20 Temp HP, and counter-attacking attackers for 2d8 radiant damage.', 'Cross-Branch', 69, 720, 4, '{"ors_moon_blessing_spirit", "ors_spirit_storm_caller", "ors_karma_mirror"}', '{"x": -822, "y": -475}', '{"save_bonus": 4, "temp_hp": 20, "counter_damage": "2d8 radiant", "duration": "3 turns"}', '❇️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4f502930-7260-4bc3-9d99-518dabc4dbe3', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_ethereal_archangel', 'Ruhani Başmelek', 'Ethereal Archangel', 'Boyutlar arasına geçmiş bir melek çağırır. Fiziksel saldırılara karşı bağışıktır ve 15m yarıçapında 8d8 parlak/güç hasarı veren bir patlama salar.', 'Summon an angel phased between planes. It is immune to physical attacks and unleashes a blast dealing 8d8 radiant/force damage in a 15m radius.', 'Cross-Branch', 76, 820, 4, '{"ors_archangel_avatar", "ors_ethereal_dragon"}', '{"x": -1039, "y": -600}', '{"damage": "8d8", "radius": "15m", "immunity": "physical"}', '⚜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('243be4eb-17d1-498d-bc72-98425bd0d955', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_chronos_wraith', 'Zaman İfriti', 'Chronos Wraith', 'Bir düşmanı hızla yaşlandıran, 8d8 nekrotik/psişik hasar veren ve 3 tur boyunca hareket hızını 10m azaltan bir zaman ifriti çağırır.', 'Summon a time wraith that ages an enemy rapidly, dealing 8d8 necrotic/psychic damage and reducing their movement speed by 10m for 3 turns.', 'Cross-Branch', 77, 850, 4, '{"ors_legion_of_ancestors", "ors_fate_rewinder"}', '{"x": -1255, "y": -725}', '{"damage": "8d8", "speed_reduction": "10m", "duration": "3 turns", "range": "15m"}', '⌛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('573ab23e-df3d-4e55-89b8-9c7450e9cac5', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_prophet_of_the_sun', 'Güneş Peygamberi', 'Prophet of the Sun', 'Düşmanların *olacağı* yerlere 3 ışık huzmesi indiren bir güneş peygamberi çağırır. Her biri 5m yarıçapında 5d10 parlak hasar verir.', 'Summon a solar prophet that predicts enemy movements, calling down 3 beams of light where enemies *will* be. Each deals 5d10 radiant damage in a 5m radius.', 'Cross-Branch', 85, 1100, 5, '{"ors_supernova_elemental", "ors_destiny_warden"}', '{"x": -1472, "y": -850}', '{"damage": "5d10 per beam", "radius": "5m per beam", "strikes": 3}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('730779e8-3a9e-431e-9e6b-ffb68d87783f', '2df3a504-d8d8-4164-8368-2b5d9d828c14', 'ors_omniscience_convergence', 'Her Şeyi Bilme Birleşimi', 'Omniscience Convergence', '(Büyük Ulti) Her Şeyi Bilen Varlığı çağırır. Tüm dostları tamamen iyileştirir, 30m içindeki ölü dostları diriltir ve tüm düşmanlara 20d12 parlak/psişik/güç hasarı vererek onları mevcut zaman çizelgesinden siler.', '(Grand Ultimate) Summon the Omniscient Entity. It heals all allies to full, resurrects dead allies within 30m, and deals 20d12 radiant/psychic/force damage to all enemies, erasing them from the current timeline.', 'Cross-Branch', 100, 1500, 5, '{"ors_seraph_of_the_cosmos", "ors_spirit_king_incarnate", "ors_avatar_of_fate"}', '{"x": -1688, "y": -975}', '{"damage": "20d12", "healing": "100%", "resurrect": true, "radius": "30m"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71b09ac5-3488-4be0-bd4e-216f628e13fd', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_minor_phantom', 'Küçük Hayalet', 'Minor Phantom', 'Düşmanları dikkatini dağıtmak için 15 metre içinde küçük bir hayalet ses veya görüntü oluşturur.', 'Creates a minor phantom sound or image within 15 meters to distract enemies.', 'Illusion', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "15m", "duration": "10s", "utility": "Distraction"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31be3cc3-82c9-47f7-b6db-54495eab99c2', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_mirror_image', 'Ayna Görüntüsü', 'Mirror Image', 'Hareketlerinizi taklit eden 3 yanılsama klonu çağırır. Her klon parçalanmadan önce bir gelen saldırıyı emebilir.', 'Summons 3 illusory clones that mimic your movements. Each clone can absorb one incoming attack before shattering.', 'Illusion', 5, 100, 1, '{"pv_minor_phantom"}', '{"x": 389, "y": -224}', '{"clones": 3, "duration": "1 min", "defense": "Absorbs 1 hit per clone"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35d5962d-1795-48cc-a0bb-3a3b57452b7f', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_phantom_step', 'Hayalet Adımı', 'Phantom Step', '10 metreye kadar ışınlanır, düşmanların kafasını karıştıran kısa süreli yanıltıcı bir iz bırakır.', 'Teleports up to 10 meters, leaving a brief illusory trail that confuses enemies.', 'Illusion', 10, 150, 1, '{"pv_minor_phantom"}', '{"x": 606, "y": -349}', '{"range": "10m", "teleport": true, "utility": "Evasion"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0202da5-a5a6-4089-bf1d-ffc87844acc8', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_spectral_decoy', 'Hayalet Yem', 'Spectral Decoy', '5 metrelik bir yarıçap içindeki tüm düşmanları 3 saniye boyunca kışkırtan hayalet bir yem bırakır.', 'Drops a spectral decoy that taunts all enemies within a 5-meter radius for 3 seconds.', 'Illusion', 22, 200, 2, '{"pv_mirror_image"}', '{"x": 822, "y": -474}', '{"range": "5m", "duration": "3s", "taunt": true}', '🎎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('86592ba0-5f0a-4111-a586-165bdd029bc3', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_blur_stance', 'Bulanık Duruş', 'Blur Stance', 'Formunuz sürekli değişir ve bulanıklaşır, 10 saniye boyunca %20 kaçınma şansı sağlar.', 'Your form shifts and blurs constantly, granting a 20% evasion chance for 10 seconds.', 'Illusion', 28, 250, 2, '{"pv_phantom_step"}', '{"x": 1039, "y": -599}', '{"evasion": "20%", "duration": "10s"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f03b7cc5-1f08-42e7-831e-bc0271111ff0', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_phantom_strike', 'Hayalet Vuruşu', 'Phantom Strike', '15 metreye kadar uzaklıktaki bir hedefe vurmak için bir yanılsama göndererek 3d6 psişik hasar verir.', 'Send forth an illusion to strike a target up to 15 meters away, dealing 3d6 psychic damage.', 'Illusion', 35, 300, 2, '{"pv_spectral_decoy"}', '{"x": 1255, "y": -724}', '{"damage": "3d6 psychic", "range": "15m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a052fded-d6f0-470c-b48d-59000020132d', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_veil_of_shadows', 'Gölgeler Peçesi', 'Veil of Shadows', '15 saniye boyunca görünmez olmak için ışığı bükün. Görünmezlikten yapılan ilk saldırınız fazladan 4d8 fiziksel hasar verir.', 'Bend light to become invisible for 15 seconds. Your next attack from invisibility deals an extra 4d8 physical damage.', 'Illusion', 42, 400, 3, '{"pv_blur_stance"}', '{"x": 1472, "y": -849}', '{"duration": "15s", "bonus_damage": "4d8 physical", "invisibility": true}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cb432c71-0a1c-4f58-9c05-42b496c192d5', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_clone_assault', 'Klon Saldırısı', 'Clone Assault', '20 metre içindeki düşmanlara hücum eden ve her biri patladığında 4d6 psişik hasar veren 4 patlayıcı klon çağırır.', 'Summon 4 explosive clones that rush at enemies within 20 meters, each dealing 4d6 psychic damage upon detonating.', 'Illusion', 48, 450, 3, '{"pv_phantom_strike"}', '{"x": 1688, "y": -974}', '{"clones": 4, "damage_per_clone": "4d6 psychic", "range": "20m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('69d311c5-e069-4a3d-9662-be2e2bcb4e96', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_illusory_terrain', 'Yanılsama Alanı', 'Illusory Terrain', '1 dakika boyunca 20 metrelik yarıçaplı bir alanın görünümünü değiştirerek tuzakları ve müttefikleri gizlerken düşmanları yanıltır.', 'Alter the appearance of a 20-meter radius area for 1 minute, hiding traps and allies while misleading enemies.', 'Illusion', 55, 500, 3, '{"pv_veil_of_shadows"}', '{"x": 1905, "y": -1099}', '{"range": "20m radius", "duration": "1 min", "utility": "Terrain alteration"}', '🏞️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71f6d986-77b3-4813-8194-ded619cbe7b1', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_mass_mirror', 'Toplu Ayna', 'Mass Mirror', '15 metre içindeki 3 müttefike kadar her birine saldırıları emen 2 ayna görüntüsü verir.', 'Grant up to 3 allies within 15 meters 2 mirror images each, absorbing attacks.', 'Illusion', 62, 700, 4, '{"pv_illusory_terrain"}', '{"x": 2121, "y": -1224}', '{"range": "15m", "targets": 3, "clones_per_target": 2}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8d78d5b-1634-47ef-9218-1a2891f9740e', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_phantom_legion', 'Hayalet Lejyonu', 'Phantom Legion', 'Geniş bir hayalet lejyonu 15 metrelik bir koni içinde hücum ederek 6d8 psişik hasar verir ve düşmanları geri iter.', 'A sweeping legion of phantoms charges in a 15-meter cone, dealing 6d8 psychic damage and pushing enemies back.', 'Illusion', 68, 800, 4, '{"pv_clone_assault"}', '{"x": 2338, "y": -1349}', '{"damage": "6d8 psychic", "area": "15m cone", "knockback": "3m"}', '🐎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7b601bb7-b4dd-4a2c-9faf-7726c389810b', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_lethal_illusion', 'Ölümcül Yanılsama', 'Lethal Illusion', 'Bir hedefi ölümcül bir yanılsamaya hapseder. Öldüklerine inanarak 8d10 psişik hasar alırlar ve 2 saniye boyunca sersemlerler.', 'Trap a target in a fatal illusion. They believe they are dying, taking 8d10 psychic damage and becoming stunned for 2 seconds.', 'Illusion', 75, 900, 4, '{"pv_phantom_legion"}', '{"x": 2554, "y": -1474}', '{"damage": "8d10 psychic", "duration": "2s", "status": "Stun"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a354ad3-c6c8-43d7-a22e-6ace85a1ac26', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_reality_tear', 'Gerçeklik Yırtılması', 'Reality Tear', '20 metrelik bir yarıçapta yanılsama ve gerçeklik arasındaki sınırı yırtarak yakalanan tüm düşmanlara 10d10 güç hasarı verir.', 'Tear the boundary between illusion and reality in a 20-meter radius, dealing 10d10 force damage to all enemies caught within.', 'Illusion', 82, 1200, 5, '{"pv_lethal_illusion"}', '{"x": 2771, "y": -1599}', '{"damage": "10d10 force", "range": "20m radius"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f9b31269-e4a4-457b-ba83-1c00fc9b2574', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_ult_phantom_king', 'Nihai: Hayaletler Kralı', 'Ultimate: King of Phantoms', 'Nihai yanılsama olun. 10 saniye boyunca bağışıklık kazanırsınız ve sayısız klon yaptığınız her saldırıyı tekrarlayarak hasar çıktınızı etkili bir şekilde üç katına çıkarır.', 'Become the ultimate illusion. You gain immunity for 10 seconds, and countless clones replicate every attack you make, effectively tripling your damage output.', 'Illusion', 90, 1500, 5, '{"pv_reality_tear"}', '{"x": 2987, "y": -1724}', '{"duration": "10s", "immunity": true, "damage_multiplier": "x3"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('326435cd-6e13-406e-b8f5-f976c427d180', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_smoke_bomb', 'Sis Bombası', 'Smoke Bomb', '10 saniye boyunca görüşü engelleyen 5 metrelik yarıçaplı bir bulut oluşturan bir sis bombası atın.', 'Throw a smoke bomb that creates a 5-meter radius cloud, blocking vision for 10 seconds.', 'Smoke', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "5m radius", "duration": "10s", "utility": "Blocks vision"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0934f154-9df5-4fa4-ac5b-b7709da5afa7', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_choking_haze', 'Boğucu Pus', 'Choking Haze', 'İçerdeki düşmanlara 5 saniye boyunca saniyede 1d6 zehir hasarı veren 5 metrelik zehirli bir bulut yaratın.', 'Conjure a 5-meter toxic cloud that deals 1d6 poison damage per second for 5 seconds to enemies inside.', 'Smoke', 8, 100, 1, '{"pv_smoke_bomb"}', '{"x": 289, "y": 344}', '{"damage": "1d6 poison/sec", "range": "5m radius", "duration": "5s"}', '🤢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('19e62876-b3fa-4625-9c25-03f2da497d97', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_smoke_dash', 'Sis Atılımı', 'Smoke Dash', 'Bir sis tutamına dönüşün ve hasar almadan düşmanların ve tehlikelerin içinden geçerek 15 metreye kadar atılın.', 'Transform into a wisp of smoke and dash up to 15 meters, passing through enemies and hazards without taking damage.', 'Smoke', 15, 150, 1, '{"pv_smoke_bomb"}', '{"x": 449, "y": 536}', '{"range": "15m", "utility": "Intangible movement"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5837b073-8238-4e26-8e69-e7b8ce5b13ab', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_ash_cloud', 'Kül Bulutu', 'Ash Cloud', '10 metrelik bir yarıçapta patlayıcı bir kül kesesini patlatın. Vurulan düşmanlar 4 saniye boyunca kör olur.', 'Detonate an explosive pouch of ash in a 10-meter radius. Enemies hit are blinded for 4 seconds.', 'Smoke', 24, 200, 2, '{"pv_smoke_dash"}', '{"x": 610, "y": 727}', '{"range": "10m radius", "duration": "4s", "status": "Blind"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('920ebb9d-b5f7-4412-86dc-4baeeb7fae2c', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_toxic_fumes', 'Zehirli Gazlar', 'Toxic Fumes', '10 metrelik bir alana zararlı bir gaz salın. Başlangıçta 3d6 zehir hasarı verir ve 8 saniye boyunca düşman zırhını %10 azaltır.', 'Release a noxious gas over a 10-meter area. Deals 3d6 poison damage initially and reduces enemy armor by 10% for 8 seconds.', 'Smoke', 30, 250, 2, '{"pv_choking_haze"}', '{"x": 771, "y": 919}', '{"damage": "3d6 poison", "armor_reduction": "10%", "duration": "8s", "range": "10m"}', '☣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35b24d15-9e72-432a-a46d-d585ce07dc30', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_smokescreen', 'Sis Perdesi', 'Smokescreen', '15 metre uzunluğunda ve 3 metre yüksekliğinde, tüm mermileri ve görüş hattını engelleyen yoğun bir sis duvarı oluşturun.', 'Create a dense wall of smoke 15 meters long and 3 meters high that blocks all projectiles and line of sight.', 'Smoke', 38, 300, 2, '{"pv_ash_cloud"}', '{"x": 932, "y": 1110}', '{"dimensions": "15x3m", "utility": "Projectile block"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4dd73bfb-e368-4d5b-a54c-f1eb8b08ba5f', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_suffocating_fog', 'Boğucu Sis', 'Suffocating Fog', 'Ağır 15 metrelik yarıçaplı bir sis, içindeki tüm düşmanları susturur ve 4d6 zehir hasarı verir.', 'A heavy 15-meter radius fog silences all enemies inside and deals 4d6 poison damage.', 'Smoke', 44, 400, 3, '{"pv_toxic_fumes"}', '{"x": 1092, "y": 1302}', '{"range": "15m radius", "damage": "4d6 poison", "status": "Silence"}', '🤐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3bee06fa-8ca2-40ce-befb-944c23b6c17a', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_smoke_clones', 'Sis Klonları', 'Smoke Clones', 'Tamamen uçucu sisten yapılmış 2 klon oluşturun. Vurulduklarında 5 metrelik bir yarıçapta patlayarak 3d6 zehir hasarı verirler.', 'Form 2 clones made entirely of volatile smoke. When struck, they explode in a 5-meter radius for 3d6 poison damage.', 'Smoke', 50, 450, 3, '{"pv_smokescreen"}', '{"x": 1253, "y": 1493}', '{"clones": 2, "damage": "3d6 poison", "explosion_radius": "5m"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('037a7283-a15d-4d0a-8c6b-a8ef4a28b835', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_blinding_smog', 'Kör Edici Duman', 'Blinding Smog', '20 metrelik bir alanı kalın, batıcı bir dumanla sarın. Düşmanlar içerideyken tüm saldırılarda %50 ıskalama şansına maruz kalırlar.', 'Envelop a 20-meter area in thick, stinging smog. Enemies suffer a 50% miss chance on all attacks while inside.', 'Smoke', 58, 500, 3, '{"pv_suffocating_fog"}', '{"x": 1414, "y": 1685}', '{"range": "20m radius", "miss_chance": "50%"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6bd15840-a7ee-459b-866e-20df8ae6f40a', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_volcanic_ash', 'Volkanik Kül', 'Volcanic Ash', '15 metrelik bir yarıçapta yanan, zehirli kül yağdırarak toplam 6d8 ateş ve zehir hasarı verin.', 'Rain down burning, toxic ash in a 15-meter radius, dealing 6d8 combined fire and poison damage.', 'Smoke', 64, 700, 4, '{"pv_blinding_smog"}', '{"x": 1574, "y": 1876}', '{"damage": "6d8 fire/poison", "range": "15m radius"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b073148c-1e05-4d2b-81d4-7185744fd837', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_shadow_smoke_veil', 'Gölge Sisi Peçesi', 'Shadow Smoke Veil', 'Kendinizi katılaşmış sisle sararak %30 fiziksel direnç kazanın ve 15 saniye boyunca kör edici bir kül izi bırakın.', 'Wreathe yourself in solidified smoke, gaining 30% physical resistance and leaving a trail of blinding ash for 15 seconds.', 'Smoke', 70, 800, 4, '{"pv_smoke_clones"}', '{"x": 1735, "y": 2068}', '{"physical_resist": "30%", "duration": "15s"}', '🦹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6f64980c-6d1e-4be0-8664-e4e4e9b5dae4', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_vaporize', 'Buharlaşma', 'Vaporize', 'Fiziksel bedeninizi 5 saniye boyunca tamamen bir sis bulutuna dönüştürün. Yenilmezsiniz ve iki kat hızla uçabilirsiniz.', 'Dissolve your physical body entirely into a cloud of smoke for 5 seconds. You are invulnerable and can fly at double speed.', 'Smoke', 78, 900, 4, '{"pv_volcanic_ash"}', '{"x": 1896, "y": 2259}', '{"duration": "5s", "invulnerability": true, "speed_multiplier": "x2"}', '☁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a1f31f86-dec3-4845-860b-aebd2c7711ce', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_abyssal_smoke', 'Hiçlik Sisi', 'Abyssal Smoke', '20 metrelik bir yarıçapta karanlık, yoğun boşluk sisi çağırın. İçerideki düşmanlar 5 saniye boyunca gerçek hasar olarak maksimum HP''lerinin %10''unu kaybederler.', 'Summon dark, dense void smoke in a 20-meter radius. Enemies inside lose 10% of their maximum HP as true damage over 5 seconds.', 'Smoke', 84, 1200, 5, '{"pv_vaporize"}', '{"x": 2056, "y": 2451}', '{"damage": "10% max HP true damage", "range": "20m radius", "duration": "5s"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a32ff8f6-ddc1-476a-91ec-c62556dc5b8a', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_ult_smoke_dragon', 'Nihai: Sis Ejderhası', 'Ultimate: Smoke Dragon', '30 metrelik bir alanı süpüren, 15d10 zehir hasarı veren ve hayatta kalanları kalıcı olarak kör eden saf zehirli sisten devasa bir ejderha yaratın.', 'Conjure a massive dragon made of pure toxic smoke that sweeps over a 30-meter area, dealing 15d10 poison damage and permanently blinding survivors.', 'Smoke', 92, 1500, 5, '{"pv_abyssal_smoke"}', '{"x": 2217, "y": 2642}', '{"damage": "15d10 poison", "range": "30m area", "status": "Permanent Blind"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2c7f1391-939a-41d4-bc35-8314464a8d2d', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_whispers_of_doubt', 'Şüphe Fısıltıları', 'Whispers of Doubt', 'Bir hedefin zihnine hayalet fısıltılar yerleştirerek 10 saniye boyunca saldırı zarlarına -2 ceza uygulayın.', 'Plant phantom whispers in a target''s mind, imposing a -2 penalty to their attack rolls for 10 seconds.', 'Confusion', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"attack_penalty": "-2", "duration": "10s", "range": "20m"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('60df3d0c-4828-4ce4-85ea-2b77be0d0e48', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_mind_jolt', 'Zihin Sarsıntısı', 'Mind Jolt', '15 metreye kadar uzaklıktaki bir hedefe ani bir psişik şok dalgası göndererek 2d6 psişik hasar verin ve büyü yapmayı kesin.', 'Send a sudden psychic shockwave to a target up to 15 meters away, dealing 2d6 psychic damage and interrupting spellcasting.', 'Confusion', 6, 100, 1, '{"pv_whispers_of_doubt"}', '{"x": -289, "y": 344}', '{"damage": "2d6 psychic", "range": "15m", "utility": "Interrupt"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c771272-eaa0-428b-9144-051d3aa195ee', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_dizzying_hex', 'Sersemletici Büyü', 'Dizzying Hex', 'Bir hedefi büyüleyerek dengesini bozun. 3 saniye boyunca rastgele bir yöne hareket etmeye zorlanırlar.', 'Hex a target, disrupting their balance. They are forced to move in a random direction for 3 seconds.', 'Confusion', 12, 150, 1, '{"pv_whispers_of_doubt"}', '{"x": -449, "y": 536}', '{"duration": "3s", "status": "Random Movement"}', '😵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8272a408-e713-46dc-a5d3-be7a3d3ef3c5', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_paranoia', 'Paranoya', 'Paranoia', '10 metrelik bir yarıçap içindeki düşmanlara şiddetli paranoya verin. 3 saniye boyunca müttefiklerini tehdit olarak algılar ve en yakın yaratığa saldırırlar.', 'Inflict severe paranoia on enemies in a 10-meter radius. For 3 seconds, they perceive their allies as threats and attack the nearest creature.', 'Confusion', 25, 200, 2, '{"pv_dizzying_hex"}', '{"x": -610, "y": 727}', '{"range": "10m radius", "duration": "3s", "status": "Confusion"}', '😨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3fdb5289-ecff-4edd-a653-799f097ae701', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_psychic_shiv', 'Psişik Hançer', 'Psychic Shiv', 'Saf zihinsel enerjiden bir bıçak oluşturun. Yakın dövüş saldırısı 4d6 psişik hasar verir ve hedefin hareket hızını 5 saniye boyunca %15 azaltır.', 'Form a blade of pure mental energy. A melee attack deals 4d6 psychic damage and reduces the target''s movement speed by 15% for 5 seconds.', 'Confusion', 32, 250, 2, '{"pv_mind_jolt"}', '{"x": -771, "y": 919}', '{"damage": "4d6 psychic", "speed_reduction": "15%", "duration": "5s"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf69d46b-0bb6-47fa-98a9-471422385ff9', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_hallucination', 'Halüsinasyon', 'Hallucination', 'Bir hedefi en kötü korkularına tanık olmaya zorlar. 3d6 psişik hasar verir ve onları 2 saniye boyunca dehşet içinde sersemletir.', 'Force a target to witness their worst fears. Deals 3d6 psychic damage and stuns them in sheer terror for 2 seconds.', 'Confusion', 36, 300, 2, '{"pv_paranoia"}', '{"x": -932, "y": 1110}', '{"damage": "3d6 psychic", "duration": "2s", "status": "Stun"}', '👺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71f82d47-70f3-473a-81b2-03f3aa247760', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_madness_glare', 'Delilik Bakışı', 'Madness Glare', '10 metre içindeki bir hedefle göz göze gelerek saf delilik yansıtın. 5d6 psişik hasar verir ve 4 saniye boyunca Korku uygular.', 'Lock eyes with a target within 10 meters, projecting raw madness. Deals 5d6 psychic damage and inflicts Fear for 4 seconds.', 'Confusion', 45, 400, 3, '{"pv_hallucination"}', '{"x": -1092, "y": 1302}', '{"damage": "5d6 psychic", "range": "10m", "status": "Fear", "duration": "4s"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5be83817-6b48-4f28-93fb-f78f7d4bd48c', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_vertigo_wave', 'Baş Dönmesi Dalgası', 'Vertigo Wave', '15 metrelik bir yönelim bozucu psişik enerji konisi yayın. Vurulan düşmanlar yere düşer ve 3 saniye boyunca kafaları karışır.', 'Emit a 15-meter cone of disorienting psychic energy. Enemies hit are knocked prone and confused for 3 seconds.', 'Confusion', 52, 450, 3, '{"pv_psychic_shiv"}', '{"x": -1253, "y": 1493}', '{"area": "15m cone", "status": "Prone & Confusion", "duration": "3s"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4db43655-a6a2-4db3-9c05-e8285f323523', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_shatter_mind', 'Zihin Parçalama', 'Shatter Mind', 'Bir hedefin zihinsel savunmasını şiddetle kırın. 6d8 psişik hasar verir ve zihinsel dirençlerini 10 saniye boyunca %20 azaltır.', 'Violently crack a target''s mental defenses. Deals 6d8 psychic damage and reduces their mental resistances by 20% for 10 seconds.', 'Confusion', 56, 500, 3, '{"pv_madness_glare"}', '{"x": -1414, "y": 1685}', '{"damage": "6d8 psychic", "resistance_reduction": "20%", "duration": "10s"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('756ca3a0-7c8b-400b-8c3b-3aa572fef419', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_mass_hysteria', 'Toplu Histeri', 'Mass Hysteria', '20 metrelik bir yarıçapta kontrolsüz bir histeri dalgası serbest bırakın. Tüm düşmanlar 5 saniye boyunca öfkeyle birbirlerine saldırır.', 'Unleash a wave of unchecked hysteria in a 20-meter radius. All enemies furiously attack each other for 5 seconds.', 'Confusion', 65, 700, 4, '{"pv_vertigo_wave"}', '{"x": -1574, "y": 1876}', '{"range": "20m radius", "duration": "5s", "status": "Frenzy/Confusion"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b222cf01-8a5c-422e-a043-63cfebc97dea', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_cognitive_collapse', 'Bilişsel Çöküş', 'Cognitive Collapse', 'Bir hedefin savaş hafızasını geçici olarak silin. 8d8 psişik hasar alırlar ve 6 saniye boyunca hiçbir sınıf yeteneğini kullanamazlar.', 'Temporarily wipe a target''s combat memory. They take 8d8 psychic damage and cannot use any class skills for 6 seconds.', 'Confusion', 72, 800, 4, '{"pv_shatter_mind"}', '{"x": -1735, "y": 2068}', '{"damage": "8d8 psychic", "duration": "6s", "status": "Skill Lock"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e47785b5-bbcf-46e8-a237-60341a4bcfb0', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_phantom_pain', 'Hayalet Ağrı', 'Phantom Pain', 'Hedefi dayanılmaz hayalet ağrılar hissetmesi için lanetleyin. Onlara isabet eden sonraki 3 saldırıdan iki kat hasar alırlar.', 'Curse a target to feel agonizing phantom pains. They take double damage from the next 3 attacks that hit them.', 'Confusion', 76, 900, 4, '{"pv_cognitive_collapse"}', '{"x": -1896, "y": 2259}', '{"vulnerability": "Double damage for 3 hits"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2778a059-8d45-4eaa-8f49-75203db56cad', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_mind_labyrinth', 'Zihin Labirenti', 'Mind Labyrinth', 'Bir hedefin bilincini kaçınılmaz bir zihinsel labirente hapsedin. 10 saniye boyunca etkisiz hale gelirler ve süre boyunca 10d10 psişik hasar alırlar.', 'Trap a target''s consciousness in an inescapable mental maze. They are incapacitated for 10 seconds and take 10d10 psychic damage over the duration.', 'Confusion', 85, 1200, 5, '{"pv_mass_hysteria"}', '{"x": -2056, "y": 2451}', '{"damage": "10d10 psychic", "duration": "10s", "status": "Incapacitated"}', '🧩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d9b825f-1093-4bf5-b61f-54715b257b66', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_ult_cerebral_void', 'Nihai: Zihinsel Boşluk', 'Ultimate: Cerebral Void', '30 metrelik bir yarıçaptaki tüm düşünceleri silin. 12d12 psişik hasar verir, tüm düşmanları 5 saniye boyunca tamamen susturur ve felç eder.', 'Erase all thoughts in a 30-meter radius. Deals 12d12 psychic damage, completely silencing and paralyzing all enemies for 5 seconds.', 'Confusion', 95, 1500, 5, '{"pv_mind_labyrinth"}', '{"x": -2217, "y": 2642}', '{"damage": "12d12 psychic", "range": "30m radius", "status": "Silence & Paralyze", "duration": "5s"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('08c04ca5-bc70-4274-bc0f-98a2972ba77f', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_smoke_illusion', 'Sis Yanılsaması', 'Smoke Illusion', 'Saldırganları şaşırtmak için anında dumanın içinde 3 gölgeli klon oluşturan yerel bir sis bombası bırakın.', 'Drop a localized smoke bomb that instantly forms 3 shadowy clones within the smoke to confuse attackers.', 'Cross-Branch', 26, 250, 2, '{"pv_mirror_image", "pv_smoke_bomb"}', '{"x": -173, "y": -100}', '{"clones": 3, "utility": "Smoke + Clones"}', '🌫️👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('df5201ba-0275-4df2-a48e-c68729cafcb8', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_confusing_mirage', 'Şaşırtıcı Serap', 'Confusing Mirage', 'Vurulduğunda psişik bir enerji patlamasına dönüşen ve saldırganın kafasını 4 saniye boyunca karıştıran bir yanılsama yaratın.', 'Conjure an illusion that, when struck, shatters into a burst of psychic energy, confusing the attacker for 4 seconds.', 'Cross-Branch', 46, 450, 3, '{"pv_spectral_decoy", "pv_paranoia"}', '{"x": -389, "y": -225}', '{"duration": "4s", "status": "Confusion on hit"}', '🪞🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3e261a46-16c6-4564-aadd-adde40c47ef4', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_choking_whispers', 'Boğucu Fısıltılar', 'Choking Whispers', 'Çıldırtıcı seslerle dolu 10 metrelik bir sis bulutu oluşturun. İçerideki düşmanlar 4d6 zehir ve 4d6 psişik hasar alır.', 'Create a 10-meter smoke cloud filled with maddening voices. Enemies inside take 4d6 poison and 4d6 psychic damage.', 'Cross-Branch', 54, 500, 3, '{"pv_toxic_fumes", "pv_madness_glare"}', '{"x": -606, "y": -350}', '{"damage": "4d6 poison + 4d6 psychic", "range": "10m"}', '🗣️🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07271248-4074-4a1b-84b5-75fcc0146704', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_phantom_miasma', 'Hayalet Miasma', 'Phantom Miasma', '20 metrelik halüsinojenik bir sis bulutu salın. Rastgele klonlar üretir, düşmanları zehirler ve 8 saniye boyunca kitlesel paranoyaya neden olur.', 'Unleash a 20-meter cloud of hallucinogenic smoke. Spawns random clones, poisons enemies, and causes mass paranoia for 8 seconds.', 'Cross-Branch', 74, 800, 4, '{"pv_illusory_terrain", "pv_blinding_smog", "pv_mass_hysteria"}', '{"x": -822, "y": -475}', '{"range": "20m radius", "duration": "8s", "status": "Poison, Paranoia, Clones"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('afef9efd-a81f-4158-abc8-00f1b570650e', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_mind_fog_assassination', 'Zihin Sisi Suikastı', 'Mind Fog Assassination', 'Sisinizin içinde sıkışıp kalmış bir düşmana anında ışınlanın. 10d8 psişik hasar için doğrudan zihinlerine vurun.', 'Instantly teleport to an enemy trapped inside your smoke. Strike their mind directly for 10d8 psychic damage.', 'Cross-Branch', 80, 850, 4, '{"pv_vaporize", "pv_phantom_pain"}', '{"x": -1039, "y": -600}', '{"damage": "10d8 psychic", "teleport": true, "condition": "Target must be in smoke"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a098c1ad-7adf-4dc6-abfe-6b36a7d96789', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_shattered_reality', 'Parçalanmış Gerçeklik', 'Shattered Reality', 'Tüm aktif yanılsamaları şiddetle parçalanmaya zorlayarak, parçalanmış herhangi bir klonun 15 metre içindeki düşmanlarına 12d8 psişik hasar verin.', 'Force all active illusions to violently shatter, dealing 12d8 psychic damage to enemies within 15 meters of any shattered clone.', 'Cross-Branch', 86, 1100, 5, '{"pv_reality_tear", "pv_mind_labyrinth"}', '{"x": -1255, "y": -725}', '{"damage": "12d8 psychic", "range": "15m from clones"}', '🪞💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('86dfbab6-56a1-49fa-ae47-c840d5a39e03', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_smoldering_psyche', 'İçin İçin Yanan Zihin', 'Smoldering Psyche', 'Hedefin bilincini tutuşturarak zihinlerinden duman solumalarına neden olun. 8d10 birleşik psişik/zehir hasarı alırlar ve 5 saniye boyunca susturulurlar.', 'Ignite a target''s consciousness, causing them to exhale smoke from their mind. They take 8d10 combined psychic/poison damage and are silenced for 5 seconds.', 'Cross-Branch', 88, 1150, 5, '{"pv_abyssal_smoke", "pv_mind_labyrinth"}', '{"x": -1472, "y": -850}', '{"damage": "8d10 psychic/poison", "status": "Silence", "duration": "5s"}', '🤯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('05f737b2-ce52-40d2-971c-916851dffed8', 'bc36ba64-0f36-4cb0-83ef-c97fb32245e1', 'pv_grand_ult_veil_of_the_phantom_lord', 'Görkemli Nihai: Hayalet Lordun Peçesi', 'Grand Ultimate: Veil of the Phantom Lord', 'Savaş alanı 30 saniye boyunca bir kabus diyarına dönüşür. Kusursuz görünmezlik, sonsuz klonlar kazanırsınız ve tüm düşmanlar kalıcı kafa karışıklığından muzdarip olurken zamanla 20d12 psişik/zehir hasarı alır.', 'The battlefield becomes a nightmare realm for 30 seconds. You gain perfect invisibility, infinite clones, and all enemies take 20d12 psychic/poison damage over time while suffering from permanent confusion.', 'Cross-Branch', 100, 2000, 5, '{"pv_ult_phantom_king", "pv_ult_smoke_dragon", "pv_ult_cerebral_void"}', '{"x": -1688, "y": -975}', '{"duration": "30s", "damage": "20d12 psychic/poison over time", "status": "Perfect Invisibility, Infinite Clones, Permanent Confusion"}', '🌌👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64edda80-84b4-4bac-a049-958ebb6a4a62', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_minor_heal', 'Küçük Şifa', 'Minor Heal', 'Dokunulan bir hedefe 1d8 + Bilgelik değiştiricisi kadar can yeniler.', 'Heals a touched target for 1d8 + Wisdom modifier hit points.', 'Healing', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"healing": "1d8", "range": "touch"}', '🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1ff1bc5d-f4a4-40ec-b298-85f2dea9a776', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_healing_word', 'Şifa Sözü', 'Healing Word', '15m içindeki bir hedefe 1d4 + Bilgelik değiştiricisi kadar can yenileyen hızlı bir şifa sözü.', 'A swift word of healing that restores 1d4 + Wisdom modifier hit points to a target within 15m.', 'Healing', 5, 75, 1, '{"pr_minor_heal"}', '{"x": 389, "y": -224}', '{"healing": "1d4", "range": "15m"}', '💬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48da03b9-c50e-4d45-8d38-5cf862dc60d2', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_soothing_light', 'Yatıştırıcı Işık', 'Soothing Light', 'Hedefi ışıkla yıkarak 3 tur boyunca 2d6 can yeniler.', 'Bathes the target in light, healing 2d6 HP over 3 turns.', 'Healing', 10, 100, 1, '{"pr_healing_word"}', '{"x": 606, "y": -349}', '{"healing": "2d6", "duration": "3 turns"}', '🕯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3650e189-bb61-4b08-9667-1029c3637d31', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_detect_poison', 'Zehir Sezme', 'Detect Poison', '10m yarıçapındaki zehirlerin ve hastalıkların varlığını ve türünü tespit eder.', 'Detects the presence and nature of poisons and diseases within a 10m radius.', 'Purification', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "10m"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('50094688-3d25-4306-83a0-c2c6199a7cac', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_purify_food', 'Yiyecek ve İçecek Arındırma', 'Purify Food and Drink', '2m yarıçapındaki büyülü olmayan yiyecek ve içeceklerdeki tüm hastalıkları ve zehirleri temizler.', 'Removes all diseases and poisons from non-magical food and drink within a 2m radius.', 'Purification', 5, 75, 1, '{"pr_detect_poison"}', '{"x": 289, "y": 344}', '{"range": "2m"}', '🥖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('690d23e1-4788-4a8c-b0b2-a8bbcb517ec6', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_lesser_restoration', 'Küçük Arınma', 'Lesser Restoration', 'Dokunulan bir yaratıktaki bir hastalığı veya bir durumu (kör, sağır, felçli veya zehirli) iyileştirir.', 'Cures one disease or one condition (blinded, deafened, paralyzed, or poisoned) on a touched creature.', 'Purification', 10, 100, 1, '{"pr_purify_food"}', '{"x": 449, "y": 536}', '{"range": "touch", "removes": "1 condition"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('294483c6-3dda-4110-9589-ab33d986611a', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_shield_of_faith', 'İnanç Kalkanı', 'Shield of Faith', '15m içindeki bir yaratığın etrafında parlayan bir kalkan belirir ve 10 dakika boyunca Zırh Sınıfına +2 bonus sağlar.', 'A shimmering field appears and surrounds a creature within 15m, granting a +2 bonus to AC for 10 minutes.', 'Divine Shield', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"ac_bonus": "+2", "range": "15m", "duration": "10 mins"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0584cc42-be90-4384-aef1-d936d4b95e78', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_sanctuary', 'Sığınak', 'Sanctuary', '10m içindeki bir yaratığı korur. Onu hedef alan herhangi bir düşman Bilgelik kurtarma zarı atmalıdır, aksi takdirde saldırıyı boşa harcar. 1 dakika sürer.', 'Wards a creature within 10m. Any enemy targeting them must succeed on a Wisdom saving throw or lose the attack. Lasts 1 minute.', 'Divine Shield', 5, 75, 1, '{"pr_shield_of_faith"}', '{"x": -289, "y": 344}', '{"range": "10m", "duration": "1 min"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4bae1a32-47af-40c8-a65a-003776b6ed84', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_protection_evil', 'Kötülükten Korunma', 'Protection from Evil', 'Dokunulan yaratığı 10 dakika boyunca sapkınlıklardan, göksellerden, elementallerden, perilerden, iblislerden ve ölümsüzlerden korur. Bu yaratıklar hedefe karşı saldırılarda dezavantajlı olur.', 'Protects a touched creature from aberrations, celestials, elementals, fey, fiends, and undead for 10 minutes. They have disadvantage on attacks against the target.', 'Divine Shield', 10, 100, 1, '{"pr_sanctuary"}', '{"x": -449, "y": 536}', '{"range": "touch", "duration": "10 mins"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34c54766-19d1-4fd1-be15-15fccc0ba5dd', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cure_wounds', 'Yara İyileştirme', 'Cure Wounds', 'Dokunduğunuz bir yaratık 2d8 + büyü yapma yeteneği değiştiriciniz kadar can geri kazanır.', 'A creature you touch regains a number of hit points equal to 2d8 + your spellcasting ability modifier.', 'Healing', 21, 175, 2, '{"pr_soothing_light"}', '{"x": 822, "y": -474}', '{"healing": "2d8", "range": "touch"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae74a9ca-7429-4e60-864d-9e25bb6fb9b1', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_mass_healing_word', 'Toplu Şifa Sözü', 'Mass Healing Word', 'Şifa sözleri haykırdığınızda, 15m içindeki seçtiğiniz en fazla 6 yaratık 1d4 + büyü yapma yeteneği değiştiriciniz kadar can geri kazanır.', 'As you call out words of restoration, up to 6 creatures of your choice within 15m regain 1d4 + your spellcasting ability modifier HP.', 'Healing', 25, 200, 2, '{"pr_cure_wounds"}', '{"x": 1039, "y": -599}', '{"healing": "1d4", "range": "15m", "targets": "6"}', '📣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4cf5a8b7-d66b-46fe-a5a7-076799028429', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_beacon_of_hope', 'Umut Işığı', 'Beacon of Hope', '10m içindeki en fazla 6 yaratığa Bilgelik ve ölüm kurtarma zarlarında avantaj sağlar ve 1 dakika boyunca aldıkları tüm şifayı en üst düzeye çıkarır.', 'Grants up to 6 creatures within 10m advantage on Wisdom saves and death saves, and maximizes any healing they receive for 1 minute.', 'Healing', 30, 250, 2, '{"pr_mass_healing_word"}', '{"x": 1255, "y": -724}', '{"range": "10m", "duration": "1 min", "targets": "6"}', '🌅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('483ce44a-4b3c-44fd-9699-77a9a3c4af49', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_remove_curse', 'Lanet Kaldırma', 'Remove Curse', 'Dokunuşunuzla, bir yaratığı veya nesneyi etkileyen tüm lanetler sona erer.', 'At your touch, all curses affecting one creature or object end.', 'Purification', 21, 175, 2, '{"pr_lesser_restoration"}', '{"x": 610, "y": 727}', '{"range": "touch"}', '🪬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c6b632b1-7499-424a-962a-31a0eaf01eb5', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cleanse_mind', 'Zihin Temizleme', 'Cleanse Mind', '10m içindeki bir hedeften cazibe, korku ve psişik rahatsızlıkları kaldırarak zihinsel berraklığı geri kazandırır.', 'Removes charm, fear, and psychic afflictions from a target within 10m, restoring mental clarity.', 'Purification', 25, 200, 2, '{"pr_remove_curse"}', '{"x": 771, "y": 919}', '{"range": "10m", "removes": "charm/fear"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf11b66c-148e-4969-808f-3e2fe499fb21', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_dispel_magic', 'Büyü Bozma', 'Dispel Magic', '30m içindeki bir yaratık, nesne veya büyü etkisini seçin. Hedefteki 3. aşama veya daha düşük tüm büyüler sona erer.', 'Choose one creature, object, or magical effect within 30m. Any spell of 3rd tier or lower on the target ends.', 'Purification', 30, 250, 2, '{"pr_cleanse_mind"}', '{"x": 932, "y": 1110}', '{"range": "30m"}', '🪄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('975fac33-f270-43a9-9439-0dcb76467d6e', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_warding_bond', 'Koruyucu Bağ', 'Warding Bond', 'Kendinizi dokunulan bir müttefike bağlar. 15m içinde kaldıkça müttefik +1 ZS, +1 kurtarma zarı ve tüm hasarlara karşı direnç kazanır. Onların aldığı hasarın aynısını siz de alırsınız.', 'Links yourself to a touched ally. While within 15m, the ally gains +1 AC, +1 saving throws, and resistance to all damage. You take the same amount of damage they take.', 'Divine Shield', 21, 175, 2, '{"pr_protection_evil"}', '{"x": -610, "y": 727}', '{"range": "15m", "ac_bonus": "+1"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0825fb80-6146-4cb7-87ba-ff500a8d5f26', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_magic_circle', 'Büyülü Çember', 'Magic Circle', '3m yarıçapında büyülü bir enerji silindiri oluşturur. Seçilen yaratık türleri içeri giremez veya içeridekileri etkileyemez. 1 saat sürer.', 'Creates a 3m radius cylinder of magical energy. Chosen creature types cannot enter or affect targets inside. Lasts 1 hour.', 'Divine Shield', 25, 200, 2, '{"pr_warding_bond"}', '{"x": -771, "y": 919}', '{"radius": "3m", "duration": "1 hour"}', '⭕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8c4c5bc-e84a-406c-aa6e-1f23e3275a62', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_divine_barrier', 'Kutsal Bariyer', 'Divine Barrier', '6m uzunluğunda ve 3m yüksekliğinde parlayan bir ışık duvarı çağırır. Fiziksel mermileri engeller ve 50''ye kadar büyü hasarını emer.', 'Summons a glowing wall of light 6m long and 3m high. It blocks physical projectiles and absorbs up to 50 magical damage.', 'Divine Shield', 30, 250, 2, '{"pr_magic_circle"}', '{"x": -932, "y": 1110}', '{"wall_length": "6m", "absorption": "50 damage"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9025f3be-a0c9-4497-9275-0234b214cee6', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cleansing_touch', 'Arındırıcı Dokunuş', 'Cleansing Touch', '1d8 can yenileyen ve bir küçük zayıflatmayı veya 1. aşama laneti anında kaldıran güçlü bir dokunuş.', 'A potent touch that heals 1d8 HP and instantly removes one minor debuff or tier 1 curse.', 'Healing, Purification', 25, 250, 2, '{"pr_cure_wounds", "pr_remove_curse"}', '{"x": 173, "y": -99}', '{"healing": "1d8", "range": "touch"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('666b5128-ac23-4389-965e-77d8c691da24', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_radiant_ward', 'Parlak Koruma', 'Radiant Ward', 'Bir hedefi 20 geçici can ile korur. Kalkan kırıldığında bir parlama yayar ve 3m içindeki düşmanları 1 turluğuna kör eder.', 'Shields a target for 20 temporary HP. When the shield breaks, it emits a flash, blinding enemies within 3m for 1 turn.', 'Purification, Divine Shield', 30, 275, 2, '{"pr_cleanse_mind", "pr_magic_circle"}', '{"x": 173, "y": -99}', '{"shield": "20 hp", "blind_radius": "3m"}', '🔆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('85bd5378-fb24-4f44-8c7a-3117dea0d8e4', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_greater_heal', 'Büyük Şifa', 'Greater Heal', 'Pozitif enerji dalgası, dokunduğunuz bir yaratığı 4d8 + Bilgelik değiştiricisi kadar canla iyileştirir.', 'A surge of positive energy heals a creature you touch for 4d8 + Wisdom modifier hit points.', 'Healing', 41, 350, 3, '{"pr_beacon_of_hope"}', '{"x": 1472, "y": -849}', '{"healing": "4d8", "range": "touch"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e787a092-95a0-4fef-ae1e-9062d79dc39a', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_revivify', 'Hayata Döndürme', 'Revivify', 'Son bir dakika içinde ölmüş bir yaratığa dokunarak onu 1 canla hayata döndürür.', 'Touch a creature that has died within the last minute, returning it to life with 1 hit point.', 'Healing', 45, 400, 3, '{"pr_greater_heal"}', '{"x": 1688, "y": -974}', '{"range": "touch", "revive": "1 hp"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('10291225-11cd-4ac4-9e1c-78ddcf9ed04d', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_healing_aura', 'Şifa Halesi', 'Healing Aura', '10m''lik bir hale yayar. İçerideki müttefikler 1 dakika boyunca turunuzun başında 1d6 can geri kazanır.', 'Emanates a 10m aura. Allies inside regain 1d6 HP at the start of your turn for 1 minute.', 'Healing', 50, 450, 3, '{"pr_revivify"}', '{"x": 1905, "y": -1099}', '{"radius": "10m", "healing": "1d6/turn", "duration": "1 min"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9667bdf6-6da8-4952-a3eb-c9190c1afd5c', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_greater_restoration', 'Büyük Arınma', 'Greater Restoration', 'Dokunulan bir yaratığı pozitif enerjiyle doldurarak yorgunluğu azaltır veya bir cazibe, taşlaşma, lanet veya yetenek puanı azalmasını sona erdirir.', 'Imbues a touched creature with positive energy, reducing exhaustion, or ending one charm, petrification, curse, or ability score reduction.', 'Purification', 41, 350, 3, '{"pr_dispel_magic"}', '{"x": 1092, "y": 1302}', '{"range": "touch"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed3e4fe4-1481-4aa7-9794-0d63cea8fb3a', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_purifying_flame', 'Arındırıcı Alev', 'Purifying Flame', '20m uzağa kutsal bir ateş topu fırlatır. 4d6 parlak hasar verir ve hedefteki büyü güçlendirmelerini arındırır.', 'Hurls a bolt of holy fire 20m. Deals 4d6 radiant damage and purges magical buffs from the target.', 'Purification', 45, 400, 3, '{"pr_greater_restoration"}', '{"x": 1253, "y": 1493}', '{"damage": "4d6", "range": "20m"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b7667bea-eb63-4553-96c3-f025abd5862c', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_aura_of_purity', 'Safiyet Halesi', 'Aura of Purity', '10m''lik bir hale, müttefiklere 10 dakika boyunca kör, cazibeli, sağır, korkmuş, felçli veya zehirli olmaya karşı kurtarma zarlarında avantaj sağlar.', 'A 10m aura that grants allies advantage on saving throws against being blinded, charmed, deafened, frightened, paralyzed, or poisoned for 10 minutes.', 'Purification', 50, 450, 3, '{"pr_purifying_flame"}', '{"x": 1414, "y": 1685}', '{"radius": "10m", "duration": "10 mins"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('17b7f96f-d2b3-4726-9269-037e062b1983', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_aura_of_life', 'Yaşam Halesi', 'Aura of Life', '10m''lik bir hale. İçindeki düşman olmayan yaratıklar nekrotik hasara karşı dirence sahip olur ve maksimum canları azaltılamaz.', 'A 10m aura. Non-hostile creatures within have resistance to necrotic damage and their maximum HP cannot be reduced.', 'Divine Shield', 41, 350, 3, '{"pr_divine_barrier"}', '{"x": -1092, "y": 1302}', '{"radius": "10m", "resistance": "necrotic"}', '🌱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3e4f96fe-95a4-4f05-95dc-9c0fc8283556', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_death_ward', 'Ölüm Koruması', 'Death Ward', 'Dokunulan yaratık 8 saat boyunca korunur. 0 cana düşeceği ilk seferde bunun yerine 1 cana düşer ve büyü sona erer.', 'Touched creature is protected for 8 hours. The first time it would drop to 0 HP, it drops to 1 HP instead, and the spell ends.', 'Divine Shield', 45, 400, 3, '{"pr_aura_of_life"}', '{"x": -1253, "y": 1493}', '{"range": "touch", "duration": "8 hours"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('baf1e11d-6bf4-4f68-b4b9-ecef10023a49', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_guardian_of_faith', 'İnanç Muhafızı', 'Guardian of Faith', '10m içinde boş bir alanda spektral bir muhafız çağırır. 3m yakınına gelen düşman yaratıklara 20 parlak hasar verir. 8 saat veya 60 hasar verene kadar sürer.', 'Summons a spectral guardian in an unoccupied space within 10m. It deals 20 radiant damage to hostile creatures that move within 3m of it. Lasts 8 hours or until it deals 60 damage.', 'Divine Shield', 50, 450, 3, '{"pr_death_ward"}', '{"x": -1414, "y": 1685}', '{"damage": "20", "duration": "8 hours"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f8dcfe6-9151-4004-8a9e-bcc166fa1af9', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_sheltering_light', 'Barındıran Işık', 'Sheltering Light', 'Tur başına 10 geçici can sağlayan ve 1d4 can yenileyen 5m''lik bir bölge. 3 tur sürer.', 'A 5m zone that grants 10 temporary HP per turn and heals 1d4 HP. Lasts 3 turns.', 'Healing, Divine Shield', 45, 450, 3, '{"pr_greater_heal", "pr_aura_of_life"}', '{"x": 173, "y": -99}', '{"radius": "5m", "shield": "10/turn", "duration": "3 turns"}', '🏕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb834d4b-e666-4d30-abf8-28debb7ab4d9', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_panacea', 'Her Derde Deva', 'Panacea', 'Bir hedefi 3d8 canla iyileştirir ve tüm aktif zehirleri, hastalıkları ve lanetleri anında kaldırır.', 'Heals a target for 3d8 HP and removes all active poisons, diseases, and curses instantly.', 'Healing, Purification', 55, 500, 3, '{"pr_healing_aura", "pr_aura_of_purity"}', '{"x": 389, "y": -224}', '{"healing": "3d8", "range": "touch"}', '⚕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d7d9906-99fb-42d8-becf-814f6459a78f', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_heal', 'İyileştirme', 'Heal', '15m içinden bir yaratık seçin. 70 can geri kazanır ve körlük, sağırlık ve hastalıklardan kurtulur.', 'Choose a creature within 15m. It regains 70 hit points and is cured of blindness, deafness, and any diseases.', 'Healing', 61, 600, 4, '{"pr_healing_aura"}', '{"x": 2121, "y": -1224}', '{"healing": "70", "range": "15m"}', '💞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c352839-9b79-4845-a60b-e87b05393333', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_mass_cure_wounds', 'Toplu Yara İyileştirme', 'Mass Cure Wounds', '15m içindeki bir noktadan şifa enerjisi dalgası yayılır. 10m yarıçapındaki en fazla 6 yaratık 3d8 + Bilgelik değiştiricisi kadar can kazanır.', 'A wave of healing energy washes out from a point within 15m. Up to 6 creatures in a 10m radius regain 3d8 + Wisdom modifier hit points.', 'Healing', 65, 700, 4, '{"pr_heal"}', '{"x": 2338, "y": -1349}', '{"healing": "3d8", "radius": "10m", "range": "15m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('568a642a-6674-4ff7-952a-edd9eefb1af9', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_resurrection', 'Diriliş', 'Resurrection', 'Dokunulan ölü bir yaratığı, yüzyıldan uzun süredir ölü olmaması şartıyla hayata döndürür. Tüm ölümcül yaraları kapatır ve eksik vücut parçalarını onarır.', 'Restores life to a deceased creature touched, provided it hasn''t been dead for more than a century. Closes all mortal wounds and restores missing body parts.', 'Healing', 70, 800, 4, '{"pr_mass_cure_wounds"}', '{"x": 2554, "y": -1474}', '{"range": "touch"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d493beb2-0893-44e9-b755-2e7e7bd1d45b', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_cleanse_area', 'Bölge Arındırma', 'Cleanse Area', '20m yarıçapında bir alanı arındırır. Doğal olmayan sisi, kara büyü yüzeylerini yok eder ve ölümsüzlere 6d6 parlak hasar verir.', 'Purifies a 20m radius. Destroys unnatural fog, dark magic surfaces, and deals 6d6 radiant damage to undead.', 'Purification', 61, 600, 4, '{"pr_aura_of_purity"}', '{"x": 1574, "y": 1876}', '{"radius": "20m", "damage": "6d6"}', '🏞️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('523aa790-2f3b-4bc1-990d-c653080a56a5', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_banishment', 'Sürgün', 'Banishment', '15m içindeki bir yaratığı başka bir varoluş düzlemine göndermeye çalışır. Hedef bir Karizma kurtarma zarında başarılı olamazsa 1 dakika boyunca sürgün edilir.', 'Attempts to send one creature within 15m to another plane of existence. The target must succeed on a Charisma saving throw or be banished for 1 minute.', 'Purification', 65, 700, 4, '{"pr_cleanse_area"}', '{"x": 1735, "y": 2068}', '{"range": "15m", "duration": "1 min"}', '🚪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('524c5e83-2fd6-4772-a570-df2196d16bb2', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_holy_word', 'Kutsal Kelam', 'Holy Word', 'Kutsal bir kelam söyleyin. 10m içindeki gökseller, elementaller, periler, iblisler ve ölümsüzler 5d8 parlak hasar alır ve sağır veya kör olurlar.', 'Utter a divine word. Celestials, elementals, fey, fiends, and undead within 10m suffer 5d8 radiant damage and are deafened or blinded.', 'Purification', 70, 800, 4, '{"pr_banishment"}', '{"x": 1896, "y": 2259}', '{"radius": "10m", "damage": "5d8"}', '📖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('11669833-ecd4-4ca3-9a20-35ed4add0e61', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_globe_of_invulnerability', 'Yenilmezlik Küresi', 'Globe of Invulnerability', 'Etrafınızda hareketsiz, hafifçe parlayan 3m yarıçaplı bir bariyer belirir. Bariyerin dışından yapılan 5. aşama veya daha düşük hiçbir büyü içerideki yaratıkları etkileyemez.', 'An immobile, faintly shimmering 3m radius barrier springs into existence around you. Any spell of 5th tier or lower cast from outside the barrier can''t affect creatures within it.', 'Divine Shield', 61, 600, 4, '{"pr_guardian_of_faith"}', '{"x": -1574, "y": 1876}', '{"radius": "3m"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('801424cb-3ea4-4825-a068-93ff9071f041', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_wall_of_light', 'Işık Duvarı', 'Wall of Light', '15m uzunluğunda, 3m yüksekliğinde parlak enerjiden bir duvar oluşturur. İçinden geçen ölümsüzler 4d8 hasar alır ve içerdeki müttefikler yarım siper kazanır.', 'Creates a 15m long, 3m high wall of radiant energy. Undead passing through take 4d8 damage, and allies inside gain half-cover.', 'Divine Shield', 65, 700, 4, '{"pr_globe_of_invulnerability"}', '{"x": -1735, "y": 2068}', '{"wall_length": "15m", "damage": "4d8"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4778018e-bd18-4d6b-9232-b4ad8985bfb6', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_holy_aura', 'Kutsal Hale', 'Holy Aura', 'Sizden 10m yarıçapında ilahi bir ışık yayılır. Müttefikler tüm kurtarma zarlarında avantaj sağlar ve düşmanların onlara karşı saldırı zarlarında dezavantajı olur.', 'Divine light radiates from you in a 10m radius. Allies have advantage on all saving throws, and enemies have disadvantage on attack rolls against them.', 'Divine Shield', 70, 800, 4, '{"pr_wall_of_light"}', '{"x": -1896, "y": 2259}', '{"radius": "10m"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8bbbb8ce-9b8a-4d82-99d9-bfc22900487c', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_hallowed_ground', 'Kutsal Toprak', 'Hallowed Ground', '15m''lik bir alanı 1 dakikalığına kutsar. Müttefikler +3 ZS kazanır ve içeride yapılan tüm lanetler anında iptal edilir.', 'Sanctifies a 15m area for 1 minute. Allies gain +3 AC, and any curses cast inside are immediately nullified.', 'Purification, Divine Shield', 65, 750, 4, '{"pr_cleanse_area", "pr_globe_of_invulnerability"}', '{"x": 389, "y": -224}', '{"radius": "15m", "duration": "1 min", "ac_bonus": "+3"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ea1987d-8b54-44b0-a1a7-c42a170e150f', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_martyrs_grace', 'Şehidin Lütfu', 'Martyr''s Grace', 'Mevcut canınızın %50''sini feda ederek bir müttefikinizin canını tamamen yeniler ve onlara 50 canlık bir kalkan sağlarsınız.', 'Sacrifice 50% of your current HP to restore an ally to full HP and grant them a 50 HP shield.', 'Healing, Divine Shield', 75, 850, 4, '{"pr_resurrection", "pr_holy_aura"}', '{"x": 389, "y": -224}', '{"range": "touch", "shield": "50 hp", "healing": "100%"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b70cd5e6-9dd7-4fc2-80bf-21f3b0ae7610', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_divine_regeneration', 'Kutsal Yenilenme', 'Divine Regeneration', 'Hedef anında 4d8 + 15 can geri kazanır ve 1 dakika boyunca her turunun başında 10 can yeniler. Kopmuş vücut parçaları yeniden büyür.', 'Target regains 4d8 + 15 HP immediately, and regenerates 10 HP at the start of each of their turns for 1 minute. Severed body parts regrow.', 'Healing', 81, 1000, 5, '{"pr_resurrection"}', '{"x": 2771, "y": -1599}', '{"healing": "4d8 + 15", "regen": "10/turn", "duration": "1 min"}', '❤️‍🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('63694a97-cc93-423b-9e96-1c303da02d51', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_ultimate_healing', 'Tanrıçanın Nefesi', 'Breath of the Goddess', 'ULTİMAT: 30m yarıçapında ilahi bir nefes akar. Tüm müttefikler 100 can iyileşir ve düşmüş tüm müttefikler %50 canla diriltilir. Günde bir kez.', 'ULTIMATE: A divine breath flows through a 30m radius. All allies are healed for 100 HP, and all fallen allies are revived with 50% HP. Once per day.', 'Healing', 90, 1200, 5, '{"pr_divine_regeneration"}', '{"x": 2987, "y": -1724}', '{"radius": "30m", "healing": "100 hp", "revive": "50%"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31deadee-4e15-4556-8318-743d3d44e8bc', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_curse_immunity', 'Lanet Bağışıklığı', 'Curse Immunity', 'Dokunulan bir müttefike 24 saat boyunca tüm lanetlere ve büyülere karşı kalıcı bağışıklık sağlar. Mevcut tüm lanetler paramparça olur.', 'Grants a touched ally permanent immunity to all curses and hexes for 24 hours. Any existing curses are shattered.', 'Purification', 81, 1000, 5, '{"pr_holy_word"}', '{"x": 2056, "y": 2451}', '{"range": "touch", "duration": "24 hours"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48e27b8a-7683-424e-9531-7a85e0de5feb', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_ultimate_purification', 'Mutlak Arınma Işığı', 'Light of Absolution', 'ULTİMAT: Göklerden kör edici bir ışık sütunu iner (20m yarıçap). Tüm kara büyüleri, lanetleri buharlaştırır ve iblislere ve ölümsüzlere 15d10 parlak hasar verir.', 'ULTIMATE: A blinding pillar of light descends from the heavens (20m radius). Evaporates all dark magic, curses, and deals 15d10 radiant damage to fiends and undead.', 'Purification', 90, 1200, 5, '{"pr_curse_immunity"}', '{"x": 2217, "y": 2642}', '{"radius": "20m", "damage": "15d10"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ca01e6d-bfb9-4ac1-b899-faaa1fbc204e', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_aegis_of_the_gods', 'Tanrıların Kalkanı', 'Aegis of the Gods', 'Dışarıdan gelen tüm fiziksel ve büyüsel saldırıları 3 tur boyunca engelleyen delinmez altın bir kubbe (10m yarıçap) çağırır. Hiçbir şey içinden geçemez.', 'Conjures an impenetrable golden dome (10m radius) that blocks all physical and magical attacks from outside for 3 turns. Nothing can pass through.', 'Divine Shield', 81, 1000, 5, '{"pr_holy_aura"}', '{"x": -2056, "y": 2451}', '{"radius": "10m", "duration": "3 turns"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07a34030-b59c-4705-8b46-eb945705b0f3', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_ultimate_shield', 'Cennetin Kalesi', 'Bastion of Heaven', 'ULTİMAT: En fazla 8 müttefike 2 tur boyunca kırılmaz ilahi bir kalkan sağlar. Kalkanlıyken, alınan hasarın %100''ünü saldırgana geri yansıtırlar.', 'ULTIMATE: Grants up to 8 allies an unbreakable divine shield for 2 turns. While shielded, they reflect 100% of damage taken back to the attacker.', 'Divine Shield', 90, 1200, 5, '{"pr_aegis_of_the_gods"}', '{"x": -2217, "y": 2642}', '{"duration": "2 turns", "reflect": "100%", "targets": "8"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8401d76a-35c4-4f03-9db8-43e2e9a69863', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_avatar_of_mercy', 'Merhamet Avatarı', 'Avatar of Mercy', '1 dakikalığına melek benzeri bir varlığa dönüşün. Uçma hızı kazanırsınız, müttefikleri turda 15 can iyileştiren, zayıflatmaları arındıran ve +5 ZS sağlayan 15m''lik bir hale yayarsınız.', 'Transform into an angelic being for 1 minute. You gain flying speed, emit a 15m aura that heals allies 15 HP/turn, purifies debuffs, and grants +5 AC.', 'Healing, Purification, Divine Shield', 85, 1100, 5, '{"pr_divine_regeneration", "pr_curse_immunity", "pr_aegis_of_the_gods"}', '{"x": 173, "y": -99}', '{"radius": "15m", "healing": "15/turn", "ac_bonus": "+5", "duration": "1 min"}', '🪽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5ea2eb5-5d00-4984-9c01-7847be46513b', '8838933d-3f1b-4886-8179-5fa2b9f3d050', 'pr_grand_ultimate', 'İlahi Mucize', 'Miracle of the Divine', 'BÜYÜK ULTİMAT: İlahi ışık savaş alanını yıkarken zaman durur. Tüm müttefikleri tamamen iyileştirir, arındırır, diriltir ve onlara 3 tur boyunca yenilmezlik sağlar. Maksimum canınızın %50''sine mal olur.', 'GRAND ULTIMATE: Time stops as divine light washes over the battlefield. Fully heals, purifies, and revives all allies, and grants them invulnerability for 3 turns. Costs 50% of your maximum HP.', 'Healing, Purification, Divine Shield', 100, 1500, 5, '{"pr_ultimate_healing", "pr_ultimate_purification", "pr_ultimate_shield"}', '{"x": 389, "y": -224}', '{"healing": "100%", "duration": "3 turns"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('713d2ebb-73c6-4183-b69d-cfb7d7f4c9cf', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_minor_telepathy', 'Küçük Telepati', 'Minor Telepathy', 'Bir yaratıkla küçük bir zihinsel bağ kurarak temel iletişim sağlar.', 'Establish a minor mental link with a creature, allowing basic communication.', 'Telepathy', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "30m", "duration": "10m"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48d7b7f1-9fc1-4ca4-adf2-c4e320af17a6', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_kinetic_push', 'Kinetik İtiş', 'Kinetic Push', 'Bir hedefi uzağa itmek için kinetik enerji patlaması yayar.', 'Emit a burst of kinetic energy to push a target away.', 'Telekinesis', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8", "range": "15m", "push": "5m"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8a0313fe-6827-42e2-acde-89cd5d00b6c8', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_mental_barrier', 'Zihinsel Bariyer', 'Mental Barrier', 'Küçük hasarları emen temel bir zihinsel bariyer oluşturur.', 'Form a basic mental barrier that absorbs minor damage.', 'Psychic Shield', 3, 70, 1, '{}', '{"x": -128, "y": 153}', '{"temporary_hp": "15", "duration": "1h"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('745f2540-e704-4f74-954f-b7a90d40f414', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_mind_spike', 'Zihin Dikeni', 'Mind Spike', 'Bir hedefin zihnini psişik enerjiyle delerek hasar verir.', 'Pierce a target''s mind with psychic energy, dealing damage.', 'Telepathy', 5, 90, 1, '{"pm_minor_telepathy"}', '{"x": 389, "y": -224}', '{"damage": "2d6", "range": "20m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45a1c9ab-1142-4117-9159-be0f28086798', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_levitation', 'Levitasyon', 'Levitation', 'Kendinizi veya hafif bir nesneyi havaya kaldırırsınız.', 'Lift yourself or a light object into the air.', 'Telekinesis', 6, 100, 1, '{"pm_kinetic_push"}', '{"x": 289, "y": 344}', '{"height": "10m", "duration": "5m"}', '🪶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b8160d4-1126-4d28-8d95-a29e012b6f33', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_force_ward', 'Güç Kalkanı', 'Force Ward', 'Bir müttefiki gelen hasarı azaltan bir koruma ile çevreler.', 'Surround an ally with a ward that reduces incoming damage.', 'Psychic Shield', 7, 110, 1, '{"pm_mental_barrier"}', '{"x": -289, "y": 344}', '{"damage_reduction": "3", "duration": "10m"}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b57649dc-f4ed-4ace-95fb-e28a12c3d45f', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_thought_steal', 'Düşünce Çalma', 'Thought Steal', 'Hedefin zihnine girerek yakın zamandaki bir anıyı veya düşünceyi çalar.', 'Peek into a target''s mind to glean a single recent memory or thought.', 'Telepathy', 10, 130, 1, '{"pm_mind_spike"}', '{"x": 606, "y": -349}', '{"range": "5m", "duration": "1m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aa203108-31f7-4556-9f8b-317a302f043a', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_force_projectile', 'Güç Mermisi', 'Force Projectile', 'Kinetik enerjiyi hızlı hareket eden bir mermiye dönüştürür.', 'Condense kinetic energy into a fast-moving projectile.', 'Telekinesis', 12, 140, 1, '{"pm_levitation"}', '{"x": 449, "y": 536}', '{"damage": "3d6", "range": "30m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1500e1b9-075b-4b17-8702-f3100f1f1fd0', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_pain_dampener', 'Acı Bastırıcı', 'Pain Dampener', 'Acı reseptörlerini bloke ederek kısa süreliğine hasara karşı yüksek direnç sağlar.', 'Block pain receptors, granting high resistance to damage for a short time.', 'Psychic Shield', 14, 150, 1, '{"pm_force_ward"}', '{"x": -449, "y": 536}', '{"resistance": "50%", "duration": "3m"}', '💊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9c7aec6-b213-4330-a535-518a279bf465', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_confusion_wave', 'Kafa Karışıklığı Dalgası', 'Confusion Wave', 'Düşmanların yönelimini bozan bir parazit dalgası gönderir.', 'Send out a wave of static that disorients enemies.', 'Telepathy', 21, 200, 2, '{"pm_thought_steal"}', '{"x": 822, "y": -474}', '{"radius": "15m", "duration": "30s"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ccc3246-e3b7-4ff8-97b8-8f99dc532cdd', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_telekinetic_grasp', 'Telekinetik Kavrama', 'Telekinetic Grasp', 'Bir hedefi hayalet bir el ile kavrayarak yerinde tutar.', 'Seize a target with a spectral hand, holding them in place.', 'Telekinesis', 22, 210, 2, '{"pm_force_projectile"}', '{"x": 610, "y": 727}', '{"range": "20m", "duration": "1m"}', '✊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49eb88eb-67af-4b7b-9b23-5026d63c2026', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_kinetic_reflection', 'Kinetik Yansıma', 'Kinetic Reflection', 'Mermileri saldırganlara geri yansıtma şansı olan bir kalkan oluşturur.', 'Create a shield that has a chance to reflect projectiles back at attackers.', 'Psychic Shield', 23, 220, 2, '{"pm_pain_dampener"}', '{"x": -610, "y": 727}', '{"reflect_chance": "30%", "duration": "5m"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('491109ca-72a6-4404-b4f4-938da6c6485e', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_mental_agony', 'Zihinsel Izdırap', 'Mental Agony', 'Hedefi sakat bırakacak kadar büyük bir psikolojik acı verir.', 'Inflict immense psychological pain, crippling the target.', 'Telepathy', 25, 240, 2, '{"pm_confusion_wave"}', '{"x": 1039, "y": -599}', '{"damage": "4d8", "range": "25m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e8b9d000-0b31-46a4-8f6e-97ba287a7cde', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_kinetic_slam', 'Kinetik Çarpma', 'Kinetic Slam', 'Telekinetik olarak tutulan bir hedefi yere veya duvara çarpar.', 'Crush a telekinetically held target into the ground or a wall.', 'Telekinesis', 26, 250, 2, '{"pm_telekinetic_grasp"}', '{"x": 771, "y": 919}', '{"damage": "5d6", "range": "15m", "stun": "1s"}', '🔨');
