INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5dbea46d-7f32-437c-8d86-33de0c049c5b', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_kinetic_mind_bomb', 'Kinetik Zihin Bombası', 'Kinetic Mind Bomb', 'Fiziksel güç ve psişik bozulma küresini aynı anda patlatır.', 'Detonate a sphere of physical force and psychic disruption simultaneously.', 'Cross-Branch', 82, 900, 4, '{"pm_psychic_vampirism", "pm_mass_telekinesis", "pm_aegis_of_will"}', '{"x": -1039, "y": -600}', '{"damage": "15d8", "radius": "25m", "stun": "5s"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e848e892-5c40-405e-beca-8a764ae4bc94', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_reactive_telekinesis', 'Reaktif Telekinezi', 'Reactive Telekinesis', 'Saldırıya uğradığınızda otomatik olarak telekinetik güçle karşılık verir.', 'Automatically lash out with telekinetic force when attacked.', 'Cross-Branch', 85, 900, 4, '{"pm_mass_telekinesis", "pm_aegis_of_will"}', '{"x": -1255, "y": -725}', '{"auto_retaliate_damage": "4d10", "duration": "10m"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74690484-3016-439c-a117-0b7699d81d59', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_telepathic_overlord', 'Telepatik Derebeyi', 'Telepathic Overlord', 'Zihninizi genişleterek geniş bir alandaki birden fazla zayıf zihne aynı anda hükmeder.', 'Expand your mind to dominate multiple lesser minds simultaneously across a vast area.', 'Telepathy', 90, 1200, 5, '{"pm_ego_whip"}', '{"x": 2987, "y": -1724}', '{"control_targets": "5", "duration": "1h", "range": "100m"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee1d65bb-4161-40d5-b780-ad89a256a659', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_telekinetic_sovereign', 'Telekinetik Hükümdar', 'Telekinetic Sovereign', 'Güç tanrısı olun; tüm yapıları manipüle edin ve orduları ezin.', 'Become a god of force, manipulating entire structures and crushing armies.', 'Telekinesis', 90, 1200, 5, '{"pm_earth_uproot"}', '{"x": 2217, "y": 2642}', '{"lift_weight": "1000 tons", "damage": "20d10", "radius": "100m"}', '🪐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7511e8eb-870e-4933-ab6a-2a7f6416b51a', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_shield_of_the_mind_god', 'Zihin Tanrısının Kalkanı', 'Shield of the Mind God', 'Saf iradeden oluşan, kırılmaz ve nihai bir bariyer inşa eder.', 'Erect an ultimate, unbreakable barrier of pure willpower.', 'Psychic Shield', 90, 1200, 5, '{"pm_absolute_ward"}', '{"x": -2217, "y": 2642}', '{"immunity": "all damage", "duration": "30s"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de93e384-7c95-4f03-a46c-a8c00732804c', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_psionic_avatar', 'Psiyonik Avatar', 'Psionic Avatar', 'Fiziksel sınırları aşarak saf psiyonik enerjiden oluşan bir varlığa dönüşür.', 'Transcending physical limits, becoming a being of pure psionic energy.', 'Cross-Branch', 95, 1400, 5, '{"pm_telepathic_overlord", "pm_telekinetic_sovereign", "pm_shield_of_the_mind_god"}', '{"x": -1472, "y": -850}', '{"all_stats_bonus": "+50%", "duration": "3m"}', '👤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('460b8e92-dc0f-40c2-a846-3baa728057da', '90345517-fe58-4e70-96a1-f9612d716a2d', 'pm_psionic_singularity', 'Psiyonik Tekillik', 'Psionic Singularity', 'Düşmanlarınızın zihinlerini ve bedenlerini tek bir hiçlik noktasına çökertir.', 'Collapse the minds and bodies of your enemies into a single point of non-existence.', 'Cross-Branch', 100, 1500, 5, '{"pm_psionic_avatar"}', '{"x": -1688, "y": -975}', '{"radius": "200m", "damage": "instant kill below 20% HP", "rewrite_reality": "1 action"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('800a65cf-5678-4ab8-998a-ddda0c1aa6c2', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_1', 'Parlama Rünü', 'Glowing Rune', 'Yayınızı parlayan bir rünle efsunlar, 10m yarıçapında ışık sağlar ve 1 saat boyunca saldırılara 1d4 parlak hasar ekler.', 'Enchants your bow with a glowing rune, providing light in a 10m radius and adding 1d4 radiant damage to attacks for 1 hour.', 'Enchantment', 2, 100, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d4 radiant", "radius": "10m", "duration": "1 hour"}', '🕯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93f515a2-858c-47f0-93d8-144a2adf3748', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_2', 'Takip İşareti', 'Mark of Tracking', 'Okunuzla vurulan bir hedefe görünmez bir rün yerleştirir, 24 saat boyunca 1000m uzaklığa kadar konumlarını tam olarak takip etmenizi sağlar.', 'Places an invisible rune on a target hit by your arrow, allowing you to track their precise location up to 1000m away for 24 hours.', 'Enchantment', 5, 120, 1, '{}', '{"x": 389, "y": -224}', '{"range": "1000m", "duration": "24 hours"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9553b8fe-7685-45cc-bc3f-7be311c93a29', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_3', 'Rüzgar Kutsaması', 'Wind Blessing', 'Yayınıza bir rüzgar rünü kazır, 10 dakika boyunca ok menzilini 20m ve uçuş hızını artırır.', 'Carves a wind rune onto your bow, increasing arrow range by 20m and flight speed for 10 minutes.', 'Enchantment', 12, 150, 1, '{"ra_enchant_1"}', '{"x": 606, "y": -349}', '{"range_increase": "20m", "duration": "10 minutes"}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('290a17b2-93b4-4b44-9505-2aaa9c424643', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_4', 'Parçalanma Rünü', 'Splintering Rune', 'Okları çarpışmada parçalanacak şekilde efsunlar, birincil hedefin 3m yakınındaki tüm düşmanlara 1d6 delici hasar verir.', 'Enchants arrows to splinter upon impact, dealing 1d6 piercing damage to all enemies within 3m of the primary target.', 'Enchantment', 22, 250, 2, '{"ra_enchant_3"}', '{"x": 822, "y": -474}', '{"damage": "1d6 piercing", "radius": "3m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3633b11-1afd-4e0d-8344-c5e587b41bf9', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_5', 'Savunmasızlık İşareti', 'Mark of Vulnerability', 'Bir hedefi zayıflatıcı bir rünle işaretler. 1 dakika boyunca, hedef tüm saldırılarınızdan fazladan 2d6 hasar alır.', 'Marks a target with a weakening rune. For 1 minute, the target takes an extra 2d6 damage from all your attacks.', 'Enchantment', 28, 260, 2, '{"ra_enchant_2"}', '{"x": 1039, "y": -599}', '{"damage_bonus": "2d6", "duration": "1 minute"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4fcd27bc-33d4-4606-a407-615c50226301', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_6', 'Hız Rünü', 'Rune of Speed', 'Bacaklarınızı bir hız rünü ile doldurur, hareket hızını 10m artırır ve 3 tur boyunca tur başına fazladan bir ok atmanızı sağlar.', 'Imbues your legs with a speed rune, increasing movement speed by 10m and allowing you to fire an extra arrow per turn for 3 turns.', 'Enchantment', 35, 280, 2, '{"ra_enchant_4"}', '{"x": 1255, "y": -724}', '{"speed_bonus": "10m", "extra_attack": 1, "duration": "3 turns"}', '👟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e6e781b2-23e2-45f6-b106-26a4e14187cc', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_7', 'Delici Efsun', 'Piercing Enchantment', 'Oklarınızı düşmanları ve siperleri delecek şekilde efsunlar. Oklar 30m boyunca düz bir çizgide ilerleyerek yollarındaki her şeye 3d8 delici hasar verir.', 'Enchants your arrows to pierce through enemies and cover. Arrows travel in a straight line for 30m, hitting everything in their path for 3d8 piercing damage.', 'Enchantment', 42, 400, 3, '{"ra_enchant_6"}', '{"x": 1472, "y": -849}', '{"damage": "3d8 piercing", "range": "30m line"}', '🪡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('08c38fb7-ddae-4877-af4c-41ee9ee55f6b', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_8', 'Gerçek Görüş İşareti', 'True Sight Mark', 'Bir hedefi işaretleyerek zayıflıklarını, görünmezliğini ve illüzyonlarını ortaya çıkarır. Onlara karşı kritik vuruş şansını 3 tur boyunca %15 artırır.', 'Marks a target, revealing their weaknesses, invisibility, and illusions. Increases critical hit chance against them by 15% for 3 turns.', 'Enchantment', 48, 420, 3, '{"ra_enchant_5"}', '{"x": 1688, "y": -974}', '{"crit_chance_bonus": "15%", "duration": "3 turns"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4c4569df-2427-4820-b441-3db64ff5e1ec', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_9', 'Güdüm Rünü', 'Homing Rune', 'Bu rün kazınmış oklar otomatik olarak işaretli hedeflere doğru kavis çizer, yarım ve üç çeyrek siperi yok sayar.', 'Arrows etched with this rune automatically curve towards marked targets, ignoring half and three-quarters cover.', 'Enchantment', 55, 450, 3, '{"ra_enchant_8"}', '{"x": 1905, "y": -1099}', '{"mechanic": "Ignores cover", "target": "Marked enemies"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5950fc04-9525-445f-b65c-38d5b7b05396', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_10', 'Kopyalama Rünü', 'Rune of Duplication', 'Bir ok attığınızda, rün onu havada çoğaltarak hedefe her biri normal hasar veren 3 özdeş ok atar.', 'When you fire an arrow, the rune duplicates it in mid-air, firing 3 identical arrows at the target, each dealing normal damage.', 'Enchantment', 62, 700, 4, '{"ra_enchant_7"}', '{"x": 2121, "y": -1224}', '{"arrows": 3}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('980df16a-06b9-4bf4-8302-ba7704477e70', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_11', 'Kıyamet İşareti', 'Mark of Doom', 'Bir hedefe ölümcül bir işaret yerleştirir. 3 tur sonra, işaret patlayarak 6d10 güç hasarı verir. Hedef patlamadan önce ölürse, işaret en yakın düşmana geçer.', 'Places a lethal mark on a target. After 3 turns, the mark detonates dealing 6d10 force damage. If the target dies before detonation, the mark transfers to the nearest enemy.', 'Enchantment', 68, 750, 4, '{"ra_enchant_9"}', '{"x": 2338, "y": -1349}', '{"damage": "6d10 force", "delay": "3 turns"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0093adfe-bf75-448a-978a-343c6407922a', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_12', 'Zırh Parçalama Rünü', 'Armor Shatter Rune', 'Savunmaları yok etmek için bir oku efsunlar. Vuruşta hedefin zırh sınıfını 1 dakika boyunca 3 azaltır ve her türlü büyülü kalkanı yok eder.', 'Enchants an arrow to destroy defenses. On hit, reduces the target''s armor class by 3 for 1 minute and destroys any magical shields.', 'Enchantment', 75, 800, 4, '{"ra_enchant_11"}', '{"x": 2554, "y": -1474}', '{"ac_reduction": 3, "duration": "1 minute"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16cfa159-1e06-4941-b362-f4bb91f0af8a', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_13', 'Rün Dokuyucu Halesi', 'Rune Weaver''s Aura', '15m''ye uzanan pasif bir hale. Hale içindeki dost menzilli saldırılar rastgele küçük bir rün etkisi kazanır (+1d6 ateş, buz veya yıldırım hasarı).', 'A passive aura extending 15m. Friendly ranged attacks within the aura gain a random minor rune effect (+1d6 fire, ice, or lightning damage).', 'Enchantment', 82, 1200, 5, '{"ra_enchant_10", "ra_enchant_12"}', '{"x": 2771, "y": -1599}', '{"radius": "15m", "bonus_damage": "1d6 random element"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c5859abd-9835-4313-b473-7685a15b55b8', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_enchant_ult', 'Ulti: Mutlak Güç Rünü', 'Ultimate: Rune of Absolute Power', 'Yayınıza nihai güç rününü kazır. 5 dakika boyunca, atılan her ok fazladan 4d12 güç hasarı verir, tüm dirençleri yok sayar ve çarpışmada 5m şok dalgası yaratır.', 'Etches the ultimate rune of power on your bow. For 5 minutes, every arrow fired deals an extra 4d12 force damage, ignores all resistances, and creates a 5m shockwave on impact.', 'Enchantment', 90, 1500, 5, '{"ra_enchant_13"}', '{"x": 2987, "y": -1724}', '{"bonus_damage": "4d12 force", "radius": "5m", "duration": "5 minutes"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('10973a2f-7dc9-47a0-b5c6-44126033f800', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_1', 'Kapan Mührü', 'Snare Sigil', 'Yere görünmez bir mühür yerleştirir. 2m yakınına adım atan ilk düşman, büyülü kökler tarafından 2 tur boyunca hareketsiz bırakılır.', 'Places an invisible sigil on the ground. The first enemy to step within 2m is immobilized for 2 turns by magical roots.', 'Rune Trap', 3, 100, 1, '{}', '{"x": 128, "y": 153}', '{"trigger_radius": "2m", "duration": "2 turns"}', '🪢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c938ac4c-311a-4d68-aef9-d0674659a554', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_2', 'Köz Tuzağı', 'Ember Trap', 'Tetiklendiğinde patlayan ateşli bir rün kurar, 4m yarıçapında 2d6 ateş hasarı verir.', 'Sets a fiery rune that explodes when triggered, dealing 2d6 fire damage in a 4m radius.', 'Rune Trap', 8, 120, 1, '{}', '{"x": 289, "y": 344}', '{"damage": "2d6 fire", "radius": "4m"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f4e5fffa-d5e0-49db-aa76-bf2b062ea774', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_3', 'Alarm Rünü', 'Alarm Rune', '20m''lik bir alanı izleyen bir rün yerleştirir. Bir düşman girerse, sizi sessizce uyarır ve konumlarını zihninize işler.', 'Places a rune that monitors a 20m area. If an enemy enters, it silently alerts you and pings their location on your mind.', 'Rune Trap', 15, 150, 1, '{"ra_trap_1"}', '{"x": 449, "y": 536}', '{"radius": "20m"}', '🚨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('92f9aaa6-6f33-4d5f-b2c1-747dd55d4a7a', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_4', 'Ayaz Koğuşu', 'Frost Ward', 'Yaklaşınca patlayan dondurucu bir tuzak, 3 tur boyunca 6m yarıçapında 3d6 soğuk hasarı verir ve hareket hızını 5m azaltır.', 'A freezing trap that detonates on proximity, dealing 3d6 cold damage and reducing movement speed by 5m in a 6m radius for 3 turns.', 'Rune Trap', 24, 250, 2, '{"ra_trap_2"}', '{"x": 610, "y": 727}', '{"damage": "3d6 cold", "speed_reduction": "5m", "radius": "6m", "duration": "3 turns"}', '❄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e8910ce-b2f7-4f25-b128-e3862450da87', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_5', 'İtme Tuzağı', 'Repulsion Trap', 'Tetiklendiğinde, 5m içindeki tüm düşmanları şiddetle 10m geriye iter, yere düşürür ve 2d8 ezme hasarı verir.', 'When triggered, violently pushes all enemies within 5m back by 10m, knocking them prone and dealing 2d8 bludgeoning damage.', 'Rune Trap', 30, 260, 2, '{"ra_trap_1"}', '{"x": 771, "y": 919}', '{"damage": "2d8 bludgeoning", "push_distance": "10m", "radius": "5m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('efe5989c-4454-4f1c-acf3-a89afdd6147a', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_6', 'Zehir Mührü', 'Venom Sigil', 'Üzerine basıldığında zehirli bir bulut salarak 8m yarıçapındaki düşmanları zehirler. 4 tur boyunca tur başına 1d10 zehir hasarı alırlar.', 'Releases a toxic cloud when stepped on, poisoning enemies in an 8m radius. They take 1d10 poison damage per turn for 4 turns.', 'Rune Trap', 38, 280, 2, '{"ra_trap_3"}', '{"x": 932, "y": 1110}', '{"damage": "1d10 poison per turn", "radius": "8m", "duration": "4 turns"}', '☣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('01c92e6c-a3a5-47f8-8f6c-1c1fd4b566f3', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_7', 'Yıldırım Ağı', 'Lightning Net', 'Yukarı doğru bir elektrik ağı fırlatan karmaşık bir tuzak. 5m yarıçapında yakalanan düşmanlar 4d8 yıldırım hasarı alır ve 1 tur sersemler.', 'A complex trap that fires a net of electricity upwards. Enemies caught in a 5m radius take 4d8 lightning damage and are stunned for 1 turn.', 'Rune Trap', 44, 400, 3, '{"ra_trap_5"}', '{"x": 1092, "y": 1302}', '{"damage": "4d8 lightning", "radius": "5m", "duration": "1 turn stun"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b3c2de3-c83d-4031-95d7-c84f8021c394', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_8', 'Patlama Rünü', 'Blast Rune', 'Son derece uçucu patlayıcı bir rün. Patladığında 10m yarıçapında 6d6 ateş ve 2d6 gök gürültüsü hasarı verir.', 'A highly volatile explosive rune. Deals 6d6 fire and 2d6 thunder damage in a 10m radius upon detonation.', 'Rune Trap', 50, 420, 3, '{"ra_trap_4"}', '{"x": 1253, "y": 1493}', '{"damage": "6d6 fire + 2d6 thunder", "radius": "10m"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0202964b-6430-4f8b-9398-2c63ac555714', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_9', 'Yerçekimi Kuyusu Tuzağı', 'Gravity Well Trap', '15m içindeki tüm yaratıkları merkeze doğru çeken, hızlarını 2 tur boyunca şiddetle 0''a düşüren mikro bir kara delik tetikler.', 'Triggers a micro black hole that pulls all creatures within 15m towards the center, drastically lowering their speed to 0 for 2 turns.', 'Rune Trap', 58, 450, 3, '{"ra_trap_7"}', '{"x": 1414, "y": 1685}', '{"radius": "15m", "duration": "2 turns speed 0"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf77ee8e-eb1e-496b-84d9-a5c94e678b82', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_10', 'Sessizlik Koğuşu', 'Silence Ward', 'Anti-büyü tuzağı. 1 dakika boyunca 15m yarıçapında mutlak sessizlik alanı yaratarak içeride büyü yapılmasını engeller.', 'An anti-magic trap. Creates a 15m radius zone of absolute silence for 1 minute, preventing any spellcasting within.', 'Rune Trap', 64, 700, 4, '{"ra_trap_6"}', '{"x": 1574, "y": 1876}', '{"radius": "15m", "duration": "1 minute"}', '🔇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fe80dfd8-e6f8-4f81-ab0e-18e81da51ebf', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_11', 'Hiçlik Tuzağı', 'Void Trap', 'Tetikleyen yaratığı 3 tur boyunca bir cep hiçlik boyutuna sürgün eder. Döndüğünde 4d10 psişik hasar alır.', 'Banishes the creature that triggers it into a pocket void dimension for 3 turns. Upon return, they take 4d10 psychic damage.', 'Rune Trap', 70, 750, 4, '{"ra_trap_9"}', '{"x": 1735, "y": 2068}', '{"damage": "4d10 psychic", "duration": "3 turns banishment"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff02d052-42f0-4fd0-9484-0313ec095c79', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_12', 'Zincirleme Patlama', 'Chain Detonation', 'Aynı anda 5 diğer tuzağı uzaktan tetikleyebilen, birleşik hasar çıktılarını %50 artıran bir ana rün yerleştirir.', 'Places a master rune that can remotely trigger up to 5 other traps at once, increasing their combined damage output by 50%.', 'Rune Trap', 78, 800, 4, '{"ra_trap_8"}', '{"x": 1896, "y": 2259}', '{"targets": 5, "damage_multiplier": "1.5x"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a516a81-41ed-4085-9a1c-efbeef1b7148', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_13', 'Koğuş Ustası', 'Master of Wards', 'Pasif yetenek. Tuzakları bonus eylem olarak anında kurabilirsiniz ve tuzaklarınız gerçek görüşe bile tamamen görünmez olur.', 'Passive skill. You can place traps instantly as a bonus action, and your traps become completely invisible even to true sight.', 'Rune Trap', 84, 1200, 5, '{"ra_trap_10", "ra_trap_12"}', '{"x": 2056, "y": 2451}', '{"action_type": "Bonus Action", "visibility": "Invisible"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1b2d73f-1275-45dd-8650-b7d770ae3f02', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_trap_ult', 'Ulti: Rün Alanı', 'Ultimate: Domain of Runes', '50m yarıçaplı bir alanı 5 dakika boyunca kişisel alanınıza dönüştürür. Zemin değişen tuzak rünleriyle kaplıdır. İçinde hareket eden düşmanlar hareket ettikleri her 5m''de rastgele bir tuzak (ateş, buz, kapan, yıldırım) tetikler.', 'Transforms a 50m radius area into your personal domain for 5 minutes. The ground is covered in shifting trap runes. Enemies moving through it trigger a random trap (fire, ice, snare, lightning) every 5m they move.', 'Rune Trap', 90, 1500, 5, '{"ra_trap_13"}', '{"x": 2217, "y": 2642}', '{"radius": "50m", "duration": "5 minutes", "trigger_interval": "every 5m moved"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87bd39cb-49d1-4e2c-9d51-3c28a7fe406f', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_1', 'Sır Ok', 'Arcane Arrow', 'Saf sır enerjisinden yapılmış bir ok atar. 1d10 güç hasarı verir ve büyülü olmayan zırhları yok sayar.', 'Fires an arrow made of pure arcane energy. Deals 1d10 force damage and ignores non-magical armor.', 'Magic Shot', 1, 100, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d10 force"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c2d76e12-836e-441a-acf6-d16b183b9633', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_2', 'Parlama Atışı', 'Flare Shot', '30m alanı aydınlatan ve 2d6 ateş hasarı veren alevli bir ok atar. Doğrudan ona bakan düşmanları 1 tur kör edebilir.', 'Shoots a blazing arrow that illuminates a 30m area and deals 2d6 fire damage. Can blind enemies looking directly at it for 1 turn.', 'Magic Shot', 6, 120, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "2d6 fire", "radius": "30m", "duration": "1 turn blind"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f2ed7481-c098-46f1-8490-d34a10f1b15f', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_3', 'Bora Oku', 'Gale Arrow', 'Yoğunlaşmış bir rüzgar rüzgarı atar. 1d8 kesme hasarı verir ve 300 lbs''den hafif hedefleri 5m geriye iter.', 'Fires a concentrated gust of wind. Deals 1d8 slashing damage and knocks targets weighing less than 300 lbs back 5m.', 'Magic Shot', 14, 150, 1, '{"ra_shot_1"}', '{"x": -449, "y": 536}', '{"damage": "1d8 slashing", "push_distance": "5m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b444a277-120b-47be-9add-0932b489a59b', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_4', 'Donuk Vuruş', 'Frostbite Shot', 'Buz gibi bir ok atar. 3d6 soğuk hasarı verir ve hedefin hareket hızını 2 tur boyunca %50 azaltır.', 'Shoots a frigid arrow. Deals 3d6 cold damage and reduces the target''s movement speed by 50% for 2 turns.', 'Magic Shot', 21, 250, 2, '{"ra_shot_2"}', '{"x": -610, "y": 727}', '{"damage": "3d6 cold", "speed_reduction": "50%", "duration": "2 turns"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e070bbb-86cd-44c5-b40a-9f97a47a426b', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_5', 'Kıvılcım Oku', 'Spark Arrow', 'Hedefin 5m yakınındaki 3 düşmana kadar yıldırım sıçratan bir ok atar, hepsine 2d8 yıldırım hasarı verir.', 'Fires an arrow that arcs lightning to up to 3 nearby enemies within 5m of the target, dealing 2d8 lightning damage to all.', 'Magic Shot', 26, 260, 2, '{"ra_shot_1"}', '{"x": -771, "y": 919}', '{"damage": "2d8 lightning", "targets": 3, "radius": "5m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6bbffec2-9704-4118-a0be-c596401c4196', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_6', 'Hayalet Delici', 'Phantom Piercer', 'Hedefi 3d8 nekrotik hasarla vurmak için maddileşmeden önce 2m kalınlığa kadar katı duvarlardan geçen ruhani bir ok atar.', 'Shoots an ethereal arrow that phases through solid walls up to 2m thick before materializing to strike the target for 3d8 necrotic damage.', 'Magic Shot', 32, 280, 2, '{"ra_shot_3"}', '{"x": -932, "y": 1110}', '{"damage": "3d8 necrotic", "pierce_thickness": "2m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24aa3e97-f4ed-44bc-80b1-0374b9b480c7', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_7', 'İnfilak Oku', 'Burst Arrow', 'Havada şarapnele dönüşerek patlayan bir ok atar. İlk hedefin arkasındaki 10m''lik koni içinde 4d6 delici hasar verir.', 'Fires an arrow that explodes into shrapnel mid-air. Deals 4d6 piercing damage in a 10m cone behind the initial target.', 'Magic Shot', 41, 400, 3, '{"ra_shot_5"}', '{"x": -1092, "y": 1302}', '{"damage": "4d6 piercing", "area": "10m cone"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('19fda7a1-011d-47ec-b33d-0494bd2088ed', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_8', 'Kuyrukluyıldız Atışı', 'Comet Shot', 'Yayı muazzam bir güçle geri çekerek buzdan bir iz bırakan parlayan bir mermi fırlatır. 5d8 soğuk/güç hasarı verir.', 'Draws the bow back with immense force, firing a glowing projectile that leaves a trail of ice. Deals 5d8 cold/force damage.', 'Magic Shot', 46, 420, 3, '{"ra_shot_4"}', '{"x": -1253, "y": 1493}', '{"damage": "5d8 cold/force"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0c78e32-7b12-4d6c-a618-04560f3abe1b', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_9', 'Faz Oku', 'Phase Arrow', 'Hedefi kısa süreliğine astral düzleme gönderen bir ok atar. 3d10 psişik hasar verir ve hedef bir sonraki eylemini kaybeder.', 'Shoots an arrow that briefly sends the target to the astral plane. Deals 3d10 psychic damage and the target loses their next action.', 'Magic Shot', 52, 450, 3, '{"ra_shot_6"}', '{"x": -1414, "y": 1685}', '{"damage": "3d10 psychic", "duration": "1 turn stun"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e60d4f18-ebc3-4029-a9d6-ab6570410a2a', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_10', 'Yıldız Düşüşü Yaylımı', 'Starfall Volley', 'Gökyüzüne tek bir ok atar, bu ok onlarca parlak yıldıza bölünür. 15m yarıçaplı bir alana yağarak 6d8 parlak hasar verir.', 'Fires a single arrow into the sky, which splits into dozens of radiant stars. Showers a 15m radius area, dealing 6d8 radiant damage.', 'Magic Shot', 61, 700, 4, '{"ra_shot_7"}', '{"x": -1574, "y": 1876}', '{"damage": "6d8 radiant", "radius": "15m"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae5e5f67-4c01-4f2d-bfa2-8b6ff40041ca', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_11', 'Tutulma Oku', 'Eclipse Arrow', 'Saf karanlıktan bir ok atar. Çarpışmada 20m''lik büyülü bir karanlık küresi yaratır ve birincil hedefe 6d10 nekrotik hasar verir.', 'Fires an arrow of pure darkness. Creates a 20m sphere of magical darkness on impact, and deals 6d10 necrotic damage to the primary target.', 'Magic Shot', 66, 750, 4, '{"ra_shot_9"}', '{"x": -1735, "y": 2068}', '{"damage": "6d10 necrotic", "radius": "20m darkness"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('53e8f718-ab7c-46cb-8581-e0897e2fa010', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_12', 'Prizmatik Atış', 'Prismatic Shot', 'Gökkuşağı renkli bir ok atar. Eşzamanlı olarak 2d6 ateş, soğuk, yıldırım, zehir ve asit hasarı verir (toplam 10d6).', 'Fires a rainbow-colored arrow. Deals 2d6 of fire, cold, lightning, poison, and acid damage simultaneously (10d6 total).', 'Magic Shot', 74, 800, 4, '{"ra_shot_8"}', '{"x": -1896, "y": 2259}', '{"damage": "10d6 mixed"}', '🌈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cea4fe01-4d02-4fe0-adb9-4257166c74f6', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_13', 'Sır Okçu Odaklanması', 'Arcane Archer''s Focus', 'Pasif. Büyülü Atışlarınız %25 daha az mana harcar, menzilleri iki katına çıkar ve kritik vuruş çarpanları x3 olur.', 'Passive. Your Magic Shots cost 25% less mana, have their range doubled, and their critical hit multiplier becomes x3.', 'Magic Shot', 81, 1200, 5, '{"ra_shot_10", "ra_shot_12"}', '{"x": -2056, "y": 2451}', '{"mana_reduction": "25%", "range_multiplier": "2x", "crit_multiplier": "x3"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33df23f1-b03c-4314-b3e4-9b0b67454514', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_shot_ult', 'Ulti: Dünyayı Delen Atış', 'Ultimate: World-Piercing Shot', 'Tüm büyünüzü tek, yıkıcı bir ışın okuna odaklar. 5m genişliğinde, 100m uzunluğunda bir çizgi atar. Yolundaki her şeye 15d10 güç hasarı verir, 0 HP''ye düşen hedefleri parçalar.', 'Focuses all your magic into a single, devastating beam arrow. Shoots a 5m wide, 100m long line. Deals 15d10 force damage to everything in its path, disintegrating targets reduced to 0 HP.', 'Magic Shot', 90, 1500, 5, '{"ra_shot_13"}', '{"x": -2217, "y": 2642}', '{"damage": "15d10 force", "area": "5m x 100m line", "mechanic": "Disintegrate on 0 HP"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b76e7013-fb0f-4f50-a80c-89b8ab253884', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_cb_1', 'Tuzaklı Ok', 'Trapped Arrow', 'Bir oka Rün Tuzağı bağlar. Ok bir hedefe veya yüzeye çarptığında tuzak anında etkinleşir. Tuzağın etkisini okun çarpışmasına ekler.', 'Ties a Rune Trap to an arrow. When the arrow hits a target or surface, the trap immediately activates. Adds the trap''s effect to the arrow''s impact.', 'Cross-Branch', 35, 300, 2, '{"ra_trap_5", "ra_shot_6"}', '{"x": -173, "y": -100}', '{"mechanic": "Combine Trap and Shot"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('621e50b6-e7b5-43ba-aefc-980c2788d3a0', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_cb_2', 'Efsunlu Tuzak', 'Enchanted Trap', 'Tuzaklarınızı silah efsunlarıyla doldurur. Tuzaktan gelen tetiklemeler, alandaki vurulan tüm hedeflere aktif işaretlerinizi (Savunmasızlık İşareti gibi) uygular.', 'Imbues your traps with weapon enchantments. Triggers from the trap will apply your active marks (like Mark of Vulnerability) to all targets hit in the area.', 'Cross-Branch', 45, 480, 3, '{"ra_trap_7", "ra_enchant_7"}', '{"x": -389, "y": -225}', '{"mechanic": "Apply Marks via Traps"}', '❇️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87493cec-a104-4dc9-8bc0-ab1c305ddebd', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_cb_3', 'İşaretli İnfaz', 'Marked Execution', 'İşaretli bir hedefe Büyülü Atış yaptığınızda, ok mükemmel bir şekilde güdümlenir, garantili maksimum hasar verir ve kalkanları yok sayar.', 'When you fire a Magic Shot at a target with a Mark, the arrow perfectly homes in, dealing guaranteed maximum damage and ignoring shields.', 'Cross-Branch', 55, 500, 3, '{"ra_enchant_8", "ra_shot_9"}', '{"x": -606, "y": -350}', '{"mechanic": "Max damage, ignores shields"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('79d371b8-f943-42ce-8e8d-23dae397ba4f', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_cb_4', 'Arayıcı Tuzak Okları', 'Seeking Trap Arrows', '30m yarıçapındaki düşmanları aktif olarak arayan, doğrudan hedeflere yerleşen ve tuzaklarını patlatan birden fazla tuzaklı ok atar.', 'Fires multiple trapped arrows that actively seek out enemies in a 30m radius, planting themselves directly onto the targets and detonating their traps.', 'Cross-Branch', 65, 850, 4, '{"ra_enchant_9", "ra_trap_10", "ra_shot_10"}', '{"x": -822, "y": -475}', '{"radius": "30m", "mechanic": "Homing Trap Detonation"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f3d11e49-ddb8-4516-92cf-5d903aa7b08a', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_cb_5', 'Eylemsel Aşırı Yük', 'Elemental Overload', 'Bir Efsunu üst seviye bir Büyülü Atış ile birleştirir. Bir sonraki Prizmatik Atışınız veya Yıldız Düşüşü Yaylımınız tüm aktif İşaretleri uygular ve düşman zırhını 3 tur boyunca tamamen parçalar (-5 AC).', 'Fuses an Enchantment with a high-tier Magic Shot. Your next Prismatic Shot or Starfall Volley applies all active Marks and shatters enemy armor entirely (-5 AC) for 3 turns.', 'Cross-Branch', 75, 900, 4, '{"ra_enchant_12", "ra_shot_12"}', '{"x": -1039, "y": -600}', '{"ac_reduction": 5, "duration": "3 turns"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf6c2511-a79d-41c4-b54a-7d169df3ae18', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_cb_6', 'Mayın Tarlası Yaylımı', 'Minefield Volley', 'Havaya, 40m''lik bir alana yağan devasa bir ok yaylımı atar. Her ok, yere rastgele bir üst seviye Rün Tuzağı yerleştirerek anında ölümcül bir bölge oluşturur.', 'Fires a massive volley of arrows into the air that rain down over a 40m area. Each arrow plants a random high-tier Rune Trap into the ground, instantly establishing a deadly zone.', 'Cross-Branch', 85, 1300, 5, '{"ra_trap_13", "ra_shot_13"}', '{"x": -1255, "y": -725}', '{"radius": "40m", "mechanic": "Mass Trap Deployment"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aa7a7622-a32e-4aeb-9178-e4e649feea1f', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_cb_7', 'Rünik Avcı Halesi', 'Aura of the Runic Hunter', 'Pasif. İşaret, Tuzak ve Atış büyünüz uyum içindedir. Bir tuzak tetiklendiğinde, tüm İşaretleriniz 2d10 güç hasarı verir. Büyülü bir Atışla her vurduğunuzda, tuzaklarınızın bekleme süreleri 1 tur azalır.', 'Passive. Your Mark, Trap, and Shot magic harmonize. Whenever a trap is triggered, all your Marks deal 2d10 force damage. Whenever you hit with a Magic Shot, your traps'' cooldowns decrease by 1 turn.', 'Cross-Branch', 88, 1400, 5, '{"ra_enchant_13", "ra_trap_13", "ra_shot_13"}', '{"x": -1472, "y": -850}', '{"damage": "2d10 force on trigger", "cooldown_reduction": "1 turn"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('73d2b821-3110-4810-a31b-acf3f66b2b53', '05af1886-c2f3-4757-9c1e-4d3dfea62de6', 'ra_grand_ult', 'Büyük Ulti: Rün Dokuyucunun Hükmü', 'Grand Ultimate: The Rune Weaver''s Judgement', 'Rün Okçusunun nihai sanatını çağırırsınız. Havaya yükselerek devasa bir rün yayı yaratırsınız. Uzayı parçalayan bir ok atarak 100m yarıçapında küresel olarak 100 patlayıcı rün-oku yağdırırsınız. Her ok 5d12 güç hasarı verir ve hayatta kalanlara bilinen her İşareti ve Tuzağı uygular.', 'You invoke the ultimate art of the Rune Archer. You float into the air, creating a massive runic bow. You fire an arrow that shatters space itself, raining down 100 explosive rune-arrows globally within a 100m radius. Each arrow deals 5d12 force damage and applies every known Mark and Trap to any survivor.', 'Cross-Branch', 100, 2500, 5, '{"ra_enchant_ult", "ra_trap_ult", "ra_shot_ult"}', '{"x": -1688, "y": -975}', '{"damage": "500d12 force total", "radius": "100m", "mechanic": "Applies all Marks and Traps"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e9cf9a9f-e6fa-4f30-8d5f-f5de5b1a754d', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_sharpening', 'Keskinleştirme Rünü', 'Rune of Sharpening', 'Bir silahı keskinleştirme rünü ile efsunlayarak +1d4 fiziksel hasar kazandırır.', 'Enchants a weapon with a sharpening rune, granting +1d4 physical damage.', 'Enchantment', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "+1d4 physical", "duration": "1 hour"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1fa2f628-d508-4e45-9c14-5effb5279e5e', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_hardening', 'Sertleştirme Rünü', 'Rune of Hardening', 'Zırha bir sertleştirme rünü kazıyarak +2 Zırh Sınıfı kazandırır.', 'Inscribes a hardening rune on armor, granting +2 AC.', 'Enchantment', 4, 70, 1, '{"rm_rune_sharpening"}', '{"x": 389, "y": -224}', '{"ac_bonus": "+2", "duration": "1 hour"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('85048cdf-aa2c-4e6c-93a7-997de6e5f2c7', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_feather', 'Tüy Rünü', 'Rune of the Feather', 'Çizmelere bir tüy rünü kazıyarak hareket hızını 4m artırır ve düşme hasarını engeller.', 'Inscribes a feather rune on boots, increasing movement speed by 4m and removing fall damage.', 'Enchantment', 8, 100, 1, '{"rm_rune_hardening"}', '{"x": 606, "y": -349}', '{"speed_bonus": "+4m", "duration": "1 hour"}', '🪶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('edd33293-cf35-4c15-8cb8-13b98fe888ff', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_flaming_edge', 'Alevli Kenar Rünü', 'Flaming Edge Rune', 'Bir silahı alev rünüyle güçlendirerek isabet halinde fazladan 2d6 ateş hasarı verir.', 'Imbues a weapon with a flaming rune, dealing an extra 2d6 fire damage on hit.', 'Enchantment', 22, 180, 2, '{"rm_rune_feather"}', '{"x": 822, "y": -474}', '{"damage": "+2d6 fire", "duration": "30 minutes"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('56975bca-eebd-4380-863a-d0228294a8f4', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_frost_guard', 'Ayaz Koruması Rünü', 'Frost Guard Rune', 'Zırhı ayaz ile efsunlar. Size saldıranlar 1 tur boyunca %50 yavaşlar.', 'Enchants armor with frost. Attackers are slowed by 50% for 1 turn upon striking you.', 'Enchantment', 26, 200, 2, '{"rm_rune_feather"}', '{"x": 1039, "y": -599}', '{"slow": "50%", "duration": "30 minutes"}', '❄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2eb43482-b204-4f96-b8bf-fead7d792404', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_mending', 'Onarım Rünü', 'Rune of Mending', 'Bir hedefin ekipmanına onarım rünü yerleştirerek her tur 1d4 can iyileştirir.', 'Places a mending rune on a target''s gear, healing them for 1d4 health per turn.', 'Enchantment', 32, 250, 2, '{"rm_flaming_edge", "rm_frost_guard"}', '{"x": 1255, "y": -724}', '{"healing": "1d4 per turn", "duration": "10 turns"}', '🛠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('967d8095-7f36-4a06-b1f5-148e60ea4fb6', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_leech', 'Sömürü Rünü', 'Rune of the Leech', 'Bir silahı sömürü rünüyle efsunlayarak verilen hasarın %20''sini cana dönüştürür.', 'Enchants a weapon with a leech rune, converting 20% of damage dealt into health.', 'Enchantment', 42, 350, 3, '{"rm_rune_mending"}', '{"x": 1472, "y": -849}', '{"lifesteal": "20%", "duration": "10 minutes"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8c051565-5fc3-460a-9748-4ce6b0de19b6', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_shockwave', 'Şok Dalgası Rünü', 'Rune of Shockwave', 'Efsunlu silah isabet ettiğinde, 5m yarıçapında 3d8 gök gürültüsü hasarı veren bir şok dalgası yayar.', 'When the enchanted weapon strikes, it unleashes a 5m shockwave dealing 3d8 thunder damage.', 'Enchantment', 48, 400, 3, '{"rm_rune_leech"}', '{"x": 1688, "y": -974}', '{"damage": "3d8 thunder", "radius": "5m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55d1a0d0-85d3-4882-97ab-d86923593b51', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_deflecting_rune', 'Saptırma Rünü', 'Deflecting Rune', 'Gelen fiziksel hasarın %30''unu saldırgana geri yansıtan bir saptırma rünü kazır.', 'Inscribes a deflecting rune that returns 30% of incoming physical damage back to the attacker.', 'Enchantment', 55, 450, 3, '{"rm_rune_shockwave"}', '{"x": 1905, "y": -1099}', '{"reflection": "30%", "duration": "5 turns"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('89437628-21c7-4ec2-bf40-497f6b8a7462', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_giant', 'Dev Rünü', 'Rune of the Giant', 'Kullanıcının boyutunu devasa ölçüde artıran ve +6 Güç kazandıran bir efsun uygular.', 'Enchants armor to drastically increase the wearer''s size, granting +6 Strength and huge size.', 'Enchantment', 62, 650, 4, '{"rm_deflecting_rune"}', '{"x": 2121, "y": -1224}', '{"size": "Huge", "strength_bonus": "+6", "duration": "5 turns"}', '🧌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('572a7669-271d-4d71-8f42-5e9e7bd470c6', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_phase', 'Faz Rünü', 'Rune of Phase', 'Bir silahı geçici olarak gerçeklikten çıkaran bir rünle efsunlar; 3 tur boyunca zırhı tamamen yok sayar.', 'Enchants a weapon to temporarily phase out of reality, ignoring armor completely for 3 turns.', 'Enchantment', 68, 700, 4, '{"rm_rune_giant"}', '{"x": 2338, "y": -1349}', '{"bypass_armor": "100%", "duration": "3 turns"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fd44455c-cddb-4488-ace0-4acef462be22', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_overclock_rune', 'Aşırı Yük Rünü', 'Overclock Rune', 'Bir silaha aşırı yük rünü kazıyarak kullanıcının tur başına fazladan 2 saldırı yapmasını sağlar.', 'Inscribes an overclocking rune on a weapon, allowing the wielder to make 2 additional attacks per turn.', 'Enchantment', 75, 800, 4, '{"rm_rune_phase"}', '{"x": 2554, "y": -1474}', '{"extra_attacks": "+2", "duration": "3 turns"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f898e603-3476-4cf2-b799-d65fb14a4fb0', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_rune_phoenix', 'Anka Rünü', 'Rune of the Phoenix', 'Kullanıcıyı öldüğünde %50 canla otomatik olarak dirilten derin bir efsun.', 'A profound enchantment that automatically revives the wearer with 50% health upon death.', 'Enchantment', 82, 1100, 5, '{"rm_overclock_rune"}', '{"x": 2771, "y": -1599}', '{"revive_health": "50%", "duration": "24 hours"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b68980ba-2512-4012-86dc-3844b31179e4', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_worldforge_blessing', 'Dünya Ocağı Kutsaması', 'Worldforge Blessing', 'Nihai efsun. 20m içindeki tüm müttefiklerin ekipmanlarını anında efsunlayarak devasa güç ve savunma kazandırır.', 'Ultimate enchantment. Instantly enchants the gear of all allies within 20m, granting immense power and defense.', 'Enchantment', 92, 1500, 5, '{"rm_rune_phoenix"}', '{"x": 2987, "y": -1724}', '{"damage_bonus": "+4d10", "ac_bonus": "+5", "radius": "20m", "duration": "10 turns"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('99ca277b-a832-49ff-b69e-75efe8b3ebf2', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_ward_warning', 'Uyarı Sembolü', 'Ward of Warning', 'Bir yaratık 10m yarıçapına girdiğinde büyücüyü zihinsel olarak uyaran görünmez bir sembol yerleştirir.', 'Places an invisible ward that alerts the caster mentally when a creature enters its 10m radius.', 'Ward', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"radius": "10m", "duration": "8 hours"}', '🔔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f97bc49d-b78d-4b5c-9c18-d08c0491f0c0', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_snare_ward', 'Kapan Sembolü', 'Snare Ward', 'Yere bir sembol çizer. Üzerine basıldığında hedefi 2 tur boyunca olduğu yere sabitler.', 'Places a ward on the ground. When stepped on, it roots the target in place for 2 turns.', 'Ward', 6, 80, 1, '{"rm_ward_warning"}', '{"x": 289, "y": 344}', '{"root_duration": "2 turns", "trigger_radius": "2m"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d1c483af-fb43-48ae-89a3-ccccc1aec6ad', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_repelling_ward', 'İtici Sembol', 'Repelling Ward', 'Tetiklendiğinde izinsiz giren yaratıkları şiddetle 10m uzağa fırlatan gizli bir sembol.', 'A hidden ward that violently repels any unauthorized creature 10m away when triggered.', 'Ward', 12, 120, 1, '{"rm_snare_ward"}', '{"x": 449, "y": 536}', '{"knockback": "10m", "trigger_radius": "3m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6dc90f45-ef47-4c0e-8801-97dc8a7e1035', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_explosive_ward', 'Patlayıcı Sembol', 'Explosive Ward', 'Yaklaşıldığında patlayan ve 5m yarıçapında 6d6 ateş hasarı veren dengesiz bir sembol yerleştirir.', 'Places a volatile ward that explodes upon proximity, dealing 6d6 fire damage in a 5m radius.', 'Ward', 24, 190, 2, '{"rm_repelling_ward"}', '{"x": 610, "y": 727}', '{"damage": "6d6 fire", "radius": "5m"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cd5b3204-1dde-42fb-9c2c-d210a67430ce', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_silence_ward', 'Sessizlik Sembolü', 'Silence Ward', 'Etkinleştirildiğinde 10m yarıçapındaki tüm sesleri ve büyü yapımını susturan bir sembol.', 'A ward that mutes all sound and spellcasting within a 10m radius when activated.', 'Ward', 28, 220, 2, '{"rm_explosive_ward"}', '{"x": 771, "y": 919}', '{"silence_duration": "3 turns", "radius": "10m"}', '🤐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('96037470-f1c3-4557-814c-2d4c0102391a', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_ward_healing', 'Şifa Sembolü', 'Ward of Healing', 'Üzerine basıldığında 5m içindeki müttefikleri 2d8 can iyileştiren iyicil bir sembol.', 'A benevolent ward that heals allies within 5m for 2d8 health when they step on it.', 'Ward', 35, 260, 2, '{"rm_silence_ward"}', '{"x": 932, "y": 1110}', '{"healing": "2d8", "radius": "5m"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2b990a3b-2d9f-493a-ba90-7d3d6fd05b2f', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_lightning_tether_ward', 'Yıldırım Bağı Sembolü', 'Lightning Tether Ward', 'İzinsiz gireni yıldırımla vuran ve onu 5m''den uzağa kaçmasını engelleyecek şekilde bağlayan bir sembol.', 'A ward that strikes the intruder with lightning and tethers them, preventing escape beyond 5m.', 'Ward', 44, 380, 3, '{"rm_ward_healing"}', '{"x": 1092, "y": 1302}', '{"damage": "4d8 lightning", "tether_duration": "3 turns"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eeebe247-2fc7-4887-9e54-52d97008458e', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_ward_confusion', 'Karmaşa Sembolü', 'Ward of Confusion', '8m içindeki düşmanların kafasını karıştırarak rastgele saldırmalarına neden olan zihin bükücü bir sembol.', 'A complex mind-altering ward that confuses enemies within 8m, causing them to attack randomly.', 'Ward', 50, 420, 3, '{"rm_lightning_tether_ward"}', '{"x": 1253, "y": 1493}', '{"confusion_duration": "3 turns", "radius": "8m"}', '😵‍💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d46c7a5d-74dc-442b-9a91-c836a0087a9d', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_nullification_ward', 'Sıfırlama Sembolü', 'Nullification Ward', '10m alandaki tüm aktif büyü etkilerini anında bozan güçlü bir anti-büyü sembolü.', 'A powerful anti-magic ward that instantly dispels all active magical effects in a 10m area.', 'Ward', 58, 480, 3, '{"rm_ward_confusion"}', '{"x": 1414, "y": 1685}', '{"dispel_magic": "100%", "radius": "10m"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('36d53312-3e13-4d5c-8da1-28dd739bab6b', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_gravity_ward', 'Yerçekimi Sembolü', 'Gravity Ward', '15m yarıçapında yerçekimini inanılmaz artırarak düşman hareket hızını %90 azaltır.', 'Increases gravity dramatically in a 15m radius, reducing enemy movement speed by 90%.', 'Ward', 64, 620, 4, '{"rm_nullification_ward"}', '{"x": 1574, "y": 1876}', '{"movement_reduction": "90%", "radius": "15m"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('be5ec951-6505-410f-bb6c-8302e9dfdf12', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_ward_petrification', 'Taşlaşma Sembolü', 'Ward of Petrification', '6m yarıçapına giren her düşman yaratığı 3 tur boyunca taşa çeviren ölümcül bir tuzak.', 'A deadly trap that turns any hostile creature entering its 6m radius to stone for 3 turns.', 'Ward', 72, 720, 4, '{"rm_gravity_ward"}', '{"x": 1735, "y": 2068}', '{"petrify_duration": "3 turns", "radius": "6m"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e91f10ec-93c4-4723-bb35-591a6de4be3b', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_mirror_ward', 'Ayna Sembolü', 'Mirror Ward', 'Bir alanın etrafında hedeflenen tüm büyüleri büyücülere geri yansıtan bir koruma alanı yaratır.', 'Creates a warding field around an area that reflects all targeted spells back to their casters.', 'Ward', 78, 850, 4, '{"rm_ward_petrification"}', '{"x": 1896, "y": 2259}', '{"spell_reflection": "100%", "duration": "2 turns"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a6d1757-cf61-4aa0-b611-497a2c5dd8fc', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_prison_ward', 'Boyutsal Zindan Sembolü', 'Dimensional Prison Ward', 'Onu tetikleyen yaratığı 5 tur boyunca cep boyutuna sürgün eden efsanevi bir sembol.', 'A legendary ward that banishes the creature who triggers it into a pocket dimension for 5 turns.', 'Ward', 85, 1150, 5, '{"rm_mirror_ward"}', '{"x": 2056, "y": 2451}', '{"banish_duration": "5 turns", "target": "1 creature"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d8fdfd6-897a-4468-8d59-675c90f8b79a', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_absolute_sanctuary', 'Mutlak Sığınak', 'Absolute Sanctuary', 'Nihai sembol. Müttefiklerin hasar almadığı ve negatif etkilerin giremediği aşılmaz 15m''lik bir alan yaratır.', 'Ultimate ward. Creates an impenetrable 15m zone where allies take no damage and negative effects cannot enter.', 'Ward', 94, 1450, 5, '{"rm_prison_ward"}', '{"x": 2217, "y": 2642}', '{"immunity": "100%", "radius": "15m", "duration": "5 turns"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35b32720-b798-4d35-b858-ceb968b0c4ad', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_decipher_text', 'Kadim Metinleri Çözme', 'Decipher Text', 'Büyücünün her türlü kadim veya gizli dili mükemmel bir şekilde okuyup anlamasını sağlar.', 'Allows the caster to read and understand any ancient or cryptic language perfectly.', 'Ancient', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"comprehension": "100%", "duration": "1 hour"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a294f16d-02a5-404c-9c22-8e3de3f9780a', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_ancient_missile', 'Kadim Mermi', 'Ancient Missile', '30m uzaklıktaki bir hedefi şaşmaz bir şekilde vuran saf güçten oluşan rünik bir ok ateşler.', 'Fires a runic bolt of pure force that unerringly strikes a target 30m away.', 'Ancient', 7, 90, 1, '{"rm_decipher_text"}', '{"x": -289, "y": 344}', '{"damage": "3d4 force", "range": "30m"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4c9d1312-74ab-44af-a3d9-e17a0cad1179', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_glyph_light', 'Işık Glifi', 'Glyph of Light', '20m''yi aydınlatan ve ona bakan düşmanları kör eden parlayan kadim bir glif çağırır.', 'Summons a glowing ancient glyph that illuminates 20m and blinds enemies looking at it.', 'Ancient', 14, 130, 1, '{"rm_ancient_missile"}', '{"x": -449, "y": 536}', '{"light_radius": "20m", "blindness": "1 turn"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a041cdfe-56c2-440c-9b80-ed3c992c5058', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_runic_familiar', 'Rünik Yoldaş', 'Runic Familiar', 'Savaşta ve gündelik işlerde yardımcı olması için rün taşlarından küçük bir yapılandırılmış yaratık canlandırır.', 'Animates a small construct out of runestones to assist the caster in combat and utility.', 'Ancient', 25, 185, 2, '{"rm_glyph_light"}', '{"x": -610, "y": 727}', '{"summon": "Runic Construct", "duration": "1 hour"}', '🐕');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46c8dec5-e4b2-4e47-be3b-4e9f52f02ef1', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_word_binding', 'Bağlama Sözcüğü', 'Word of Binding', 'Kadim bağlama büyüsünün bir kelimesini söyleyerek 15m içindeki bir hedefi 2 tur felç eder.', 'Speaks a word of ancient binding magic, paralyzing a target within 15m for 2 turns.', 'Ancient', 30, 230, 2, '{"rm_runic_familiar"}', '{"x": -771, "y": 919}', '{"paralysis": "2 turns", "range": "15m"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07858377-0be2-4c9a-a41d-f6ec7f6f8526', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_scroll_ancients', 'Kadimlerin Parşömeni', 'Scroll of the Ancients', 'Ruhani bir parşömenden okuyarak unutulmuş bir çağdan rastgele güçlü bir büyü yapar.', 'Reads from an ethereal scroll, casting a random powerful spell from a forgotten era.', 'Ancient', 38, 280, 2, '{"rm_word_binding"}', '{"x": -932, "y": 1110}', '{"spell_copy": "1 random spell", "duration": "Instant"}', '🖜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a6008a6-7f22-49fe-b4af-9b13fbd6bae1', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_erase_magic', 'Büyü Yok Etme', 'Erase Magic', 'Yok oluş hecesini söyleyerek 20m içindeki büyülü bir etkiyi veya çağrılmış yaratığı tamamen siler.', 'Utters a syllable of unmaking, completely erasing a magical effect or summon within 20m.', 'Ancient', 46, 360, 3, '{"rm_scroll_ancients"}', '{"x": -1092, "y": 1302}', '{"remove_magic": "Target", "range": "20m"}', '🧽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fda6cc3e-32aa-43a2-b704-83d012817a48', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_word_power_push', 'Güç Sözcüğü: İtiş', 'Word of Power: Push', '4d10 güç hasarı veren ve bir koni içindeki tüm düşmanları 15m uzağa fırlatan muazzam bir güç sözcüğü.', 'A word of immense power that deals 4d10 force damage and blasts all enemies in a cone 15m away.', 'Ancient', 52, 410, 3, '{"rm_erase_magic"}', '{"x": -1253, "y": 1493}', '{"knockback": "15m", "damage": "4d10 force"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3690db07-96f8-4063-ad43-ba6784232f76', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_ancient_golem', 'Kadim Golem', 'Ancient Golem', 'Sizin için savaşması adına rünik büyüyle aşılanmış devasa bir Kadim Golem çağırır.', 'Summons a towering Ancient Golem infused with runic magic to fight for you.', 'Ancient', 59, 490, 3, '{"rm_word_power_push"}', '{"x": -1414, "y": 1685}', '{"summon": "Ancient Golem", "duration": "10 minutes"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('597027e3-04aa-456d-85e9-9353d86ee535', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_runic_monolith', 'Rünik Monolit', 'Runic Monolith', '30m içindeki tüm müttefiklere %20 statü artışı sağlayan devasa bir Rünik Monolit indirir.', 'Calls down a massive Runic Monolith that grants a 20% stat boost to all allies within 30m.', 'Ancient', 66, 630, 4, '{"rm_ancient_golem"}', '{"x": -1574, "y": 1876}', '{"buff": "+20% stats to allies", "radius": "30m"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('631bdb54-285e-4698-8520-0b26f395cef8', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_word_power_shatter', 'Güç Sözcüğü: Parçalama', 'Word of Power: Shatter', 'Fiziksel nesneleri parçalayan, zırhları yok eden ve 10d8 ses hasarı veren yıkıcı bir sözcük.', 'A devastating word that shatters physical objects, destroys armor, and deals 10d8 sonic damage.', 'Ancient', 74, 730, 4, '{"rm_runic_monolith"}', '{"x": -1735, "y": 2068}', '{"damage": "10d8 sonic", "destroy_armor": "Yes"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('53113c8e-6be1-45ce-9f4c-9f8f04d16df6', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_time_lost_rune', 'Zamanın Unuttuğu Rün', 'Time-Lost Rune', 'Zamanın dışına çıkan bir rünü etkinleştirerek büyücüye fazladan 1 serbest tur eylem hakkı tanır.', 'Activates a rune that steps outside of time, granting the caster 1 free turn of action.', 'Ancient', 80, 860, 4, '{"rm_word_power_shatter"}', '{"x": -1896, "y": 2259}', '{"time_stop": "1 turn", "range": "Personal"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2b77f6c2-6ce4-4e44-978c-b29e030350b9', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_word_power_kill', 'Güç Sözcüğü: Ölüm', 'Word of Power: Kill', 'Yok oluşun nihai sözcüğünü söyler. 15m içindeki bir yaratığın 100 veya daha az canı varsa anında öldürür.', 'Speaks the ultimate word of undoing. Instantly kills a creature within 15m if it has 100 HP or less.', 'Ancient', 88, 1200, 5, '{"rm_time_lost_rune"}', '{"x": -2056, "y": 2451}', '{"instant_death_threshold": "100 HP", "range": "15m"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49da7f0c-b667-4700-bf31-1c5e623bc864', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_echoes_creation', 'Yaratılış Yankıları', 'Echoes of Creation', 'Nihai kadim büyü. Yaratılışın sözcüklerini söyleyerek tüm müttefikleri tamamen iyileştirir ve 40m içindeki düşmanlara kıyamet hasarı verir.', 'Ultimate ancient magic. Speaks the words of creation, healing all allies to full and dealing apocalyptic damage to enemies in 40m.', 'Ancient', 96, 1480, 5, '{"rm_word_power_kill"}', '{"x": -2217, "y": 2642}', '{"reality_warp": "Massive damage & heal", "radius": "40m"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5075042a-fffe-4caf-8f95-7139fdb632c5', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_warded_armor', 'Korumalı Zırh', 'Warded Armor', 'Zırhı gizli sembollerle efsunlar. Darbe alındığında %20 ihtimalle saldırganın ayaklarının dibine patlayıcı bir sembol bırakır.', 'Enchants armor with hidden wards. When struck, there''s a 20% chance to drop an explosive ward at the attacker''s feet.', 'Cross-Branch', 36, 250, 2, '{"rm_flaming_edge", "rm_ward_healing"}', '{"x": -173, "y": -100}', '{"ac_bonus": "+3", "ward_drop_chance": "20%"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c6dbdbd-1698-4a2c-b8fb-997f7295cf38', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_ancient_trap', 'Kadim Tuzak', 'Ancient Trap', 'Tetikleyen ilk yaratığı bağlayan ve ona ağır hasar veren, üzerinde kadim metinler yazılı gizli bir tuzak kurar.', 'Sets a hidden trap inscribed with ancient texts that binds and heavily damages the first creature to trigger it.', 'Cross-Branch', 40, 290, 2, '{"rm_ward_healing", "rm_scroll_ancients"}', '{"x": -389, "y": -225}', '{"damage": "8d6 force", "snare_duration": "2 turns"}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0bfbe6dc-e008-4995-8659-bb76bc355d61', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_golem_forging', 'Golem İşleme', 'Golem Forging', 'Kadim Golem''inizi kalıcı olarak efsunlayarak statülerini %50 artırır ve ona alevli saldırılar kazandırır.', 'Permanently enchants your Ancient Golem, boosting its stats by 50% and granting it flaming attacks.', 'Cross-Branch', 56, 450, 3, '{"rm_rune_shockwave", "rm_ancient_golem"}', '{"x": -606, "y": -350}', '{"golem_buff": "+50% stats, flaming fists"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2cb109f1-332e-425d-9e46-24ffca16e245', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_weapon_warding', 'Muhafızın Silahı', 'Weapon of Warding', 'Başarılı her vuruşta yere küçük bir itici sembol bırakması için bir silahı efsunlar.', 'Enchants a weapon to place a mini repelling ward on the ground upon every successful strike.', 'Cross-Branch', 60, 480, 3, '{"rm_deflecting_rune", "rm_nullification_ward"}', '{"x": -822, "y": -475}', '{"ward_on_hit": "10% chance"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('275c8f67-93c0-4fdd-bcb9-df2b9c332fae', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_runic_fortress', 'Rünik Kale', 'Runic Fortress', 'Kadim büyü ve sembolleri birleştirerek, içerideki müttefiklerin zırhını artıran ve düşmanlara hasar veren 20m''lik bir kale alanı yaratır.', 'Combines ancient magic and warding to create a 20m fortress zone, buffing allies'' AC and damaging enemies inside.', 'Cross-Branch', 70, 750, 4, '{"rm_gravity_ward", "rm_runic_monolith"}', '{"x": -1039, "y": -600}', '{"zone_ac": "+5", "zone_damage": "2d8 per turn", "radius": "20m"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3031da47-94ee-451d-9843-3a6bbfcdef62', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_word_empowerment', 'Güçlendirme Sözcüğü', 'Word of Empowerment', '30m içindeki tüm müttefiklerin silahlarını geçici olarak saf güçle efsunlayan kadim bir sözcük haykırır.', 'Shouts an ancient word that temporarily enchants the weapons of all allies within 30m with raw force.', 'Cross-Branch', 76, 820, 4, '{"rm_overclock_rune", "rm_word_power_shatter"}', '{"x": -1255, "y": -725}', '{"group_enchant": "+3d6 force damage", "radius": "30m"}', '📣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0c8c1c65-5c79-4ade-b8a0-ac17a5b7da28', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_masters_convergence', 'Ustanın Yakınsaması', 'Master''s Convergence', 'Mobil bir sembol görevi gören ve yakındaki müttefikleri otomatik olarak efsunlayan uçan kristal bir yoldaş çağırır.', 'Summons a floating crystalline familiar that acts as a mobile ward, enchanting nearby allies automatically.', 'Cross-Branch', 79, 880, 4, '{"rm_rune_phase", "rm_mirror_ward", "rm_time_lost_rune"}', '{"x": -1472, "y": -850}', '{"summon": "Ward Familiar", "buff_radius": "10m"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('acf83b89-da90-4f23-b857-14bbb1cf86cf', '6c24fb30-e8d4-4bfc-9eac-ae5389321f80', 'rm_the_world_rune', 'Dünya Rünü', 'The World Rune', 'Büyük Nihai. Gerçekliğin dokusuna bir rün kazıyarak dünyanın kurallarını Rün Ustası''nın mutlak iradesine göre büker.', 'Grand Ultimate. Etches a rune upon the very fabric of reality, bending the world''s laws to the Rune Master''s absolute will.', 'Grand Ultimate', 100, 1500, 5, '{"rm_worldforge_blessing", "rm_absolute_sanctuary", "rm_echoes_creation"}', '{"x": 173, "y": -99}', '{"global_reality_overwrite": "Immeasurable"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b0a80697-ba9f-4772-8b39-10f63f621f3d', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_draw', 'Hızlı Çekiş', 'Quick Draw', 'Kından yıldırım hızında bir çekiş yaparak hedefe 2X (iki kez) vurur. Her vuruş 1d8 kesici hasar verir.', 'Perform a lightning-fast quick draw from the scabbard, hitting the target 2X. Each hit deals 1d8 slashing damage.', 'Iaijutsu', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "2x 1d8", "range": "2m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('69817e32-2b34-4841-9b08-b139c1e53cb9', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_step', 'Flaş Adımı', 'Flash Step', 'Anında 5m ileri atılır ve 1d6 kesici hasar veren hızlı bir vuruş yapar.', 'Dash up to 5m instantaneously and deliver a swift strike dealing 1d6 slashing damage.', 'Iaijutsu', 1, 50, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "1d6", "range": "5m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b8d79259-54cc-46f8-bfdf-ba109371d239', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_sheathe', 'Kılıç Kınlama Odağı', 'Resheathing Focus', 'Kılıcınızı sakince kınına koyarsınız. 1 dakika içindeki bir sonraki saldırınız ekstra 1d6 hasar verir ve avantajlı olur.', 'Calmly resheathe your blade. Your next attack within 1 minute deals an additional 1d6 damage and has advantage.', 'Iaijutsu', 5, 100, 1, '{"sm_iai_draw"}', '{"x": 606, "y": -349}', '{"damage_bonus": "1d6", "buff": "Advantage"}', '🎴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55792987-dd05-48d7-9569-4e52a5c8ebb4', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_gale', 'Fırtına Vuruşu', 'Gale Strike', 'Rüzgarla aşılanmış şiddetli bir kesik savurur. Vuruş 2X vurur ve her isabet 1d10 kesici hasar verir.', 'Unleash a fierce wind-infused slash. The strike hits 2X, dealing 1d10 slashing damage per hit.', 'Iaijutsu', 21, 200, 2, '{"sm_iai_draw"}', '{"x": 822, "y": -474}', '{"damage": "2x 1d10", "range": "3m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e3474d05-e254-4d9a-a0f3-f27e05593754', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_phantom', 'Hayalet Çekiş', 'Phantom Draw', 'Hayalet bir silüet olarak 15m''ye kadar atılır, düşmanların içinden geçerek onlara 2d8 kesici hasar verir.', 'Dash up to 15m as a phantom image, passing through enemies and dealing 2d8 slashing damage to all passed through.', 'Iaijutsu', 21, 250, 2, '{"sm_iai_step"}', '{"x": 1039, "y": -599}', '{"damage": "2d8", "range": "15m line"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70aa5c75-81dd-468c-a5aa-f9b0516f0ba4', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_counter', 'İai Karşı Saldırısı', 'Iai Counter', 'Bir karşı saldırı duruşu alır. Yakın dövüşte saldırıya uğrarsa, hasarı yok sayar ve anında 2d6 kesici hasarla misilleme yapar.', 'Adopt a counter stance. If attacked in melee, negate the hit and instantly retaliate for 2d6 slashing damage.', 'Iaijutsu', 25, 300, 2, '{"sm_iai_sheathe"}', '{"x": 1255, "y": -724}', '{"damage": "2d6", "mechanic": "Parry & Counter"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b818f630-c8d1-45d7-b1ba-feb010816d8a', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_blossom', 'Kiraz Çiçeği Vuruşu', 'Cherry Blossom Strike', 'Güzel ve peş peşe vuruşlar. 3m yarıçaptaki tüm düşmanlara 3x 1d8 kesici hasar verir.', 'A flurry of beautiful strikes. Deals 3x 1d8 slashing damage to all enemies within a 3m radius.', 'Iaijutsu', 41, 400, 3, '{"sm_iai_gale"}', '{"x": 1472, "y": -849}', '{"damage": "3x 1d8", "aoe": "3m radius"}', '🌸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0ed4e62-f8b3-4c35-b567-53d4aca47d56', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_vacuum', 'Vakum Kesik', 'Vacuum Slash', 'Kılıcı o kadar hızlı çeker ki bir vakum oluşturur. 10m''lik bir hatta 3d8 kesici hasar verir ve düşmanları size doğru 2m çeker.', 'Draw the blade so fast it creates a vacuum. Deals 3d8 slashing damage in a 10m line, pulling enemies 2m towards you.', 'Iaijutsu', 41, 450, 3, '{"sm_iai_gale"}', '{"x": 1688, "y": -974}', '{"damage": "3d8", "range": "10m line", "pull": "2m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cae48066-12da-40d2-b697-24568ce3bd98', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_blink', 'Göz Kırpma Vuruşu', 'Blink Strike', '10m''ye kadar ışınlanıp doğrudan bir düşmanın arkasına geçer ve 3d6 kesici hasar vurur. Düşmanı şaşkına çevirir.', 'Teleport up to 10m directly behind an enemy and strike for 3d6 slashing damage. Leaves the enemy surprised.', 'Iaijutsu', 45, 500, 3, '{"sm_iai_phantom"}', '{"x": 1905, "y": -1099}', '{"damage": "3d6", "range": "10m teleport"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fd60c9af-b082-47ea-b850-f52e0276c506', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_thousand', 'Bin Kesik', 'Thousand Cuts', 'Tek bir hedefe ezici bir vuruş yağmuru yapar. Her biri 1d8 kesici hasar veren 5 isabet sağlar.', 'Deliver an overwhelming barrage of strikes against a single target. Hits 5 times for 1d8 slashing damage each.', 'Iaijutsu', 61, 700, 4, '{"sm_iai_blossom"}', '{"x": 2121, "y": -1224}', '{"damage": "5x 1d8", "range": "2m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e8bb1754-b190-4179-9eb3-eaed902bce37', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_swallow', 'Kırlangıç Dönüşü', 'Swallow Return', 'Efsanevi teknik. Kaçınılmaz bir saldırı olarak 2X vurur, isabet başına 4d10 hasar verir. Savunmaları ve kaçınmayı yok sayar.', 'The legendary technique. An unavoidable attack that hits 2X, dealing 4d10 damage per hit. Ignores evasion.', 'Iaijutsu', 61, 800, 4, '{"sm_iai_counter", "sm_iai_vacuum"}', '{"x": 2338, "y": -1349}', '{"damage": "2x 4d10", "range": "2m", "unavoidable": true}', '🐦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f58d13fd-6c0b-48dc-9752-126c8d29be9b', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_void', 'Hiçlik Çekişi', 'Void Draw', 'Kılıcınızı uzay dokusunun içinden çekersiniz. Zırhı ve büyülü bariyerleri tamamen yok sayarak 5d10 hasar verir.', 'Draw your blade through the fabric of space. Deals 5d10 damage, completely ignoring armor and magical barriers.', 'Iaijutsu', 65, 900, 4, '{"sm_iai_vacuum"}', '{"x": 2554, "y": -1474}', '{"damage": "5d10", "armor_pierce": "100%"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('210062c9-fe77-42fa-bb4e-18315b55c224', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_time', 'Zaman Yaran', 'Time Splitter', 'O kadar hızlı hareket eder ki zaman durmuş gibi görünür. Tek bir hedefe anında 2d8 kesici hasar veren 8 vuruş yapar.', 'Move so fast time seems to stop. Instantly deliver 8 hits of 2d8 slashing damage to a single target.', 'Iaijutsu', 81, 1200, 5, '{"sm_iai_thousand", "sm_iai_blink"}', '{"x": 2771, "y": -1599}', '{"damage": "8x 2d8", "speed": "Instant"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('517d8a64-60a0-4fee-a6a0-3ca0462d23d1', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_iai_dimension', 'Boyutsal Koparma', 'Dimensional Severance', 'Nihai İaijutsu. Boyutları koparan tek bir kılıç çekişi. 15m''lik bir hattaki tüm düşmanlara 10d10 güç/kesici hasar verir. Gerçekliğin bunu kavraması 1 tur sürer.', 'Ultimate Iaijutsu. A single draw that severs dimensions. Deals 10d10 force/slashing damage to all enemies in a 15m line. Reality takes 1 turn to catch up.', 'Iaijutsu', 90, 1500, 5, '{"sm_iai_swallow", "sm_iai_void"}', '{"x": 2987, "y": -1724}', '{"damage": "10d10", "aoe": "15m line"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9909fb43-93b5-4ce4-a631-f0eca59242f6', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_honor', 'Onur Halesi', 'Aura of Honor', 'Saf bir irade halesi yayarsınız. 5m içindeki müttefikler ve siz +2 Zırh Sınıfı ve cezbetme etkilerine karşı avantaj kazanırsınız.', 'Emanate an aura of pure resolve. You and allies within 5m gain +2 AC and advantage against charm effects.', 'Bushido', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"ac_bonus": "+2", "range": "5m aura"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9734fa1f-64bd-4df3-93f7-1107a2bc3093', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_resolve', 'Demir İrade', 'Iron Resolve', 'Zihninizi odaklayarak 10 geçici Darbe Puanı kazanırsınız ve 5''in altındaki ilk hasarı yok sayarsınız.', 'Focus your mind, gaining 10 temporary Hit Points and ignoring the first instance of damage below 5.', 'Bushido', 1, 50, 1, '{}', '{"x": 289, "y": 344}', '{"temp_hp": "10", "duration": "1 min"}', '😤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f31b100-769c-47bf-8dc6-f2aa221d8d7a', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_challenge', 'Onurlu Meydan Okuma', 'Honorable Challenge', '10m içindeki bir düşmanı düelloya davet eder. Düşman, 1 tur boyunca sizden başkasına yaptığı saldırılarda dezavantajlı olur.', 'Challenge an enemy within 10m to a duel. They have disadvantage on attacks against anyone other than you for 1 turn.', 'Bushido', 5, 100, 1, '{}', '{"x": 449, "y": 536}', '{"range": "10m", "taunt": "1 turn"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d874cc5b-357e-428f-a8fe-62b099df5733', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_spirit', 'Samuray Ruhu', 'Spirit of the Samurai', 'Boyun eğmez ruhunuz sizi korkuya karşı kalıcı olarak bağışık yapar. Tüm kurtarma zarlarına +1d4 bonus kazandırır.', 'Your indomitable spirit makes you permanently immune to fear. Gain a +1d4 bonus to all saving throws.', 'Bushido', 21, 200, 2, '{"sm_bus_honor"}', '{"x": 610, "y": 727}', '{"save_bonus": "+1d4", "immune": "Fear"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ba5d2d83-f6b9-4f88-b310-4ee90a057d37', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_stance', 'Dağ Duruşu', 'Mountain Stance', 'Sağlam bir duruş alır. 3 tur boyunca hareket ettirilemez veya yere serilemezsiniz, ayrıca fiziksel hasara karşı direnç kazanırsınız.', 'Adopt a firm stance. For 3 turns, you cannot be moved or knocked prone, and gain resistance to physical damage.', 'Bushido', 21, 200, 2, '{"sm_bus_resolve"}', '{"x": 771, "y": 919}', '{"resist": "Physical", "immovable": true, "duration": "3 turns"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61dd1ab1-3cdd-4597-9a1d-5600dcd34366', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_clarity', 'Berrak Zihin', 'Mind of Clarity', 'Zihninizi tüm dikkat dağıtıcılardan arındırın. Her dinlenmede bir kez, başarısız bir kurtarma zarını +5 bonusla yeniden atın.', 'Clear your mind of all distractions. Once per rest, reroll a failed saving throw with a +5 bonus.', 'Bushido', 25, 250, 2, '{"sm_bus_challenge"}', '{"x": 932, "y": 1110}', '{"reroll": "Save", "bonus": "+5"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24fd34be-af36-4a1f-b109-0abfda0a689c', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_ancestor', 'Ataların Yankısı', 'Ancestral Echo', 'Samuray atalarınızı yardıma çağırın. Sonraki 2 tur boyunca, seçtiğiniz tüm saldırılar otomatik olarak 2X (iki kez) vurur.', 'Call upon your samurai ancestors. For the next 2 turns, all your chosen attacks hit 2X automatically.', 'Bushido', 41, 400, 3, '{"sm_bus_spirit"}', '{"x": 1092, "y": 1302}', '{"buff": "Attacks hit 2X", "duration": "2 turns"}', '📿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b539e2a0-8ca5-4e76-9f7e-378776ceec51', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_sacrifice', 'Bencil Olmayan Fedakarlık', 'Selfless Sacrifice', 'Hasar almak üzere olan 5m içindeki bir müttefikle anında yer değiştirir ve %50 hasar azaltmasıyla darbeyi kendiniz alırsınız.', 'Instantly swap places with an ally within 5m who is about to take damage, taking the blow yourself with 50% damage reduction.', 'Bushido', 41, 400, 3, '{"sm_bus_stance"}', '{"x": 1253, "y": 1493}', '{"range": "5m", "absorb_damage": "50% reduction"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1a3c8a2-e9ca-4220-abc1-1eb9668f25a8', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_kiai', 'Kiai Çığlığı', 'Kiai Shout', 'Korkutucu bir savaşçı çığlığı atar. 10m''lik konideki düşmanlar Bilgelik zarı atmalıdır, aksi takdirde Korkmuş duruma düşer ve silahlarını düşürürler.', 'Release a terrifying warrior''s shout. Enemies in a 10m cone must make a Wisdom save or become Frightened and drop their weapons.', 'Bushido', 45, 450, 3, '{"sm_bus_clarity"}', '{"x": 1414, "y": 1685}', '{"aoe": "10m cone", "status": "Frightened, Disarmed"}', '🗯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b70e8b39-cfcd-4bbe-a42c-04738c0a0ba5', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_unyielding', 'Boyun Eğmez Ruh', 'Unyielding Spirit', 'Bir saldırı sizi 0 HP''ye düşüreceğinde, bunun yerine 1 HP''de kalırsınız ve anında ücretsiz bir yakın dövüş saldırısı yaparsınız. Uzun dinlenme başına bir kez kullanılabilir.', 'When an attack would reduce you to 0 HP, you instead drop to 1 HP and immediately make a free melee attack. Usable once per long rest.', 'Bushido', 61, 700, 4, '{"sm_bus_sacrifice", "sm_bus_spirit"}', '{"x": 1574, "y": 1876}', '{"survive": "1 HP", "reaction": "Free Attack"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d56d6341-65e3-4592-bf8b-a57eaab0658f', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_aura', 'Savaş Beyi Halesi', 'Aura of the Warlord', 'Liderliğiniz ilham verir. 10m içindeki müttefikler tüm saldırılarında ekstra 1d8 hasar verir ve +3m hareket hızı kazanır.', 'Your commanding presence inspires. Allies within 10m deal an extra 1d8 damage on all their attacks and gain +3m movement speed.', 'Bushido', 65, 800, 4, '{"sm_bus_kiai", "sm_bus_honor"}', '{"x": 1735, "y": 2068}', '{"range": "10m", "damage_bonus": "1d8", "speed_bonus": "+3m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4629ee5-342b-4af1-9205-0a958c664431', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_immortal', 'Ölümsüz İrade', 'Immortal Will', 'Saf iradeniz ölümü reddeder. Haftada bir kez, eğer öldürülürseniz, anında %100 HP ile dirilirsiniz ve sonraki turunuz için 2X hasar kazanırsınız.', 'Your sheer will rejects death. Once per week, if killed, you instantly revive with 100% HP and 2X damage for your next turn.', 'Bushido', 81, 1200, 5, '{"sm_bus_unyielding"}', '{"x": 1896, "y": 2259}', '{"heal": "100%", "trigger": "On Death"}', '🌅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8db5a704-f558-4779-bbb0-b871496372a1', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_bus_avatar', 'Bushido Avatarı', 'Avatar of Bushido', 'Nihai Bushido. 1 dakika boyunca mükemmel savaşçıyı temsil edersiniz: +5 ZS, +20m hız, tüm saldırılarda avantaj ve tüm durum etkilerine bağışıklık.', 'Ultimate Bushido. For 1 minute, you embody the perfect warrior: +5 AC, +20m speed, advantage on all attacks, and immunity to all status conditions.', 'Bushido', 90, 1500, 5, '{"sm_bus_aura", "sm_bus_ancestor"}', '{"x": 2056, "y": 2451}', '{"ac_bonus": "+5", "speed": "+20m", "advantage": "All attacks", "immune": "All Statuses", "duration": "1 min"}', '👺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98a3e66a-80c9-42b8-9616-a4f912b6a804', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_slash', 'İkiz Kesik', 'Twin Slash', 'Kasıtlı olarak 2X (iki kez) vuran temel bir katana saldırısı. Her vuruş 1d10 kesici hasar verir.', 'A fundamental katana strike that deliberately hits 2X. Each hit deals 1d10 slashing damage.', 'Katana Mastery', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "2x 1d10", "range": "2m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e363ad9-a671-4e15-991d-d9333cf106c5', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_bleed', 'Yırtıcı Kenar', 'Lacerating Edge', 'Hedefin 3 tur boyunca her tur 1d4 hasar kanamasına neden olan hassas bir kesik.', 'A precise cut that causes the target to bleed for 1d4 damage per turn for 3 turns.', 'Katana Mastery', 1, 50, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "1d4 bleed/turn", "duration": "3 turns"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45297c4e-2926-4cdc-b01b-f23f18037169', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_parry', 'Kılıç Savuşturması', 'Blade Parry', 'Gelen bir yakın dövüş saldırısını saptırmak için reaksiyonunuzu kullanın, o saldırıya karşı ZS''ye +3 bonus kazanırsınız.', 'Use your reaction to deflect an incoming melee attack, gaining a +3 bonus to AC against it.', 'Katana Mastery', 5, 100, 1, '{}', '{"x": -449, "y": 536}', '{"ac_bonus": "+3 vs melee", "reaction": true}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7c434766-2d76-4bba-9c6b-ddf334c24d27', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_cleave', 'Süpürücü Yarma', 'Sweeping Cleave', 'Katananızı geniş bir kavisle savurarak 3m''lik bir koni içindeki tüm düşmanlara 2d8 kesici hasar verir.', 'Swing your katana in a wide arc, dealing 2d8 slashing damage to all enemies in a 3m cone.', 'Katana Mastery', 21, 200, 2, '{"sm_kat_slash"}', '{"x": -610, "y": 727}', '{"damage": "2d8", "aoe": "3m cone"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c64e498b-ca55-4c25-89d4-8c5c191af61e', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_pierce', 'Zırh Delici', 'Armor Piercer', 'Zayıf noktalara hedeflenen bir saplama saldırısı. 2d10 delici hasar verir ve hedefin ZS''sinden 5 puanı yok sayar.', 'A thrusting attack aimed at weak points. Deals 2d10 piercing damage and ignores 5 points of target AC.', 'Katana Mastery', 21, 200, 2, '{"sm_kat_slash"}', '{"x": -771, "y": 919}', '{"damage": "2d10", "armor_pierce": "5 AC"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b443959-f387-400e-a652-1bd6a4f15655', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_flow', 'Akan Su', 'Flowing Water', 'Eğer saldırınız bir düşmanı 0 HP''ye düşürürse, hemen yakındaki başka bir hedefe yakın dövüş saldırısı yapabilirsiniz.', 'If your attack reduces an enemy to 0 HP, you may immediately make another melee attack against a different target nearby.', 'Katana Mastery', 25, 250, 2, '{"sm_kat_bleed"}', '{"x": -932, "y": 1110}', '{"mechanic": "Extra attack on kill"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dde1ff80-64fe-4661-9805-f9d201d6c14d', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_dragon', 'Ejderha Dişi', 'Dragon Fang', '3d10 kesici hasar veren ve hedefi Yere Seren güçlü bir baş üstü savurması.', 'A powerful overhead swing dealing 3d10 slashing damage and knocking the target Prone.', 'Katana Mastery', 41, 400, 3, '{"sm_kat_cleave"}', '{"x": -1092, "y": 1302}', '{"damage": "3d10", "status": "Prone"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fe91f5d8-21f0-4731-aa93-fe3e4077d265', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_blood', 'Kan Akıtma', 'Bloodletting', 'Açık yaralardan faydalanır. 2d8 hasar verir ve hedefteki mevcut tüm kanama hasarını kalıcı olarak 1d8 artırır.', 'Exploit open wounds. Deals 2d8 damage and increases all existing bleed damage on the target by 1d8 permanently.', 'Katana Mastery', 41, 400, 3, '{"sm_kat_flow"}', '{"x": -1253, "y": 1493}', '{"damage": "2d8", "buff": "Bleed +1d8"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('00eba0bb-e896-4bac-8d0d-890a206de511', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_whirlwind', 'Çelik Kasırga', 'Steel Whirlwind', 'Ölümcül bir zarafetle döner. 5m yarıçaptaki tüm düşmanlara 3d8 kesici hasar verir.', 'Spin with lethal grace. Deals 3d8 slashing damage to all enemies within a 5m radius.', 'Katana Mastery', 45, 450, 3, '{"sm_kat_parry", "sm_kat_cleave"}', '{"x": -1414, "y": 1685}', '{"damage": "3d8", "aoe": "5m radius"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e56f350-e729-49d5-b629-3b1fea0cdedf', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_sever', 'Koparan Vuruş', 'Severing Strike', 'Sakat bırakmak için hedeflenmiş bir vuruş. 4d12 kesici hasar verir ve %25 şansla ölümcül olmayan bir uzvu koparır.', 'A targeted strike to cripple. Deals 4d12 slashing damage and has a 25% chance to sever a non-fatal limb.', 'Katana Mastery', 61, 700, 4, '{"sm_kat_dragon", "sm_kat_pierce"}', '{"x": -1574, "y": 1876}', '{"damage": "4d12", "status": "Limb Sever (25%)"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4313ae5d-ff33-42f7-9a42-95d546dc3824', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_twin', 'İkiz Ejderhalar', 'Twin Dragons', 'Yıkıcı bir çift-duruş saldırısı. Hedefe 2X vurur, isabet başına 3d12 kesici hasar verir.', 'A devastating dual-stance attack. Hits the target 2X, dealing 3d12 slashing damage per hit.', 'Katana Mastery', 65, 800, 4, '{"sm_kat_dragon", "sm_kat_whirlwind"}', '{"x": -1735, "y": 2068}', '{"damage": "2x 3d12", "range": "2m"}', '🐲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61672021-ba9a-49d6-a5df-f92ebf98a300', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_execution', 'Kusursuz İnfaz', 'Flawless Execution', 'Bir cellat darbesi indirir. 10d12 hasar verir, ancak %20 HP''nin altındaki herhangi bir hedefi anında öldürür.', 'Deliver an executioner''s blow. Deals 10d12 damage, but instantly kills any target below 20% HP.', 'Katana Mastery', 81, 1200, 5, '{"sm_kat_sever", "sm_kat_blood"}', '{"x": -1896, "y": 2259}', '{"damage": "10d12", "execute": "<20% HP"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('69ebeae3-79d3-40f8-82f2-4565d2e19001', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_kat_mastery', 'Mutlak Ustalık', 'Absolute Mastery', 'Nihai Katana Ustalığı. Pasif: Tüm katana saldırılarınız 2X hasar verir ve zarlarda 18-20 attığınızda kritik vurursunuz.', 'Ultimate Katana Mastery. Passive: All your katana attacks deal 2X damage, and you critically hit on an 18-20.', 'Katana Mastery', 90, 1500, 5, '{"sm_kat_twin", "sm_kat_sever"}', '{"x": -2056, "y": 2451}', '{"passive": "Katana 2X Damage", "crit_range": "18-20"}', '🎖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('deeda4cb-7507-4828-8e0f-7e4f4f2ef502', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_focus', 'Odaklı Vuruş', 'Focused Strike', 'Duruş ve tekniği birleştiren özenle hedeflenmiş bir darbe. 2d10 hasar verir ve eğer hedefe Meydan Okunmuşsa (Challenged) garantili isabet sağlar.', 'A carefully aimed blow combining stance and technique. Deals 2d10 damage and is a guaranteed hit if the target is Challenged.', 'Cross-Branch', 25, 250, 2, '{"sm_bus_challenge", "sm_kat_slash"}', '{"x": -173, "y": -100}', '{"damage": "2d10", "mechanic": "Guaranteed hit on challenged"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d5e53d49-244f-43a8-9ee2-fac46da1083e', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_dance', 'Kılıç Dansı', 'Blade Dance', '10m''ye kadar atılır ve yol boyunca 3 düşmana kadar saldırır. Her düşmana 1d8 kesici hasar verilir.', 'Dash up to 10m, attacking up to 3 enemies along the path. Each enemy is hit for 1d8 slashing damage.', 'Cross-Branch', 25, 250, 2, '{"sm_iai_step", "sm_kat_cleave"}', '{"x": -389, "y": -225}', '{"damage": "3x 1d8", "dash": "10m"}', '🩰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c369708e-8257-40b0-8b4e-e322bd7b89a8', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_guard', 'Onurlu Koruma', 'Honorable Guard', 'Bir müttefiki korur. 2m içindeki bir müttefik saldırıya uğrarsa, saldırıyı anında savuşturur ve saldırgana 2d8 hasarla karşı saldırı yaparsınız.', 'Protect an ally. If an ally within 2m is attacked, you instantly parry and counterattack the aggressor for 2d8 damage.', 'Cross-Branch', 45, 450, 3, '{"sm_bus_honor", "sm_iai_counter"}', '{"x": -606, "y": -350}', '{"range": "2m", "mechanic": "Counterattack for ally"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3abeac6a-07ec-4795-ad60-b7514590a8f2', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_storm', 'Çelik Fırtınası', 'Storm of Steel', 'Her biri 1d8 hasar veren 5 hızlı vuruş başlatır, isabet eden her vuruş için 1d4 kanama uygular.', 'Unleash 5 rapid strikes dealing 1d8 damage each, applying 1d4 bleed for each strike that connects.', 'Cross-Branch', 45, 500, 3, '{"sm_iai_gale", "sm_kat_whirlwind"}', '{"x": -822, "y": -475}', '{"damage": "5x 1d8", "status": "Bleed 1d4 per hit"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a874f9f0-1d23-4358-bcd2-ed9ce015bdb5', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_lightning', 'Yıldırım Meydan Okuması', 'Lightning Challenge', '15m içindeki bir düşmana meydan okur ve anında onlara doğru atılarak göz açıp kapayıncaya kadar 3d8 hasar veren bir vuruş yapar.', 'Taunt an enemy within 15m and instantly dash to them, delivering a 3d8 strike in the blink of an eye.', 'Cross-Branch', 45, 500, 3, '{"sm_iai_phantom", "sm_bus_challenge"}', '{"x": -1039, "y": -600}', '{"damage": "3d8", "dash": "15m", "taunt": true}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('284b726f-79b8-4721-84aa-0408b6af52c9', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_will', 'Kılıcın İradesi', 'Will of the Blade', 'Pasif: İradeniz düşman kanını canlılığa çevirir. Düşmanlarınıza verdiğiniz tüm Kanama hasarının %50''si kadar iyileşirsiniz.', 'Passive: Your resolve turns enemy blood into vitality. You heal for 50% of all Bleed damage dealt to your enemies.', 'Cross-Branch', 65, 800, 4, '{"sm_bus_sacrifice", "sm_kat_blood"}', '{"x": -1255, "y": -725}', '{"heal": "50% of Bleed damage", "passive": true}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6196d5f6-0dc6-4dd1-b345-9e26e2f98c31', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_judgment', 'Hüküm Kesiği', 'Judgment Cut', 'Anında 5d10 hasar veren ve bir sonraki tur 3d10 hasar için patlayan boyutsal bir yırtık bırakan 10m menzilli bir kesik.', 'A 10m ranged slash dealing 5d10 damage immediately, and leaving a dimensional tear that explodes for 3d10 damage next turn.', 'Cross-Branch', 65, 850, 4, '{"sm_iai_vacuum", "sm_kat_sever"}', '{"x": -1472, "y": -850}', '{"damage": "5d10 + 3d10 delay", "range": "10m"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('123f3b9b-0534-470f-ad24-57b16c94acbd', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_shogun', 'Şogun''un Fermanı', 'Shogun''s Decree', 'Nihai otoritenizi serbest bırakın. 15m yarıçaptaki tüm düşmanlar 4d8 psişik hasar alır ve 2 tur boyunca korkarlar.', 'Release your ultimate authority. All enemies in a 15m radius take 4d8 psychic damage and are frightened for 2 turns.', 'Cross-Branch', 65, 900, 4, '{"sm_bus_aura", "sm_kat_twin", "sm_iai_thousand"}', '{"x": -1688, "y": -975}', '{"damage": "4d8", "aoe": "15m", "status": "Frightened"}', '🎌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('701c469e-89b1-420a-ab35-37442ce1948e', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_cb_mirror', 'Ayna Gücü', 'Mirror Force', 'Size yöneltilen bir sonraki büyüyü veya saldırıyı, saldırgana çifte güçle mükemmel bir şekilde geri yansıtmak için reaksiyonunuzu kullanın.', 'Use your reaction to perfectly reflect the next spell or attack directed at you back at the attacker with double power.', 'Cross-Branch', 85, 1200, 5, '{"sm_iai_time", "sm_bus_immortal"}', '{"x": -1905, "y": -1100}', '{"mechanic": "Perfect Reflect (2X damage)", "reaction": true}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d21685fe-a0cc-432a-bd33-754d582a75fb', '78b48b9c-98ea-41c6-a13f-0e30a5591e0b', 'sm_grand_samurai', 'Gerçek Samuray', 'The True Samurai', 'BÜYÜK NİHAİ. 1 dakika boyunca Kılıcın Tanrısı olursunuz. Tüm hasarınız 2 ile çarpılır, ZS''niz +5 artar ve hızınız 30m artar. Eylem başına iki kez saldırabilirsiniz.', 'GRAND ULTIMATE. For 1 minute, you become the God of the Blade. All your damage is multiplied by 2, your AC increases by +5, and your speed increases by 30m. You can attack twice per action.', 'Cross-Branch', 95, 1500, 5, '{"sm_iai_dimension", "sm_bus_avatar", "sm_kat_mastery"}', '{"x": -2121, "y": -1225}', '{"damage_multiplier": "2X Everything", "duration": "1 min", "ac_bonus": "+5", "speed_bonus": "+30m", "extra_attacks": true}', '⛩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('44729c6d-617c-46af-ad73-f62c045ac49f', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_healing_totem', 'Şifa Totemi', 'Healing Totem', '5m yarıçapındaki müttefikleri saniyede 1d4 HP iyileştiren bir totem çağırır.', 'Summons a totem that heals allies for 1d4 HP per second within a 5m radius.', 'Totem', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"healing": "1d4/sec", "range": "5m", "duration": "10s"}', '⚕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('da9ad7ea-3814-41b5-8db3-0832732107ec', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_searing_totem', 'Kavurucu Totem', 'Searing Totem', '10m içindeki bir hedefe saniyede 1d6 ateş hasarı veren bir ateş totemi çağırır.', 'Summons a fire totem that deals 1d6 fire damage per second to a target within 10m.', 'Totem', 5, 70, 1, '{"sh_healing_totem"}', '{"x": 389, "y": -224}', '{"damage": "1d6/sec", "range": "10m", "duration": "15s"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6b7cc125-27c2-4e16-8b4d-3f93cbc3b197', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_earthbind_totem', 'Toprakbağı Totemi', 'Earthbind Totem', '8m yarıçapındaki düşmanların hareket hızını %30 yavaşlatan bir toprak totemi çağırır.', 'Summons an earth totem that slows enemy movement speed by 30% within an 8m radius.', 'Totem', 10, 95, 1, '{"sh_healing_totem"}', '{"x": 606, "y": -349}', '{"slow": "30%", "range": "8m", "duration": "20s"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d6e4e580-dfab-4aba-9a0b-97d0b0e5526d', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_totemic_recall', 'Totemik Geri Çağrı', 'Totemic Recall', 'Tüm aktif totemlerinizi anında yok ederek mana bedellerinin %50''sini iade eder.', 'Instantly destroys all your active totems, refunding 50% of their mana cost.', 'Totem', 15, 120, 1, '{"sh_searing_totem", "sh_earthbind_totem"}', '{"x": 822, "y": -474}', '{"mana_refund": "50%", "range": "Self"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64f8d82b-5bcd-433a-80c7-fd33a7f6ef96', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_stoneclaw_totem', 'Taşpençe Totemi', 'Stoneclaw Totem', '10m yarıçapındaki tüm düşmanları kışkırtan 100 HP''li bir taş totem çağırır.', 'Summons a stone totem with 100 HP that taunts all enemies within a 10m radius.', 'Totem', 22, 180, 2, '{"sh_earthbind_totem"}', '{"x": 1039, "y": -599}', '{"hp": "100", "taunt": "True", "range": "10m", "duration": "15s"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b374ebe-3668-4693-acfe-8f4098ded155', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_windfury_totem', 'Rüzgar Hiddeti Totemi', 'Windfury Totem', '8m içindeki müttefiklerin saldırı hızını %20 artıran bir hava totemi çağırır.', 'Summons an air totem that increases the attack speed of allies within 8m by 20%.', 'Totem', 28, 220, 2, '{"sh_searing_totem"}', '{"x": 1255, "y": -724}', '{"attack_speed": "+20%", "range": "8m", "duration": "20s"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3709923f-ccb1-44a0-adb0-b52bb9be514e', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_cleansing_totem', 'Arındırma Totemi', 'Cleansing Totem', '5m içindeki müttefiklerden her 3 saniyede 1 zehir veya hastalığı kaldıran bir su totemi çağırır.', 'Summons a water totem that removes 1 poison or disease from allies within 5m every 3 seconds.', 'Totem', 35, 270, 2, '{"sh_healing_totem"}', '{"x": 1472, "y": -849}', '{"cleanse": "1 debuff/3sec", "range": "5m", "duration": "15s"}', '💧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46b4435a-1444-4661-944e-d92970840687', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_magma_totem', 'Magma Totemi', 'Magma Totem', 'Her 2 saniyede bir patlayarak 6m içindeki düşmanlara 3d6 ateş hasarı veren bir magma totemi çağırır.', 'Summons a magma totem that erupts every 2 seconds, dealing 3d6 fire damage to enemies within 6m.', 'Totem', 42, 360, 3, '{"sh_stoneclaw_totem", "sh_searing_totem"}', '{"x": 1688, "y": -974}', '{"damage": "3d6/2sec", "range": "6m", "duration": "12s"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b2bc2e6c-39a6-45e9-96c8-e2a88ec5d364', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_grounding_totem', 'Topraklama Totemi', 'Grounding Totem', 'Kırılmadan önce 10m içindeki bir müttefike yöneltilen 1 düşman büyüsünü emen bir hava totemi çağırır.', 'Summons an air totem that absorbs 1 hostile spell aimed at an ally within 10m before shattering.', 'Totem', 48, 415, 3, '{"sh_cleansing_totem"}', '{"x": 1905, "y": -1099}', '{"absorb": "1 spell", "range": "10m", "duration": "20s"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ad54c233-d0b2-4911-b95a-26bbf203e40f', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_totemic_projection', 'Totemik Yansıtma', 'Totemic Projection', 'Tüm aktif totemlerinizi 30m içinde hedeflenen bir konuma taşır.', 'Relocates all your active totems to a targeted location within 30m.', 'Totem', 55, 465, 3, '{"sh_totemic_recall"}', '{"x": 2121, "y": -1224}', '{"relocate": "True", "range": "30m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9048c996-32cd-46c8-8631-f224883a3498', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_link_totem', 'Ruh Bağı Totemi', 'Spirit Link Totem', '10m içindeki tüm müttefiklerin sağlık yüzdelerini her saniye eşitleyen ve alınan hasarı %10 azaltan bir totem çağırır.', 'Summons a totem that equalizes the health percentages of all allies within 10m every second, reducing damage taken by 10%.', 'Totem', 62, 615, 4, '{"sh_grounding_totem"}', '{"x": 2338, "y": -1349}', '{"health_equalize": "1/sec", "damage_reduction": "10%", "range": "10m", "duration": "6s"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8cae511d-2de8-47db-be33-b588c7a01f7a', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_tremor_totem', 'Sarsıntı Totemi', 'Tremor Totem', 'Yeri sarsarak 15m içindeki müttefiklerden her 2 saniyede bir korku, cazibe ve uyku etkilerini kaldıran bir toprak totemi çağırır.', 'Summons an earth totem that shakes the ground, removing fear, charm, and sleep effects from allies within 15m every 2 seconds.', 'Totem', 68, 700, 4, '{"sh_magma_totem"}', '{"x": 2554, "y": -1474}', '{"cleanse_cc": "1/2sec", "range": "15m", "duration": "10s"}', '📳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('00d46dc1-07de-4e94-a022-850014d65c2d', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_storm_totem', 'Fırtına Totemi', 'Storm Totem', 'Her 3 saniyede bir 15m içindeki düşmanlara 4d8 yıldırım hasarı vuran zincirleme yıldırım atan bir fırtına totemi çağırır.', 'Summons a storm totem that shoots chain lightning for 4d8 lightning damage at enemies within 15m every 3 seconds.', 'Totem', 75, 800, 4, '{"sh_windfury_totem"}', '{"x": 2771, "y": -1599}', '{"damage": "4d8/3sec", "range": "15m", "duration": "15s"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c8cda1b0-9aa7-47da-856e-44bde4bab39b', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_totem_of_the_ancients', 'Kadimlerin Totemi', 'Totem of the Ancients', 'Devasa bir totem çağırır. 20m yarıçapında tüm istatistiklere +%50 verir, saniyede 5d8 HP iyileştirir ve düşmanlara saniyede 10d10 doğa hasarı verir.', 'Summons a colossal totem. Grants +50% to all stats, heals 5d8 HP/sec, and deals 10d10 nature damage/sec to enemies in a 20m radius.', 'Totem', 90, 1200, 5, '{"sh_spirit_link_totem", "sh_tremor_totem", "sh_storm_totem"}', '{"x": 2987, "y": -1724}', '{"stat_boost": "+50%", "healing": "5d8/sec", "damage": "10d10/sec", "range": "20m", "duration": "30s"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9d67ff7-3e63-4664-b20c-d049869085d3', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_vision', 'Ruhsal Görüş', 'Spirit Vision', 'Görünmez varlıkları görmenizi ve 30m içindeki canavarların ruh türlerini tanımlamanızı pasif olarak sağlar.', 'Passively allows you to see invisible entities and identify the soul types of monsters within 30m.', 'Spirit', 2, 55, 1, '{}', '{"x": 128, "y": 153}', '{"true_sight": "True", "range": "30m"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1624d6f6-0a3c-487e-bfaa-5e8809572f37', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_soul_harvest', 'Ruh Hasadı', 'Soul Harvest', '5m içinde öldürülen bir canavarın ruhunu çıkarır. Aynı anda en fazla 3 ruh depolayabilirsiniz.', 'Extracts the soul of a monster killed within 5m. You can store up to 3 souls at a time.', 'Spirit', 8, 85, 1, '{"sh_spirit_vision"}', '{"x": 289, "y": 344}', '{"soul_capacity": "3", "range": "5m"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8a017e80-8de2-4ccb-89ed-afd2c1e4a286', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_bestial_trait_minor', 'Küçük Hayvani Özellik', 'Minor Bestial Trait', 'Depolanan bir ruhu kalıcı olarak tüketerek canavar türüyle ilgili bir istatistiğe +1 bonus verir. Maksimum 5 küçük özellik.', 'Permanently consumes a stored soul to grant a +1 bonus to a stat related to the monster type. Max 5 minor traits.', 'Spirit', 12, 105, 1, '{"sh_soul_harvest"}', '{"x": 449, "y": 536}', '{"stat_bonus": "+1", "max_stacks": "5", "duration": "Permanent"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aef05a7a-27e6-4fc6-8e27-5126fba8bb8d', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_bolt', 'Ruh Mermisi', 'Spirit Bolt', 'Yoğunlaştırılmış ruh enerjisinden oluşan bir mermi ateşleyerek 20m''ye kadar uzaklıktaki bir hedefe 2d8 güç hasarı verir.', 'Fires a bolt of concentrated soul energy, dealing 2d8 force damage to a target up to 20m away.', 'Spirit', 18, 140, 1, '{"sh_spirit_vision"}', '{"x": 610, "y": 727}', '{"damage": "2d8", "range": "20m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2becf1bb-b131-4a89-9d47-b7559837fbf1', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_consume_essence', 'Öz Tüketimi', 'Consume Essence', 'Depolanan bir ruhu tüketerek anında 4d8 HP iyileştirir ve maksimum mananızın %20''sini yeniler.', 'Consumes a stored soul to instantly heal 4d8 HP and restore 20% of your maximum mana.', 'Spirit', 24, 195, 2, '{"sh_soul_harvest"}', '{"x": 771, "y": 919}', '{"healing": "4d8", "mana_restore": "20%", "range": "Self"}', '🍷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('86c983b5-e305-4934-84cb-2efc5cd3a8e8', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_wolves', 'Ruh Kurtları', 'Spirit Wolves', '30 saniyeliğine 2 ruhani kurt çağırır. Vuruş başına 2d6 fiziksel hasar verir ve verilen hasarın %50''si kadar sizi iyileştirir.', 'Summons 2 ethereal wolves for 30 seconds. They deal 2d6 physical damage per hit and heal you for 50% of the damage dealt.', 'Spirit', 30, 235, 2, '{"sh_spirit_bolt"}', '{"x": 932, "y": 1110}', '{"summons": "2", "damage": "2d6/hit", "lifesteal": "50%", "duration": "30s"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('91e9879d-4eb5-4686-bea8-d78ff33d4645', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_bestial_trait_moderate', 'Orta Hayvani Özellik', 'Moderate Bestial Trait', 'Orta boy bir canavar ruhunu kalıcı olarak tüketerek belirli bir elemente karşı +%10 direnç kazandırır. Maksimum 3 orta özellik.', 'Permanently consumes a medium monster soul to gain +10% resistance to a specific element. Max 3 moderate traits.', 'Spirit', 38, 285, 2, '{"sh_bestial_trait_minor"}', '{"x": 1092, "y": 1302}', '{"resistance": "+10%", "max_stacks": "3", "duration": "Permanent"}', '🐅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('161fcd2f-94c9-4a36-971b-51e9cb3a107d', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_hex', 'Uğursuzluk', 'Hex', 'Hedeflenen bir düşmanı 10 saniyeliğine zararsız bir kurbağaya dönüştürür. Menzil 15m. Herhangi bir hasar etkiyi bozar.', 'Transforms a targeted enemy into a harmless frog for 10 seconds. Range 15m. Any damage breaks the effect.', 'Spirit', 44, 380, 3, '{"sh_spirit_wolves"}', '{"x": 1253, "y": 1493}', '{"polymorph": "True", "range": "15m", "duration": "10s"}', '🐸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de8ecf27-e461-4ead-8574-44bf2d0d8ed7', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_walk', 'Ruh Yürüyüşü', 'Spirit Walk', 'Sizi 8 saniyeliğine ruhani aleme geçirerek %50 hareket hızı ve fiziksel nesnelerin içinden geçme yeteneği verir.', 'Shifts you into the spirit realm for 8 seconds, granting 50% movement speed and the ability to pass through physical objects.', 'Spirit', 50, 430, 3, '{"sh_consume_essence"}', '{"x": 1414, "y": 1685}', '{"movement_speed": "+50%", "phase": "True", "duration": "8s"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('167a404b-3358-4bb3-aaca-e9a69ad953b3', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_bestial_adaptation', 'Hayvani Adaptasyon', 'Bestial Adaptation', 'Büyük bir canavar ruhunu kalıcı olarak tüketerek pasif bir yetenek (örn. suda nefes alma, karanlık görüş) kazandırır. Maksimum 2 adaptasyon.', 'Permanently consumes a large monster soul to gain a passive ability (e.g., water breathing, darkvision). Max 2 adaptations.', 'Spirit', 58, 485, 3, '{"sh_bestial_trait_moderate"}', '{"x": 1574, "y": 1876}', '{"passive_trait": "1", "max_stacks": "2", "duration": "Permanent"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fdd0b8cc-5804-4e3a-a2de-005638feb116', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_mend', 'Ruh Onarımı', 'Spirit Mend', 'Ruhsal enerjiyi yönlendirerek bir müttefiki 8d8 HP iyileştirir ve tüm lanetleri kaldırır. Menzil 15m.', 'Channels spiritual energy to heal an ally for 8d8 HP and removes all curses. Range 15m.', 'Spirit', 64, 640, 4, '{"sh_spirit_walk"}', '{"x": 1735, "y": 2068}', '{"healing": "8d8", "cleanse": "All Curses", "range": "15m"}', '🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d5fcd52d-b59b-4b69-b541-801597029100', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_soul_sever', 'Ruh Koparma', 'Soul Sever', 'Hedefe vurarak ruhunu bedeninden ayırır. 3 saniye sersemletir ve 6d10 nekrotik hasar verir.', 'Strikes the target, separating their soul from their body. Stuns for 3 seconds and deals 6d10 necrotic damage.', 'Spirit', 70, 725, 4, '{"sh_hex"}', '{"x": 1896, "y": 2259}', '{"damage": "6d10", "stun": "3s", "range": "5m"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('93bc282c-a4c7-4c9b-b787-70eabe8be0a7', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_apex_predator_trait', 'Zirve Avcı Özelliği', 'Apex Predator Trait', 'Bir patron canavarın ruhunu kalıcı olarak tüketerek büyük bir özellik (örn. uçma, hızlı yenilenme) kazandırır. Maksimum 1 zirve özellik.', 'Permanently consumes a boss monster''s soul to gain a major trait (e.g., flight, fast regeneration). Max 1 apex trait.', 'Spirit', 78, 850, 4, '{"sh_bestial_adaptation"}', '{"x": 2056, "y": 2451}', '{"major_trait": "1", "max_stacks": "1", "duration": "Permanent"}', '🦖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64ae64c8-d859-4728-9b15-916d64ecafc9', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_chimaera_soul', 'Kimera Ruhu', 'Chimaera Soul', 'Tüm kalıcı canavar özelliklerinizi 1 dakikalığına %300 etkinlikle aktifleştirerek sizi korkunç bir ruh kimerasına dönüştürür.', 'Activates all your permanent monster traits at 300% effectiveness for 1 minute, turning you into a terrifying spirit chimaera.', 'Spirit', 92, 1250, 5, '{"sh_spirit_mend", "sh_soul_sever", "sh_apex_predator_trait"}', '{"x": 2217, "y": 2642}', '{"trait_multiplier": "300%", "duration": "1m"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('525f9f54-ded4-4a95-90a8-3ce1001db820', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_ancestral_strike', 'Atasal Vuruş', 'Ancestral Strike', 'Silahınızı atasal güçle aşılar. Sonraki yakın dövüş saldırınız fazladan 1d8 güç hasarı verir.', 'Infuses your weapon with ancestral power. Your next melee attack deals an additional 1d8 force damage.', 'Ancestral', 3, 60, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d8", "range": "Melee"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('762999c6-61a6-4f05-9493-ff83a4f42b11', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_lightning_shield', 'Yıldırım Kalkanı', 'Lightning Shield', 'Sizi 3 yıldırım yüküyle çevreler. Saldıranlar vuruş başına 1d6 yıldırım hasarı alır ve bir yük tüketilir.', 'Surrounds you with 3 charges of lightning. Attackers take 1d6 lightning damage per hit, consuming a charge.', 'Ancestral', 7, 80, 1, '{"sh_ancestral_strike"}', '{"x": -289, "y": 344}', '{"damage": "1d6/hit", "charges": "3", "range": "Self"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3eb25cd4-d694-4773-953a-d1cd676d8adb', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_ancestral_guidance', 'Atasal Rehberlik', 'Ancestral Guidance', '15 saniye boyunca, verdiğiniz hasarın %20''si 10m içindeki en fazla 3 müttefik için iyileştirmeye dönüştürülür.', 'For 15 seconds, 20% of your damage dealt is converted into healing for up to 3 nearby allies within 10m.', 'Ancestral', 14, 115, 1, '{"sh_ancestral_strike"}', '{"x": -449, "y": 536}', '{"lifesteal_aura": "20%", "targets": "3", "range": "10m", "duration": "15s"}', '🧭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c81c28ca-dea3-4c84-9541-74a7ff42ed3a', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_bloodlust', 'Kan Hırsı', 'Bloodlust', '20m içindeki müttefiklere ilham vererek saldırı ve büyü yapma hızlarını 20 saniyeliğine %25 artırır.', 'Inspires allies within 20m, increasing their attack and casting speed by 25% for 20 seconds.', 'Ancestral', 20, 150, 1, '{"sh_lightning_shield"}', '{"x": -610, "y": 727}', '{"speed_boost": "+25%", "range": "20m", "duration": "20s"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30b8071f-b917-4f6a-8150-48f0ff706191', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_chain_lightning', 'Zincirleme Yıldırım', 'Chain Lightning', '3d8 yıldırım hasarı veren ve bir öncekinin 8m içindeki 3 ek hedefe sıçrayan bir yıldırım fırlatır.', 'Hurls a lightning bolt that deals 3d8 lightning damage, jumping to 3 additional targets within 8m of the previous one.', 'Ancestral', 25, 200, 2, '{"sh_lightning_shield"}', '{"x": -771, "y": 919}', '{"damage": "3d8", "jumps": "3", "jump_range": "8m", "range": "20m"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a5776476-17d8-4b2d-a185-869a3cfe6344', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_ancestral_fortitude', 'Atasal İrade', 'Ancestral Fortitude', 'Bir hedefi kutsayarak maksimum HP''sini %15 ve zırhını 1 saatliğine +2 artırır.', 'Blesses a target, increasing their maximum HP by 15% and armor by +2 for 1 hour.', 'Ancestral', 32, 250, 2, '{"sh_ancestral_guidance"}', '{"x": -932, "y": 1110}', '{"max_hp": "+15%", "armor": "+2", "range": "10m", "duration": "1h"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('112c8cd8-f1fd-4257-813d-92cb037559c9', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_weapons', 'Ruh Silahları', 'Spirit Weapons', 'Grubunuzun silahlarını efsunlar. 10 dakika boyunca fazladan 1d6 ruhsal hasar verirler ve düşman zırhının %10''unu yok sayarlar.', 'Enchants your party''s weapons. They deal an extra 1d6 spiritual damage and ignore 10% of enemy armor for 10 minutes.', 'Ancestral', 39, 295, 2, '{"sh_bloodlust"}', '{"x": -1092, "y": 1302}', '{"damage": "+1d6", "armor_pen": "10%", "range": "15m", "duration": "10m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2b2d538d-2555-408c-a404-09fe50ed4ea4', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_earth_shock', 'Toprak Şoku', 'Earth Shock', 'Hedefi anında sarsıcı bir güçle şok ederek 4d8 doğa hasarı verir ve büyü yapmayı keser. Menzil 15m.', 'Instantly shocks the target with concussive force, dealing 4d8 nature damage and interrupting spellcasting. Range 15m.', 'Ancestral', 45, 390, 3, '{"sh_chain_lightning"}', '{"x": -1253, "y": 1493}', '{"damage": "4d8", "interrupt": "True", "range": "15m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3f67f100-fdd0-47b3-aa72-896d4dc7cbf5', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_ancestral_awakening', 'Atasal Uyanış', 'Ancestral Awakening', 'Ne zaman kritik bir iyileştirme yapsanız, atasal bir ruh belirerek 15m içindeki en düşük HP''li müttefiki kritik miktarın %30''u kadar iyileştirir.', 'Whenever you critically heal, an ancestral spirit appears to heal the lowest HP ally within 15m for 30% of the critical amount.', 'Ancestral', 52, 445, 3, '{"sh_ancestral_fortitude"}', '{"x": -1414, "y": 1685}', '{"trigger": "Critical Heal", "healing": "30%", "range": "15m", "duration": "Passive"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('423676eb-de22-41fc-82be-206e888fb6b8', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_feral_spirit_call', 'Vahşi Ruh Çağrısı', 'Feral Spirit Call', 'Sizin aldığınız hasarın %50''sini kendisine yönlendiren kadim bir ayı ruhunu 15 saniyeliğine çağırır.', 'Summons an ancient bear spirit for 15 seconds that redirects 50% of the damage you take to itself.', 'Ancestral', 60, 500, 3, '{"sh_spirit_weapons"}', '{"x": -1574, "y": 1876}', '{"damage_redirect": "50%", "range": "Self", "duration": "15s"}', '🐻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e137b22f-3edf-4d9a-999c-e4dbff06e3d6', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_thunderstorm', 'Gök Gürültüsü Fırtınası', 'Thunderstorm', '10m içindeki tüm düşmanları 8m geriye savuran ve 5d8 yıldırım hasarı veren bir gök gürültüsü patlaması çağırır.', 'Summons a blast of thunder that knocks all enemies within 10m back by 8m, dealing 5d8 lightning damage.', 'Ancestral', 65, 655, 4, '{"sh_earth_shock"}', '{"x": -1735, "y": 2068}', '{"damage": "5d8", "knockback": "8m", "range": "10m"}', '⛈️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9b719e25-a1a0-43bf-9b85-60fcc7069777', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_ancestral_guardian', 'Atasal Muhafız', 'Ancestral Guardian', '30 saniyeliğine güçlü bir atasal savaşçı çağırır. 4d10 fiziksel hasar verir ve 10m içindeki düşmanları kışkırtır.', 'Summons a powerful ancestral warrior for 30 seconds. It deals 4d10 physical damage and taunts enemies within 10m.', 'Ancestral', 72, 750, 4, '{"sh_feral_spirit_call"}', '{"x": -1896, "y": 2259}', '{"damage": "4d10", "taunt": "True", "duration": "30s"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('595a53eb-23a6-4bb3-b1b1-01c55f1f6712', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_elemental_ascendance', 'Elementel Yükseliş', 'Elemental Ascendance', 'Sizi 20 saniyeliğine saf elementel enerjiden oluşan bir varlığa dönüştürür. Büyülerinizin bekleme süresi yoktur ve yarı mana harcar.', 'Transforms you into a being of pure elemental energy for 20 seconds. Your spells have no cooldown and cost half mana.', 'Ancestral', 79, 880, 4, '{"sh_ancestral_awakening", "sh_bloodlust"}', '{"x": -2056, "y": 2451}', '{"cooldown": "0s", "mana_cost": "-50%", "duration": "20s"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46381bf9-c754-449c-8e92-51036c31c171', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_wrath_of_the_ancestors', 'Ataların Gazabı', 'Wrath of the Ancestors', 'Nesillerin öfkesini çağırır. 15 saniyeliğine 30m yarıçapında saniyede 12d10 güç hasarı veren ruhsal silahlar fırtınası çağırır.', 'Calls down the fury of generations. Summons a storm of spiritual weapons in a 30m radius for 15 seconds, dealing 12d10 force damage per second.', 'Ancestral', 95, 1350, 5, '{"sh_thunderstorm", "sh_ancestral_guardian", "sh_elemental_ascendance"}', '{"x": -2217, "y": 2642}', '{"damage": "12d10/sec", "range": "30m", "duration": "15s"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ef0ae4ed-1760-44a6-924c-8f8d9b65d66b', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_totemic_spirit_link', 'Totemik Ruh Bağı', 'Totemic Spirit Link', 'Depolanan bir ruhu tüketerek yakın zamanda ölmüş bir müttefiki %20 HP ile dirilten bir totem bırakır. Menzil 5m.', 'Drops a totem that consumes a stored soul to resurrect a recently dead ally with 20% HP. Range 5m.', 'Cross-Branch', 35, 270, 2, '{"sh_cleansing_totem", "sh_consume_essence"}', '{"x": -173, "y": -100}', '{"resurrect": "20% HP", "range": "5m"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e9aa0d5-fdec-4a7c-a30c-3eca6ca235f8', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_ancestral_totem', 'Atasal Totem', 'Ancestral Totem', 'Her 2 saniyede bir 15m içindeki rastgele düşmanlara Atasal Vuruş yapan bir totem çağırır.', 'Summons a totem that casts Ancestral Strike at random enemies within 15m every 2 seconds.', 'Cross-Branch', 50, 430, 3, '{"sh_magma_totem", "sh_chain_lightning"}', '{"x": -389, "y": -225}', '{"damage": "Auto-cast Ancestral Strike", "range": "15m", "duration": "10s"}', '🛖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e48a0281-e23d-4732-99f7-0aebc5e8da20', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_soul_imbued_weapon', 'Ruhla Bütünleşmiş Silah', 'Soul-Imbued Weapon', 'Silahınızı depolanan bir canavar ruhuyla aşılar. 1 dakika boyunca saldırıların canavarın imza yeteneğini tetikleme şansı vardır.', 'Infuses your weapon with a stored monster soul. For 1 minute, attacks have a chance to trigger the monster''s signature ability.', 'Cross-Branch', 55, 465, 3, '{"sh_bestial_trait_moderate", "sh_spirit_weapons"}', '{"x": -606, "y": -350}', '{"proc": "Monster Ability", "range": "Self", "duration": "1m"}', '🪄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b0dfb710-a8a2-410a-b998-c0da539b9426', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_monster_totem', 'Canavar Totemi', 'Monster Totem', 'Depolanan bir ruhu kullanarak bir totem üretir. Totem, canavarın aurasını (örn. korku, yenilenme) 15m yarıçapında yansıtır.', 'Crafts a totem using a stored soul. The totem projects the monster''s aura (e.g., fear, regeneration) in a 15m radius.', 'Cross-Branch', 65, 655, 4, '{"sh_totemic_projection", "sh_bestial_adaptation"}', '{"x": -822, "y": -475}', '{"aura": "Monster Aura", "range": "15m", "duration": "20s"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7ee2668b-8ce2-4ddb-8e1d-19e78de02226', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_primal_ancestor_trait', 'İlkel Ata Özelliği', 'Primal Ancestor Trait', 'Kan Hırsı veya Elementel Yükseliş etkisi altındayken Hayvani Özelliklerinizin etkinliğini pasif olarak %50 artırır.', 'Passively boosts the effectiveness of your Bestial Traits by 50% while under the effect of Bloodlust or Elemental Ascendance.', 'Cross-Branch', 75, 800, 4, '{"sh_bestial_adaptation", "sh_elemental_ascendance"}', '{"x": -1039, "y": -600}', '{"trait_boost": "50%", "trigger": "Buff active", "duration": "Passive"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f5471b03-5729-4b79-b598-920b114b8751', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_totem_of_the_apex', 'Zirve Totemi', 'Totem of the Apex', 'Bir Zirve Avcı ruhunu tüketerek sizi takip eden ve Seviye 3 ile 4 büyülerini otonom olarak yapan kalıcı bir canlı totem yaratır.', 'Consumes an Apex Predator soul to create a permanent living totem that follows you, casting Tier 3 and Tier 4 spells autonomously.', 'Cross-Branch', 85, 1050, 5, '{"sh_totem_of_the_ancients", "sh_apex_predator_trait"}', '{"x": -1255, "y": -725}', '{"auto_cast": "T3/T4 Spells", "range": "20m", "duration": "Permanent"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('299259be-f45a-4515-ad5d-85106cbe1d7b', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_spirit_echoes', 'Ruh Yankıları', 'Spirit Echoes', 'Ne zaman bir Hayvani Özellik yeteneği veya Atasal büyü kullansanız, bir ruh yankısı etkiyi %50 güçle tekrarlar.', 'Whenever you use a Bestial Trait ability or Ancestral spell, a spirit echo repeats the effect at 50% power.', 'Cross-Branch', 88, 1150, 5, '{"sh_chimaera_soul", "sh_wrath_of_the_ancestors"}', '{"x": -1472, "y": -850}', '{"echo": "50% Power", "duration": "Passive"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7eb8f9cd-968a-41c1-8dac-fecd40e0b70b', '1e5c47c8-85dc-4484-946d-bcae2f244810', 'sh_manifestation_of_the_primal_gods', 'İlkel Tanrıların Tezahürü', 'Manifestation of the Primal Gods', 'Sizi nihai atasal ruh, totemleriniz ve tüm emilen canavar özellikleriyle birleştirerek 15m boyunda bir avatara dönüştürür. 3 dakika boyunca +%500 HP kazanırsınız, 30m''de 50d10 karma hasar verirsiniz, tüm auraları yayarsınız ve totemler küresel menzile sahip olur.', 'Merges you with the ultimate ancestral spirit, your totems, and all absorbed monster traits into a 15m tall avatar. For 3 mins, you gain +500% HP, deal 50d10 mixed damage in 30m, emit all monster auras, and totems have global range.', 'Cross-Branch', 100, 1500, 5, '{"sh_totem_of_the_ancients", "sh_chimaera_soul", "sh_wrath_of_the_ancestors", "sh_totem_of_the_apex"}', '{"x": -1688, "y": -975}', '{"hp": "+500%", "damage": "50d10", "range": "Global", "duration": "3m"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4863ecc-40bd-4ece-9849-24661c1bb7f0', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_take_aim', 'Nişan Al', 'Take Aim', 'Sonraki saldırıda avantaj kazanmak ve menzili 20m artırmak için odaklanır.', 'Focuses to gain advantage on the next attack and increase range by 20m.', 'Precision', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"advantage": true, "range_bonus": "20m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ec6cce2e-5b72-465b-9c8e-286c0d59269a', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_eagle_eye', 'Kartal Gözü', 'Eagle Eye', 'Pasif. Temel saldırı menzilini 50m ve görüş menzilini 100m artırır.', 'Passive. Increases base attack range by 50m and vision range by 100m.', 'Precision', 5, 80, 1, '{"sn_take_aim"}', '{"x": 389, "y": -224}', '{"base_range": "+50m", "vision": "+100m"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d2ae104-a344-4abb-b226-b6ccb93fee87', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_vital_strike', 'Hayati Vuruş', 'Vital Strike', 'Zayıf bir noktayı hedef al. %+20 kritik şansı ve 2d8 delici hasar ekler.', 'Target a weak point. +20% crit chance and adds 2d8 piercing damage.', 'Precision', 10, 120, 1, '{"sn_take_aim"}', '{"x": 606, "y": -349}', '{"crit_chance": "+20%", "bonus_damage": "2d8"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('80868e1e-2b7f-4e57-b380-d2f0b8eda1ec', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_wind_reader', 'Rüzgar Okuyucu', 'Wind Reader', 'Rüzgar ve yarım siper cezalarını yok sayar. Atışlar engellerin arkasındaki hedefleri vurmak için kavis çizer.', 'Ignore penalties from wind and half-cover. Shots curve to hit targets behind obstacles.', 'Precision', 22, 200, 2, '{"sn_eagle_eye"}', '{"x": 822, "y": -474}', '{"ignore_cover": "half", "ignore_wind": true}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5bad6b0a-b19c-4064-a5f4-da8bc95941c9', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_piercing_shot', 'Delici Atış', 'Piercing Shot', 'Atış 30m''lik bir hatta hedefin içinden geçerek arkasındaki tüm düşmanlara hasar verir.', 'The shot passes through the target in a 30m line, dealing damage to all enemies behind.', 'Precision', 26, 230, 2, '{"sn_vital_strike"}', '{"x": 1039, "y": -599}', '{"aoe": "30m line", "piercing": true}', '🪡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e5e1693-8699-419d-a2b4-639feabec338', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_headshot', 'Kafadan Vuruş', 'Headshot', 'Kafayı hedefleyen hassas bir atış. 4d10 hasar verir ve kritik vuruşlarda hedefi 1 tur sersemletir.', 'A precise shot aiming for the head. Deals 4d10 damage and stuns the target for 1 turn on critical hits.', 'Precision', 32, 280, 2, '{"sn_vital_strike"}', '{"x": 1255, "y": -724}', '{"damage": "4d10", "stun_on_crit": "1 turn"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81ed36e0-00d5-47db-978b-373295dffb49', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_heart_seeker', 'Kalp Arayan', 'Heart Seeker', 'Kaçıramayan güdümlü bir mermi. 6d10 hasar verir ve şiddetli kanamaya (tur başına 2d6) neden olur.', 'A homing bullet that cannot miss. Deals 6d10 damage and causes severe bleeding (2d6 per turn).', 'Precision', 42, 380, 3, '{"sn_wind_reader", "sn_headshot"}', '{"x": 1472, "y": -849}', '{"damage": "6d10", "auto_hit": true, "bleed": "2d6/turn"}', '💘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e45610b5-3df2-4814-8f34-3dcb1ccf9c09', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_armor_bane', 'Zırh Düşmanı', 'Armor Bane', 'Tüm fiziksel zırhları yok sayan ve hedefin AC''sini 4 düşüren tungsten çekirdekli bir mermi ateşler.', 'Fires a tungsten-core round that ignores all physical armor and reduces target AC by 4.', 'Precision', 48, 420, 3, '{"sn_piercing_shot"}', '{"x": 1688, "y": -974}', '{"armor_penetration": "100%", "ac_reduction": 4}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29ccd4e5-b56b-45d1-a69d-2e84643e4058', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_ricochet_shot', 'Seken Atış', 'Ricochet Shot', 'Mermi birincil hedeften sekerek birbirinden en fazla 15m uzaktaki 3 düşmana kadar çarpar.', 'The bullet bounces from the primary target to up to 3 enemies within 15m of each other.', 'Precision', 55, 480, 3, '{"sn_piercing_shot"}', '{"x": 1905, "y": -1099}', '{"bounces": 3, "bounce_range": "15m"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff294a5a-b618-47c6-9ff5-66663164142d', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_lethal_trajectory', 'Ölümcül Yörünge', 'Lethal Trajectory', 'Kusursuz atışı hesaplamak için tam bir tur harca. Sonraki saldırı %+200 hasar verir ve hedefi 10m geriye savurur.', 'Take a full turn to calculate the perfect shot. Next attack deals +200% damage and knocks the target back 10m.', 'Precision', 62, 650, 4, '{"sn_heart_seeker"}', '{"x": 2121, "y": -1224}', '{"damage_multiplier": "3.0x", "knockback": "10m", "cast_time": "1 turn"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d9498610-39f3-4b88-a9ab-05c82951a503', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_shatter_shot', 'Parçalayan Atış', 'Shatter Shot', 'Büyülü bariyerleri ve fiziksel kalkanları yok eder, uzuvlara ağır hasar vererek hareketi kısıtlar.', 'Destroys magical barriers, physical shields, and heavily damages limbs, crippling movement.', 'Precision', 68, 720, 4, '{"sn_armor_bane"}', '{"x": 2338, "y": -1349}', '{"destroy_shields": true, "cripple_movement": true}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c1374958-e94d-434e-b9a6-e44eaf29aad8', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_horizon_piercer', 'Ufuk Delen', 'Horizon Piercer', 'Aşırı uzun menzilli bir atış (1000m''ye kadar). Devasa 10d10 hasar verir ve tüm büyüsel olmayan siperleri aşar.', 'An extreme-range shot (up to 1000m). Deals massive 10d10 damage and bypasses all non-magical cover.', 'Precision', 75, 800, 4, '{"sn_lethal_trajectory"}', '{"x": 2554, "y": -1474}', '{"range": "1000m", "damage": "10d10", "ignore_cover": "all"}', '🌅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2107c55e-044d-4083-b765-94ae9eafc072', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_death_mark', 'Ölüm İşareti', 'Death Mark', 'Bir hedefi infaz için işaretler. Keskin nişancının bu hedefe yapacağı tüm saldırılar %100 kritik vuruş şansına sahip olur.', 'Marks a target for execution. All attacks against this target by the sniper have 100% critical hit chance.', 'Precision', 82, 1100, 5, '{"sn_horizon_piercer", "sn_shatter_shot"}', '{"x": 2771, "y": -1599}', '{"mark": "execution", "crit_chance": "100%"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b839bd2-898f-485d-9dec-986a4adb2cd3', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_gods_eye', 'Tanrı''nın Gözü', 'God''s Eye', 'Nihai hassasiyet. Aynı varoluş düzlemindeki herhangi bir yerdeki hedefi vur. 20d12 gerçek hasar verir.', 'Ultimate precision. Shoot a target anywhere on the same plane of existence. Deals 20d12 true damage.', 'Precision', 95, 1400, 5, '{"sn_death_mark"}', '{"x": 2987, "y": -1724}', '{"range": "infinite", "damage": "20d12 true", "ignore_invulnerability": true}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('873da3a2-3ff8-4962-994b-2e9bf719ba43', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_entrench', 'Siper Al', 'Entrench', 'Bir çatal ayak kur. Hareket 0 olur ancak saldırı menzili 30m artar ve geri tepme sıfırlanır.', 'Set up a bipod. Movement becomes 0, but attack range increases by 30m and recoil is negated.', 'Nest', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"speed": 0, "range_bonus": "30m", "recoil": 0}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('410d7342-ae4d-47f5-9220-4f35d5cc68b1', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_tripwire', 'Bubi Tuzağı', 'Tripwire', '5m''lik bir hatta tuzak kur. Üzerinden geçen düşmanlar 2d6 patlayıcı hasar alır ve 1 tur yerine sabitlenir.', 'Place a trap in a 5m line. Enemies crossing it take 2d6 explosive damage and are rooted for 1 turn.', 'Nest', 6, 90, 1, '{"sn_entrench"}', '{"x": 289, "y": 344}', '{"damage": "2d6", "root": "1 turn", "length": "5m"}', '🪢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed6a2aa7-4a59-4d64-b3ec-b3f69d421abb', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_scout_drone', 'Keşif Dronu', 'Scout Drone', '200m içindeki alanı keşfetmek, düşmanları ve tuzakları ortaya çıkarmak için mekanik bir kuş konuşlandır.', 'Deploy a mechanical bird to scout the area within 200m, revealing enemies and traps.', 'Nest', 12, 130, 1, '{"sn_entrench"}', '{"x": 449, "y": 536}', '{"scout_radius": "200m", "reveal_stealth": true}', '🚁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f26ec60-e534-422b-9076-42718d95416a', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_smoke_canister', 'Sis Kutusu', 'Smoke Canister', '10m yarıçaplı bir sis perdesi konuşlandır. Düşmanların görüşünü engeller ancak sen içinden görebilirsin.', 'Deploy a smoke screen covering a 10m radius. Blocks line of sight for enemies, but you can see through it.', 'Nest', 24, 210, 2, '{"sn_tripwire"}', '{"x": 610, "y": 727}', '{"radius": "10m", "block_los": true, "see_through": true}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e672f1ce-f43e-471e-9524-027c95957a06', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_bouncing_betty', 'Sıçrayan Mayın', 'Bouncing Betty', 'Yakınlık mayını yerleştir. Tetiklendiğinde havaya sıçrar ve 6m yarıçapta 4d8 ateş hasarı vererek patlar.', 'Place a proximity mine. When triggered, it jumps up and explodes for 4d8 fire damage in a 6m radius.', 'Nest', 28, 250, 2, '{"sn_tripwire"}', '{"x": 771, "y": 919}', '{"damage": "4d8", "radius": "6m", "trigger": "proximity"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a159aaa0-9974-4441-ab09-96c8818d8add', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_decoy_target', 'Hedef Şaşırtmaca', 'Decoy Target', 'Kendinin gerçekçi bir maketini konuşlandır. Düşmanların senin yerine ona saldırma ihtimali çok yüksektir.', 'Deploy a lifelike dummy of yourself. Enemies have a high chance to attack it instead of you.', 'Nest', 35, 290, 2, '{"sn_scout_drone"}', '{"x": 932, "y": 1110}', '{"decoy_health": "50hp", "taunt_chance": "75%"}', '🧍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3c7e4542-89ba-4c26-b5ca-f2cf95c83e13', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_nest_fortification', 'Yuva Tahkimatı', 'Nest Fortification', 'Siper almışken, +5 AC ve tüm menzilli saldırılara karşı direnç kazan.', 'While entrenched, gain +5 AC and resistance to all ranged attacks.', 'Nest', 45, 400, 3, '{"sn_smoke_canister"}', '{"x": 1092, "y": 1302}', '{"ac_bonus": 5, "ranged_resistance": true}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8896b59f-1d39-42cb-b878-f065c4d9c08a', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_grapple_hook', 'Kanca', 'Grapple Hook', 'Kendini 30m''ye kadar uzaklıktaki bir görüş noktasına anında çekmek için kanca fırlat.', 'Shoot a grapple to instantly pull yourself to a vantage point up to 30m away.', 'Nest', 50, 440, 3, '{"sn_decoy_target"}', '{"x": 1253, "y": 1493}', '{"movement": "30m", "action_type": "bonus"}', '🪝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d41aa9a-4808-4ad3-87ff-869309acd847', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_spotter_turret', 'Gözcü Tareti', 'Spotter Turret', 'Düşmanları lazerle işaretleyerek onlara karşı sana avantaj sağlayan otomatik bir taret konuşlandır.', 'Deploy an automated turret that marks enemies with lasers, granting you advantage against them.', 'Nest', 56, 490, 3, '{"sn_bouncing_betty", "sn_scout_drone"}', '{"x": 1414, "y": 1685}', '{"mark_target": true, "advantage_on_marked": true}', '🔭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9d9ac478-595a-47f9-a711-ccf1649d390e', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_kill_zone', 'Ölüm Bölgesi', 'Kill Zone', '20m yarıçaplı bir alan belirle. Bu bölge içindeki tüm düşmanlara %+50 hasar verirsin.', 'Designate a 20m radius area. You deal +50% damage to all enemies inside this zone.', 'Nest', 65, 680, 4, '{"sn_spotter_turret"}', '{"x": 1574, "y": 1876}', '{"zone_radius": "20m", "damage_bonus": "50%"}', '❌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc267cc8-0a6b-406c-a0a2-9ab56886c6c1', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_spider_mines', 'Örümcek Mayınlar', 'Spider Mines', '15m içindeki düşmanları kovalayan ve her biri 3d8 hasarla patlayan 3 hareketli mayın konuşlandır.', 'Deploy 3 mobile mines that chase enemies within 15m and explode for 3d8 damage each.', 'Nest', 70, 750, 4, '{"sn_bouncing_betty"}', '{"x": 1735, "y": 2068}', '{"count": 3, "damage": "3d8 each", "chase_range": "15m"}', '🕷️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae8d07a6-2d2c-4f65-aa2c-8c55a59c9d93', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_overwatch', 'Gözetleme', 'Overwatch', 'Savunma duruşuna geç. Görüş alanında hareket eden ilk 3 düşmana otomatik olarak ateş et.', 'Enter a defensive stance. Automatically shoot the first 3 enemies that move within your line of sight.', 'Nest', 78, 850, 4, '{"sn_kill_zone", "sn_nest_fortification"}', '{"x": 1896, "y": 2259}', '{"auto_shots": 3, "trigger": "enemy movement"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e4949c6f-f865-48dc-abb7-4c3ecc8a056b', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_perfect_vantage', 'Kusursuz Görüş', 'Perfect Vantage', 'Yuvandayken yerinden edilemezsin. Menzil iki katına çıkar ve hasar zamanla %+100''e kadar artar.', 'You cannot be displaced while in your nest. Range is doubled, and damage increases over time up to +100%.', 'Nest', 85, 1150, 5, '{"sn_overwatch", "sn_grapple_hook"}', '{"x": 2056, "y": 2451}', '{"immune_displacement": true, "range_multiplier": 2.0, "scaling_damage": "up to 100%"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1145af60-f9cb-43ed-ab5f-ed2bb7347a59', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_fortress_of_solitude', 'Yalnızlık Kalesi', 'Fortress of Solitude', 'Bulunduğun yeri kendi kendini onaran bariyerler ve otomatik karşı ateş ile aşılmaz bir kaleye dönüştür.', 'Transform your location into an impenetrable fortress with auto-repairing barriers and automated counter-fire.', 'Nest', 95, 1400, 5, '{"sn_perfect_vantage", "sn_spider_mines"}', '{"x": 2217, "y": 2642}', '{"barrier_health": "500hp", "auto_repair": "50hp/turn", "counter_attack": "4d10"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d896156-c886-4311-b251-32b1881c4f63', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_ghillie_suit', 'Kamuflaj Kıyafeti', 'Ghillie Suit', 'Doğal ortamlara karışarak gizlilik zarlarına +10 kazan.', 'Blend into natural environments, gaining +10 to stealth checks.', 'Camouflage', 2, 60, 1, '{}', '{"x": -128, "y": 153}', '{"stealth_bonus": "+10", "environment": "natural"}', '🌿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33ffd233-8f33-4b83-9872-b6aacdff4a9b', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_silent_step', 'Sessiz Adım', 'Silent Step', 'Tamamen sessiz hareket et. Titreşim sezgisi veya duyma ile tespit edilemezsin.', 'Move completely silently. You cannot be detected by tremorsense or hearing.', 'Camouflage', 8, 100, 1, '{"sn_ghillie_suit"}', '{"x": -289, "y": 344}', '{"silent_movement": true, "immune_tremorsense": true}', '🧦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cdb7e9aa-1aba-46c3-8118-b529220e141a', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_breath_control', 'Nefes Kontrolü', 'Breath Control', 'Tamamen hareketsiz kalırken 2 tur boyunca görünmez olmak için nefesini tut.', 'Hold your breath to become invisible for 2 turns while remaining perfectly still.', 'Camouflage', 15, 140, 1, '{"sn_ghillie_suit"}', '{"x": -449, "y": 536}', '{"invisibility": "2 turns", "condition": "stationary"}', '🫁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a41438e9-003c-40e6-a5b5-8d64d3d9c1d3', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_chameleon_skin', 'Bukalemun Derisi', 'Chameleon Skin', 'Görünümünü herhangi bir yüzeyle eşleşecek şekilde sihirli bir şekilde değiştirerek neredeyse görünmez ol.', 'Magically alter your appearance to match any surface, becoming nearly invisible.', 'Camouflage', 25, 220, 2, '{"sn_silent_step"}', '{"x": -610, "y": 727}', '{"camouflage": "any surface", "stealth_advantage": true}', '🦎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a67c87fe-966f-40a4-ad6f-43fabab22f1f', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_suppressor', 'Susturucu', 'Suppressor', 'Büyülü bir susturucu kuşan. Atışın bir hedefi öldürürse gizliliğin bozulmaz.', 'Equip a magical suppressor. If your shot kills a target, your stealth is not broken.', 'Camouflage', 30, 260, 2, '{"sn_breath_control"}', '{"x": -771, "y": 919}', '{"silent_kill": true, "stealth_maintained": true}', '🔇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2eaf9138-c2df-4e32-ab18-9dc3fcd955dd', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_thermal_mask', 'Termal Maske', 'Thermal Mask', 'Vücut ısını ve büyüsel imzanı gizleyerek termal görüşe karşı bağışık ol.', 'Hide your body heat and magical signature, becoming immune to thermal vision.', 'Camouflage', 38, 300, 2, '{"sn_chameleon_skin"}', '{"x": -932, "y": 1110}', '{"immune_thermal": true, "immune_detect_magic": true}', '🥽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('960a8825-e63b-47c7-bcd9-f399401c8b41', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_vanish', 'Gözden Kaybolma', 'Vanish', 'Anında görünmez ol ve herhangi bir yöne 15m atıl. Arkanda bir toz bulutu bırakır.', 'Instantly turn invisible and dash 15m in any direction. Leaves behind a puff of dust.', 'Camouflage', 46, 410, 3, '{"sn_chameleon_skin"}', '{"x": -1092, "y": 1302}', '{"invisibility": "instant", "dash": "15m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b946d46a-4498-40b0-99aa-fa6f46014544', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_ghost_walk', 'Hayalet Yürüyüşü', 'Ghost Walk', 'Zorlu arazilerden ve ince duvarlardan (1m''ye kadar) gizliliği bozmadan geç.', 'Move through difficult terrain and thin walls (up to 1m) without breaking stealth.', 'Camouflage', 52, 450, 3, '{"sn_silent_step", "sn_thermal_mask"}', '{"x": -1253, "y": 1493}', '{"ignore_terrain": true, "wall_phasing": "1m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('38b1428f-a62a-4592-973e-1e946717218a', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_mirage', 'Serap', 'Mirage', 'Hareket ettiğinde kendinin 2 illüzyon kopyasını yaratarak düşmanları şaşırt.', 'Create 2 illusory copies of yourself when you move, confusing enemies.', 'Camouflage', 58, 500, 3, '{"sn_vanish"}', '{"x": -1414, "y": 1685}', '{"clones": 2, "confuse_chance": "50%"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d343d6d2-9205-4910-b7da-2862f01a927c', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_shadow_sniper', 'Gölge Keskin Nişancı', 'Shadow Sniper', 'Gizlilikten yapılan saldırılar fazladan 6d6 nekrotik hasar verir ve hedefi 1 tur kör eder.', 'Attacks made from stealth deal an extra 6d6 necrotic damage and blind the target for 1 turn.', 'Camouflage', 66, 700, 4, '{"sn_suppressor", "sn_vanish"}', '{"x": -1574, "y": 1876}', '{"bonus_damage": "6d6 necrotic", "blind": "1 turn"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71d57f21-91d8-472c-a812-b3ff7e689d4b', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_untraceable', 'İz Bırakmayan', 'Untraceable', 'Büyülü gözetleme, iz sürme ve tüm izleme zayıflatmalarına karşı tamamen bağışık ol.', 'Become entirely immune to magical scrying, tracking, and all forms of tracking debuffs.', 'Camouflage', 72, 780, 4, '{"sn_ghost_walk"}', '{"x": -1735, "y": 2068}', '{"immune_scrying": true, "immune_tracking": true}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('12fb1bbb-dd01-4b95-a0d2-481ffbd2e20f', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_assassins_shroud', 'Suikastçı Örtüsü', 'Assassin''s Shroud', 'Yalnızca art arda 3 el ateş ettikten sonra bozulan kalıcı görünmezlik kazan.', 'Gain permanent invisibility that only breaks after firing 3 consecutive shots.', 'Camouflage', 79, 880, 4, '{"sn_mirage", "sn_untraceable"}', '{"x": -1896, "y": 2259}', '{"permanent_invisibility": true, "break_condition": "3 shots"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('396f7145-c47f-4572-9d1f-e8d935dbb345', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_phantom_presence', 'Fantom Varlığı', 'Phantom Presence', 'Düşmanlar orada olduğunu unutur. Ateş ettiğini görseler bile hafızaları silinir.', 'Enemies simply forget you are there. Even if they see you shoot, their memory is wiped.', 'Camouflage', 86, 1200, 5, '{"sn_assassins_shroud"}', '{"x": -2056, "y": 2451}', '{"memory_wipe": true, "aggro_drop": "instant"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf5da4a3-4d78-4fb3-9b8a-20dfa4996c11', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_invisible_death', 'Görünmez Ölüm', 'Invisible Death', 'Hiçbir şekilde açığa çıkarılamazsın ve atışların isabet edene kadar tamamen sessiz ve görünmezdir.', 'You cannot be revealed by any means, and your shots are perfectly silent and invisible until they strike.', 'Camouflage', 95, 1400, 5, '{"sn_phantom_presence", "sn_shadow_sniper"}', '{"x": -2217, "y": 2642}', '{"absolute_invisibility": true, "invisible_shots": true}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('444ac80e-02c0-46ff-b0f3-ecb4fc5059bf', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_ambush_predator', 'Pusu Avcısı', 'Ambush Predator', 'Gizlilikten yaptığın ilk atış otomatik olarak hedefin en zayıf noktasını vurarak üç kat hasar verir.', 'Your first shot from stealth automatically hits the target''s weakest point, dealing triple damage.', 'Precision, Camouflage', 36, 290, 2, '{"sn_headshot", "sn_suppressor"}', '{"x": 173, "y": -99}', '{"auto_crit": true, "damage_multiplier": "3.0x", "condition": "first shot from stealth"}', '🐅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0af893dd-fd4c-48c9-ae2e-c73acde2be35', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_booby_trapped_decoy', 'Tuzaklı Şaşırtmaca', 'Booby-Trapped Decoy', 'Maketin artık görünmezdir ve bir düşman 3m yaklaştığında şiddetle patlayarak 8d8 hasar verir.', 'Your decoy is now invisible and explodes violently for 8d8 damage when an enemy gets within 3m.', 'Nest, Camouflage', 59, 490, 3, '{"sn_decoy_target", "sn_mirage"}', '{"x": 173, "y": -99}', '{"invisible_decoy": true, "explosion_damage": "8d8", "trigger_radius": "3m"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3639300f-9843-4c8d-9bd9-a213769f89ab', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_calculated_ricochet', 'Hesaplanmış Sekme', 'Calculated Ricochet', 'Siperdeki düşmanları %+30 hasarla vurmak için atışlarını kendi konuşlandırdığın ekipmanlardan sektir.', 'Bounce your shots off your deployables to hit enemies in cover with +30% damage.', 'Precision, Nest', 60, 500, 3, '{"sn_ricochet_shot", "sn_spotter_turret"}', '{"x": 173, "y": -99}', '{"bounce_off_deployables": true, "damage_bonus": "30%", "ignore_cover": true}', '🎱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8259acfc-5c75-408d-85f3-97bbe70f8d91', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_phantom_nest', 'Fantom Yuvası', 'Phantom Nest', 'Tuzaklar ve taretler dahil olmak üzere tüm yuvan düşmanlar için tamamen görünmez hale gelir.', 'Your entire nest, including traps and turrets, becomes completely invisible to enemies.', 'Nest, Camouflage', 74, 800, 4, '{"sn_nest_fortification", "sn_untraceable"}', '{"x": 389, "y": -224}', '{"invisible_nest": true, "stealth_traps": true}', '🏕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('252ba32f-ae3b-42ff-8b09-4c3f16d3a159', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_executioners_overwatch', 'Cellat Gözetlemesi', 'Executioner''s Overwatch', 'Gözetleme atışların artık kafayı hedefler ve otomatik kritik vuruşlar yapar.', 'Your overwatch shots now target the head, scoring automatic critical hits.', 'Precision, Nest', 80, 900, 4, '{"sn_overwatch", "sn_shatter_shot"}', '{"x": 389, "y": -224}', '{"overwatch_crit": true, "headshot_priority": true}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b2707a0d-3c2c-48f2-8553-790e7c09abd3', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_wraith_bullet', 'Hayalet Mermi', 'Wraith Bullet', '50m''ye kadar katı duvarların içinden geçen ve tüm zırhları yok sayan bir mermi ateşle.', 'Fire a bullet that travels through up to 50m of solid walls and ignores all armor.', 'Precision, Camouflage', 77, 850, 4, '{"sn_horizon_piercer", "sn_shadow_sniper"}', '{"x": 389, "y": -224}', '{"wall_penetration": "50m", "armor_penetration": "100%", "silent_shot": true}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('abfc79b9-e388-468b-9b85-4798618b3e77', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_apex_predator', 'Zirve Avcısı', 'Apex Predator', '5 tur boyunca tamamen görünmezsin, devasa savunmalarla siper almışsın ve her atışın kritik vuruştur.', 'For 5 turns, you are fully invisible, entrenched with massive defenses, and every shot is a critical hit.', 'Precision, Nest, Camouflage', 90, 1300, 5, '{"sn_death_mark", "sn_perfect_vantage", "sn_phantom_presence"}', '{"x": 173, "y": -99}', '{"duration": "5 turns", "absolute_stealth": true, "auto_crit": true, "entrenched": true}', '🦖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41318da5-8778-4d8c-bd9b-eb4e21bb7bb0', '43245dbf-79d6-40d3-842e-a83237981c5d', 'sn_one_shot_one_kill', 'Tek Atış Tek Ölüm', 'One Shot One Kill', 'Sonsuz menzilli, gerçekliği delen bir mermi ateşle. Hedef 100d100 hasar alır ve tarihten silinir.', 'Fire a reality-piercing bullet with infinite range. The target takes 100d100 damage and is erased from history.', 'Precision, Nest, Camouflage', 100, 1500, 5, '{"sn_gods_eye", "sn_fortress_of_solitude", "sn_invisible_death"}', '{"x": 389, "y": -224}', '{"range": "infinite", "damage": "100d100", "existence_erasure": true}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8ff5d35a-6632-4284-9249-bf40a799d7ff', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spectral_wisp', 'Spektral Işık', 'Spectral Wisp', 'Düşmanlara ruhani enerji okları atan temel bir spektral ışık çağırır. Aynı anda 3 adede kadar ışık aktif olabilir.', 'Summons a basic spectral wisp that shoots bolts of ethereal energy at enemies. Up to 3 wisps can be active.', 'Spectral', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"summon_limit": 3, "damage": "1d6", "range": "15m"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('134fe58e-d1c5-401d-bb2e-adf4a69b9024', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_phantom_claws', 'Hayalet Pençeler', 'Phantom Claws', 'Spektral minyonlarınıza jilet gibi keskin hayalet pençeler vererek yakın dövüş hasarlarını artırır.', 'Grants your spectral minions razor-sharp phantom claws, increasing their melee damage.', 'Spectral', 5, 75, 1, '{"sos_spectral_wisp"}', '{"x": 389, "y": -224}', '{"minion_damage_bonus": "+1d4", "duration": "Passive"}', '🐾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d30ff94-f0a7-4c2f-a579-bafbd5966a38', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_ethereal_shift', 'Ruhani Kayma', 'Ethereal Shift', 'Minyonlarınıza tamamen ruhani düzleme geçmelerini emreder, saldırılardan kaçınma şanslarını büyük ölçüde artırır.', 'Commands your minions to temporarily shift fully into the ethereal plane, gaining a high chance to dodge attacks.', 'Spectral', 10, 100, 1, '{"sos_spectral_wisp"}', '{"x": 606, "y": -349}', '{"dodge_chance": "40%", "duration": "5s", "cooldown": "15s"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7b5260da-718a-4dd3-85f9-cc0ea4de5483', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spectral_hound', 'Spektral Tazı', 'Spectral Hound', 'Düşmanları avlayan, fiziksel ve ruhani hasar veren hızlı bir spektral tazı çağırır.', 'Summons a swift spectral hound that hunts down enemies, dealing physical and ethereal damage.', 'Spectral', 15, 125, 1, '{"sos_spectral_wisp"}', '{"x": 822, "y": -474}', '{"summon_hp": 30, "damage": "2d6", "speed": "12m"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f37b9a76-4cc5-40ad-9c7e-4a09fd9b415f', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_ghostly_wail', 'Hayalet Feryadı', 'Ghostly Wail', 'Spektral Tazınızın korkunç bir feryat atmasını sağlayarak yakındaki düşmanları korkutur.', 'Causes your Spectral Hound to let out a terrifying wail, fearing nearby enemies.', 'Spectral', 22, 180, 2, '{"sos_spectral_hound"}', '{"x": 1039, "y": -599}', '{"radius": "8m", "fear_duration": "3s", "cooldown": "20s"}', '🔊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40aac4e0-1410-4718-8490-39c7e2b19920', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_phantom_shield', 'Hayalet Kalkanı', 'Phantom Shield', 'Minyonlarınızı gelen hasarı emen koruyucu bir hayalet bariyerle sarar.', 'Wraps your minions in a protective phantom barrier that absorbs incoming damage.', 'Spectral', 28, 220, 2, '{"sos_ethereal_shift"}', '{"x": 1255, "y": -724}', '{"shield_amount": "50", "duration": "10s"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9284b9b0-c532-47eb-9e2b-6d1787696e78', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_wraith_summon', 'Hortlak Çağrısı', 'Wraith Summon', 'Önündeki birden fazla düşmana hasar veren, tırpan darbeleriyle saldıran ölümcül bir Hortlak çağırır.', 'Summons a deadly Wraith that attacks with sweeping scythe strikes, damaging multiple enemies in front of it.', 'Spectral', 35, 270, 2, '{"sos_spectral_hound"}', '{"x": 1472, "y": -849}', '{"summon_hp": 80, "cleave_damage": "3d6", "arc": "120_degrees"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('88564d76-757d-40dc-a1e4-1c86c62b0265', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spectral_swarm', 'Spektral Sürü', 'Spectral Swarm', 'Çağırabileceğiniz maksimum Spektral Işık sayısını 8''e çıkarır ve onları kümeler halinde çağırmanıza olanak tanır.', 'Increases the maximum number of Spectral Wisps you can summon to 8, and allows summoning them in clusters.', 'Spectral', 42, 360, 3, '{"sos_ghostly_wail", "sos_wraith_summon"}', '{"x": 1688, "y": -974}', '{"new_limit": 8, "summon_count": 3}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e9f7da75-516c-42cc-9c61-ab3707c1b7b2', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_incorporeal_form', 'Cisimsiz Form', 'Incorporeal Form', 'Minyonlar artık pasif olarak katı nesnelerin ve düşmanların içinden geçebilir, çarpışmaları yok sayar ve alınan fiziksel hasarı azaltır.', 'Minions can now passively pass through solid objects and enemies, ignoring collision and reducing physical damage taken.', 'Spectral', 48, 410, 3, '{"sos_phantom_shield"}', '{"x": 1905, "y": -1099}', '{"physical_reduction": "30%", "duration": "Passive"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b829e659-8723-407c-a5a8-62f8f99896b5', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_banshee_summon', 'Ölüm Perisi Çağrısı', 'Banshee Summon', 'Sürekli bir çaresizlik aurası yayan, düşman hareket ve saldırı hızlarını yavaşlatan bir Ölüm Perisi çağırır.', 'Summons a Banshee that constantly emits an aura of despair, slowing enemy movement and attack speeds.', 'Spectral', 55, 480, 3, '{"sos_wraith_summon"}', '{"x": 2121, "y": -1224}', '{"aura_radius": "10m", "slow_amount": "25%", "summon_hp": 120}', '🧟‍♀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d57df0b-4066-4a10-9c12-883f3186e866', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_poltergeist_fury', 'Poltergeist Öfkesi', 'Poltergeist Fury', 'Minyonlarınızı çıldırtarak saldırı hızlarını büyük ölçüde artırır ve saldırılarının ilave telekinetik hasar vermesini sağlar.', 'Frenzy your minions, massively increasing their attack speed and causing their attacks to deal bonus telekinetic damage.', 'Spectral', 62, 650, 4, '{"sos_spectral_swarm"}', '{"x": 2338, "y": -1349}', '{"attack_speed": "+50%", "bonus_damage": "1d8", "duration": "12s"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e2bab665-d232-4640-8c1c-d6b460c751a8', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spectral_behemoth', 'Spektral Dev', 'Spectral Behemoth', 'Düşmanların dikkatini çeken ve yere vurarak alan hasarı veren devasa bir Spektral Dev çağırır.', 'Summons a giant Spectral Behemoth that acts as a tank, drawing enemy aggro and slamming the ground for AoE damage.', 'Spectral', 68, 720, 4, '{"sos_banshee_summon"}', '{"x": 2554, "y": -1474}', '{"summon_hp": 500, "aoe_damage": "4d8", "taunt_radius": "15m"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b8865fd-3a4e-4ebd-9d43-3bc6db39582a', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_possession', 'Ele Geçirme', 'Possession', 'Bir Hortlağa bir düşmanı ele geçirmesini emreder, kısa süreliğine kontrollerini ele alır. Hortlak sonrasında yok olur.', 'Commands a Wraith to possess an enemy, taking control of them for a short duration. The Wraith perishes afterwards.', 'Spectral', 74, 800, 4, '{"sos_banshee_summon", "sos_incorporeal_form"}', '{"x": 2771, "y": -1599}', '{"control_duration": "10s", "cost": "1_Wraith", "cooldown": "60s"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('960f3b7e-c45c-4bdc-a1a5-3dc107055d43', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_ethereal_army', 'Ruhani Ordu', 'Ethereal Army', 'Tüm çağırma sınırlarını pasif olarak artırır ve tüm minyonlara maksimum sağlığınızın bir kısmını verir.', 'Passively increases all summon limits and grants all minions a portion of your maximum health.', 'Spectral', 78, 880, 4, '{"sos_spectral_behemoth", "sos_poltergeist_fury"}', '{"x": 2987, "y": -1724}', '{"summon_limit_bonus": "+2", "hp_share": "15%"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aeaa634a-3d16-4d30-a63c-78ba7a08651f', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spectral_dragon', 'Spektral Ejderha', 'Spectral Dragon', 'Ulti: Ruhani alevler püskürten, düşmanları yok eden ve ruhlarını geçici ışıklara dönüştüren devasa bir Spektral Ejderha çağırır.', 'Ultimate: Summons a colossal Spectral Dragon that breathes ethereal flames, decimating enemies and turning their souls into temporary wisps.', 'Spectral', 90, 1300, 5, '{"sos_ethereal_army", "sos_possession"}', '{"x": 3204, "y": -1849}', '{"summon_hp": 1500, "breath_damage": "10d10", "wisp_spawn_chance": "100_on_kill"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4c6f450d-1ac0-4014-bd2e-0d0755e050cf', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_tear', 'Ruh Yırtması', 'Soul Tear', 'Bir düşmanın ruhundan bir parça kopararak büyü hasarı verir ve size 1 Ruh Yükü kazandırır.', 'Tears a fragment of an enemy''s soul, dealing magic damage and granting you 1 Soul Charge.', 'Extraction', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8", "soul_charges": 1, "range": "20m"}', '🪝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9dd7b5d-6f21-42f1-9c92-0b491163faeb', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_harvest', 'Ruh Hasadı', 'Soul Harvest', 'Çok zayıf düşmanları anında öldürmek için bir alanı tarar, ruhlarını hasat ederek çoklu Ruh Yükü kazandırır.', 'Sweeps an area to instantly kill very weak enemies, harvesting their souls to grant multiple Soul Charges.', 'Extraction', 5, 75, 1, '{"sos_soul_tear"}', '{"x": 289, "y": 344}', '{"execute_threshold": "10%_hp", "radius": "10m", "soul_per_kill": 2}', '🌾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6913085f-20e9-4aea-9ee2-fc3d9ab54aa6', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_consume_soul', 'Ruh Tüketimi', 'Consume Soul', 'Kendinizi anında iyileştirmek için 1 Ruh Yükü tüketir.', 'Consumes 1 Soul Charge to instantly heal yourself.', 'Extraction', 10, 100, 1, '{"sos_soul_tear"}', '{"x": 449, "y": 536}', '{"heal": "2d8", "cost": "1_Soul_Charge"}', '🍷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b77027b-7961-4597-90dd-c7367d782c79', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_dart', 'Ruh Oku', 'Soul Dart', 'Konsantre bir Ruh Yükünü ok olarak ateşler, yüksek delici hasar verir.', 'Fires a concentrated Soul Charge as a dart, dealing high piercing damage.', 'Extraction', 15, 125, 1, '{"sos_soul_tear"}', '{"x": 610, "y": 727}', '{"damage": "3d6", "cost": "1_Soul_Charge", "range": "30m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7abc70af-9204-424c-8f14-b9909e1a87e5', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_shatter', 'Ruh Parçalanması', 'Soul Shatter', 'Hedef konumda yıkıcı bir patlama yaratmak için 2 Ruh Yükü harcar.', 'Expends 2 Soul Charges to create a devastating explosion at a target location.', 'Extraction', 22, 180, 2, '{"sos_soul_dart", "sos_soul_harvest"}', '{"x": 771, "y": 919}', '{"damage": "4d8", "radius": "8m", "cost": "2_Soul_Charges"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3ac17a02-b97a-4f08-8a57-4bbbb3f81b79', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_essence_drain', 'Öz Sömürüsü', 'Essence Drain', 'Bir düşmanı lanetleyerek zamanla hasar verir. Her 3 saniyede bir onlardan 1 Ruh Yükü çıkarır.', 'Curses an enemy, dealing damage over time. Every 3 seconds, it extracts 1 Soul Charge from them.', 'Extraction', 28, 220, 2, '{"sos_soul_tear"}', '{"x": 932, "y": 1110}', '{"dot_damage": "1d6/s", "duration": "9s", "total_souls": 3}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ac14c2ae-644a-4504-a3e2-fd37309a1a73', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_siphon', 'Ruh Çekişi', 'Soul Siphon', 'Ruh Yüklerini doğrudan minyonlarınıza aktararak onları önemli ölçüde iyileştirir.', 'Channels Soul Charges directly into your minions, healing them significantly.', 'Extraction', 35, 270, 2, '{"sos_consume_soul"}', '{"x": 1092, "y": 1302}', '{"minion_heal": "3d8", "cost": "1_Soul_Charge_per_minion"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13d79f39-3d1b-414a-8f6f-1da33be2ed04', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_mass_extraction', 'Toplu Çıkarma', 'Mass Extraction', 'Geniş bir konideki tüm düşmanlardan ruhları koparır, hasar verir ve 5 adede kadar Ruh Yükü kazandırır.', 'Tears souls from all enemies in a wide cone, dealing damage and gaining up to 5 Soul Charges.', 'Extraction', 42, 360, 3, '{"sos_essence_drain", "sos_soul_shatter"}', '{"x": 1253, "y": 1493}', '{"damage": "3d8", "cone": "15m", "max_souls": 5}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b065b3f-22af-4d0f-9d89-933c69eaf4c9', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_forge', 'Ruh Ocağı', 'Soul Forge', 'Maksimum sağlığınızı ve büyü gücünüzü kalıcı olarak artırmak için 10 Ruh Yükünü kalıcı olarak tüketir.', 'Permanently consume 10 Soul Charges to permanently increase your max health and spell power.', 'Extraction', 48, 410, 3, '{"sos_soul_siphon"}', '{"x": 1414, "y": 1685}', '{"hp_bonus": "+20", "spell_power": "+5", "cost": "10_Soul_Charges"}', '⚒️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('aea26f45-899a-460e-8b41-4072c84cc7ef', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_tormented_soul', 'Azaplı Ruh', 'Tormented Soul', 'Bir düşmana bulaşan, büyü direncini düşüren ve sürekli hasar veren işkence görmüş bir ruh ateşler.', 'Fires a tortured soul that infects an enemy, reducing their magic resistance and dealing continuous damage.', 'Extraction', 55, 480, 3, '{"sos_essence_drain"}', '{"x": 1574, "y": 1876}', '{"resist_reduction": "-30%", "dot_damage": "2d6/s", "duration": "8s", "cost": "2_Soul_Charges"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ff48cae-dd2e-4a65-9c0e-a703b896ffe0', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_vortex', 'Ruh Girdabı', 'Soul Vortex', 'Düşmanları içine çeken, sürekli Ruh Yükü çıkaran ve devasa hasar veren karanlık bir girdap yaratır.', 'Creates a dark vortex that pulls in enemies, constantly extracting Soul Charges and dealing massive damage.', 'Extraction', 62, 650, 4, '{"sos_mass_extraction"}', '{"x": 1735, "y": 2068}', '{"radius": "12m", "damage": "4d8/s", "souls_per_sec": 2, "duration": "5s"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cdab79a6-5dc4-429b-822d-786b170f5ae1', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_barrier', 'Ruh Bariyeri', 'Soul Barrier', 'Geçilemez bir kalkan yaratmak için mevcut tüm Ruh Yüklerini harcar. Kalkan gücü harcanan yüklerle çarpılır.', 'Expends all current Soul Charges to create an impenetrable shield. Shield strength multiplies by charges spent.', 'Extraction', 68, 720, 4, '{"sos_soul_forge"}', '{"x": 1896, "y": 2259}', '{"base_shield": 100, "multiplier": "50_per_charge", "duration": "15s"}', '🪩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a88a8559-075a-43ce-9bd1-460657ab8586', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_rend', 'Ruh Yırtılışı', 'Soul Rend', 'Düşmanın ruhunu parçalayarak ölümcül hasar veren yıkıcı bir tek hedefli saldırı. Öldürmede maksimum Ruh Yükü kazandırır.', 'A devastating single-target attack that rips the enemy''s soul apart, dealing fatal damage. Grants max Soul Charges on kill.', 'Extraction', 74, 800, 4, '{"sos_tormented_soul"}', '{"x": 2056, "y": 2451}', '{"damage": "12d10", "on_kill": "Max_Souls", "cooldown": "40s"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9436181-dfa5-4235-b16f-9bb40afb8a04', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_essence_overload', 'Öz Aşırı Yüklenmesi', 'Essence Overload', 'Bir düşmanın ruhunu kendi içlerinde şiddetle genişlemeye zorlar, onları sersemletir ve alan hasarı için patlamalarına neden olur.', 'Forces an enemy''s soul to expand violently inside them, stunning them and causing them to explode for AoE damage.', 'Extraction', 78, 880, 4, '{"sos_soul_vortex"}', '{"x": 2217, "y": 2642}', '{"stun_duration": "3s", "explosion_damage": "6d8", "radius": "10m", "cost": "3_Soul_Charges"}', '🤯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e2d1539a-f0bc-4782-b4a2-b5110bb5f62e', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_reaper', 'Ruh Biçici', 'Soul Reaper', 'Ulti: Ölüm Avatarı''na dönüşün. Temel saldırılarınız anında ruh çıkarır ve pasif olarak ölüm aurası hasarı verirsiniz.', 'Ultimate: Transform into an Avatar of Death. Your basic attacks instantly extract souls, and you passively deal death aura damage.', 'Extraction', 90, 1300, 5, '{"sos_essence_overload", "sos_soul_rend", "sos_soul_barrier"}', '{"x": 2378, "y": 2834}', '{"duration": "30s", "aura_damage": "5d8/s", "attack_soul_gain": 2}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e91fca39-5fe5-4273-98e9-719a32d37713', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spirit_link', 'Ruh Bağlantısı', 'Spirit Link', 'İki düşmanı birbirine bağlar. Birinin aldığı hasarın bir kısmı diğeriyle paylaşılır.', 'Links two enemies together. A portion of the damage taken by one is shared with the other.', 'Spirit Chain', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"shared_damage": "40%", "duration": "10s", "range": "20m"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('14f21436-9d97-4629-b6ca-c28c35e7f21b', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_minion_tether', 'Minyon Bağı', 'Minion Tether', 'Kendinizi bir minyona bağlarsınız. Gelen hasarı bağlı minyona yönlendirebilirsiniz.', 'Links yourself to a minion. You can redirect incoming damage to the tethered minion.', 'Spirit Chain', 5, 75, 1, '{"sos_spirit_link"}', '{"x": -289, "y": 344}', '{"damage_redirect": "50%", "duration": "Until_broken"}', '🪢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fec3515f-b0c8-462d-98d1-0c76d1773cf1', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_chain_whip', 'Zincir Kırbaç', 'Chain Whip', 'Bir düşmana hayalet bir zincirle vurarak hasar verir ve onları hafifçe size doğru çeker.', 'Strikes an enemy with a ghostly chain, dealing damage and pulling them slightly towards you.', 'Spirit Chain', 10, 100, 1, '{"sos_spirit_link"}', '{"x": -449, "y": 536}', '{"damage": "2d6", "pull_distance": "5m"}', '〰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34cce6b6-9773-4c80-a5da-5b85d1a230f3', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spectral_bind', 'Spektral Bağlama', 'Spectral Bind', 'Bir düşmanı ruhani zincirlere sararak onları oldukları yere sabitler ve hareket yeteneklerini engeller.', 'Wraps an enemy in spiritual chains, rooting them in place and preventing movement skills.', 'Spirit Chain', 15, 125, 1, '{"sos_spirit_link"}', '{"x": -610, "y": 727}', '{"root_duration": "4s", "cooldown": "12s"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca7ed631-b860-43ff-8478-bea9e7535f16', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_ethereal_chain', 'Ruhani Zincir', 'Ethereal Chain', 'Bir düşmana çarpan, ardından yakındaki 3 düşmana kadar seken bir zincir fırlatır, hasar verir ve onları kısa süreliğine yavaşlatır.', 'Throws a chain that hits an enemy, then bounces to up to 3 nearby enemies, dealing damage and briefly slowing them.', 'Spirit Chain', 22, 180, 2, '{"sos_chain_whip"}', '{"x": -771, "y": 919}', '{"damage": "3d6", "bounces": 3, "slow": "30%"}', '➰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98548bfd-1fb3-4636-9581-572beb4d406e', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_shackles', 'Ruh Prangaları', 'Soul Shackles', 'Ruh Bağlantısı''nı geliştirir. Bağlı düşmanlar artık hareket hızı cezası alır ve 2 saniyeliğine susturulur.', 'Upgrades Spirit Link. Linked enemies now suffer a movement speed penalty and are silenced for 2 seconds.', 'Spirit Chain', 28, 220, 2, '{"sos_spectral_bind"}', '{"x": -932, "y": 1110}', '{"slow": "40%", "silence_duration": "2s"}', '🔐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('75e81b7f-d3dc-45f8-ab7f-1702ebfc12ef', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_chain_of_command', 'Komuta Zinciri', 'Chain of Command', 'Tüm aktif minyonlarınızı birbirine bağlar. Bir minyona uygulanan herhangi bir güçlendirme, %50 etkinlikle tüm bağlı minyonlara yayılır.', 'Links all your active minions together. Any buff applied to one minion spreads to all linked minions at 50% effectiveness.', 'Spirit Chain', 35, 270, 2, '{"sos_minion_tether"}', '{"x": -1092, "y": 1302}', '{"buff_share": "50%", "duration": "Passive"}', '🎖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8fd3fffd-4a2f-4177-ad60-72d1d68248c9', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_pain_resonance', 'Acı Rezonansı', 'Pain Resonance', 'Bağlı düşmanlar artık alınan hasarın %75''ini paylaşır ve kritik vuruşların bağlı hedefi sersemletme şansı vardır.', 'Linked enemies now share 75% of damage taken, and critical hits have a chance to stun the linked target.', 'Spirit Chain', 42, 360, 3, '{"sos_soul_shackles"}', '{"x": -1253, "y": 1493}', '{"shared_damage": "75%", "stun_chance": "20%"}', '📻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e720c1e8-c669-44ce-b4ab-23d55d9dbcc7', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_chain_drag', 'Zincir Çekimi', 'Chain Drag', 'Tüm bağlı düşmanları şiddetle merkezi bir noktaya çeker ve ağır fiziksel hasar için çarpışmalarına neden olur.', 'Violently yanks all linked enemies towards a central point, causing them to collide for heavy physical damage.', 'Spirit Chain', 48, 410, 3, '{"sos_ethereal_chain"}', '{"x": -1414, "y": 1685}', '{"collision_damage": "4d8", "pull_center": "Target_Location"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2bd0b04b-e6f7-4bc9-8831-1a08ee1b49c9', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_life_funnel', 'Yaşam Hunisi', 'Life Funnel', 'Bir düşman ile bir minyon arasında sömürücü bir bağ yaratır. Düşman sürekli hasar alır ve minyonu iyileştirir.', 'Creates a draining link between an enemy and a minion. The enemy takes continuous damage, healing the minion.', 'Spirit Chain', 55, 480, 3, '{"sos_chain_of_command"}', '{"x": -1574, "y": 1876}', '{"drain_damage": "2d8/s", "heal_conversion": "100%", "duration": "6s"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f799f50-1b67-4ff2-99b6-c32e41ff52c8', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_anchor', 'Ruh Çapası', 'Soul Anchor', '15m yarıçapındaki tüm düşmanlara bağlanan devasa bir ruhani çapa bırakır. Bir düşman yarıçapı terk ederse zincir kopar, devasa hasar verir ve onları sersemletir.', 'Drops a massive ethereal anchor that links to all enemies in a 15m radius. If an enemy leaves the radius, the chain snaps, dealing immense damage and stunning them.', 'Spirit Chain', 62, 650, 4, '{"sos_chain_drag"}', '{"x": -1735, "y": 2068}', '{"radius": "15m", "snap_damage": "8d10", "stun": "3s"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04ad6e12-12ea-4e1f-ac92-e989ebf5e291', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_web_of_souls', 'Ruhlar Ağı', 'Web of Souls', '10 düşmana kadar devasa bir ağda birbirine bağlayan düzinelerce zincir ateşler. Birine verilen hasar tümüne dağıtılır.', 'Fires dozens of chains that link up to 10 enemies in a massive web. Damage dealt to one is distributed among all.', 'Spirit Chain', 68, 720, 4, '{"sos_pain_resonance"}', '{"x": -1896, "y": 2259}', '{"max_targets": 10, "damage_distribution": "Evenly_Split", "duration": "12s"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('39b24261-7752-46fa-9737-50554498fb90', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_chain_explosion', 'Zincir Patlaması', 'Chain Explosion', 'Tüm aktif Ruh Bağlantılarını ve Bağları anında patlatarak her bağlı varlığın etrafında ağır alan hasarı verir.', 'Instantly detonates all active Spirit Links and Tethers, dealing heavy AoE damage around every linked entity.', 'Spirit Chain', 74, 800, 4, '{"sos_web_of_souls"}', '{"x": -2056, "y": 2451}', '{"explosion_damage": "6d8_per_entity", "radius": "6m"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('62b4ea7d-a088-41c4-a85b-027ab1d2f11b', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_unbreakable_bond', 'Kırılmaz Bağ', 'Unbreakable Bond', 'Size bağlıyken minyonların canı 1''in altına düşemez. Aldıkları ölümcül hasar bunun yerine Mana''nızı tüketir.', 'While linked to you, minions cannot drop below 1 HP. Any fatal damage they take drains your Mana instead.', 'Spirit Chain', 78, 880, 4, '{"sos_life_funnel"}', '{"x": -2217, "y": 2642}', '{"immortality": "Yes", "mana_drain": "1_Mana_per_2_Damage"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('88cb20b3-9ae8-47ae-94ff-7fcc83f6109f', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_puppeteer_chains', 'Kuklacı Zincirleri', 'Puppeteer''s Chains', 'Ulti: Bağlı 3 düşmana kadar tam kontrolü ele geçirerek onları 20 saniyeliğine beyinsiz kuklalarınıza dönüştürün. Devasa güçlendirmeler kazanırlar.', 'Ultimate: Take full control of up to 3 linked enemies, turning them into your mindless puppets for 20 seconds. They gain massive buffs.', 'Spirit Chain', 90, 1300, 5, '{"sos_soul_anchor", "sos_chain_explosion", "sos_unbreakable_bond"}', '{"x": -2378, "y": 2834}', '{"control_count": 3, "duration": "20s", "buff": "+100%_Damage_and_HP"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b363ff5f-a708-4551-a7c7-9bc707742914', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_infusion', 'Ruh İnfüzyonu', 'Soul Infusion', 'Bir Spektral Minyonu devasa bir şekilde mutasyona uğratmak ve güçlendirmek için Ruh Yüklerini harcar ve onu ruhla beslenen korkunç bir varyanta dönüştürür.', 'Spends Soul Charges to massively mutate and empower a Spectral Minion, turning it into a monstrous soul-fueled variant.', 'Cross-Branch', 50, 450, 3, '{"sos_spectral_swarm", "sos_mass_extraction"}', '{"x": -173, "y": -100}', '{"cost": "5_Soul_Charges", "hp_multiplier": "x3", "damage_multiplier": "x2"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('62515a93-f95e-4a11-9185-7bc2fc2a4519', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_spectral_chains', 'Spektral Zincirler', 'Spectral Chains', 'Hasar vermeyen ancak yakındaki tüm düşmanlara otomatik olarak Ruh Bağlantıları uygulayan özel bir Hayalet çağırır.', 'Summons a specialized Phantom that does no damage, but automatically casts Spirit Links on all nearby enemies.', 'Cross-Branch', 50, 450, 3, '{"sos_banshee_summon", "sos_chain_drag"}', '{"x": -389, "y": -225}', '{"summon_hp": 200, "link_radius": "15m", "cast_rate": "1_per_sec"}', '⛓️‍💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1ef48c59-97b8-424f-8e60-7e3532c5ef06', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_harvesting_links', 'Hasat Bağları', 'Harvesting Links', 'Bağlı bir düşmandan ruh çıkarmak, diğer tüm bağlı düşmanlardan otomatik olarak yarım ruh (yukarı yuvarlanmış) çıkarır.', 'Extracting a soul from a linked enemy automatically extracts half a soul (rounded up) from all other linked enemies.', 'Cross-Branch', 70, 750, 4, '{"sos_soul_vortex", "sos_web_of_souls"}', '{"x": -606, "y": -350}', '{"soul_multiplication": "Passive", "chain_synergy": "True"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c8f133bf-6aaf-4913-bf0b-ad8ca8b6fa40', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_soul_golem', 'Ruh Golemi', 'Soul Golem', 'Devasa bir Ruh Golemi yaratmak için Spektral enerji, Çıkarma yükleri ve Zincirleri birleştirir. Gücü, kaç düşmanın zincirlendiğine ve kaç ruh harcandığına göre artar.', 'Combines Spectral energy, Extraction charges, and Chains to create a hulking Soul Golem. Its power scales with how many enemies are chained and how many souls were spent.', 'Cross-Branch', 75, 850, 4, '{"sos_soul_infusion", "sos_spectral_chains"}', '{"x": -822, "y": -475}', '{"base_hp": 800, "scaling": "+100_HP_per_chain", "damage_scaling": "+1d8_per_soul"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea41e9d7-8c7a-4918-83a2-46f70ad97bf5', '5da817a6-abb7-45c1-9c73-4389b28a78c3', 'sos_domain_of_souls', 'Ruhlar Alanı', 'Domain of Souls', 'Büyük Ulti: Savaş alanını Yeraltı Dünyasına dönüştürür. Sonsuz hayaletler düşmanlara akın eder, her düşman birbirine zincirlenir ve Ruh Yükleriniz 15 saniyeliğine sonsuz olur.', 'Grand Ultimate: Transforms the battlefield into the Underworld. Endless phantoms swarm enemies, every enemy is chained together, and your Soul Charges become infinite for 15 seconds.', 'Cross-Branch', 100, 1500, 5, '{"sos_spectral_dragon", "sos_soul_reaper", "sos_puppeteer_chains"}', '{"x": -1039, "y": -600}', '{"duration": "15s", "infinite_souls": "True", "global_chain": "True", "phantom_dps": "10d10/s"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e1f356ee-9325-4f13-816c-d5b168a4600d', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_shadow_step', 'Gölge Adımı', 'Shadow Step', 'Gölgelerle hafifçe bütünleşerek gizlilik zarlarına +5 bonus kazanır ve 1 saat boyunca hareket hızını 3m artırırsınız.', 'Merge slightly into the shadows, gaining a +5 bonus to stealth checks and increasing movement speed by 3m for 1 hour.', 'Infiltration', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"stealth_bonus": "+5", "movement_speed": "+3m", "duration": "1 hour"}', '🥷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ecfcf90c-4ea5-42cb-a5b3-f1464e63dcf2', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_disguise_self', 'Hızlı Kılık Değiştirme', 'Quick Disguise', 'Görünümünüzü, kıyafetlerinizi ve sesinizi 4 saatliğine başka bir insansıyla eşleşecek şekilde hızla değiştirerek aldatmaya +10 kazanırsınız.', 'Quickly alter your appearance, clothes, and voice to match another humanoid for 4 hours, granting a +10 to deception.', 'Infiltration', 5, 100, 1, '{"sp_shadow_step"}', '{"x": 389, "y": -224}', '{"disguise_duration": "4 hours", "deception_bonus": "+10"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a831bc53-7957-4280-9efc-597b7b877a2a', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_lockpick_mastery', 'Sessiz Maymuncuk', 'Silent Lockpick', 'Büyülü olmayan ve temel büyülü kilitleri 1 eylemde %95 başarı oranıyla tamamen sessizce açarsınız.', 'Open non-magical and basic magical locks completely silently in 1 action with a 95% success rate.', 'Infiltration', 15, 150, 1, '{"sp_disguise_self"}', '{"x": 606, "y": -349}', '{"unlock_time": "1 action", "success_chance": "95%", "noise_level": "0m"}', '🔓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('43c7463e-bb93-48f0-b096-f171c09a14e6', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_blend_in', 'Kalabalığa Karışma', 'Blend In', 'En az 3 kişilik bir kalabalığın içinde olduğunuz sürece neredeyse görünmez olursunuz. Tespit edilme yarıçapı 1m''ye düşer.', 'Become virtually invisible as long as you are within a crowd of at least 3 people. Detection radius is reduced to 1m.', 'Infiltration', 25, 200, 2, '{"sp_lockpick_mastery"}', '{"x": 822, "y": -474}', '{"invisibility_in_crowds": "True", "detection_radius": "1m"}', '🧥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('69292f38-5198-49c8-98c5-e670d8ab4c3d', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_wall_crawler', 'Duvar Sürüngeni', 'Wall Crawler', 'Dikey yüzeylere ve tavanlara normal yürüme hızınızda tırmanarak ellerinizi savaş veya teçhizat için serbest bırakırsınız.', 'Climb vertical surfaces and ceilings at your normal walking speed, leaving your hands free for combat or gadgets.', 'Infiltration', 30, 250, 2, '{"sp_blend_in"}', '{"x": 1039, "y": -599}', '{"climb_speed": "Equal to walking speed", "hands_free": "True"}', '🕷️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed5eedcc-7694-45cd-a2d7-ba0567f02858', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_voice_mimicry', 'Ses Taklidi', 'Voice Mimicry', 'En az 1 dakika boyunca duyduğunuz herhangi bir sesi kusursuzca taklit edersiniz. Taklit süresiz devam eder.', 'Flawlessly mimic any voice you have heard for at least 1 minute. The mimicry lasts indefinitely.', 'Infiltration', 35, 300, 2, '{"sp_wall_crawler"}', '{"x": 1255, "y": -724}', '{"mimicry_accuracy": "100%", "duration": "Unlimited"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09fc6f5e-7d10-4c2d-a5ae-f17b4dccabae', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_vanish', 'Ortadan Kaybolma', 'Vanish', 'Bonus eylem olarak 10 dakika boyunca tamamen görünmez olursunuz. Gizliliği bozan saldırılar etkiyi sonlandırır.', 'Turn completely invisible for 10 minutes as a bonus action. Breaking stealth attacks end the effect.', 'Infiltration', 45, 400, 3, '{"sp_voice_mimicry"}', '{"x": 1472, "y": -849}', '{"invisibility_duration": "10 minutes", "bonus_action": "True"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fbc9f16c-7dd9-4cdf-a7bc-1975d744eddb', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_phase_door', 'Duvar Geçişi', 'Phase Door', '1.5m kalınlığa kadar katı engellerin içinden geçersiniz. Uzun dinlenme başına 3 kez kullanılabilir.', 'Walk through solid barriers up to 1.5m thick. Usable 3 times per long rest.', 'Infiltration', 50, 450, 3, '{"sp_vanish"}', '{"x": 1688, "y": -974}', '{"wall_thickness_max": "1.5m", "uses_per_rest": "3"}', '🚪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3df36ae9-d9cb-44ef-98f3-66b432de3bd2', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_perfect_imposter', 'Kusursuz Sahtekar', 'Perfect Imposter', '24 saatliğine birinin tam kimliğine bürünürsünüz. Bir şeylerin yanlış olduğunu fark etmek için gereken pasif sezgi Zorluk Derecesi 20''dir.', 'Assume someone''s exact identity perfectly for 24 hours. Passive insight DC to notice something wrong is 20.', 'Infiltration', 55, 500, 3, '{"sp_phase_door"}', '{"x": 1905, "y": -1099}', '{"imposter_duration": "24 hours", "insight_dc": "20"}', '👥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94c2cda3-2f76-4d15-b792-356534b16092', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_mass_hallucination', 'Kitlesel Halüsinasyon', 'Mass Hallucination', '20m yarıçapa psişik bir illüzyon yansıtır. 18 ZD kurtarmasını geçemeyen hedefler 1 saat boyunca sizi gördüklerini unutur.', 'Project a psychic illusion over a 20m radius. Targets failing a DC 18 save forget seeing you for 1 hour.', 'Infiltration', 65, 700, 4, '{"sp_perfect_imposter"}', '{"x": 2121, "y": -1224}', '{"radius": "20m", "memory_loss_duration": "1 hour", "save_dc": "18"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ea917b4d-d3f9-4557-afda-ad77ffc5397b', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_shadow_clone', 'Gölge Kopyası', 'Shadow Clone', 'Gölgeden yapılmış 50 Canlı somut bir kopya yaratır. 10 dakika boyunca eylemlerinizi taklit eder veya düşmanları oyalar.', 'Create a tangible clone made of shadow with 50 HP. It mimics your actions or distracts enemies for 10 minutes.', 'Infiltration', 75, 850, 4, '{"sp_mass_hallucination"}', '{"x": 2338, "y": -1349}', '{"clone_hp": "50", "duration": "10 minutes", "action_mimicry": "True"}', '👯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b0270103-cf1c-43c7-8238-d6ed8309e5b6', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_ghost_walker', 'Hayalet Yürüyüşçü', 'Ghost Walker', 'Nihai Sızma. 1 dakika boyunca tamamen dokunulmaz ve görünmez olursunuz. Fiziksel hasara bağışıklık ve +10m hız kazanırsınız.', 'Ultimate Infiltration. Become completely intangible and invisible for 1 minute. Immune to physical damage and +10m speed.', 'Infiltration', 90, 1200, 5, '{"sp_shadow_clone"}', '{"x": 2554, "y": -1474}', '{"intangibility_duration": "1 minute", "movement_speed": "+10m", "immune_to_physical": "True"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('da01af09-86ac-488d-b691-4b001d8f27b9', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_smoke_bomb', 'Sis Bombası', 'Smoke Bomb', '10m yarıçapında 1 dakika boyunca yoğun dumandan oluşan ağır gizlenmiş bir alan yaratan bir bomba fırlatır.', 'Throw a bomb that creates a heavily obscured area of thick smoke in a 10m radius for 1 minute.', 'Gadgets', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"radius": "10m", "duration": "1 minute", "vision": "Heavily Obscured"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('43cfce41-4107-400f-95fb-8963ee36a384', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_poison_dart', 'Zehirli Ok', 'Poison Dart', '20m''ye kadar sessiz bir ok atar. 1d4 delici ve 2d8 zehir hasarı vererek hedefi 1 dakika boyunca zehirli bırakır.', 'Fire a silent dart up to 20m. Deals 1d4 piercing and 2d8 poison damage, leaving the target poisoned for 1 minute.', 'Gadgets', 10, 120, 1, '{"sp_smoke_bomb"}', '{"x": 289, "y": 344}', '{"damage": "1d4 piercing + 2d8 poison", "range": "20m", "condition": "Poisoned for 1 min"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f66c709-dade-410b-b4cb-f7709085f745', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_grappling_hook', 'Kanca', 'Grappling Hook', '30m uzağa kadar bir kanca fırlatır. Sizi tur başına 15m hızla hedef konuma çeker.', 'Shoot a hook up to 30m away. Pulls you to the target location at 15m per turn.', 'Gadgets', 18, 150, 1, '{"sp_poison_dart"}', '{"x": 449, "y": 536}', '{"range": "30m", "pull_speed": "15m/turn"}', '🪝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6a633ed9-baeb-44c3-a195-3bc3d73034b8', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_flashbang', 'Flaş Bombası', 'Flashbang', '15m içinde kör edici bir flaş patlatır. Düşmanları 1d4 tur boyunca kör eder ve 1 dakika boyunca sağır bırakır.', 'Detonate a blinding flash within 15m. Blinds enemies for 1d4 turns and deafens them for 1 minute.', 'Gadgets', 22, 180, 2, '{"sp_grappling_hook"}', '{"x": 610, "y": 727}', '{"radius": "15m", "blind_duration": "1d4 turns", "deafen_duration": "1 minute"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb973391-eb34-4031-a964-d2c8312a724f', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_caltrops', 'Çivili Tuzak', 'Caltrops', '5m x 5m alana dikenler saçar. Giren düşmanlar 1d6 delici hasar alır ve hızları 3m düşer.', 'Scatter spikes over a 5m x 5m area. Enemies entering take 1d6 piercing damage and lose 3m of speed.', 'Gadgets', 28, 230, 2, '{"sp_flashbang"}', '{"x": 771, "y": 919}', '{"area": "5m x 5m", "damage": "1d6 piercing", "speed_reduction": "-3m"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4212760-fab1-4f30-baf1-898ab6037fcb', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_wire_garrote', 'Çelik Tel', 'Wire Garrote', 'Bir hedefi arkadan sessizce boğar. 4d6 kesici hasar verir, susturur ve yakalar.', 'Silently strangle a target from behind. Deals 4d6 slashing damage, silences, and grapples them.', 'Gadgets', 38, 300, 2, '{"sp_caltrops"}', '{"x": 932, "y": 1110}', '{"damage": "4d6 slashing", "condition": "Silenced and Grappled", "stealth_req": "Advantage"}', '🧵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('022d15d4-ef71-4b1a-ad7e-81fa6a34b1cd', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_explosive_decoy', 'Patlayıcı Yem', 'Explosive Decoy', 'Küçük mekanik bir yem bırakır. Bir düşman 2m yaklaştığında 10m yarıçapta patlayarak 6d6 ateş hasarı verir.', 'Deploy a small mechanical lure. Explodes in a 10m radius for 6d6 fire damage when an enemy comes within 2m.', 'Gadgets', 42, 380, 3, '{"sp_wire_garrote"}', '{"x": 1092, "y": 1302}', '{"damage": "6d6 fire", "radius": "10m", "trigger": "Proximity 2m"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('528aa0d4-82cb-4480-8558-0f2867b0d624', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_sleeping_gas', 'Uyku Gazı', 'Sleeping Gas', '15m yarıçapında sessiz bir gaz bombası salar. 16 ZD kurtarmasını geçemeyen hedefler 1 saat uykuya dalar.', 'Release a silent gas canister in a 15m radius. Targets failing a DC 16 save fall asleep for 1 hour.', 'Gadgets', 48, 450, 3, '{"sp_explosive_decoy"}', '{"x": 1253, "y": 1493}', '{"radius": "15m", "sleep_duration": "1 hour", "save_dc": "16"}', '💤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87ef9eb5-1e6a-4803-8322-d0b5c479044a', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_sabotage_kit', 'Sabotaj Kiti', 'Sabotage Kit', 'Tuzakları otomatik olarak hızla devre dışı bırakır veya temas yoluyla büyülü veya mekanik yapılara 3d10 hasar verir.', 'Quickly disable traps automatically or deal 3d10 damage to magical or mechanical constructs via touch.', 'Gadgets', 58, 500, 3, '{"sp_sleeping_gas"}', '{"x": 1414, "y": 1685}', '{"disable_construct": "3d10 damage", "disable_trap": "100% success", "range": "Touch"}', '🔧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6c091fda-5987-421c-a96b-9094248490df', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_nano_tracker', 'Nano Takipçi', 'Nano Tracker', 'Mikroskobik bir takip cihazı yerleştirir. 30 gün boyunca hedefin tam konumunu sınırsız mesafeden takip etmeyi sağlar.', 'Plant a microscopic tracker. Allows unlimited range tracking of the target''s exact position for 30 days.', 'Gadgets', 68, 750, 4, '{"sp_sabotage_kit"}', '{"x": 1574, "y": 1876}', '{"tracking_range": "Unlimited", "duration": "30 days"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6996e2e2-9c91-491b-873a-67c0dd9f89e6', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_emp_grenade', 'Büyü Bozucu Bomba', 'Magic Disruptor', '20m yarıçapındaki büyü ve elektronikleri 1 dakikalığına bozan bir cihaz fırlatır. Yapıları 1d4 tur sersemletir.', 'Throw a device that disrupts magic and electronics in a 20m radius for 1 minute. Stuns constructs for 1d4 turns.', 'Gadgets', 78, 880, 4, '{"sp_nano_tracker"}', '{"x": 1735, "y": 2068}', '{"radius": "20m", "magic_disable_duration": "1 minute", "construct_stun": "1d4 turns"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4418af74-486f-4252-a3af-ae12c231e29e', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_gadget_mastery', 'Teçhizat Cephaneliği', 'Gadget Arsenal', 'Nihai Teçhizat. 5 dakika boyunca teçhizat bekleme süreleri anında sıfırlanır ve tüm teçhizatlar ek +2d6 hasar verir.', 'Ultimate Gadget. For 5 minutes, your gadget cooldowns are reset instantly and all gadgets deal an extra +2d6 damage.', 'Gadgets', 92, 1300, 5, '{"sp_emp_grenade"}', '{"x": 1896, "y": 2259}', '{"duration": "5 minutes", "gadget_cooldowns": "0", "gadget_damage_bonus": "+2d6"}', '🧰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bad30157-f89d-4031-8805-f770d49fcea0', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_eavesdrop', 'Gizli Dinleme', 'Eavesdrop', 'İşitmenizi odaklayarak standart duvarların arkasından bile 50m''ye kadar uzaklıktaki konuşmaları net bir şekilde dinlersiniz.', 'Focus your hearing to clearly listen to conversations up to 50m away, even through standard walls.', 'Intel', 3, 70, 1, '{}', '{"x": -128, "y": 153}', '{"hearing_range": "50m", "through_walls": "True"}', '👂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a550dcc-a3a1-4425-b059-0ea056b2236b', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_lip_reading', 'Dudak Okuma', 'Lip Reading', '100m''ye kadar uzaktaki insanların dudaklarını okuyarak ne dediklerini %100 doğrulukla anlarsınız.', 'Understand what people are saying by reading their lips with 100% accuracy up to 100m away.', 'Intel', 12, 130, 1, '{"sp_eavesdrop"}', '{"x": -289, "y": 344}', '{"sight_range": "100m", "accuracy": "100%"}', '👄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cbc102c8-e531-42c7-b79e-815bfb23dd48', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_target_analysis', 'Hedef Analizi', 'Target Analysis', 'Bir hedefi 1 dakika inceleyerek zayıf noktalarını ortaya çıkarır ve onlara karşı +3 saldırı bonusu kazanırsınız.', 'Analyze a target for 1 minute to reveal their weaknesses, gaining a +3 attack bonus against them.', 'Intel', 16, 150, 1, '{"sp_lip_reading"}', '{"x": -449, "y": 536}', '{"reveal_weakness": "True", "attack_bonus": "+3 vs Target"}', '🔍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('513c66b0-5ba8-4ce7-88b7-6327bc19cca4', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_interrogation', 'Gelişmiş Sorgu', 'Enhanced Interrogation', 'Bağlı bir hedefi sorgularsınız. 15 ZD kurtarmasını geçemezlerse 10 dakika boyunca tüm sorulara dürüstçe cevap vermeye zorlanırlar.', 'Interrogate a bound target. They must pass a DC 15 save or be compelled to answer all questions truthfully for 10 minutes.', 'Intel', 24, 200, 2, '{"sp_target_analysis"}', '{"x": -610, "y": 727}', '{"truth_compulsion": "Save DC 15", "duration": "10 minutes"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8f503541-2e23-4dea-9995-7b83c108d81b', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_mind_read', 'Yüzeysel Düşünceler', 'Surface Thoughts', '16 ZD kurtarmasında başarısız olan 10m içindeki bir hedefin yüzeysel düşüncelerini 1 dakika boyunca araştırırsınız.', 'Probe the surface thoughts of a target within 10m for 1 minute on a failed DC 16 save.', 'Intel', 32, 260, 2, '{"sp_interrogation"}', '{"x": -771, "y": 919}', '{"range": "10m", "duration": "1 minute", "save_dc": "16"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('985f6935-a205-4b3b-bac1-2805120acfd8', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_photographic_memory', 'Fotografik Hafıza', 'Photographic Memory', 'Herhangi bir belge, harita veya kitabı (sayfa başına 1 eylem) sonsuza dek %100 hatırlama doğruluğuyla anında ezberlersiniz.', 'Memorize any document, map, or book instantly (1 action per page) with 100% recall accuracy forever.', 'Intel', 36, 290, 2, '{"sp_mind_read"}', '{"x": -932, "y": 1110}', '{"memorize_time": "1 action/page", "recall_accuracy": "100%"}', '📸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4f589b61-597b-4d8d-af51-457b39c9c3ea', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_clairvoyance', 'Uzaktan Görü', 'Clairvoyance', 'Bölgeyi 10 dakika boyunca görmek ve duymak için 500m uzağa kadar görünmez bir sensör yaratırsınız.', 'Create an invisible sensor up to 500m away to see and hear the area for 10 minutes.', 'Intel', 44, 400, 3, '{"sp_photographic_memory"}', '{"x": -1092, "y": 1302}', '{"range": "500m", "duration": "10 minutes", "sensor_visibility": "Invisible"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8b0448b-5bc8-4c6b-813f-84e1ed6a0c0a', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_extract_secrets', 'Sır Çıkarma', 'Extract Secrets', 'Önemli bir sırrı doğrudan zihinden söküp alırsınız. Hedef 4d8 psişik hasar alır ve 17 ZD kurtarmasını geçemezse sırrı verir.', 'Rip a major secret directly from a mind. Target takes 4d8 psychic damage and must fail a DC 17 save.', 'Intel', 52, 460, 3, '{"sp_clairvoyance"}', '{"x": -1253, "y": 1493}', '{"damage": "4d8 psychic", "secret_revealed": "1 Major Secret", "save_dc": "17"}', '🗝️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6084c7b7-17de-415e-915b-a9bde36fe212', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_network_of_spies', 'Muhbir Ağı', 'Informant Network', 'Belirli bir konuda 1 saat boyunca bilgi toplamak için herhangi bir yerleşim yerindeki 1d4 yerel muhbiri çağırırsınız.', 'Call upon 1d4 local informants in any settlement to gather intel for 1 hour on a specific topic.', 'Intel', 60, 500, 3, '{"sp_extract_secrets"}', '{"x": -1414, "y": 1685}', '{"summon_spies": "1d4", "intel_gathering_time": "1 hour"}', '🐦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('133eceec-2a63-4b9f-ada2-24ce9af78b34', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_precognition', 'Taktiksel Öngörü', 'Tactical Precognition', '8 saat boyunca geleceğe dair anlık görüler kazanırsınız. İnisiyatife +5 ve Zırh Sınıfına +2 bonus sağlar.', 'Gain flashes of the future for 8 hours. Grants a +5 bonus to initiative and a +2 bonus to Armor Class.', 'Intel', 66, 720, 4, '{"sp_network_of_spies"}', '{"x": -1574, "y": 1876}', '{"initiative_bonus": "+5", "ac_bonus": "+2", "duration": "8 hours"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d29e3331-71ee-4e94-9bcc-6c8e6f938419', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_blackmail', 'Şantaj', 'Blackmail', 'Keşfedilen bir sırrı kullanarak bir NPC''yi itaate zorlarsınız. Görev tamamlanana kadar onlara karşı +10 Karizma sağlar.', 'Leverage a discovered secret to force an NPC into compliance. Grants +10 Charisma against them until the task is complete.', 'Intel', 76, 860, 4, '{"sp_precognition"}', '{"x": -1735, "y": 2068}', '{"npc_control": "1 task", "duration": "Until completed", "charisma_bonus": "+10"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('16236ca8-2e71-486b-948e-ff6ad64e66cf', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_omniscience', 'Her Şeyi Bilen Casus', 'Omniscient Spymaster', 'Nihai İstihbarat. 1 saat boyunca 10km yarıçap içindeki tüm önemli varlıkların konumlarını, sırlarını ve mevcut planlarını anında öğrenirsiniz.', 'Ultimate Intel. Instantly know the locations, secrets, and current plans of all major entities within a 10km radius for 1 hour.', 'Intel', 95, 1400, 5, '{"sp_blackmail"}', '{"x": -1896, "y": 2259}', '{"radius": "10km", "reveal_all": "True", "duration": "1 hour"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('307a9e92-0f35-44dc-802b-4b87924c5dd8', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_concealed_blade', 'Gizli Bıçak', 'Concealed Blade', 'Gizli bir bıçak kullanarak yapılan saklı saldırı. 3d6 delici hasar verir ve sinsi saldırınıza +2d6 ekler.', 'A hidden strike using a concealed blade. Deals 3d6 piercing damage and adds +2d6 to your sneak attack.', 'Cross-Branch', 26, 220, 2, '{"sp_lockpick_mastery", "sp_grappling_hook"}', '{"x": -173, "y": -100}', '{"damage": "3d6 piercing", "sneak_attack_bonus": "+2d6", "concealment_dc": "18"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('399bab5d-6194-4c28-a7bb-bc9e28d5056f', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_scout_drone', 'Saatli Gözcü', 'Clockwork Scout', 'Bölgeleri uzaktan güvenle keşfetmek için 10 Canlı ve 15m uçuş hızlı küçük mekanik bir gözcü konuşlandırır.', 'Deploys a small mechanical drone with 10 HP and 15m fly speed to safely scout areas remotely.', 'Cross-Branch', 34, 280, 2, '{"sp_flashbang", "sp_interrogation"}', '{"x": -389, "y": -225}', '{"drone_hp": "10", "fly_speed": "15m", "stealth": "+10"}', '🚁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1dcd9af4-6d18-4798-b4a1-57e1597e27ec', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_shadow_tailing', 'Gölge Takibi', 'Shadow Tailing', 'Bir hedefi 8 saat boyunca kusursuzca takip edersiniz. Onları 30m içinde tutarken gizliliğe +10 bonus sağlar.', 'Follow a target flawlessly for up to 8 hours. Grants a +10 stealth bonus while keeping them within 30m.', 'Cross-Branch', 38, 300, 2, '{"sp_wall_crawler", "sp_mind_read"}', '{"x": -606, "y": -350}', '{"stealth_bonus": "+10", "tracking_duration": "8 hours"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0312845-18a0-442a-b6e1-95531be2c171', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_silent_assassination', 'Sessiz Suikast', 'Silent Assassination', 'Farkında olmayan bir hedefe anında ölümcül saldırı yapar. 10d6 kesin vuruş hasarı verir; 50 Canın altına düşerlerse anında öldürür.', 'Execute an instant kill attempt on an unaware target. Deals 10d6 precision damage; instantly kills if they drop below 50 HP.', 'Cross-Branch', 46, 420, 3, '{"sp_voice_mimicry", "sp_wire_garrote"}', '{"x": -822, "y": -475}', '{"damage": "10d6 precision", "instant_kill_threshold": "50 HP"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61b8b141-2314-4b75-bfe7-345c1b8c63f0', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_truth_serum', 'Doğruluk Serumu', 'Truth Serum', 'Güçlü bir serum enjekte eder. Hedef 18 ZD kurtarmasını geçemezse büyülenir ve 1 saat boyunca doğruları söylemeye zorlanır.', 'Administer a potent serum. Target must pass a DC 18 save or become charmed and forced to speak the truth for 1 hour.', 'Cross-Branch', 54, 480, 3, '{"sp_sleeping_gas", "sp_extract_secrets"}', '{"x": -1039, "y": -600}', '{"duration": "1 hour", "save_dc": "18", "condition": "Charmed"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3cdebcdc-7d0f-4d96-a514-4974113dc8f3', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_identity_theft', 'Kimlik Hırsızlığı', 'Identity Theft', 'Bir hedefin kimliğini 7 gün boyunca çalarsınız. Anılarına tam erişim kazanarak kusursuz taklit yapmanızı sağlar.', 'Steal a target''s identity for 7 days. You gain full access to their memories, allowing perfect mimicry.', 'Cross-Branch', 56, 490, 3, '{"sp_perfect_imposter", "sp_extract_secrets"}', '{"x": -1255, "y": -725}', '{"duration": "7 days", "memory_access": "Full", "mimicry_perfection": "True"}', '🥸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2dfcbabe-58cb-457c-b520-66d037114337', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_toxic_room', 'Zehirli Oda', 'Toxic Room', '30m x 30m''ye kadar kapalı bir alanı tuzağa düşürür. 10 dakika boyunca tur başına 8d6 zehir hasarı veren ölümcül bir gazla dolar.', 'Trap an enclosed space up to 30m x 30m. It fills with deadly gas dealing 8d6 poison damage per turn for 10 minutes.', 'Cross-Branch', 58, 500, 3, '{"sp_phase_door", "sp_sabotage_kit"}', '{"x": -1472, "y": -850}', '{"room_size": "Up to 30m x 30m", "damage": "8d6 poison/turn", "duration": "10 minutes"}', '☣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('68abe095-7889-4048-9a6f-fdadf998d7ef', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_mind_hack', 'Zihin Hackleme', 'Mind Hack', 'Arkana teçhizatı kullanarak hedefin 24 saate kadar olan anılarını kalıcı olarak değiştirir. Direnmek için 19 ZD kurtarması.', 'Use an arcane gadget to permanently alter up to 24 hours of a target''s memories. DC 19 save to resist.', 'Cross-Branch', 68, 750, 4, '{"sp_nano_tracker", "sp_precognition"}', '{"x": -1688, "y": -975}', '{"memory_alteration": "Up to 24 hours of memory", "save_dc": "19"}', '💻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e485710d-c577-4118-886e-ebd9d04c0dd4', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_feign_death', 'Sahte Ölüm', 'Feign Death', '24 saate kadar ölümü kusursuzca taklit eden bir duruma girersiniz. Bonus eylemle anında sonlandırılabilir.', 'Enter a state that perfectly mimics death for up to 24 hours. Can be ended instantly with a bonus action.', 'Cross-Branch', 72, 800, 4, '{"sp_mass_hallucination", "sp_emp_grenade"}', '{"x": -1905, "y": -1100}', '{"duration": "1 to 24 hours", "catalepsy": "True", "revive_action": "Bonus Action"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('470bd2e6-f558-4004-91ba-01a21a4717d2', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_inside_job', 'İçeriden Vurgun', 'Inside Job', '30m içindeki 5''e kadar düşmanı müttefiklerinin hain olduğuna ikna ederek, 1 dakika boyunca birbirlerine düşman olmalarını sağlar.', 'Convince up to 5 enemies within 30m that their allies are traitors, making them hostile to each other for 1 minute.', 'Cross-Branch', 78, 880, 4, '{"sp_shadow_clone", "sp_blackmail"}', '{"x": -2121, "y": -1225}', '{"targets": "Up to 5", "duration": "1 minute", "condition": "Hostile to allies"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5fae468b-44be-4094-94c7-71c27f8ac9aa', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_arcane_wiretap', 'Arkana Dinleme Cihazı', 'Arcane Wiretap', 'Hedefe tespit edilemeyen büyülü bir dinleyici yerleştirir. Mesafe ne olursa olsun 30 gün boyunca etrafındaki her şeyi duyabilirsiniz.', 'Plant an undetectable magic listener on a target. You can hear everything around them for 30 days regardless of distance.', 'Cross-Branch', 80, 900, 4, '{"sp_emp_grenade", "sp_blackmail"}', '{"x": -2338, "y": -1350}', '{"range": "Unlimited", "duration": "30 days", "detection_dc": "25"}', '🎙️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30d0c34f-1b9d-48b8-902b-211ac5d1a548', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_doppelganger_protocol', 'Çifte Yaşam Protokolü', 'Doppelganger Protocol', 'Canınızın %100''üne sahip otonom bir kopya yaratır. 24 saat boyunca bağımsız olarak savaşır ve istihbarat toplar.', 'Create an autonomous clone with 100% of your HP. It fights independently and gathers intelligence for 24 hours.', 'Cross-Branch', 85, 1100, 5, '{"sp_mass_hallucination", "sp_emp_grenade", "sp_precognition"}', '{"x": -2554, "y": -1475}', '{"clone_hp": "100%", "duration": "24 hours", "autonomous": "True"}', '🤖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d6eea243-b33c-4f9f-8983-b32164e8dc9b', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_deep_cover', 'Derin Gizlilik', 'Deep Cover', 'O kadar derin bir gizlilik ki, tüm kehanet büyüleri gerçek yöneliminizi veya niyetinizi okumada başarısız olur, sizi tamamen gizler.', 'Immersion so deep that all divination fails to read your true alignment or intent, hiding you completely.', 'Cross-Branch', 88, 1150, 5, '{"sp_shadow_clone", "sp_blackmail"}', '{"x": -2771, "y": -1600}', '{"duration": "Unlimited", "anti_divination": "True", "alignment_mask": "True"}', '🕵️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cafc5040-a4cc-4cd0-b394-6969b431fbcc', '065cd5a7-34a9-494d-a73b-1e29477689dd', 'sp_syndicate_master', 'Sendika Lideri', 'Master of the Syndicate', 'Görkemli Nihai Yetenek. 100m yarıçap içinde 10 dakikalığına 10 Elit Gölge çağırır. Bölgeyi kilitler, tuzakları bozar, sırları çıkarır ve düşmanlara suikast yaparlar (Toplam 20d10 hasar).', 'Grand Ultimate. Summons 10 Elite Shadows within 100m for 10 minutes. They lockdown the area, disable traps, extract secrets, and assassinate enemies (20d10 total damage).', 'Cross-Branch', 100, 1500, 5, '{"sp_ghost_walker", "sp_gadget_mastery", "sp_omniscience"}', '{"x": -2987, "y": -1725}', '{"summon_agents": "10 Elite Shadows", "area_control": "100m radius", "duration": "10 minutes", "damage": "20d10 total"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f9186b3-f602-40a7-8499-a4f180225295', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_rock_toss', 'Taş Fırlatma', 'Rock Toss', 'Düşmana sivri bir taş fırlatarak 1d10 ezici hasar verir.', 'Throws a jagged rock at an enemy, dealing 1d10 bludgeoning damage.', 'Earthbound', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d10 bludgeoning", "range": "15m"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('88d7c2f9-0bf8-4eb4-babe-571394856591', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_tremor_step', 'Sarsıntı Adımı', 'Tremor Step', 'Yere sertçe basarak küçük bölgesel bir sarsıntı yaratır. 3m içindeki düşmanlar 1d6 hasar alır ve kurtarma zarı atamazlarsa yere düşerler.', 'Stomps the ground, creating a small localized tremor. Enemies within 3m take 1d6 damage and must save or fall prone.', 'Earthbound', 5, 75, 1, '{"sth_rock_toss"}', '{"x": 389, "y": -224}', '{"damage": "1d6", "range": "3m", "status": "prone"}', '🦶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26a8dcb4-563f-42ce-83ba-31ccba8ec5ac', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_earth_wall', 'Toprak Duvar', 'Earth Wall', 'Saldırıları ve görüşü engellemek için 3m genişliğinde, 2m yüksekliğinde topraktan bir duvar çağırır. 2 tur sürer.', 'Summons a 3m wide, 2m high wall of dirt to block attacks and line of sight. Lasts 2 turns.', 'Earthbound', 10, 100, 1, '{"sth_tremor_step"}', '{"x": 606, "y": -349}', '{"duration": "2 turns", "size": "3m x 2m"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4c2ecd55-b228-4124-b75f-46e84af98d8f', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_boulder_crash', 'Kaya Çarpması', 'Boulder Crash', 'Bir hedefin üzerine devasa bir kaya düşürür. 4m yarıçapta 3d8 ezici hasar verir.', 'Drops a massive boulder on a target. Deals 3d8 bludgeoning damage in a 4m radius.', 'Earthbound', 21, 175, 2, '{"sth_earth_wall"}', '{"x": 822, "y": -474}', '{"damage": "3d8 bludgeoning", "range": "4m radius"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b0aeade1-1e79-4c5a-ab36-ba488d6c6736', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_seismic_wave', 'Sismik Dalga', 'Seismic Wave', 'Yerde 10m''lik bir koni şeklinde şok dalgası gönderir. 2d8 hasar verir ve hedefleri 2m geriye iter.', 'Sends a shockwave through the ground in a 10m cone. Deals 2d8 damage and pushes targets back 2m.', 'Earthbound', 25, 200, 2, '{"sth_boulder_crash"}', '{"x": 1039, "y": -599}', '{"damage": "2d8", "range": "10m cone", "knockback": "2m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ac775d39-9687-49d3-bfd5-8ab021d1c21d', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_quicksand_trap', 'Bataklık Tuzağı', 'Quicksand Trap', '5m yarıçapındaki bir alanı bataklığa çevirir. İçerideki düşmanlar yarı hızda hareket eder ve tur başına 1d4 hasar alır. 3 tur sürer.', 'Turns a 5m radius area into quicksand. Enemies inside move at half speed and take 1d4 damage per turn. Lasts 3 turns.', 'Earthbound', 35, 250, 2, '{"sth_seismic_wave"}', '{"x": 1255, "y": -724}', '{"damage": "1d4/turn", "range": "5m radius", "duration": "3 turns", "speed": "-50%"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7eaa77bf-63bb-4ca4-9b6e-15f7b8c89638', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_earthen_pillars', 'Toprak Sütunları', 'Earthen Pillars', 'Hedeflerin altından 3 keskin taş sütun patlatır. Her sütun 4d6 delici hasar verir ve hedefleri 2m havaya fırlatır.', 'Erupts 3 sharp stone pillars from beneath targets. Each pillar deals 4d6 piercing damage and launches targets 2m into the air.', 'Earthbound', 41, 350, 3, '{"sth_quicksand_trap"}', '{"x": 1472, "y": -849}', '{"damage": "4d6 piercing", "knockup": "2m"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9bcc4e7d-cf96-43e5-b4b7-a1047d823f33', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_meteor_strike', 'Meteor Saldırısı', 'Meteor Strike', 'Gökyüzünden alevli bir kayayı 8m''lik bir alana düşürür. 5d8 ateş ve ezici hasar verir.', 'Pulls a flaming rock from the sky, crashing it into an 8m area. Deals 5d8 fire and bludgeoning damage.', 'Earthbound', 48, 400, 3, '{"sth_earthen_pillars"}', '{"x": 1688, "y": -974}', '{"damage": "5d8 fire/bludgeoning", "range": "8m radius"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2fa7cd14-2470-4eba-b8e8-a5731cefe03a', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_tectonic_shift', 'Tektonik Kayma', 'Tectonic Shift', 'Savaş alanı arazisini 20m''ye kadar uzaktan değiştirerek 5m boyutuna kadar yükseltilmiş platformlar veya derin hendekler yaratır.', 'Alters the battlefield terrain up to 20m away, creating elevated platforms or deep trenches up to 5m in size.', 'Earthbound', 55, 450, 3, '{"sth_meteor_strike"}', '{"x": 1905, "y": -1099}', '{"range": "20m", "size": "5m"}', '🗺️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e3709929-7e84-40ca-8bd4-62b8136f1c96', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_earthshatter', 'Yer Yaran', 'Earthshatter', 'Bir silahı yere vurarak zemini 15m''lik bir hat boyunca parçalar. Düşmanlar 6d10 hasar alır ve 1 tur sersemler.', 'Slams a weapon into the earth, fracturing the ground in a 15m line. Enemies take 6d10 damage and are stunned for 1 turn.', 'Earthbound', 61, 600, 4, '{"sth_tectonic_shift"}', '{"x": 2121, "y": -1224}', '{"damage": "6d10", "range": "15m line", "status": "stunned"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8b1fac8-537c-4b35-8428-79721236bf22', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_gravity_well', 'Yerçekimi Kuyusu', 'Gravity Well', '10m yarıçapta yerçekimini artırır. Uçan düşmanlar düşer ve yerdeki düşmanlar 2 tur boyunca hareket edemez veya atılamaz.', 'Increases gravity in a 10m radius. Flying enemies fall, and ground enemies cannot move or dash for 2 turns.', 'Earthbound', 68, 700, 4, '{"sth_earthshatter"}', '{"x": 2338, "y": -1349}', '{"range": "10m radius", "duration": "2 turns"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('721d6890-32f3-462f-accf-a9e05c3d3486', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_mountain_maker', 'Dağ Yapan', 'Mountain Maker', 'Ayaklarınızın altından 10m yüksekliğinde devasa bir zirve yükseltir, size yüksek zemin avantajı ve 50 geçici HP sağlar.', 'Raises a massive 10m tall peak from the earth under your feet, granting you high ground advantage and 50 temporary HP.', 'Earthbound', 75, 800, 4, '{"sth_gravity_well"}', '{"x": 2554, "y": -1474}', '{"size": "10m tall", "temp_hp": "50"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fbdada97-70e9-4752-873b-825638be845e', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_world_tremor', 'Dünya Sarsıntısı', 'World Tremor', 'Devasa, sürekli bir deprem tetikler. 50m içindeki tüm düşmanlar her tur 4d10 hasar alır ve yere düşer. 3 tur sürer.', 'Triggers a massive continuous earthquake. All enemies within 50m take 4d10 damage each turn and are knocked prone. Lasts 3 turns.', 'Earthbound', 81, 1000, 5, '{"sth_mountain_maker"}', '{"x": 2771, "y": -1599}', '{"damage": "4d10/turn", "range": "50m", "duration": "3 turns", "status": "prone"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf64816f-7369-4c35-9f88-6f4a61420b46', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_wrath_of_titans', 'Titanların Öfkesi', 'Wrath of the Titans', 'Savaş alanını parçalamak için ilkel bir titanın astral kollarını çağırır. 30m yarıçapta 15d12 ezici hasar verir ve tüm yapıları yok eder.', 'Summons the astral arms of a primordial titan to smash the battlefield. Deals 15d12 bludgeoning damage in a 30m radius and destroys all structures.', 'Earthbound', 95, 1500, 5, '{"sth_world_tremor"}', '{"x": 2987, "y": -1724}', '{"damage": "15d12 bludgeoning", "range": "30m radius"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('42175848-c0a9-4a8d-be98-5f68a69f47e0', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_stiffening_touch', 'Sertleştiren Dokunuş', 'Stiffening Touch', 'Hedefin eklemlerini kısmen kireçlendiren, hareket hızını 2 tur boyunca 3m azaltan bir yakın dövüş dokunuş saldırısı.', 'A melee touch attack that partially calcifies a target''s joints, reducing their movement speed by 3m for 2 turns.', 'Petrification', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "Melee", "duration": "2 turns", "speed": "-3m"}', '🤌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b204f888-4048-4ff7-bc0e-6ca6d12d7e24', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_fossil_dust', 'Fosil Tozu', 'Fossil Dust', '4m''lik bir koniye kadim bir toz üfler. Düşmanlar kurtarma zarı atamazsa 1 tur boyunca büyü yapmada %10 başarısız olma ihtimali kazanır.', 'Blows ancient dust in a 4m cone. Enemies must save or have a 10% chance to fail casting spells for 1 turn.', 'Petrification', 8, 80, 1, '{"sth_stiffening_touch"}', '{"x": 289, "y": 344}', '{"range": "4m cone", "duration": "1 turn", "spell_failure": "10%"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4491d846-9a0a-4cc5-9b7e-6c563230d4f5', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_heavy_limbs', 'Ağır Uzuvlar', 'Heavy Limbs', '10m''ye kadar uzaktaki bir hedefi lanetler. Kolları taş gibi ağırlaşır ve 2 tur boyunca saldırı zarlarında dezavantaj verir.', 'Curses a target up to 10m away. Their arms turn heavy as stone, giving them disadvantage on attack rolls for 2 turns.', 'Petrification', 15, 120, 1, '{"sth_fossil_dust"}', '{"x": 449, "y": 536}', '{"range": "10m", "duration": "2 turns", "status": "disadvantage"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0b93d9a-5e2d-4690-9cdd-15c77bd23a4b', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_stone_gaze', 'Taş Bakışı', 'Stone Gaze', '15m içindeki tek bir hedefe odaklanır. Hedef kurtarma zarı atamazsa 1 tur boyunca felç olur (kısmen taşa dönüşür).', 'Focuses on a single target within 15m. Target must save or be paralyzed (partially turned to stone) for 1 turn.', 'Petrification', 22, 180, 2, '{"sth_heavy_limbs"}', '{"x": 610, "y": 727}', '{"range": "15m", "duration": "1 turn", "status": "paralyzed"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f7fd93ee-a1f3-4a70-b5af-9e75529a6dff', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_calcify_armor', 'Zırh Kireçlendirme', 'Calcify Armor', 'Bir düşmanın zırhını isteği dışında sertleştirerek eklemlerini kilitler. Hedef 2d8 ezici hasar alır ve 3 tur boyunca 2 Zırh Sınıfı kaybeder.', 'Hardens an enemy''s armor against their will, locking its joints. Target takes 2d8 crushing damage and loses 2 AC for 3 turns.', 'Petrification', 28, 220, 2, '{"sth_stone_gaze"}', '{"x": 771, "y": 919}', '{"damage": "2d8 crushing", "ac_reduction": "2", "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('87f84150-e019-4a6d-ab3c-8b3b8b4f2470', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_petrifying_strike', 'Taşlaştıran Vuruş', 'Petrifying Strike', 'Silahınıza taşlaştırma büyüsü aşılar. Sonraki vuruş fazladan 3d6 hasar verir ve hedefin eylemlerini %20 yavaşlatır.', 'Infuses your weapon with petrification magic. The next strike deals extra 3d6 damage and slows the target''s actions by 20%.', 'Petrification', 38, 280, 2, '{"sth_calcify_armor"}', '{"x": 932, "y": 1110}', '{"damage": "+3d6", "speed": "-20%"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('11871a2c-fc4b-4492-9075-6d28feaf6f4b', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_gorgons_breath', 'Gorgon''un Nefesi', 'Gorgon''s Breath', '10m''lik bir koniye zehirli yeşil bir sis üfler. Hedefler 4d8 zehir hasarı alır ve bacaklarına tırmanan taşlar tarafından kısıtlanır.', 'Exhales a toxic green mist in a 10m cone. Targets take 4d8 poison damage and are restrained by stone creeping up their legs.', 'Petrification', 42, 360, 3, '{"sth_petrifying_strike"}', '{"x": 1092, "y": 1302}', '{"damage": "4d8 poison", "range": "10m cone", "status": "restrained"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0699157d-a13e-44c3-aae0-7b612eeef817', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_statue_shatter', 'Heykel Parçalama', 'Statue Shatter', 'Taşlaşmış, kısıtlanmış veya felç olmuş bir hedefe vurarak üzerlerindeki taşı patlatır ve 6d8 hasar verir.', 'Strikes a petrified, restrained, or paralyzed target, detonating the stone on them for 6d8 damage.', 'Petrification', 49, 420, 3, '{"sth_gorgons_breath"}', '{"x": 1253, "y": 1493}', '{"damage": "6d8"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f1e415f3-747e-4e8a-b2c4-fef8fe0f91f9', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_geode_trap', 'Jeot Tuzağı', 'Geode Trap', 'Gizli bir rün yerleştirir. Tetiklendiğinde kurbanı kristal bir jeodun içine hapseder, 2 tur sersemletir ve zamanla 3d10 hasar verir.', 'Places a hidden rune. When triggered, it encases the victim in a crystal geode, stunning them for 2 turns and dealing 3d10 damage over time.', 'Petrification', 58, 480, 3, '{"sth_statue_shatter"}', '{"x": 1414, "y": 1685}', '{"damage": "3d10/turn", "duration": "2 turns", "status": "stunned"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e7cbeaef-5931-4310-850a-1dab90444841', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_medusas_curse', 'Medusa''nın Laneti', 'Medusa''s Curse', '20m''ye kadar uzaktaki bir hedefe taşlaştırıcı bir enerji ışını ateşler. Kurtarma zarında başarısız olurlarsa iyileştirilene kadar kalıcı olarak taşa dönüşürler.', 'Fires a beam of petrifying energy at a target up to 20m. If they fail a save, they are permanently turned to stone until cured.', 'Petrification', 62, 650, 4, '{"sth_geode_trap"}', '{"x": 1574, "y": 1876}', '{"range": "20m", "status": "permanently petrified"}', '👱‍♀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e170d17-42fd-4714-86f1-b0fd05e63c83', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_fossilize_blood', 'Kan Fosilize Etme', 'Fossilize Blood', '15m içindeki düşmanların kanındaki mineralleri kaynatır. 5d10 nekrotik hasar verir ve şiddetli iç kanamaya neden olarak iyileşmeyi %50 azaltır.', 'Boils the minerals in enemies'' blood within 15m. Deals 5d10 necrotic damage and causes severe internal bleeding, reducing healing by 50%.', 'Petrification', 70, 750, 4, '{"sth_medusas_curse"}', '{"x": 1735, "y": 2068}', '{"damage": "5d10 necrotic", "range": "15m", "healing_reduction": "50%"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb55ae2b-123d-41b6-a2d8-3995bab3b44a', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_basilisk_eye', 'Basilisk Gözü', 'Basilisk Eye', '15m''lik bir alanı tarayan sihirli bir göz yaratır. Bakışına yakalanan herkes 6d8 psişik hasar alır ve ağır şekilde taşlaşır (2 tur hareket edemez).', 'Creates a magical eye that sweeps a 15m area. Anyone caught in its gaze takes 6d8 psychic damage and is heavily petrified (cannot act for 2 turns).', 'Petrification', 78, 850, 4, '{"sth_fossilize_blood"}', '{"x": 1896, "y": 2259}', '{"damage": "6d8 psychic", "range": "15m area", "status": "heavy petrification", "duration": "2 turns"}', '🦎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b7531dc2-d9d1-4bdc-a412-e78394a959cf', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_mass_petrification', 'Toplu Taşlaştırma', 'Mass Petrification', '20m''lik bir gorgon büyüsü patlaması yayar. İçerideki tüm düşmanlar zorlu bir kurtarma zarını geçemezse 3 tur boyunca taş heykellere dönüşür.', 'Releases a 20m burst of gorgon magic. All enemies inside must pass a strict save or become stone statues for 3 turns.', 'Petrification', 82, 1100, 5, '{"sth_basilisk_eye"}', '{"x": 2056, "y": 2451}', '{"range": "20m burst", "status": "petrified", "duration": "3 turns"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0ad5ff32-5081-4d7f-b90d-7455effc6e8c', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_gorgons_garden', 'Gorgon''un Bahçesi', 'The Gorgon''s Garden', '40m yarıçapını ölü bir taş çorak araziye dönüştürür. %20 HP altındaki düşmanlar kalıcı olarak taş heykellere dönüşür. Diğerleri tur başına 10d10 hasar alır.', 'Transforms a 40m radius into a dead stone wasteland. Enemies turn into stone statues permanently if under 20% HP. Others take 10d10 damage per turn.', 'Petrification', 96, 1500, 5, '{"sth_mass_petrification"}', '{"x": 2217, "y": 2642}', '{"range": "40m radius", "damage": "10d10/turn", "status": "permanent petrification < 20% HP"}', '🥀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d3c06d00-ee4d-4105-b670-15b23a8fe3ba', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_pebble_skin', 'Çakıl Derisi', 'Pebble Skin', 'Derinizi geçici olarak sertleştirerek +2 Zırh Sınıfı kazandırır ve 3 tur boyunca gelen fiziksel hasarı 2 azaltır.', 'Hardens your skin temporarily, gaining +2 AC and reducing incoming physical damage by 2 for 3 turns.', 'Stone Resolve', 2, 60, 1, '{}', '{"x": -128, "y": 153}', '{"ac_bonus": "2", "damage_reduction": "2", "duration": "3 turns"}', '🔘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7910f2ec-eb6a-411c-aba9-fbb219ac50a1', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_rooted_stance', 'Köklü Duruş', 'Rooted Stance', 'Ayaklarınızı yere sıkıca basarsınız. 3 tur boyunca itilemez veya yere düşürülemezsiniz, ancak hareket hızınız yarıya iner.', 'Plants your feet firmly into the ground. You cannot be pushed or knocked prone for 3 turns, but your movement speed is halved.', 'Stone Resolve', 6, 90, 1, '{"sth_pebble_skin"}', '{"x": -289, "y": 344}', '{"duration": "3 turns", "speed": "-50%", "status": "immune to prone/push"}', '🌳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d1650dc-6ebf-44b0-be3b-2227b153bb9d', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_unflinching_guard', 'Sarsılmaz Koruma', 'Unflinching Guard', 'Kollarınızı çaprazlayarak sonraki saldırıdan 20 hasara kadar emersiniz. Emilen hasarın %50''sini güç olarak geri yansıtır.', 'Crosses your arms, absorbing up to 20 damage from the next attack. Reflects 50% of the absorbed damage back as force.', 'Stone Resolve', 12, 130, 1, '{"sth_rooted_stance"}', '{"x": -449, "y": 536}', '{"damage_absorption": "20", "damage_reflection": "50%"}', '🙅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e67af36-27a9-4359-9a20-4ebcf97266ce', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_granite_carapace', 'Granit Kabuk', 'Granite Carapace', 'Kendinizi kalın bir granite hapsedersiniz. 40 geçici HP ve kesici ile delici hasara karşı direnç kazanırsınız.', 'Encases yourself in thick granite. You gain 40 temporary HP and resistance to slashing and piercing damage.', 'Stone Resolve', 23, 190, 2, '{"sth_unflinching_guard"}', '{"x": -610, "y": 727}', '{"temp_hp": "40", "resistance": "slashing, piercing"}', '🐢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6a546290-9e18-466e-b69c-588faa9d8060', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_stalwart_defender', 'Sadık Savunmacı', 'Stalwart Defender', 'Etrafınızda 5m''lik bir aura yaratır. Aura içindeki müttefikler +3 ZS kazanır ve onlara yönelik hasarın %25''ini siz alırsınız.', 'Creates a 5m aura around you. Allies within the aura gain +3 AC and you take 25% of the damage intended for them.', 'Stone Resolve', 30, 230, 2, '{"sth_granite_carapace"}', '{"x": -771, "y": 919}', '{"range": "5m aura", "ac_bonus": "3", "damage_share": "25%"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b50b4a15-a532-4337-900a-d9b311a86f19', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_weight_of_earth', 'Dünyanın Ağırlığı', 'Weight of the Earth', 'Kütlenizi pasif olarak artırır. Yakalanmaya veya fırlatılmaya karşı bağışıklık kazanırsınız. Aktif: Bitişik hedeflere 3d6 hasar vermek için yere basın.', 'Passively increases your mass. You are immune to being grappled or thrown. Active: Stomp to deal 3d6 damage to adjacent targets.', 'Stone Resolve', 36, 270, 2, '{"sth_stalwart_defender"}', '{"x": -932, "y": 1110}', '{"damage": "3d6", "status": "immune grapple/throw"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('877e4802-3fac-4fac-8262-cc6cb3c4aeb3', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_obsidian_armor', 'Obsidyen Zırh', 'Obsidian Armor', 'Büyüyü yansıtan simsiyah bir zırh çağırır. 2 tur boyunca, sizi hedef alan tüm büyülerin büyücüye geri dönme şansı %30''dur.', 'Summons jet-black armor that reflects magic. For 2 turns, any spells targeting you have a 30% chance to rebound to the caster.', 'Stone Resolve', 43, 370, 3, '{"sth_weight_of_earth"}', '{"x": -1092, "y": 1302}', '{"duration": "2 turns", "spell_reflection": "30%"}', '🖤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0ec1883-303a-4412-a7ec-a3d7fbe19ae9', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_ignore_pain', 'Acıyı Görmezden Gelme', 'Ignore Pain', 'Saf bir dayanıklılık transına girersiniz. 3 tur boyunca tüm olumsuz durum etkilerini (zehir, yanma, kanama) yok sayar ve 0 HP''de savaşmaya devam edersiniz.', 'Enter a trance of pure endurance. For 3 turns, you ignore all negative status effects (poison, burn, bleed) and continue fighting at 0 HP.', 'Stone Resolve', 51, 430, 3, '{"sth_obsidian_armor"}', '{"x": -1253, "y": 1493}', '{"duration": "3 turns", "status": "ignore negative effects & death"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('197458dc-abaa-48d6-868c-6a8e48e42ec2', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_immovable_object', 'Taşınmaz Nesne', 'Immovable Object', '1 tur boyunca tüm hasar ve etkilere karşı tamamen savunmasız hale gelirsiniz, ancak hiçbir eylem, bonus eylem veya tepki alamazsınız.', 'You become completely invulnerable to all damage and effects for 1 turn, but you cannot take any actions, bonus actions, or reactions.', 'Stone Resolve', 57, 490, 3, '{"sth_ignore_pain"}', '{"x": -1414, "y": 1685}', '{"duration": "1 turn", "status": "invulnerable & immobile"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('12954904-9ad1-4046-805f-09da1c2696c0', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_diamond_skin', 'Elmas Deri', 'Diamond Skin', 'Etiniz mükemmel elmasa dönüşür. 2 tur boyunca tüm fiziksel hasarlara (ezici, delici, kesici) karşı bağışıklık kazanırsınız.', 'Your flesh turns to perfect diamond. You gain immunity to all physical damage (bludgeoning, piercing, slashing) for 2 turns.', 'Stone Resolve', 64, 680, 4, '{"sth_immovable_object"}', '{"x": -1574, "y": 1876}', '{"duration": "2 turns", "immunity": "physical damage"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e6252f09-f1a5-4b4d-8957-acc461affa51', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_juggernauts_charge', 'Juggernaut''un Hücumu', 'Juggernaut''s Charge', '15m''ye kadar ileri atılırsınız. Büyülü bariyerleri kırar ve yolunuzdaki her şeye 8d6 hasar vererek onları kenara fırlatırsınız.', 'Dash forward up to 15m. You break through magical barriers and deal 8d6 damage to anything in your path, tossing them aside.', 'Stone Resolve', 72, 780, 4, '{"sth_diamond_skin"}', '{"x": -1735, "y": 2068}', '{"range": "15m dash", "damage": "8d6"}', '🦏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cc91bd2e-03bf-47e5-b840-97bb697811c2', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_avatar_of_stone', 'Taşın Avatarı', 'Avatar of Stone', 'Boyutunuzu Büyük''e çıkarır. Tüm Güç zarlarında avantaj, +50 maksimum HP kazanırsınız ve yakın dövüş menziliniz 2m artar. 5 tur sürer.', 'Increase your size to Large. You gain advantage on all Strength checks, +50 maximum HP, and your melee range increases by 2m. Lasts 5 turns.', 'Stone Resolve', 79, 880, 4, '{"sth_juggernauts_charge"}', '{"x": -1896, "y": 2259}', '{"duration": "5 turns", "max_hp": "+50", "melee_range": "+2m", "size": "Large"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ab32d9b2-491d-4c5c-841e-8ca0952b4c72', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_heart_of_mountain', 'Dağın Kalbi', 'Heart of the Mountain', 'Pasif yenilenme devreye girer. Her tur maksimum HP''nizin %5''ini iyileştirin. HP''niz %10''un altına düştüğünde anında %50 iyileşirsiniz. (Uzun dinlenme başına bir kez).', 'Passive regeneration kicks in. Heal 5% of your max HP every turn. When your HP drops below 10%, instantly heal for 50%. (Once per long rest).', 'Stone Resolve', 84, 1200, 5, '{"sth_avatar_of_stone"}', '{"x": -2056, "y": 2451}', '{"healing": "5%/turn", "emergency_heal": "50%"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('20d1bc67-f37c-495a-947f-790c5308ab82', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_aegis_of_gaia', 'Gaia''nın Kalkanı', 'Aegis of Gaia', 'Dünyanın mutlak savunucusu olun. 3 tur boyunca 30m içindeki tüm müttefikler ZS''nizi, dirençlerinizi ve bağışıklıklarınızı paylaşır. Aldıkları tüm hasarın %50''sini emersiniz.', 'Become the absolute defender of the world. For 3 turns, all allies within 30m share your AC, resistances, and immunities. You absorb 50% of all damage they take.', 'Stone Resolve', 97, 1500, 5, '{"sth_heart_of_mountain"}', '{"x": -2217, "y": 2642}', '{"range": "30m", "duration": "3 turns", "damage_share": "50%"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b0709ee0-8f60-4ac2-99e5-043c23661cf1', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_trembling_defense', 'Titreyen Savunma', 'Trembling Defense', 'Savunma duruşunuz etrafınızdaki yerin sarsılmasına neden olur. Size yakın dövüş saldırısı ile vuran her düşman 3d6 ezici hasar alır ve 2m geriye itilir.', 'Your defensive stance causes the ground around you to shake. Any enemy that hits you with a melee attack takes 3d6 bludgeoning damage and is pushed 2m back.', 'Cross-Branch', 45, 400, 3, '{"sth_earthen_pillars", "sth_obsidian_armor"}', '{"x": -173, "y": -100}', '{"damage": "3d6 bludgeoning", "knockback": "2m"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bc869f26-bd70-4123-a10f-ca3d1cfa9b68', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_gorgons_shield', 'Gorgon Kalkanı', 'Gorgon''s Shield', 'Gorgon yüzü taşıyan bir kalkan çağırır. +3 ZS verir. Çatışma başına bir kez, kalkanı parlatarak 5m''lik konideki düşmanları 1 tur taşlaştırabilirsiniz.', 'Summons a shield bearing the face of a gorgon. Gives +3 AC. Once per combat, you can flash the shield to petrify enemies in a 5m cone for 1 turn.', 'Cross-Branch', 52, 450, 3, '{"sth_gorgons_breath", "sth_stalwart_defender"}', '{"x": -389, "y": -225}', '{"ac_bonus": "3", "range": "5m cone", "duration": "1 turn", "status": "petrified"}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b3e24e9d-ffc4-4891-b3a9-1b2b03873844', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_seismic_fossilization', 'Sismik Fosilize Etme', 'Seismic Fossilization', 'Düşmanlara hasar vermenin (5d8) yanı sıra taşlaştırıcı toz aşılayan 15m''lik bir sarsıntı gönderir. Kurtarma zarında başarısız olan düşmanlar felç olur ve kırılganlaşarak iki kat fiziksel hasar alır.', 'Sends a 15m tremor that not only damages enemies (5d8) but also infuses petrifying dust. Enemies failing the save are paralyzed and brittle, taking double physical damage.', 'Cross-Branch', 65, 720, 4, '{"sth_earthshatter", "sth_medusas_curse"}', '{"x": -606, "y": -350}', '{"damage": "5d8", "range": "15m", "status": "paralyzed, x2 physical damage taken"}', '🕸️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e034b91e-f5fc-4c59-9b4b-5bdf07292fee', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_avalanche_charge', 'Çığ Hücumu', 'Avalanche Charge', 'Kendinizi kayalara sarın ve 20m ileri atılın. Yol üzerindeki hedeflere 6d10 hasar verirsiniz ve düşmanlara hasar veren zorlu bir arazi izi bırakırsınız.', 'Cloak yourself in boulders and rush forward 20m. You deal 6d10 damage to targets in the path and leave a trail of difficult terrain that damages enemies.', 'Cross-Branch', 73, 820, 4, '{"sth_gravity_well", "sth_juggernauts_charge"}', '{"x": -822, "y": -475}', '{"damage": "6d10", "range": "20m dash"}', '🏂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('32ad618f-1e42-4945-9fa5-ac7e291cbf52', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_diamond_dust', 'Elmas Tozu', 'Diamond Dust', 'Sertleşmiş derinizin bir kısmını parçalayarak 10m yarıçapında 8d8 delici hasar verir. Hayatta kalan düşmanların zırhı kalıcı olarak 3 ZS zayıflar.', 'Shatters a portion of your hardened skin, dealing 8d8 piercing damage in a 10m radius. Surviving enemies have their armor permanently degraded by 3 AC.', 'Cross-Branch', 77, 870, 4, '{"sth_basilisk_eye", "sth_diamond_skin"}', '{"x": -1039, "y": -600}', '{"damage": "8d8 piercing", "range": "10m radius", "ac_reduction": "3"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84462017-8095-4127-aa72-767002a4c7d7', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_meteor_of_gorgos', 'Gorgos Meteoru', 'Meteor of Gorgos', 'Yoğunlaştırılmış gorgon enerjisinden bir meteor çağırır. Çarpma anında (15m yarıçap) 10d10 güç hasarı verir. Hayatta kalan herkes anında taşa dönüşür.', 'Summons a meteor of concentrated gorgon energy. On impact (15m radius), deals 10d10 force damage. Any survivor is instantly turned to stone.', 'Cross-Branch', 86, 1250, 5, '{"sth_world_tremor", "sth_mass_petrification"}', '{"x": -1255, "y": -725}', '{"damage": "10d10 force", "range": "15m radius", "status": "permanent petrification"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('897c99a5-76fe-4f5b-b919-9b3958ae6bc8', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_mountain_kings_command', 'Dağ Kralının Emri', 'Mountain King''s Command', 'Arazi ile birleşirsiniz. 3 tur boyunca hareket edemezsiniz, ancak 100 geçici HP kazanırsınız ve Dünya Bağı büyülerini savaş alanının herhangi bir yerinde görüş alanı olmadan kullanabilirsiniz.', 'You merge with the terrain. For 3 turns, you cannot move, but you gain 100 temporary HP and can cast Earthbound spells globally anywhere on the battlefield without line of sight.', 'Cross-Branch', 92, 1400, 5, '{"sth_world_tremor", "sth_heart_of_mountain"}', '{"x": -1472, "y": -850}', '{"duration": "3 turns", "temp_hp": "100", "range": "Global"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e7019930-8b27-4c9d-a46c-9b4c938768f4', '6131e7f8-eb6a-4082-b950-6d2035a1132a', 'sth_genesis_worldstone', 'Dünya Taşının Doğuşu', 'Genesis of the Worldstone', 'Nihai eseri yaratırsınız: bir Dünya Taşı kristali. Tüm müttefiklerin HP''sini tamamen yeniler, onlara Elmas Deri verir ve tüm savaş alanı boyunca %50 HP altındaki tüm düşmanları kalıcı olarak taşa çevirir.', 'You create the ultimate artifact: a Worldstone crystal. It restores all allies to full HP, grants them Diamond Skin, and permanently petrifies all enemies below 50% HP across the entire battlefield.', 'Cross-Branch', 100, 2500, 5, '{"sth_wrath_of_titans", "sth_gorgons_garden", "sth_aegis_of_gaia"}', '{"x": -1688, "y": -975}', '{"healing": "100%", "status": "Diamond Skin (Allies), Permanent Petrification (Enemies < 50% HP)"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d5e34e0-d94b-4b1f-bac2-94f19960b82b', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_static_shot', 'Statik Atış', 'Static Shot', 'Statik elektrikle yüklü bir ok fırlatarak 1d8 delici ve 1d6 yıldırım hasarı verir. Vurulan hedeflerin hareket hızı 1 tur boyunca 2m azalır.', 'Fires an arrow charged with static electricity, dealing 1d8 piercing and 1d6 lightning damage. Targets hit have their movement speed reduced by 2m for 1 turn.', 'Lightning', 1, 100, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8 piercing + 1d6 lightning", "range": "30m", "duration": "1 turn"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b4b390e-2ed9-49a8-9ce5-79f7bb68ee48', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_arc_arrow', 'Ark Oku', 'Arc Arrow', 'Ana hedefin 5m yakınındaki ek bir hedefe atlayan, her ikisine de 2d6 yıldırım hasarı veren bir ok.', 'An arrow that jumps to one additional target within 5m of the primary target, dealing 2d6 lightning damage to both.', 'Lightning', 5, 100, 1, '{"sts_static_shot"}', '{"x": 389, "y": -224}', '{"damage": "2d6 lightning", "range": "40m", "jump_range": "5m"}', '🏹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c0f95b05-44dd-4dec-bbaf-2ece55d80369', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_lightning_reflexes', 'Yıldırım Refleksleri', 'Lightning Reflexes', 'Pasif. Temel hareket hızınız 3m artar ve Çeviklik kurtarma zarlarına +2 bonus kazanırsınız.', 'Passive. Your base movement speed increases by 3m, and you gain a +2 bonus to Dexterity saving throws.', 'Lightning', 10, 150, 1, '{"sts_static_shot"}', '{"x": 606, "y": -349}', '{"passive": "true", "movement_bonus": "3m", "save_bonus": "+2 Dex"}', '🏃‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0b757387-3061-4b89-b502-edcb0bb0f678', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_chain_lightning_arrow', 'Zincirleme Yıldırım Oku', 'Chain Lightning Arrow', 'Ok çarpma anında parçalanır ve 10m içindeki 3 hedefe kadar yıldırım zincirler. Her birine 3d8 yıldırım hasarı verir.', 'The arrow splinters upon impact, chaining lightning up to 3 targets within 10m. Deals 3d8 lightning damage to each.', 'Lightning', 21, 250, 2, '{"sts_arc_arrow"}', '{"x": 822, "y": -474}', '{"damage": "3d8 lightning", "range": "40m", "chain_range": "10m", "targets": "3"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('282bf321-82ac-4f31-9297-896880893e7f', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_voltage_trap', 'Voltaj Tuzağı', 'Voltage Trap', 'Yere görünmez bir elektrik tuzağı kurar. Tetiklendiğinde 5m yarıçapta patlayarak 4d6 yıldırım hasarı verir ve 1 tur felç eder.', 'Places an invisible electrical trap on the ground. When triggered, it explodes in a 5m radius, dealing 4d6 lightning damage and paralyzing for 1 turn.', 'Lightning', 25, 250, 2, '{"sts_lightning_reflexes"}', '{"x": 1039, "y": -599}', '{"damage": "4d6 lightning", "aoe": "5m radius", "duration": "1 turn"}', '🪤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2c55c7c1-4fdc-441d-83c6-016c531e18b2', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_overcharge', 'Aşırı Yükleme', 'Overcharge', 'Yayınızı geçici olarak aşırı yükleyerek sonraki 3 saldırınızın ek 2d8 yıldırım hasarı vermesini ve yıldırım direncini yok saymasını sağlar.', 'Temporarily overcharges your bow, causing your next 3 attacks to deal an additional 2d8 lightning damage and ignore lightning resistance.', 'Lightning', 30, 300, 2, '{"sts_chain_lightning_arrow"}', '{"x": 1255, "y": -724}', '{"damage_bonus": "2d8 lightning", "attacks": "3", "buff": "ignore resistance"}', '🔋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84182298-6985-47b6-9a3d-95df3b10add8', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_plasma_piercer', 'Plazma Delici', 'Plasma Piercer', '30m''lik bir hat boyunca ilerleyen, tüm hedeflerin içinden geçen ve 5d8 yıldırım hasarı veren aşırı ısınmış bir plazma oku fırlatır.', 'Fires a superheated plasma arrow that travels in a 30m line, passing through all targets and dealing 5d8 lightning damage.', 'Lightning', 41, 450, 3, '{"sts_overcharge"}', '{"x": 1472, "y": -849}', '{"damage": "5d8 lightning", "area": "30m line"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e7df7585-49ef-4ab7-a84d-b12a338ace2f', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_storm_step', 'Fırtına Adımı', 'Storm Step', 'Anında 15m içindeki herhangi bir konuma ışınlanarak, başlangıç noktanızın 3m içindeki düşmanlara 2d10 yıldırım hasarı veren bir kıvılcım bırakır.', 'Instantly teleport to any location within 15m, leaving a spark that deals 2d10 lightning damage to enemies within 3m of your starting point.', 'Lightning', 45, 450, 3, '{"sts_voltage_trap"}', '{"x": 1688, "y": -974}', '{"teleport": "15m", "damage": "2d10 lightning", "aoe": "3m"}', '⚡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b9cd82b-3a93-4dc0-a36b-239d981367a7', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_paralytic_shock', 'Felç Edici Şok', 'Paralytic Shock', '4d10 yıldırım hasarı veren yüksek yüklü bir ok. Hedef Dayanıklılık kurtarma zarında başarısız olursa 1 tur sersemler.', 'A highly charged arrow that deals 4d10 lightning damage. The target must succeed on a Constitution saving throw or be stunned for 1 turn.', 'Lightning', 50, 500, 3, '{"sts_plasma_piercer"}', '{"x": 1905, "y": -1099}', '{"damage": "4d10 lightning", "range": "50m", "status": "stun 1 turn"}', '😵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a7c47ca-da72-4abe-b104-472d4b50bf48', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_thundergods_bolt', 'Yıldırım Tanrısının Oku', 'Thundergod''s Bolt', 'Okunuzun çarptığı noktaya devasa bir yıldırım çağırarak 10m yarıçapta 8d8 yıldırım hasarı verir.', 'Calls down a massive bolt of lightning at the impact site of your arrow, dealing 8d8 lightning damage in a 10m radius.', 'Lightning', 61, 750, 4, '{"sts_paralytic_shock"}', '{"x": 2121, "y": -1224}', '{"damage": "8d8 lightning", "aoe": "10m radius", "range": "60m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('27c51e86-4ff6-4754-b61d-4ba0c65ffd87', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_lightning_rod', 'Paratoner', 'Lightning Rod', 'Yere veya bir hedefe işaret fişeği görevi gören bir ok atar. 3 tur boyunca 20m içinde verilen herhangi bir yıldırım hasarı %50 artar.', 'Fires an arrow into the ground or a target that acts as a beacon. For 3 turns, any lightning damage dealt within 20m is amplified by 50%.', 'Lightning', 65, 750, 4, '{"sts_storm_step"}', '{"x": 2338, "y": -1349}', '{"buff": "+50% lightning damage", "aoe": "20m radius", "duration": "3 turns"}', '🗼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c77ec462-dad4-4d85-be58-8eee708f4479', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_ball_lightning_strike', 'Top Yıldırım Vuruşu', 'Ball Lightning Strike', '2 tur boyunca 20m ilerleyen, her tur 5m içindeki düşmanları çarparak 3d12 yıldırım hasarı veren yavaş hareket eden bir yıldırım küresi fırlatır.', 'Fires a slow-moving orb of lightning that travels 20m over 2 turns, zapping enemies within 5m for 3d12 lightning damage each turn.', 'Lightning', 70, 900, 4, '{"sts_thundergods_bolt"}', '{"x": 2554, "y": -1474}', '{"damage": "3d12 lightning/turn", "area": "5m radius around orb", "duration": "2 turns"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0c2c2d30-df75-4a7b-bb5b-93ada05ef20f', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_wrath_of_the_storm', 'Fırtınanın Gazabı', 'Wrath of the Storm', 'Varlığınızı saf elektrikle doldurur. 1 dakika boyunca oklarınız fazladan 4d8 yıldırım hasarı verir ve hareket hızınız iki katına çıkar.', 'Infuses your being with pure electricity. For 1 minute, your arrows deal an extra 4d8 lightning damage and your movement speed is doubled.', 'Lightning', 81, 1200, 5, '{"sts_ball_lightning_strike"}', '{"x": 2771, "y": -1599}', '{"damage_bonus": "4d8 lightning", "movement": "x2", "duration": "1 minute"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cc14ec71-6cfa-49e6-a0c0-1aa8002588c0', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_raijins_judgment', 'Raijin''in Hükmü', 'Raijin''s Judgment', 'Nihai Yetenek. Gökyüzüne bir ok fırlatarak felaket getiren bir yıldırım fırtınası çağırır. 30m yarıçap içinde rastgele 5 kez vurur, her vuruş 10d10 yıldırım hasarı verir.', 'Ultimate. Fires an arrow into the sky, summoning a catastrophic lightning storm. Strikes 5 times randomly in a 30m radius, each strike dealing 10d10 lightning damage.', 'Lightning', 90, 1500, 5, '{"sts_wrath_of_the_storm"}', '{"x": 2987, "y": -1724}', '{"damage": "5x 10d10 lightning", "aoe": "30m radius", "strikes": "5"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ed89be1-41c9-4f3b-ac0d-9dbbfc3d3db5', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_sonic_arrow', 'Sonik Ok', 'Sonic Arrow', '1d8 delici ve 1d6 gök gürültüsü hasarı veren titreşen bir ok fırlatır. Yüksek bir çınlama yayarak hedefin gizlilik kullanmasını engeller.', 'Fires a vibrating arrow that deals 1d8 piercing and 1d6 thunder damage. Emits a loud ring that prevents the target from using stealth.', 'Thunder', 1, 100, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d8 piercing + 1d6 thunder", "range": "30m", "debuff": "no stealth"}', '🔉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('20f76e5e-ce9e-4f06-a95a-11c744d81f22', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_echoing_boom', 'Yankılanan Patlama', 'Echoing Boom', 'Sarsıcı bir kuvvetle patlayan bir ok. 3m yarıçapta 2d8 gök gürültüsü hasarı verir ve düşmanları 2m geriye iter.', 'An arrow that explodes with concussive force. Deals 2d8 thunder damage in a 3m radius and pushes enemies back 2m.', 'Thunder', 5, 100, 1, '{"sts_sonic_arrow"}', '{"x": 289, "y": 344}', '{"damage": "2d8 thunder", "aoe": "3m radius", "push": "2m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b821884-b3c1-4154-88b3-0565a0f3fd23', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_concussive_shot', 'Sarsıcı Atış', 'Concussive Shot', 'Yön şaşırtmak için tasarlanmış ağır bir ok. 2d6 ezici hasar verir ve 1 tur boyunca hedefin saldırı zarlarına -2 ceza uygular.', 'A heavy arrow designed to disorient. Deals 2d6 bludgeoning damage and applies a -2 penalty to the target''s attack rolls for 1 turn.', 'Thunder', 10, 150, 1, '{"sts_sonic_arrow"}', '{"x": 449, "y": 536}', '{"damage": "2d6 bludgeoning", "debuff": "-2 to attacks", "duration": "1 turn"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('672babfe-e001-4650-925a-d506221c82a0', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_thunderclap_trap', 'Gök Gürültüsü Tuzağı', 'Thunderclap Trap', 'Sonik bir mayın yerleştirir. Tetiklendiğinde sağır edici bir patlama yayarak 4d6 gök gürültüsü hasarı verir ve düşmanları 2 tur sağır eder.', 'Places a sonic mine. When triggered, it releases a deafening boom dealing 4d6 thunder damage, deafening enemies for 2 turns.', 'Thunder', 21, 250, 2, '{"sts_concussive_shot"}', '{"x": 610, "y": 727}', '{"damage": "4d6 thunder", "status": "deafened 2 turns", "aoe": "5m radius"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('14f005cc-4587-4a2d-aed5-bbcfa9c8a661', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_resonance_wave', 'Rezonans Dalgası', 'Resonance Wave', '15m ileriye bir ses dalgası göndermek için yay kirişini çeker. Konideki tüm düşmanlara 3d8 gök gürültüsü hasarı verir ve kırılgan nesneleri parçalar.', 'Plucks the bowstring to send a wave of sound 15m forward. Deals 3d8 thunder damage to all enemies in the cone and shatters fragile objects.', 'Thunder', 25, 250, 2, '{"sts_echoing_boom"}', '{"x": 771, "y": 919}', '{"damage": "3d8 thunder", "area": "15m cone"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a09b6137-99de-4c23-b934-92e9e05b7b3e', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_blast_back', 'Geri Tepme', 'Blast Back', 'Geriye doğru sıçrarken ayaklarınızın dibine patlayıcı bir ok atarsınız. 10m geriye gidersiniz ve 5m içindeki düşmanlar 3d6 gök gürültüsü hasarı alır.', 'Fires an explosive arrow at your feet while leaping backward. You travel 10m back, while enemies within 5m take 3d6 thunder damage.', 'Thunder', 30, 300, 2, '{"sts_resonance_wave"}', '{"x": 932, "y": 1110}', '{"damage": "3d6 thunder", "movement": "10m backwards", "aoe": "5m"}', '🦘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('21c79b42-8743-46de-81ee-3127653ea1c4', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_thundercrash', 'Gök Gürlemesi', 'Thundercrash', 'Çarpma anında devasa bir sonik patlama yaratan güçlü bir atış. 10m yarıçapta 5d8 gök gürültüsü hasarı verir ve hedefleri yere serer.', 'A powerful shot that creates a massive sonic boom on impact. Deals 5d8 thunder damage in a 10m radius and knocks targets prone.', 'Thunder', 41, 450, 3, '{"sts_blast_back"}', '{"x": 1092, "y": 1302}', '{"damage": "5d8 thunder", "aoe": "10m radius", "status": "prone"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7926a682-6117-4837-80ff-506314300ac0', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_deafening_roar', 'Sağır Edici Kükreme', 'Deafening Roar', 'Havada çığlık atarak ilerleyen bir ok fırlatır. Uçuş yolunun 5m içindeki herhangi bir düşman 4d8 gök gürültüsü hasarı alır ve 1 tur boyunca sözlü bileşenli büyü yapamaz.', 'Fires an arrow that screams through the air. Any enemy within 5m of its flight path takes 4d8 thunder damage and cannot cast spells with verbal components for 1 turn.', 'Thunder', 45, 450, 3, '{"sts_thunderclap_trap"}', '{"x": 1253, "y": 1493}', '{"damage": "4d8 thunder", "area": "line + 5m radius", "debuff": "silence 1 turn"}', '🦁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a1094ae-9b19-463d-a83b-eff17c2dd46e', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_tremor_shot', 'Sarsıntı Atışı', 'Tremor Shot', 'Yere bir ok saplayarak yerel depremlere neden olur. 3 tur boyunca etrafındaki 15m''lik alan zorlu arazidir ve düşmanlar tur başına 2d8 ezici hasar alır.', 'Pins an arrow into the ground, causing localized earthquakes. For 3 turns, the 15m area around it is difficult terrain, and enemies take 2d8 bludgeoning damage per turn.', 'Thunder', 50, 500, 3, '{"sts_thundercrash"}', '{"x": 1414, "y": 1685}', '{"damage": "2d8 bludgeoning/turn", "aoe": "15m radius", "duration": "3 turns", "terrain": "difficult"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2a9abbc9-fc92-4fe0-92fa-e05a9064b4c9', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_sonic_boom_blast', 'Sonik Patlama Vuruşu', 'Sonic Boom Blast', 'Bir okla ses bariyerini aşar. Tek bir hedefe 8d8 gök gürültüsü hasarı verir ve onları 10m geriye iter.', 'Breaks the sound barrier with an arrow. Deals 8d8 thunder damage to a single target and forces them back 10m.', 'Thunder', 61, 750, 4, '{"sts_tremor_shot"}', '{"x": 1574, "y": 1876}', '{"damage": "8d8 thunder", "push": "10m", "range": "60m"}', '🚀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bcd7b00e-b453-4f89-8571-4acd43929b33', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_mjolnirs_impact', 'Mjölnir''in Etkisi', 'Mjölnir''s Impact', 'Gök gürültüsünün ağırlığını taşıyan bir ok. Geçici can puanlarını ve kalkanları yok sayarak 6d10 ezici ve gök gürültüsü hasarı verir.', 'An arrow carrying the weight of thunder. Deals 6d10 bludgeoning and thunder damage, ignoring temporary hit points and shields.', 'Thunder', 65, 750, 4, '{"sts_deafening_roar"}', '{"x": 1735, "y": 2068}', '{"damage": "6d10 bludgeoning/thunder", "pierce": "ignores shields"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9b2e78c3-417f-4714-8db2-b35bc4bdb5af', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_disruptive_frequency', 'Bozucu Frekans', 'Disruptive Frequency', 'İptal edici bir frekans yayan özel bir ok fırlatır. 10m yarıçapındaki hedeflerin üzerindeki tüm büyüsel güçlendirmeleri kaldırır.', 'Fires a specialized arrow that emits a cancelling frequency. Removes all magical buffs from targets within a 10m radius.', 'Thunder', 70, 900, 4, '{"sts_sonic_boom_blast"}', '{"x": 1896, "y": 2259}', '{"utility": "dispel magic", "aoe": "10m radius"}', '📻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a2319c9f-c9c0-484a-9752-92821ed41a2e', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_cataclysmic_roar', 'Yıkıcı Kükreme', 'Cataclysmic Roar', '20m''lik bir konide 10d8 gök gürültüsü hasarı veren bir şok dalgası serbest bırakır. Yapılar ve golem benzeri yaratıklar iki kat hasar alır.', 'Unleashes a shockwave that deals 10d8 thunder damage in a 20m cone. Structures and constructs take double damage.', 'Thunder', 81, 1200, 5, '{"sts_disruptive_frequency"}', '{"x": 2056, "y": 2451}', '{"damage": "10d8 thunder", "area": "20m cone", "multiplier": "x2 vs structures"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d52fb4ee-da5b-48bc-8ee2-fbfee6e41e8f', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_sky_shatter', 'Gökyüzü Parçalayan', 'Sky Shatter', 'Nihai Yetenek. Gökyüzünü çatlatan devasa gök gürültülü bir ok fırlatır. 40m yarıçaplı bir ses dalgası indirerek 15d10 gök gürültüsü hasarı verir, herkesi yere serer ve 1 tur sersemletir.', 'Ultimate. Fires a massive thundering arrow that cracks the sky. Drops a 40m radius soundwave that deals 15d10 thunder damage, knocking everyone prone and stunning them for 1 turn.', 'Thunder', 90, 1500, 5, '{"sts_cataclysmic_roar"}', '{"x": 2217, "y": 2642}', '{"damage": "15d10 thunder", "aoe": "40m radius", "status": "prone + stun 1 turn"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d30e69a-d47d-4dbf-b014-5cded5fae0d1', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_zephyr_arrow', 'Zefir Oku', 'Zephyr Arrow', 'Rüzgar tarafından yönlendirilen, yarım ve üç çeyrek siperi yok sayan bir ok. 1d10 delici hasar verir.', 'An arrow guided by the wind, ignoring half cover and three-quarters cover. Deals 1d10 piercing damage.', 'Wind', 1, 100, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d10 piercing", "utility": "ignores cover", "range": "40m"}', '🍃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b9c371ce-b652-4cca-8b16-c526ecabc94b', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_tailwind_walk', 'Kuyruk Rüzgarı Yürüyüşü', 'Tailwind Walk', 'Rüzgar sizi arkadan iter. 3 tur boyunca hareket hızınız 5m artar ve size karşı yapılan fırsat saldırıları dezavantajlı olur.', 'The wind pushes you from behind. For 3 turns, your movement speed increases by 5m, and opportunity attacks against you have disadvantage.', 'Wind', 5, 100, 1, '{"sts_zephyr_arrow"}', '{"x": -289, "y": 344}', '{"buff": "+5m movement, disadvantage on opp. attacks", "duration": "3 turns"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55be7f69-d8ff-425e-9d8d-154a700b3bac', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_gust_push', 'Rüzgar İtişi', 'Gust Push', 'Sıkıştırılmış havadan bir ok fırlatır. 2d6 ezici hasar verir ve hedefi herhangi bir yöne 5m iter.', 'Fires an arrow of compressed air. Deals 2d6 bludgeoning damage and pushes the target 5m in any direction.', 'Wind', 10, 150, 1, '{"sts_zephyr_arrow"}', '{"x": -449, "y": 536}', '{"damage": "2d6 bludgeoning", "push": "5m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f4ae2f2b-6654-4980-86d1-ab339a54aa24', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_gale_force_shot', 'Fırtına Gücünde Atış', 'Gale Force Shot', 'Doğrusal bir fırtına yaratan bir atış. 20m''lik bir hattaki tüm düşmanlara 3d8 delici hasar verir ve gelen mermileri savuşturur.', 'A shot that creates a linear gale. Deals 3d8 piercing damage to all enemies in a 20m line and knocks away incoming projectiles.', 'Wind', 21, 250, 2, '{"sts_gust_push"}', '{"x": -610, "y": 727}', '{"damage": "3d8 piercing", "area": "20m line", "utility": "deflects projectiles"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('af39f819-0c36-487f-ac98-c4d4cc0b90e7', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_wind_wall', 'Rüzgar Duvarı', 'Wind Wall', '2 tur boyunca 10m genişliğinde bir rüzgar duvarına dönüşen bir ok atar. İçinden geçen tüm büyüsel olmayan menzilli saldırıları savuşturur.', 'Shoots an arrow that expands into a 10m wide wall of wind for 2 turns. Deflects all non-magical ranged attacks crossing it.', 'Wind', 25, 250, 2, '{"sts_tailwind_walk"}', '{"x": -771, "y": 919}', '{"utility": "blocks ranged attacks", "area": "10m wall", "duration": "2 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b701664f-8bd4-4154-bfd1-8a1ceda7ae0b', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_aerodynamic_flight', 'Aerodinamik Uçuş', 'Aerodynamic Flight', 'Kendinizi dönen rüzgarlarla çevreleyerek 3 tur boyunca 12m uçma hızı kazandırır.', 'Surrounds yourself with swirling winds, granting you a flying speed of 12m for 3 turns.', 'Wind', 30, 300, 2, '{"sts_gale_force_shot"}', '{"x": -932, "y": 1110}', '{"buff": "fly speed 12m", "duration": "3 turns"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40a54fdb-f7bd-4a05-8562-15285d714aea', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_tornado_arrow', 'Hortum Oku', 'Tornado Arrow', 'Mini bir hortum oluşturan dönen bir ok fırlatır. 5m yarıçapta 4d8 ezici hasar verir ve hedefleri havaya 3m kaldırır.', 'Fires a spinning arrow that generates a mini-tornado. Deals 4d8 bludgeoning damage in a 5m radius and lifts targets 3m into the air.', 'Wind', 41, 450, 3, '{"sts_aerodynamic_flight"}', '{"x": -1092, "y": 1302}', '{"damage": "4d8 bludgeoning", "aoe": "5m radius", "status": "lifted 3m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8f7f7347-a547-4b48-9ab7-f6d4b4c7559a', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_slipstream', 'Hava Akımı', 'Slipstream', '20m boyunca dönen bir hava yolu yaratır. Bu yolda hareket eden müttefikler iki kat hareket hızı kazanır ve zorlu araziyi yok sayar. 2 tur sürer.', 'Creates a path of swirling air for 20m. Allies moving along this path gain doubled movement speed and ignore difficult terrain. Lasts 2 turns.', 'Wind', 45, 450, 3, '{"sts_wind_wall"}', '{"x": -1253, "y": 1493}', '{"buff": "x2 movement, ignore terrain", "area": "20m line", "duration": "2 turns"}', '🛤️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2071b43d-51cb-4c66-856d-709506680438', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_razor_wind', 'Jilet Rüzgarı', 'Razor Wind', 'Üç görünmez rüzgar bıçağı fırlatır. Her biri 2d10 kesici hasar veren üç ayrı menzilli saldırı yapın.', 'Shoots three invisible wind blades. Make three separate ranged attacks, each dealing 2d10 slashing damage.', 'Wind', 50, 500, 3, '{"sts_tornado_arrow"}', '{"x": -1414, "y": 1685}', '{"damage": "3x 2d10 slashing", "attacks": "3"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40abe0cb-bb0a-44a7-bb08-46470b56d76f', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_hurricane_volley', 'Kasırga Yaylımı', 'Hurricane Volley', 'Bir kasırgaya yakalanmış düzinelerce ok fırlatır. 15m yarıçaplı bir alanı etkileyerek 6d8 delici hasar verir ve düşman hareket hızlarını yarıya indirir.', 'Fires dozens of arrows caught in a hurricane. Affects a 15m radius area, dealing 6d8 piercing damage and halving enemy movement speeds.', 'Wind', 61, 750, 4, '{"sts_razor_wind"}', '{"x": -1574, "y": 1876}', '{"damage": "6d8 piercing", "aoe": "15m radius", "debuff": "1/2 movement"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('361ba769-b109-421f-89a7-20222bfe01c0', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_vacuum_strike', 'Vakum Vuruşu', 'Vacuum Strike', 'Çarpma anında 5m yarıçaplı bir alandaki tüm havayı boşaltan bir ok. Düşmanlar 5d10 güç hasarı alır ve boğulmaya başlar, konuşamaz veya sözlü büyü yapamazlar.', 'An arrow that removes all air from a 5m radius area upon impact. Enemies take 5d10 force damage and begin suffocating, unable to speak or cast verbal spells.', 'Wind', 65, 750, 4, '{"sts_slipstream"}', '{"x": -1735, "y": 2068}', '{"damage": "5d10 force", "aoe": "5m radius", "status": "suffocating + silence"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f2a3ddb-bbd7-4d0d-8b4f-3c53245a57ed', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_cloud_runner', 'Bulut Koşucusu', 'Cloud Runner', 'Pasif. Hiçbir fiziksel iz bırakmazsınız, suda veya havada (5m yüksekliğe kadar) yürüyebilirsiniz ve tüm Çeviklik kurtarma zarlarında avantaj kazanırsınız.', 'Passive. You leave no physical tracks, can walk on water or thin air (up to 5m high), and gain advantage on all Dexterity saving throws.', 'Wind', 70, 900, 4, '{"sts_hurricane_volley"}', '{"x": -1896, "y": 2259}', '{"passive": "true", "utility": "walk on water/air, trackless", "buff": "advantage Dex saves"}', '☁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('175437af-f405-4b5d-bc8e-61f51ba219ec', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_eye_of_the_storm', 'Fırtınanın Gözü', 'Eye of the Storm', 'Kenarlarında şiddetli bir fırtına koparken etrafınızda 20m''lik sakin bir alan yaratır. Alana giren veya çıkan düşmanlar 8d10 kesici hasar alır.', 'Creates a 20m zone of calm around you while a violent storm rages on the edges. Enemies entering or leaving the zone take 8d10 slashing damage.', 'Wind', 81, 1200, 5, '{"sts_cloud_runner"}', '{"x": -2056, "y": 2451}', '{"damage": "8d10 slashing", "area": "20m radius border"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('96c2aa59-4bbe-44f6-903b-170d18aef606', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_tempest_barrage', 'Fırtına Yaylım Ateşi', 'Tempest Barrage', 'Nihai Yetenek. Havaya sıçrayarak 40m''lik devasa bir alana rüzgarla aşılanmış oklar yağdırır. 12d10 delici hasar verir ve merkezde 3 tur boyunca kalıcı bir hortum tehlikesi yaratır.', 'Ultimate. Leaps into the air, raining down wind-infused arrows over a massive 40m area. Deals 12d10 piercing damage and permanently creates a tornado hazard in the center for 3 turns.', 'Wind', 90, 1500, 5, '{"sts_eye_of_the_storm"}', '{"x": -2217, "y": 2642}', '{"damage": "12d10 piercing", "aoe": "40m radius", "hazard": "tornado for 3 turns"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fbcbc1a5-3316-4323-868e-5504bd036bc4', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_thunderstorm_shot', 'Gök Gürültülü Fırtına Atışı', 'Thunderstorm Shot', 'Yıldırım ve gök gürültüsünü birleştirir. 3d6 yıldırım ve 3d6 gök gürültüsü hasarı veren ve hedefi 1 tur sersemleten bir ok fırlatır.', 'Combines lightning and thunder. Fires an arrow that deals 3d6 lightning and 3d6 thunder damage, stunning the target for 1 turn.', 'Cross-Branch', 35, 300, 2, '{"sts_chain_lightning_arrow", "sts_resonance_wave"}', '{"x": -173, "y": -100}', '{"damage": "3d6 lightning + 3d6 thunder", "status": "stun 1 turn"}', '🌩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a98177b3-e599-459d-ad86-53bfe340ccb2', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_electric_gale', 'Elektrikli Fırtına', 'Electric Gale', 'Yıldırım ve rüzgarı birleştirir. 10m genişliğinde elektrikli bir hortum yaratan, 4d8 yıldırım ve 4d8 kesici hasar veren bir ok atar.', 'Combines lightning and wind. Shoots an arrow that creates a 10m wide electrified tornado, dealing 4d8 lightning and 4d8 slashing damage.', 'Cross-Branch', 55, 500, 3, '{"sts_storm_step", "sts_slipstream"}', '{"x": -389, "y": -225}', '{"damage": "4d8 lightning + 4d8 slashing", "aoe": "10m tornado"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d94a514f-f360-40b4-ad73-1894f134e2db', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_sonic_wind', 'Sonik Rüzgar', 'Sonic Wind', 'Gök gürültüsü ve rüzgarı birleştirir. Sarsıcı bir patlama taşıyan hızlı bir rüzgar esintisi gönderir. 25m''lik bir hatta 5d8 gök gürültüsü hasarı verir ve herkesi 10m geriye iter.', 'Combines thunder and wind. Sends a fast gust of wind that carries a concussive blast. Deals 5d8 thunder damage in a 25m line, pushing everyone back 10m.', 'Cross-Branch', 55, 500, 3, '{"sts_thundercrash", "sts_tornado_arrow"}', '{"x": -606, "y": -350}', '{"damage": "5d8 thunder", "area": "25m line", "push": "10m"}', '🔊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d733105-a49a-4474-9323-cefbc1e63ef4', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_supercell_trap', 'Süper Hücre Tuzağı', 'Supercell Trap', 'Yerel bir süper hücre eken usta işi bir tuzak. Tetiklendiğinde 15m yarıçaplı bir alanı 8d8 yıldırım ve 8d8 gök gürültüsü hasarıyla patlatır, geriye kalıcı bir fırtına bulutu bırakır.', 'A master trap that seeds a localized supercell. When triggered, it blasts a 15m radius with 8d8 lightning and 8d8 thunder damage, leaving a lingering storm cloud.', 'Cross-Branch', 75, 900, 4, '{"sts_lightning_rod", "sts_mjolnirs_impact"}', '{"x": -822, "y": -475}', '{"damage": "8d8 lightning + 8d8 thunder", "aoe": "15m radius"}', '⛈️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b952e1f2-bb96-4797-81c9-232501402ac4', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_stormriders_vault', 'Fırtına Binicisinin Atlayışı', 'Stormrider''s Vault', 'Rüzgarı kullanarak 30m havaya sıçrar, ardından bir yıldırım çarpmasıyla yere inersiniz. İnişte 15m yarıçapta 10d8 yıldırım ve gök gürültüsü hasarı verir.', 'You vault 30m into the air using wind, then crash down with a lightning strike. Deals 10d8 lightning and thunder damage in a 15m radius upon landing.', 'Cross-Branch', 75, 900, 4, '{"sts_thundergods_bolt", "sts_cloud_runner"}', '{"x": -1039, "y": -600}', '{"movement": "30m jump", "damage": "10d8 lightning/thunder", "aoe": "15m radius"}', '🤸‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('70a8e4f9-0137-40de-b75a-649bdbfc9165', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_plasma_cyclone', 'Plazma Siklonu', 'Plasma Cyclone', 'Aşırı ısınmış plazmadan oluşan bir siklon yaratan bir ok fırlatır. 20m içindeki düşmanları merkeze çekerek 10d10 yıldırım/ateş hasarı verir.', 'Fires an arrow that spawns a cyclone of superheated plasma. Pulls enemies within 20m toward the center, dealing 10d10 lightning/fire damage.', 'Cross-Branch', 85, 1200, 5, '{"sts_wrath_of_the_storm", "sts_eye_of_the_storm"}', '{"x": -1255, "y": -725}', '{"damage": "10d10 lightning/fire", "aoe": "20m radius pull"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1f61e2a5-a89b-445f-bdfd-2616e6914f64', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_roaring_typhoon', 'Kükreyen Tayfun', 'Roaring Typhoon', 'Hedeflenen bir noktayı merkez alan devasa bir kasırga yaratır. 3 tur boyunca 30m''lik alanın içindeki herkese 10d8 gök gürültüsü ve 10d8 ezici hasar verir.', 'Creates a massive hurricane centered on a targeted point. For 3 turns, it deals 10d8 thunder damage and 10d8 bludgeoning damage to anyone inside the 30m area.', 'Cross-Branch', 85, 1200, 5, '{"sts_cataclysmic_roar", "sts_eye_of_the_storm"}', '{"x": -1472, "y": -850}', '{"damage": "10d8 thunder + 10d8 bludgeoning/turn", "aoe": "30m radius", "duration": "3 turns"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6bda517f-38b4-4d2f-bd48-cf7d94542eab', 'c07d7bb7-58ea-4482-b353-a32427fda6c2', 'sts_aspect_of_the_storm', 'Fırtınanın Sureti', 'Aspect of the Storm', 'Görkemli Nihai Yetenek. Fırtınanın canlı bir tezahürü olursunuz. 1 dakika boyunca 20m uçma hızı, yıldırım ve gök gürültüsü hasarına bağışıklık kazanırsınız ve yay saldırılarınız fazladan 3d10 yıldırım, 3d10 gök gürültüsü ve 3d10 delici hasar verir. Her atış mini bir sonik patlamaya neden olur.', 'Grand Ultimate. You become the living embodiment of the storm. For 1 minute, you gain flying speed 20m, immunity to lightning and thunder damage, and your bow attacks deal an extra 3d10 lightning, 3d10 thunder, and 3d10 piercing damage. Every shot causes a miniature sonic boom.', 'Cross-Branch', 100, 1500, 5, '{"sts_raijins_judgment", "sts_sky_shatter", "sts_tempest_barrage"}', '{"x": -1688, "y": -975}', '{"buff": "fly 20m, immune lightning/thunder", "damage_bonus": "3d10 lightning + 3d10 thunder + 3d10 piercing", "duration": "1 minute"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('23af5464-8c81-4aab-a648-1b8db87f3aeb', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_telekinetic_thrust', 'Telekinetik İtiş', 'Telekinetic Thrust', 'Telekinetik olarak kontrol edilen bir kılıcı düşmana sapla, 15m menzilde 1d8 kesici ve 1d4 güç hasarı ver.', 'Thrust a telekinetically controlled sword at an enemy, dealing 1d8 slashing and 1d4 force damage at 15m range.', 'Telekinetic Blade', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8+1d4", "damage_type": "slashing+force", "range": "15m"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d810fb8a-9069-47d6-80e5-3adefff9c5f9', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_dancing_blade', 'Dans Eden Kılıç', 'Dancing Blade', 'Bir kılıcı bağımsız olarak süzülüp saldırması için canlandır, 3 tur boyunca her tur 1d6 kesici hasar ver.', 'Animate a sword to hover and attack independently, dealing 1d6 slashing damage per turn for 3 turns.', 'Telekinetic Blade', 5, 75, 1, '{"ss_telekinetic_thrust"}', '{"x": 389, "y": -224}', '{"damage": "1d6", "damage_type": "slashing", "duration": "3 turns", "per_turn": true}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('efc8d420-18da-4ae3-b18a-1ccc6fc4a685', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_returning_edge', 'Dönen Kenar', 'Returning Edge', '2d6 kesici hasar verip geri dönen bir kılıç fırlat, bir sonraki turuna kadar +2 AC kazan.', 'Throw a sword that strikes for 2d6 slashing damage and returns, granting +2 AC until your next turn.', 'Telekinetic Blade', 10, 100, 1, '{"ss_dancing_blade"}', '{"x": 606, "y": -349}', '{"damage": "2d6", "damage_type": "slashing", "ac_bonus": 2, "duration": "1 turn"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6166fdfa-081e-4e1f-a628-7fd6bbf6dbec', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_blade_sweep', 'Kılıç Süpürmesi', 'Blade Sweep', 'Kılıçlarını 3m genişliğinde bir yay çizecek şekilde savur, içindeki tüm düşmanlara 2d8 kesici hasar ver.', 'Sweep your swords in a 3m wide arc, dealing 2d8 slashing damage to all enemies caught within.', 'Telekinetic Blade', 15, 125, 1, '{"ss_returning_edge"}', '{"x": 822, "y": -474}', '{"damage": "2d8", "damage_type": "slashing", "aoe": "3m arc"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eaf7eaee-34ba-4aad-aada-01c4681f7db9', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_twin_strike', 'İkiz Vuruş', 'Twin Strike', 'Aynı anda iki kılıç fırlat, her biri 2d6 kesici hasar verir. İki farklı düşmanı hedef alabilir.', 'Launch two swords simultaneously, dealing 2d6 slashing damage each. Can target up to two different enemies.', 'Telekinetic Blade', 22, 175, 2, '{"ss_blade_sweep"}', '{"x": 1039, "y": -599}', '{"damage": "2d6", "attacks": 2, "damage_type": "slashing", "multi_target": true}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf6b2d2d-d36c-4c66-8c5d-bc2bb3c6d68d', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_hovering_guard', 'Süzülen Koruma', 'Hovering Guard', 'Kılıçlarına gelen saldırıları aktif olarak savuşturmasını emret, 2 tur boyunca alınan fiziksel hasarı %30 azalt.', 'Command your swords to actively parry incoming attacks, reducing physical damage taken by 30% for 2 turns.', 'Telekinetic Blade', 28, 200, 2, '{"ss_twin_strike"}', '{"x": 1255, "y": -724}', '{"physical_damage_reduction": "30%", "duration": "2 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('956354f8-9b00-4cf4-9b9a-5bde2a17555c', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_piercing_flight', 'Delici Uçuş', 'Piercing Flight', '10m düz bir çizgide uçan bir kılıç gönder, vurulan tüm hedeflerin 2 AC''sini yok sayarak 3d8 delici hasar ver.', 'Send a sword flying in a 10m straight line, dealing 3d8 piercing damage and ignoring 2 AC of all targets hit.', 'Telekinetic Blade', 34, 250, 2, '{"ss_hovering_guard"}', '{"x": 1472, "y": -849}', '{"damage": "3d8", "damage_type": "piercing", "aoe": "10m line", "armor_penetration": 2}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b544f221-975e-40c6-ab8c-ee7fab7d6dd1', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_blade_storm', 'Kılıç Fırtınası', 'Blade Storm', 'Kılıçlarını 6m yarıçapında bir çılgınlığa sürükle, içerideki tüm düşmanlara 4d6 kesici hasar ver.', 'Whip your swords into a frenzy in a 6m radius, dealing 4d6 slashing damage to all enemies inside.', 'Telekinetic Blade', 38, 300, 2, '{"ss_piercing_flight"}', '{"x": 1688, "y": -974}', '{"damage": "4d6", "damage_type": "slashing", "aoe": "6m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('395a95b0-bf87-4705-aa93-1d4e78b2316b', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_phantom_swords', 'Hayalet Kılıçlar', 'Phantom Swords', '6 kılıcının kinetik kopyalarını yarat ve hepsini fırlatarak 4d8 güç hasarı ver.', 'Create kinetic duplicates of your 6 swords, launching them all to deal 4d8 force damage.', 'Telekinetic Blade', 42, 350, 3, '{"ss_blade_storm"}', '{"x": 1905, "y": -1099}', '{"damage": "4d8", "damage_type": "force"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a9eec127-5add-49a6-9f61-ac3acf0e88fc', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_relentless_pursuit', 'Amansız Takip', 'Relentless Pursuit', 'Bir hedefi işaretle. Kılıçların onları amansızca takip eder, 3 tur boyunca hedefin turunun başında 2d6 hasar verir.', 'Mark a target. Your swords relentlessly pursue them, dealing 2d6 damage at the start of their turn for 3 turns.', 'Telekinetic Blade', 50, 400, 3, '{"ss_phantom_swords"}', '{"x": 2121, "y": -1224}', '{"damage": "2d6", "duration": "3 turns", "trigger": "start_of_turn"}', '🦅');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40e0605b-f666-4e29-b5fc-55622295c6f5', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_sword_rain', 'Kılıç Yağmuru', 'Sword Rain', '10m''lik bir alana telekinetik kılıçlar yağdır, 5d8 hasar ver ve hedefleri 1 tur sabitle.', 'Shower a 10m area with telekinetic blades, dealing 5d8 damage and rooting targets for 1 turn.', 'Telekinetic Blade', 58, 450, 3, '{"ss_relentless_pursuit"}', '{"x": 2338, "y": -1349}', '{"damage": "5d8", "aoe": "10m", "root": "1 turn"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6e80a2ec-e232-4a65-ae6a-0a0de320cae8', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_six_fold_slash', 'Altı Katlı Kesik', 'Six-Fold Slash', 'Tüm kılıçlarınla tek bir hedefe hızlıca 6 vuruşluk bir dizi gerçekleştir, her biri 2d8 kesici hasar verir.', 'Execute a rapid sequence of 6 strikes with all your swords, each dealing 2d8 slashing damage to a single target.', 'Telekinetic Blade', 64, 600, 4, '{"ss_sword_rain"}', '{"x": 2554, "y": -1474}', '{"damage": "2d8", "attacks": 6, "damage_type": "slashing"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('22b3765e-832a-473f-b80a-bcbf3d78ea0d', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_meteor_blade', 'Meteor Kılıcı', 'Meteor Blade', '6 kılıcın kinetik gücünü devasa bir tepeden vuruşta birleştir, 8d10 güç hasarı ver.', 'Combine the kinetic force of all 6 swords into one massive overhead strike, dealing 8d10 force damage.', 'Telekinetic Blade', 72, 750, 4, '{"ss_six_fold_slash"}', '{"x": 2771, "y": -1599}', '{"damage": "8d10", "damage_type": "force"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cca8879f-a1f1-4d23-82c4-8c4527f63bb6', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_telekinetic_mastery', 'Telekinetik Ustalık', 'Telekinetic Mastery', 'Telekineziyi ustalaştır. Tüm Telekinetik Kılıç büyüleri kalıcı olarak %30 daha fazla hasar verir ve +10m menzil kazanır.', 'Master telekinesis. All Telekinetic Blade spells permanently deal 30% more damage and gain +10m range.', 'Telekinetic Blade', 78, 900, 4, '{"ss_meteor_blade"}', '{"x": 2987, "y": -1724}', '{"passive": true, "telekinetic_damage_bonus": "30%", "range_bonus": "10m"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b509c1a2-6dc2-4f94-a29a-5c48ae22d1de', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_omni_blade', 'Her Yerdeki Kılıç', 'Omni-Blade', 'NİHAİ: Mutlak telekinetik kontrolü serbest bırak. 6 kılıcın hepsi 20m yarıçapındaki her şeye saldırarak 12d12 kesici ve güç hasarı verir, hedefleri 1 tur sersemletir.', 'ULTIMATE: Unleash absolute telekinetic control. All 6 swords attack everything in a 20m radius, dealing 12d12 slashing and force damage, stunning targets for 1 turn.', 'Telekinetic Blade', 92, 1200, 5, '{"ss_telekinetic_mastery"}', '{"x": 3204, "y": -1849}', '{"damage": "12d12", "damage_type": "slashing+force", "aoe": "20m", "stun": "1 turn"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bfa15811-798e-41ec-ab7b-dc15de3e4231', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_basic_array', 'Temel Dizilim', 'Basic Array', '3m''lik savunma alanı yaratmak için 2 kılıç sapla. İçerdeki müttefikler 3 tur boyunca +2 AC kazanır.', 'Plant 2 swords to create a 3m defensive zone. Allies within gain +2 AC for 3 turns.', 'Sword Formation', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"aoe": "3m", "ac_bonus": 2, "duration": "3 turns"}', '🔺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0a9f1e7-59b4-4e75-aeeb-5791b9fd0749', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_shield_formation', 'Kalkan Dizilimi', 'Shield Formation', '4 kılıçla koruyucu bir duvar oluştur, gelen 15 puanlık hasarı emen bir kalkan kazandır.', 'Form a protective wall with 4 swords, granting a shield that absorbs 15 points of incoming damage.', 'Sword Formation', 6, 75, 1, '{"ss_basic_array"}', '{"x": 289, "y": 344}', '{"shield": 15}', '🔰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cffbcabc-f545-47d5-a857-79ccf3a9d6f4', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_pinning_swords', 'Sabitleyici Kılıçlar', 'Pinning Swords', 'Bir hedefin gölgesini 2 kılıçla sabitle, hareket hızını 2 tur boyunca 4m azalt.', 'Pin a target''s shadow with 2 swords, reducing their movement speed by 4m for 2 turns.', 'Sword Formation', 12, 100, 1, '{"ss_shield_formation"}', '{"x": 449, "y": 536}', '{"movement_penalty": "4m", "duration": "2 turns"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('49ee5af8-b06e-4210-8955-2adb6a414ca5', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_blade_barrier', 'Kılıç Bariyeri', 'Blade Barrier', 'Dönen kılıçlardan 5m''lik bir duvar yarat. İçinden geçen her yaratık 3d6 kesici hasar alır.', 'Create a 5m wall of spinning blades. Any creature passing through takes 3d6 slashing damage.', 'Sword Formation', 18, 125, 1, '{"ss_pinning_swords"}', '{"x": 610, "y": 727}', '{"damage": "3d6", "damage_type": "slashing", "wall_length": "5m"}', '🚧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('846d517c-8575-4b2c-87b0-012aee4a3095', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_imprisoning_array', 'Hapseden Dizilim', 'Imprisoning Array', 'Bir hedefi 4 kılıçlı dizilimin içine hapset, 2 tur sabitle. Herhangi bir eylem yapması ona 2d6 hasar verir.', 'Trap a target inside a 4-sword array, rooting them for 2 turns. Taking any action deals them 2d6 damage.', 'Sword Formation', 24, 175, 2, '{"ss_blade_barrier"}', '{"x": 771, "y": 919}', '{"root": "2 turns", "action_damage": "2d6"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e56531c-228e-4b84-974c-63ff7fe1abc0', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_triangular_lock', 'Üçgen Kilit', 'Triangular Lock', '3 kılıçlı üçgen bir alan oluştur. İçerideki düşmanlar kaldıkları sürece tüm istatistiklerine -2 cezası alır.', 'Form a 3-sword triangular zone. Enemies inside suffer a -2 penalty to all stats while they remain.', 'Sword Formation', 30, 225, 2, '{"ss_imprisoning_array"}', '{"x": 932, "y": 1110}', '{"aoe": "triangle", "stat_penalty": -2}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7984219e-49fc-4b34-8ec8-efa4b0486ab3', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_rotating_defense', 'Dönen Savunma', 'Rotating Defense', '6 kılıcın tamamını etrafında hızla döndür, 2 tur boyunca mermi hasarının %50''sini saldıranlara geri yansıt.', 'Make all 6 swords rotate around you rapidly, reflecting 50% of projectile damage back to attackers for 2 turns.', 'Sword Formation', 35, 275, 2, '{"ss_triangular_lock"}', '{"x": 1092, "y": 1302}', '{"projectile_reflect": "50%", "duration": "2 turns"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d1a727f0-0579-44e2-8085-198bff65ea8b', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_hexagonal_prison', 'Altıgen Hapishane', 'Hexagonal Prison', 'Bir alanı 6 kılıçlı altıgen bir kafese al. Girmek veya çıkmak 4d8 hasar verir ve ışınlanmayı engeller.', 'Enclose an area in a 6-sword hexagonal cage. Entering or exiting deals 4d8 damage, and blocks teleportation.', 'Sword Formation', 40, 300, 2, '{"ss_rotating_defense"}', '{"x": 1253, "y": 1493}', '{"aoe": "hexagon", "barrier_damage": "4d8", "block_teleport": true}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eb9259ce-5dcb-4288-be0c-4a173ba92251', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_crushing_array', 'Ezen Dizilim', 'Crushing Array', 'Kılıç dizilimini şiddetle sıkıştır, 5m yarıçapındaki tüm düşmanlara 5d10 ezici hasar ver.', 'Compress a sword formation violently, dealing 5d10 bludgeoning damage to all enemies in a 5m radius.', 'Sword Formation', 45, 350, 3, '{"ss_hexagonal_prison"}', '{"x": 1414, "y": 1685}', '{"damage": "5d10", "damage_type": "bludgeoning", "aoe": "5m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7418987a-6700-46c5-96e6-b952ff43a022', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_sentinel_domain', 'Nöbetçi Alanı', 'Sentinel Domain', 'Dizilimini 15m''lik bir auraya genişlet. Müttefikler +4 AC kazanır ve düşmanlar tur başına 1d8 kesici hasar alır.', 'Expand your array to a 15m aura. Allies gain +4 AC, and enemies take 1d8 slashing damage per turn.', 'Sword Formation', 52, 400, 3, '{"ss_crushing_array"}', '{"x": 1574, "y": 1876}', '{"aoe": "15m aura", "ally_ac_bonus": 4, "enemy_damage": "1d8", "per_turn": true}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('53a75e6d-f444-4e94-ba24-52afa8d4ce04', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_blade_vortex', 'Kılıç Girdabı', 'Blade Vortex', 'Kılıçlarınla çeken bir girdap yarat. 10m içindeki düşmanlar merkeze çekilir, 4d8 hasar alır ve yavaşlar.', 'Create a pulling vortex with your swords. Enemies within 10m are pulled to the center, taking 4d8 damage and getting slowed.', 'Sword Formation', 60, 450, 3, '{"ss_sentinel_domain"}', '{"x": 1735, "y": 2068}', '{"aoe": "10m", "pull": true, "damage": "4d8", "slow": true}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8cd4f62-1855-4f23-9cc5-7c0bcf558be0', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_absolute_defense', 'Mutlak Savunma', 'Absolute Defense', '6 kılıcınla kusursuz bir kubbe oluştur, 1 tur boyunca tüm saldırılara karşı tamamen bağışık ol.', 'Form a flawless dome with your 6 swords, becoming completely immune to all attacks for 1 turn.', 'Sword Formation', 66, 650, 4, '{"ss_blade_vortex"}', '{"x": 1896, "y": 2259}', '{"immunity": "all", "duration": "1 turn"}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7640e848-c5f8-46bc-a60e-57bded4b8a47', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_annihilation_formation', 'Yok Oluş Dizilimi', 'Annihilation Formation', '6 kılıçlı dizilimine aşırı yükleme yaparak patlat, 10m yarıçapında 10d10 güç hasarı ver.', 'Overcharge your 6-sword array to detonate, dealing 10d10 force damage in a 10m radius.', 'Sword Formation', 74, 800, 4, '{"ss_absolute_defense"}', '{"x": 2056, "y": 2451}', '{"damage": "10d10", "damage_type": "force", "aoe": "10m"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('217249b4-2bb9-45f6-bd61-1080cb3caead', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_formation_mastery', 'Dizilim Ustalığı', 'Formation Mastery', 'Kılıç dizilimlerini ustalaştır. Dizilimler %25 daha az mana harcar, yarıçapı 3m ve süresi 1 tur artar.', 'Master sword arrays. Formations cost 25% less mana, radius is increased by 3m, and duration by 1 turn.', 'Sword Formation', 80, 900, 4, '{"ss_annihilation_formation"}', '{"x": 2217, "y": 2642}', '{"passive": true, "mana_cost_reduction": "25%", "radius_bonus": "3m", "duration_bonus": 1}', '🏗️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('99f043b7-ea26-49db-b717-d2d3306f0793', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_heavenly_sword_array', 'Göksel Kılıç Dizilimi', 'Heavenly Sword Array', 'NİHAİ: İlahi 30m''lik bir kılıç dizilimi kur. İçerdeki müttefikler yenilmez olurken, düşmanlar 3 tur boyunca tur başına 6d12 gerçek hasar alır.', 'ULTIMATE: Establish a divine 30m sword array. Allies inside are invincible, while enemies take 6d12 true damage per turn for 3 turns.', 'Sword Formation', 95, 1250, 5, '{"ss_formation_mastery"}', '{"x": 2378, "y": 2834}', '{"aoe": "30m", "ally_invincibility": true, "enemy_damage": "6d12", "damage_type": "true", "per_turn": true, "duration": "3 turns"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a34ff163-84ac-49fb-9eca-79e43d499a5d', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_psychic_edge', 'Psişik Kenar', 'Psychic Edge', 'Kılıçlarına psişik enerji aşıla. Sonraki 3 vuruşun fazladan 1d6 psişik hasar verir ve hedefin INT''ini 1 azaltır.', 'Infuse your blades with psychic energy. Your next 3 strikes deal an additional 1d6 psychic damage and reduce target INT by 1.', 'Mind Edge', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"buff_attacks": 3, "bonus_damage": "1d6", "damage_type": "psychic", "int_penalty": 1}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d1dcd01d-4b22-4d49-93dd-5b16d223fcb6', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_mind_link', 'Zihin Bağı', 'Mind Link', 'Bir kılıçla zihinsel bağ kurarak onun perspektifinden görmeni ve 20m uzağa kadar hassasça kontrol etmeni sağla.', 'Forge a mental link with a sword, allowing you to see through its perspective and control it precisely up to 20m away.', 'Mind Edge', 8, 75, 1, '{"ss_psychic_edge"}', '{"x": -289, "y": 344}', '{"remote_vision": true, "control_range": "20m"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9581ec6f-55a5-4ab7-90bc-5287ccb4c3f4', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_fear_blade', 'Korku Kılıcı', 'Fear Blade', 'Düşmanın zihnine dehşetle vur. 2d6 psişik hasar verir ve 1 tur Korku uygular.', 'Strike an enemy''s mind with terror. Deals 2d6 psychic damage and applies Fear for 1 turn.', 'Mind Edge', 14, 100, 1, '{"ss_mind_link"}', '{"x": -449, "y": 536}', '{"damage": "2d6", "damage_type": "psychic", "fear": "1 turn"}', '😱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('874be33b-24d8-4897-a163-689005604b4f', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_telepathic_strike', 'Telepatik Vuruş', 'Telepathic Strike', 'Fiziksel zırhı tamamen aşarak doğrudan hedefin zihnine vur, 15m menzilde 2d8 psişik hasar ver.', 'Bypass physical armor entirely to strike the target''s mind directly, dealing 2d8 psychic damage at 15m range.', 'Mind Edge', 20, 125, 1, '{"ss_fear_blade"}', '{"x": -610, "y": 727}', '{"damage": "2d8", "damage_type": "psychic", "armor_penetration": "infinite", "range": "15m"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c11f013e-77fc-4d4b-a6ab-06b6b4e0a003', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_illusionary_swords', 'İllüzyon Kılıçlar', 'Illusionary Swords', 'Kılıçlarının değişken psişik illüzyonlarını yarat. Sana saldıran düşmanlar 3 tur boyunca -3 isabet cezası alır.', 'Create shifting psychic illusions of your swords. Enemies attacking you suffer a -3 accuracy penalty for 3 turns.', 'Mind Edge', 25, 175, 2, '{"ss_telepathic_strike"}', '{"x": -771, "y": 919}', '{"enemy_accuracy_penalty": 3, "duration": "3 turns"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1d86dec2-e607-451e-880b-e309c617ab61', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_mental_parry', 'Zihinsel Savuşturma', 'Mental Parry', 'Bağlı kılıçlarını zihinsel müdahaleleri savuşturmak için kullan, 3 tur boyunca çekicilik, korku ve karmaşaya bağışık ol.', 'Use your connected blades to parry mental intrusions, rendering you immune to charm, fear, and confusion for 3 turns.', 'Mind Edge', 32, 225, 2, '{"ss_illusionary_swords"}', '{"x": -932, "y": 1110}', '{"immunity": "charm, fear, confusion", "duration": "3 turns"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('755f9895-5ae0-4b70-aaa7-004fd30d2484', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_soul_slash', 'Ruh Kesiği', 'Soul Slash', 'Hedefin ruhunu kes. 3d8 psişik hasar verir ve maksimum manasını %10 düşürür.', 'Slice the target''s spirit. Deals 3d8 psychic damage and lowers their maximum mana by 10%.', 'Mind Edge', 36, 275, 2, '{"ss_mental_parry"}', '{"x": -1092, "y": 1302}', '{"damage": "3d8", "damage_type": "psychic", "max_mana_reduction": "10%"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d67a6f4e-517f-4e17-b199-b8b550eab916', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_confusion_edge', 'Karmaşa Kenarı', 'Confusion Edge', 'Hedefin düşüncelerini karıştır. 3d6 psişik hasar verir ve 1 tur boyunca kafasını karıştırır (rastgele hedeflere saldırır).', 'Scramble the target''s thoughts. Deals 3d6 psychic damage and confuses them (attacks random targets) for 1 turn.', 'Mind Edge', 40, 300, 2, '{"ss_soul_slash"}', '{"x": -1253, "y": 1493}', '{"damage": "3d6", "damage_type": "psychic", "confusion": "1 turn"}', '😵');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('96d63e2e-c871-4d26-b203-5e19ef663de9', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_willpower_blade', 'İrade Kılıcı', 'Willpower Blade', 'Saf iradeni kılıçların aracılığıyla tezahür ettir, yıkıcı bir vuruşla 5d8 psişik hasar ver.', 'Manifest your pure willpower through your swords, dealing 5d8 psychic damage in a devastating strike.', 'Mind Edge', 48, 350, 3, '{"ss_confusion_edge"}', '{"x": -1414, "y": 1685}', '{"damage": "5d8", "damage_type": "psychic"}', '✊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2cd8c780-2de1-4286-9951-78e33d98dfbd', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_psychic_resonance', 'Psişik Rezonans', 'Psychic Resonance', 'Kılıçlarının psişik frekansla titreşmesini sağla, AoE alanında 4d8 psişik hasar ver ve hedefleri 2 tur sustur.', 'Cause your swords to vibrate with psychic frequency, dealing 4d8 psychic damage in an AoE and silencing targets for 2 turns.', 'Mind Edge', 55, 400, 3, '{"ss_willpower_blade"}', '{"x": -1574, "y": 1876}', '{"damage": "4d8", "damage_type": "psychic", "aoe": true, "silence": "2 turns"}', '🔊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ff538dc8-26e6-4938-9b0f-3e6b9f13dc24', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_mind_shatter', 'Zihin Parçalama', 'Mind Shatter', 'Hedefin konsantrasyonunu parçala. 6d8 psişik hasar verir ve yaptıkları son büyüyü 3 tur unutmalarına neden olur.', 'Shatter the target''s concentration. Deals 6d8 psychic damage and forces them to forget the last spell they cast for 3 turns.', 'Mind Edge', 60, 450, 3, '{"ss_psychic_resonance"}', '{"x": -1735, "y": 2068}', '{"damage": "6d8", "damage_type": "psychic", "spell_lock": "last cast, 3 turns"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f783c4a3-b6bb-49be-8eda-7d7bae68e6d1', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_ethereal_strike', 'Ruhani Vuruş', 'Ethereal Strike', 'Vurmadan önce kılıçlarını ruhani düzleme geçir, tüm kalkanları ve bariyerleri aşan 8d8 psişik hasar ver.', 'Shift your swords to the ethereal plane before striking, dealing 8d8 psychic damage that bypasses all shields and barriers.', 'Mind Edge', 68, 600, 4, '{"ss_mind_shatter"}', '{"x": -1896, "y": 2259}', '{"damage": "8d8", "damage_type": "psychic", "bypasses_shields": true}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3a268fbe-8a6b-4306-b21d-58624e3a92e7', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_ego_death', 'Ego Ölümü', 'Ego Death', 'Hedefin benlik duygusunu yok et. 6d10 psişik hasar verir ve onları 2 tur felç eder.', 'Destroy the target''s sense of self. Deals 6d10 psychic damage and paralyzes them for 2 turns.', 'Mind Edge', 75, 750, 4, '{"ss_ethereal_strike"}', '{"x": -2056, "y": 2451}', '{"damage": "6d10", "damage_type": "psychic", "paralyze": "2 turns"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8103b06e-0b03-4405-a7b6-0b45fcf828ef', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_mind_edge_mastery', 'Zihin Kenarı Ustalığı', 'Mind Edge Mastery', 'Zihin kenarını ustalaştır. Psişik büyülerin +%20 zırh delme kazanır ve verilen psişik hasarın %15''i kadar mananı iyileştirirsin.', 'Master the mind edge. Your psychic spells gain +20% armor penetration, and you heal your mana for 15% of psychic damage dealt.', 'Mind Edge', 80, 900, 4, '{"ss_ego_death"}', '{"x": -2217, "y": 2642}', '{"passive": true, "armor_penetration_bonus": "20%", "mana_lifesteal": "15%"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1be60834-2322-435d-a24d-acd44d078ce5', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_blade_of_consciousness', 'Bilinç Kılıcı', 'Blade of Consciousness', 'NİHAİ: 6 kılıcını saf düşünceye dönüştür. 15d10 psişik hasar ver, hedefin maksimum manasının %50''sini çek ve onları 2 tur büyüle.', 'ULTIMATE: Transform your 6 swords into pure thought. Deal 15d10 psychic damage, drain 50% of target''s max mana, and charm them for 2 turns.', 'Mind Edge', 98, 1300, 5, '{"ss_mind_edge_mastery"}', '{"x": -2378, "y": 2834}', '{"damage": "15d10", "damage_type": "psychic", "mana_drain": "50%", "charm": "2 turns"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('629ba478-2e21-4e72-8df6-4832af745db0', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_kinetic_array', 'Kinetik Dizilim', 'Kinetic Array', 'Çapraz Dal: Telekinezi ve Dizilimi birleştir. Hareketli bir kılıç dizilimi etrafında döner, 3 tur boyunca yakındaki düşmanlara otomatik olarak 4d6 hasar verir.', 'Cross-Branch: Combine Telekinesis and Formation. A mobile sword array orbits you, dealing 4d6 damage to nearby enemies automatically for 3 turns.', 'Cross-Branch', 50, 450, 3, '{"ss_phantom_swords", "ss_crushing_array"}', '{"x": -173, "y": -100}', '{"mobile_aoe": true, "damage": "4d6", "duration": "3 turns", "auto_attack": true}', '⚙️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('52435ac0-dda3-4496-b049-3fa9da4449f2', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_psychic_storm', 'Psişik Fırtına', 'Psychic Storm', 'Çapraz Dal: Telekinezi ve Zihin Kenarını birleştir. 10m yarıçapında 5d6 fiziksel ve 5d6 psişik hasar veren bir kılıç fırtınası yağdır.', 'Cross-Branch: Combine Telekinesis and Mind Edge. Rain down a storm of blades dealing 5d6 physical and 5d6 psychic damage in a 10m radius.', 'Cross-Branch', 55, 500, 3, '{"ss_phantom_swords", "ss_willpower_blade"}', '{"x": -389, "y": -225}', '{"damage": "5d6+5d6", "damage_type": "physical+psychic", "aoe": "10m"}', '⛈️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d72490b7-b835-418a-a7a2-c6eb83d2ecc3', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_mind_prison', 'Zihin Hapishanesi', 'Mind Prison', 'Çapraz Dal: Dizilim ve Zihin Kenarını birleştir. Hedefin bedenini ve zihnini hapset, 2 tur sürgün et ve psişik hasar olarak %10 maksimum HP çek.', 'Cross-Branch: Combine Formation and Mind Edge. Trap a target''s body and mind, banishing them for 2 turns and draining 10% max HP as psychic damage.', 'Cross-Branch', 60, 500, 3, '{"ss_crushing_array", "ss_willpower_blade"}', '{"x": -606, "y": -350}', '{"banish": "2 turns", "drain": "10% max HP", "damage_type": "psychic"}', '🔲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb12e335-68ed-4447-a203-fecf100c94d8', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_perfect_harmony', 'Kusursuz Uyum', 'Perfect Harmony', 'Çapraz Dal Pasif: Kusursuz dengeye ulaş. Aktif bir dizilime sahip olmak telekinetik hasarını %20 artırır ve tüm kılıç vuruşları düşman hareketini 1m azaltır.', 'Cross-Branch Passive: Achieve perfect balance. Having an active formation boosts your telekinetic damage by 20%, and all sword strikes reduce enemy movement by 1m.', 'Cross-Branch', 90, 1000, 5, '{"ss_telekinetic_mastery", "ss_formation_mastery", "ss_mind_edge_mastery"}', '{"x": -822, "y": -475}', '{"passive": true, "telekinetic_damage_bonus": "20%", "on_hit": "reduce_movement_1m"}', '☯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('147c5fe3-b5b6-4414-898a-2bab02b9c048', '4919f48b-b5cd-4551-909c-27f05702c9d4', 'ss_sword_gods_domain', 'Kılıç Tanrısının Alanı', 'Sword God''s Domain', 'BÜYÜK NİHAİ: 3 dal nihaisi gerektirir. 30m''de 20d12 birleşik (Kesici/Güç/Psişik) hasar ver. Tüm düşmanlar 3 tur boyunca sabitlenir, susturulur ve silahsızlandırılır. Savaş boyunca kalıcı olarak 6 ekstra hayalet kılıç kazanırsın.', 'GRAND ULTIMATE: Requires all 3 branch ultimates. Deal 20d12 combined (Slashing/Force/Psychic) damage in 30m. All enemies are rooted, silenced, and disarmed for 3 turns. You gain 6 extra phantom swords permanently for the battle.', 'Cross-Branch', 100, 1500, 5, '{"ss_omni_blade", "ss_heavenly_sword_array", "ss_blade_of_consciousness"}', '{"x": -1039, "y": -600}', '{"damage": "20d12", "damage_type": "slashing+force+psychic", "aoe": "30m", "root": "3 turns", "silence": "3 turns", "disarm": "3 turns", "summon": "6_phantom_swords", "permanent_battle": true}', '⛩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('255492aa-7aa5-4ea4-9cff-792c527bcffc', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_oath_of_protection', 'Koruma Yemini', 'Oath of Protection', '15 metre içindeki bir müttefike bağlanır. Aldıkları hasarın %20''sini siz üstlenirsiniz.', 'Links to an ally within 15 meters. You take 20% of the damage they receive.', 'Oath Bond', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"link_range": "15m", "damage_share": "20%"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('818d2246-4210-4c23-a748-5acc03d4c13c', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_shared_burden', 'Paylaşılan Yük', 'Shared Burden', 'Bağınızı güçlendirir. Bağlı müttefikin aldığı fiziksel hasarın %30''unu emersiniz.', 'Enhances your link. You now absorb 30% of physical damage taken by the linked ally.', 'Oath Bond', 5, 75, 1, '{"sws_oath_of_protection"}', '{"x": 389, "y": -224}', '{"damage_type": "physical", "share": "30%"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f80cb25d-2549-4f49-9394-9b15dd919ec2', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_vow_of_vitality', 'Canlılık Yemini', 'Vow of Vitality', 'Bağlı müttefike 10 saniye boyunca hızlı can yenilenmesi sağlar.', 'Grants the linked ally rapid health regeneration for 10 seconds.', 'Oath Bond', 10, 100, 1, '{"sws_oath_of_protection"}', '{"x": 606, "y": -349}', '{"hp_regen": "+5/s", "duration": "10s"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('82719b87-f03a-4cc8-aa27-743a10be5730', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_life_tether', 'Yaşam Bağı', 'Life Tether', 'Bağ menzilini 30 metreye çıkarır. Aldığınız her iyileştirmenin %50''si bağlı müttefike de uygulanır.', 'Extends link range to 30 meters. 50% of any healing you receive is also applied to the linked ally.', 'Oath Bond', 22, 200, 2, '{"sws_shared_burden", "sws_vow_of_vitality"}', '{"x": 822, "y": -474}', '{"link_range": "30m", "heal_transfer": "50%"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3dc67c07-4f72-4006-b961-db73a4e7e468', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_oathkeepers_stride', 'Yemin Tutanın Adımı', 'Oathkeeper''s Stride', 'Kendinizi bağlı müttefikiniz ve tehlike arasına yerleştirmek için 30 metreye kadar anında atılın.', 'Instantly dash up to 30 meters to place yourself between your linked ally and danger.', 'Oath Bond', 28, 250, 2, '{"sws_life_tether"}', '{"x": 1039, "y": -599}', '{"dash_range": "30m"}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3558c093-6349-4c67-9429-7d5ce534e636', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_empathic_shield', 'Empatik Kalkan', 'Empathic Shield', 'Bağlı müttefikinizin etrafında 100 HP''lik geçici bir kalkan oluşturur.', 'Projects a 100 HP temporary shield around your linked ally.', 'Oath Bond', 35, 280, 2, '{"sws_life_tether"}', '{"x": 1255, "y": -724}', '{"shield": "100 HP", "duration": "5s"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8e6e1090-bee5-4da1-9439-99c303c6ff2e', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_martyrs_pledge', 'Şehit Sözü', 'Martyr''s Pledge', '10 saniye boyunca müttefikin aldığı hasarın %50''sini üstlenirken, buna dayanmak için +30 Zırh kazanırsınız.', 'For 10 seconds, take 50% of the ally''s incoming damage while gaining +30 Armor to withstand it.', 'Oath Bond', 42, 400, 3, '{"sws_oathkeepers_stride", "sws_empathic_shield"}', '{"x": 1472, "y": -849}', '{"damage_share": "50%", "armor_bonus": "+30", "duration": "10s"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('86ae70dd-19b5-4865-b95f-a141d3db580e', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_unbreakable_vow', 'Bozulmaz Yemin', 'Unbreakable Vow', 'Bağınız görüş alanı içinde sonsuz menzile ulaşır ve savrulma etkilerine karşı tamamen bağışıklık kazanırsınız.', 'Your link becomes infinite in line-of-sight, and you become completely immune to knockback effects.', 'Oath Bond', 48, 450, 3, '{"sws_martyrs_pledge"}', '{"x": 1688, "y": -974}', '{"range": "infinite (LoS)", "knockback_immune": "true"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('64a1c1cf-0882-4a82-bd07-9d3e1f647dc6', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_blood_pact', 'Kan Anlaşması', 'Blood Pact', 'Bağlı müttefikinizin canının %20''sini anında yenilemek için mevcut canınızın %10''unu feda edersiniz.', 'Sacrifice 10% of your current health to instantly restore 20% of your linked ally''s health.', 'Oath Bond', 55, 480, 3, '{"sws_martyrs_pledge"}', '{"x": 1905, "y": -1099}', '{"cost": "10% HP", "heal": "20% Ally HP"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4247d3b-09cf-4f29-a088-11070bc3eeac', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_vow_of_defiance', 'Meydan Okuma Yemini', 'Vow of Defiance', '8 saniye boyunca, bağınız aracılığıyla emdiğiniz hasarın %30''u saldırgana geri yansıtılır.', 'For 8 seconds, 30% of the damage you absorb through your bond is reflected back to the attacker.', 'Oath Bond', 62, 650, 4, '{"sws_unbreakable_vow", "sws_blood_pact"}', '{"x": 2121, "y": -1224}', '{"reflect": "30%", "duration": "8s"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2a01e7bb-17f7-4247-8fe9-fd7da0da0528', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_soul_link', 'Ruh Bağı', 'Soul Link', 'Aynı anda 3 müttefike kadar bağlanmak için bağınızı genişletin. Herhangi birinin aldığı hasar tüm bağlı hedefler arasında eşit olarak dağıtılır.', 'Expand your bond to link up to 3 allies simultaneously. Damage taken by any of them is evenly distributed among all linked targets.', 'Oath Bond', 68, 750, 4, '{"sws_vow_of_defiance"}', '{"x": 2338, "y": -1349}', '{"max_allies": 3, "damage_share": "evenly distributed"}', '💞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3caf97f-e43a-4edd-8e84-d9498ef2dc24', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_oath_of_eternity', 'Sonsuzluk Yemini', 'Oath of Eternity', 'Eğer bağlı bir müttefik ölecekse, ölümü engellenir ve anında maksimum canının %30''u kadar iyileşir. Bağı sonlandırır.', 'If a linked ally would die, they are instead prevented from dying and instantly healed for 30% of their max HP. Ends the link.', 'Oath Bond', 75, 850, 4, '{"sws_vow_of_defiance"}', '{"x": 2554, "y": -1474}', '{"death_prevent": "true", "heal_on_trigger": "30%"}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('242160ce-3afc-42b2-a48d-76aefbb503e3', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_aegis_incarnate', 'Beden Bulmuş Aegis', 'Aegis Incarnate', '12 saniye boyunca bağlı müttefik +%50 hasar verir. Bu süre zarfında ona yöneltilen tüm hasarın %80''ini siz alırsınız.', 'For 12 seconds, a linked ally deals +50% damage. During this time, you take 80% of all damage directed at them.', 'Oath Bond', 82, 1100, 5, '{"sws_soul_link", "sws_oath_of_eternity"}', '{"x": 2771, "y": -1599}', '{"ally_damage_bonus": "+50%", "damage_taken_share": "80%", "duration": "12s"}', '🪽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('58a481b1-77be-47db-9ea5-d295612d84a9', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_ultimate_sacred_covenant', 'Nihai: Kutsal Sözleşme', 'Ultimate: Sacred Covenant', 'Nihai. 30 metre içindeki tüm müttefiklere bağlanır. 10 saniye boyunca onlar tamamen hasar görmez olur ve alacakları tüm hasarın %100''ünü siz emersiniz.', 'Ultimate. Bind to all allies within 30 meters. For 10 seconds, they are completely invulnerable, and you absorb 100% of all damage they would have taken.', 'Oath Bond', 90, 1500, 5, '{"sws_aegis_incarnate"}', '{"x": 2987, "y": -1724}', '{"radius": "30m", "invulnerability": "10s", "damage_absorption": "100%"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e2cf75d9-6ff5-43fd-a8a8-e663754b25ee', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spell_siphon', 'Büyü Sifonu', 'Spell Siphon', 'Gelen tek bir büyü mermisini emerek hasarını tamamen sıfırlar.', 'Absorbs a single incoming magic projectile, nullifying its damage completely.', 'Magic Absorption', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"absorb_chance": "100%", "target": "magic projectile"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('468ddd09-ac59-484c-8a52-6ec055aafd3d', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_mana_drain', 'Mana Çekişi', 'Mana Drain', '10 metre içindeki bir düşmandan 5 saniye boyunca saniyede 10 mana çeker.', 'Drains 10 mana per second from an enemy within 10 meters for 5 seconds.', 'Magic Absorption', 6, 80, 1, '{"sws_spell_siphon"}', '{"x": 289, "y": 344}', '{"mana_drain": "10/s", "range": "10m", "duration": "5s"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d53cea27-00cd-4e46-afff-b7c01ce97912', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_arcane_sponge', 'Arkana Süngeri', 'Arcane Sponge', 'Alınan tüm büyü hasarını pasif olarak %10 azaltır.', 'Passively reduces all magic damage taken by 10%.', 'Magic Absorption', 12, 120, 1, '{"sws_spell_siphon"}', '{"x": 449, "y": 536}', '{"magic_damage_reduction": "10%", "type": "passive"}', '🧽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9356b2f9-b92a-45a1-81b6-0ddc689b4eaa', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_nullify_magic', 'Büyü İptali', 'Nullify Magic', 'Gelen bir büyüyü doğrudan karşılar ve dağıtır. 20 saniye bekleme süresi vardır.', 'Directly counter and dispel an incoming magic spell. Has a 20-second cooldown.', 'Magic Absorption', 24, 220, 2, '{"sws_mana_drain", "sws_arcane_sponge"}', '{"x": 610, "y": 727}', '{"counter": "magic spell", "cooldown": "20s"}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5063d140-a0c5-4ec6-ac46-33d55a2428a3', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_absorb_elements', 'Element Emilimi', 'Absorb Elements', 'Gelen element hasarını emer. Bir sonraki fiziksel saldırınız o elementten fazladan 2d6 hasar verir.', 'Absorb incoming elemental damage. Your next physical attack deals an extra 2d6 damage of that element.', 'Magic Absorption', 30, 260, 2, '{"sws_nullify_magic"}', '{"x": 771, "y": 919}', '{"absorb_type": "elemental", "next_attack_bonus": "2d6"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c9eacc0e-f876-448e-996d-d5e34d1f86e0', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_magic_sink', 'Büyü Gideri', 'Magic Sink', '10m yarıçapındaki tüm alan etkili büyüleri 3 saniye boyunca kendinize çeker.', 'Draws all area-of-effect spells within a 10m radius towards yourself for 3 seconds.', 'Magic Absorption', 38, 290, 2, '{"sws_nullify_magic"}', '{"x": 932, "y": 1110}', '{"pull_radius": "10m", "duration": "3s"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ab1c3cc5-acf1-48d8-abd0-26b3c59fccb0', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spell_mirror', 'Büyü Aynası', 'Spell Mirror', '5 saniye boyunca, emdiğiniz tüm büyüler bunun yerine onları yapanlara geri yansıtılır.', 'For 5 seconds, all spells you absorb are instead reflected back at their casters.', 'Magic Absorption', 44, 420, 3, '{"sws_absorb_elements", "sws_magic_sink"}', '{"x": 1092, "y": 1302}', '{"reflect_chance": "100%", "duration": "5s"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09d1f19f-426a-4b9b-9f5a-b39c11d9c085', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_arcane_conversion', 'Arkana Dönüşümü', 'Arcane Conversion', 'Bir büyüyü her emdiğinizde, anında 50 HP geri kazanırsınız.', 'Every time you absorb a spell, you instantly regain 50 HP.', 'Magic Absorption', 50, 460, 3, '{"sws_spell_mirror"}', '{"x": 1253, "y": 1493}', '{"magic_to_hp": "50 HP per spell"}', '♻️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f31418f1-4216-467d-8709-8778a3e5e566', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_void_shield', 'Hiçlik Kalkanı', 'Void Shield', 'Sadece büyü hasarını emen 500 HP''lik bir kalkan oluşturur. 10 saniye sürer.', 'Creates a 500 HP shield that only absorbs magic damage. Lasts 10 seconds.', 'Magic Absorption', 58, 500, 3, '{"sws_spell_mirror"}', '{"x": 1414, "y": 1685}', '{"magic_shield": "500 HP", "duration": "10s"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7d1eb537-ade4-48fd-b3be-494daf073d7b', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_devour_magic', 'Büyü Yutan', 'Devour Magic', '15 metre içindeki sihirli bir bölgeyi tamamen tüketir ve dağıtır.', 'Completely consumes and dispels a magical zone within 15 meters.', 'Magic Absorption', 64, 700, 4, '{"sws_arcane_conversion", "sws_void_shield"}', '{"x": 1574, "y": 1876}', '{"devour_radius": "15m", "zone_dispel": "true"}', '🦖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e6db4e1-4576-4363-be95-e159d7c8d209', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_mana_overload', 'Mana Aşırı Yüklemesi', 'Mana Overload', 'Emilen tüm büyüyü devasa bir 10m alan patlaması olarak serbest bırakır ve 8d6 saf hasar verir.', 'Release all absorbed magic as a massive 10m area blast, dealing 8d6 pure damage.', 'Magic Absorption', 70, 800, 4, '{"sws_devour_magic"}', '{"x": 1735, "y": 2068}', '{"blast_radius": "10m", "pure_damage": "8d6"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f4e908cd-3116-478c-b46f-3f5207e0e361', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spell_warden', 'Büyü Gardiyanı', 'Spell Warden', '15 metre içindeki tüm düşmanları 3 saniye boyunca susturan bir aura yayar.', 'Emits an aura that silences all enemies within 15 meters for 3 seconds.', 'Magic Absorption', 78, 900, 4, '{"sws_devour_magic"}', '{"x": 1896, "y": 2259}', '{"silence_radius": "15m", "duration": "3s"}', '🤐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34196a0a-73dc-4ec3-9303-21279c5123c6', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_black_hole_aegis', 'Kara Delik Aegis''i', 'Black Hole Aegis', '5 saniye boyunca, 30 metre içindeki tüm büyü saldırıları zorla kalkanınıza çekilir.', 'For 5 seconds, all magic attacks within 30 meters are forcefully pulled into your shield.', 'Magic Absorption', 84, 1200, 5, '{"sws_mana_overload", "sws_spell_warden"}', '{"x": 2056, "y": 2451}', '{"pull_radius": "30m", "duration": "5s"}', '⚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7387f2da-af53-476d-8d3b-b8de339cdde1', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_ultimate_magic_singularity', 'Nihai: Büyü Tekilliği', 'Ultimate: Magic Singularity', 'Nihai. 15 saniye boyunca 50 metre içindeki TÜM büyüleri emerek takımınızı büyü etkilerine ve hasarına karşı tamamen bağışık hale getirirsiniz.', 'Ultimate. For 15 seconds, you absorb ALL magic within 50 meters, rendering your team completely immune to magical effects and damage.', 'Magic Absorption', 90, 1500, 5, '{"sws_black_hole_aegis"}', '{"x": 2217, "y": 2642}', '{"radius": "50m", "duration": "15s", "magic_immunity": "true"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1052ff85-563e-4711-b7b7-14e4ee85ba6b', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_summon_ward', 'Koruyucu Çağrısı', 'Summon Ward', '15 saniye süren 100 HP''ye sahip sabit bir ruh kalkanı çağırır.', 'Summon a stationary spirit shield with 100 HP that lasts for 15 seconds.', 'Guardian Spirit', 3, 50, 1, '{}', '{"x": -128, "y": 153}', '{"shield_hp": "100", "duration": "15s"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('717b5dff-0652-47c8-8792-34f80bd11219', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spirit_companion', 'Ruhani Yoldaş', 'Spirit Companion', 'Küçük bir koruyucu ruh sizi takip ederek saldırıları engelleme konusunda pasif %15 şans verir.', 'A small guardian spirit follows you, granting a passive 15% chance to block attacks.', 'Guardian Spirit', 8, 90, 1, '{"sws_summon_ward"}', '{"x": -289, "y": 344}', '{"block_chance": "15%", "duration": "passive"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8b1cc54-b1db-4979-8f9f-f81042744250', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_ethereal_armor', 'Eterik Zırh', 'Ethereal Armor', 'Kendinizi ruh enerjisiyle kaplayarak 10 saniye boyunca +15 Zırh kazanırsınız.', 'Cover yourself in spirit energy, gaining +15 Armor for 10 seconds.', 'Guardian Spirit', 15, 130, 1, '{"sws_summon_ward"}', '{"x": -449, "y": 536}', '{"armor_bonus": "+15", "duration": "10s"}', '🧥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bd6c2901-42b4-408a-b2b3-d25015340acb', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_guardian_totem', 'Muhafız Totemi', 'Guardian Totem', '20 saniye boyunca 10 metre içindeki tüm müttefiklere +20 Zırh sağlayan bir totem yerleştirir.', 'Places a totem that grants +20 Armor to all allies within 10 meters for 20 seconds.', 'Guardian Spirit', 25, 230, 2, '{"sws_spirit_companion", "sws_ethereal_armor"}', '{"x": -610, "y": 727}', '{"totem_radius": "10m", "armor_bonus": "+20", "duration": "20s"}', '🗼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4c42568b-81e2-43b5-a225-9852fddb97ad', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spirit_taunt', 'Ruhani Kışkırtma', 'Spirit Taunt', 'Ruhani yoldaşınız 5 metre içindeki düşmanları kışkırtarak 4 saniye boyunca kendisine saldırmaya zorlar.', 'Your spirit companion taunts enemies within 5 meters, forcing them to attack it for 4 seconds.', 'Guardian Spirit', 32, 270, 2, '{"sws_guardian_totem"}', '{"x": -771, "y": 919}', '{"taunt_radius": "5m", "duration": "4s"}', '📣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2a684339-fdcf-4f59-82a7-e8fc4a2f276d', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_phantom_bulwark', 'Hayalet Siper', 'Phantom Bulwark', '8 saniye boyunca tüm mermileri tamamen engelleyen 5 metre genişliğinde bir ruhlar duvarı çağırır.', 'Summon a 5m wide wall of spirits that completely blocks all projectiles for 8 seconds.', 'Guardian Spirit', 40, 300, 2, '{"sws_guardian_totem"}', '{"x": -932, "y": 1110}', '{"wall_width": "5m", "projectile_block": "100%", "duration": "8s"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('34909b28-f551-4643-ab3d-988b3aad9cd4', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_ancestral_guardian', 'Atasal Muhafız', 'Ancestral Guardian', 'Sizinle birlikte savaşan ve vuruş başına 2d8 hasar veren vahşi bir atasal ruh çağırır.', 'Summon a fierce ancestral spirit that fights alongside you, dealing 2d8 damage per hit.', 'Guardian Spirit', 45, 430, 3, '{"sws_spirit_taunt", "sws_phantom_bulwark"}', '{"x": -1092, "y": 1302}', '{"damage": "2d8", "duration": "15s"}', '🐺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fef78611-c4b2-4ac2-981a-063dfd11a442', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_guardian_link', 'Muhafız Bağı', 'Guardian Link', 'Ruhunuzu 20m içindeki bir müttefike bağlayın. Ruh onların aldığı hasarın %30''unu üstlenir.', 'Link your spirit to an ally within 20m. The spirit takes 30% of their damage.', 'Guardian Spirit', 52, 470, 3, '{"sws_ancestral_guardian"}', '{"x": -1253, "y": 1493}', '{"spirit_damage_take": "30%", "link_range": "20m"}', '🎗️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fb493d50-2e97-4d05-b606-813a21016695', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_ethereal_intervention', 'Eterik Müdahale', 'Ethereal Intervention', 'Ruhunuz tehlikedeki bir müttefike ışınlanır ve anında onları 200 HP ile kalkanlar.', 'Your spirit teleports to an ally in danger, instantly shielding them for 200 HP.', 'Guardian Spirit', 60, 500, 3, '{"sws_ancestral_guardian"}', '{"x": -1414, "y": 1685}', '{"teleport": "ally location", "shield": "200 HP"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84e18b3e-c762-4e23-b287-884083498443', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_avatar_of_protection', 'Koruma Avatarı', 'Avatar of Protection', 'Ruhunuz 10 metrelik bir kubbe kalkana dönüşerek içerideki herkesi 10 saniye boyunca korur.', 'Your spirit transforms into a 10m dome shield, protecting everyone inside for 10 seconds.', 'Guardian Spirit', 65, 720, 4, '{"sws_guardian_link", "sws_ethereal_intervention"}', '{"x": -1574, "y": 1876}', '{"dome_radius": "10m", "duration": "10s"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13a72f6e-0648-4346-8811-a533790cac9a', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spirit_bastion', 'Ruhani Kale', 'Spirit Bastion', 'Ruhani kubbe 15 metreye genişler ve gelen tüm hasarı 8 saniye boyunca %40 azaltır.', 'The spirit dome expands to 15m and reduces all incoming damage by 40% for 8 seconds.', 'Guardian Spirit', 72, 820, 4, '{"sws_avatar_of_protection"}', '{"x": -1735, "y": 2068}', '{"damage_reduction": "40%", "radius": "15m", "duration": "8s"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f6f91f87-9cc7-45e8-9406-5a3c8b3d3810', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_guardian_angel', 'Koruyucu Melek', 'Guardian Angel', 'Ruhunuz kendini feda ederek düşmüş bir müttefiki otomatik olarak %50 HP ile diriltir. 10dk bekleme süresi.', 'Your spirit sacrifices itself to automatically revive a fallen ally with 50% HP. 10m cooldown.', 'Guardian Spirit', 80, 900, 4, '{"sws_avatar_of_protection"}', '{"x": -1896, "y": 2259}', '{"revive_hp": "50%", "cooldown": "10m"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('413e01f8-723e-4c3c-bcf9-3dad95a75c81', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_legion_of_shields', 'Kalkanlar Lejyonu', 'Legion of Shields', 'Geçilmez bir falanks oluşturmak için 10 koruyucu ruh çağırır ve arkalarındaki müttefiklere %80 engelleme şansı verir.', 'Summon 10 guardian spirits to form an impenetrable phalanx, granting an 80% block chance to allies behind them.', 'Guardian Spirit', 86, 1300, 5, '{"sws_spirit_bastion", "sws_guardian_angel"}', '{"x": -2056, "y": 2451}', '{"spirits": 10, "block_chance": "80%", "duration": "15s"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e300f4a3-6c8f-4052-b943-874ed1989b80', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_ultimate_valkyries_descent', 'Nihai: Valkürün İnişi', 'Ultimate: Valkyrie''s Descent', 'Nihai. Devasa bir Valkür ruhu çağırır. 15 saniye boyunca 40m içindeki tüm müttefikler %90 hasar azaltma ve muazzam yenilenme kazanır.', 'Ultimate. Summon a massive Valkyrie spirit. For 15 seconds, all allies within 40m gain 90% damage reduction and massive regeneration.', 'Guardian Spirit', 90, 1500, 5, '{"sws_legion_of_shields"}', '{"x": -2217, "y": 2642}', '{"radius": "40m", "damage_reduction": "90%", "hp_regen": "+100/s", "duration": "15s"}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b682a96-419c-4990-9623-e15b45853cab', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spell_share', 'Büyü Paylaşımı', 'Spell Share', 'Emilen büyü enerjisini bağlı bir müttefike aktararak onlara anında 50 mana verir.', 'Transfers absorbed magic energy to a linked ally, granting them 50 mana instantly.', 'Oath Bond', 35, 280, 2, '{"sws_empathic_shield", "sws_magic_sink"}', '{"x": 3204, "y": -1849}', '{"mana_transfer": "50", "cooldown": "5s"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('66d6ad54-0507-4d16-9e53-cb8bbb5b5735', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_arcane_spirit', 'Arkana Ruhu', 'Arcane Spirit', 'Koruyucu ruhlarınız artık büyüyü emer. Emilen her büyü, boyutlarını ve güçlerini %10 artırır (en fazla 5 yük).', 'Your guardian spirits now absorb magic. Each absorbed spell increases their size and power by 10% (max 5 stacks).', 'Magic Absorption', 55, 480, 3, '{"sws_void_shield", "sws_ethereal_intervention"}', '{"x": 2378, "y": 2834}', '{"size_increase": "10%", "power_increase": "10%", "max_stacks": 5}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('da6b1080-e290-4142-92a4-21af5afa07d1', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_vow_of_ancestors', 'Ataların Yemini', 'Vow of the Ancestors', 'Bağlı olduğunuz her müttefik, 20 saniye boyunca kendi geçici ruhani yoldaşını kazanır.', 'Any ally you are linked to gains their own temporary spirit companion for 20 seconds.', 'Guardian Spirit', 55, 480, 3, '{"sws_blood_pact", "sws_ethereal_intervention"}', '{"x": -2378, "y": 2834}', '{"ally_spirit": "true", "duration": "20s"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3bcf1cb5-9cc0-4b3f-87c3-a19e6bb31f6e', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_trinity_ward', 'Üçlü Koruma', 'Trinity Ward', '15 saniye boyunca müttefikin konumunda birleştiren, büyü emen ve bir koruyucu çağıran bir ruh bağı oluşturur.', 'Creates a spirit link that connects, absorbs magic, and summons a guardian at the ally''s location for 15 seconds.', 'Oath Bond', 75, 850, 4, '{"sws_soul_link", "sws_spell_warden", "sws_guardian_angel"}', '{"x": 3420, "y": -1974}', '{"trinity_link": "true", "duration": "15s"}', '🔱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('23344cee-c430-47e6-9603-667dbae7770a', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_empathic_absorption', 'Empatik Emilim', 'Empathic Absorption', 'Bağlı bir müttefik küresel olarak ne zaman büyü hasarı alsa, otomatik olarak %50''sini emersiniz.', 'Whenever a linked ally takes magic damage globally, you automatically absorb 50% of it.', 'Magic Absorption', 75, 850, 4, '{"sws_soul_link", "sws_spell_warden"}', '{"x": 2539, "y": 3025}', '{"global_absorb": "50%", "damage_type": "magic"}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a261ebd0-7b14-4ba7-9501-62753d3dd69f', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_mana_spirit', 'Mana Ruhu', 'Mana Spirit', 'Koruyucu ruhunuz büyü enerjisiyle beslenir. Engellediği her büyü size 20 mana geri kazandırır.', 'Your guardian spirit feeds on magical energy. Every spell it blocks restores 20 mana to you.', 'Guardian Spirit', 75, 850, 4, '{"sws_spell_warden", "sws_guardian_angel"}', '{"x": -2539, "y": 3025}', '{"mana_regen": "20 per blocked spell"}', '🦋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('55c8321a-8e11-4f34-91f9-3d30b9199b78', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_spirit_vow', 'Ruh Yemini', 'Spirit Vow', 'Ruhunuzu doğrudan koruyucu ruhunuza bağlayın. Ruh yaşadığı sürece ölüme karşı bağışık olursunuz (en fazla 10 sn).', 'Bind your very soul to your guardian spirit. You are immune to death as long as the spirit lives (up to 10s).', 'Oath Bond', 85, 1200, 5, '{"sws_aegis_incarnate", "sws_legion_of_shields"}', '{"x": 3637, "y": -2099}', '{"death_immunity": "10s", "soul_bound": "true"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bf5f1334-1c5e-434b-986b-cb20e915c48c', '5f73dede-db67-42fd-baa1-2a4cf6c480c6', 'sws_grand_ultimate_absolute_aegis', 'Yüce Nihai: Mutlak Aegis', 'Grand Ultimate: Absolute Aegis', 'Nihai Yeminli Kalkan olun. 100m içindeki tüm müttefikleri bağlar. 15 saniyeliğine %100 hasar bağışıklığı verir. Sonunda emilen hasarın iki katı ile dışa doğru patlar.', 'Become the ultimate Sworn Shield. Binds all allies within 100m. Grants 100% damage immunity for 15s. Explodes outward with double the absorbed damage at the end.', 'Oath Bond', 100, 1500, 5, '{"sws_ultimate_sacred_covenant", "sws_ultimate_magic_singularity", "sws_ultimate_valkyries_descent"}', '{"x": 3853, "y": -2224}', '{"radius": "100m", "damage_immunity": "100%", "duration": "15s", "final_damage": "absorbed * 2"}', '🔆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f6042add-8a8a-4c46-a0d7-32d937a5fcee', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_trishield_bash', 'Üçlü Kalkan Vuruşu', 'Tri-Shield Bash', 'Hedefi ana kalkanla ezerek 1d8 ezici hasar verir ve 2m geriye iter.', 'Smashes the target with the primary shield, dealing 1d8 bludgeoning damage and pushing them back 2m.', 'Tri-Shield', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d8 bludgeoning", "range": "Melee", "push": "2m"}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d60eb6f6-f3e3-4797-8021-af6a100f2b9e', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_floating_shield', 'Yüzen Kalkan', 'Floating Shield', 'Kalkanlarından birini canlandırarak etrafında yüzmesini sağlar, 1 dakika boyunca +2 Zırh Sınıfı verir. Ana silahınla saldırmaya devam edebilirsin.', 'Animates one of your shields to float around you, granting +2 AC for 1 minute. You can still attack with your main weapon.', 'Tri-Shield', 5, 80, 1, '{}', '{"x": 389, "y": -224}', '{"buff": "+2 AC", "duration": "1 minute"}', '🛸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('eeb71e20-6279-40c7-b000-5997592447b8', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_shield_boomerang', 'Bumerang Kalkan', 'Shield Boomerang', 'Bir kalkanı 15m''ye kadar fırlatarak hedefe 2d6 ezici hasar verir ve ardından kalkan elinize geri döner.', 'Throws a shield up to 15m away, dealing 2d6 bludgeoning damage to a target before returning to your hand.', 'Tri-Shield', 10, 120, 1, '{}', '{"x": 606, "y": -349}', '{"damage": "2d6 bludgeoning", "range": "15m"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4feaba07-1bf0-45e7-bf4c-5c48071f6027', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_tri_strike', 'Üçlü Vuruş', 'Tri-Strike', 'Üç kalkanı da kullanarak yapılan hızlı bir 3 vuruşluk kombo, 2m içindeki tek bir hedefe 3d6 ezici hasar verir.', 'A rapid 3-hit combo using all three shields, dealing 3d6 bludgeoning damage to a single target within 2m.', 'Tri-Shield', 22, 200, 2, '{"trp_trishield_bash"}', '{"x": 822, "y": -474}', '{"damage": "3d6 bludgeoning", "range": "2m", "hits": "3"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('886b88b7-88a4-4a6f-a81c-931ff97dec6b', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_orbiting_guard', 'Yörünge Koruması', 'Orbiting Guard', 'İki kalkanın 30 saniye boyunca 3m yarıçapında etrafında dönmesini emreder, alana giren düşmanlara 1d6 hasar verir.', 'Commands two shields to orbit you at a 3m radius for 30 seconds, dealing 1d6 damage to enemies that enter the area.', 'Tri-Shield', 28, 240, 2, '{"trp_floating_shield"}', '{"x": 1039, "y": -599}', '{"damage": "1d6", "radius": "3m", "duration": "30 seconds"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9f32ef20-ecf0-4324-92ca-3b9014bbbc85', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_shield_charge', 'Kalkan Hücumu', 'Shield Charge', 'Kalkanlar havada olacak şekilde 10m''ye kadar ileri atılır, 2d8 hasar verir ve yol üzerindeki Orta veya daha küçük yaratıkları yere serer.', 'Charges forward up to 10m with shields raised, dealing 2d8 damage and knocking prone any Medium or smaller creature in the path.', 'Tri-Shield', 35, 280, 2, '{"trp_trishield_bash"}', '{"x": 1255, "y": -724}', '{"damage": "2d8", "range": "10m", "condition": "Prone"}', '🐂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('75c0ed4b-e15f-4d77-9c05-a55c6c0bf87e', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_heavy_ricochet', 'Ağır Sekme', 'Heavy Ricochet', 'Birbirine 10m mesafedeki 3 hedefe kadar seken bir kalkan fırlatarak her birine 3d6 hasar verir.', 'Throws a shield that bounces between up to 3 targets within 10m of each other, dealing 3d6 damage to each.', 'Tri-Shield', 42, 380, 3, '{"trp_shield_boomerang"}', '{"x": 1472, "y": -849}', '{"damage": "3d6", "range": "10m between targets", "targets": "3"}', '🏓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('10434ccf-1303-4d47-86a1-93d6ed31cb25', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_shield_juggernaut', 'Kalkan Devi', 'Shield Juggernaut', 'Pasif: 3 kalkan birden kullanırken hareket hızın 2m azalır ancak Güç zarlarına ve kurtarma atışlarına +4 kazanırsın.', 'Passive: While wielding 3 shields, your movement speed is reduced by 2m but you gain +4 to Strength checks and saves.', 'Tri-Shield', 50, 420, 3, '{"trp_shield_charge"}', '{"x": 1688, "y": -974}', '{"buff": "+4 Strength checks/saves", "debuff": "-2m Movement Speed"}', '🏋️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('15cbdbaf-c249-4be2-8d3f-e1d3924d0fd2', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_phantom_fourth', 'Dördüncü Hayalet', 'Phantom Fourth', '1 dakika boyunca ruhani dördüncü bir kalkan oluşturarak, tam savunmanı korurken iki kalkan fırlatmana olanak tanır.', 'Manifests an ethereal fourth shield for 1 minute, allowing you to throw two shields while maintaining full defense.', 'Tri-Shield', 58, 480, 3, '{"trp_orbiting_guard"}', '{"x": 1905, "y": -1099}', '{"duration": "1 minute", "mechanics": "Allows throwing 2 shields while maintaining defense"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('de60e2e0-ebe1-41e9-b28c-95694d257af4', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_triple_meteor', 'Üçlü Meteor', 'Triple Meteor', 'Havaya sıçrar ve 5m yarıçaplı bir alana inerek üç kalkanı birden yere çarpar. 5d8 alan hasarı verir.', 'Leaps into the air and crashes down in a 5m radius, slamming all three shields into the ground. Deals 5d8 area damage.', 'Tri-Shield', 65, 650, 4, '{"trp_shield_charge"}', '{"x": 2121, "y": -1224}', '{"damage": "5d8", "radius": "5m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b12664a8-82c3-4df1-8541-5de21db2f8a7', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_whirlwind_of_steel', 'Çelik Hortumu', 'Whirlwind of Steel', 'Kalkanlar uzatılmış halde hızla dönerek bitişik düşmanlara 4d10 hasar veren 4m''lik çelik bir hortum yaratır.', 'Spins rapidly with out-stretched shields, creating a 4m tornado of steel that deals 4d10 damage to adjacent enemies.', 'Tri-Shield', 75, 800, 4, '{"trp_tri_strike"}', '{"x": 2338, "y": -1349}', '{"damage": "4d10", "radius": "4m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('90837dcd-2211-4b79-9edc-77a9afff4e50', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_unending_barrage', 'Bitmeyen Yaylım', 'Unending Barrage', '3 tur boyunca sürekli bir yaylım ateşiyle kalkanları hızla fırlatır ve geri çağırır, 20m''ye kadar olan hedeflere tur başına 4d6 hasar verir.', 'Rapidly throws and recalls shields in a continuous barrage for 3 turns, dealing 4d6 damage per turn to targets up to 20m away.', 'Tri-Shield', 85, 1100, 5, '{"trp_heavy_ricochet"}', '{"x": 2554, "y": -1474}', '{"damage": "4d6 per turn", "range": "20m", "duration": "3 turns"}', '🚀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d8c021a-d18a-4a68-b127-16e1bac289a9', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_tri_shield_avalanche', 'Üçlü Kalkan Çığı', 'Tri-Shield Avalanche', 'Üç kalkanının devasa spektral kopyalarını çağırarak 20m''lik bir koni içindeki her şeyi ezer, 12d10 hasar verir ve 1 tur sersemletir.', 'Summons massive spectral duplicates of your three shields that crush everything in a 20m cone, dealing 12d10 damage and stunning for 1 turn.', 'Tri-Shield', 95, 1400, 5, '{"trp_triple_meteor", "trp_whirlwind_of_steel"}', '{"x": 2771, "y": -1599}', '{"damage": "12d10", "range": "20m cone", "condition": "Stunned", "duration": "1 turn"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3568b5d-1517-46d8-bd8d-906d486a0278', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_iron_brace', 'Demir Siper', 'Iron Brace', 'Kalkanının arkasında siper alarak bir sonraki turuna kadar alınan tüm fiziksel hasarı yarıya indirir. Hareket hızı 0''a düşer.', 'Brace behind your shield, halving all physical damage taken until your next turn. Movement speed drops to 0.', 'Bastion', 2, 60, 1, '{}', '{"x": 128, "y": 153}', '{"damage_reduction": "50% physical", "duration": "Until next turn", "debuff": "0 Movement"}', '🚧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13c58137-7919-405e-9ad8-3eaa838cc426', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_cover_ally', 'Dosta Siper Ol', 'Cover Ally', 'Bir dosta doğru 5m atılarak ona yöneltilmiş bir saldırının önüne geçer ve hasarı sen alırsın.', 'Dash up to 5m to an ally and intercept an incoming attack aimed at them, taking the damage yourself.', 'Bastion', 8, 100, 1, '{}', '{"x": 289, "y": 344}', '{"range": "5m dash", "mechanics": "Intercepts attack"}', '🫂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3c275053-fd70-4d23-9bf6-ef2a63832667', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_shield_wall', 'Kalkan Duvarı', 'Shield Wall', 'Bir kalkanı yere sabitleyerek 3m genişliğinde, 2m yüksekliğinde bir siper yaratır ve arkasındaki dostlara 3/4 siper sağlar.', 'Plants one shield into the ground to create a 3m wide, 2m high cover that grants 3/4 cover to allies behind it.', 'Bastion', 15, 140, 1, '{}', '{"x": 449, "y": 536}', '{"dimension": "3m wide x 2m high", "buff": "3/4 Cover"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4fda36b5-f3c2-4109-8fde-6df5fb9162aa', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_entrench', 'Mevzi Al', 'Entrench', 'İki kalkanı sabitleyerek açılı bir savunma pozisyonu oluşturur. 1 dakika boyunca itilmeye veya yere serilmeye karşı bağışıklık kazandırır.', 'Plants two shields to form an angled defensive position. Grants immunity to being pushed or knocked prone for 1 minute.', 'Bastion', 25, 220, 2, '{"trp_iron_brace"}', '{"x": 610, "y": 727}', '{"immunity": "Push/Prone", "duration": "1 minute"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c4aec0e2-6d35-490a-b8bc-516a9f2656c4', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_unmovable_object', 'Kaldırılamaz Obje', 'Unmovable Object', 'Pasif: Maksimum Canın %20 artar ve 3m içindeki her düşman için zırh sınıfın +1 artar.', 'Passive: You gain +20% maximum HP and your armor class increases by +1 for every enemy within 3m.', 'Bastion', 32, 260, 2, '{"trp_cover_ally"}', '{"x": 771, "y": 919}', '{"buff": "+20% Max HP, +1 AC per enemy within 3m"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('33a635bb-f14b-4383-bd34-4d55dd400697', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_heavy_plating', 'Ağır Kaplama', 'Heavy Plating', 'Kalkanlarını yoğun büyülü toprakla kaplar. 10 dakika boyunca sana yapılan kritik vuruşlar normal vuruşlara dönüşür.', 'Coats your shields in dense magical earth. For 10 minutes, critical hits against you become normal hits.', 'Bastion', 38, 290, 2, '{"trp_shield_wall"}', '{"x": 932, "y": 1110}', '{"duration": "10 minutes", "mechanics": "Nullifies critical hits"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41677f3a-76d8-43cc-ace3-7b88a1386fc8', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_fortress_stance', 'Kale Duruşu', 'Fortress Stance', 'Üç kalkanını birbirine kilitler. Saldıramazsın, ancak +10 Zırh Sınıfı kazanırsın ve 5 tur boyunca tur başına 5 Can yenilersin.', 'Locks your three shields together. You cannot attack, but you gain +10 AC and regenerate 5 HP per turn for up to 5 turns.', 'Bastion', 45, 400, 3, '{"trp_entrench"}', '{"x": 1092, "y": 1302}', '{"buff": "+10 AC, 5 HP regeneration", "duration": "5 turns"}', '🏦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('24b42fca-349c-4734-b5eb-607ab1e2675f', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_dome_of_protection', 'Koruma Kubbesi', 'Dome of Protection', '5m yarıçapında yarım küre şeklinde bir bariyer yansıtır. İçerideki dostlar 1 dakika boyunca element hasarına direnç kazanır.', 'Projects a hemispherical barrier 5m in radius. Allies inside gain resistance to elemental damage for 1 minute.', 'Bastion', 52, 440, 3, '{"trp_heavy_plating"}', '{"x": 1253, "y": 1493}', '{"radius": "5m", "buff": "Elemental Resistance", "duration": "1 minute"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc10f184-f2cf-4f47-bf23-ea795060cc2d', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_magnetic_pull', 'Manyetik Çekim', 'Magnetic Pull', '15m içindeki tüm düşmanları sana saldırması için kışkırtan ve metal giyen düşmanları 5m yakınına çeken manyetik bir alan yaratır.', 'Creates a magnetic field that taunts all enemies within 15m to attack you, and pulls metal-wearing enemies 5m closer.', 'Bastion', 59, 490, 3, '{"trp_unmovable_object"}', '{"x": 1414, "y": 1685}', '{"radius": "15m", "condition": "Taunt", "pull": "5m (metal wearers)"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a00f445-472a-4a52-8b97-50c6ed332b5a', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_impenetrable_phalanx', 'Geçilmez Falanks', 'Impenetrable Phalanx', 'Seni 3m yarıçapında çevreleyen 5 spektral kalkan taşıyıcısı çağırır. 3 tur boyunca görüş hattı gerektiren tüm saldırıları engeller.', 'Summons 5 spectral shieldbearers that surround you in a 3m radius. Blocks all line-of-sight attacks for 3 turns.', 'Bastion', 68, 700, 4, '{"trp_fortress_stance"}', '{"x": 1574, "y": 1876}', '{"radius": "3m", "duration": "3 turns", "mechanics": "Blocks line-of-sight attacks"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b86e395e-8731-47a6-b5a3-834eeebd379e', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_bastion_of_hope', 'Umut Tablası', 'Bastion of Hope', '10m''lik saf savunma aurası yayar. Aura içindeki dostlar +3 Zırh Sınıfı ve tüm kurtarma atışlarında avantaj kazanır.', 'Radiates a 10m aura of pure defense. Allies within the aura gain +3 AC and advantage on all saving throws.', 'Bastion', 78, 850, 4, '{"trp_dome_of_protection"}', '{"x": 1735, "y": 2068}', '{"radius": "10m", "buff": "+3 AC, Advantage on Saving Throws"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0039271f-f4df-455c-a23f-b638d8b1d585', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_walking_fortress', 'Yürüyen Kale', 'Walking Fortress', 'Savunma devine dönüşürsün. 1 dakika boyunca vuruş başına 15 puandan az olan tüm hasarları yok sayarsın.', 'Transforms into a juggernaut of defense. For 1 minute, you ignore all damage less than 15 points per hit.', 'Bastion', 88, 1200, 5, '{"trp_impenetrable_phalanx"}', '{"x": 1896, "y": 2259}', '{"damage_reduction": "Ignores damage < 15", "duration": "1 minute"}', '🚶‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dceb4e28-c4ea-4e54-a317-a8321781f1b2', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_absolute_defense', 'Mutlak Savunma', 'Absolute Defense', '2 tur boyunca hasar görmez 6m''lik bir alan yaratır. Bu alana hiçbir hasar veya düşmanca büyü giremez ya da alanda gerçekleşemez.', 'Generates an invulnerable 6m zone for 2 turns. No damage or hostile magic can enter or occur inside this zone.', 'Bastion', 98, 1450, 5, '{"trp_bastion_of_hope", "trp_walking_fortress"}', '{"x": 2056, "y": 2451}', '{"radius": "6m", "duration": "2 turns", "mechanics": "Total invulnerability"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95a6ee4f-8411-4e6c-8cfc-6b623f9924bb', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_deflect', 'Saptırma', 'Deflect', 'Tek bir yakın dövüş saldırısına karşı Zırh Sınıfına +3 eklemek için reaksiyonunu kullanırsın. Iskalarsa saldıranı 1m itebilirsin.', 'Use your reaction to add +3 to your AC against a single melee attack. If it misses, you may push the attacker 1m.', 'Reflection', 3, 70, 1, '{}', '{"x": -128, "y": 153}', '{"buff": "+3 AC (reaction)", "push": "1m"}', '🏑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b54e523b-e549-4920-af55-2997fa692d73', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_mirror_polish', 'Ayna Cilası', 'Mirror Polish', 'Kalkanını ayna mükemmelliğinde parlatır. Bakış saldırılarını yansıtır ve ışın/hüzme büyülerine karşı +2 Zırh Sınıfı verir.', 'Polishes your shield to mirror perfection. Reflects gaze attacks and grants +2 AC against beam/ray spells.', 'Reflection', 9, 110, 1, '{}', '{"x": -289, "y": 344}', '{"buff": "+2 AC against rays", "mechanics": "Reflects gaze attacks"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('37c89f52-b853-4b22-8f07-ca19fccf5423', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_kinetic_absorb', 'Kinetik Emilim', 'Kinetic Absorb', 'Gelen bir fiziksel saldırının kinetik enerjisini emerek hasarı 1d10+Seviye kadar azaltır ve enerjiyi depolar.', 'Absorbs the kinetic energy of an incoming physical attack, reducing damage by 1d10+Level and storing the energy.', 'Reflection', 16, 150, 1, '{}', '{"x": -449, "y": 536}', '{"damage_reduction": "1d10 + Level", "mechanics": "Stores kinetic energy"}', '📥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('22f70cf3-28cc-4bbb-9569-6f6b79511463', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_rebound_strike', 'Sekme Vuruşu', 'Rebound Strike', 'Depolanan kinetik enerjiyi bir sonraki yakın dövüş vuruşunda serbest bırakarak fazladan 2d8 güç hasarı verir.', 'Releases stored kinetic energy on your next melee hit, dealing an additional 2d8 force damage.', 'Reflection', 24, 210, 2, '{"trp_kinetic_absorb"}', '{"x": -610, "y": 727}', '{"damage": "+2d8 force"}', '📤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8fb5d3ab-4bfe-4594-a27e-d9568532f4d5', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_magic_dispersion', 'Büyü Dağıtma', 'Magic Dispersion', 'Gelen bir büyü mermisine kalkanınla vurarak hasarını 4d6 azaltır ve kalanını arkanda 3m''lik bir koniye dağıtır.', 'Smashes an incoming spell projectile with your shield, reducing its damage by 4d6 and scattering the rest in a 3m cone behind you.', 'Reflection', 30, 250, 2, '{"trp_deflect"}', '{"x": -771, "y": 919}', '{"damage_reduction": "4d6", "area": "3m cone"}', '🎇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc323530-9d4f-4582-9524-a2cdd7408bbf', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_resonant_shield', 'Rezonans Kalkanı', 'Resonant Shield', 'Kendi kalkanlarını birbirine çarparak 5m''lik sağır edici bir ses dalgası yaratır, 2d6 gök gürültüsü hasarı verir ve hedefleri 1 tur susturur.', 'Strikes your own shields together to create a deafening 5m sonic wave, dealing 2d6 thunder damage and silencing targets for 1 turn.', 'Reflection', 36, 280, 2, '{"trp_mirror_polish"}', '{"x": -932, "y": 1110}', '{"damage": "2d6 thunder", "radius": "5m", "condition": "Silenced", "duration": "1 turn"}', '🔔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c42a7a4c-6575-4296-b7f0-05d93ccef9bf', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_energy_redirection', 'Enerji Yönlendirme', 'Energy Redirection', 'Büyülü bir saldırıyı yakalayarak reaksiyon olarak anında büyücüye veya 15m içindeki başka bir hedefe geri ateşler.', 'Catch a magical attack and instantly fire it back at the caster or another target within 15m as a reaction.', 'Reflection', 44, 390, 3, '{"trp_magic_dispersion"}', '{"x": -1092, "y": 1302}', '{"range": "15m", "mechanics": "Reflects magical attack"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ae4fd2e1-1ead-43d7-86a8-9b03df9d4946', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_vengeful_echo', 'İntikamcı Yankı', 'Vengeful Echo', 'Pasif: Bir düşman sana ne zaman kritik vuruş yapsa, kalkanların misilleme olarak onları 3d10 güç hasarıyla otomatik olarak patlatır.', 'Passive: Whenever an enemy critically hits you, your shields automatically blast them with 3d10 force damage in retaliation.', 'Reflection', 54, 450, 3, '{"trp_rebound_strike"}', '{"x": -1253, "y": 1493}', '{"damage": "3d10 force", "mechanics": "Triggers on critical hit taken"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a2a4af4-f808-4410-9f31-a7f5d2b4fb35', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_blinding_flash', 'Kör Eden Flaş', 'Blinding Flash', 'Kalkanlarına ışık odaklar ve dışarı patlatır. Sana bakan 10m içindeki tüm düşmanlar kurtarma atışı yapmalı aksi takdirde 2 tur kör olurlar.', 'Channels light into your shields and bursts it outward. All enemies within 10m looking at you must save or be blinded for 2 turns.', 'Reflection', 60, 500, 3, '{"trp_resonant_shield"}', '{"x": -1414, "y": 1685}', '{"radius": "10m", "condition": "Blinded", "duration": "2 turns"}', '☀️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2fc573c1-540e-494b-82cd-8b2a143f87c7', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_perfect_parry', 'Kusursuz Savuşturma', 'Perfect Parry', 'Kısa dinlenme başına bir kez, gücü ne olursa olsun tek bir fiziksel veya büyülü saldırının hasarını ve etkilerini tamamen sıfırlar.', 'Once per short rest, completely negate the damage and effects of a single physical or magical attack, regardless of power.', 'Reflection', 66, 680, 4, '{"trp_energy_redirection"}', '{"x": -1574, "y": 1876}', '{"mechanics": "Negates one attack completely", "limit": "Once per short rest"}', '✋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a749acde-0b1d-48fc-806d-268c834184c9', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_kinetic_discharge', 'Kinetik Deşarj', 'Kinetic Discharge', 'Biriken tüm savaş enerjisini 8m''lik bir şok dalgasıyla serbest bırakır, 6d8 güç hasarı verir ve düşmanları 4m geriye fırlatır.', 'Releases all accumulated battle energy in a 8m shockwave, dealing 6d8 force damage and throwing enemies 4m backwards.', 'Reflection', 76, 820, 4, '{"trp_vengeful_echo"}', '{"x": -1735, "y": 2068}', '{"damage": "6d8 force", "radius": "8m", "push": "4m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9b802ebb-c17a-444f-ac2a-0cfe5eddedce', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_mirror_dimension', 'Ayna Boyutu', 'Mirror Dimension', '10m içindeki bir hedefi 1 dakika boyunca yansıtıcı kalkanlardan oluşan bir kafese hapseder. İçerideyken kendi saldırılarına eşit hasar alırlar.', 'Trap a target within 10m inside a cage of reflective shields for 1 minute. They take damage equal to their own attacks while inside.', 'Reflection', 86, 1150, 5, '{"trp_perfect_parry"}', '{"x": -1896, "y": 2259}', '{"range": "10m", "duration": "1 minute", "mechanics": "Target takes damage equal to their own attacks"}', '🪩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c765e57f-d0af-4340-91a9-43b8d59c2616', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_aegis_of_reflection', 'Yansıma Kalkanı', 'Aegis of Reflection', '3 tur boyunca, sana veya 5m içindeki dostlarına yöneltilen tüm büyülü ve fiziksel saldırılar iki kat hasarla kaynağına geri yansıtılır.', 'For 3 turns, all magical and physical attacks aimed at you or allies within 5m are reflected back to their source with double damage.', 'Reflection', 96, 1450, 5, '{"trp_mirror_dimension", "trp_kinetic_discharge"}', '{"x": -2056, "y": 2451}', '{"radius": "5m", "duration": "3 turns", "mechanics": "Reflects attacks with 200% damage"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07a77f5d-f813-4794-aeaf-8fbc2e4b4efc', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_bouncing_bastion', 'Seken Tabya', 'Bouncing Bastion', '10m''ye kadar uzaktaki bir dosta sekerek ona 1d8 geçici Can veren ve ardından bir düşmana sekerek 2d6 hasar veren bir kalkan fırlatır.', 'Throws a shield that bounces to an ally up to 10m away, granting them 1d8 temporary HP, before bouncing to an enemy for 2d6 damage.', 'Cross-Branch', 26, 230, 2, '{"trp_shield_boomerang", "trp_cover_ally"}', '{"x": -173, "y": -100}', '{"range": "10m", "buff": "1d8 Temp HP", "damage": "2d6"}', '💚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5a59de87-67d5-4fd6-93ef-96cdcd495a2e', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_reflecting_wall', 'Yansıtan Duvar', 'Reflecting Wall', '3m genişliğinde bir duvar yaratan bir kalkan sabitler. Duvara çarpan her menzilli saldırı saldırgana geri yansıtılır.', 'Plants a shield that creates a 3m wide wall. Any ranged attack hitting the wall is reflected back toward the attacker.', 'Cross-Branch', 34, 270, 2, '{"trp_shield_wall", "trp_deflect"}', '{"x": -389, "y": -225}', '{"dimension": "3m wide", "mechanics": "Reflects ranged attacks"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9a04ee45-fff6-420a-b9ab-913120b7a120', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_boomerang_parry', 'Bumerang Savuşturması', 'Boomerang Parry', 'Geri dönen kalkanın, arkadan sana yöneltilmiş bir saldırının önüne otomatik olarak geçerek arkana +2 Zırh Sınıfı verir.', 'Your returning shield automatically intercepts one attack aimed at you from behind, granting +2 AC to your rear.', 'Cross-Branch', 39, 300, 2, '{"trp_shield_boomerang", "trp_kinetic_absorb"}', '{"x": -606, "y": -350}', '{"buff": "+2 AC to rear", "mechanics": "Intercepts one rear attack"}', '🔙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fa690517-e957-40f2-8adb-eb7f1bd4cacd', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_orbiting_fortress', 'Yörünge Kalesi', 'Orbiting Fortress', 'Yörüngendeki kalkanlar 4m yarıçapa genişler. Yörünge içindeki dostlar +2 Zırh Sınıfı ve kesici hasara direnç kazanır.', 'Your orbiting shields expand to a 4m radius. Allies inside the orbit gain +2 AC and resistance to slashing damage.', 'Cross-Branch', 48, 410, 3, '{"trp_orbiting_guard", "trp_fortress_stance"}', '{"x": -822, "y": -475}', '{"radius": "4m", "buff": "+2 AC, Slashing Resistance"}', '🪐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0345f2af-e17b-439e-9f5f-75c9df79b86c', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_absorb_and_throw', 'Em ve Fırlat', 'Absorb and Throw', 'Elementsel bir büyüyü emerek enerjisini kalkanına yerleştirir. Bir sonraki kalkan fırlatışın o elementten fazladan 4d6 hasar verir.', 'Absorbs an elemental spell, embedding its energy into your shield. Your next shield throw deals an extra 4d6 of that element.', 'Cross-Branch', 55, 460, 3, '{"trp_heavy_ricochet", "trp_rebound_strike"}', '{"x": -1039, "y": -600}', '{"damage": "+4d6 elemental", "mechanics": "Absorbs elemental spell"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('01072628-5a47-489f-8ccd-f51edaf4dbdc', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_magnetic_reflection', 'Manyetik Yansıma', 'Magnetic Reflection', '10m yarıçapındaki tüm serseri mermileri manyetik olarak kalkanlarına çeker, ardından 5m''lik bir alan etkisinde şiddetle dışarı iterek 4d8 hasar verir.', 'Magnetically draws all stray projectiles in a 10m radius to your shields, then violently repels them outward in a 5m AoE, dealing 4d8 damage.', 'Cross-Branch', 59, 490, 3, '{"trp_magnetic_pull", "trp_magic_dispersion"}', '{"x": -1255, "y": -725}', '{"radius": "10m pull, 5m blast", "damage": "4d8"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1df2cb6b-c6ba-4096-ac99-c2e84c61b920', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_triple_guard_stance', 'Üçlü Koruma Duruşu', 'Triple Guard Stance', 'Üstün bir savunma duruşuna geçer. Aynı anda üç yönden savunma yaparak kuşatılmayı yok sayar ve tüm kurtarma atışlarına +5 kazanırsın.', 'Enters a supreme defensive stance. You block in three directions simultaneously, ignoring flanking and gaining +5 to all saves.', 'Cross-Branch', 69, 720, 4, '{"trp_triple_meteor", "trp_impenetrable_phalanx"}', '{"x": -1472, "y": -850}', '{"buff": "+5 Saving Throws, immunity to flanking"}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8c9c5245-6ffa-4de0-9bf9-80267783966a', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_kinetic_entrenchment', 'Kinetik Mevzi', 'Kinetic Entrenchment', 'Siper almışken, kalkanlarına isabet eden her saldırı yük biriktirir. 3 vuruştan sonra otomatik olarak 5d10 güç hasarı veren 15m''lik bir şok dalgası yayar.', 'While entrenched, every attack that hits your shields builds charge. After 3 hits, it automatically releases a 15m shockwave for 5d10 force damage.', 'Cross-Branch', 74, 780, 4, '{"trp_entrench", "trp_kinetic_discharge"}', '{"x": -1688, "y": -975}', '{"damage": "5d10 force", "radius": "15m", "mechanics": "Triggers after 3 hits"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3e002522-1c84-4e1d-838b-dfd02f9e3fa4', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_whirlwind_reflector', 'Yansıtıcı Hortum', 'Whirlwind Reflector', 'Çelik Hortumu kullanırken, hortuma temas eden tüm büyü ve fiziksel saldırılar 15m''ye kadar rastgele bir şekilde şiddetle saptırılır.', 'While using Whirlwind of Steel, all magic and physical attacks that touch the whirlwind are violently deflected randomly up to 15m away.', 'Cross-Branch', 79, 860, 4, '{"trp_whirlwind_of_steel", "trp_perfect_parry"}', '{"x": -1905, "y": -1100}', '{"range": "15m reflect", "mechanics": "Randomly deflects all attacks"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('67724c11-da9d-4b3c-9efb-69a48a84dd57', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_three_headed_hydra', 'Üç Başlı Hidra', 'Three-Headed Hydra', '1 dakika boyunca üç kalkandan oluşan spektral bir hidra projeksiyonu çağırır. 5m içindeki düşmanları ısırarak 3d10 hasar verir ve dostları +3 Zırh Sınıfı ile savunur.', 'Summons a spectral hydra projection made of three shields for 1 minute. It bites enemies for 3d10 damage and defends allies for +3 AC within 5m.', 'Cross-Branch', 80, 900, 4, '{"trp_triple_meteor", "trp_bastion_of_hope", "trp_perfect_parry"}', '{"x": -2121, "y": -1225}', '{"duration": "1 minute", "damage": "3d10", "buff": "+3 AC within 5m"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca09849b-206e-4fca-8183-d4b50d252d2b', '22ae70c4-aef6-46fc-a142-86ef09dcef23', 'trp_grand_rampart_trinity', 'Büyük Üçlü Sur', 'Grand Rampart Trinity', 'Üçlü Surların nihai tekniği. Üç kalkanı 3 tur boyunca tepende devasa yüzen bir kaleye dönüştürür. Tur başına 10d10 hasar veren kalkan meteorları yağdırır, 30m içindeki tüm dostlara tam hasar bağışıklığı verir ve 8. seviye veya daha düşük tüm büyüleri yansıtır.', 'The ultimate technique of the Triple Ramparts. Merges three shields into a colossal floating fortress above you for 3 turns. It rains down shield-meteors dealing 10d10 damage per turn, grants all allies within 30m complete damage immunity, and reflects any spell level 8 or lower.', 'Cross-Branch', 100, 1500, 5, '{"trp_tri_shield_avalanche", "trp_absolute_defense", "trp_aegis_of_reflection"}', '{"x": -2338, "y": -1350}', '{"duration": "3 turns", "damage": "10d10 per turn", "buff": "Immunity within 30m", "mechanics": "Reflects level 8 or lower spells"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('be89b8b0-c5ce-4ce6-be6a-338caabb3cfa', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_shield_wall', 'Kalkan Duvarı', 'Shield Wall', 'Pozisyonunu güçlendirerek +2 Zırh Sınıfı ve %15 bloklama şansı bonusu kazanırsın.', 'Fortify your position, gaining +2 AC and a 15% bonus to your block chance.', 'Bulwark', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"ac": "+2", "block_chance": "+15%"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('01f7df5e-6007-4061-b061-15055eb5c801', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_taunting_strike', 'Kışkırtıcı Vuruş', 'Taunting Strike', 'Düşmanına kalkanınla vurarak 1d8 ezici hasar verir ve onu 2 tur boyunca seni hedef almaya zorlarsın.', 'Hit an enemy with your shield for 1d8 bludgeoning damage, forcing them to target you for 2 turns.', 'Bulwark', 3, 60, 1, '{}', '{"x": 389, "y": -224}', '{"damage": "1d8 bludgeoning", "duration": "2 turns"}', '📢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('631b0213-1919-4daf-82fe-5afcb25b108a', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_iron_stance', 'Demir Duruş', 'Iron Stance', 'Olduğun yere kök salarak hareketsiz kaldığın sürece alınan tüm hasarı %20 azaltırsın.', 'Root yourself in place, reducing all incoming damage by 20% while you remain stationary.', 'Bulwark', 7, 80, 1, '{}', '{"x": 606, "y": -349}', '{"damage_reduction": "20%"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('86fcdf3c-f5e4-4280-91bb-6b954c19bba3', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_fortified_armor', 'Güçlendirilmiş Zırh', 'Fortified Armor', 'Pasif: Sıkı eğitimin sana +15 Maksimum Can ve kalıcı olarak +2 Zırh Sınıfı kazandırır.', 'Passive: Your rigorous training grants +15 Maximum HP and a permanent +2 to AC.', 'Bulwark', 12, 100, 1, '{}', '{"x": 822, "y": -474}', '{"max_hp": "+15", "ac": "+2"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d5efd445-0343-41af-873f-f715f9bb6b53', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_phalanx_formation', 'Falanks Düzeni', 'Phalanx Formation', '5m içindeki müttefiklerin %15 bloklama şansı kazanır ve kalkanını siper olarak kullanabilirler.', 'Allies within 5m of you gain a +15% block chance and can use your shield for cover.', 'Bulwark', 21, 180, 2, '{"twr_shield_wall"}', '{"x": 1039, "y": -599}', '{"block_chance": "+15%", "radius": "5m"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7f41c985-785b-4310-b07c-944ed511bbc8', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_ignore_pain', 'Acıya Tahammül', 'Ignore Pain', 'İradeni güçlendirerek anında 20 Geçici Can kazanırsın.', 'Harden your resolve to instantly gain 20 Temporary HP.', 'Bulwark', 25, 200, 2, '{"twr_iron_stance"}', '{"x": 1255, "y": -724}', '{"temp_hp": "20"}', '🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9cc69a52-d8fa-4bd9-b1bc-293ba2c1c34a', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_unbreakable_guard', 'Kırılamaz Siper', 'Unbreakable Guard', '3 tur boyunca kritik vuruşlara karşı tamamen bağışıklık kazanırsın.', 'For 3 turns, you become completely immune to critical hits.', 'Bulwark', 35, 250, 2, '{"twr_fortified_armor"}', '{"x": 1472, "y": -849}', '{"immune_crit": "true", "duration": "3 turns"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1c4900af-feee-40ae-b0d5-143244a2fc5b', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_aegis_aura', 'Himaye Halesi', 'Aegis Aura', '10m içindeki müttefiklerin aldığı tüm hasarı %10 azaltan koruyucu bir hale yayarsın.', 'Radiate a protective aura that reduces all damage taken by allies within 10m by 10%.', 'Bulwark', 42, 360, 3, '{"twr_phalanx_formation"}', '{"x": 1688, "y": -974}', '{"damage_reduction": "10%", "radius": "10m"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8cc7075-3c25-483d-bbf3-94f1564ffca7', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_immovable_object', 'Sarsılmaz Nesne', 'Immovable Object', 'Pasif: Geri savurma, çekme, yakalanma ve zorunlu hareket etkilerine bağışıklık kazanırsın.', 'Passive: You become immune to knockbacks, hooks, grapples, and forced movement.', 'Bulwark', 48, 400, 3, '{"twr_ignore_pain"}', '{"x": 1905, "y": -1099}', '{"immune_knockback": "true"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1279b7a1-df15-4121-9212-68cfe2ccc7df', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_last_bastion', 'Son Kale', 'Last Bastion', 'Canın %20''nin altına düştüğünde otomatik olarak 50 Canlık koruyucu bir kalkan üretirsin.', 'When your HP drops below 20%, automatically generate a 50 HP protective shield.', 'Bulwark', 55, 450, 3, '{"twr_unbreakable_guard"}', '{"x": 2121, "y": -1224}', '{"shield": "50 HP"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bc6325da-90f4-4582-aa9b-8524ea2e2ec3', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_colossus_avatar', 'Dev Avatarı', 'Colossus Avatar', 'Bir boyut kategorisi büyüyerek Maksimum Canını 40 artırır ve +3 Zırh Sınıfı kazanırsın.', 'Grow by one size category, increasing Max HP by 40 and gaining +3 AC.', 'Bulwark', 62, 650, 4, '{"twr_immovable_object"}', '{"x": 2338, "y": -1349}', '{"max_hp": "+40", "ac": "+3"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81edd227-e8d5-4a88-a3b5-f6d31e5a171c', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_mass_provocation', 'Kitlesel Kışkırtma', 'Mass Provocation', '15m yarıçapındaki tüm düşmanları sana saldırmaya kışkırtan bir savaş çığlığı atarsın.', 'Emit a warcry that taunts all enemies within a 15m radius to attack you.', 'Bulwark', 68, 700, 4, '{"twr_aegis_aura"}', '{"x": 2554, "y": -1474}', '{"taunt_radius": "15m"}', '🤬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ef9d058f-1b9c-4520-bc7f-bfaf8001af17', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_steadfast_defender', 'Metanetli Savunmacı', 'Steadfast Defender', 'Pasif: Bir saldırıyı her başarıyla blokladığında Maksimum Canının %5''i kadar iyileşirsin.', 'Passive: Every time you successfully block an attack, you heal 5% of your Maximum HP.', 'Bulwark', 75, 800, 4, '{"twr_last_bastion"}', '{"x": 2771, "y": -1599}', '{"heal": "5% max hp"}', '🐢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2440e059-551e-4aa7-a8a8-a11b4d0705ed', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_living_fortress_ult', 'Yaşayan Kale', 'The Living Fortress', 'Ulti: 5 tur boyunca 20m içindeki müttefiklerin aldığı tüm hasarı kendine yönlendirir ve bu transfer edilen hasarı %80 azaltırsın.', 'Ultimate: For 5 turns, redirect all damage taken by allies within 20m to yourself, reducing the transferred damage by 80%.', 'Bulwark', 90, 1200, 5, '{"twr_colossus_avatar", "twr_mass_provocation"}', '{"x": 2987, "y": -1724}', '{"damage_reduction": "80%", "duration": "5 turns", "radius": "20m"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e6cb58bf-5b4e-442f-a6e8-20c414c4795b', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_shield_bash', 'Kalkan Vuruşu', 'Shield Bash', 'Kalkanınla güçlü bir şekilde vurarak 1d10 ezici hasar verir ve hedefi 2m geri itersin.', 'Strike forcefully with your shield, dealing 1d10 bludgeoning damage and pushing the target 2m.', 'Counter', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "1d10 bludgeoning", "push": "2m"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fcfae79c-956e-4d82-b71d-07b081f475b0', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_spiked_defense', 'Dikenli Savunma', 'Spiked Defense', 'Sana yakın dövüş saldırısı yapan herkese 1d6 delici hasar yansıtan savunmacı bir duruş sergilersin.', 'Adopt a defensive posture that returns 1d6 piercing damage to anyone hitting you with a melee attack.', 'Counter', 4, 65, 1, '{}', '{"x": 289, "y": 344}', '{"reflect_damage": "1d6 piercing"}', '🦔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('320f20e2-5c4b-4cdb-89d8-dbf2614d0362', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_reactive_strike', 'Tepkisel Vuruş', 'Reactive Strike', '3m içindeki bir müttefik vurulduğunda anında 1d10 hasar veren bir fırsat saldırısı yaparsın.', 'When an ally within 3m is hit, you immediately make an attack of opportunity dealing 1d10 damage.', 'Counter', 8, 85, 1, '{}', '{"x": 449, "y": 536}', '{"damage": "1d10", "radius": "3m"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0364e2d5-4d5f-4f5d-853b-b8e1cf8138b7', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_perfect_parry', 'Kusursuz Savuşturma', 'Perfect Parry', 'Bir saldırıyı tam zamanında bloklayarak hasarı tamamen sıfırlar ve saldırganı 1 tur sersemletirsin.', 'Perfectly time a block to completely nullify the attack and stun the attacker for 1 turn.', 'Counter', 14, 110, 1, '{}', '{"x": 610, "y": 727}', '{"stun": "1 turn"}', '⏱️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c0690684-2521-4c29-8c5b-6c1e778d50e8', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_shield_charge', 'Kalkan Hücumu', 'Shield Charge', '10m ileri atılarak düşmanlara çarpar, 2d8 hasar verir ve onları yere serersin.', 'Dash up to 10m forward, slamming into enemies for 2d8 damage and knocking them prone.', 'Counter', 22, 185, 2, '{"twr_shield_bash"}', '{"x": 771, "y": 919}', '{"damage": "2d8", "dash": "10m", "status": "prone"}', '🏈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94d36573-9042-4eed-bc5a-c3645402edf8', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_deflecting_spin', 'Yansıtıcı Dönüş', 'Deflecting Spin', 'Hızla dönerek 5m yarıçapındaki tüm fiziksel mermileri saldırganlara geri yansıtırsın.', 'Spin rapidly, reflecting all physical projectiles within a 5m radius back at their attackers.', 'Counter', 28, 210, 2, '{"twr_spiked_defense"}', '{"x": 932, "y": 1110}', '{"reflect_projectiles": "true", "radius": "5m"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a312ab78-0556-4cd6-b520-a32bc6438d66', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_vengeful_slam', 'İntikamcı Çarpış', 'Vengeful Slam', '3d8 hasar ve önceki tur aldığın tüm hasarın %50''si kadar ek hasar verirsin.', 'Deal 3d8 damage plus 50% of all the damage you took in the previous turn.', 'Counter', 36, 260, 2, '{"twr_perfect_parry"}', '{"x": 1092, "y": 1302}', '{"damage": "3d8 + 50% taken"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('35224140-e4da-450c-a4cb-78be33420984', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_heavy_counter', 'Ağır Misilleme', 'Heavy Counter', 'Başarılı bir bloklamanın hemen ardından yıkıcı bir güçle karşı saldırı yaparak 4d8 hasar verirsin.', 'Immediately after a successful block, strike back with devastating force, dealing 4d8 damage.', 'Counter', 44, 370, 3, '{"twr_perfect_parry"}', '{"x": 1253, "y": 1493}', '{"damage": "4d8"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('851e045c-ebbc-4233-b640-f25404c53b92', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_seismic_stomp', 'Sismik Ezme', 'Seismic Stomp', 'Yere şiddetle vurarak 8m içindeki düşmanlara 3d6 hasar verir ve onları %50 yavaşlatırsın.', 'Stomp the ground violently, dealing 3d6 damage and slowing enemies within 8m by 50%.', 'Counter', 50, 410, 3, '{"twr_shield_charge"}', '{"x": 1414, "y": 1685}', '{"damage": "3d6", "slow": "50%", "radius": "8m"}', '🥾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2603d27b-b219-41ed-9d2f-df57be59bc32', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_kinetic_absorption', 'Kinetik Emilim', 'Kinetic Absorption', 'Bloklanan hasarı depolar ve 5m''lik bir koni içinde 4d10 kinetik şok dalgası olarak serbest bırakırsın.', 'Store blocked damage and release it as a 4d10 kinetic shockwave in a 5m cone.', 'Counter', 56, 460, 3, '{"twr_deflecting_spin"}', '{"x": 1574, "y": 1876}', '{"damage": "4d10", "cone": "5m"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd921f78-9f53-45c0-9830-3347c8683326', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_shield_guillotine', 'Kalkan Giyotini', 'Shield Guillotine', 'Kalkanının kenarıyla aşağı doğru vurarak hedefe 6d8 kesici hasar verirsin.', 'Strike downwards with the edge of your shield, dealing 6d8 slashing damage to a target.', 'Counter', 64, 660, 4, '{"twr_heavy_counter"}', '{"x": 1735, "y": 2068}', '{"damage": "6d8 slashing"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09706c41-31e2-4d57-bd9a-2547c320f7f4', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_punishing_rebound', 'Cezalandırıcı Sekme', 'Punishing Rebound', 'Pasif: Başarıyla blokladığın tüm hasarın %50''si otomatik olarak saldırgana geri verilir.', 'Passive: 50% of all damage you successfully block is automatically dealt back to the attacker.', 'Counter', 70, 720, 4, '{"twr_kinetic_absorption"}', '{"x": 1896, "y": 2259}', '{"reflect_damage": "50%"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b592a32-dd8a-4928-a9e0-1862eec17598', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_relentless_pursuer', 'Acımasız Takipçi', 'Relentless Pursuer', 'Pasif: Kışkırtılmış bir hedefe karşı Kalkan Hücumu kullanmak aksiyon gerektirmez.', 'Passive: Using Shield Charge against a taunted target costs no action.', 'Counter', 76, 820, 4, '{"twr_seismic_stomp"}', '{"x": 2056, "y": 2451}', '{"cost_reduction": "action"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('98c3ad2e-1a9d-492c-866d-7e66185f9bba', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_absolute_retribution_ult', 'Mutlak İntikam', 'Absolute Retribution', 'Ulti: 3 tur boyunca gelen tüm hasarı %100 bloklar ve saldırganlara gerçek hasar olarak geri yansıtırsın.', 'Ultimate: For 3 turns, you block 100% of all incoming damage and reflect it back to attackers as true damage.', 'Counter', 90, 1200, 5, '{"twr_shield_guillotine", "twr_punishing_rebound"}', '{"x": 2217, "y": 2642}', '{"block": "100%", "reflect_true_damage": "true", "duration": "3 turns"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0e1486d6-1e95-431a-90a3-0446c90a139e', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_twin_shield_stance', 'Çifte Kalkan Duruşu', 'Twin Shield Stance', 'Her iki ele de kalkan kuşanırsın. Saldırıların 2d6 hasar verir ve her iki kalkanın Zırh Sınıfı bonusundan faydalanırsın.', 'Equip a shield in each hand. Your attacks deal 2d6 damage, and you benefit from both shields'' AC bonuses.', 'Dual Shields', 2, 55, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "2d6", "ac_bonus": "both shields"}', '♊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c43c1268-0b2b-42b9-be73-4d72564706aa', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_clashing_plates', 'Çarpışan Plakalar', 'Clashing Plates', 'Çifte kalkanlarını birbirine çarparak 5m içindeki düşmanlara 1d6 gök gürültüsü hasarı verir ve onları sağır edersin.', 'Slam your dual shields together, dealing 1d6 thunder damage and deafening enemies within 5m.', 'Dual Shields', 5, 70, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "1d6 thunder", "deafen": "true", "radius": "5m"}', '🔔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a92d2400-4976-448c-b061-e7a9628e6467', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_momentum_swing', 'İvme Savuruşu', 'Momentum Swing', 'Her iki kalkanın ağırlığını kullanarak 3m''lik bir yay çizer ve isabet alan tüm hedeflere 2d8 hasar verirsin.', 'Use the weight of both shields to swing in a 3m arc, dealing 2d8 damage to all targets hit.', 'Dual Shields', 9, 90, 1, '{}', '{"x": -449, "y": 536}', '{"damage": "2d8", "arc": "3m"}', '⚾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fd61611c-de89-49e1-83c3-000335e1c42f', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_interlocking_guard', 'Kenetlenen Siper', 'Interlocking Guard', 'Kalkanlarını üst üste bindirerek nefes saldırılarına ve alan büyülerine karşı kurtarma zarlarında avantaj kazanırsın.', 'Overlap your shields to gain advantage on saving throws against breath weapons and AoE spells.', 'Dual Shields', 15, 120, 1, '{}', '{"x": -610, "y": 727}', '{"advantage": "aoe and breath"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('875b6a2a-37bf-4f2d-94ee-3db214b8fa82', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_battering_ram', 'Koçbaşı', 'Battering Ram', 'Kenetlenmiş kalkanlarla 15m''ye kadar depar atarak yoluna çıkan tüm düşmanlara 3d8 hasar verirsin.', 'Sprint up to 15m with locked shields, dealing 3d8 damage to any enemy in your path.', 'Dual Shields', 24, 190, 2, '{"twr_momentum_swing"}', '{"x": -771, "y": 919}', '{"damage": "3d8", "sprint": "15m"}', '🐏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71f9c42c-d5f5-4e37-a378-66bbcfecd918', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_pincer_bash', 'Kıskaç Vuruşu', 'Pincer Bash', 'Bir düşmanı her iki kalkanın arasında eşzamanlı ezerek 3d10 hasar verir ve 1 tur sersemletirsin.', 'Crush an enemy simultaneously between both shields for 3d10 damage and a 1-turn stun.', 'Dual Shields', 30, 220, 2, '{"twr_twin_shield_stance"}', '{"x": -932, "y": 1110}', '{"damage": "3d10", "stun": "1 turn"}', '🦞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2e9db9d1-f5bb-493b-90f3-889b4248c076', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_shield_skater', 'Kalkan Kaykaycısı', 'Shield Skater', 'Bir kalkanı yere atıp üzerinde kayarak hareket hızını tur başına 10m artırırsın.', 'Drop one shield and slide on it, increasing your movement speed by 10m per turn.', 'Dual Shields', 38, 270, 2, '{"twr_clashing_plates"}', '{"x": -1092, "y": 1302}', '{"move_speed": "+10m"}', '🛹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d679edd7-01b9-4ac6-845e-1d5a93039ed1', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_flying_disc', 'Uçan Disk', 'Flying Disc', 'Kalkanlarından birini 15m''ye kadar fırlatıp 3d8 hasar verirsin, kalkan mucizevi bir şekilde eline geri döner.', 'Throw one of your shields up to 15m, dealing 3d8 damage before it miraculously returns to your hand.', 'Dual Shields', 45, 380, 3, '{"twr_momentum_swing"}', '{"x": -1253, "y": 1493}', '{"damage": "3d8", "range": "15m"}', '🛸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d6976bb-5fdc-4dbe-9f00-e56ef05615d7', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_cyclone_of_steel', 'Çelik Kasırgası', 'Cyclone of Steel', 'Çifte kalkanlarla çılgınca dönerek 4m yarıçapındaki tüm düşmanlara 4d8 hasar verirsin.', 'Spin wildly with dual shields, dealing 4d8 damage to all enemies within a 4m radius.', 'Dual Shields', 52, 420, 3, '{"twr_shield_skater"}', '{"x": -1414, "y": 1685}', '{"damage": "4d8", "radius": "4m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ec9be8d8-3d44-411a-8110-0165bbcfe410', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_dual_ward', 'Çifte Koruma', 'Dual Ward', 'Büyüyü bir kalkanla, fiziksel vuruşları diğeriyle bloklayarak tüm hasar türlerine karşı %30 direnç kazanırsın.', 'Block magic with one shield and physical strikes with the other, granting a flat 30% resistance to all damage types.', 'Dual Shields', 58, 480, 3, '{"twr_interlocking_guard"}', '{"x": -1574, "y": 1876}', '{"resistance": "30%", "block_types": "magic and physical"}', '☯️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cf4be7e9-7424-48a6-a79c-9895f1e7fc8c', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_meteor_crash', 'Meteor Çarpıntısı', 'Meteor Crash', '15m''ye kadar sıçrayıp her iki kalkanı da yere çarparak 6m yarıçapında 6d10 hasar verirsin.', 'Leap up to 15m and slam both shields into the earth, dealing 6d10 damage in a 6m radius.', 'Dual Shields', 65, 680, 4, '{"twr_battering_ram"}', '{"x": -1735, "y": 2068}', '{"damage": "6d10", "leap": "15m", "radius": "6m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('68497236-52a8-4f67-89fa-4e89a013aa83', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_unstoppable_juggernaut', 'Durdurulamaz Yıkıcı', 'Unstoppable Juggernaut', 'Koşarken veya hücum ederken tüm kitle kontrol etkilerine karşı tamamen bağışıklık kazanırsın.', 'While sprinting or charging, you become completely immune to all crowd control effects.', 'Dual Shields', 72, 750, 4, '{"twr_cyclone_of_steel"}', '{"x": -1896, "y": 2259}', '{"immune_cc": "true", "condition": "sprinting"}', '🚂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1583d577-7e4b-417c-932a-aa72b8585b40', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_twin_dragon_breath', 'İkiz Ejderha Nefesi', 'Twin Dragon Breath', 'İkiz kalkanlarından saf büyü enerjisi yönlendirerek 15m''lik bir ateş konisi salar ve 8d8 hasar verirsin.', 'Channel raw magical energy through your twin shields to unleash a 15m cone of fire, dealing 8d8 damage.', 'Dual Shields', 78, 850, 4, '{"twr_dual_ward"}', '{"x": -2056, "y": 2451}', '{"damage": "8d8 fire", "cone": "15m"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('be17513b-58ac-4f35-bea7-b2c7f87b26e4', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_twin_ramparts_ult', 'İkiz Surlar Ustalığı', 'Twin Ramparts Mastery', 'Ulti: Kalkanların devasa boyutlara ulaşır. Sürekli 5d8 alan hasarı verir, zayıflatıcılara bağışıklık kazanır ve bonus aksiyon olarak saldırabilirsin.', 'Ultimate: Your shields grow massive. You deal continuous 5d8 AoE damage, become immune to conditions, and can attack as a bonus action.', 'Dual Shields', 90, 1200, 5, '{"twr_meteor_crash", "twr_unstoppable_juggernaut"}', '{"x": -2217, "y": 2642}', '{"damage": "5d8 aoe", "immune_conditions": "true", "bonus_action_attack": "true"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('17ee8396-06aa-412b-856f-9996004371eb', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_retaliatory_guard', 'Misilleme Siperi', 'Retaliatory Guard', 'Kışkırtılmış düşmanlar sana her vurduğunda 2d6 delici hasar alır.', 'Taunted enemies take 2d6 piercing damage every time they land a hit on you.', 'Counter', 35, 280, 2, '{"twr_taunting_strike", "twr_spiked_defense"}', '{"x": 2378, "y": 2834}', '{"damage": "2d6 piercing"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84e5fd91-cbcf-4e72-9af4-cf0b6b4f3dce', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_ricochet_bash', 'Seken Vuruş', 'Ricochet Bash', 'Fırlattığın kalkan 3 düşmana kadar sekerek her birine 3d8 hasar verir ve karşı saldırı etkilerini uygular.', 'Your thrown shield bounces to up to 3 enemies, dealing 3d8 damage to each and applying counter-attack effects.', 'Dual Shields', 50, 430, 3, '{"twr_flying_disc", "twr_shield_bash"}', '{"x": -2378, "y": 2834}', '{"damage": "3d8", "bounces": "3"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('05c611ff-07cf-4890-81eb-539193b58c32', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_mobile_fortress', 'Hareketli Kale', 'Mobile Fortress', 'Demir Duruş halindeyken %20 hasar azaltmasını koruyarak normal hızda hareket edebilirsin.', 'You can move at normal speed while in Iron Stance, keeping the 20% damage reduction active.', 'Bulwark', 55, 470, 3, '{"twr_iron_stance", "twr_shield_skater"}', '{"x": 3204, "y": -1849}', '{"move_speed": "normal", "damage_reduction": "20%"}', '🚚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cdd7312e-dff4-4510-9e3f-fa47e9e8cba6', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_absorbing_bastion', 'Emen İstihkâm', 'Absorbing Bastion', 'Dikenli Savunma tarafından başarıyla yansıtılan hasarın %100''ü kadar kendini iyileştirirsin.', 'Heal yourself for 100% of the damage successfully reflected by your Spiked Defense.', 'Counter', 75, 800, 4, '{"twr_punishing_rebound", "twr_last_bastion"}', '{"x": 2539, "y": 3025}', '{"heal": "100% reflected damage"}', '🧛');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('52986fe0-b998-437a-b8bb-ab1dba3b531e', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_devastating_clap', 'Yıkıcı Çarpma', 'Devastating Clap', 'Kıskaç Vuruşun kinetik enerjiyi depolayarak ek 5d10 alan hasarı veren patlayıcı bir şok dalgası yaratır.', 'Your Pincer Bash stores kinetic energy, creating a shockwave that explodes for an additional 5d10 AoE damage.', 'Dual Shields', 78, 850, 4, '{"twr_pincer_bash", "twr_kinetic_absorption"}', '{"x": -2539, "y": 3025}', '{"damage": "5d10 aoe"}', '👏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5945fa71-833e-4c4d-aa08-6808249ff6a5', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_aegis_of_the_twins', 'İkizlerin Himayesi', 'Aegis of the Twins', '2 tur boyunca 30m yarıçapındaki tüm mermileri engelleyen devasa ruhanî kalkanlar yansıtırsın.', 'Project massive ethereal shields that block all incoming projectiles in a 30m radius for 2 turns.', 'Bulwark', 85, 1100, 5, '{"twr_mass_provocation", "twr_twin_dragon_breath"}', '{"x": 3420, "y": -1974}', '{"block_projectiles": "true", "radius": "30m", "duration": "2 turns"}', '👐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('00df09dc-2df7-4009-80a8-3fb016b7d0c5', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_judgment_spin', 'Hüküm Dönüşü', 'Judgment Spin', 'Çelik Kasırgası artık isabet ettiği tüm büyüleri ve mermileri kusursuzca atanlara geri yansıtır.', 'Cyclone of Steel now perfectly reflects all spells and projectiles it hits back to the casters.', 'Dual Shields', 88, 1150, 5, '{"twr_cyclone_of_steel", "twr_deflecting_spin"}', '{"x": -2699, "y": 3217}', '{"reflect_all": "true"}', '🎡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bfe2cd97-d921-45a0-b0c9-233d5873558f', '39c8f2d9-50a5-4e8f-8ab3-d2b69271c7c2', 'twr_indomitable_mountain_ult', 'Boyun Eğmez Dağ', 'The Indomitable Mountain', 'Görkemli Ulti: İkiz kalkanlarını aşılamaz bir duvarda birleştir. Tüm grubun 3 tur boyunca hasar görmezlik kazanır, sen %100 iyileşirsin ve gelen tüm küresel hasarı yansıtırsın.', 'Grand Ultimate: Merge your twin shields into an unbreachable wall. Your entire party gains invulnerability for 3 turns, you heal to 100%, and reflect all global incoming damage.', 'Bulwark', 100, 1500, 5, '{"twr_living_fortress_ult", "twr_absolute_retribution_ult", "twr_twin_ramparts_ult"}', '{"x": 3637, "y": -2099}', '{"invulnerable": "3 turns", "heal": "100%", "reflect_global": "true"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('39518e8f-a835-4d3e-81c2-c7f5de9fa3dc', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_shield_bash', 'Kalkan Darbesi', 'Shield Bash', 'Kalkanınızı bir düşmana çarparak 1d6 ezme hasarı verin ve onları 2 metre geriye itin.', 'Smash your shield into an enemy, dealing 1d6 bludgeoning damage and knocking them back 2 meters.', 'Shield Wall', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d6", "knockback": "2m"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('847210b3-5026-4e69-be06-24759ba92602', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_phalanx_stance', 'Falanks Duruşu', 'Phalanx Stance', 'Bir savunma duruşu alarak kalkan tutarken 3 tur boyunca +2 ZS kazanın.', 'Adopt a defensive stance, gaining +2 AC for 3 turns while holding a shield.', 'Shield Wall', 5, 80, 1, '{"vg_shield_bash"}', '{"x": 389, "y": -224}', '{"ac_bonus": "+2", "duration": "3 turns"}', '🧱');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ed63ae6c-b565-439f-bd8a-2cc7347cc63c', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_warding_light', 'Koruyucu Işık', 'Warding Light', '10 metre uzağa bir ışık huzmesi yansıtarak bir müttefike 2 tur boyunca +2 ZS kazandırın.', 'Project a beacon of light 10 meters away, granting an ally +2 AC for 2 turns.', 'Shield Wall', 12, 120, 1, '{"vg_phalanx_stance"}', '{"x": 606, "y": -349}', '{"range": "10m", "ac_bonus": "+2", "duration": "2 turns"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46468f3a-0a61-4858-84ff-d9634a2fcee5', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_take_the_blow', 'Darbeyi Üstlenme', 'Take the Blow', '5 metre içindeki bir müttefike yönelik bir saldırının arasına girerek hasarın yarısını siz alın.', 'Intercept an attack meant for an ally within 5 meters, taking half of the damage yourself instead.', 'Sacrifice', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "5m", "damage_reduction": "50%"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d17a153f-9121-480f-9fab-e2999fda021a', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_life_tether', 'Yaşam Bağı', 'Life Tether', '10 metre içindeki bir müttefikle mistik bir bağ kurarak aldıkları herhangi bir hasarın %25''ini 3 tur boyunca kendinize aktarın.', 'Create a mystical link with an ally within 10 meters, transferring 25% of any damage they take to you for 3 turns.', 'Sacrifice', 6, 90, 1, '{"vg_take_the_blow"}', '{"x": 289, "y": 344}', '{"range": "10m", "damage_transfer": "25%", "duration": "3 turns"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5ac23727-23b6-4db6-8f4f-5b39c8f91890', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_martyrs_blood', 'Şehit Kanı', 'Martyr''s Blood', 'Kendi Can Puanınızdan 10 feda ederek bir müttefiki 20 CP iyileştirin. Menzil 5 metre.', 'Sacrifice 10 of your own HP to heal an ally for 20 HP. Range 5 meters.', 'Sacrifice', 15, 130, 1, '{"vg_life_tether"}', '{"x": 449, "y": 536}', '{"cost": "10 HP", "heal": "20 HP", "range": "5m"}', '❤️‍🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('81a72696-9a06-463c-9dd3-7e55a129e6e7', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_iron_skin', 'Demir Deri', 'Iron Skin', 'Etinizi sertleştirerek 3 tur boyunca +3 ZS kazanın.', 'Harden your flesh, gaining +3 AC for 3 turns.', 'Fortification', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"ac_bonus": "+3", "duration": "3 turns"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('06a2455e-e1ef-4be7-91d4-65714967cff0', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_endurance_boost', 'Dayanıklılık Artışı', 'Endurance Boost', 'İçsel dayanıklılığınızı yönlendirerek anında 15 Geçici Can Puanı kazanın.', 'Channel your inner stamina to immediately gain 15 Temporary HP.', 'Fortification', 7, 100, 1, '{"vg_iron_skin"}', '{"x": -289, "y": 344}', '{"temp_hp": 15}', '💪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dbe20c03-9a00-4228-b49c-4f7b5e8b8f5c', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_steeled_mind', 'Çelik Zihin', 'Steeled Mind', 'Bilincinizi güçlendirerek 10 dakika boyunca tüm zihinsel kurtarma zarlarına +2 bonus kazanın.', 'Fortify your consciousness, granting yourself a +2 bonus to all mental saving throws for 10 minutes.', 'Fortification', 18, 140, 1, '{"vg_endurance_boost"}', '{"x": -449, "y": 536}', '{"saving_throw_bonus": "+2", "duration": "10 mins"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('08f0bdc8-3a6c-4cb3-a95c-abb9130c1bdc', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_barrier_wave', 'Bariyer Dalgası', 'Barrier Wave', 'Kalkanınızı ileri doğru iterek 5 metrelik bir koni içinde 2d6 güç hasarı veren ve düşmanları 3 metre geriye iten bir kuvvet dalgası gönderin.', 'Push your shield forward, sending a wave of force in a 5-meter cone that deals 2d6 force damage and pushes enemies back 3 meters.', 'Shield Wall', 22, 200, 2, '{"vg_warding_light"}', '{"x": 822, "y": -474}', '{"area": "5m cone", "damage": "2d6", "knockback": "3m"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('627884ba-8606-4182-b195-016fdf4fa15c', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_shield_charge', 'Kalkan Hücumu', 'Shield Charge', 'Düz bir çizgide 10 metreye kadar ileri atılarak 3d6 ezme hasarı verin ve vurulan ilk düşmanı yere serin.', 'Dash up to 10 meters forward in a straight line, dealing 3d6 bludgeoning damage and knocking the first enemy struck prone.', 'Shield Wall', 28, 230, 2, '{"vg_barrier_wave"}', '{"x": 1039, "y": -599}', '{"range": "10m dash", "damage": "3d6", "condition": "prone"}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31b7df9e-8e37-4c3d-85ae-63eabbfcecc3', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_dome_of_protection', 'Koruma Kubbesi', 'Dome of Protection', 'Kendinizin etrafında 5 metre yarıçapında bir kubbe oluşturun. İçerideki müttefikler +4 ZS kazanır. 2 tur sürer.', 'Conjure a 5-meter radius dome around yourself. Allies inside gain +4 AC. Lasts 2 turns.', 'Shield Wall', 36, 280, 2, '{"vg_shield_charge"}', '{"x": 1255, "y": -724}', '{"radius": "5m", "ac_bonus": "+4", "duration": "2 turns"}', '⛺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('22dbdad4-f140-485a-85ae-246a8857d5a1', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_pain_sharing', 'Acı Paylaşımı', 'Pain Sharing', '10 metre içindeki bir müttefik vurulduğunda, hasarı kendiniz ve menzil içindeki gönüllü müttefikler arasında eşit olarak dağıtın.', 'When an ally within 10 meters is hit, distribute the damage equally among yourself and any willing allies within range.', 'Sacrifice', 23, 210, 2, '{"vg_martyrs_blood"}', '{"x": 610, "y": 727}', '{"range": "10m", "damage_distribution": "equal"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1fc83c30-c2bd-49aa-bd67-6ce7424bcba0', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_guardian_leap', 'Muhafız Atlayışı', 'Guardian Leap', '15 metreye kadar sıçrayarak bir müttefikin yanına gidin ve 1 tur içinde onlara yöneltilen ilk saldırıyı otomatik olarak emdirin.', 'Leap up to 15 meters to an ally''s side, automatically absorbing the very next attack directed at them within 1 turn.', 'Sacrifice', 29, 240, 2, '{"vg_pain_sharing"}', '{"x": 771, "y": 919}', '{"range": "15m", "duration": "1 turn", "intercept": "1 attack"}', '🦸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('796e938f-e71b-47bc-b7fa-f60ecbea317e', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_blood_shield', 'Kan Kalkanı', 'Blood Shield', '5 metre içindeki bir müttefik üzerinde 40 Geçici Can Puanlık büyülü bir kalkan oluşturmak için 20 CP harcayın.', 'Spend 20 HP to create a 40 HP temporary magical shield on an ally within 5 meters.', 'Sacrifice', 38, 290, 2, '{"vg_guardian_leap"}', '{"x": 932, "y": 1110}', '{"cost": "20 HP", "temp_hp": "40", "range": "5m"}', '🔴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9510881c-3bbd-4b9d-9904-2af7e13ec424', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_juggernaut_plating', 'Juggernaut Zırhı', 'Juggernaut Plating', 'Zırhınızı güçlendirerek 5 tur boyunca gelen tüm fiziksel hasarı 5 azaltın.', 'Reinforce your armor, reducing all incoming physical damage by 5 for 5 turns.', 'Fortification', 24, 220, 2, '{"vg_steeled_mind"}', '{"x": -610, "y": 727}', '{"damage_reduction": 5, "duration": "5 turns"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('45e07540-5a51-4063-ba3b-6b108a58d23d', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_second_wind', 'İkinci Nefes', 'Second Wind', 'Gizli rezervlerinize erişerek kendinizi anında 3d10 CP iyileştirin.', 'Tap into your hidden reserves to instantly heal yourself for 3d10 HP.', 'Fortification', 32, 260, 2, '{"vg_juggernaut_plating"}', '{"x": -771, "y": 919}', '{"heal": "3d10"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('586e4f3b-1d88-410e-bb60-8b26280fec2e', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_unstoppable_force', 'Durdurulamaz Güç', 'Unstoppable Force', '3 tur boyunca itilmeye, çekilmeye veya yere serilmeye karşı tamamen bağışıklık kazanın.', 'Become completely immune to being pushed, pulled, or knocked prone for 3 turns.', 'Fortification', 40, 300, 2, '{"vg_second_wind"}', '{"x": -932, "y": 1110}', '{"immunity": "push/pull/prone", "duration": "3 turns"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9cd229ee-8c46-448a-9f08-61fd256af3bf', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_shielding_surge', 'Kalkan Dalgası', 'Shielding Surge', 'Savunma enerjisi dalgası salarak 20 Geçici Can Puanı kazanın. Bir sonraki Kalkan Darbeniz fazladan 2d6 hasar verir.', 'Release a surge of defensive energy, gaining 20 Temporary HP. Your next Shield Bash deals an additional 2d6 damage.', 'Shield Wall, Fortification', 30, 270, 2, '{"vg_shield_charge", "vg_second_wind"}', '{"x": 173, "y": -99}', '{"temp_hp": 20, "damage_bonus": "2d6"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94816e94-3b76-47d9-81cd-8f36aaf58263', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_blood_bulwark', 'Kan Siperi', 'Blood Bulwark', '15 CP feda ederek önünüzde 50 puana kadar gelen hasarı engelleyen 5 metre genişliğinde bir bariyer oluşturun.', 'Sacrifice 15 HP to create a 5-meter wide barrier in front of you that blocks up to 50 points of incoming damage.', 'Shield Wall, Sacrifice', 34, 280, 2, '{"vg_barrier_wave", "vg_blood_shield"}', '{"x": 173, "y": -99}', '{"cost": "15 HP", "barrier_hp": 50, "width": "5m"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6ef02eb9-5247-45c9-ba92-fa769115e312', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_reflecting_shield', 'Yansıtan Kalkan', 'Reflecting Shield', 'Kalkanınızı gizemli enerjiyle kaplayarak tam olarak bir menzilli büyüyü veya saldırıyı gönderene geri yansıtmanızı sağlar.', 'Coat your shield in arcane energy, allowing you to reflect exactly one ranged spell or attack back at its sender.', 'Shield Wall', 42, 360, 3, '{"vg_dome_of_protection"}', '{"x": 1472, "y": -849}', '{"reflect": "1 ranged attack"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31fb9b6c-3599-402e-8a5e-0b8354e12ed9', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_shattering_bash', 'Parçalayan Darbe', 'Shattering Bash', '4d6 hasar veren ve hedefin ZS''sini 2 tur boyunca 2 azaltan yıkıcı bir kalkan darbesi vurun.', 'Deliver a devastating shield blow that deals 4d6 damage and reduces the target''s AC by 2 for 2 turns.', 'Shield Wall', 48, 400, 3, '{"vg_reflecting_shield"}', '{"x": 1688, "y": -974}', '{"damage": "4d6", "ac_reduction": 2, "duration": "2 turns"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('701b39e9-8d44-48b1-8539-d8858f160291', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_mobile_fortress', 'Mobil Kale', 'Mobile Fortress', 'Duruşunuzu kilitleyerek yürüyen bir kale olun. +5 ZS kazanın, ancak hareket hızınız 3 tur boyunca yarıya iner.', 'Lock your stance to become a moving fortress. Gain +5 AC, but your movement speed is halved for 3 turns.', 'Shield Wall', 56, 480, 3, '{"vg_shattering_bash"}', '{"x": 1905, "y": -1099}', '{"ac_bonus": "+5", "speed": "-50%", "duration": "3 turns"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c7d86037-07d6-4994-91b5-abfaf49cc22c', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_empathic_transfer', 'Empatik Aktarım', 'Empathic Transfer', '5 metre içindeki bir müttefikten 1 negatif durumu emerek kendinize aktarın ve onları 3d8 CP iyileştirin.', 'Absorb 1 negative condition from an ally within 5 meters, transferring it to yourself, and heal them for 3d8 HP.', 'Sacrifice', 44, 380, 3, '{"vg_blood_shield"}', '{"x": 1092, "y": 1302}', '{"condition_transfer": 1, "heal": "3d8", "range": "5m"}', '🫂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fec310e0-6e7f-4055-b037-f5db0f987d73', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_vanguard_provocation', 'Öncü Kışkırtması', 'Vanguard Provocation', 'Gürleyen bir kışkırtma ile 15 metre içindeki tüm düşmanları bir sonraki saldırılarında sizi hedef almaya veya dezavantaj yaşamaya zorlayın.', 'Let out a booming taunt, forcing all enemies within 15 meters to target you for their next attack or suffer disadvantage.', 'Sacrifice', 50, 420, 3, '{"vg_empathic_transfer"}', '{"x": 1253, "y": 1493}', '{"radius": "15m", "taunt": "1 attack"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('04551ec4-411a-4792-a3bd-e846f68af912', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_sacrificial_pact', 'Kurban Anlaşması', 'Sacrificial Pact', 'Ruhunuzu bir müttefike bağlayın. Eğer 0 CP''ye düşerlerse, 1 CP''de kalırlar ve siz anında 50 nekrotik hasar alırsınız.', 'Bind your soul to an ally. If they drop to 0 HP, they remain at 1 HP, and you instantly take 50 necrotic damage.', 'Sacrifice', 58, 490, 3, '{"vg_vanguard_provocation"}', '{"x": 1414, "y": 1685}', '{"prevent_death": "1 ally", "self_damage": 50}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0aac58be-959c-4434-aff9-d728496f4fa7', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_adamantine_bones', 'Adamantiyum Kemikler', 'Adamantine Bones', 'İskelet yapınızı mistik dayanıklılıkla aşılayın. Kritik vuruşlara karşı bağışıklık kazanın ve %30 fiziksel hasar direnci elde edin.', 'Infuse your skeletal structure with mystical durability. You become immune to critical hits and gain 30% physical damage resistance.', 'Fortification', 46, 390, 3, '{"vg_unstoppable_force"}', '{"x": -1092, "y": 1302}', '{"crit_immunity": true, "resist": "30% physical"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4ed82c15-487d-4aea-a239-d1cef83f9910', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_titan_grip', 'Titan Tutuşu', 'Titan Grip', 'Muazzam gücünüz, kalkanınızı tutarken bir elinizle ağır, çift elli bir silah kullanmanızı sağlar.', 'Your immense strength allows you to wield a heavy, two-handed weapon in one hand while still holding your shield.', 'Fortification', 52, 440, 3, '{"vg_adamantine_bones"}', '{"x": -1253, "y": 1493}', '{"two_handed_in_one_hand": true}', '✊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a5ab2aac-2cd8-42b9-9100-8ec9fc0ef6c9', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_regenerative_tissue', 'Yenilenen Doku', 'Regenerative Tissue', 'Hücreleriniz hızla yenilenerek, 5 tur boyunca her turunuzun başında sizi 10 CP iyileştirir.', 'Your cells regenerate rapidly, healing you for 10 HP at the start of each of your turns for 5 turns.', 'Fortification', 60, 500, 3, '{"vg_titan_grip"}', '{"x": -1414, "y": 1685}', '{"regen": "10 HP/turn", "duration": "5 turns"}', '🧬');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26e97443-6280-417a-b608-fc8deda3a333', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_martyrs_fortress', 'Şehit Kalesi', 'Martyr''s Fortress', 'Acınız zırha dönüşür. Maksimum canınızdan eksik olan her 10 CP için +1 ZS kazanırsınız.', 'Your pain crystallizes into armor. For every 10 HP you are missing from your maximum, you gain +1 AC.', 'Sacrifice, Fortification', 48, 410, 3, '{"vg_empathic_transfer", "vg_adamantine_bones"}', '{"x": 173, "y": -99}', '{"ac_scaling": "+1 per 10 missing HP"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('df208844-2200-4e44-8e13-f043367e01e4', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_deflective_bond', 'Yansıtıcı Bağ', 'Deflective Bond', 'Yaşam Bağı ile bir müttefike bağlandığınızda, kalkanınızın hayalet kopyaları onların etrafında dönerek onlara +3 ZS kazandırır.', 'When linked to an ally via Life Tether, that ally also gains +3 AC as phantom copies of your shield orbit them.', 'Shield Wall, Sacrifice', 54, 460, 3, '{"vg_reflecting_shield", "vg_vanguard_provocation"}', '{"x": 389, "y": -224}', '{"linked_ally_ac_bonus": "+3"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b831d7e7-180a-422b-8a49-6e548cba94c4', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_aegis_throw', 'Kalkan Fırlatma', 'Aegis Throw', 'Kalkanınızı 15 metreye kadar fırlatın. En fazla 3 düşman arasında sekerek her birine 5d6 ezme hasarı verir ve geri döner.', 'Hurl your shield up to 15 meters. It bounces between up to 3 enemies, dealing 5d6 bludgeoning damage to each before returning.', 'Shield Wall', 62, 620, 4, '{"vg_mobile_fortress"}', '{"x": 2121, "y": -1224}', '{"range": "15m", "targets": 3, "damage": "5d6"}', '🥏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6bbe7944-4e05-4bce-b48b-1bdcaa29c98f', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_wall_of_repulsion', 'İtme Duvarı', 'Wall of Repulsion', '10 metre genişliğinde büyülü bir bariyer dikin. İçinden geçmeye çalışan düşmanlar şiddetle 5 metre geriye itilir. 3 tur sürer.', 'Erect a 10-meter wide magical barrier. Enemies attempting to pass through are violently pushed back 5 meters. Lasts 3 turns.', 'Shield Wall', 68, 700, 4, '{"vg_aegis_throw"}', '{"x": 2338, "y": -1349}', '{"width": "10m", "knockback": "5m", "duration": "3 turns"}', '🛑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8d6537fc-3e5b-4d8d-8150-88d78e97620c', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_kinetic_absorption', 'Kinetik Emilim', 'Kinetic Absorption', '1 tur boyunca alınan tüm fiziksel hasarı tamamen emin. Bir sonraki turunuzun başında, emilen hasarın yarısını veren 10 metrelik bir patlama olarak serbest bırakın.', 'For 1 turn, completely absorb all physical damage taken. At the start of your next turn, release it as a 10m blast dealing half the absorbed damage.', 'Shield Wall', 76, 850, 4, '{"vg_wall_of_repulsion"}', '{"x": 2554, "y": -1474}', '{"absorb": "100% physical", "blast_radius": "10m", "blast_damage": "50% absorbed"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d51316cd-3f08-4305-88fc-12469560239a', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_aura_of_absorption', 'Emilim Aurası', 'Aura of Absorption', '10 metrelik bir aura yayın. İçerideki müttefiklere verilen tüm hasarın %50''sini alırsınız, ancak aktarılan bu hasar kendi zırh değeriniz kadar azalır.', 'Emit a 10-meter aura. You take 50% of all damage dealt to allies inside, but this transferred damage is reduced by your armor value.', 'Sacrifice', 64, 650, 4, '{"vg_sacrificial_pact"}', '{"x": 1574, "y": 1876}', '{"radius": "10m", "damage_transfer": "50%", "mitigate_with_armor": true}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2977defc-0c61-4c65-a40d-850fa83730e5', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_vital_redirection', 'Hayati Yönlendirme', 'Vital Redirection', 'Alan etkili bir büyünün arasına girmek için uzayı bükün. Büyünün tüm hasarını siz alırsınız, ancak alanındaki tüm müttefikler sıfır hasar alır.', 'Bend space to intercept an area-of-effect spell. You take the full damage of the spell, but all allies in its area take zero damage.', 'Sacrifice', 70, 750, 4, '{"vg_aura_of_absorption"}', '{"x": 1735, "y": 2068}', '{"redirect_aoe": "100% to self", "allies_damage": 0}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('defa4a32-4d36-4951-b2b6-76ee30962841', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_unyielding_martyr', 'Boyun Eğmez Şehit', 'Unyielding Martyr', 'Bir müttefik adına hasar aldığınızda, savaşın geri kalanı için birikimli olarak %5 hasar azaltma (en fazla %50) kazanırsınız.', 'Whenever you take damage on behalf of an ally, you gain a cumulative 5% damage reduction (up to 50%) for the rest of combat.', 'Sacrifice', 78, 880, 4, '{"vg_vital_redirection"}', '{"x": 1896, "y": 2259}', '{"stacking_reduction": "5% per absorb", "max": "50%"}', '🦸‍♂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4d44aad9-73c6-4ed4-bb81-5124cbbeef58', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_colossus_form', 'Kolezyum Formu', 'Colossus Form', '5 tur boyunca devasa bir boyuta ulaşın. +100 Maksimum CP, +2 metre uzanma mesafesi ve Güç zarlarında avantaj kazanın.', 'Grow to a massive size for 5 turns. Gain +100 Max HP, +2 meters reach, and advantage on Strength checks.', 'Fortification', 66, 680, 4, '{"vg_regenerative_tissue"}', '{"x": -1574, "y": 1876}', '{"max_hp": "+100", "reach": "+2m", "duration": "5 turns"}', '🦍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f159167e-c2be-4976-88f8-527876f2cfd2', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_adaptive_armor', 'Adaptif Zırh', 'Adaptive Armor', 'Zırhınız saldırılardan öğrenir. Element hasarı aldığınızda, o elemente karşı anında 3 tur boyunca %50 direnç kazanırsınız.', 'Your armor learns from attacks. When hit by elemental damage, instantly gain 50% resistance to that element for 3 turns.', 'Fortification', 72, 780, 4, '{"vg_colossus_form"}', '{"x": -1735, "y": 2068}', '{"adapt_resist": "50%", "duration": "3 turns"}', '🦎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c41fd2f3-1b85-4a8a-98e3-a163321b44ad', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_indomitable_will', 'Yılmaz İrade', 'Indomitable Will', 'Kararlılığınız kırılamaz. Herhangi bir türdeki sonraki 3 kurtarma zarınızı otomatik olarak başarırsınız.', 'Your resolve is unbreakable. You automatically succeed your next 3 saving throws of any kind.', 'Fortification', 80, 900, 4, '{"vg_adaptive_armor"}', '{"x": -1896, "y": 2259}', '{"auto_succeed_saves": 3}', '🧘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6faf535a-5ff6-4601-a78d-90cc9e2d8032', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_titan_guard', 'Titan Koruması', 'Titan Guard', 'Kolezyum Formundayken, Koruma Kubbeniz 15 metre yarıçapa genişler ve +4 yerine +6 ZS sağlar.', 'While in Colossus Form, your Dome of Protection expands to a 15-meter radius and provides +6 AC instead of +4.', 'Shield Wall, Fortification', 74, 800, 4, '{"vg_kinetic_absorption", "vg_colossus_form"}', '{"x": 389, "y": -224}', '{"radius_increase": "15m", "ac_bonus": "+6"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0fac514-d9db-4342-bb36-8ac81c25d42e', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_pain_fueled_armor', 'Acıyla Beslenen Zırh', 'Pain-Fueled Armor', 'Müttefikleriniz için hasar almak yenilenmenizi besler. Bir müttefikten emdiğiniz herhangi bir hasarın %25''i kadar iyileşirsiniz.', 'Taking damage for your allies fuels your regeneration. You heal for 25% of any damage you absorb from an ally.', 'Sacrifice, Fortification', 75, 820, 4, '{"vg_vital_redirection", "vg_adaptive_armor"}', '{"x": 389, "y": -224}', '{"heal_from_absorb": "25%"}', '❤️‍🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('600921ee-81d2-4db5-a93d-bbb3667823ef', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_impenetrable_bulwark', 'Aşılmaz Siper', 'Impenetrable Bulwark', 'Topuklarınızı yere gömün ve kalkanınızı dikin. 3 tur boyunca önünüzden gelen tüm hasarlara karşı tamamen bağışıklık kazanırsınız.', 'Dig your heels in and plant your shield. You become completely immune to all damage originating from your front arc for 3 turns.', 'Shield Wall', 85, 1100, 5, '{"vg_kinetic_absorption"}', '{"x": 2771, "y": -1599}', '{"frontal_immunity": true, "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d223de9f-b058-4029-a826-39ae7484e4d6', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_ultimate_shield_wall', 'Öncü Birliğin Tabyası', 'Vanguard''s Bastion', 'Nihai: Devasa 10 metrelik kutsal bir tabya oluşturun. İçerideki müttefikler +10 ZS kazanır ve 3 tur boyunca alanın dışından gelen saldırılardan 0 hasar alır.', 'Ultimate: Create a massive 10m holy bastion. Allies inside gain +10 AC and take 0 damage from attacks originating outside the area for 3 turns.', 'Shield Wall', 95, 1400, 5, '{"vg_impenetrable_bulwark"}', '{"x": 2987, "y": -1724}', '{"radius": "10m", "ac_bonus": "+10", "outside_damage_immunity": true, "duration": "3 turns"}', '🏟️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7533c310-a25c-4027-8fbd-c5ed0457b373', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_soul_bind', 'Ruh Bağı', 'Soul Bind', 'Ruhunuzu 3 müttefike kadar bağlayın. Onlara gelen hasarın %100''ünü siz alırsınız, ancak bu şekilde size aktarılan tüm hasar %75 oranında azalır.', 'Bind your soul to up to 3 allies. You take 100% of their incoming damage, but all damage transferred to you this way is reduced by 75%.', 'Sacrifice', 86, 1150, 5, '{"vg_unyielding_martyr"}', '{"x": 2056, "y": 2451}', '{"targets": 3, "damage_transfer": "100%", "transfer_reduction": "75%"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cddec575-7c7d-4e16-a1ef-bbd66fd00e34', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_ultimate_sacrifice', 'Nihai Fedakarlık', 'Ultimate Sacrifice', 'Nihai: 20m içindeki bir müttefik ölürse, onları anında %100 CP ile diriltirsiniz. Siz 1 CP''ye düşersiniz, ancak 1 tur boyunca Yenilmezlik kazanırsınız.', 'Ultimate: If an ally within 20m dies, you instantly revive them to 100% HP. You drop to 1 HP, but gain Invulnerability for 1 turn.', 'Sacrifice', 96, 1450, 5, '{"vg_soul_bind"}', '{"x": 2217, "y": 2642}', '{"revive": "100% HP", "self_hp_set": 1, "self_invulnerable": "1 turn", "range": "20m"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c2688ec6-f236-4aaa-86d9-0c4bf157888a', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_avatar_of_defense', 'Savunma Avatarı', 'Avatar of Defense', 'Savunmanın fiziksel vücut bulmuş hali olun. Mevcut ZS''niz ikiye katlanır ve 5 tur boyunca tüm negatif durum etkilerine karşı bağışıklık kazanırsınız.', 'Become the physical embodiment of defense. Your current AC is doubled, and you are immune to all negative status effects for 5 turns.', 'Fortification', 88, 1200, 5, '{"vg_indomitable_will"}', '{"x": -2056, "y": 2451}', '{"ac_multiplier": "x2", "status_immunity": true, "duration": "5 turns"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('000234c9-61b5-4939-8ade-7d9c99045497', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_ultimate_fortification', 'Yaşayan Dağ', 'Living Mountain', 'Nihai: Hareketsiz bir dağa dönüşün. 5 tur boyunca +300 Maksimum CP, +10 ZS ve tam Kitle Kontrol bağışıklığı kazanın, ancak hareket edemezsiniz.', 'Ultimate: Transform into an immovable mountain. Gain +300 Max HP, +10 AC, and complete CC immunity for 5 turns, but you cannot move.', 'Fortification', 98, 1500, 5, '{"vg_avatar_of_defense"}', '{"x": -2217, "y": 2642}', '{"max_hp": "+300", "ac_bonus": "+10", "cc_immunity": true, "speed": 0, "duration": "5 turns"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30a70b08-7190-4d73-a47e-3304dac55f22', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_vanguards_legacy', 'Öncünün Mirası', 'Vanguard''s Legacy', '3 tur boyunca, 15 metre içindeki tüm müttefikler temel ZS''nizi ve dirençlerinizi miras alır ve her tur Maksimum CP''lerinin %5''i kadar iyileşirler.', 'For 3 turns, all allies within 15 meters inherit your base AC, your resistances, and heal for 5% of their Max HP per turn.', 'Shield Wall, Sacrifice, Fortification', 90, 1300, 5, '{"vg_impenetrable_bulwark", "vg_soul_bind", "vg_avatar_of_defense"}', '{"x": 173, "y": -99}', '{"radius": "15m", "share_ac": true, "share_resist": true, "ally_heal": "5% max HP"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('44da3f78-f60b-4782-adfe-dda327c579cf', '518513b1-77f3-4b81-8332-2ed17be001b6', 'vg_grand_aegis_of_the_ancients', 'Kadimlerin Kalkanı', 'Aegis of the Ancients', 'Büyük Nihai Büyü: 5 tur boyunca, 30 metre içindeki müttefiklere verilen TÜM hasarı emersiniz, ancak bu hasarın sadece %10''unu alırsınız. Müttefikler Kitle Kontrolüne karşı tamamen bağışıklık kazanır.', 'Grand Ultimate: For 5 turns, you absorb ALL damage dealt to allies within 30 meters, but you only take 10% of that damage. Allies become completely immune to CC.', 'Grand Ultimate', 100, 1500, 5, '{"vg_ultimate_shield_wall", "vg_ultimate_sacrifice", "vg_ultimate_fortification"}', '{"x": 173, "y": -99}', '{"radius": "30m", "absorb_all_damage": true, "self_damage_taken": "10%", "ally_cc_immunity": true, "duration": "5 turns"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a68b8a8-ca25-4312-863c-6790456fd5cb', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_toxic_fumes', 'Zehirli Duman', 'Toxic Fumes', '2 metre yarıçapında zehirli duman bulutu salarak nefes alan yaratıklara tur başına 1d4 zehir hasarı verir.', 'Releases a small cloud of toxic fumes in a 2m radius, dealing 1d4 poison damage per turn to breathing creatures.', 'Toxic', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d4", "range": "2m", "duration": "2 turns"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0a3ab9e0-5e30-4044-8101-3030dbbdbec0', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_poison_spray', 'Zehir Püskürtme', 'Poison Spray', '5 metreye kadar zehirli sis püskürterek 2d6 zehir hasarı verir.', 'Sprays a cone of venomous mist up to 5m, dealing 2d6 poison damage.', 'Toxic', 8, 80, 1, '{"vb_toxic_fumes"}', '{"x": 389, "y": -224}', '{"damage": "2d6", "range": "5m cone"}', '💦');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e11838ae-b0de-4aea-bb3d-0573cde54f2c', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_toxic_puddle', 'Toksik Birikinti', 'Toxic Puddle', 'Yerde 3 metrelik toksik bir çamur birikintisi oluşturur. İçinden geçen düşmanlar %50 yavaşlar ve 1d6 asit hasarı alır.', 'Creates a 3m puddle of toxic sludge on the ground. Enemies moving through it are slowed by 50% and take 1d6 acid damage.', 'Toxic', 15, 120, 1, '{"vb_poison_spray"}', '{"x": 606, "y": -349}', '{"damage": "1d6", "range": "3m", "slow": "50%"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f8823af2-19e0-4516-a96e-0e03fe6c0c07', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_choking_gas', 'Boğucu Gaz', 'Choking Gas', 'Düşmanları susturan ve tur başına 2d4 zehir hasarı veren 4 metre yarıçapında kalın bir gaz yayar.', 'Emits a thick 4m radius gas that silences enemies and deals 2d4 poison damage per turn.', 'Toxic', 22, 180, 2, '{"vb_toxic_puddle"}', '{"x": 822, "y": -474}', '{"damage": "2d4", "range": "4m", "status": "Silence"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('51213c73-ca56-4861-9eed-f8b76c742217', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_acid_flask', 'Asit Şişesi', 'Acid Flask', 'Kırılarak 3 metre yarıçapında 3d6 asit hasarı veren cam bir şişe fırlatır. Menzil 10m.', 'Throws a glass flask that shatters, dealing 3d6 acid damage in a 3m radius. Range 10m.', 'Toxic', 30, 220, 2, '{"vb_choking_gas"}', '{"x": 1039, "y": -599}', '{"damage": "3d6", "range": "10m", "radius": "3m"}', '🧪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc9ed0b1-e26a-467e-a724-2e778cfe5308', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_corrosive_mist', 'Aşındırıcı Sis', 'Corrosive Mist', 'Zırhı aşındıran, 2 azaltan ve tur başına 2d6 asit hasarı veren 6 metrelik bir sis çağırır.', 'Summons a 6m radius mist that corrodes armor, reducing it by 2 and dealing 2d6 acid damage per turn.', 'Toxic', 38, 280, 2, '{"vb_acid_flask"}', '{"x": 1255, "y": -724}', '{"damage": "2d6", "range": "6m", "armor_reduction": "2"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2fc9e5b3-ebb9-461b-8cd0-2457413470b9', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_poison_nova', 'Zehir Novası', 'Poison Nova', 'Etrafınızda 8 metre yarıçapında bir zehir halkası serbest bırakarak 4d8 zehir hasarı verir ve düşmanları zehirler.', 'Unleashes a ring of poison in an 8m radius around you, dealing 4d8 poison damage and poisoning enemies.', 'Toxic', 45, 380, 3, '{"vb_corrosive_mist"}', '{"x": 1472, "y": -849}', '{"damage": "4d8", "range": "8m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('faae178f-50d3-48a9-bd88-e7017aece977', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_toxic_barrage', 'Toksik Yaylım', 'Toxic Barrage', '15m içindeki hedeflere her biri 2d6 zehir hasarı veren 3 yoğun toksik küre ateşler.', 'Fires 3 concentrated toxic globes at targets within 15m, each dealing 2d6 poison damage.', 'Toxic', 52, 420, 3, '{"vb_poison_nova"}', '{"x": 1688, "y": -974}', '{"damage": "3x 2d6", "range": "15m"}', '🥎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('232fb34b-8853-4b90-ad2f-e00ebd0e1bd1', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_lethal_spores', 'Ölümcül Sporlar', 'Lethal Spores', '5 metrelik bir alanı uçuşan sporlarla doldurur. İçinde eylem yapan düşmanlar 3d6 zehir hasarı alır.', 'Fills a 5m radius with floating spores. Enemies taking actions within it take 3d6 poison damage.', 'Toxic', 58, 480, 3, '{"vb_toxic_barrage"}', '{"x": 1905, "y": -1099}', '{"damage": "3d6 on action", "range": "5m"}', '🍄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dd05be95-e031-4168-af91-43255ae88ce2', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_caustic_eruption', 'Kostik Patlama', 'Caustic Eruption', 'Yerin 6 metre yarıçapında asitle patlamasına neden olarak 5d8 asit hasarı verir ve araziyi eritir.', 'Causes the ground to erupt with acid in a 6m radius, dealing 5d8 acid damage and melting terrain.', 'Toxic', 65, 650, 4, '{"vb_lethal_spores"}', '{"x": 2121, "y": -1224}', '{"damage": "5d8", "range": "6m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('177520b1-6aa3-46de-b5f3-513639e1ba83', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_miasma_field', 'Miasma Alanı', 'Miasma Field', '10 metrelik bir çürüme bölgesi yaratır. Tüm iyileşmeyi engeller ve tur başına 3d8 nekrotik-zehir hasarı verir.', 'Creates a 10m zone of pure decay. Prevents all healing and deals 3d8 necrotic-poison damage per turn.', 'Toxic', 72, 720, 4, '{"vb_caustic_eruption"}', '{"x": 2338, "y": -1349}', '{"damage": "3d8", "range": "10m", "anti_heal": "100%"}', '♨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8f8ef339-d0a9-4132-9290-c064d6b2f9c2', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_plague_wind', 'Veba Rüzgarı', 'Plague Wind', '15m uzunluğunda, 4m genişliğinde vebalı bir rüzgar estirir. Düşmanları 5m geri iter ve 6d6 zehir hasarı verir.', 'Channels a 15m long, 4m wide gust of plagued wind. Pushes enemies back 5m and deals 6d6 poison damage.', 'Toxic', 78, 850, 4, '{"vb_miasma_field"}', '{"x": 2554, "y": -1474}', '{"damage": "6d6", "range": "15x4m line", "knockback": "5m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5148964-2d6e-4f83-96c6-e64b01a33936', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_toxic_overload', 'Toksik Aşırı Yükleme', 'Toxic Overload', '10 metre yarıçapındaki tüm toksinleri patlamaya zorlar, aktif zehirleri tüketerek 10d6 anlık hasar verir.', 'Forces all toxins in a 10m radius to detonate, consuming active poisons for 10d6 burst damage.', 'Toxic', 85, 1100, 5, '{"vb_plague_wind"}', '{"x": 2771, "y": -1599}', '{"damage": "10d6", "range": "10m"}', '🛢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('622d2207-f903-41aa-97ca-e994c537c24a', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_chernobyl_cloud', 'Çernobil Bulutu', 'Chernobyl Cloud', '20 metre yarıçapında devasa bir radyoaktif ve toksik bulut salar. 5 tur boyunca 10d10 zehir hasarı verir ve zehir bağışıklığını yok sayar.', 'Unleashes an ultimate radioactive and toxic cloud in a 20m radius. Deals 10d10 poison damage over 5 turns and ignores poison immunity.', 'Toxic', 95, 1400, 5, '{"vb_toxic_overload"}', '{"x": 2987, "y": -1724}', '{"damage": "10d10", "range": "20m", "duration": "5 turns"}', '☢️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31f95f45-51b3-4373-bd7f-820d5a82f840', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_venom_strike', 'Zehirli Vuruş', 'Venom Strike', 'Zehirli bir bıçakla yapılan isabetli bir yakın dövüş vuruşu, silah hasarı ve 2 tur boyunca tur başına 1d4 zehir hasarı verir.', 'A precise melee strike with a poisoned blade, dealing weapon damage plus 1d4 poison damage per turn for 2 turns.', 'Venom', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "Weapon + 1d4 DOT", "range": "Melee", "duration": "2 turns"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c19b5a69-7fca-440d-920b-6c3feaddb38f', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_poisoned_dart', 'Zehirli Ok', 'Poisoned Dart', '15m uzağa kadar hızlı bir dart atarak 1d8 delici hasar verir ve hedefi zehirler.', 'Shoots a quick dart up to 15m away, dealing 1d8 piercing damage and poisoning the target.', 'Venom', 6, 70, 1, '{"vb_venom_strike"}', '{"x": 289, "y": 344}', '{"damage": "1d8", "range": "15m"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7ee40b26-40eb-43a9-b9c7-a732279207f4', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_serpent_sting', 'Yılan Sokması', 'Serpent Sting', 'Yılan ısırığını taklit eden hızlı bir saplama. 2d6 zehir hasarı verir ve hedefin hareket hızını 2m azaltır.', 'A swift stab mimicking a snake bite. Deals 2d6 poison damage and reduces the target''s movement speed by 2m.', 'Venom', 12, 100, 1, '{"vb_poisoned_dart"}', '{"x": 449, "y": 536}', '{"damage": "2d6", "range": "Melee", "speed_reduction": "2m"}', '🐍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b4aecbc0-c020-4f60-bab6-8e23ee09c2a2', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_venom_coating', 'Zehir Kaplama', 'Venom Coating', 'Silahınıza hızlı etki eden bir zehir sürer. Sonraki 3 saldırınız fazladan 1d6 zehir hasarı verir.', 'Applies a fast-acting venom to your weapon. Your next 3 attacks deal an additional 1d6 poison damage.', 'Venom', 24, 190, 2, '{"vb_serpent_sting"}', '{"x": 610, "y": 727}', '{"damage": "+1d6", "charges": "3 attacks"}', '🍯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f597098-44a4-4a22-b06d-3f5a9f57aa60', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_toxic_slash', 'Toksik Kesik', 'Toxic Slash', 'Zehir izi bırakan geniş bir yakın dövüş saldırısı, 3m yay içindeki hedeflere 3d6 zehir hasarı verir.', 'A sweeping melee attack that leaves a trail of venom, dealing 3d6 poison damage to targets in a 3m arc.', 'Venom', 28, 210, 2, '{"vb_venom_coating"}', '{"x": 771, "y": 919}', '{"damage": "3d6", "range": "3m arc"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2681392b-0afa-4fe1-9331-f4350670568b', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_spider_bite', 'Örümcek Isırığı', 'Spider Bite', 'Lokal kasları felç eden özel bir vuruş. Hedefi 1 tur yerine sabitler ve 2d8 zehir hasarı verir.', 'A specialized strike that paralyses local muscles. Roots the target in place for 1 turn and deals 2d8 poison damage.', 'Venom', 35, 260, 2, '{"vb_toxic_slash"}', '{"x": 932, "y": 1110}', '{"damage": "2d8", "range": "Melee", "status": "Root"}', '🕷️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2fdadf66-bd4c-4d71-8ad1-171fd57fe2b8', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_viper_fang', 'Engerek Dişi', 'Viper Fang', 'Zırhı delen ölümcül bir saplama. 4d6 zehir hasarı verir ve hedefin fiziksel zırhının %20''sini yok sayar.', 'A lethal stab that pierces armor. Deals 4d6 poison damage and ignores 20% of the target''s physical armor.', 'Venom', 42, 360, 3, '{"vb_spider_bite"}', '{"x": 1092, "y": 1302}', '{"damage": "4d6", "range": "Melee", "armor_penetration": "20%"}', '🦷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d90cea7a-1f97-450d-beaa-f72b0989ec56', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_venomous_barrage', 'Zehirli Bıçak Yağmuru', 'Venomous Barrage', '10m içindeki hedeflere 5 adet zehirli fırlatma bıçağı atar, her biri 1d6 delici ve 1d6 zehir hasarı verir.', 'Throws 5 poisoned throwing knives at targets within 10m, each dealing 1d6 piercing and 1d6 poison damage.', 'Venom', 48, 400, 3, '{"vb_viper_fang"}', '{"x": 1253, "y": 1493}', '{"damage": "5x (1d6 + 1d6)", "range": "10m"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4e94ef99-8d6e-4182-bb96-752adcedd813', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_paralyzing_toxin', 'Felç Edici Zehir', 'Paralyzing Toxin', 'Yakın dövüşte güçlü bir nörotoksin enjekte eder. Hedefi 1 tur sersemletir ve 3d6 zehir hasarı verir.', 'Injects a potent neurotoxin via melee strike. Stuns the target for 1 turn and deals 3d6 poison damage.', 'Venom', 55, 450, 3, '{"vb_venomous_barrage"}', '{"x": 1414, "y": 1685}', '{"damage": "3d6", "range": "Melee", "status": "Stun"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8b5234b8-c3a0-4822-b73f-091553363d16', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_manticore_sting', 'Mantikor İğnesi', 'Manticore Sting', '10m menzilli ağır bir fırlatma dikeni. 5d8 zehir hasarı verir ve şiddetli acı yaratarak saldırılarda dezavantaja neden olur.', 'A heavy thrown barb with 10m range. Deals 5d8 poison damage and inflicts severe pain, causing disadvantage on attacks.', 'Venom', 62, 620, 4, '{"vb_paralyzing_toxin"}', '{"x": 1574, "y": 1876}', '{"damage": "5d8", "range": "10m", "debuff": "Disadvantage on attacks"}', '🦂');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e2c1e066-bcea-4617-9a36-92b1366787b6', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_venom_surge', 'Zehir Dalgası', 'Venom Surge', '8m uzağa kadar düşmanların içinden atılarak yolunuzun üzerindeki herkese 4d8 zehir hasarı veren kesikler atar.', 'Dashes through enemies up to 8m away, slashing all in your path for 4d8 poison damage.', 'Venom', 68, 680, 4, '{"vb_manticore_sting"}', '{"x": 1735, "y": 2068}', '{"damage": "4d8", "range": "8m dash"}', '〰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('126d573e-3979-4411-806e-d407edd94155', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_lethal_injection', 'Ölümcül Enjeksiyon', 'Lethal Injection', '8d6 zehir hasarı veren yıkıcı bir yakın dövüş enjeksiyonu. %20 Canın altındaki hedefleri anında öldürür.', 'A devastating melee injection dealing 8d6 poison damage. Instantly kills targets below 20% HP.', 'Venom', 75, 750, 4, '{"vb_venom_surge"}', '{"x": 1896, "y": 2259}', '{"damage": "8d6", "range": "Melee", "execute": "20% HP"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ddd8e62d-1c50-42dc-855a-1308bc44f4b8', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_neurotoxin_blade', 'Nörotoksin Bıçağı', 'Neurotoxin Blade', 'Yüksek konsantrasyonlu nörotoksinle vurur. 6d8 hasar verir ve hedefin 2 tur boyunca büyü yapma yeteneğini devre dışı bırakır.', 'Strikes with a highly concentrated neurotoxin. Deals 6d8 damage and disables the target''s ability to cast spells for 2 turns.', 'Venom', 82, 1050, 5, '{"vb_lethal_injection"}', '{"x": 2056, "y": 2451}', '{"damage": "6d8", "range": "Melee", "status": "Silence"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('85a73adf-56c8-4f69-bd54-c3b62d7a647d', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_hydra_fangs', 'Hydra Dişleri', 'Hydra Fangs', 'Her biri iyileştirilemez bir zehirle 3d10 zehir hasarı veren 5 inanılmaz hızlı vuruş yapar.', 'Delivers 5 incredibly rapid strikes, each dealing 3d10 poison damage with an un-curable venom.', 'Venom', 92, 1300, 5, '{"vb_neurotoxin_blade"}', '{"x": 2217, "y": 2642}', '{"damage": "5x 3d10", "range": "Melee"}', '🐉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9653200c-2b67-4d29-aff9-729fa060932b', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_fever_touch', 'Ateşli Dokunuş', 'Fever Touch', 'Ani ateşe neden olan bir dokunuş. Hedefin hareket hızını 3m azaltır ve tur başına 1d4 hasar verir.', 'A touch that induces a sudden fever. Reduces target''s movement speed by 3m and deals 1d4 damage per turn.', 'Affliction', 4, 60, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d4", "range": "Melee", "speed_reduction": "3m"}', '🤒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b204ce3f-7577-4fbd-91ec-eaefa53040f1', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_weakening_sickness', 'Zayıflatan Hastalık', 'Weakening Sickness', '10m içindeki bir hedefi enfekte eder. 3 tur boyunca Güç ve Çeviklik kurtarma zarlarında dezavantaj yaşarlar.', 'Infects a target within 10m. They suffer disadvantage on Strength and Dexterity saving throws for 3 turns.', 'Affliction', 10, 90, 1, '{"vb_fever_touch"}', '{"x": -289, "y": 344}', '{"range": "10m", "duration": "3 turns", "debuff": "Disadvantage on STR/DEX saves"}', '🤢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('77bb5614-d8f8-4225-9e10-8f302211e221', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_blood_rot', 'Kan Çürümesi', 'Blood Rot', '15m içindeki bir hedefin kanını bozar. Tur başına 2d4 nekrotik hasar verir ve alınan tüm iyileştirmeyi yarıya indirir.', 'Corrupts the blood of a target within 15m. Deals 2d4 necrotic damage per turn and halves all healing received.', 'Affliction', 18, 140, 1, '{"vb_weakening_sickness"}', '{"x": -449, "y": 536}', '{"damage": "2d4", "range": "15m", "anti_heal": "50%"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('321a7f94-6b72-430d-91cc-741565351817', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_blinding_venom', 'Kör Edici Zehir', 'Blinding Venom', 'Hedefin gözlerine zehirli bir şişe fırlatır (10m menzil). Onları 2 tur boyunca kör eder.', 'Throws a venomous vial at the target''s eyes (10m range). Blinds them for 2 turns.', 'Affliction', 25, 200, 2, '{"vb_blood_rot"}', '{"x": -610, "y": 727}', '{"range": "10m", "status": "Blind", "duration": "2 turns"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f345ea28-ebeb-4ffa-b631-f4167017215d', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_flesh_decay', 'Et Çürümesi', 'Flesh Decay', '10m içindeki bir hedefi yavaşça çürümesi için lanetler. Tur başına 3d4 nekrotik hasar verir ve maksimum canlarını verilen hasar kadar azaltır.', 'Curses a target within 10m to slowly rot. Deals 3d4 necrotic damage per turn and reduces their maximum HP by the damage dealt.', 'Affliction', 32, 240, 2, '{"vb_blinding_venom"}', '{"x": -771, "y": 919}', '{"damage": "3d4", "range": "10m", "max_hp_reduction": "Equal to damage"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a70e7512-a2dc-44a6-97a2-2c8a002bcd49', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_plague_bearer', 'Veba Taşıyıcısı', 'Plague Bearer', 'Hastalığa ev sahipliği yaparsınız. 3m aura içindeki düşmanlar pasif olarak tur başına 1d6 zehir hasarı alır.', 'You become a host to disease. Enemies within a 3m aura take 1d6 poison damage per turn passively.', 'Affliction', 39, 290, 2, '{"vb_flesh_decay"}', '{"x": -932, "y": 1110}', '{"damage": "1d6", "range": "3m aura"}', '🐀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('745dc425-2a69-4211-bb72-a99b28fb7974', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_wasting_disease', 'Tüketen Hastalık', 'Wasting Disease', 'Tüketen bir lanet uygular. Hedef tur başına 2d6 Can kaybeder ve devam ettiği her 2 turda bir yorgunluk seviyesi kazanır.', 'Inflicts a wasting curse. Target loses 2d6 HP per turn and gains one level of exhaustion every 2 turns it persists.', 'Affliction', 46, 390, 3, '{"vb_plague_bearer"}', '{"x": -1092, "y": 1302}', '{"damage": "2d6", "range": "10m", "status": "Exhaustion"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('380fe600-cd94-4dcc-b05f-974f57948b01', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_contagion', 'Bulaşıcı Hastalık', 'Contagion', 'Hedefi tur başına 3d6 hasar veren oldukça bulaşıcı bir hastalıkla enfekte eder. Hedef ölürse, en yakın düşmana sıçrar.', 'Infects a target with a highly contagious disease dealing 3d6 damage per turn. If the target dies, it spreads to the nearest enemy.', 'Affliction', 50, 410, 3, '{"vb_wasting_disease"}', '{"x": -1253, "y": 1493}', '{"damage": "3d6", "range": "10m", "mechanic": "Spreads on death"}', '🦠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('132d4de4-93e9-46f7-b375-bbedd09f359a', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_mind_fog_toxin', 'Zihin Sisi Zehri', 'Mind Fog Toxin', '15m uzaktan hedefin beynini bulandırır. Kafaları karışır ve 1 tur boyunca rastgele hedeflere saldırırlar.', 'Fogs the target''s brain from 15m away. They become confused and attack random targets for 1 turn.', 'Affliction', 56, 460, 3, '{"vb_contagion"}', '{"x": -1414, "y": 1685}', '{"range": "15m", "status": "Confusion", "duration": "1 turn"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('dc18e4ae-db1c-4e7b-8af8-ea931adc53d2', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_organ_failure', 'Organ Yetmezliği', 'Organ Failure', '10m içindeki bir hedefte ani iç çöküşe neden olur. 5d8 nekrotik hasar verir ve onları 1 tur sersemletir.', 'Causes sudden internal collapse in a target within 10m. Deals 5d8 necrotic damage and stuns them for 1 turn.', 'Affliction', 64, 640, 4, '{"vb_mind_fog_toxin"}', '{"x": -1574, "y": 1876}', '{"damage": "5d8", "range": "10m", "status": "Stun"}', '🫀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('049c1f24-2113-415d-a1f9-2fa162d5e5d8', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_epidemic', 'Salgın', 'Epidemic', 'Tek bir hedefteki tüm hastalıkların ve zamanla verilen hasarların 10m içindeki tüm düşmanlara anında yayılmasını sağlar.', 'Forces all afflictions and DOTs on a single target to instantly spread to all enemies within 10m of them.', 'Affliction', 70, 700, 4, '{"vb_organ_failure"}', '{"x": -1735, "y": 2068}', '{"range": "10m", "mechanic": "AOE Spread"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('47f3be3c-9e76-4746-a085-7e58e29ca609', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_black_blood', 'Kara Kan', 'Black Blood', 'Kanınız toksik bir çamura dönüşür. Yakın dövüş saldırısıyla vurulduğunuzda saldırgana sıçrayarak 3d6 asit hasarı verir.', 'Your blood turns to toxic sludge. When hit by a melee attack, you splash the attacker for 3d6 acid damage.', 'Affliction', 76, 780, 4, '{"vb_epidemic"}', '{"x": -1896, "y": 2259}', '{"damage": "3d6", "trigger": "On melee hit"}', '🖤');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('246d5d88-e46c-494f-b9e8-6652327a409b', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_necrotizing_fasciitis', 'Nekrotizan Fasiit', 'Necrotizing Fasciitis', 'Et yiyen bir bakteri hedefi enfekte eder (15m menzil). 8d6 nekrotik hasar verir ve doğal zırhı kalıcı olarak yok eder.', 'A flesh-eating bacteria infects the target (15m range). Deals 8d6 necrotic damage and permanently destroys natural armor.', 'Affliction', 84, 1080, 5, '{"vb_black_blood"}', '{"x": -2056, "y": 2451}', '{"damage": "8d6", "range": "15m", "armor_destruction": "Permanent"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5348ad3a-0ce3-4704-92f5-db1c8557f009', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_crimson_plague', 'Kızıl Veba', 'Crimson Plague', 'Nihai hastalık. 4 tur boyunca 8d10 hasar verir. İyileştirme etkileri bunun yerine hedefe zarar verir. Ölüm durumunda hızla yayılır.', 'The ultimate affliction. Deals 8d10 damage over 4 turns. Healing effects harm the target instead. Spreads rapidly on death.', 'Affliction', 94, 1350, 5, '{"vb_necrotizing_fasciitis"}', '{"x": -2217, "y": 2642}', '{"damage": "8d10", "duration": "4 turns", "mechanic": "Anti-heal damage"}', '🥀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('85b25932-5240-4a65-a481-94ab1aadcec1', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_toxic_blood', 'Toksik Kan', 'Toxic Blood', 'Vücudunuz toksinlere tamamen uyum sağlar. Zehir hasarına bağışıklık kazandırır ve zehirle vurulduğunda maksimum Canınızın %10''u kadar iyileştirir.', 'Your body fully adapts to toxins. Grants immunity to poison damage and heals you for 10% of max HP when struck by poison.', 'Cross-Branch', 36, 270, 2, '{"vb_acid_flask", "vb_spider_bite"}', '{"x": -173, "y": -100}', '{"immunity": "Poison", "healing": "10% Max HP from poison"}', '🫁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3d6a01a9-eadc-4466-9f1e-97b140a1d38f', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_plague_daggers', 'Veba Hançerleri', 'Plague Daggers', 'Hedefleri arayan 3 ruhani zehirli hançer çağırır. Her biri 3d6 hasar verir ve rastgele bir hastalık uygular.', 'Summons 3 ethereal poisoned daggers that seek out targets. Deals 3d6 damage each and applies a random disease.', 'Cross-Branch', 54, 440, 3, '{"vb_venomous_barrage", "vb_wasting_disease"}', '{"x": -389, "y": -225}', '{"damage": "3x 3d6", "status": "Random Disease"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f903b53e-761d-422b-81bf-78137ffbf7bc', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_miasma_coating', 'Miasma Kaplama', 'Miasma Coating', 'Silahlarınızı yoğun miasma ile kaplar. Saldırılar +2d6 zehir hasarı verir ve arkasında 2 metrelik çürüyen gaz bulutları bırakır.', 'Coats your weapons in thick miasma. Attacks deal +2d6 poison damage and leave behind 2m clouds of decaying gas.', 'Cross-Branch', 60, 490, 3, '{"vb_lethal_spores", "vb_contagion"}', '{"x": -606, "y": -350}', '{"damage": "+2d6", "cloud_radius": "2m"}', '🖌️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('352b2b19-3313-410e-a245-eb2028b23efe', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_venomous_explosion', 'Zehirli Patlama', 'Venomous Explosion', 'Zehirli bir hedefe vurmak uçucu bir reaksiyonu tetikler ve 4 metre yarıçapında 5d6 zehir hasarıyla patlamalarına neden olur.', 'Striking a poisoned target triggers a volatile reaction, causing them to explode for 5d6 poison damage in a 4m radius.', 'Cross-Branch', 74, 740, 4, '{"vb_venom_surge", "vb_miasma_field"}', '{"x": -822, "y": -475}', '{"damage": "5d6", "range": "4m radius"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1a89f4c9-71ae-4337-9cc1-ca6486ea8118', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_pandemic_strike', 'Pandemi Vuruşu', 'Pandemic Strike', '6d6 delici hasar veren ve hedefi anında 3 farklı hastalıkla enfekte eden feci bir yakın dövüş saldırısı.', 'A catastrophic melee attack dealing 6d6 piercing damage and instantly infecting the target with 3 different afflictions.', 'Cross-Branch', 80, 880, 4, '{"vb_lethal_injection", "vb_epidemic"}', '{"x": -1039, "y": -600}', '{"damage": "6d6", "range": "Melee", "afflictions": "3 random"}', '😷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d8fb6395-2577-4156-8965-362d0067ab41', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_corrosive_rot', 'Aşındırıcı Çürüme', 'Corrosive Rot', '8 metrelik asit ve çürüme havuzu salar. 4d8 asit hasarı verir ve patron olmayan düşmanların maksimum Canını kalıcı olarak yarıya indirir.', 'Unleashes an 8m pool of acid and decay. Deals 4d8 acid damage and permanently halves the maximum HP of non-boss enemies.', 'Cross-Branch', 88, 1150, 5, '{"vb_toxic_overload", "vb_necrotizing_fasciitis"}', '{"x": -1255, "y": -725}', '{"damage": "4d8", "range": "8m", "max_hp_reduction": "50%"}', '🫠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('32eac109-25b1-4f51-aece-7ef86f2cf057', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_venomblood_avatar', 'Zehirkan Avatarı', 'Venomblood Avatar', 'Toksisitenin vücut bulmuş haline dönüşün. +%50 zehir hasarı, saldırılar alan etkili sıçramalara neden olur ve 3 tur boyunca tüm zayıflatmalara tam bağışıklık sağlar.', 'Transform into the embodiment of toxicity. +50% poison damage, attacks cause AOE splashes, and complete immunity to all debuffs for 3 turns.', 'Cross-Branch', 96, 1450, 5, '{"vb_chernobyl_cloud", "vb_hydra_fangs", "vb_crimson_plague"}', '{"x": -1472, "y": -850}', '{"buff": "+50% Poison Damage", "immunity": "Debuffs", "duration": "3 turns"}', '🧌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ac9a651b-a169-41dc-a806-90447ae894de', 'cdbd8f15-5697-47a0-8b55-a8a7c324fc88', 'vb_apocalypse_toxin', 'Kıyamet Toksini', 'Apocalypse Toxin', '30 metre yarıçapında nihai biyokimyasal silahı serbest bırakır. Tüm bağışıklıkları atlayarak 20d10 mutlak zehir hasarı verir ve alanı bir çorak araziye dönüştürür.', 'Releases the ultimate biochemical weapon in a 30m radius. Deals 20d10 absolute poison damage, bypassing all immunities and converting the area into a wasteland.', 'Cross-Branch', 100, 1500, 5, '{"vb_venomblood_avatar"}', '{"x": -1688, "y": -975}', '{"damage": "20d10", "range": "30m", "mechanic": "Bypasses immunity"}', '☣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c97e5a2-7274-4f89-bab1-38a3908c2b20', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_shield_block', 'Kalkan Bloğu', 'Shield Block', 'Gelen fiziksel bir saldırıyı engeller ve o vuruş için savunmanıza +50 ekler.', 'Block an incoming physical attack, adding +50 to your defense for that hit.', 'Iron Wall', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"bonus_defense": 50, "duration": "1 hit"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a7bb11d-c1a5-4818-bbea-5923b4cb345a', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_iron_plating', 'Demir Kaplama', 'Iron Plating', 'Pasif. Temel savunmanıza sabit +20 bonus sağlar.', 'Passive. Grants a flat +20 bonus to your base defense.', 'Iron Wall', 4, 75, 1, '{"wg_shield_block"}', '{"x": 389, "y": -224}', '{"defense": "+20", "type": "passive"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('456ed602-4887-42a7-90c7-26480d255371', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_deflect_strike', 'Darbe Saptırma', 'Deflect Strike', 'Bir yakın dövüş saldırısını savuşturur ve hasarının %50''sini saldırgana geri yansıtır. Menzil: 2m.', 'Parry a melee attack and deflect 50% of its damage back to the attacker. Range: 2m.', 'Iron Wall', 8, 100, 1, '{"wg_iron_plating"}', '{"x": 606, "y": -349}', '{"reflect": "50%", "range": "2m"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca2325ce-855f-4795-977f-f4a25939d730', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_heavy_stance', 'Ağır Duruş', 'Heavy Stance', 'Alçak bir duruşa geçerek savrulma mesafelerini %50 azaltır ve +10 savunma kazanırsınız.', 'Adopt a low stance, reducing knockback distances by 50% and gaining +10 defense.', 'Iron Wall', 12, 150, 1, '{"wg_deflect_strike"}', '{"x": 822, "y": -474}', '{"knockback_reduction": "50%", "bonus_defense": 10}', '🏋️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4eda6b3e-73e0-4e76-b4ad-bf6e85b3cad8', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_steel_barricade', 'Çelik Barikat', 'Steel Barricade', '10 saniye boyunca mermileri ve hareketi engelleyen 3m genişliğinde çelik bir duvar çağırır.', 'Summon a 3m wide steel wall that blocks projectiles and movement for 10 seconds.', 'Iron Wall', 20, 200, 2, '{"wg_heavy_stance"}', '{"x": 1039, "y": -599}', '{"wall_width": "3m", "duration": "10s", "hp": 500}', '🚧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8348c59-0424-4c72-a643-668554b6bd0d', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_phalanx_guard', 'Falanks Koruması', 'Phalanx Guard', 'Savunmanızın %30''unu 15 saniye boyunca 5m içindeki müttefiklerinizle paylaşırsınız.', 'Share 30% of your defense with allies within a 5m radius for 15 seconds.', 'Iron Wall', 26, 250, 2, '{"wg_steel_barricade"}', '{"x": 1255, "y": -724}', '{"radius": "5m", "defense_share": "30%", "duration": "15s"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('887a8324-55a1-4f5f-a679-00b53219014c', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_shatter_proof', 'Kırılmaz', 'Shatterproof', 'Pasif. %30''un altındaki zırh delme etkilerine karşı bağışıklık kazanırsınız.', 'Passive. You become immune to armor penetration effects below 30%.', 'Iron Wall', 32, 300, 2, '{"wg_phalanx_guard"}', '{"x": 1472, "y": -849}', '{"armor_pen_immunity": "30%", "type": "passive"}', '💎');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9c9662f4-4936-4dca-a080-e73d79ffe7f8', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_titanium_shell', 'Titanyum Kabuk', 'Titanium Shell', 'Kendinizi titanyumla kaplayarak 10 saniye boyunca temel savunmanızı ikiye katlarsınız.', 'Coat yourself in titanium, doubling your base defense for 10 seconds.', 'Iron Wall', 40, 400, 3, '{"wg_shatter_proof"}', '{"x": 1688, "y": -974}', '{"defense_multiplier": 2.0, "duration": "10s"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ec35fb75-05fc-47dd-961d-180bcaab1bd9', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_kinetic_absorption', 'Kinetik Emilim', 'Kinetic Absorption', '5 saniye boyunca fiziksel hasarı emer, ardından emilen hasarın %50''sini 5m çapında bir şok dalgası olarak salarsınız.', 'Absorb physical damage for 5 seconds, then release 50% of absorbed damage as a 5m shockwave.', 'Iron Wall', 46, 450, 3, '{"wg_titanium_shell"}', '{"x": 1905, "y": -1099}', '{"duration": "5s", "absorb": "100%", "release_damage": "50%", "radius": "5m"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('db64d7b1-7a12-45b2-9e2b-55159ec031ba', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_bastion_of_steel', 'Çelik Kale', 'Bastion of Steel', 'Müttefiklerin +50 savunma ve %20 hasar azaltımı kazandığı 8 metrelik bir alan yaratırsınız.', 'Create an 8m zone where allies gain +50 defense and 20% damage reduction.', 'Iron Wall', 52, 500, 3, '{"wg_kinetic_absorption"}', '{"x": 2121, "y": -1224}', '{"radius": "8m", "bonus_defense": 50, "damage_reduction": "20%", "duration": "12s"}', '🏰');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3cb9136e-6215-4cb5-95ad-9ce34397dc30', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_adamantine_armor', 'Adamantiyum Zırh', 'Adamantine Armor', 'Pasif. Size karşı yapılan kritik vuruşlar normal vuruş sayılır ve zırhınız aşındırılamaz.', 'Passive. Critical hits against you are treated as normal hits, and your armor cannot be degraded.', 'Iron Wall', 60, 650, 4, '{"wg_bastion_of_steel"}', '{"x": 2338, "y": -1349}', '{"crit_immunity": true, "armor_degrade_immunity": true}', '💠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f19d39eb-e585-4b4e-89c3-eb7718727727', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_impenetrable_dome', 'Geçilmez Kubbe', 'Impenetrable Dome', '8 saniye boyunca tüm büyülü ve fiziksel mermileri engelleyen 15 metrelik koruyucu bir kubbe yansıtırsınız.', 'Project a 15m protective dome that blocks all magical and physical projectiles for 8 seconds.', 'Iron Wall', 68, 750, 4, '{"wg_adamantine_armor"}', '{"x": 2554, "y": -1474}', '{"radius": "15m", "duration": "8s", "projectile_block": "100%"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('07e99abf-eeb8-4eec-b1fe-422361f9ab36', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_fortress_manifestation', 'Kale Tezahürü', 'Fortress Manifestation', 'Boyutunuz %50 büyür, +150 savunma kazanırsınız ve yakın dövüş menziliniz 20 saniye boyunca 2m artar.', 'Grow in size by 50%, gaining +150 defense and extending your melee reach by 2m for 20 seconds.', 'Iron Wall', 76, 900, 4, '{"wg_impenetrable_dome"}', '{"x": 2771, "y": -1599}', '{"size": "+50%", "bonus_defense": 150, "reach": "+2m", "duration": "20s"}', '🏯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('74c1445b-876b-49e1-bca2-fd64b5bc3731', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_ultimate_aegis', 'Nihai Kalkan', 'Ultimate Aegis', 'Nihai. 10 saniye boyunca tamamen zarar göremez hale gelirsiniz. 20m içindeki müttefiklere yönelik tüm saldırılar size yönlendirilir.', 'Ultimate. Become completely invulnerable for 10 seconds. All attacks aimed at allies within 20m are redirected to you.', 'Iron Wall', 90, 1200, 5, '{"wg_fortress_manifestation"}', '{"x": 2987, "y": -1724}', '{"invulnerability": "10s", "taunt_radius": "20m", "redirect_damage": "100%"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('caba58c2-75fb-4d69-9146-c33e9fbc326b', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_vitality_surge', 'Canlılık Dalgası', 'Vitality Surge', 'Maksimum HP''nizin %15''ini anında iyileştirir.', 'Instantly recover 15% of your maximum HP.', 'Endurance', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"heal": "15% max_hp", "cooldown": "30s"}', '💖');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('41a96c8c-8667-453a-b894-a0a1e19d401a', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_pain_tolerance', 'Acı Toleransı', 'Pain Tolerance', 'Pasif. Savunma uygulanmadan önce gelen tüm hasarı sabit 5 puan azaltır.', 'Passive. Reduce all incoming damage by a flat 5 points before defense is applied.', 'Endurance', 5, 80, 1, '{"wg_vitality_surge"}', '{"x": 289, "y": 344}', '{"flat_damage_reduction": 5, "type": "passive"}', '🩹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6e3a2b76-34f9-4e25-95fa-faaebf5da132', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_thick_skin', 'Kalın Deri', 'Thick Skin', 'Pasif. Maksimum HP''nizi %10 artırır.', 'Passive. Increases your maximum HP by 10%.', 'Endurance', 9, 110, 1, '{"wg_pain_tolerance"}', '{"x": 449, "y": 536}', '{"max_hp": "+10%", "type": "passive"}', '🐘');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0c8aa501-0acc-4611-afdd-b726b461945b', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_endless_stamina', 'Sonsuz Dayanıklılık', 'Endless Stamina', 'Anında 1 bitkinlik yükünü temizler ve 50 dayanıklılık yenilersiniz.', 'Instantly clear 1 stack of exhaustion and recover 50 stamina.', 'Endurance', 14, 150, 1, '{"wg_thick_skin"}', '{"x": 610, "y": 727}', '{"exhaustion_clear": 1, "stamina_heal": 50}', '🔋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3341359b-0806-44b2-b320-1b64973eacb9', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_shrug_it_off', 'Umursamazlık', 'Shrug It Off', 'Pasif. Maksimum HP''nizin %5''inden daha az olan herhangi bir hasar yarı yarıya azaltılır.', 'Passive. Any instance of damage that is less than 5% of your max HP is reduced by half.', 'Endurance', 22, 220, 2, '{"wg_endless_stamina"}', '{"x": 771, "y": 919}', '{"damage_threshold": "5% max_hp", "reduction": "50%"}', '🤷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3cf85a98-09cf-4bac-a16a-4646fa172b87', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_second_wind', 'İkinci Nefes', 'Second Wind', 'HP %30''un altına düştüğünde, otomatik olarak eksik HP''nizin %20''sini iyileştirirsiniz.', 'When dropping below 30% HP, automatically heal for 20% of your missing HP.', 'Endurance', 28, 260, 2, '{"wg_shrug_it_off"}', '{"x": 932, "y": 1110}', '{"trigger": "30% hp", "heal": "20% missing_hp", "cooldown": "60s"}', '🌬️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ef9839b6-bf7f-4315-b7cd-6e802c503047', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_hardened_flesh', 'Sertleşmiş Et', 'Hardened Flesh', 'Ateş, soğuk ve yıldırım hasarlarına karşı %20 direnç kazanırsınız.', 'Gain 20% resistance to fire, cold, and lightning damage.', 'Endurance', 34, 300, 2, '{"wg_second_wind"}', '{"x": 1092, "y": 1302}', '{"elemental_resist": "20%", "type": "passive"}', '🥩');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f51b7dc5-72f1-4e1c-ac44-26ff7f212084', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_indomitable_spirit', 'Boyun Eğmez Ruh', 'Indomitable Spirit', 'Günde bir kez, 0 HP''ye düşecekken bunun yerine 1 HP''ye düşer ve 3 saniye boyunca hasara karşı bağışıklık kazanırsınız.', 'Once per day, when you would be reduced to 0 HP, you instead drop to 1 HP and become immune to damage for 3 seconds.', 'Endurance', 42, 420, 3, '{"wg_hardened_flesh"}', '{"x": 1253, "y": 1493}', '{"death_defy": 1, "immunity": "3s", "charges": "1/day"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e47c8dd1-9406-4d56-a81f-66f236c641fa', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_rapid_regeneration', 'Hızlı Yenilenme', 'Rapid Regeneration', '15 saniye boyunca her saniye maksimum HP''nizin %2''sini yenilersiniz.', 'Regenerate 2% of your max HP every second for 15 seconds.', 'Endurance', 48, 480, 3, '{"wg_indomitable_spirit"}', '{"x": 1414, "y": 1685}', '{"regen": "2%/s", "duration": "15s"}', '🌿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('616fdfbc-6bd0-4a3a-9909-52715401ee52', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_pain_is_power', 'Acı Güçtür', 'Pain is Power', 'Pasif. Eksik olan her %10 HP için +15 savunma ve +%5 fiziksel hasar kazanırsınız.', 'Passive. For every 10% HP you are missing, gain +15 defense and +5% physical damage.', 'Endurance', 54, 500, 3, '{"wg_rapid_regeneration"}', '{"x": 1574, "y": 1876}', '{"hp_missing_trigger": "10%", "bonus_defense": 15, "bonus_damage": "5%"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c152937d-4432-486c-aa45-e8cd71a1e299', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_juggernaut_vitality', 'Juggernaut Canlılığı', 'Juggernaut Vitality', 'Maksimum HP''nizi geçici olarak %50 artırır ve aynı miktarda iyileşirsiniz. 30 saniye sürer.', 'Temporarily increase your maximum HP by 50% and heal for the same amount. Lasts 30 seconds.', 'Endurance', 62, 700, 4, '{"wg_pain_is_power"}', '{"x": 1735, "y": 2068}', '{"max_hp_bonus": "50%", "duration": "30s"}', '🧟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a53f4df4-07c5-4f11-8b4b-9c625d7a3b9d', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_colossus_blood', 'Dev Kanı', 'Colossus Blood', 'Pasif. Temel can yenilenmeniz kalıcı olarak dakikada +50 HP artar ve zehirler %50 daha az hasar verir.', 'Passive. Your base health regeneration is permanently increased by +50 HP per minute, and poisons deal 50% less damage.', 'Endurance', 70, 800, 4, '{"wg_juggernaut_vitality"}', '{"x": 1896, "y": 2259}', '{"regen": "50/min", "poison_resist": "50%"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c8319665-aa1c-420e-81a9-b75fb40c8f6e', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_unyielding_flesh', 'Sarsılmaz Et', 'Unyielding Flesh', 'Tüm kanama, yanma ve zamanla hasar veren etkileri kaldırır, kaldırılan her etki için maksimum HP''nin %5''ini iyileştirir.', 'Remove all bleeds, burns, and damage-over-time effects, healing 5% max HP for each effect removed.', 'Endurance', 78, 900, 4, '{"wg_colossus_blood"}', '{"x": 2056, "y": 2451}', '{"cleanse": "DoTs", "heal_per_dot": "5% max_hp"}', '🧴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26a288aa-0aa7-4677-9fa0-2583b47a72b1', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_ultimate_undying', 'Nihai Ölümsüzlük', 'Ultimate Undying', 'Nihai. 20 saniye boyunca HP''niz 1''in altına düşemez. Etki sona erdiğinde, bu süre zarfında alınan tüm hasarın %50''si kadar iyileşirsiniz.', 'Ultimate. For 20 seconds, your HP cannot drop below 1. When the effect ends, heal for 50% of all damage taken during the duration.', 'Endurance', 90, 1200, 5, '{"wg_unyielding_flesh"}', '{"x": 2217, "y": 2642}', '{"duration": "20s", "immortality": true, "post_heal": "50% damage_taken"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('86b47e8c-559e-453b-b934-173869c7558c', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_rooted_stance', 'Köklü Duruş', 'Rooted Stance', 'Kendinizi 5 saniye boyunca yere sabitler, tüm itme, çekme ve havaya savurma etkilerine karşı bağışıklık kazanırsınız.', 'Root yourself in place for 5 seconds, becoming immune to all push, pull, and knockup effects.', 'Immovable', 2, 60, 1, '{}', '{"x": -128, "y": 153}', '{"root_self": true, "cc_immunity": "displacement", "duration": "5s"}', '🌳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2d01577e-10fb-4578-a7c7-103a54fca962', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_heavy_steps', 'Ağır Adımlar', 'Heavy Steps', 'Pasif. Hareket hızınız %10 azalır, ancak her adım bir mikro sarsıntıya neden olarak 3m içindeki düşmanların kaçınmasını %20 zorlaştırır.', 'Passive. Your movement speed is reduced by 10%, but every step causes a micro-tremor, making it 20% harder for enemies within 3m to dodge.', 'Immovable', 6, 90, 1, '{"wg_rooted_stance"}', '{"x": -289, "y": 344}', '{"move_speed": "-10%", "enemy_dodge_penalty": "20%", "radius": "3m"}', '👣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('fbfa3c27-7567-411a-a3c9-b6838c2fe387', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_gravity_anchor', 'Yerçekimi Çapası', 'Gravity Anchor', 'Bir düşmana vurarak ona bir yerçekimi çapası takarsınız; bu çapa 6 saniye boyunca o noktadan 5m uzağa gitmelerini engeller.', 'Strike an enemy, attaching a gravity anchor that prevents them from moving further than 5m from that spot for 6 seconds.', 'Immovable', 10, 120, 1, '{"wg_heavy_steps"}', '{"x": -449, "y": 536}', '{"tether_range": "5m", "duration": "6s"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('94da9dd2-a3f0-4e96-b6d4-9222f939b3e4', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_staggering_blow', 'Sarsıcı Darbe', 'Staggering Blow', '2d8 ezici hasar veren ve hedefi 1.5 saniye sersemleten ağır bir kalkan darbesi. Menzil: 2m.', 'A heavy shield bash that deals 2d8 bludgeoning damage and stuns the target for 1.5 seconds. Range: 2m.', 'Immovable', 15, 150, 1, '{"wg_gravity_anchor"}', '{"x": -610, "y": 727}', '{"damage": "2d8", "stun": "1.5s", "range": "2m"}', '🥊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('501b7a53-7465-46dc-b013-38a997e8667a', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_earth_bind', 'Toprak Bağı', 'Earth Bind', 'Yere şiddetle basarak 5m içindeki tüm düşmanları 3 saniye boyunca yere sabitlersiniz.', 'Stomp the ground, rooting all enemies within a 5m radius for 3 seconds.', 'Immovable', 24, 240, 2, '{"wg_staggering_blow"}', '{"x": -771, "y": 919}', '{"radius": "5m", "root": "3s"}', '🪨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2ec98b42-32b0-44e7-9900-00095d1055ac', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_mountain_stance', 'Dağ Duruşu', 'Mountain Stance', '8 saniye boyunca tüm kitle kontrol etkilerine karşı bağışıklık kazanırsınız, ancak hareket hızınız yarıya iner.', 'Gain immunity to all crowd control effects for 8 seconds, but your movement speed is halved.', 'Immovable', 30, 280, 2, '{"wg_earth_bind"}', '{"x": -932, "y": 1110}', '{"cc_immunity": "all", "move_speed": "-50%", "duration": "8s"}', '🏔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c6613e7a-ab78-49f9-9b0c-d2fe176f6649', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_bulwark_charge', 'Siper Hücumu', 'Bulwark Charge', 'Düz bir çizgide 10m ileri hücum edin. Yolunuzdaki düşmanlar kenara savrulur ve 4d6 ezici hasar alır.', 'Charge forward 10m in a straight line. Enemies in your path are knocked aside and take 4d6 bludgeoning damage.', 'Immovable', 36, 300, 2, '{"wg_mountain_stance"}', '{"x": -1092, "y": 1302}', '{"range": "10m", "damage": "4d6", "knockback": "3m"}', '🦏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('47124652-960c-410f-9eae-23b76def4621', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_gravity_well', 'Yerçekimi Kuyusu', 'Gravity Well', 'Güçlü bir yerçekimi çekimi yaratarak 15m içindeki tüm düşmanları kendinize doğru sürüklersiniz.', 'Generate a strong gravitational pull, dragging all enemies within 15m towards you.', 'Immovable', 44, 440, 3, '{"wg_bulwark_charge"}', '{"x": -1253, "y": 1493}', '{"pull_radius": "15m", "pull_center": "self"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f38a2fca-70c2-4251-8cab-a22a40088dfd', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_unstoppable_force', 'Durdurulamaz Güç', 'Unstoppable Force', '6 saniye boyunca fiziksel engellerden, duvarlardan ve büyülü güç alanlarından geçebilir, eğer kırılabilirlerse onları yok edebilirsiniz.', 'For 6 seconds, you can walk through physical barriers, walls, and magical forcefields, destroying them if they are breakable.', 'Immovable', 50, 490, 3, '{"wg_gravity_well"}', '{"x": -1414, "y": 1685}', '{"duration": "6s", "barrier_destruction": true}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('09d7687c-c980-421e-a5a3-d08bee93c067', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_seismic_slam', 'Sismik Çarpma', 'Seismic Slam', '8m''ye kadar sıçrar ve yere sertçe çarparsınız. 10m yarıçapındaki düşmanlar 6d8 hasar alır ve yere serilir.', 'Leap up to 8m and slam the ground. Enemies in a 10m radius take 6d8 damage and are knocked prone.', 'Immovable', 56, 500, 3, '{"wg_unstoppable_force"}', '{"x": -1574, "y": 1876}', '{"leap": "8m", "radius": "10m", "damage": "6d8", "knock_prone": true}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('354826f1-0c0b-4d49-bd66-4663ad7a856b', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_petrify_self', 'Kendini Taşlaştırma', 'Petrify Self', '5 saniye boyunca katı taşa dönüşürsünüz. Hareket edemezsiniz, %90 daha az hasar alırsınız ve saniyede %10 max HP iyileşirsiniz.', 'Turn into solid stone for 5 seconds. You cannot act, take 90% reduced damage, and heal 10% max HP per second.', 'Immovable', 64, 720, 4, '{"wg_seismic_slam"}', '{"x": -1735, "y": 2068}', '{"duration": "5s", "stun_self": true, "damage_reduction": "90%", "heal": "10%/s"}', '🗿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bc6f293e-e2a6-4bf5-a83c-b4a0b58bba94', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_weight_of_the_world', 'Dünyanın Yükü', 'Weight of the World', '10 saniye boyunca 30m yarıçapta yerçekimini artırır. Düşmanlar %80 yavaşlar ve uçan yaratıklar yere indirilir.', 'Increase gravity in a 30m radius for 10 seconds. Enemies are slowed by 80% and flying creatures are grounded.', 'Immovable', 72, 820, 4, '{"wg_petrify_self"}', '{"x": -1896, "y": 2259}', '{"radius": "30m", "duration": "10s", "slow": "80%", "ground_flyers": true}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d3f67be1-d8e7-45a9-b280-c64c3018cb17', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_tectonic_shift', 'Tektonik Kayma', 'Tectonic Shift', '20 metrelik bir alanda toprağı manipüle ederek düşmanları tuzağa düşürmek veya müttefikleri korumak için 4m yüksekliğinde duvarlar ve derin hendekler oluşturursunuz. 1 dakika sürer.', 'Manipulate the earth in a 20m area, creating 4m high walls and deep trenches to trap enemies or protect allies. Lasts 1 minute.', 'Immovable', 80, 900, 4, '{"wg_weight_of_the_world"}', '{"x": -2056, "y": 2451}', '{"radius": "20m", "wall_height": "4m", "duration": "60s"}', '🗺️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ce14d21d-88b0-475e-8a1d-3560434b3906', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_ultimate_mountain', 'Nihai Dağ', 'Ultimate Mountain', 'Nihai. 15 saniye boyunca yaşayan bir dağa dönüşürsünüz. Sonsuz kütleye sahipsiniz, hareket ettirilemezsiniz ve temel saldırılarınız 10m içinde alan etkili deprem yaratır.', 'Ultimate. Become a living mountain for 15 seconds. You have infinite mass, cannot be moved, and your basic attacks deal an AoE earthquake in 10m.', 'Immovable', 90, 1200, 5, '{"wg_tectonic_shift"}', '{"x": -2217, "y": 2642}', '{"duration": "15s", "mass": "infinite", "attack_aoe": "10m", "cc_immunity": "all"}', '🗻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e0c241ef-eb2e-4d80-b578-61010923bef1', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_iron_lungs', 'Demir Akciğerler', 'Iron Lungs', 'Gürleyen bir kükreme ile 15m içindeki düşmanları 4 saniye boyunca kışkırtır ve can yenilenmenizi artırırsınız.', 'Let out a booming roar that taunts enemies within 15m for 4 seconds and increases your health regeneration.', 'Cross-Branch', 25, 300, 2, '{"wg_heavy_stance", "wg_endless_stamina"}', '{"x": -173, "y": -100}', '{"taunt_radius": "15m", "duration": "4s", "bonus_regen": "1% max_hp/s"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f57545c8-eab7-4087-9a57-e28506b530e0', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_entrenched_bastion', 'Hendekli Siper', 'Entrenched Bastion', 'Yere kazarak 5 metrelik bir savunma çevresi oluşturursunuz. İçerideyken siz ve müttefikleriniz +40 savunma kazanır ve savrulmalara karşı bağışıklık kazanırsınız.', 'Dig into the ground, creating a 5m defensive perimeter. While inside, you and allies gain +40 defense and are immune to knockbacks.', 'Cross-Branch', 25, 300, 2, '{"wg_heavy_stance", "wg_staggering_blow"}', '{"x": -389, "y": -225}', '{"radius": "5m", "bonus_defense": 40, "knockback_immunity": true}', '🏕️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a4949f11-ef44-47db-b685-36531ee588dc', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_enduring_mountain', 'Dayanıklı Dağ', 'Enduring Mountain', 'Pasif. Hareketsiz kaldığınız her 2 saniye için %2 max HP ve +5 savunma yükü kazanırsınız (en fazla 10 yük). Hareket edince sıfırlanır.', 'Passive. For every 2 seconds you remain stationary, you gain a stack of 2% max HP and +5 defense (max 10 stacks). Resets upon moving.', 'Cross-Branch', 45, 500, 3, '{"wg_hardened_flesh", "wg_bulwark_charge"}', '{"x": -606, "y": -350}', '{"stack_timer": "2s", "max_stacks": 10, "hp_per_stack": "2%", "defense_per_stack": 5}', '⛺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7218f414-4aa8-4b2d-8041-c231bd3b9d89', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_reflective_carapace', 'Yansıtıcı Kabuk', 'Reflective Carapace', '8 saniye boyunca fiziksel hasarı saldıranlara geri yansıtırsınız. Yansıtma miktarı eksik HP yüzdenize eşittir.', 'For 8 seconds, reflect physical damage back to attackers. The reflection amount equals your missing HP percentage.', 'Cross-Branch', 45, 500, 3, '{"wg_shatter_proof", "wg_hardened_flesh"}', '{"x": -822, "y": -475}', '{"duration": "8s", "reflect_scaling": "missing_hp_%"}', '🪞');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('18484482-f43c-4802-92b5-fd5dc806fb79', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_gravity_shield', 'Yerçekimi Kalkanı', 'Gravity Shield', '10m içindeki düşman mermilerini aktif olarak kendine çeken, darbelerini emen ve mermi başına size 10 dayanıklılık veren bir kalkan yaratırsınız.', 'Create a shield that actively pulls enemy projectiles within 10m into itself, absorbing their impact and granting you 10 stamina per projectile.', 'Cross-Branch', 65, 800, 4, '{"wg_bastion_of_steel", "wg_seismic_slam"}', '{"x": -1039, "y": -600}', '{"pull_radius": "10m", "stamina_per_projectile": 10, "duration": "8s"}', '🧲');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cbf3aa37-1c3f-459f-8005-3cf9eae2b7bf', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_unstoppable_juggernaut', 'Durdurulamaz Juggernaut', 'Unstoppable Juggernaut', 'Pervasızca 15m''lik bir hücum. Çarpıştığınız her düşman için %5 max HP iyileşir ve +10 savunma kazanırsınız.', 'A reckless 15m charge. For every enemy you collide with, you heal 5% max HP and gain +10 defense.', 'Cross-Branch', 65, 800, 4, '{"wg_pain_is_power", "wg_seismic_slam"}', '{"x": -1255, "y": -725}', '{"range": "15m", "heal_per_target": "5%", "defense_per_target": 10}', '🚄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('28e56703-071f-4fb8-a18d-09c9f1c75fda', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_absolute_threshold', 'Mutlak Eşik', 'Absolute Threshold', 'Pasif. Duvar Muhafızı''nın temel prensibi. Eğer gelen bir saldırının ham hasarı Savunmanızın %150''sini aşarsa, darbe tamamen yok sayılır ve 0 hasar verir.', 'Passive. The core tenet of the Wall Guard. If an incoming attack''s raw damage exceeds 150% of your Defense, the hit is entirely ignored, dealing 0 damage.', 'Cross-Branch', 75, 900, 4, '{"wg_adamantine_armor", "wg_juggernaut_vitality", "wg_weight_of_the_world"}', '{"x": -1472, "y": -850}', '{"ignore_threshold": "1.5x defense", "damage_taken": 0}', '🚫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ccc75c3b-9aaa-4248-a10f-93140c73f3b2', 'd5034784-1d26-4fdb-9603-ff3722d20713', 'wg_grand_ultimate_world_shield', 'Yüce Nihai: Dünya Kalkanı', 'Grand Ultimate: World Shield', 'Yüce Nihai. 100m içindeki tüm müttefikleri korursunuz. 15 saniye boyunca alacakları tüm hasarın %100''ünü emersiniz. Eğer bu hasar Mutlak Eşik''i tetiklerse, hasar almak yerine iyileşirsiniz.', 'Grand Ultimate. Protect all allies in a 100m radius. You absorb 100% of all damage they would take for 15 seconds. If this damage triggers Absolute Threshold, you heal instead of taking damage.', 'Cross-Branch', 100, 1500, 5, '{"wg_ultimate_aegis", "wg_ultimate_undying", "wg_ultimate_mountain"}', '{"x": -1688, "y": -975}', '{"radius": "100m", "absorb_ally_damage": "100%", "duration": "15s", "threshold_heal": true}', '🛡️🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('935f9e87-b4c4-44f8-b510-f1f558d82944', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_blast', 'Kadim Işın', 'Eldritch Blast', 'Çatırdayan bir enerji ışını fırlatarak 1d10 güç hasarı ver.', 'Fire a beam of crackling energy dealing 1d10 force damage.', 'Eldritch Power', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"damage": "1d10", "damage_type": "force", "range": "20m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f11c6710-11a8-4d75-a348-c805c1f0bee9', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_force_repel', 'Güç İtimi', 'Force Repel', 'Bir hedefi 5m uzağa it ve 1d8 güç hasarı ver.', 'Push a target 5m away and deal 1d8 force damage.', 'Eldritch Power', 8, 100, 1, '{"wl_eldritch_blast"}', '{"x": 389, "y": -224}', '{"damage": "1d8", "damage_type": "force", "push": "5m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c01bc9c-dabb-4c8a-85b4-f5d93c243242', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_spear', 'Kadim Mızrak', 'Eldritch Spear', '30m menzile kadar ulaşabilen ve 2d10 güç hasarı veren uzak mesafe ışını.', 'A long-range blast up to 30m dealing 2d10 force damage.', 'Eldritch Power', 15, 150, 1, '{"wl_eldritch_blast"}', '{"x": 606, "y": -349}', '{"damage": "2d10", "damage_type": "force", "range": "30m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e634a605-a84b-45f7-9d46-73bf9b63406c', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_agonizing_blast', 'Istırap Işını', 'Agonizing Blast', '3 tur boyunca ışınlarına ıstırap aşılayarak hasarlarını %50 artır.', 'For 3 turns, infuse your blasts with agony, increasing their damage by 50%.', 'Eldritch Power', 22, 200, 2, '{"wl_eldritch_spear"}', '{"x": 822, "y": -474}', '{"buff": true, "blast_damage_multiplier": 1.5, "duration": "3 turns"}', '😣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8d0263a4-d1f6-4311-95da-e87d314f2ad8', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_barrage', 'Kadim Yaylım', 'Eldritch Barrage', 'Art arda 3 ışın fırlat, her biri 1d10 güç hasarı verir.', 'Fire 3 consecutive blasts, each dealing 1d10 force damage.', 'Eldritch Power', 28, 250, 2, '{"wl_eldritch_spear"}', '{"x": 1039, "y": -599}', '{"damage": "1d10", "hits": 3, "damage_type": "force"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0d71de98-f551-474c-a00e-131c701994c8', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_force_shield', 'Güç Kalkanı', 'Force Shield', 'Kendini bir güç alanıyla sar, 3 tur boyunca +3 Zırh Sınıfı ve 15 geçici Can Puanı kazan.', 'Surround yourself with a force field, gaining +3 AC and 15 temp HP for 3 turns.', 'Eldritch Power', 34, 275, 2, '{"wl_force_repel"}', '{"x": 1255, "y": -724}', '{"ac_bonus": 3, "temp_hp": 15, "duration": "3 turns"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13053ecc-5152-4089-ad25-47e86365bf33', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_chain', 'Kadim Zincir', 'Eldritch Chain', 'Işının 5m içindeki fazladan 2 hedefe sekerek her birine 2d8 güç hasarı verir.', 'Your blast chains to 2 additional targets within 5m, dealing 2d8 force damage to each.', 'Eldritch Power', 40, 300, 2, '{"wl_eldritch_barrage"}', '{"x": 1472, "y": -849}', '{"damage": "2d8", "damage_type": "force", "chain_targets": 2, "chain_range": "5m"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26281d43-a561-4360-a4c7-53b47c138be7', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_repelling_blast', 'İtici Işın', 'Repelling Blast', 'Devasa bir güç hedefi 10m uzağa itip yere serer, 4d8 hasar verir.', 'A massive force pushes the target 10m away and knocks them prone, dealing 4d8 damage.', 'Eldritch Power', 45, 375, 3, '{"wl_force_repel"}', '{"x": 1688, "y": -974}', '{"damage": "4d8", "damage_type": "force", "push": "10m", "prone": true}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9fa22273-7219-43ff-a903-a4711a762b71', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_storm', 'Kadim Fırtına', 'Eldritch Storm', '5m alan içinde saf güçten oluşan bir fırtına çağırarak 5d10 güç hasarı ver.', 'Call down a storm of pure force in a 5m AoE dealing 5d10 force damage.', 'Eldritch Power', 50, 425, 3, '{"wl_eldritch_barrage"}', '{"x": 1905, "y": -1099}', '{"damage": "5d10", "damage_type": "force", "aoe": "5m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('76404fd4-d6fb-4600-ab25-71d01dd161ea', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_force_singularity', 'Güç Tekilliği', 'Force Singularity', 'Bir yerçekimi kuyusu yarat. 10m içindeki tüm düşmanlar merkeze çekilir ve 4d10 güç hasarı alır.', 'Create a gravity well. All enemies within 10m are pulled to the center and take 4d10 force damage.', 'Eldritch Power', 55, 475, 3, '{"wl_eldritch_chain", "wl_force_shield"}', '{"x": 2121, "y": -1224}', '{"damage": "4d10", "damage_type": "force", "aoe": "10m", "pull_to_center": true}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('543770b3-4ae3-4d2e-8e67-440b3a5dd9a1', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_beam', 'Kadim Hüzme', 'Eldritch Beam', '15m uzunluğunda bir hat boyunca yoğunlaşmış bir güç hüzmesi sal, yoluna çıkan herkese 6d10 hasar ver.', 'Unleash a 15m line of concentrated force, dealing 6d10 damage to all in its path.', 'Eldritch Power', 60, 500, 3, '{"wl_agonizing_blast"}', '{"x": 2338, "y": -1349}', '{"damage": "6d10", "damage_type": "force", "line": "15m"}', '🔆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4eec4d48-f4a6-4d83-ba4b-1149968be568', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_annihilation', 'Kadim Yok Oluş', 'Eldritch Annihilation', 'Tek bir hedefi mutlak güçle ezerek 10d10 güç hasarı ver.', 'Overwhelm a single target with absolute force, dealing 10d10 force damage.', 'Eldritch Power', 66, 650, 4, '{"wl_eldritch_beam"}', '{"x": 2554, "y": -1474}', '{"damage": "10d10", "damage_type": "force", "single_target": true}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7198a758-c249-49fe-9864-09812c3a500e', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_force_quake', 'Güç Depremi', 'Force Quake', '10m yarıçapında yeri parçalayarak 8d10 güç hasarı ver ve herkesi yere ser.', 'Shatter the ground in a 10m radius, dealing 8d10 force damage and knocking everyone prone.', 'Eldritch Power', 72, 750, 4, '{"wl_repelling_blast", "wl_force_singularity"}', '{"x": 2771, "y": -1599}', '{"damage": "8d10", "damage_type": "force", "aoe": "10m", "prone": true}', '🫨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6f40619f-54e9-49f1-8b74-4b6098f6f5d6', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_avatar', 'Kadim Avatar', 'Eldritch Avatar', 'Haminin enerjisine kanalize ol. 3 tur boyunca tur başına iki Kadim büyü yapabilirsin.', 'Channel the Patron''s energy. For 3 turns, you can cast two Eldritch spells per turn.', 'Eldritch Power', 78, 850, 4, '{"wl_eldritch_storm"}', '{"x": 2987, "y": -1724}', '{"buff": true, "extra_casts": 1, "spell_type_restriction": "Eldritch", "duration": "3 turns"}', '👁️‍🗨️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('22c0271d-af22-45b8-ba76-45d1309b659c', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_supernova', 'Kadim Süpernova', 'Eldritch Supernova', 'NİHAİ: 20m yarıçapında devasa bir güç patlaması yaratarak 15d12 güç hasarı ver ve hayatta kalanları 1 tur sersemlet.', 'ULTIMATE: Detonate a massive force explosion in a 20m radius, dealing 15d12 force damage and stunning survivors for 1 turn.', 'Eldritch Power', 95, 1200, 5, '{"wl_eldritch_annihilation", "wl_force_quake", "wl_eldritch_avatar"}', '{"x": 3204, "y": -1849}', '{"damage": "15d12", "damage_type": "force", "aoe": "20m", "stun": "1 turn"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a98a1df5-975e-4207-a100-46b0ad0bc592', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_pact_weapon', 'Antlaşma Silahı', 'Pact Weapon', '3 tur boyunca 1d8 + Karizma değiştiricisi kadar büyü hasarı veren büyülü bir silah çağır.', 'Summon a magical weapon for 3 turns that deals 1d8 + Charisma modifier magic damage.', 'Pact Magic', 2, 50, 1, '{}', '{"x": 128, "y": 153}', '{"summon_weapon": true, "damage": "1d8+CHA", "duration": "3 turns"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5d24e2f5-e858-455a-b123-f4845c1b00c1', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_hex', 'Uğursuzluk', 'Hex', 'Bir hedefi 3 tur boyunca lanetle. Saldırıların ona fazladan 1d6 nekrotik hasar verir.', 'Curse a target for 3 turns. Your attacks deal an extra 1d6 necrotic damage to them.', 'Pact Magic', 10, 100, 1, '{}', '{"x": 289, "y": 344}', '{"debuff": true, "extra_damage_taken": "1d6 necrotic", "duration": "3 turns"}', '🧿');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a925d699-8c75-435a-85fe-d05a8d4c4555', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_pact_familiar', 'Antlaşma Yoldaşı', 'Pact Familiar', '3 tur boyunca seninle savaşması için başka dünyadan bir yoldaş çağır, tur başına 1d6 hasar verir.', 'Summon an otherworldly familiar for 3 turns to fight alongside you, dealing 1d6 damage per turn.', 'Pact Magic', 18, 150, 1, '{}', '{"x": 449, "y": 536}', '{"summon": true, "damage_per_turn": "1d6", "duration": "3 turns"}', '🦇');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('424ca405-b2ba-4db5-a4ff-dba071497752', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_patrons_grace', 'Haminin Lütfu', 'Patron''s Grace', 'Hami seni 2d8 iyileştirir ve bir olumsuz durum etkisini temizler.', 'The Patron heals you for 2d8 and cleanses one negative status effect.', 'Pact Magic', 24, 200, 2, '{"wl_pact_familiar"}', '{"x": 610, "y": 727}', '{"heal": "2d8", "cleanse": 1}', '🕊️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bb648020-3529-431b-b242-782d068f1960', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_hex_blade', 'Uğursuzluk Kılıcı', 'Hex Blade', 'Silahını 3 tur boyunca güçlendirerek fazladan 2d6 nekrotik hasar vermesini sağla.', 'Enhance your weapon for 3 turns, making it deal an additional 2d6 necrotic damage.', 'Pact Magic', 30, 250, 2, '{"wl_pact_weapon", "wl_hex"}', '{"x": 771, "y": 919}', '{"weapon_buff": true, "extra_damage": "2d6", "damage_type": "necrotic", "duration": "3 turns"}', '🪄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('73630632-5240-4596-a8a1-153d3d98acc6', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_pact_armor', 'Antlaşma Zırhı', 'Pact Armor', '3 tur boyunca büyüsel olmayan hasara karşı direnç sağlayan başka dünyadan bir zırh kazan.', 'Gain an otherworldly armor for 3 turns, granting resistance to non-magical damage.', 'Pact Magic', 36, 275, 2, '{"wl_pact_weapon"}', '{"x": 932, "y": 1110}', '{"resistance": "non-magical", "duration": "3 turns"}', '🧥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3f8f413f-5e7d-4811-8753-05c44eaef0b4', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_mystic_arcanum', 'Mistik Sır', 'Mystic Arcanum', 'Tüm 1. ve 2. aşama büyülerinin bekleme sürelerini anında sıfırla.', 'Instantly refresh the cooldowns of all your tier 1 and 2 spells.', 'Pact Magic', 40, 300, 2, '{"wl_hex"}', '{"x": 1092, "y": 1302}', '{"cooldown_reset": "tier 1-2"}', '🔮');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('800ce3f6-9831-4df2-918b-d8bc25bcc506', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_patrons_wrath', 'Haminin Gazabı', 'Patron''s Wrath', 'Şu anda Uğursuzluk etkisi altında olan bir hedefe 4d10 psişik hasar ver.', 'Deal 4d10 psychic damage to a target currently under your Hex.', 'Pact Magic', 46, 375, 3, '{"wl_hex_blade"}', '{"x": 1253, "y": 1493}', '{"damage": "4d10", "damage_type": "psychic", "requires": "Hex"}', '💢');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9e97be84-a8bb-4565-ad48-581d47c3c919', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_hex_storm', 'Uğursuzluk Fırtınası', 'Hex Storm', '10m yarıçapındaki tüm düşmanları 3 tur boyunca lanetleyerek senin hasarına karşı savunmasız hale getir.', 'Curse all enemies in a 10m radius for 3 turns, making them vulnerable to your damage.', 'Pact Magic', 52, 425, 3, '{"wl_hex_blade"}', '{"x": 1414, "y": 1685}', '{"aoe_hex": true, "aoe": "10m", "vulnerability": "self_damage", "duration": "3 turns"}', '🌧️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1e2462dd-5ea4-4924-a535-5538e9c7db2d', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_pact_summoning', 'Antlaşma Çağrısı', 'Pact Summoning', '3 tur boyunca maksimum Can Puanının %50''sine sahip olan ve 3d6 hasar veren zayıf bir iblis çağır.', 'Summon a lesser fiend for 3 turns that has 50% of your max HP and deals 3d6 damage.', 'Pact Magic', 56, 475, 3, '{"wl_pact_familiar"}', '{"x": 1574, "y": 1876}', '{"summon": "lesser_fiend", "summon_hp": "50% max HP", "summon_damage": "3d6", "duration": "3 turns"}', '👾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a1f4390-2f24-44d0-b80e-e51be8facb1a', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_arcanum_burst', 'Sır Patlaması', 'Arcanum Burst', 'Savaş alanındaki tüm aktif Uğursuzlukları tüketerek etkilenen her hedefe 5d10 hasar ver.', 'Consume all active Hexes on the battlefield, dealing 5d10 damage to each affected target.', 'Pact Magic', 60, 500, 3, '{"wl_mystic_arcanum", "wl_hex_storm"}', '{"x": 1735, "y": 2068}', '{"consume_hexes": true, "damage": "5d10", "damage_type": "force"}', '🧨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('551a6caa-8ad3-40c8-bfc2-3114dd57d659', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_patrons_vessel', 'Haminin Kabı', 'Patron''s Vessel', 'Haminin savaşçı kabı ol. 3 tur boyunca silah saldırıların otomatik olarak kritik vuruş yapar.', 'Become the Patron''s martial vessel. For 3 turns, your weapon attacks automatically critically hit.', 'Pact Magic', 68, 650, 4, '{"wl_patrons_wrath"}', '{"x": 1896, "y": 2259}', '{"buff": true, "auto_crit": "weapon_attacks", "duration": "3 turns"}', '🏺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7b2fe781-4a68-4b1b-ac1a-bb11639a9e9d', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_hex_mastery', 'Uğursuzluk Ustalığı', 'Hex Mastery', 'Uğursuzluk büyün artık hedefin Zırh Sınıfını ve kurtarma zarlarını 3 tur boyunca 3 düşürür.', 'Your Hex now also reduces the target''s Armor Class and saving throws by 3 for 3 turns.', 'Pact Magic', 74, 750, 4, '{"wl_hex_storm"}', '{"x": 2056, "y": 2451}', '{"passive": true, "hex_upgrade": true, "ac_reduction": 3, "saving_throw_reduction": 3}', '🎭');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('352f1747-34c4-4714-adb9-746a11ef8f29', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_pact_overload', 'Antlaşma Aşırı Yükü', 'Pact Overload', '3 tur boyunca tüm büyülerde +%100 hasar kazanmak için maksimum Can Puanının %20''sini feda et.', 'Sacrifice 20% of your max HP to gain +100% damage to all spells for 3 turns.', 'Pact Magic', 80, 850, 4, '{"wl_arcanum_burst"}', '{"x": 2217, "y": 2642}', '{"sacrifice_hp": "20%", "spell_damage_bonus": "100%", "duration": "3 turns"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8ae7f085-cdda-4147-889e-36031617aa9c', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_pact_apotheosis', 'Antlaşma Yücelişi', 'Pact Apotheosis', 'NİHAİ: Haminin devasa bir silüetini çağır. 3 tur boyunca 15m içindeki tüm düşmanlara otomatik olarak her tur 10d12 hasar verir.', 'ULTIMATE: Summon a towering aspect of your Patron. For 3 turns, it automatically deals 10d12 damage per turn to all enemies within 15m.', 'Pact Magic', 95, 1200, 5, '{"wl_patrons_vessel", "wl_hex_mastery", "wl_pact_overload"}', '{"x": 2378, "y": 2834}', '{"summon_aspect": true, "auto_damage": "10d12", "aoe": "15m", "duration": "3 turns"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('029e30d4-aacb-49e7-8252-14739f8d9f99', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_dark_bargain', 'Karanlık Pazarlık', 'Dark Bargain', '3 tur boyunca tüm saldırılarda avantaj kazanmak için mevcut Can Puanının %10''unu takas et.', 'Trade 10% of your current HP to gain advantage on all attacks for 3 turns.', 'Dark Pact', 4, 75, 1, '{}', '{"x": -128, "y": 153}', '{"sacrifice_current_hp": "10%", "advantage": "all_attacks", "duration": "3 turns"}', '🤝');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('61d001bb-ef76-4960-833d-e111097af6dc', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_life_drain', 'Yaşam Emişi', 'Life Drain', 'Bir hedefin yaşam gücünü emerek 2d6 nekrotik hasar ver ve verdiğin hasar kadar iyileş.', 'Drain a target''s life force, dealing 2d6 necrotic damage and healing yourself for the damage dealt.', 'Dark Pact', 12, 125, 1, '{}', '{"x": -289, "y": 344}', '{"damage": "2d6", "damage_type": "necrotic", "lifesteal": "100%"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('51c945d4-5e71-4edf-b7a6-2c05d43abc7b', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_hellish_rebuke', 'Cehennem Azarı', 'Hellish Rebuke', 'Hasar aldığında tepki olarak saldıranı cehennem ateşiyle sararak 2d10 ateş hasarı ver.', 'As a reaction when taking damage, surround your attacker in hellfire dealing 2d10 fire damage.', 'Dark Pact', 20, 150, 1, '{}', '{"x": -449, "y": 536}', '{"reaction": true, "damage": "2d10", "damage_type": "fire"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f7ca4f07-45c9-4876-9318-4bc6bdacfdf1', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_blood_pact', 'Kan Antlaşması', 'Blood Pact', '3 tur boyunca büyülerin mana yerine can harcar ve %25 fazladan hasar verir.', 'For 3 turns, your spells cost health instead of mana, and deal 25% extra damage.', 'Dark Pact', 25, 200, 2, '{"wl_dark_bargain"}', '{"x": -610, "y": 727}', '{"health_cost": true, "damage_bonus": "25%", "duration": "3 turns"}', '💉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b690b1f2-4802-42b9-9db5-c6b408f26d35', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_soul_harvest', 'Ruh Hasadı', 'Soul Harvest', 'Hedefin ruhundan bir parça kopararak 3d8 nekrotik hasar ver. Ölürlerse bir ruh parçası kazanırsın.', 'Rip a soul shard from a target, dealing 3d8 necrotic damage. Gain a soul shard if they die.', 'Dark Pact', 32, 250, 2, '{"wl_life_drain"}', '{"x": -771, "y": 919}', '{"damage": "3d8", "damage_type": "necrotic", "generate_soul_shard": "on_kill"}', '🫙');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('26dc5898-931d-444a-b398-cbd1ca2a1902', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_dark_flight', 'Karanlık Uçuş', 'Dark Flight', '3 tur boyunca uçurum kanatları oluştur, 15m uçma hızı kazan ve yer saldırılarından kaçın.', 'Manifest abyssal wings for 3 turns, gaining a flying speed of 15m and dodging ground attacks.', 'Dark Pact', 38, 275, 2, '{"wl_hellish_rebuke"}', '{"x": -932, "y": 1110}', '{"fly_speed": "15m", "dodge_ground_attacks": true, "duration": "3 turns"}', '🪽');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3b1bf464-6723-460f-a494-d0875d59b45a', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_infernal_gaze', 'Cehennem Bakışı', 'Infernal Gaze', 'Bir hedefle göz göze gel, 3 tur boyunca Korku aşıla ve 3d8 psişik hasar ver.', 'Lock eyes with a target, inflicting Fear for 3 turns and dealing 3d8 psychic damage.', 'Dark Pact', 40, 300, 2, '{"wl_soul_harvest"}', '{"x": -1092, "y": 1302}', '{"fear": "3 turns", "damage": "3d8", "damage_type": "psychic"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('18909237-9a94-49dd-8da2-1248bdefd94a', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_shadow_veil', 'Gölge Peçesi', 'Shadow Veil', 'Gölgelere karışarak 3 tur boyunca görünmezlik ve +%50 hareket hızı kazan.', 'Blend into the shadows, gaining invisibility and +50% movement speed for 3 turns.', 'Dark Pact', 48, 375, 3, '{"wl_dark_flight"}', '{"x": -1253, "y": 1493}', '{"invisibility": true, "movement_speed_bonus": "50%", "duration": "3 turns"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13ce80dd-199f-42f5-b533-1463e9d40f08', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_abyssal_flame', 'Uçurum Alevi', 'Abyssal Flame', 'Ateş direncini yok sayan ve 6d8 cehennem ateşi hasarı veren karanlık alevler yarat.', 'Conjure dark flames dealing 6d8 hellfire damage that ignores fire resistance.', 'Dark Pact', 54, 425, 3, '{"wl_infernal_gaze"}', '{"x": -1414, "y": 1685}', '{"damage": "6d8", "damage_type": "hellfire", "ignore_resistance": "fire"}', '💜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c80f242e-b16c-4679-afaf-270010555f7c', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_soul_rend', 'Ruh Yırtığı', 'Soul Rend', 'Bir ruh parçasını tüketerek 8d8 nekrotik hasar ver ve hedefi 1 tur sustur.', 'Consume a soul shard to deal 8d8 necrotic damage and silence the target for 1 turn.', 'Dark Pact', 58, 475, 3, '{"wl_soul_harvest"}', '{"x": -1574, "y": 1876}', '{"consume_soul_shard": 1, "damage": "8d8", "damage_type": "necrotic", "silence": "1 turn"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1ec88556-6c14-4b40-b7c5-4514406b0782', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_dark_sacrifice', 'Karanlık Kurban', 'Dark Sacrifice', 'Bir müttefikine maksimum Can Puanının %15''i kadar hasar vererek bir sonraki büyünün hasarını ikiye katla.', 'Deal damage to an ally equal to 15% of their max HP to double the damage of your next spell.', 'Dark Pact', 60, 500, 3, '{"wl_blood_pact"}', '{"x": -1735, "y": 2068}', '{"ally_damage": "15% max HP", "next_spell_damage_multiplier": 2.0}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('48bac015-3a54-43e7-a658-ff2d913032f9', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_fiendish_form', 'İblis Formu', 'Fiendish Form', '3 tur boyunca bir iblise dönüş. +%50 maksimum Can Puanı kazan ve saldırıların fazladan 4d10 ateş hasarı verir.', 'Transform into a fiend for 3 turns. Gain +50% max HP and your attacks deal +4d10 fire damage.', 'Dark Pact', 70, 700, 4, '{"wl_abyssal_flame"}', '{"x": -1896, "y": 2259}', '{"transform": true, "max_hp_bonus": "50%", "extra_attack_damage": "4d10 fire", "duration": "3 turns"}', '😈');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('46cd6c24-c582-47fa-9bf7-f6b0a7e6e212', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_hellfire_eruption', 'Cehennem Ateşi Patlaması', 'Hellfire Eruption', 'Yerden 10m alan içinde cehennem ateşi fışkırtarak 8d10 karışık ateş ve nekrotik hasar ver.', 'Erupt hellfire from the ground in a 10m AoE, dealing 8d10 mixed fire and necrotic damage.', 'Dark Pact', 76, 775, 4, '{"wl_abyssal_flame"}', '{"x": -2056, "y": 2451}', '{"damage": "8d10", "damage_type": "fire/necrotic", "aoe": "10m"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bd8fdb09-0c05-4a0f-b2c6-fc8bed46a50b', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_soul_devour', 'Ruh Yiyici', 'Soul Devour', 'En fazla 3 ruh parçasını tüket. Her parça seni maksimum Can Puanının %25''i kadar iyileştirir ve aktif Hami güçlendirmelerini 1 tur uzatır.', 'Consume up to 3 soul shards. Each shard heals you for 25% max HP and extends your active Patron buffs by 1 turn.', 'Dark Pact', 80, 850, 4, '{"wl_soul_rend"}', '{"x": -2217, "y": 2642}', '{"consume_soul_shard": "up to 3", "heal_per_shard": "25% max HP", "extend_buffs_per_shard": "1 turn"}', '🍷');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('00f4a7bc-a136-4ec1-954e-a7485894fc9b', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_contract_of_doom', 'Kıyamet Sözleşmesi', 'Contract of Doom', 'NİHAİ: Bir hedefi işaretle. 3 tur sonra 20d12 nekrotik hasar alırlar. Bundan ölürlerse, kalıcı olarak rastgele bir istatistiğe +1 kazanırsın (en fazla 5 kez).', 'ULTIMATE: Mark a target. After 3 turns, they take 20d12 necrotic damage. If they die from this, you permanently gain +1 to a random stat (max 5 times).', 'Dark Pact', 95, 1200, 5, '{"wl_fiendish_form", "wl_hellfire_eruption", "wl_soul_devour"}', '{"x": -2378, "y": 2834}', '{"mark": true, "delayed_damage": "20d12", "damage_type": "necrotic", "delay": "3 turns", "permanent_stat_gain": "+1 random stat (on kill)"}', '📜');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cfda1dfe-3ff5-4a63-95e3-da7b8daa0b77', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_eldritch_hex', 'Kadim Uğursuzluk', 'Eldritch Hex', 'Çapraz Dal: Ağır bir lanet uygula. Hedef 3 tur boyunca Uğursuzluğa uğrar ve anında 5d10 güç hasarı alır.', 'Cross-Branch: Inflict a heavy curse. The target is Hexed for 3 turns and instantly takes 5d10 force damage.', 'Cross-Branch', 55, 450, 3, '{"wl_eldritch_storm", "wl_hex_storm"}', '{"x": -173, "y": -100}', '{"damage": "5d10", "damage_type": "force", "debuff": "Hex", "duration": "3 turns"}', '⚛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b5aee731-90d6-426a-badf-b87bd95f1fef', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_dark_arcanum', 'Karanlık Sır', 'Dark Arcanum', 'Çapraz Dal: 3. ve 4. aşama Hami dönüşüm büyülerinin bekleme sürelerini anında sıfırla, bunun için Can Puanının %15''ini feda et.', 'Cross-Branch: Sacrifice 15% of your HP to instantly reset the cooldowns of your tier 3 and 4 Patron transformation spells.', 'Cross-Branch', 60, 500, 3, '{"wl_arcanum_burst", "wl_dark_sacrifice"}', '{"x": -389, "y": -225}', '{"sacrifice_hp": "15%", "cooldown_reset": "tier 3-4 transformations"}', '🗝️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('656ae12a-09b8-47e4-88cb-6609be9fef63', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_abyssal_blast', 'Uçurum Işını', 'Abyssal Blast', 'Çapraz Dal: 10d10 nekrotik/güç hasarı veren ve 3 tur boyunca Korku uygulayan yozlaşmış bir ışın fırlat.', 'Cross-Branch: Fire a corrupted blast dealing 10d10 necrotic/force damage and applying Fear for 3 turns.', 'Cross-Branch', 80, 800, 4, '{"wl_eldritch_avatar", "wl_fiendish_form"}', '{"x": -606, "y": -350}', '{"damage": "10d10", "damage_type": "necrotic/force", "fear": "3 turns"}', '🌑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4b1b0e99-bbef-4b82-a16b-957440826048', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_patrons_chosen', 'Haminin Seçilmişi', 'Patron''s Chosen', 'Çapraz Dal Pasif: Kadim Avatar, Haminin Kabı veya İblis Formu yeteneklerinden birini etkinleştirdiğinde, diğer ikisinin de etkilerinin yarısını 3 tur boyunca kazanırsın.', 'Cross-Branch Passive: When you activate Eldritch Avatar, Patron''s Vessel, or Fiendish Form, you gain half the benefits of the other two for 3 turns.', 'Cross-Branch', 90, 1100, 5, '{"wl_eldritch_avatar", "wl_patrons_vessel", "wl_fiendish_form"}', '{"x": -822, "y": -475}', '{"passive": true, "synergy": "form_benefits", "effectiveness": "50%", "duration": "3 turns"}', '🌟');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7150a7ff-0e35-4d1b-9878-2f3a5e835c6a', '09fc3407-bc97-40f1-8bcd-98210ca6e6f0', 'wl_absolute_pact', 'Mutlak Antlaşma', 'Absolute Pact', 'BÜYÜK NİHAİ: Tüm düşmanlar için zaman 3 tur durur. Sınırsız mana ve iki kat hasar kazanırsın. Tüm 3 dal nihaisi gerektirir. Uzun dinlenme başına bir kez.', 'GRAND ULTIMATE: Time stops for all enemies for 3 turns. You gain infinite mana and double damage. Requires all 3 branch ultimates. Once per long rest.', 'Cross-Branch', 100, 1500, 5, '{"wl_eldritch_supernova", "wl_pact_apotheosis", "wl_contract_of_doom"}', '{"x": -1039, "y": -600}', '{"time_stop": "3 turns", "infinite_mana": true, "damage_multiplier": 2.0, "once_per_long_rest": true}', '⏳');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d33b410-cac9-4b0d-8cae-05c986ee2175', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_bond_initiation', 'Bağ Başlangıcı', 'Bond Initiation', 'Tek bir silahla ön hazırlık bağı kurar. Silah, bonus eylem olarak 10 metreye kadar uzaktan ele çağrılabilir ve fazladan 1d4 güç hasarı verir.', 'Forges a preliminary bond with a single weapon. The weapon can be summoned to your hand from up to 10m away as a bonus action, and deals an extra 1d4 force damage.', 'Weapon Bond', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"summon_range": "10m", "bonus_damage": "1d4 force"}', '🗡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ca263a3e-c0bf-4d7a-8a71-75d16350c49b', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_weapon_recall', 'Silah Çağrısı', 'Weapon Recall', 'Fırlatılan veya düşürülen bağlı silahlar engelleri yok sayarak anında elinize döner. Dönüş yolundaki düşmanlar 1d6 kesici hasar alır. Menzil: 30m.', 'Thrown or dropped bonded weapons return to your hand instantly, ignoring obstacles. Enemies in the return path take 1d6 slashing damage. Range: 30m.', 'Weapon Bond', 5, 70, 1, '{"ws_bond_initiation"}', '{"x": 389, "y": -224}', '{"range": "30m", "return_damage": "1d6 slashing"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1431e7e-a820-4f41-9e80-084f094027b7', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_honed_edge', 'Bilenmiş Keski', 'Honed Edge', 'Bağınız, silahı doğaüstü bir dereceye kadar keskinleştirir. 1 dakika boyunca silah saldırılarınız 19-20 zarında kritik vuruş yapar ve +2 hasar verir.', 'Your bond sharpens the weapon to a supernatural degree. For 1 minute, your weapon attacks score a critical hit on a roll of 19-20 and deal +2 damage.', 'Weapon Bond', 10, 100, 1, '{"ws_bond_initiation"}', '{"x": 606, "y": -349}', '{"duration": "1 minute", "crit_range": "19-20", "bonus_damage": "+2"}', '🔪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d810c6d6-8501-4352-b441-6ce95eca302f', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_floating_blade', 'Uçan Kılıç', 'Floating Blade', 'Yanınızda süzülmesi için tek elli bir silahı canlandırırsınız. Bonus eylem olarak 15 metre içindeki bir hedefe saldırarak 1d8 + Zeka değiştiriciniz kadar kesici hasar verebilir.', 'You animate a one-handed weapon to float beside you. As a bonus action, it can attack a target within 15m, dealing 1d8 + your Intelligence modifier slashing damage.', 'Telekinetic Mastery', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"range": "15m", "damage": "1d8+Int slashing"}', '🪶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5f760538-ec70-4c2f-8914-be5a2ba8843b', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_phantom_throw', 'Hayalet Fırlatışı', 'Phantom Throw', 'Silahınızı telekinetik güçle fırlatın. 20 metreye kadar ilerler, cansız maddelerin içinden geçerek bir düşmana 2d6 delici hasar verir ve anında geri döner.', 'Hurl your weapon with telekinetic force. It travels up to 20m, phasing through non-living matter to strike an enemy for 2d6 piercing damage, then returns instantly.', 'Telekinetic Mastery', 8, 80, 1, '{"ws_floating_blade"}', '{"x": 289, "y": 344}', '{"range": "20m", "damage": "2d6 piercing", "special": "Phases through objects"}', '🎯');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('809f14cc-5d7f-486d-8ee9-461f84367637', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_telekinetic_push', 'Telekinetik İtiş', 'Telekinetic Push', 'Zihinsel bir enerji patlaması serbest bırakın. 10 metrelik bir koni içindeki düşmanlar 2d8 ezici hasar alır ve 5 metre geriye itilir.', 'Release a burst of mental energy. Enemies within a 10m cone take 2d8 bludgeoning damage and are pushed back 5m.', 'Telekinetic Mastery', 15, 120, 1, '{"ws_floating_blade"}', '{"x": 449, "y": 536}', '{"area": "10m cone", "damage": "2d8 bludgeoning", "knockback": "5m"}', '💨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('50bc614b-209e-40a0-bf68-d00ec69aa69f', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_spirit_slash', 'Ruhsal Kesiş', 'Spirit Slash', 'Silahınızı ruh enerjisiyle doldurun. Bir sonraki saldırı fiziksel zırhı yok sayar ve doğrudan hedefin yaşam gücüne 1d10 nekrotik hasar verir.', 'Infuse your weapon with soul energy. The next attack ignores physical armor and deals 1d10 necrotic damage directly to the target''s life force.', 'Soul Edge', 2, 60, 1, '{}', '{"x": -128, "y": 153}', '{"armor_bypass": "True", "damage": "1d10 necrotic"}', '👻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5c936191-533b-4208-8f68-9d8fa4104f65', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_ethereal_pierce', 'Eterik Delme', 'Ethereal Pierce', 'Kılıcınızı kalkanları aşmak için eterik hale getirerek 8 metreye kadar ileri atılın. 2d8 psişik hasar verir ve hedefin hareket hızını 1 tur boyunca %50 azaltır.', 'Lunge forward up to 8m, turning your blade ethereal to bypass shields. Deals 2d8 psychic damage and reduces the target''s movement speed by 50% for 1 round.', 'Soul Edge', 9, 90, 1, '{"ws_spirit_slash"}', '{"x": -289, "y": 344}', '{"range": "8m dash", "damage": "2d8 psychic", "status": "50% Slow"}', '💫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ddbf8405-48a6-4d78-aa72-4b523f91f59a', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_soul_rend', 'Ruh Yırtışı', 'Soul Rend', 'Ruhu parçalayan acımasız bir savurma. 3d6 kesici hasar verir. Hedef Bilgelik kurtarışında başarısız olursa, 1 tur boyunca büyü yapamaz veya büyülü yetenekler kullanamaz.', 'A vicious sweep that tears at the soul. Deals 3d6 slashing damage. If the target fails a Wisdom save, they cannot cast spells or use magical abilities for 1 round.', 'Soul Edge', 18, 140, 1, '{"ws_spirit_slash"}', '{"x": -449, "y": 536}', '{"damage": "3d6 slashing", "status": "Silence 1 round"}', '💔');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a8d92758-99fa-4498-b25e-e9a9aec291fa', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_unbreakable_steel', 'Kırılmaz Çelik', 'Unbreakable Steel', 'Silahınız tamamen yok edilemez hale gelir. Bir saldırıyı engellediğinizde +3 Zırh Sınıfı kazanırsınız ve saldıran kişi 2d6 geri tepme hasarı alır.', 'Your weapon becomes completely indestructible. When you block an attack, you gain +3 AC, and the attacker takes 2d6 recoil damage.', 'Weapon Bond', 22, 200, 2, '{"ws_honed_edge"}', '{"x": 822, "y": -474}', '{"ac_bonus": "+3", "recoil_damage": "2d6"}', '🛡️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('791f04bc-c625-43eb-820f-654816582684', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_sentient_parry', 'Bilinçli Savuşturma', 'Sentient Parry', 'Bağlı silah sizi korumak için kendi kendine hafifçe hareket eder. Kalıcı olarak +1 Zırh Sınıfı sağlar ve tur başına bir ücretsiz savuşturma reaksiyonu vererek gelen hasarı 1d10 + seviyeniz kadar azaltır.', 'The bonded weapon moves slightly on its own to protect you. Grants a permanent +1 to AC and allows one free parry reaction per round, reducing incoming damage by 1d10 + your level.', 'Weapon Bond', 28, 230, 2, '{"ws_weapon_recall"}', '{"x": 1039, "y": -599}', '{"passive_ac": "+1", "damage_reduction": "1d10 + level"}', '👁️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9b93e920-1d2f-40df-99ca-cfe22ecc8600', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_bonded_strike', 'Bağlı Vuruş', 'Bonded Strike', 'Bağınızı yıkıcı bir vuruşa dönüştürün. 4d8 fiziksel hasar verir. Hedef son bir dakika içinde size vurduysa, hasar iki katına çıkar.', 'Channel your bond into a devastating blow. Deals 4d8 physical damage. If the target has struck you in the last minute, the damage is doubled.', 'Weapon Bond', 35, 280, 2, '{"ws_unbreakable_steel"}', '{"x": 1255, "y": -724}', '{"damage": "4d8 physical", "conditional_multiplier": "x2"}', '⚔️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e859b682-5f74-4251-a783-b9a6f2c6c8dc', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_dancing_swords', 'Dans Eden Kılıçlar', 'Dancing Swords', 'Aynı anda en fazla 3 silahı canlandırabilirsiniz. Savunma ekranı oluşturarak +2 Zırh Sınıfı sağlarlar ve bağımsız olarak saldırıp 15m içindeki hedeflere her biri 1d8 hasar verebilirler.', 'You can animate up to 3 weapons at once. They form a defensive screen, granting +2 AC, and can strike out independently, dealing 1d8 damage each to targets within 15m.', 'Telekinetic Mastery', 24, 200, 2, '{"ws_phantom_throw"}', '{"x": 610, "y": 727}', '{"summons": "3 weapons", "ac_bonus": "+2", "damage": "3x 1d8"}', '💃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('95fa8b9c-2bd6-4cb2-abc6-dfacd6133eb7', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_orbiting_guard', 'Yörüngesel Koruma', 'Orbiting Guard', 'Uçan kılıçlarınız etrafınızda 3 metrelik bir yarıçapta hızla döner. Bu alana giren veya turuna burada başlayan her düşman 3d6 kesici hasar alır.', 'Your floating blades spin rapidly around you in a 3m radius. Any enemy entering or starting their turn in this zone takes 3d6 slashing damage.', 'Telekinetic Mastery', 30, 250, 2, '{"ws_dancing_swords"}', '{"x": 771, "y": 919}', '{"radius": "3m", "damage": "3d6 slashing"}', '🪐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('486ce40f-c930-4426-a9c0-434e1a205a80', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_mind_over_metal', 'Metale Hükmeden Zihin', 'Mind Over Metal', '20 metre içindeki bir rakibin silahını zihninizle zorla çekerek onu silahsız bırakın veya çevredeki metal nesneleri yönlendirerek düşmanları ezip 4d6 hasar verin.', 'Disarm an opponent within 20m by forcefully pulling their weapon with your mind, or manipulate environmental metal objects to crush foes for 4d6 damage.', 'Telekinetic Mastery', 38, 290, 2, '{"ws_telekinetic_push"}', '{"x": 932, "y": 1110}', '{"range": "20m", "damage": "4d6 bludgeoning", "utility": "Disarm"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bca7d7b5-d46d-4c97-adf5-867cf8c675ce', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_astral_cleave', 'Astral Yarma', 'Astral Cleave', '15 metre ilerleyen bir astral enerji yayı serbest bırakın. Bir hat üzerindeki tüm hedefleri vurarak 4d6 radyant ve nekrotik hasar verir.', 'Unleash an arc of astral energy that travels 15m. Hits all targets in a line, dealing 4d6 radiant and necrotic damage.', 'Soul Edge', 25, 210, 2, '{"ws_ethereal_pierce"}', '{"x": -610, "y": 727}', '{"area": "15m line", "damage": "4d6 radiant/necrotic"}', '✨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c6d00436-91a0-4b55-986a-e784c273cdfd', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_phantom_reach', 'Hayalet Menzil', 'Phantom Reach', 'Silahınız, siz vurduktan hemen sonra vuran ardıl görüntüler bırakır. 1 dakika boyunca, her başarılı yakın dövüş saldırısı orijinal hasarın yarısı kadar ikincil bir vuruş yapar.', 'Your weapon leaves afterimages that strike slightly after you do. For 1 minute, every successful melee attack deals a secondary hit for half the original damage.', 'Soul Edge', 32, 260, 2, '{"ws_soul_rend"}', '{"x": -771, "y": 919}', '{"duration": "1 minute", "buff": "Extra hit for 50% damage"}', '📏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('848965ae-3e66-4fee-a3a0-05b20f68bd49', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_spirit_burn', 'Ruh Yanığı', 'Spirit Burn', 'Lanetli bir vuruşla hedefin ruhunu ateşe verin. 3d8 ateş hasarı verir ve hedef 3 tur boyunca sırasının başında ek olarak 2d6 nekrotik hasar alır.', 'Ignite the target''s soul with a cursed strike. Deals 3d8 fire damage, and the target takes an additional 2d6 necrotic damage at the start of their turn for 3 rounds.', 'Soul Edge', 39, 300, 2, '{"ws_astral_cleave"}', '{"x": -932, "y": 1110}', '{"damage": "3d8 fire", "dot": "2d6 necrotic for 3 rounds"}', '🔥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8a319ba6-ce9c-4453-9aa1-9011ab7d4770', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_telepathic_bond', 'Telepatik Bağ', 'Telepathic Bond', 'Telekineziyi silah bağınızla birleştirin. Artık silahınızın kabzasından, orada gözleriniz varmış gibi 100 metreye kadar görebilir ve zihinsel olarak bir bölgede devriye gezmesini emredebilirsiniz.', 'Merge telekinesis with your weapon bond. You can now see through the hilt of your weapon as if you had eyes there, up to 100m away, and can mentally command it to patrol an area.', 'Cross-Branch', 26, 220, 2, '{"ws_weapon_recall", "ws_floating_blade"}', '{"x": -173, "y": -100}', '{"utility": "Remote vision 100m", "duration": "1 hour"}', '📡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('31c11b2f-1c6e-4316-9b10-05bf27942420', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_soul_bonded_weapon', 'Ruhla Bağlanmış Silah', 'Soul Bonded Weapon', 'Silahınız bedeninize değil doğrudan ruhunuza bağlanır. Artık çalınamaz. Eğer ölürseniz, silah siz dirilene kadar eterik düzlemde kaybolur. Fazladan 2d6 güç hasarı verir.', 'Your weapon binds directly to your soul instead of your body. It can no longer be stolen. If you die, the weapon vanishes into the ethereal plane until you are resurrected. Deals an extra 2d6 force damage.', 'Cross-Branch', 34, 270, 2, '{"ws_bonded_strike", "ws_ethereal_pierce"}', '{"x": -389, "y": -225}', '{"passive": "Unstealable, vanishes on death", "bonus_damage": "2d6 force"}', '🔗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2f0fb26b-34d8-429a-b42f-6edf84e95052', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_blood_pact', 'Kan Anlaşması', 'Blood Pact', 'Yaşam gücünüzü silahla karıştırırsınız. Maksimum canınızın %10''unu feda ederek silahınızın fazladan 3d6 nekrotik hasar vermesini ve 3 tur boyunca verilen toplam hasarın %50''si kadar sizi iyileştirmesini sağlarsınız.', 'You mix your vitality with the weapon. By sacrificing 10% of your max HP, your weapon deals an additional 3d6 necrotic damage and heals you for 50% of the total damage dealt for 3 rounds.', 'Weapon Bond', 42, 360, 3, '{"ws_bonded_strike"}', '{"x": 1472, "y": -849}', '{"cost": "10% HP", "bonus_damage": "3d6 necrotic", "lifesteal": "50%", "duration": "3 rounds"}', '🩸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('97c0ed3a-2381-4f05-baeb-ba49034b8c2f', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_symbiotic_healing', 'Simbiyotik İyileşme', 'Symbiotic Healing', 'Silah, yaralarınızı sarmak için ortamdaki büyüyü emer. Bonus eylem olarak 4d8 + 15 Can yeniler. Uzun dinlenme başına 3 kez kullanılabilir.', 'The weapon absorbs ambient magic to knit your wounds. As a bonus action, restore 4d8 + 15 HP. Can be used 3 times per long rest.', 'Weapon Bond', 48, 400, 3, '{"ws_sentient_parry"}', '{"x": 1688, "y": -974}', '{"healing": "4d8 + 15", "uses": "3/long rest"}', '💚');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('658fc758-a6e3-4391-babe-ad965050b956', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_weapon_surge', 'Silah Taşkını', 'Weapon Surge', 'Bağınızın depolanan enerjisini 15 metrelik bir şok dalgasıyla serbest bırakın. 6d6 güç hasarı verir ve düşmanları yere serer. 2 tur boyunca hızlanma kazanırsınız.', 'Unleash the stored energy of your bond in a 15m shockwave. Deals 6d6 force damage and knocks enemies prone. You gain haste for 2 rounds.', 'Weapon Bond', 55, 460, 3, '{"ws_blood_pact"}', '{"x": 1905, "y": -1099}', '{"range": "15m radius", "damage": "6d6 force", "status": "Prone", "buff": "Haste 2 rounds"}', '🌊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f18db789-0028-465e-a104-82c9c78b6a5b', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_blade_storm', 'Kılıç Fırtınası', 'Blade Storm', 'Düzinelerce telekinetik spektral kılıca 15 metrelik bir alanda yağmasını emredin. Hedefler 6d8 kesici hasar alır. Başarılı bir Çeviklik kurtarışında yarı hasar alınır.', 'Command dozens of telekinetic spectral blades to rain down in a 15m radius. Targets take 6d8 slashing damage. Half damage on a successful Dexterity save.', 'Telekinetic Mastery', 45, 380, 3, '{"ws_dancing_swords"}', '{"x": 1092, "y": 1302}', '{"radius": "15m", "damage": "6d8 slashing", "save": "Dexterity for half"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('57633eaa-d19e-4655-8823-2ef69dde3934', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_telekinetic_execution', 'Telekinetik İnfaz', 'Telekinetic Execution', 'Tüm zihinsel gücünüzü odaklayarak bir kılıcı uzaktan tek bir hedefin hayati noktasına saplayın. Menzil 30m. 8d8 delici hasar verir. Hedefin canı %20''nin altındaysa anında öldürür (patronlar bunun yerine 50 ekstra hasar alır).', 'Focus all your mental might to drive a blade into a single target''s vital spot from afar. Range 30m. Deals 8d8 piercing damage. If the target is below 20% HP, it is an instant kill (bosses take 50 extra damage instead).', 'Telekinetic Mastery', 52, 420, 3, '{"ws_orbiting_guard"}', '{"x": 1253, "y": 1493}', '{"range": "30m", "damage": "8d8 piercing", "special": "Execute at 20% HP"}', '⚖️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f8e92525-b123-4c84-808c-08f466a2930a', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_magnetic_pull', 'Manyetik Çekim', 'Magnetic Pull', 'Metalik enerjiden oluşan bir yerçekimi kuyusu yaratın. 25m içindeki tüm düşmanları merkezi bir noktaya çeker, onları 1 tur sabitler ve 4d8 güç hasarı verir.', 'Create a gravity well of metallic energy. Pulls all enemies within 25m towards a central point, pinning them for 1 round and dealing 4d8 force damage.', 'Telekinetic Mastery', 58, 480, 3, '{"ws_mind_over_metal"}', '{"x": 1414, "y": 1685}', '{"radius": "25m", "damage": "4d8 force", "status": "Pinned 1 round"}', '🕳️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('991e5bec-1ca3-4337-b3cb-11d8a42ddae6', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_soul_severing_strike', 'Ruh Koparan Vuruş', 'Soul Severing Strike', 'Beden ile ruhu birbirine bağlayan ipliği hedefleyen kesin bir vuruş. 6d10 nekrotik hasar verir. Kritik vuruşta hedef 1 tur felç olur.', 'A precise strike aimed at the thread connecting body and soul. Deals 6d10 necrotic damage. On a critical hit, the target is paralyzed for 1 round.', 'Soul Edge', 44, 370, 3, '{"ws_phantom_reach"}', '{"x": -1092, "y": 1302}', '{"damage": "6d10 necrotic", "status": "Paralyze on crit"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a87182ba-bdc1-43cc-9333-f4dd66f78c50', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_ghost_blade', 'Hayalet Kılıç', 'Ghost Blade', 'Kılıcınız gerçekliğin dışına çıkar. 3 tur boyunca saldırılarınız tüm fiziksel zırhları, büyülü bariyerleri ve hasar dirençlerini tamamen yok sayar.', 'Your blade phases out of reality. For 3 rounds, your attacks completely ignore all physical armor, magical barriers, and damage resistances.', 'Soul Edge', 50, 430, 3, '{"ws_astral_cleave"}', '{"x": -1253, "y": 1493}', '{"duration": "3 rounds", "buff": "Ignore armor/barriers/resistance"}', '🌫️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f0046811-0c4b-46ca-805f-aa745e8512b4', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_inner_demon_manifestation', 'İçsel İblis Tezahürü', 'Inner Demon Manifestation', 'Ruhunuzun karanlık enerjisini tezahür ettirin. Seviyenizin iki katı kadar geçici Can kazanırsınız, gözleriniz parlar ve 10 metrelik bir yarıçapta korku aurası yayarsınız.', 'Manifest the dark energy of your soul. You gain temporary HP equal to twice your level, your eyes glow, and you project an aura of fear in a 10m radius.', 'Soul Edge', 56, 490, 3, '{"ws_spirit_burn"}', '{"x": -1414, "y": 1685}', '{"temp_hp": "Level x2", "aura": "10m Fear"}', '👹');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('170dee16-7859-4096-a572-006f8e2dd323', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_phantom_barrage', 'Hayalet Yaylım Ateşi', 'Phantom Barrage', 'Uçan silahlarınız eterik hale gelir. 20m içindeki hedeflere 6 hayalet vuruşluk bir yaylım ateşi başlatırlar. Her vuruş 2d10 psişik hasar verir ve siperi yok sayar.', 'Your floating weapons become ethereal. They unleash a volley of 6 phantom strikes on targets within 20m. Each strike deals 2d10 psychic damage and ignores cover.', 'Cross-Branch', 46, 390, 3, '{"ws_dancing_swords", "ws_spirit_slash"}', '{"x": -606, "y": -350}', '{"range": "20m", "strikes": "6", "damage": "2d10 psychic/strike"}', '🎆');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0fd683f-ae93-40ca-a29e-5209b4ad7839', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_trinity_strike', 'Üçlü Vuruş', 'Trinity Strike', 'Fiziksel kudreti, telekinetik gücü ve ruh parçalamayı tek bir saldırıda birleştirin. 15 metreye kadar atılır ve 4d8 fiziksel, 4d8 güç ve 4d8 nekrotik hasar verirsiniz.', 'Combine physical might, telekinetic force, and soul rending into a single attack. You dash up to 15m and strike for 4d8 physical, 4d8 force, and 4d8 necrotic damage.', 'Cross-Branch', 55, 470, 3, '{"ws_blood_pact", "ws_telekinetic_execution", "ws_ghost_blade"}', '{"x": -822, "y": -475}', '{"range": "15m dash", "damage": "4d8 phys + 4d8 force + 4d8 necrotic"}', '🔺');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('13bc329c-2ba0-44d2-9d0d-4505283e1ff0', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_true_name_awakening', 'Gerçek İsim Uyanışı', 'True Name Awakening', 'Silahınızın gerçek ruh adını öğrenirsiniz. 10 dakika boyunca eser seviyesinde bir silaha dönüşerek her vuruşta fazladan 4d10 güç hasarı verir ve tüm fiziksel dirençleri yok sayar.', 'You learn the true spirit name of your weapon. It transforms into an artifact-level weapon for 10 minutes, dealing an extra 4d10 force damage per hit and ignoring all physical resistances.', 'Weapon Bond', 65, 650, 4, '{"ws_weapon_surge"}', '{"x": 2121, "y": -1224}', '{"duration": "10 minutes", "bonus_damage": "4d10 force", "penetration": "Ignores physical resistance"}', '🗣️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('65199226-7e01-415f-a135-edf9818388b8', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_master_s_grip', 'Ustanın Tutuşu', 'Master''s Grip', 'Asla silahsız bırakılamazsınız ve vuruşlarınız engellenemez veya savuşturulamaz. Silahınız kalkanlardan ve büyülerden gelen Zırh Sınıfı bonuslarını yok sayarak hedefin ZS''sini 10 + Çeviklik olarak kabul eder.', 'You can never be disarmed, and your strikes cannot be blocked or parried. Your weapon ignores AC bonuses from shields and spells, treating target AC as 10 + Dex.', 'Weapon Bond', 72, 700, 4, '{"ws_symbiotic_healing", "ws_blood_pact"}', '{"x": 2338, "y": -1349}', '{"passive": "Cannot be disarmed/blocked", "ac_bypass": "Treats AC as 10+Dex"}', '🗜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6bbc1efb-586d-4c75-a8bd-d68b164473f7', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_living_arsenal', 'Yaşayan Cephanelik', 'Living Arsenal', 'Vücudunuz silahınız için bir kın haline gelir. Silahınızı vücudunuzun içinde saklayabilirsiniz. Saklıyken tur başına 20 Can yenilersiniz. Çekildiğinde, ilk vuruş maksimum hasarla otomatik olarak kritik vurur.', 'Your body becomes a sheath for your weapon. You can store your weapon inside your body. While stored, you regenerate 20 HP per round. When drawn, the first strike deals an automatic critical hit with max damage.', 'Weapon Bond', 78, 780, 4, '{"ws_master_s_grip"}', '{"x": 2554, "y": -1474}', '{"regen": "20 HP/round", "draw_attack": "Auto-crit max damage"}', '🏛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1b644749-55fc-43d9-bef4-ef1c76f7928b', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_thousand_swords_formation', 'Bin Kılıç Dizilimi', 'Thousand Swords Formation', 'Arkanızda süzülen 1000 spektral kılıç çağırın. Sonraki 5 tur boyunca, bonus eylem olarak 30 metrelik bir hat boyunca 10d6 büyülü kesici hasar veren 200 kılıçlık bir yaylım ateşi başlatabilirsiniz.', 'Conjure 1000 spectral swords that hover behind you. For the next 5 rounds, as a bonus action, you can unleash a barrage of 200 swords dealing 10d6 magical slashing damage in a 30m line.', 'Telekinetic Mastery', 66, 680, 4, '{"ws_blade_storm"}', '{"x": 1574, "y": 1876}', '{"duration": "5 rounds", "area": "30m line", "damage": "10d6 magical slashing/round"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e062651-a45a-44c5-b70e-0a51a56bb2a1', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_invisible_wielder', 'Görünmez Silahtar', 'Invisible Wielder', 'Ana silahınızı telekinetik olarak o kadar hızlı kullanırsınız ki görünmez olur. Bu silahla yapılan saldırılar avantajlıdır, savuşturulamaz ve ekstra 6d8 psişik hasar verir. 3 tur sürer.', 'Telekinetically manipulate your primary weapon so fast it becomes invisible. Attacks with this weapon have advantage, cannot be parried, and deal an additional 6d8 psychic damage. Lasts 3 rounds.', 'Telekinetic Mastery', 74, 760, 4, '{"ws_telekinetic_execution"}', '{"x": 1735, "y": 2068}', '{"duration": "3 rounds", "buff": "Advantage, unparryable", "bonus_damage": "6d8 psychic"}', '🫥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e5fd8e67-05c7-47b5-b542-b72d9b22b6e2', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_domain_of_blades', 'Kılıçların Alanı', 'Domain of Blades', '40 metrelik bir yarıçapı kişisel alanınıza dönüştürün. Alan içinde bir silahın bulunduğu herhangi bir yere anında ışınlanabilirsiniz. İçerideki düşmanlar hareket ettikleri her 5 metre için 2d10 hasar alır.', 'Transform a 40m radius area into your personal domain. You can instantly teleport to any location within the domain where a weapon is present. Enemies inside take 2d10 damage for every 5m they move.', 'Telekinetic Mastery', 79, 850, 4, '{"ws_magnetic_pull", "ws_blade_storm"}', '{"x": 1896, "y": 2259}', '{"radius": "40m", "utility": "Teleport to weapon", "movement_penalty": "2d10 per 5m moved"}', '⛩️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a0efc53a-b7a8-474f-b452-4c6d0c052401', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_dimension_cutter', 'Boyut Kesen', 'Dimension Cutter', 'Uzay dokusunu kesin. İçerideki herkese 10d8 güç hasarı veren 20 metrelik bir uzaysal yarık yaratır ve sizi anında diğer tarafa ışınlar.', 'Slice through the fabric of space. Creates a 20m spatial rift that deals 10d8 force damage to all inside and teleports you instantly to the other side.', 'Soul Edge', 64, 630, 4, '{"ws_ghost_blade"}', '{"x": -1574, "y": 1876}', '{"area": "20m line", "damage": "10d8 force", "utility": "Teleport 20m"}', '✂️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40d07c52-ca73-4e16-b850-f6649cc63254', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_soul_reaper_s_dance', 'Ruh Biçicinin Dansı', 'Soul Reaper''s Dance', 'Hayaletimsi bir zarafetle hareket ederek 25m içindeki en fazla 5 farklı hedefe saldırı yapın. Her vuruş 5d10 psişik hasar verir ve sizi verilen hasarın yarısı kadar iyileştirir.', 'Move with phantom grace, making an attack against up to 5 different targets within 25m. Each strike deals 5d10 psychic damage and heals you for half the damage dealt.', 'Soul Edge', 70, 690, 4, '{"ws_soul_severing_strike"}', '{"x": -1735, "y": 2068}', '{"targets": "5", "range": "25m", "damage": "5d10 psychic", "lifesteal": "50%"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ffeda12f-64c7-4569-905f-aeeeea5d8552', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_absolute_severance', 'Mutlak Koparma', 'Absolute Severance', 'Büyü kavramının kendisini kesen kusursuz bir vuruş. 12d8 nekrotik hasar verir. Hedefteki tüm büyülü güçlendirmeleri siler ve 1 dakika boyunca iyileştirilmelerini engeller.', 'A flawless strike that cuts the very concept of magic. Deals 12d8 necrotic damage. Purges all magical buffs from the target and prevents them from being healed for 1 minute.', 'Soul Edge', 77, 770, 4, '{"ws_dimension_cutter", "ws_soul_severing_strike"}', '{"x": -1896, "y": 2259}', '{"damage": "12d8 necrotic", "utility": "Dispel buffs", "status": "Prevent healing 1 minute"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('3cd667fb-4668-4939-b0c4-7adbea54b400', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_living_storm', 'Yaşayan Fırtına', 'Living Storm', 'İçinizde depolanan cephaneliği telekinetik bir kasırgaya yansıtın. 1 dakika boyunca, etrafınızı 10 metrelik bir yarıçapta saran uçan kılıçlar aurası oluşur ve giren her düşmana 8d6 kesici hasar verir.', 'Project your inner stored arsenal into a telekinetic hurricane. For 1 minute, an aura of flying blades surrounds you in a 10m radius, dealing 8d6 slashing damage to any enemy that enters.', 'Cross-Branch', 68, 670, 4, '{"ws_living_arsenal", "ws_blade_storm"}', '{"x": -1039, "y": -600}', '{"duration": "1 minute", "aura": "10m radius", "damage": "8d6 slashing/round"}', '⛈️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d3179638-a223-4300-8ce0-1b3c2ad185ed', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_ethereal_domain', 'Eterik Alan', 'Ethereal Domain', 'Kılıçların Alanı''nı eterik düzleme kaydırın. İçeride kapana kısılan düşmanlar ışınlanamaz veya boyutsal seyahat kullanamaz ve turlarının başında 4d10 psişik hasar alırlar.', 'Shift your Domain of Blades into the ethereal plane. Enemies trapped inside cannot teleport or use dimensional travel, and take 4d10 psychic damage at the start of their turns.', 'Cross-Branch', 75, 750, 4, '{"ws_domain_of_blades", "ws_dimension_cutter"}', '{"x": -1255, "y": -725}', '{"area": "Same as Domain", "utility": "Blocks teleportation", "damage": "4d10 psychic/round"}', '🕋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c9f954b8-290d-4e4c-8bb1-441ba5fa8bfc', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_spirit_forge', 'Ruh Ocağı', 'Spirit Forge', 'Ruhunuzu doğrudan silahın fiziksel formuna döversiniz. Kritik çarpanınızı kalıcı olarak x1 artırır (örn. x2 iken x3 olur), ancak maksimum Can kalıcı olarak %10 azalır.', 'You forge your soul directly into the weapon''s physical form. Permanently increases your critical multiplier by x1 (e.g. x2 becomes x3), but max HP is permanently reduced by 10%.', 'Cross-Branch', 76, 760, 4, '{"ws_master_s_grip", "ws_soul_severing_strike"}', '{"x": -1472, "y": -850}', '{"buff": "+x1 Critical Multiplier", "penalty": "-10% Max HP permanent"}', '🔨');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('beb420ce-5705-4240-9241-dd779cca64f2', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_ultimate_avatar_of_steel', 'Çelik Avatarı', 'Avatar of Steel', 'Nihai teknik. Siz ve silahınız mükemmel bir şekilde birleşirsiniz. 1 dakika boyunca fiziksel hasara bağışıklık kazanırsınız, menziliniz 10 metreye çıkar ve saldırılarınız 10d10 + 50 güç hasarı verir.', 'Ultimate technique. You and your weapon merge perfectly. For 1 minute, you become immune to physical damage, your reach extends to 10m, and your attacks deal 10d10 + 50 force damage.', 'Weapon Bond', 90, 1200, 5, '{"ws_true_name_awakening", "ws_living_arsenal"}', '{"x": 2771, "y": -1599}', '{"duration": "1 minute", "immunity": "Physical damage", "reach": "10m", "damage": "10d10+50 force"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('bae0a8b1-4bda-41f4-aa9e-a6e0875f0335', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_ultimate_telekinetic_emperor', 'Telekinetik İmparator', 'Telekinetic Emperor', 'Nihai teknik. Savaş alanının telekinetik kontrolünü ele geçirin. Havada 10 metre yükselirsiniz, menzilli saldırılara bağışıklık kazanırsınız ve her tur otomatik olarak 100m içindeki 10''a kadar düşmana 15d8 güç hasarı verirsiniz. 1 dakika sürer.', 'Ultimate technique. Seize telekinetic control over the battlefield. You levitate 10m in the air, become immune to ranged attacks, and every round automatically deal 15d8 force damage to up to 10 enemies within 100m. Lasts 1 minute.', 'Telekinetic Mastery', 92, 1300, 5, '{"ws_thousand_swords_formation", "ws_domain_of_blades"}', '{"x": 2056, "y": 2451}', '{"duration": "1 minute", "immunity": "Ranged attacks", "damage": "15d8 force/round", "targets": "Up to 10"}', '👑');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2e4f0f8b-c1d3-4b39-bbbf-22dc871945d4', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_ultimate_soul_eradication', 'Ruh Yok Oluşu', 'Soul Eradication', 'Nihai teknik. Bir hedefin öz varlığına vurun. 25d10 türsüz hasar verir. Eğer hedef ölürse, ruhu yok edilir ve Dilek büyüsü dışında herhangi bir yolla diriltilmesi engellenir.', 'Ultimate technique. Strike a target''s core being. Deals 25d10 untyped damage. If the target is killed, their soul is destroyed, preventing resurrection by any means short of a Wish spell.', 'Soul Edge', 95, 1400, 5, '{"ws_absolute_severance", "ws_soul_reaper_s_dance"}', '{"x": -2056, "y": 2451}', '{"damage": "25d10 untyped", "special": "Prevents resurrection"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e019a712-2f3a-4334-bd64-6a1409c52232', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_omnipresent_blade', 'Her Yerde Olan Kılıç', 'Omnipresent Blade', 'Silahınız etrafınızdaki her yerde aynı anda var olur. 50m içindeki herhangi bir hedefe sanki bitişiğinizdeymiş gibi yakın dövüş saldırıları yapabilirsiniz. 3 tur sürer.', 'Your weapon exists in all places simultaneously around you. You can make melee attacks against any target within 50m as if they were adjacent to you. Lasts for 3 rounds.', 'Cross-Branch', 85, 1100, 5, '{"ws_living_arsenal", "ws_thousand_swords_formation"}', '{"x": -1688, "y": -975}', '{"duration": "3 rounds", "reach": "50m"}', '🌐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('353711c2-565c-460a-8174-8c9d4867e310', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_soul_shredding_tornado', 'Ruh Parçalayan Hortum', 'Soul Shredding Tornado', '1000 kılıcı devasa bir ruh kesici enerji kasırgasına dönüştürün. 40 metrelik bir silindir içinde 15d10 güç ve nekrotik hasar verir, hayatta kalan herkesi 1 dakika boyunca susturur ve kör eder.', 'Merge 1000 swords into a massive cyclone of soul-cutting energy. Deals 15d10 force and necrotic damage in a 40m cylinder, silencing and blinding all survivors for 1 minute.', 'Cross-Branch', 86, 1150, 5, '{"ws_thousand_swords_formation", "ws_absolute_severance"}', '{"x": -1905, "y": -1100}', '{"area": "40m cylinder", "damage": "15d10 force/necrotic", "status": "Silence/Blind 1 min"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5e209e47-49a7-4b79-8988-3b082da0a0a8', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_eternal_edge', 'Sonsuz Kenar', 'Eternal Edge', 'Haftada bir kez, vuruşunuz patron olmayan bir düşmanı kalıcı olarak varoluştan silebilir veya bir patronun maksimum Canını kalıcı olarak %20 azaltabilir. Kesik, gerçeklikte bir yara izi bırakır.', 'Once per week, your strike can permanently erase a non-boss enemy from existence, or permanently reduce a boss''s max HP by 20%. The cut leaves a scar on reality.', 'Cross-Branch', 88, 1180, 5, '{"ws_true_name_awakening", "ws_absolute_severance"}', '{"x": -2121, "y": -1225}', '{"cooldown": "1 week", "special": "Erase non-boss or -20% max HP boss"}', '♾️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ad80fc08-41bb-4245-b5b9-17e721b589df', 'f84d698e-3be4-474b-9413-2b42de08d563', 'ws_grand_ultimate_saint_of_swords', 'Kılıçların Azizi', 'Saint of Swords', 'Büyük Nihai. Kılıç kavramının temeli olursunuz. 3 tur boyunca diğer herkes için zaman durur. Her biri 20d10 radyant güç hasarı veren sınırsız sayıda saldırı yapabilirsiniz. Zaman yeniden aktığında gerçeklik parçalanır.', 'Grand Ultimate. You become the fundamental concept of the Sword. For 3 rounds, time stops for everyone else. You can make an unlimited number of attacks, each dealing 20d10 radiant force damage. When time resumes, reality shatters.', 'Cross-Branch', 100, 1500, 5, '{"ws_ultimate_avatar_of_steel", "ws_ultimate_telekinetic_emperor", "ws_ultimate_soul_eradication"}', '{"x": -2338, "y": -1350}', '{"duration": "3 rounds", "special": "Time Stop, Unlimited Attacks", "damage": "20d10 radiant force"}', '👼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('83b16e49-7a0c-4962-a2f3-338cd3f24f26', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_iron_grip', 'Demir Kavrama', 'Iron Grip', '2m mesafedeki bir hedefi kavrayarak hareket hızını 0''a düşürürsün. Hedef, saldırı zarlarında dezavantaja sahip olur.', 'Grip a target within 2m, reducing their movement speed to 0. Target has disadvantage on their attack rolls.', 'Grapple', 1, 50, 1, '{}', '{"x": 173, "y": -99}', '{"range": "2m", "movement_speed": "0", "debuff": "Disadvantage on attacks"}', '🦾');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('507e0b17-1fcc-4be4-9eed-cd56201912a3', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_bear_hug', 'Ayı Kapanı', 'Bear Hug', 'Hedefi sıkarak tur başına 2d6 ezici hasar verirsin. 3 tur sürer. Hedefin hızı 0''dır.', 'Squeeze the target, dealing 2d6 bludgeoning damage per turn. Lasts 3 turns. Target speed is 0.', 'Grapple', 10, 100, 1, '{"wr_iron_grip"}', '{"x": 389, "y": -224}', '{"damage": "2d6 bludgeoning", "duration": "3 turns", "speed": "0m"}', '🐻');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b97ea721-806d-477e-99d8-013b7cf37352', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_dash_grab', 'Atılıp Yakalama', 'Dash Grab', '10m''ye kadar atıl ve anında bir hedefi kavra.', 'Dash up to 10m and immediately grapple a target.', 'Grapple', 15, 150, 1, '{"wr_iron_grip"}', '{"x": 606, "y": -349}', '{"dash_range": "10m", "condition": "Grappled"}', '🏃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('67f15aaa-9d8f-487f-b038-96a10360a68f', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_chokehold', 'Boğma Mandalı', 'Chokehold', '3d6 ezici hasar ver ve hedefi sustur. Kavrandıkları sürece sözlü büyü yapamazlar.', 'Deal 3d6 bludgeoning damage and silence the target. They cannot cast verbal spells while grappled.', 'Grapple', 22, 200, 2, '{"wr_bear_hug"}', '{"x": 822, "y": -474}', '{"damage": "3d6 bludgeoning", "condition": "Silenced", "duration": "2 turns"}', '🤫');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6d69fd41-00ce-4923-b19f-79f8f4cc8408', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_unbreakable_pin', 'Kırılmaz Tuş', 'Unbreakable Pin', 'Yere serilmiş bir hedefi yere çivile. Çok zor bir Güç zarını geçmedikçe hareket edemez veya ayağa kalkamazlar.', 'Pin a prone target to the ground. They cannot move or stand up unless they pass a massive Strength check.', 'Grapple', 30, 250, 2, '{"wr_chokehold"}', '{"x": 1039, "y": -599}', '{"condition": "Pinned (Prone + Grappled)", "escape_dc": "Strength save with Disadvantage"}', '📌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d9d6e204-0251-4c76-84f0-a54b3bb34fd7', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_giant_swing', 'Dev Savurma', 'Giant Swing', 'Kavranmış bir hedefi çevirerek 3m içindeki diğer düşmanlara 4d6 hasar ver, ardından onu 5m uzağa fırlat.', 'Spin a grappled target, hitting other enemies within 3m for 4d6 damage, then throw them up to 5m.', 'Grapple', 38, 300, 2, '{"wr_unbreakable_pin", "wr_dash_grab"}', '{"x": 1255, "y": -724}', '{"aoe_damage": "4d6 bludgeoning", "aoe_range": "3m radius", "throw_distance": "5m"}', '🌪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('764631ef-31f9-48fa-b96c-a2002a5fb041', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_ground_pound', 'Yere Serme ve Yumruklama', 'Ground and Pound', 'Yere çivilenmiş hedefin üzerine yumruk yağdırarak 5d6 hasar ver. Hedefi 1 tur sersemletir.', 'Rain blows on a pinned target for 5d6 damage. Stuns target for 1 turn.', 'Grapple', 45, 400, 3, '{"wr_unbreakable_pin"}', '{"x": 1472, "y": -849}', '{"damage": "5d6 bludgeoning", "condition": "Stunned", "duration": "1 turn"}', '🥊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('6cd776f5-4267-4b37-958d-002ffbb09173', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_titans_grasp', 'Titan''ın Kavrayışı', 'Titan''s Grasp', 'Artık senden iki boyut kategorisine kadar daha büyük yaratıkları kavrayabilirsin.', 'You can now grapple creatures up to two size categories larger than you.', 'Grapple', 55, 450, 3, '{"wr_giant_swing"}', '{"x": 1688, "y": -974}', '{"passive": "Grapple targets up to 2 size categories larger"}', '🖐️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e22f4eb7-9550-4d77-8202-a3afed19380f', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_immobilizing_lock', 'Hareketsiz Bırakan Kilit', 'Immobilizing Lock', 'Hedef 6d8 hasar alır ve tamamen kısıtlanır. Hiçbir fiziksel eylem yapamaz.', 'Target takes 6d8 damage and is completely restrained. Cannot take any physical actions.', 'Grapple', 60, 500, 3, '{"wr_ground_pound"}', '{"x": 1905, "y": -1099}', '{"damage": "6d8 bludgeoning", "condition": "Restrained"}', '⛓️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b1a844e3-bfc0-4b92-aff4-29fb46475f6f', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_spinecrusher', 'Omurga Kıran', 'Spinecrusher', 'Acımasız bir kavrama hareketi. 8d8 hasar verir ve iyileştirilene kadar hedefin hareket hızı kalıcı olarak yarıya iner.', 'A brutal grapple move. Deals 8d8 damage, and the target''s movement speed is halved permanently until healed.', 'Grapple', 65, 650, 4, '{"wr_titans_grasp"}', '{"x": 2121, "y": -1224}', '{"damage": "8d8 bludgeoning", "debuff": "Movement speed halved permanently"}', '🦴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8da3e3ab-2389-41b6-88dc-f9e7a229006d', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_grapplers_instinct', 'Güreşçi İçgüdüsü', 'Grappler''s Instinct', 'Pasif. Tüm kavrama zarlarına +5 ve bir düşmana doğru hareket ederken +10m hareket hızı kazanırsın.', 'Passive. Gain +5 to all grapple checks and +10m movement speed when moving towards an enemy.', 'Grapple', 72, 750, 4, '{"wr_immobilizing_lock"}', '{"x": 2338, "y": -1349}', '{"buff": "+5 to Grapple checks", "movement": "+10m when moving toward enemy"}', '🧠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2d5d86d5-6a84-419c-8dde-aad88e80e9af', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_colossal_restraint', 'Devasa Zaptetme', 'Colossal Restraint', '8m içindeki düşmanları yere sabitleyen bir şok dalgası yaratarak tüm bir grubu zaptet.', 'Restrain an entire group by creating a shockwave that roots enemies within 8m.', 'Grapple', 78, 850, 4, '{"wr_spinecrusher"}', '{"x": 2554, "y": -1474}', '{"aoe_radius": "8m", "condition": "Rooted"}', '⚓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b7475f1-2786-4b17-979c-06a97ba5c038', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_absolute_control', 'Mutlak Kontrol', 'Absolute Control', 'Senin 5m çevren senin alanın olur. Giren her düşman otomatik olarak kavranır.', 'The area within 5m of you becomes your domain. Any enemy entering is automatically grappled.', 'Grapple', 85, 1100, 5, '{"wr_colossal_restraint"}', '{"x": 2771, "y": -1599}', '{"aura_radius": "5m", "condition": "Auto-Grapple on entry"}', '🎛️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('76d3527a-f505-4349-8746-fac12bd5d024', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_black_hole_grip', 'Kara Delik Kavrayışı', 'Black Hole Grip', 'Ulti. Bir hedefi gerçekliği bükecek bir güçle kavra. 20d10 güç hasarı verir. Hedef ezilerek bir tekilliğe dönüşür.', 'Ultimate. Grip a target with such force that reality distorts. Deals 20d10 force damage. Target is crushed into a singularity.', 'Grapple', 95, 1400, 5, '{"wr_absolute_control", "wr_grapplers_instinct"}', '{"x": 2987, "y": -1724}', '{"damage": "20d10 force", "condition": "Crushed into singularity"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f8c4de7c-27f0-41f4-8f6d-3fc765e894f4', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_body_slam', 'Gövde Savurma', 'Body Slam', '2m içindeki bir hedefi kaldırıp yere çarp. 3d6 ezici hasar verir ve onları yere serer.', 'Lift and slam a target within 2m. Deals 3d6 bludgeoning damage and knocks them prone.', 'Throw', 1, 50, 1, '{}', '{"x": 128, "y": 153}', '{"damage": "3d6 bludgeoning", "condition": "Prone", "range": "2m"}', '💥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('08a6f7a5-8b64-49f1-aefc-9d68daeb66dc', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_hip_toss', 'Kalça Fırlatması', 'Hip Toss', 'Hedefi 4m uzağa fırlat. Yere düştüklerinde 2d6 hasar alırlar.', 'Throw the target up to 4m away. They take 2d6 damage upon landing.', 'Throw', 8, 80, 1, '{"wr_body_slam"}', '{"x": 289, "y": 344}', '{"throw_distance": "4m", "damage": "2d6 bludgeoning"}', '↪️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7a1e9765-cf2c-46bb-8954-e2f20023bc94', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_backdrop', 'Geriye Düşürme', 'Backdrop', 'Hedefi doğrudan arkana düşür. 4d6 hasar verir ve zırhı yok sayar.', 'Drop the target directly behind you. Deals 4d6 damage and bypasses armor.', 'Throw', 18, 150, 1, '{"wr_hip_toss"}', '{"x": 449, "y": 536}', '{"damage": "4d6 bludgeoning (ignores armor)", "position": "Directly behind caster"}', '🔄');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('84e9db27-1e94-4000-9677-b7c889121eba', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_suplex', 'Supleks', 'Suplex', 'Klasik bir geriye fırlatma. 5d6 hasar verir ve hedefi 1 tur sersemletir.', 'A classic backward throw. Deals 5d6 damage and stuns the target for 1 turn.', 'Throw', 25, 200, 2, '{"wr_backdrop"}', '{"x": 610, "y": 727}', '{"damage": "5d6 bludgeoning", "condition": "Stunned", "duration": "1 turn"}', '📉');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('99d5c31d-9cb0-4290-8da2-1428c6ba69a6', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_powerbomb', 'Güç Bombası', 'Powerbomb', 'Hedefi yükseğe kaldırıp yere vur. Hedefin etrafındaki 2m''lik bir alanda 6d6 hasar verir.', 'Lift the target high and smash them down. Deals 6d6 damage in a 2m radius around the target.', 'Throw', 32, 250, 2, '{"wr_suplex"}', '{"x": 771, "y": 919}', '{"aoe_damage": "6d6 bludgeoning", "aoe_radius": "2m"}', '💣');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('b4725804-ccb8-4538-a266-852a727ec106', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_tornado_throw', 'Kasırga Fırlatışı', 'Tornado Throw', 'Bir kasırga gibi dön ve hedefi 10m uzağa fırlat. Çarptıkları herkese 4d6 hasar verirler.', 'Spin like a tornado and throw the target up to 10m. They deal 4d6 damage to anyone they hit.', 'Throw', 38, 300, 2, '{"wr_powerbomb"}', '{"x": 932, "y": 1110}', '{"throw_distance": "10m", "collision_damage": "4d6 bludgeoning"}', '🌀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('e33e9ebe-bf5e-491b-abe3-36ad31097a38', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_aerial_crash', 'Havadan Çarpışma', 'Aerial Crash', 'Hedefle birlikte havaya 8m sıçra ve yere çakıl. Hedefe 8d6, 4m içindeki düşmanlara 4d6 hasar verir.', 'Leap 8m into the air with the target and crash down. Deals 8d6 damage to the target and 4d6 to enemies within 4m.', 'Throw', 45, 400, 3, '{"wr_tornado_throw"}', '{"x": 1092, "y": 1302}', '{"leap_height": "8m", "target_damage": "8d6 bludgeoning", "aoe_damage": "4d6 bludgeoning", "aoe_radius": "4m"}', '☄️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('40633c13-70ca-4c1f-8bcc-f686a34b09eb', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_avalanche_slam', 'Çığ Çarpması', 'Avalanche Slam', 'Hedefi o kadar sert çarp ki, 6m''lik bir koni şeklinde 5d8 hasar veren bir şok dalgası yaratır.', 'Slam the target so hard it creates a 6m cone shockwave dealing 5d8 damage.', 'Throw', 50, 420, 3, '{"wr_powerbomb"}', '{"x": 1253, "y": 1493}', '{"aoe_damage": "5d8 bludgeoning", "cone_range": "6m"}', '⛰️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('a3de4dde-1976-4574-8a89-1c6dcd1d3846', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_german_suplex', 'Alman Supleksi', 'German Suplex', 'Yıkıcı bir geriye fırlatma. 7d8 hasar verir ve tur başına 2d4 kanama hasarına neden olur.', 'A devastating backward throw. Deals 7d8 damage and causes 2d4 bleeding damage per turn.', 'Throw', 58, 480, 3, '{"wr_avalanche_slam"}', '{"x": 1414, "y": 1685}', '{"damage": "7d8 bludgeoning", "bleed": "2d4 damage per turn"}', '🤼');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d2a8821b-54b8-49b0-9487-5989e3e7107f', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_meteor_slam', 'Meteor Çarpması', 'Meteor Slam', '15m sıçra ve bir meteor gibi yere çakıl. Hedefe 10d8, 6m yarıçapa ise 6d8 hasar verir.', 'Jump 15m and crash down like a meteor. Deals 10d8 damage to the target and 6d8 in a 6m radius.', 'Throw', 66, 680, 4, '{"wr_aerial_crash"}', '{"x": 1574, "y": 1876}', '{"leap_distance": "15m", "target_damage": "10d8 bludgeoning", "aoe_damage": "6d8 bludgeoning", "aoe_radius": "6m"}', '🌠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('01d492dd-c96b-4f08-9963-1c58b91c8d64', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_living_projectile', 'Canlı Mermi', 'Living Projectile', 'Bir düşmanı bir silah gibi 15m uzağa fırlat. Hem fırlatılan düşmana hem de çarptığı hedefe 8d8 hasar verir.', 'Throw an enemy up to 15m like a weapon. Deals 8d8 damage to both the thrown enemy and the target they hit.', 'Throw', 74, 780, 4, '{"wr_german_suplex"}', '{"x": 1735, "y": 2068}', '{"throw_distance": "15m", "damage": "8d8 bludgeoning to both targets"}', '🚀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('cfbe7334-1f45-4991-9c9f-a238f698e093', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_earthshatter_drop', 'Yeri Sarsan Düşüş', 'Earthshatter Drop', 'Hedefi yere çarparak yerin çatlamasını sağla. 12d8 hasar verir ve 10m''lik alanı zorlu arazi yapar.', 'Slam the target, causing the ground to crack. Deals 12d8 damage and makes a 10m radius difficult terrain.', 'Throw', 80, 880, 4, '{"wr_meteor_slam"}', '{"x": 1896, "y": 2259}', '{"damage": "12d8 bludgeoning", "terrain": "Difficult terrain in 10m radius"}', '🌋');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('183f8cc8-8dce-40cc-9726-949c73796e85', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_gravity_defiance', 'Yerçekimine Meydan Okuma', 'Gravity Defiance', 'Bir düşmanı o kadar yükseğe fırlat ki düşmesi 3 tur sürsün, yere çarptığında 15d10 düşme hasarı alsın.', 'Toss an enemy so high they take 3 turns to fall, taking 15d10 falling damage upon impact.', 'Throw', 85, 1100, 5, '{"wr_earthshatter_drop"}', '{"x": 2056, "y": 2451}', '{"falling_delay": "3 turns", "falling_damage": "15d10"}', '🌌');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('d5942fd8-c380-4b6d-bf80-b700fbf83ba7', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_world_breaker_suplex', 'Dünya Yıkan Supleks', 'World Breaker Suplex', 'Ulti. Yeryüzünü parçalayan bir supleks. Hedefe 25d10 hasar verir ve devasa 20m''lik bir krater oluşturarak diğerlerine 10d10 hasar verir.', 'Ultimate. A suplex that shatters the earth. Deals 25d10 damage to the target and creates a massive 20m crater, dealing 10d10 to others.', 'Throw', 95, 1400, 5, '{"wr_gravity_defiance", "wr_living_projectile"}', '{"x": 2217, "y": 2642}', '{"target_damage": "25d10 bludgeoning", "aoe_damage": "10d10 bludgeoning", "crater_radius": "20m"}', '🌍');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('30d62066-1cce-432e-bb3e-20798a2b140a', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_joint_lock', 'Eklem Kilidi', 'Joint Lock', 'Bir eklemi bük. 1d8 hasar verir ve hedefin saldırı zarlarını 1d4 düşürür.', 'Twist a joint. Deals 1d8 damage and reduces the target''s attack rolls by 1d4.', 'Submission', 1, 50, 1, '{}', '{"x": -128, "y": 153}', '{"damage": "1d8 bludgeoning", "debuff": "-1d4 to attack rolls"}', '🔧');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('631e792d-04e8-4b81-9d43-71b9204933fa', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_ankle_breaker', 'Ayak Bileği Kıran', 'Ankle Breaker', 'Hedefin hareketi 3 tur boyunca %50 azalır. 2d6 hasar verir.', 'Target''s movement is reduced by 50% for 3 turns. Deals 2d6 damage.', 'Submission', 12, 120, 1, '{"wr_joint_lock"}', '{"x": -289, "y": 344}', '{"damage": "2d6 bludgeoning", "movement": "-50% for 3 turns"}', '🦶');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('29bcb0e1-6774-4701-87c8-cad5a379ca94', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_armbar', 'Kol Kilidi', 'Armbar', 'Hedefin kolunu kilitle. Silahlarını düşürürler ve o kolu 2 tur kullanamazlar.', 'Lock the target''s arm. They drop their weapon and cannot use that arm for 2 turns.', 'Submission', 16, 140, 1, '{"wr_ankle_breaker"}', '{"x": -449, "y": 536}', '{"condition": "Disarmed (One arm)", "duration": "2 turns"}', '💪');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1461ba4e-9470-4cd4-ba17-76bbcfe83403', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_guillotine_choke', 'Giyotin Boğması', 'Guillotine Choke', 'Hedef 3d8 hasar alır. Eğer bir Bünye zarında başarısız olurlarsa uykuya dalarlar.', 'Target takes 3d8 damage. If they fail a Constitution save, they fall asleep.', 'Submission', 24, 200, 2, '{"wr_armbar"}', '{"x": -610, "y": 727}', '{"damage": "3d8 bludgeoning", "condition": "Sleep on failed Con save"}', '🪓');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5a8446b0-71dc-431d-b5cb-36db45569000', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_sleeper_hold', 'Uyku Kilidi', 'Sleeper Hold', 'Tur başına 4d6 hasar verir. Eğer 3 tur sürdürülürse, hedef bilincini kaybeder.', 'Deals 4d6 damage per turn. If maintained for 3 turns, the target falls unconscious.', 'Submission', 30, 250, 2, '{"wr_guillotine_choke"}', '{"x": -771, "y": 919}', '{"damage": "4d6 bludgeoning per turn", "condition": "Unconscious after 3 turns"}', '😴');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('9147047e-fc30-4bc4-a8bf-727af60532a3', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_pain_inducer', 'Acı Tetikleyici', 'Pain Inducer', 'Izdırap verici bir acı yaşat. Hedef tüm kurtarma ve saldırı zarlarında dezavantaja sahip olur.', 'Inflict agonizing pain. Target has disadvantage on all saving throws and attacks.', 'Submission', 35, 280, 2, '{"wr_sleeper_hold"}', '{"x": -932, "y": 1110}', '{"debuff": "Disadvantage on saves and attacks"}', '⚡');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c21730da-741c-4647-a0b4-86cffd60faa8', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_triangle_choke', 'Üçgen Kilit', 'Triangle Choke', 'Kan akışını kısıtla. 5d8 hasar verir ve hedef susturulur ve kör edilir.', 'Restrict blood flow. Deals 5d8 damage, and the target is silenced and blinded.', 'Submission', 42, 380, 3, '{"wr_pain_inducer"}', '{"x": -1092, "y": 1302}', '{"damage": "5d8 bludgeoning", "condition": "Silenced and Blinded"}', '📐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('71dee669-4303-4142-a0c2-c62a15f86667', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_bone_crusher', 'Kemik Kıran', 'Bone Crusher', 'Kemikleri kır. 6d8 hasar verir ve hedef 2 tur boyunca tüm fiziksel saldırılardan iki kat hasar alır.', 'Snap bones. Deals 6d8 damage, and the target takes double damage from all physical attacks for 2 turns.', 'Submission', 52, 450, 3, '{"wr_triangle_choke"}', '{"x": -1253, "y": 1493}', '{"damage": "6d8 bludgeoning", "vulnerability": "Double damage from physical attacks", "duration": "2 turns"}', '💀');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('2bc2f5a8-0904-4afe-95ad-8a663626bac3', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_nerve_pinch', 'Sinir Sıkıştırması', 'Nerve Pinch', 'Hedef 1 tur felç olur ve 4d8 psişik hasar alır.', 'Target is paralyzed for 1 turn and takes 4d8 psychic damage.', 'Submission', 58, 480, 3, '{"wr_bone_crusher"}', '{"x": -1414, "y": 1685}', '{"damage": "4d8 psychic", "condition": "Paralyzed", "duration": "1 turn"}', '🤏');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('39735eb6-d0d3-417e-bbb0-dca91ee5e733', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_kimura_lock', 'Kimura Kilidi', 'Kimura Lock', 'Hedefin omzunu yok et. 8d8 hasar verir ve sihirle iyileştirilene kadar bir kolu kalıcı olarak silahsız bırakır.', 'Destroy the target''s shoulder. Deals 8d8 damage and permanently disarms one arm until magically healed.', 'Submission', 65, 650, 4, '{"wr_nerve_pinch"}', '{"x": -1574, "y": 1876}', '{"damage": "8d8 bludgeoning", "condition": "Permanently disarms one arm"}', '🔐');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('0f604d1e-d77d-4ea4-b882-47acf00d1588', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_paralytic_grip', 'Felç Edici Tutuş', 'Paralytic Grip', 'Sinir sistemini durduran bir tutuş. Hedef 2 tur boyunca hareket edemez, saldıramaz veya büyü yapamaz.', 'A grip that stops the nervous system. Target cannot move, attack, or cast spells for 2 turns.', 'Submission', 70, 700, 4, '{"wr_kimura_lock"}', '{"x": -1735, "y": 2068}', '{"condition": "Cannot move, attack, or cast", "duration": "2 turns"}', '🧊');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('559d19d3-47e9-4799-9c14-ab6243655c38', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_suffocating_vice', 'Boğucu Mengene', 'Suffocating Vice', 'Hedef tutulduğu süre boyunca tur başına maksimum canının %15''ini kaybeder.', 'Target loses 15% of their maximum HP per turn while held.', 'Submission', 78, 800, 4, '{"wr_paralytic_grip"}', '{"x": -1896, "y": 2259}', '{"damage": "15% max HP per turn"}', '🗜️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('017c3379-014d-491d-a4e8-eed1af91c400', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_asphyxiation', 'Oksijensiz Bırakma', 'Asphyxiation', 'Hedef boğulmaya başlar. Tutuş bozulmazsa 3 tur içinde canı 0''a düşer.', 'Target begins to suffocate. They drop to 0 HP in 3 turns if the hold is not broken.', 'Submission', 82, 1000, 5, '{"wr_suffocating_vice"}', '{"x": -2056, "y": 2451}', '{"condition": "Drops to 0 HP in 3 turns"}', '🫁');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('c9675c89-df86-4902-b5ba-89fdd733ae34', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_executioners_lock', 'Cellat Kilidi', 'Executioner''s Lock', 'Ulti. Kusursuz, ölümcül bir pes ettiriş. 20d10 hasar verir. Eğer hedefin canı %25''in altındaysa anında ölürler.', 'Ultimate. A flawless, lethal submission. Deals 20d10 damage. If the target is below 25% HP, they die instantly.', 'Submission', 95, 1400, 5, '{"wr_asphyxiation"}', '{"x": -2217, "y": 2642}', '{"damage": "20d10 bludgeoning", "execute": "Insta-kill if under 25% HP"}', '☠️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('1270390b-c4fa-4310-8d07-e352051daec9', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_launching_grab', 'Fırlatan Tutuş', 'Launching Grab', '8m atıl, bir hedefi kavra ve anında onları 8m daha uzağa fırlat.', 'Dash 8m, grab a target, and instantly throw them 8m further.', 'Cross-Branch', 25, 250, 2, '{"wr_dash_grab", "wr_hip_toss"}', '{"x": -173, "y": -100}', '{"dash_range": "8m", "throw_distance": "8m"}', '🪃');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('5b75f3a5-3356-4f3f-9cb7-ec714e47d8c5', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_crushing_embrace', 'Ezen Kucaklaşma', 'Crushing Embrace', 'Aynı zamanda pes ettirme zayıflatmaları uygulayan bir ayı kapanı. 4d8 hasar verir ve hedefi 1 tur felç eder.', 'A bear hug that also applies submission debuffs. Deals 4d8 damage and paralyzes the target for 1 turn.', 'Cross-Branch', 34, 280, 2, '{"wr_bear_hug", "wr_sleeper_hold"}', '{"x": -389, "y": -225}', '{"damage": "4d8 bludgeoning", "condition": "Paralyzed", "duration": "1 turn"}', '🤗');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('ee9e8517-8f2a-4673-b8ee-74cdf9794498', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_dislocating_slam', 'Çıkık Yaratan Çarpma', 'Dislocating Slam', 'Hedefi yere çarp ve uzvunu tutmaya devam ederek çıkar. 6d8 hasar verir ve kol kilidi etkilerini uygular.', 'Slam the target and keep hold of their limb, dislocating it. Deals 6d8 damage and applies armbar effects.', 'Cross-Branch', 48, 450, 3, '{"wr_powerbomb", "wr_triangle_choke"}', '{"x": -606, "y": -350}', '{"damage": "6d8 bludgeoning", "condition": "Disarmed (One arm)"}', '🏥');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('4a684633-efe2-4b6d-8e16-426fec3a52bb', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_lucha_libre_combo', 'Lucha Libre Kombosu', 'Lucha Libre Combo', '3 vuruşluk bir kombo: Kavra, havaya fırlat ve yere düşerken bir kilitle yakala. Toplam 10d8 hasar verir.', 'A 3-hit combo: Grab, throw into the air, and catch them in a submission upon landing. Deals 10d8 total damage.', 'Cross-Branch', 55, 500, 3, '{"wr_unbreakable_pin", "wr_suplex", "wr_bone_crusher"}', '{"x": -822, "y": -475}', '{"total_damage": "10d8 bludgeoning", "combo": "Grab -> Air Throw -> Submission"}', '🦸');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('f5eed794-d383-4063-9773-f23892af5e2e', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_inescapable_doom', 'Kaçınılmaz Kıyamet', 'Inescapable Doom', 'Hedefi yere çivile ve ölümcül bir boğma uygula. Tur başına 8d8 hasar verir ve fiziksel yollarla bozulamaz.', 'Pin the target and apply a lethal choke. Deals 8d8 damage per turn and cannot be broken by physical means.', 'Cross-Branch', 68, 700, 4, '{"wr_ground_pound", "wr_nerve_pinch"}', '{"x": -1039, "y": -600}', '{"damage": "8d8 bludgeoning per turn", "condition": "Unbreakable by physical means"}', '🕷️');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('8d2bf594-1e9b-43d4-83c6-918da90024fd', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_breakneck_toss', 'Boyun Kıran Fırlatma', 'Breakneck Toss', 'Hedefi boynundan tutarak fırlat. 12d8 hasar verir ve 2 tur sersemletir.', 'Throw the target by their neck. Deals 12d8 damage and stuns them for 2 turns.', 'Cross-Branch', 75, 800, 4, '{"wr_meteor_slam", "wr_paralytic_grip"}', '{"x": -1255, "y": -725}', '{"damage": "12d8 bludgeoning", "condition": "Stunned", "duration": "2 turns"}', '🦒');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('7dd185b4-937e-4b76-9ff2-1d3a89e04e76', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_titans_carousel', 'Titan Atlıkarıncası', 'Titan''s Carousel', 'İki düşmanı kavra, 6m içindeki her şeye 10d8 hasar vererek onları çevir, ardından 15m uzağa fırlat.', 'Grab two enemies, spin them around dealing 10d8 damage to everything in a 6m radius, then throw them 15m.', 'Cross-Branch', 88, 1200, 5, '{"wr_absolute_control", "wr_gravity_defiance"}', '{"x": -1472, "y": -850}', '{"aoe_damage": "10d8 bludgeoning", "aoe_radius": "6m", "throw_distance": "15m"}', '🎠');
INSERT INTO spells (id, spell_tree_id, spell_key, name_tr, name_en, description_tr, description_en, branch, min_level, xp_cost, tier, prerequisites, position, effects, icon) VALUES ('36426a8a-05e2-4877-8ecc-8558fe15fdc6', '36f3ab60-f57a-443c-ae43-feab252aab30', 'wr_god_of_the_ring', 'Ringin Tanrısı', 'God of the Ring', 'Büyük Ulti. Hayaletimsi 30m''lik bir güreş ringi çağır. İçeride fiziksel istatistiklerin iki katına çıkar, düşmanlar ayrılamaz ve bekleme sürelerin yarıya iner. 5 tur sürer.', 'Grand Ultimate. Summon a ghostly 30m wrestling ring. Inside, your physical stats are doubled, enemies cannot leave, and your cooldowns are halved. Lasts 5 turns.', 'Cross-Branch', 100, 1500, 5, '{"wr_black_hole_grip", "wr_world_breaker_suplex", "wr_executioners_lock"}', '{"x": -1688, "y": -975}', '{"arena_radius": "30m", "buff": "Double physical stats, half cooldowns", "duration": "5 turns"}', '🏟️');
